B.KM=new A.cv(1,"\u05d4\u05e7\u05d3\u05de\u05d4: \u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d1\u05ea\u05e4\u05d9\u05dc\u05d4 \u2013 \u05de\u05e1\u05e2 \u05e4\u05e0\u05d9\u05de\u05d9 \u05d0\u05dc \u05d4\u05e0\u05e9\u05de\u05d4",'\u05d4\u05e7\u05d3\u05de\u05d4 \u05dc\u05e1\u05e4\u05e8: \u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d1\u05ea\u05e4\u05d9\u05dc\u05d4 \u2013 \u05de\u05e1\u05e2 \u05e4\u05e0\u05d9\u05de\u05d9 \u05d0\u05dc \u05d4\u05e0\u05e9\u05de\u05d4\n\u05de\u05d4 \u05d4\u05e7\u05e9\u05e8 \u05d1\u05d9\u05df \u05ea\u05e4\u05d9\u05dc\u05d4 \u05dc\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4? \u05d4\u05d0\u05dd \u05d4\u05dd \u05d0\u05d5\u05ea\u05d5 \u05d4\u05d3\u05d1\u05e8?\n\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d4\u05d9\u05d0 \u05e8\u05d9\u05db\u05d5\u05d6 \u05d5\u05ea\u05e4\u05d9\u05dc\u05d4 \u05e6\u05e8\u05d9\u05db\u05d4 \u05dc\u05d1\u05d5\u05d0 \u05de\u05ea\u05d5\u05da \u05e8\u05d9\u05db\u05d5\u05d6.\n\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d0\u05d9\u05e0\u05d4 \u05e8\u05e7 \u05d1\u05e7\u05e9\u05d4 \u05d0\u05d5 \u05d4\u05dc\u05dc \u05dc\u05d1\u05d5\u05e8\u05d0.\n\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d4\u05d9\u05d0 \u05d0\u05d9\u05e4\u05d5\u05e1 \u05dc\u05de\u05e2\u05e8\u05db\u05ea \u05e9\u05dc\u05e0\u05d5\n\u05d4\u05d7\u05d9\u05d1\u05d5\u05e8 \u05d1\u05d9\u05df \u05d4\u05d2\u05d5\u05e3 \u05dc\u05e0\u05e4\u05e9 \u05d5\u05dc\u05e0\u05e9\u05de\u05d4.\n\u05d9\u05e9 \u05de\u05e9\u05e4\u05d8 \u05d7\u05d6"\u05dc \u05e9\u05d0\u05d5\u05de\u05e8 \u05e9\u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05dc\u05dc\u05d0 \u05db\u05d5\u05d5\u05e0\u05d4 \u05d4\u05d9\u05d0 \u05db\u05de\u05d5 \u05d2\u05d5\u05e3 \u05dc\u05dc\u05d0 \u05e0\u05e9\u05de\u05d4. \u05d4\u05d7\u05e1\u05d9\u05d3\u05d5\u05ea \u05dc\u05e7\u05d7\u05d4 \u05d0\u05ea \u05d6\u05d4 \u05e2\u05d5\u05d3 \u05e6\u05e2\u05d3, \u05d5\u05d0\u05de\u05e8\u05d4 \u05e9\u05ea\u05e4\u05d9\u05dc\u05d4 \u05db\u05d6\u05d5 \u05dc\u05d0 \u05e8\u05d9\u05e7\u05d4, \u05d0\u05dc\u05d0 \u05d0\u05e4\u05d9\u05dc\u05d5 \u05de\u05d6\u05d9\u05e0\u05d4 \u05d0\u05ea \u05d4\u05db\u05d5\u05d7\u05d5\u05ea \u05e9\u05de\u05e8\u05d7\u05d9\u05e7\u05d9\u05dd \u05d0\u05d5\u05ea\u05e0\u05d5 \u05de\u05e2\u05e6\u05de\u05e0\u05d5. \u05d4\u05d7\u05e1\u05d9\u05d3\u05d5\u05ea \u05e7\u05d5\u05e8\u05d0\u05ea \u05dc\u05d6\u05d4 \u05e7\u05dc\u05d9\u05e4\u05d5\u05ea, \u05d4\u05e1\u05d8\u05e8\u05d0 \u05d0\u05d7\u05e8\u05d0.\n\u05d1\u05de\u05e9\u05da \u05e9\u05e0\u05d9\u05dd \u05d4\u05de\u05e9\u05e4\u05d8\u05d9\u05dd \u05d4\u05d0\u05dc\u05d4 \u05d2\u05e8\u05de\u05d5 \u05dc\u05d9 \u05dc\u05d4\u05e8\u05d2\u05d9\u05e9 \u05e8\u05e2. \u05db\u05d0\u05d9\u05dc\u05d5 \u05d0\u05dd \u05d0\u05e0\u05d9 \u05dc\u05d0 \u05de\u05e6\u05dc\u05d9\u05d7\u05d4 \u05dc\u05d4\u05ea\u05e8\u05db\u05d6 \u05d0\u05d5 \u05dc\u05d4\u05e8\u05d2\u05d9\u05e9 \u05de\u05e9\u05d4\u05d5 \u05d1\u05ea\u05e4\u05d9\u05dc\u05d4 \u2013 \u05d0\u05e0\u05d9 \u05e0\u05db\u05e9\u05dc\u05ea. \u05db\u05d0\u05d9\u05dc\u05d5 \u05db\u05dc \u05e0\u05d9\u05e1\u05d9\u05d5\u05df \u05e9\u05dc\u05d0 \u201c\u05d4\u05e6\u05dc\u05d9\u05d7\u201d \u05d4\u05d5\u05d0 \u05d7\u05d8\u05d0.\n\u05d0\u05d1\u05dc \u05e4\u05ea\u05d0\u05d5\u05dd \u05e0\u05e4\u05dc \u05dc\u05d9 \u05d4\u05d0\u05e1\u05d9\u05de\u05d5\u05df - \u05d0\u05d5\u05dc\u05d9 \u05d6\u05d4 \u05d1\u05db\u05dc\u05dc \u05dc\u05d0 \u05d0\u05d9\u05d5\u05dd. \u05d0\u05d5\u05dc\u05d9 \u05d6\u05d4 \u05e4\u05e9\u05d5\u05d8 \u05ea\u05d9\u05d0\u05d5\u05e8 \u05e9\u05dc \u05de\u05d4 \u05e9\u05e7\u05d5\u05e8\u05d4 \u05dc\u05e0\u05d5 \u05d1\u05e4\u05e0\u05d9\u05dd.\n\u05db\u05e9\u05d0\u05e0\u05d7\u05e0\u05d5 \u05de\u05d3\u05e7\u05dc\u05de\u05d9\u05dd \u05ea\u05e4\u05d9\u05dc\u05d4 \u05d1\u05dc\u05d9 \u05dc\u05d4\u05d9\u05d5\u05ea \u05e9\u05dd, \u05d0\u05e0\u05d7\u05e0\u05d5 \u05e0\u05e9\u05d0\u05e8\u05d9\u05dd \u05e8\u05d9\u05e7\u05d9\u05dd. \u05d7\u05e1\u05e8\u05d9 \u05d7\u05d9\u05d1\u05d5\u05e8. \u05d4\u05ea\u05d7\u05d5\u05e9\u05d4 \u05d4\u05d6\u05d5, \u05e9\u05dc \u05e0\u05d9\u05ea\u05d5\u05e7, \u05d9\u05db\u05d5\u05dc\u05d4 \u05dc\u05d4\u05d5\u05d1\u05d9\u05dc \u05dc\u05e2\u05d5\u05d3 \u05e0\u05d9\u05ea\u05d5\u05e7. \u05e2\u05d5\u05d3 \u05e2\u05dc \u05db\u05da \u05d1\u05d4\u05de\u05e9\u05da \u05d4\u05e4\u05e8\u05e7 \u05e2\u05dc \u05e9\u05de\u05df \u05d4\u05d8\u05d5\u05d1 \u05ea\u05e8\u05d9\u05e7 \u05e2\u05dc \u05e9\u05d1\u05e2\u05ea \u05e7\u05e0\u05d9 \u05d4\u05de\u05e0\u05d5\u05e8\u05d4\n\u05d6\u05d4 \u05de\u05d4 \u05e9\u05d4\u05d7\u05e1\u05d9\u05d3\u05d5\u05ea \u05d0\u05d5\u05dc\u05d9 \u05e0\u05d9\u05e1\u05ea\u05d4 \u05dc\u05d4\u05d2\u05d9\u05d3; \u05dc\u05d0 \u05e9\u05d0\u05dc\u05d5\u05d4\u05d9\u05dd \u05d9\u05db\u05e2\u05e1, \u05d0\u05dc\u05d0 \u05e9\u05e4\u05e9\u05d5\u05d8 \u05d4\u05de\u05d5\u05d3\u05e2\u05d5\u05ea \u05e9\u05dc\u05e0\u05d5 \u05ea\u05ea\u05e8\u05d7\u05e7 \u05d0\u05dd \u05dc\u05d0 \u05e0\u05d4\u05d9\u05d4 \u05e0\u05d5\u05db\u05d7\u05d9\u05dd.\n\u05d0\u05d1\u05dc \u05d4\u05d7\u05d3\u05e9\u05d5\u05ea \u05d4\u05d8\u05d5\u05d1\u05d5\u05ea? \u05e9\u05d2\u05dd \u05d0\u05dd \u05de\u05e8\u05d2\u05d9\u05e9\u05d9\u05dd \u05d4\u05db\u05d9 \u05e8\u05d7\u05d5\u05e7, \u05d6\u05d4 \u05d1\u05d3\u05d9\u05d5\u05e7 \u05d4\u05de\u05e7\u05d5\u05dd \u05e9\u05de\u05de\u05e0\u05d5 \u05d0\u05e4\u05e9\u05e8 \u05dc\u05d4\u05ea\u05d7\u05d9\u05dc.\n\u05db\u05de\u05d5 \u05e9\u05d0\u05de\u05e8 \u05e8\u05d1\u05d9 \u05e0\u05d7\u05de\u05df: "\u05d0\u05dd \u05d0\u05ea\u05d4 \u05dc\u05d0 \u05de\u05e6\u05dc\u05d9\u05d7 \u05dc\u05d4\u05ea\u05e4\u05dc\u05dc \u05ea\u05ea\u05e4\u05dc\u05dc \u05e2\u05dc \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4, \u05e2\u05dc \u05d4\u05d7\u05d9\u05d1\u05d5\u05e8 \u05d5\u05e2\u05dc \u05ea\u05d7\u05d5\u05e9\u05ea \u05d4\u05e0\u05d5\u05db\u05d7\u05d5\u05ea. \u05ea\u05ea\u05e4\u05dc\u05dc \u05e9\u05ea\u05d6\u05db\u05d4 \u05dc\u05d4\u05ea\u05e4\u05dc\u05dc."\n\u05d2\u05dd \u05d4\u05e8\u05e6\u05d5\u05df, \u05d2\u05dd \u05d4\u05d7\u05d9\u05e4\u05d5\u05e9, \u05d2\u05dd \u05d4\u05d1\u05dc\u05d1\u05d5\u05dc \u05d4\u05dd \u05e1\u05d5\u05d2 \u05e9\u05dc \u05e7\u05e9\u05e8. \u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05d0\u05e4\u05d9\u05dc\u05d5 \u05d4\u05e7\u05e9\u05e8 \u05d4\u05d0\u05d5\u05dc\u05d8\u05d9\u05de\u05d8\u05d9\u05d1\u05d9. \u05d4\u05d1\u05e2\u05ea \u05e8\u05e6\u05d5\u05df \u05d4\u05dc\u05d1 \u05dc\u05e7\u05d9\u05e8\u05d1\u05d4. \u05dc\u05e8\u05d9\u05db\u05d5\u05d6 \u05dc\u05e0\u05d5\u05db\u05d7\u05d5\u05ea \u05d5\u05dc\u05d0\u05d5\u05e8 \u05e2\u05dc\u05d9\u05d5\u05df.  \u05db\u05de\u05d5 \u05e9\u05e0\u05e8\u05d7\u05d9\u05d1 \u05d1\u05e4\u05e8\u05e7 \u05e2\u05dc \u05d4\u05e7\u05d3\u05d5\u05e9\u05d4.\n\u05d1\u05e2\u05d5\u05dc\u05dd \u05d4\u05e8\u05d5\u05e2\u05e9 \u05d5\u05d4\u05ea\u05d5\u05d1\u05e2\u05e0\u05d9 \u05e9\u05d1\u05d5 \u05d0\u05e0\u05d5 \u05d7\u05d9\u05d9\u05dd, \u05e8\u05d2\u05e2\u05d9\u05dd \u05e9\u05dc \u05e9\u05e7\u05d8 \u05e4\u05e0\u05d9\u05de\u05d9 \u05d4\u05e4\u05db\u05d5 \u05dc\u05e0\u05db\u05e1 \u05e0\u05d3\u05d9\u05e8. \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4, \u05e2\u05dc \u05db\u05dc \u05e8\u05d1\u05d3\u05d9\u05d4, \u05e0\u05d5\u05ea\u05e8\u05d4 \u05e2\u05d1\u05d5\u05e8 \u05e8\u05d1\u05d9\u05dd \u05d8\u05e7\u05e1 \u05de\u05e1\u05d5\u05e8\u05ea\u05d9, \u05d0\u05da \u05dc\u05de\u05e2\u05e9\u05d4 \u05d4\u05d9\u05d0 \u05d9\u05db\u05d5\u05dc\u05d4 \u05dc\u05d4\u05d9\u05d5\u05ea \u05e9\u05e2\u05e8 \u05e2\u05d5\u05e6\u05de\u05ea\u05d9 \u05dc\u05de\u05e1\u05e2 \u05e8\u05d5\u05d7\u05e0\u05d9 \u05e2\u05de\u05d5\u05e7. \u05e1\u05e4\u05e8 \u05d6\u05d4 \u05e0\u05db\u05ea\u05d1 \u05de\u05ea\u05d5\u05da \u05d4\u05d1\u05e0\u05d4 \u05e9\u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d0\u05d9\u05e0\u05d4 \u05e8\u05e7 \u05de\u05d9\u05dc\u05d9\u05dd \u05d4\u05e0\u05d0\u05de\u05e8\u05d5\u05ea \u05d1\u05e7\u05e6\u05d1 \u05e9\u05d2\u05e8\u05ea\u05d9, \u05d0\u05dc\u05d0 \u05d7\u05d5\u05d5\u05d9\u05d4 \u05e9\u05dc \u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea, \u05d7\u05d9\u05d1\u05d5\u05e8, \u05d5\u05d4\u05ea\u05e2\u05dc\u05d5\u05ea.\n\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d1\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d4\u05d9\u05d0 \u05d3\u05e8\u05da \u05dc\u05d4\u05d7\u05d6\u05d9\u05e8 \u05d0\u05ea \u05d4\u05e0\u05e9\u05de\u05d4 \u05d0\u05dc \u05d4\u05de\u05e8\u05db\u05d6. \u05d1\u05de\u05e7\u05d5\u05dd \u05dc\u05d4\u05d9\u05e9\u05d0\u05e8 \u05d1\u05d2\u05d9\u05e9\u05d4 \u05de\u05db\u05e0\u05d9\u05ea, \u05d0\u05e0\u05d5 \u05dc\u05d5\u05de\u05d3\u05d9\u05dd \u05db\u05d9\u05e6\u05d3 \u05dc\u05e2\u05e6\u05d5\u05e8, \u05dc\u05d4\u05e7\u05e9\u05d9\u05d1, \u05d5\u05dc\u05ea\u05ea \u05dc\u05de\u05d9\u05dc\u05d5\u05ea \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05dc\u05d4\u05e4\u05d5\u05da \u05dc\u05db\u05dc\u05d9 \u05d8\u05e8\u05e0\u05e1\u05e4\u05d5\u05e8\u05de\u05d8\u05d9\u05d1\u05d9. \u05d3\u05e8\u05da \u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d1\u05ea\u05e4\u05d9\u05dc\u05d4, \u05db\u05dc\u05d5\u05de\u05e8 \u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea \u05d1\u05db\u05dc \u05de\u05d9\u05dc\u05d4 \u05db\u05d5\u05d5\u05e0\u05d5\u05ea \u05d4\u05d7\u05d9\u05d9\u05dd \u05de\u05ea\u05d7\u05d3\u05d3\u05d5\u05ea, \u05d5\u05d4\u05d7\u05d5\u05d5\u05d9\u05d4 \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9\u05ea \u05d4\u05d5\u05e4\u05db\u05ea \u05dc\u05de\u05e9\u05de\u05e2\u05d5\u05ea\u05d9\u05ea \u05d5\u05de\u05d7\u05d5\u05d1\u05e8\u05ea \u05d9\u05d5\u05ea\u05e8.\n\u05e1\u05e4\u05e8 \u05d6\u05d4 \u05de\u05d1\u05d5\u05e1\u05e1 \u05e2\u05dc \u05d7\u05d9\u05e4\u05d5\u05e9 \u05de\u05e2\u05de\u05d9\u05e7 \u05e9\u05dc\u05d9 \u05d0\u05e8\u05d5\u05da \u05e9\u05e0\u05d9\u05dd \u05d0\u05d7\u05e8 \u05db\u05d5\u05d5\u05e0\u05d4 \u05d5\u05d7\u05d9\u05d1\u05e8 \u05dc\u05ea\u05e4\u05d9\u05dc\u05d4. \u05e0\u05e2\u05d6\u05e8\u05ea\u05d9 \u05d1\u05de\u05e7\u05d5\u05e8\u05d5\u05ea \u05d9\u05d4\u05d5\u05d3\u05d9\u05d9\u05dd \u05e2\u05ea\u05d9\u05e7\u05d9\u05dd \u05dc\u05e6\u05d3 \u05ea\u05d5\u05d1\u05e0\u05d5\u05ea \u05d0\u05d9\u05e9\u05d9\u05d5\u05ea \u05e9\u05e2\u05dc\u05d5 \u05d0\u05e6\u05dc\u05d9 \u05d1\u05d6\u05de\u05df \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d5\u05e1\u05e4\u05e8\u05d5\u05ea \u05e2\u05db\u05e9\u05d5\u05d5\u05d9\u05ea \u05de\u05ea\u05d7\u05d5\u05dd \u05d4\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d5\u05d4\u05de\u05d5\u05d3\u05e2\u05d5\u05ea.\n\u05d4\u05e1\u05e4\u05e8 \u05de\u05d9\u05d5\u05e2\u05d3 \u05dc\u05db\u05dc \u05de\u05d9 \u05e9\u05de\u05d7\u05e4\u05e9 \u05dc\u05d4\u05e2\u05de\u05d9\u05e7 \u05d0\u05ea \u05ea\u05e4\u05d9\u05dc\u05ea\u05d5, \u05dc\u05d4\u05e4\u05d5\u05da \u05d0\u05d5\u05ea\u05d4 \u05dc\u05d0\u05d9\u05e9\u05d9\u05ea, \u05d7\u05d9\u05d5\u05e0\u05d9\u05ea \u05d5\u05de\u05e8\u05d2\u05e9\u05ea. \u05d1\u05d9\u05df \u05d4\u05d3\u05e4\u05d9\u05dd \u05ea\u05de\u05e6\u05d0\u05d5 \u05d4\u05e0\u05d7\u05d9\u05d5\u05ea \u05de\u05e2\u05e9\u05d9\u05d5\u05ea, \u05ea\u05e8\u05d2\u05d9\u05dc\u05d9\u05dd \u05e9\u05d9\u05e1\u05d9\u05d9\u05e2\u05d5 \u05dc\u05d4\u05e2\u05de\u05d9\u05e7 \u05d0\u05ea \u05d4\u05e7\u05e9\u05d1 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9, \u05d5\u05e8\u05e2\u05d9\u05d5\u05e0\u05d5\u05ea \u05e9\u05d9\u05e4\u05ea\u05d7\u05d5 \u05d3 \u05dc\u05ea\u05d5\u05ea \u05d7\u05d3\u05e9\u05d5\u05ea \u05d1\u05d4\u05d1\u05e0\u05ea \u05de\u05e9\u05de\u05e2\u05d5\u05ea \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4.\n\u05d1\u05d9\u05df \u05d0\u05dd \u05d0\u05ea\u05dd \u05d1\u05ea\u05d7\u05d9\u05dc\u05ea \u05d3\u05e8\u05db\u05db\u05dd \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9\u05ea \u05d5\u05d1\u05d9\u05df \u05d0\u05dd \u05d0\u05ea\u05dd \u05de\u05ea\u05e4\u05dc\u05dc\u05d9\u05dd \u05e9\u05e0\u05d9\u05dd \u05e8\u05d1\u05d5\u05ea, \u05d0\u05e0\u05d9 \u05de\u05d6\u05de\u05d9\u05e0\u05d4 \u05d0\u05ea\u05db\u05dd \u05dc\u05e6\u05d0\u05ea \u05dc\u05de\u05e1\u05e2 \u05d1\u05d5 \u05db\u05dc \u05de\u05d9\u05dc\u05d4 \u05d4\u05d5\u05e4\u05db\u05ea \u05dc\u05db\u05d9\u05d5\u05d5\u05e0\u05d5\u05df \u05d4\u05ea\u05d5\u05d3\u05e2\u05d4, \u05db\u05dc \u05e0\u05e9\u05d9\u05de\u05d4 \u05d4\u05d9\u05d0 \u05d7\u05d9\u05d1\u05d5\u05e8, \u05d5\u05db\u05dc \u05ea\u05e4\u05d9\u05dc\u05d4 \u05d4\u05d9\u05d0 \u05e9\u05e2\u05e8 \u05dc\u05d0\u05d9\u05e0\u05e1\u05d5\u05e3.\n\u05e4\u05e2\u05dd \u05d0\u05d7\u05ea \u05e7\u05e4\u05e6\u05d5 \u05dc\u05d9 \u05dc\u05e2\u05d9\u05df \u05d4\u05de\u05d9\u05dc\u05d9\u05dd \u05d4\u05e8\u05d9\u05e0\u05d9 \u05de\u05ea\u05e2\u05d8\u05e3 \u05d2\u05d5\u05e4\u05d9 \u05d1\u05e6\u05d9\u05e6\u05d9\u05ea. \u05db\u05de\u05d5\u05d1\u05df \u05d1\u05d4\u05d9\u05d5\u05ea\u05d9 \u05d0\u05d9\u05e9\u05d4 \u05d0\u05dc\u05d5 \u05de\u05d9\u05dc\u05d9\u05dd \u05e9\u05d0\u05d9\u05e0\u05df \u05e8\u05dc\u05d5\u05d5\u05e0\u05d8\u05d9\u05d5\u05ea \u05e2\u05d1\u05d5\u05e8\u05d9. \u05d0\u05da \u05e4\u05ea\u05d0\u05d5\u05dd \u05db\u05d0\u05e9\u05e8 \u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05ea\u05d9 \u05d1\u05de\u05d9\u05dc\u05d9\u05dd \u05d0\u05dc\u05d5 \u05d5\u05d7\u05e9\u05d1\u05ea\u05d9 \u05de\u05d4 \u05d4\u05e6\u05d9\u05e6\u05d9\u05ea \u05de\u05e1\u05de\u05dc\u05ea \u05dc\u05d2\u05d1\u05e8. \u05d4\u05ea\u05e2\u05d8\u05e4\u05d5\u05ea \u05d1\u05d0\u05d4\u05d1\u05ea \u05d4\u05d1\u05d5\u05e8\u05d0 \u05e7\u05e4\u05e6\u05d5 \u05dc\u05d9 \u05d4\u05de\u05d9\u05dc\u05d9\u05dd \u05d4\u05e0\u05e0\u05d9 \u05de\u05ea\u05e2\u05d8\u05e4\u05ea \u05d1\u05d0\u05d4\u05d1\u05ea \u05d4\u05d1\u05d5\u05e8\u05d0. \u05ea\u05df \u05dc\u05d9 \u05dc\u05d0\u05d4\u05d5\u05d1 \u05d0\u05d5\u05ea\u05da \u05d5\u05dc\u05d4\u05e8\u05d2\u05d9\u05e9 \u05d0\u05ea \u05d0\u05d4\u05d1\u05ea\u05da \u05db\u05d3\u05d9 \u05e9\u05d9\u05d4\u05d9\u05d4 \u05dc\u05d9 \u05db\u05d7 \u05dc\u05ea\u05ea \u05d0\u05d4\u05d1\u05d4 \u05dc\u05d9\u05dc\u05d3\u05d9\u05d9\u05da \u05d4\u05d0\u05d7\u05e8\u05d9\u05dd.\n\u05d1\u05d0\u05d4\u05d1\u05d4 \u05d5\u05d1\u05e8\u05db\u05d4 \u05dc\u05d4\u05e9\u05e8\u05d0\u05d4,\n\u05de\u05e8\u05d9\u05dd \u05d3\u05e8\u05d5\u05e8\u05d9',"","")
B.KU=new A.cv(2,"\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d9\u05d4\u05d5\u05d3\u05d9\u05ea: \u05ea\u05d4\u05dc\u05d9\u05da \u05e9\u05dc \u05e2\u05d9\u05d1\u05d5\u05d3 \u05d5\u05ea\u05d5\u05d1\u05e0\u05d4",'\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d9\u05d4\u05d5\u05d3\u05d9\u05ea: \u05ea\u05d4\u05dc\u05d9\u05da \u05e9\u05dc \u05e2\u05d9\u05d1\u05d5\u05d3 \u05d5\u05ea\u05d5\u05d1\u05e0\u05d4\n\u05d6\u05de\u05df \u05dc\u05d4\u05ea\u05e2\u05dc\u05d5\u05ea \u05d0\u05dc \u05e2\u05d5\u05dc\u05dd \u05e9\u05db\u05d5\u05dc\u05d5 \u05d8\u05d5\u05d1\n\u05d7\u05db\u05de\u05d9\u05e0\u05d5 \u05d6"\u05dc \u05e0\u05d4\u05d2\u05d5 \u05dc\u05e9\u05d4\u05d5\u05ea \u05e9\u05e2\u05d4 \u05dc\u05e4\u05e0\u05d9 \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d5\u05e9\u05e2\u05d4 \u05d0\u05d7\u05e8\u05d9\u05d4. \u05de\u05d4 \u05e2\u05e9\u05d5 \u05d1\u05d6\u05de\u05df \u05d6\u05d4?\n\u05d6\u05d5\u05d4\u05d9 \u05e9\u05d0\u05dc\u05d4 \u05de\u05e9\u05de\u05e2\u05d5\u05ea\u05d9\u05ea, \u05d5\u05de\u05e2\u05e0\u05d4 \u05dc\u05d4 \u05d9\u05db\u05d5\u05dc \u05dc\u05d4\u05e2\u05e9\u05d9\u05e8 \u05d0\u05ea \u05d4\u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05e9\u05dc\u05e0\u05d5. \u05d1\u05d1\u05d5\u05d0\u05e0\u05d5 \u05dc\u05d4\u05e2\u05de\u05d9\u05e7 \u05d1\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d9\u05d4\u05d5\u05d3\u05d9\u05ea, \u05e0\u05d5\u05db\u05dc \u05dc\u05e9\u05d0\u05d5\u05dc \u05d0\u05ea \u05e2\u05e6\u05de\u05e0\u05d5: \u05de\u05d4 \u05d0\u05e0\u05d7\u05e0\u05d5 \u05de\u05d1\u05e7\u05e9\u05d9\u05dd \u05dc\u05d4\u05e9\u05d9\u05d2?\n\u05d4\u05d0\u05dd \u05d1\u05e8\u05e6\u05d5\u05e0\u05da \u05dc\u05e4\u05e0\u05d5\u05ea \u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05d8\u05d5\u05e8\u05d3\u05e0\u05d9\u05d5\u05ea? \u05d0\u05d5 \u05e9\u05de\u05d0 \u05dc\u05d4\u05d8\u05de\u05d9\u05e2 \u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05e8\u05e6\u05d5\u05d9\u05d5\u05ea \u05d5\u05ea\u05d5\u05de\u05db\u05d5\u05ea?\n\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d5\u05ea \u05de\u05d4\u05e2\u05d5\u05dc\u05dd \u05de\u05d5\u05dc \u05d4\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9\u05ea\n\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d5\u05ea \u05e8\u05d1\u05d5\u05ea \u05de\u05ea\u05de\u05e7\u05d3\u05d5\u05ea \u05d1\u05d4\u05e4\u05d2\u05ea \u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05e9\u05dc\u05d9\u05dc\u05d9\u05d5\u05ea \u05d0\u05d5 \u05d1\u05d4\u05e7\u05e0\u05d9\u05d9\u05ea \u05ea\u05e9\u05d5\u05de\u05ea \u05dc\u05d1 \u05dc\u05ea\u05d4\u05dc\u05d9\u05da \u05d4\u05d7\u05e9\u05d9\u05d1\u05d4. \u05d0\u05da \u05d4\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9\u05ea \u05dc\u05d5\u05e7\u05d7\u05ea \u05d0\u05d5\u05ea\u05e0\u05d5 \u05e6\u05e2\u05d3 \u05e7\u05d3\u05d9\u05de\u05d4: \u05d4\u05d9\u05d0 \u05d0\u05d9\u05e0\u05d4 \u05e2\u05d5\u05e6\u05e8\u05ea \u05e8\u05e7 \u05d1\u05e0\u05d9\u05d8\u05d5\u05e8 \u05d0\u05d5 \u05d1\u05e9\u05d7\u05e8\u05d5\u05e8 \u05de\u05d7\u05e9\u05d1\u05d5\u05ea, \u05d0\u05dc\u05d0 \u05de\u05d1\u05e7\u05e9\u05ea \u05dc\u05e9\u05e0\u05d5\u05ea\u05df \u05dc\u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05d7\u05d9\u05d5\u05d1\u05d9\u05d5\u05ea, \u05ea\u05d5\u05de\u05db\u05d5\u05ea \u05d5\u05e4\u05e8\u05d5\u05d3\u05d5\u05e7\u05d8\u05d9\u05d1\u05d9\u05d5\u05ea.\n\u05db\u05d3\u05d9 \u05dc\u05e2\u05e9\u05d5\u05ea \u05d6\u05d0\u05ea, \u05d4\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9\u05ea \u05e2\u05d5\u05d1\u05e8\u05ea \u05d3\u05e8\u05da \u05e9\u05dc\u05d1\u05d9\u05dd:\n\u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea \u05d1\u05dc\u05ea\u05d9 \u05d1\u05d9\u05e7\u05d5\u05e8\u05ea\u05d9\u05ea \u05d1\u05de\u05d7\u05e9\u05d1\u05d5\u05ea.\n\u05d1\u05e9\u05dc\u05d1 \u05d4\u05e8\u05d0\u05e9\u05d5\u05df, \u05d0\u05e0\u05d5 \u05e0\u05d5\u05ea\u05e0\u05d9\u05dd \u05dc\u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05dc\u05d6\u05e8\u05d5\u05dd \u05de\u05d1\u05dc\u05d9 \u05dc\u05e9\u05e4\u05d5\u05d8 \u05d0\u05d5\u05ea\u05df.\n\u05d1\u05d7\u05d9\u05e0\u05d4 \u05d5\u05d1\u05d9\u05e7\u05d5\u05e8\u05ea.\n\u05dc\u05d0\u05d7\u05e8 \u05de\u05db\u05df, \u05d0\u05e0\u05d5 \u05d1\u05d5\u05d3\u05e7\u05d9\u05dd \u05d0\u05d9\u05dc\u05d5 \u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05de\u05d5\u05d6\u05de\u05e0\u05d5\u05ea \u05dc\u05d4\u05d9\u05e9\u05d0\u05e8 \u05d5\u05d0\u05d9\u05dc\u05d5 \u05d3\u05d5\u05e8\u05e9\u05d5\u05ea \u05e9\u05d9\u05e0\u05d5\u05d9.\n\u05de\u05d4 \u05e2\u05e9\u05d5 \u05d7\u05db\u05de\u05d9\u05e0\u05d5 \u05d1\u05e9\u05e2\u05d5\u05ea \u05d0\u05dc\u05d5?\n\u05d7\u05db\u05de\u05d9\u05e0\u05d5 \u05e0\u05d9\u05e6\u05dc\u05d5 \u05d0\u05ea \u05d4\u05d6\u05de\u05df \u05db\u05d3\u05d9 \u05dc\u05d0\u05e8\u05d2\u05df \u05d0\u05ea \u05de\u05d7\u05e9\u05d1\u05d5\u05ea\u05d9\u05d4\u05dd \u05d5\u05dc\u05d4\u05e4\u05d5\u05da \u05d0\u05d5\u05ea\u05df \u05dc\u05d7\u05d9\u05d5\u05d1\u05d9\u05d5\u05ea. \u05d4\u05dd \u05e2\u05e9\u05d5 \u05d6\u05d0\u05ea \u05d1\u05d0\u05de\u05e6\u05e2\u05d5\u05ea \u05d8\u05db\u05e0\u05d9\u05e7\u05d5\u05ea \u05e9\u05d5\u05e0\u05d5\u05ea, \u05d5\u05d1\u05d4\u05df:\n\u05d9\u05e9\u05d9\u05d1\u05d4 \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05de\u05d6\u05e8\u05d7.\n\u05ea\u05e0\u05d5\u05d7\u05d4 \u05d6\u05d5 \u05e0\u05d7\u05e9\u05d1\u05ea \u05ea\u05d5\u05de\u05db\u05ea \u05d1\u05d4\u05ea\u05db\u05d5\u05d5\u05e0\u05d5\u05ea \u05d7\u05d9\u05d5\u05d1\u05d9\u05ea, \u05e2\u05dc\u05d9\u05d4\u05dd \u05d0\u05e8\u05d7\u05d9\u05d1 \u05d1\u05d4\u05de\u05e9\u05da.',"","")
B.KY=new A.cv(3,"\u05d1\u05e8\u05db\u05d5\u05ea \u05d4\u05ea\u05d5\u05e8\u05d4: \u05d4\u05db\u05e8\u05ea \u05ea\u05d5\u05d3\u05d4 \u05d5\u05d3\u05e8\u05da \u05d4\u05d7\u05d9\u05d9\u05dd","\u05e4\u05e8\u05e7: \u05d1\u05e8\u05db\u05d5\u05ea \u05d4\u05ea\u05d5\u05e8\u05d4 \u2013 \u05d4\u05db\u05e8\u05ea \u05ea\u05d5\u05d3\u05d4 \u05d5\u05d3\u05e8\u05da \u05d4\u05d7\u05d9\u05d9\u05dd\n\u05dc\u05e2\u05e1\u05d5\u05e7 \u05d1\u05d3\u05d1\u05e8\u05d9 \u05ea\u05d5\u05e8\u05d4 \u05d4\u05d5\u05d0 \u05de\u05ea\u05e0\u05d4 \u05e9\u05d0\u05d9\u05df \u05dc\u05d4 \u05ea\u05d7\u05dc\u05d9\u05e3. \u05d0\u05e0\u05d9 \u05de\u05d5\u05e6\u05d0\u05ea \u05d0\u05ea \u05e2\u05e6\u05de\u05d9 \u05e4\u05e2\u05de\u05d9\u05dd \u05e8\u05d1\u05d5\u05ea \u05de\u05d5\u05d3\u05d4 \u05dc\u05e9\u05dd \u05e2\u05dc \u05e9\u05e0\u05d9 \u05d3\u05d1\u05e8\u05d9\u05dd \u05e2\u05d9\u05e7\u05e8\u05d9\u05d9\u05dd: \u05e8\u05d0\u05e9\u05d9\u05ea, \u05e2\u05dc \u05d4\u05d0\u05e4\u05e9\u05e8\u05d5\u05ea \u05dc\u05dc\u05de\u05d5\u05d3 \u05ea\u05d5\u05e8\u05d4, \u05dc\u05d4\u05e2\u05de\u05d9\u05e7 \u05d1\u05de\u05e7\u05d5\u05e8\u05d5\u05ea, \u05dc\u05d4\u05d1\u05d9\u05df \u05d0\u05ea \u05e2\u05d5\u05de\u05e7 \u05d7\u05db\u05de\u05ea \u05d4\u05e2\u05dd \u05e9\u05dc\u05e0\u05d5; \u05d5\u05e9\u05e0\u05d9\u05ea, \u05e2\u05dc \u05d4\u05d0\u05e4\u05e9\u05e8\u05d5\u05ea \u05dc\u05d3\u05e2\u05ea \u05d0\u05ea \u05d3\u05e8\u05da \u05d4\u05ea\u05d5\u05e8\u05d4 \u05d1\u05d7\u05d9\u05d9 \u2013 \u05dc\u05d0 \u05e8\u05e7 \u05db\u05d9\u05d3\u05e2 \u05ea\u05d9\u05d0\u05d5\u05e8\u05d8\u05d9, \u05d0\u05dc\u05d0 \u05db\u05d3\u05e8\u05da \u05de\u05e2\u05e9\u05d9\u05ea, \u05db\u05d3\u05e8\u05da \u05d7\u05d9\u05d9\u05dd \u05e9\u05de\u05dc\u05d5\u05d5\u05d4 \u05d0\u05d5\u05ea\u05d9 \u05d1\u05db\u05dc \u05d9\u05d5\u05dd.\n\u05dc\u05dc\u05de\u05d5\u05d3 \u05ea\u05d5\u05e8\u05d4 \u05de\u05e2\u05e0\u05d9\u05e7 \u05dc\u05d9 \u05d9\u05d5\u05ea\u05e8 \u05de\u05d4\u05d1\u05e0\u05d4 \u05e9\u05dc \u05d7\u05d5\u05e7\u05d9\u05dd \u05d5\u05de\u05e6\u05d5\u05d5\u05ea. \u05d6\u05d4 \u05de\u05d7\u05d1\u05e8 \u05d0\u05d5\u05ea\u05d9 \u05dc\u05d3\u05e8\u05da \u05d7\u05d9\u05d9\u05dd, \u05dc\u05e2\u05e8\u05db\u05d9\u05dd \u05d5\u05dc\u05de\u05d8\u05e8\u05d5\u05ea \u05e9\u05de\u05d2\u05d3\u05d9\u05e8\u05d9\u05dd \u05d0\u05ea \u05e7\u05d9\u05d5\u05de\u05e0\u05d5. \u05d0\u05da \u05d7\u05e9\u05d5\u05d1 \u05dc\u05d0 \u05e4\u05d7\u05d5\u05ea, \u05dc\u05d3\u05e2\u05ea \u05dc\u05d4\u05d7\u05d9\u05dc \u05d0\u05ea \u05d4\u05ea\u05d5\u05e8\u05d4 \u05d1\u05d7\u05d9\u05d9 \u05d4\u05d0\u05d9\u05e9\u05d9\u05d9\u05dd \u2013 \u05dc\u05d4\u05d9\u05d5\u05ea \u05e2\u05e1\u05d5\u05e7\u05d4 \u05d1\u05de\u05e2\u05e9\u05d9\u05dd \u05d8\u05d5\u05d1\u05d9\u05dd, \u05d1\u05e8\u05d7\u05de\u05d9\u05dd \u05d5\u05d1\u05d7\u05de\u05dc\u05d4, \u05d1\u05d4\u05ea\u05e0\u05d4\u05d2\u05d5\u05ea \u05d4\u05d9\u05d5\u05de\u05d9\u05d5\u05de\u05d9\u05ea, \u05d1\u05d4\u05d7\u05dc\u05d8\u05d5\u05ea \u05d4\u05e7\u05d8\u05e0\u05d5\u05ea \u05d5\u05d4\u05d2\u05d3\u05d5\u05dc\u05d5\u05ea \u05db\u05d0\u05d7\u05d3.\n\u05d4\u05db\u05e8\u05ea \u05d4\u05ea\u05d5\u05d3\u05d4 \u05d4\u05d6\u05d5 \u05d0\u05d9\u05e0\u05d4 \u05e8\u05e7 \u05e8\u05d2\u05e2 \u05e9\u05dc \u05d4\u05e8\u05d4\u05d5\u05e8. \u05d4\u05d9\u05d0 \u05e4\u05d5\u05ea\u05d7\u05ea \u05d3\u05dc\u05ea \u05e4\u05e0\u05d9\u05de\u05d9\u05ea: \u05d4\u05d9\u05d0 \u05de\u05d6\u05db\u05d9\u05e8\u05d4 \u05dc\u05d9 \u05e9\u05d4\u05d7\u05d9\u05d9\u05dd \u05e2\u05e6\u05de\u05dd \u05d4\u05dd \u05d4\u05d6\u05d3\u05de\u05e0\u05d5\u05ea \u05dc\u05dc\u05de\u05d5\u05d3, \u05dc\u05ea\u05e7\u05df, \u05dc\u05d2\u05d3\u05d5\u05dc, \u05d5\u05dc\u05d7\u05d9\u05d5\u05ea \u05dc\u05e4\u05d9 \u05e2\u05e7\u05e8\u05d5\u05e0\u05d5\u05ea \u05d4\u05ea\u05d5\u05e8\u05d4 \u05d4\u05e7\u05d3\u05d5\u05e9\u05d4. \u05d1\u05db\u05dc \u05d9\u05d5\u05dd, \u05d1\u05db\u05dc \u05e4\u05e2\u05d5\u05dc\u05d4, \u05d1\u05db\u05dc \u05de\u05e4\u05d2\u05e9 \u05e2\u05dd \u05d4\u05d6\u05d5\u05dc\u05ea, \u05d0\u05e0\u05d9 \u05de\u05d5\u05d6\u05de\u05e0\u05ea \u05dc\u05d1\u05d7\u05d5\u05e8 \u05d1\u05d3\u05e8\u05da \u05e9\u05de\u05d7\u05d1\u05e8\u05ea \u05d0\u05d5\u05ea\u05d9 \u05dc\u05e2\u05d5\u05de\u05e7, \u05dc\u05d7\u05db\u05de\u05d4, \u05d5\u05dc\u05d4\u05e9\u05e8\u05d0\u05d4 \u05e9\u05de\u05d2\u05d9\u05e2\u05d4 \u05e8\u05e7 \u05d3\u05e8\u05da \u05d4\u05d4\u05ea\u05e2\u05e1\u05e7\u05d5\u05ea \u05d1\u05e2\u05d5\u05dc\u05de\u05d5\u05ea \u05d4\u05e8\u05d5\u05d7 \u05d5\u05d4\u05de\u05e2\u05e9\u05d4 \u05d9\u05d7\u05d3.\n\u05db\u05da, \u05d1\u05e8\u05db\u05ea \u05d4\u05ea\u05d5\u05e8\u05d4 \u05d4\u05d9\u05d0 \u05dc\u05d0 \u05e8\u05e7 \u05de\u05d9\u05dc\u05d9\u05dd \u05e9\u05dc \u05ea\u05d5\u05d3\u05d4 \u2013 \u05d4\u05d9\u05d0 \u05ea\u05d6\u05db\u05d5\u05e8\u05ea \u05dc\u05d7\u05d9\u05d9\u05dd \u05e9\u05dc \u05de\u05d5\u05d3\u05e2\u05d5\u05ea, \u05e9\u05dc \u05db\u05d5\u05d5\u05e0\u05d4 \u05d5\u05e9\u05dc \u05d9\u05d9\u05e9\u05d5\u05dd. \u05d4\u05d9\u05d0 \u05d4\u05d3\u05e8\u05da \u05d1\u05d4 \u05d0\u05e0\u05d9 \u05de\u05d7\u05d1\u05e8\u05ea \u05d1\u05d9\u05df \u05d4\u05dc\u05d1 \u05dc\u05de\u05d7\u05e9\u05d1\u05d4, \u05d1\u05d9\u05df \u05dc\u05de\u05d9\u05d3\u05d4 \u05dc\u05de\u05e2\u05e9\u05d4, \u05d1\u05d9\u05df \u05d9\u05d3\u05e2 \u05dc\u05d7\u05d9\u05d9\u05dd.","\u05ea\u05e8\u05d2\u05d5\u05dc \u05d7\u05d9\u05d1\u05d5\u05e8 \u05dc\u05d1\u05e8\u05db\u05ea \u05d4\u05ea\u05d5\u05e8\u05d4",'\u05e9\u05e7\u05d8 \u05d5\u05d4\u05db\u05e0\u05d4 \u2013 \u05e9\u05d1\u05d5 \u05d1\u05de\u05e7\u05d5\u05dd \u05e9\u05e7\u05d8, \u05e2\u05e6\u05de\u05d5 \u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05d5\u05e7\u05d7\u05d5 \u05db\u05de\u05d4 \u05e0\u05e9\u05d9\u05de\u05d5\u05ea \u05e2\u05de\u05d5\u05e7\u05d5\u05ea  \u05db\u05d3\u05d9 \u05dc\u05d4\u05d1\u05d9\u05d0 \u05d0\u05ea \u05d4\u05d2\u05d5\u05e3 \u05d5\u05d4\u05e0\u05e4\u05e9 \u05dc\u05e8\u05d9\u05db\u05d5\u05d6\n\u05d4\u05db\u05e8\u05ea \u05ea\u05d5\u05d3\u05d4 \u05e2\u05dc \u05d4\u05dc\u05de\u05d9\u05d3\u05d4 \u2013 \u05d7\u05d6\u05e8\u05d5 \u05dc\u05e2\u05e6\u05de\u05db\u05dd \u05e2\u05dc \u05d4\u05de\u05e9\u05e4\u05d8:\n"\u05d0\u05e0\u05d9 \u05de\u05d5\u05d3\u05d4 \u05e2\u05dc \u05d4\u05d0\u05e4\u05e9\u05e8\u05d5\u05ea \u05dc\u05dc\u05de\u05d5\u05d3 \u05ea\u05d5\u05e8\u05d4 \u05d5\u05dc\u05d4\u05e2\u05de\u05d9\u05e7 \u05d1\u05d7\u05db\u05de\u05d4 \u05d4\u05e7\u05d3\u05d5\u05e9\u05d4."\n\u05d4\u05e8\u05e9\u05d5 \u05dc\u05de\u05d9\u05dc\u05d9\u05dd \u05dc\u05d4\u05ea\u05e4\u05e9\u05d8 \u05d1\u05dc\u05d1, \u05d5\u05dc\u05d4\u05d6\u05db\u05d9\u05e8 \u05dc\u05db\u05dd \u05d0\u05ea \u05d4\u05de\u05ea\u05e0\u05d4 \u05e9\u05d1\u05d9\u05d3\u05db\u05dd.\n\u05d4\u05db\u05e8\u05ea \u05ea\u05d5\u05d3\u05d4 \u05e2\u05dc \u05d4\u05d9\u05d9\u05e9\u05d5\u05dd \u05d1\u05d7\u05d9\u05d9 \u2013 \u05e2\u05db\u05e9\u05d9\u05d5 \u05d4\u05d5\u05e1\u05d9\u05e4\u05d5 \u05d0\u05ea \u05d4\u05de\u05e9\u05e4\u05d8:\n"\u05d0\u05e0\u05d9 \u05de\u05d5\u05d3\u05d4 \u05e2\u05dc \u05d4\u05d0\u05e4\u05e9\u05e8\u05d5\u05ea \u05dc\u05d9\u05d9\u05e9\u05dd \u05d0\u05ea \u05d3\u05e8\u05da \u05d4\u05ea\u05d5\u05e8\u05d4 \u05d1\u05d7\u05d9\u05d9, \u05d1\u05de\u05e2\u05e9\u05d9\u05dd \u05d8\u05d5\u05d1\u05d9\u05dd \u05d5\u05d1\u05d7\u05d9\u05d9 \u05d4\u05d9\u05d5\u05dd\u05be\u05d9\u05d5\u05dd."\n\u05d7\u05e9\u05d1\u05d5 \u05e2\u05dc \u05d3\u05d5\u05d2\u05de\u05d4 \u05d9\u05d5\u05de\u05d9\u05d5\u05de\u05d9\u05ea \u05d0\u05d7\u05ea \u05e9\u05d1\u05d4 \u05ea\u05d5\u05db\u05dc\u05d5 \u05dc\u05d1\u05d7\u05d5\u05e8 \u05d1\u05d3\u05e8\u05da \u05d4\u05ea\u05d5\u05e8\u05d4 \u2013 \u05de\u05e2\u05e9\u05d4 \u05e7\u05d8\u05df \u05e9\u05dc \u05d7\u05e1\u05d3, \u05e1\u05d1\u05dc\u05e0\u05d5\u05ea, \u05d0\u05d5 \u05de\u05d9\u05dc\u05d4 \u05d8\u05d5\u05d1\u05d4.\n\u05e7\u05e9\u05e8 \u05d1\u05d9\u05df \u05d4\u05dc\u05d1 \u05dc\u05de\u05e2\u05e9\u05d4 \u2013 \u05db\u05ea\u05d1\u05d5 \u05d1\u05e8\u05e9\u05d9\u05de\u05d4 \u05e7\u05e6\u05e8\u05d4 \u05e9\u05dc\u05d5\u05e9 \u05d3\u05e8\u05db\u05d9\u05dd \u05d1\u05d4\u05df \u05ea\u05d5\u05db\u05dc\u05d5 \u05dc\u05d4\u05d1\u05d9\u05d0 \u05d0\u05ea \u05d7\u05db\u05de\u05ea \u05d4\u05ea\u05d5\u05e8\u05d4 \u05dc\u05e4\u05e2\u05d5\u05dc\u05d4 \u05d4\u05d9\u05d5\u05dd, \u05d2\u05dd \u05d1\u05de\u05e6\u05d1\u05d9\u05dd \u05e4\u05e9\u05d5\u05d8\u05d9\u05dd \u05d5\u05d2\u05dd \u05d1\u05de\u05d5\u05e8\u05db\u05d1\u05d9\u05dd.\n\u05e1\u05d9\u05d9\u05de\u05d5 \u05d1\u05e0\u05e9\u05d9\u05de\u05d4 \u05e2\u05de\u05d5\u05e7\u05d4, \u05d4\u05d0\u05e8\u05d9\u05db\u05d5 \u05d0\u05d5\u05ea\u05d4 \u05d5\u05d4\u05e8\u05d2\u05d9\u05e9\u05d5 \u05d0\u05ea \u05d4\u05db\u05e8\u05ea \u05d4\u05ea\u05d5\u05d3\u05d4 \u05d6\u05d5\u05e8\u05de\u05ea \u05d1\u05db\u05dc \u05d2\u05d5\u05e4\u05db\u05dd. \u05d0\u05de\u05e8\u05d5 \u05d1\u05dc\u05d1:\n"\u05d3\u05e8\u05da \u05d4\u05ea\u05d5\u05e8\u05d4 \u05d0\u05e0\u05d9 \u05d2\u05d3\u05dc\u05d4, \u05d0\u05e0\u05d9 \u05de\u05ea\u05e7\u05d3\u05de\u05ea, \u05d5\u05d0\u05e0\u05d9 \u05de\u05e7\u05e8\u05d9\u05e0\u05d4 \u05d0\u05d5\u05e8 \u05e2\u05dc \u05e2\u05d5\u05dc\u05de\u05d9 \u05d5\u05e2\u05dc \u05d0\u05d7\u05e8\u05d9\u05dd."')
B.KP=new A.cv(4,"\u05db\u05e9\u05de\u05df \u05d4\u05d8\u05d5\u05d1 \u05e2\u05dc \u05d4\u05e8\u05d0\u05e9: \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05db\u05d9\u05e8\u05d9\u05d3\u05ea \u05e9\u05e4\u05e2",'\u05e4\u05e8\u05e7: \u05db\u05e9\u05de\u05df \u05d4\u05d8\u05d5\u05d1 \u05e2\u05dc \u05d4\u05e8\u05d0\u05e9 \u2013 \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05db\u05d9\u05e8\u05d9\u05d3\u05ea \u05e9\u05e4\u05e2 \u05de\u05df \u05d4\u05e0\u05e9\u05d2\u05d1 \u05d0\u05dc \u05d4\u05de\u05d9\u05d3\u05d5\u05ea\n\u05d5\u05e9\u05de\u05df \u05d4\u05d8\u05d5\u05d1 \u05d9\u05e8\u05d9\u05e7 \u05e2\u05dc \u05e9\u05d1\u05e2\u05d4 \u05e7\u05e0\u05d9 \u05d4\u05de\u05e0\u05d5\u05e8\u05d4\u201d\n\u05d4\u05d5\u05d0 \u05ea\u05d9\u05d0\u05d5\u05e8 \u05e2\u05de\u05d5\u05e7 \u05e9\u05dc \u05ea\u05e0\u05d5\u05e2\u05ea \u05d7\u05d9\u05d9\u05dd: \u05de\u05df \u05d4\u05e0\u05e9\u05d2\u05d1 \u05d0\u05dc \u05d4\u05de\u05de\u05e9\u05d9, \u05de\u05df \u05d4\u05d0\u05d5\u05e8 \u05d4\u05e2\u05dc\u05d9\u05d5\u05df \u05d0\u05dc \u05d9\u05de\u05d9 \u05d4\u05d7\u05d5\u05dc, \u05de\u05df \u05d4\u05d4\u05e9\u05e8\u05d0\u05d4 \u05d0\u05dc \u05d4\u05de\u05e2\u05e9\u05d4.\n\u05d4\u05e9\u05de\u05df \u2013 \u05d1\u05e0\u05d9\u05d2\u05d5\u05d3 \u05dc\u05d0\u05d5\u05e8 \u2013 \u05d0\u05d9\u05e0\u05e0\u05d5 \u05de\u05d0\u05d9\u05e8 \u05de\u05e2\u05e6\u05de\u05d5. \u05d4\u05d5\u05d0 \u05d7\u05d5\u05de\u05e8 \u05d2\u05dc\u05dd \u05e9\u05e7\u05d8, \u05e1\u05de\u05d5\u05d9, \u05d8\u05e2\u05d5\u05df \u05e4\u05d5\u05d8\u05e0\u05e6\u05d9\u05d0\u05dc. \u05e8\u05e7 \u05db\u05d0\u05e9\u05e8 \u05d4\u05d5\u05d0 \u05e0\u05de\u05e9\u05da, \u05e0\u05e9\u05e4\u05da \u05d5\u05de\u05d5\u05d6\u05df \u05d0\u05dc \u05d4\u05e7\u05e0\u05d9\u05dd \u2013 \u05de\u05ea\u05d2\u05dc\u05d4 \u05d4\u05d0\u05d5\u05e8. \u05db\u05da \u05d2\u05dd \u05d4\u05e9\u05e4\u05e2 \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9: \u05d0\u05d9\u05e0\u05d5 \u05e4\u05d5\u05dc\u05e9, \u05d0\u05dc\u05d0 \u05de\u05de\u05ea\u05d9\u05df \u05dc\u05db\u05dc\u05d9. \u05dc\u05d0 \u05d3\u05d9 \u05d1\u05d0\u05d5\u05e8 \u05e9\u05de\u05d9\u05de\u05d9; \u05e0\u05d3\u05e8\u05e9 \u05db\u05dc\u05d9 \u05d0\u05e0\u05d5\u05e9\u05d9 \u05de\u05d3\u05d5\u05d9\u05e7.\n\u05e9\u05d1\u05e2\u05ea \u05d4\u05e7\u05e0\u05d9\u05dd \u2013 \u05e9\u05d1\u05e2 \u05d4\u05e1\u05e4\u05d9\u05e8\u05d5\u05ea \u05e9\u05d1\u05d0\u05d3\u05dd\n\u05e9\u05d1\u05e2\u05ea \u05e7\u05e0\u05d9 \u05d4\u05de\u05e0\u05d5\u05e8\u05d4 \u05de\u05db\u05d5\u05bc\u05d5\u05e0\u05d9\u05dd \u05db\u05e0\u05d2\u05d3 \u05e9\u05d1\u05e2 \u05d4\u05de\u05d9\u05d3\u05d5\u05ea, \u05e9\u05d1\u05e2 \u05d4\u05e1\u05e4\u05d9\u05e8\u05d5\u05ea \u05d4\u05e4\u05d5\u05e2\u05dc\u05d5\u05ea \u05d1\u05e0\u05e4\u05e9:\n\u05d7\u05e1\u05d3 \u2013 \u05d4\u05d9\u05db\u05d5\u05dc\u05ea \u05dc\u05d4\u05d9\u05e4\u05ea\u05d7, \u05dc\u05d4\u05e2\u05e0\u05d9\u05e7, \u05dc\u05d0\u05d4\u05d5\u05d1.\n\u05d2\u05d1\u05d5\u05e8\u05d4 \u2013 \u05d4\u05d9\u05db\u05d5\u05dc\u05ea \u05dc\u05d4\u05e6\u05d9\u05d1 \u05d2\u05d1\u05d5\u05dc, \u05dc\u05d1\u05d7\u05d5\u05e8, \u05dc\u05d3\u05d9\u05d9\u05e7.\n\u05ea\u05e4\u05d0\u05e8\u05ea \u2013 \u05d4\u05d0\u05d9\u05d6\u05d5\u05df \u05d4\u05d7\u05d9 \u05d1\u05d9\u05df \u05e0\u05ea\u05d9\u05e0\u05d4 \u05dc\u05de\u05e9\u05de\u05e2\u05ea.\n\u05e0\u05e6\u05d7 \u2013 \u05d4\u05ea\u05de\u05d3\u05d4, \u05d0\u05d5\u05de\u05e5, \u05d4\u05dc\u05d9\u05db\u05d4 \u05e7\u05d3\u05d9\u05de\u05d4 \u05d2\u05dd \u05db\u05e9\u05e7\u05e9\u05d4.\n\u05d4\u05d5\u05d3 \u2013 \u05d4\u05e7\u05e9\u05d1\u05d4, \u05e2\u05e0\u05d5\u05d5\u05d4, \u05d4\u05d5\u05d3\u05d0\u05d4 \u05d1\u05d0\u05de\u05ea.\n\u05d9\u05e1\u05d5\u05d3 \u2013 \u05d7\u05d9\u05d1\u05d5\u05e8, \u05e7\u05e9\u05e8, \u05d4\u05e2\u05d1\u05e8\u05ea \u05e9\u05e4\u05e2.\n\u05de\u05dc\u05db\u05d5\u05ea \u2013 \u05de\u05d9\u05de\u05d5\u05e9, \u05d4\u05e0\u05d4\u05d2\u05d4, \u05d4\u05d1\u05d0\u05d4 \u05d0\u05dc \u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea.\n\u05db\u05d0\u05e9\u05e8 \u201c\u05e9\u05de\u05df \u05d8\u05d5\u05d1\u201d \u05e0\u05de\u05e9\u05da \u05d0\u05dc \u05db\u05dc \u05d0\u05d7\u05d3 \u05de\u05d4\u05e7\u05e0\u05d9\u05dd, \u05d0\u05d9\u05df \u05de\u05d9\u05d3\u05d4 \u05d0\u05d7\u05ea \u05e9\u05e9\u05d5\u05dc\u05d8\u05ea \u05dc\u05d1\u05d3\u05d4. \u05d4\u05d0\u05d5\u05e8 \u05e0\u05e2\u05e9\u05d4 \u05d4\u05e8\u05de\u05d5\u05e0\u05d9, \u05e8\u05d1\u05be\u05e7\u05d5\u05dc\u05d9, \u05e9\u05dc\u05dd. \u05d6\u05d5 \u05e0\u05e4\u05e9 \u05e9\u05de\u05d5\u05d0\u05e8\u05ea \u05de\u05d1\u05e4\u05e0\u05d9\u05dd.\n\u05d4\u05d7\u05d9\u05d1\u05d5\u05e8 \u05d0\u05dc \u05d4\u05e0\u05e9\u05d2\u05d1 \u2013 \u05d5\u05d4\u05d5\u05dc\u05db\u05ea\u05d5 \u05dc\u05d7\u05d9\u05d9\u05dd\n\u05d4\u05e9\u05de\u05df \u05de\u05d9\u05d9\u05e6\u05d2 \u05d0\u05ea \u05d4\u05ea\u05d5\u05d1\u05e0\u05d4 \u05d4\u05e2\u05dc\u05d9\u05d5\u05e0\u05d4, \u05d0\u05ea \u05d4\u05d7\u05db\u05de\u05d4 \u05e9\u05d0\u05d9\u05e0\u05d4 \u05e0\u05ea\u05e4\u05e1\u05ea \u05de\u05d9\u05d3 \u05d1\u05de\u05d9\u05dc\u05d9\u05dd. \u05e8\u05d2\u05e2 \u05e9\u05dc \u05d4\u05d1\u05e0\u05d4 \u05e2\u05de\u05d5\u05e7\u05d4, \u05e9\u05dc \u05de\u05d2\u05e2 \u05e2\u05dd \u05d0\u05de\u05ea \u05d2\u05d3\u05d5\u05dc\u05d4 \u05de\u05d4\u05e9\u05db\u05dc \u05d4\u05e8\u05d2\u05d9\u05dc. \u05d0\u05d1\u05dc \u05d0\u05dd \u05d4\u05ea\u05d5\u05d1\u05e0\u05d4 \u05e0\u05e9\u05d0\u05e8\u05ea \u201c\u05dc\u05de\u05e2\u05dc\u05d4\u201d \u2013 \u05d4\u05d9\u05d0 \u05de\u05ea\u05e4\u05d5\u05d2\u05d2\u05ea. \u05e8\u05e7 \u05db\u05d0\u05e9\u05e8 \u05d4\u05d9\u05d0 \u05d9\u05d5\u05e8\u05d3\u05ea \u05d3\u05e8\u05da \u05d4\u05e7\u05e0\u05d9\u05dd, \u05d3\u05e8\u05da \u05d4\u05de\u05d9\u05d3\u05d5\u05ea, \u05d4\u05d9\u05d0 \u05e0\u05e2\u05e9\u05d9\u05ea \u05d0\u05d5\u05e8 \u05d7\u05d9.\n\u05db\u05da \u05e0\u05e8\u05d0\u05d4 \u05d4\u05d7\u05d9\u05d1\u05d5\u05e8 \u05d4\u05d0\u05de\u05d9\u05ea\u05d9 \u05dc\u05e0\u05e9\u05d2\u05d1:\n\u05dc\u05d0 \u05d1\u05e8\u05d9\u05d7\u05d4 \u05de\u05d4\u05e2\u05d5\u05dc\u05dd, \u05d0\u05dc\u05d0 \u05d4\u05d5\u05dc\u05db\u05d4 \u05e9\u05dc \u05d4\u05d0\u05d5\u05e8 \u05d0\u05dc \u05ea\u05d5\u05da \u05d4\u05d9\u05d7\u05e1\u05d9\u05dd, \u05d4\u05d4\u05d7\u05dc\u05d8\u05d5\u05ea, \u05d4\u05d3\u05d9\u05d1\u05d5\u05e8, \u05d4\u05d1\u05d7\u05d9\u05e8\u05d4 \u05d4\u05d9\u05d5\u05de\u05d9\u05d5\u05de\u05d9\u05ea.\n\u05d7\u05e1\u05d3 \u05e9\u05e0\u05e2\u05e9\u05d4 \u05de\u05e2\u05e9\u05d4.\n\u05d2\u05d1\u05d5\u05e8\u05d4 \u05e9\u05e0\u05e2\u05e9\u05d9\u05ea \u05d2\u05d1\u05d5\u05dc \u05d1\u05e8\u05d9\u05d0.\n\u05ea\u05e4\u05d0\u05e8\u05ea \u05e9\u05e0\u05e2\u05e9\u05d9\u05ea \u05e8\u05d9\u05e4\u05d5\u05d9.\n\u05d4\u05de\u05e0\u05d5\u05e8\u05d4 \u05db\u05e2\u05d1\u05d5\u05d3\u05ea \u05d7\u05d9\u05d9\u05dd\n\u05d4\u05d0\u05d3\u05dd \u05e0\u05e7\u05e8\u05d0 \u05dc\u05d4\u05d9\u05d5\u05ea \u05de\u05e0\u05d5\u05e8\u05d4 \u05de\u05d4\u05dc\u05db\u05ea:\n\u05dc\u05d4\u05e1\u05db\u05d9\u05dd \u05dc\u05e7\u05d1\u05dc \u05e9\u05de\u05df \u05de\u05dc\u05de\u05e2\u05dc\u05d4 \u2013 \u05d4\u05e9\u05e8\u05d0\u05d4, \u05d0\u05de\u05d5\u05e0\u05d4, \u05de\u05e9\u05de\u05e2\u05d5\u05ea \u2013\n\u05d5\u05dc\u05e2\u05de\u05d5\u05dc \u05dc\u05d4\u05d6\u05e8\u05d9\u05dd \u05d0\u05d5\u05ea\u05d5 \u05d0\u05dc \u05db\u05dc \u05e7\u05e0\u05d9 \u05e0\u05e4\u05e9\u05d5.\n\u05d6\u05d4\u05d5 \u05ea\u05d4\u05dc\u05d9\u05da \u05de\u05ea\u05de\u05d9\u05d3 \u05e9\u05dc \u05d6\u05d9\u05db\u05d5\u05da:\n\u05dc\u05d1\u05d3\u05d5\u05e7 \u05d4\u05d9\u05db\u05df \u05d4\u05d0\u05d5\u05e8 \u05e0\u05ea\u05e7\u05e2, \u05d4\u05d9\u05db\u05df \u05d4\u05e7\u05e0\u05d4 \u05e1\u05ea\u05d5\u05dd, \u05d4\u05d9\u05db\u05df \u05de\u05d9\u05d3\u05d4 \u05d0\u05d7\u05ea \u05de\u05d1\u05e7\u05e9\u05ea \u05e8\u05d9\u05e4\u05d5\u05d9.\n\u05d5\u05db\u05d0\u05e9\u05e8 \u05d4\u05d6\u05e8\u05d9\u05de\u05d4 \u05de\u05ea\u05d7\u05d3\u05e9\u05ea \u2013 \u05d4\u05d0\u05d5\u05e8 \u05e0\u05d3\u05dc\u05e7.\n\u05d0\u05d6 \u05de\u05ea\u05d2\u05dc\u05d4 \u05d4\u05e1\u05d5\u05d3:\n\u05d4\u05d0\u05d5\u05e8 \u05e9\u05de\u05d0\u05d9\u05e8 \u05d4\u05d7\u05d5\u05e6\u05d4, \u05d0\u05dc \u05d4\u05e2\u05d5\u05dc\u05dd,\n\u05d4\u05d5\u05d0 \u05d0\u05d5\u05ea\u05d5 \u05d0\u05d5\u05e8 \u05e9\u05e0\u05e9\u05e4\u05da \u05e4\u05e0\u05d9\u05de\u05d4 \u2013\n\u05d5\u05e9\u05d1\u05e2\u05ea \u05e7\u05e0\u05d9 \u05d4\u05de\u05e0\u05d5\u05e8\u05d4 \u05e0\u05e2\u05e9\u05d9\u05dd \u05e9\u05d1\u05d9\u05dc \u05d7\u05d9\n\u05d1\u05d9\u05df \u05e9\u05de\u05d9\u05dd \u05dc\u05d0\u05e8\u05e5,\n\u05d1\u05d9\u05df \u05ea\u05d5\u05d1\u05e0\u05d4 \u05dc\u05de\u05e2\u05e9\u05d4,\n\u05d1\u05d9\u05df \u05e0\u05e9\u05d2\u05d1 \u05dc\u05d7\u05d9\u05d9\u05dd.\n\u05d0. \u05ea\u05e4\u05d9\u05dc\u05d4 \u05db\u05ea\u05e0\u05d5\u05e2\u05d4 \u05e0\u05e4\u05e9\u05d9\u05ea \u05d5\u05dc\u05d0 \u05db\u05d0\u05de\u05d9\u05e8\u05d4\n\u05d4\u05ea\u05e4\u05d9\u05dc\u05d4, \u05e2\u05dc \u05e4\u05d9 \u05e2\u05d5\u05de\u05e7 \u05d4\u05de\u05e1\u05d5\u05e8\u05ea, \u05d0\u05d9\u05e0\u05e0\u05d4 \u05e8\u05e7 \u05d3\u05d9\u05d1\u05d5\u05e8 \u05d0\u05dc \u05d4\u05d0\u05dc \u05d0\u05dc\u05d0 \u05ea\u05d4\u05dc\u05d9\u05da \u05e9\u05dc \u05d6\u05e8\u05d9\u05de\u05d4. \u05dc\u05d0 \u05e2\u05dc\u05d9\u05d9\u05d4 \u05d7\u05d3\u05be\u05db\u05d9\u05d5\u05d5\u05e0\u05d9\u05ea \u05e9\u05dc \u05d4\u05d0\u05d3\u05dd \u05d0\u05dc \u05e9\u05de\u05d9\u05dd, \u05d0\u05dc\u05d0 \u05d9\u05e8\u05d9\u05d3\u05d4 \u05e2\u05d3\u05d9\u05e0\u05d4, \u05de\u05d3\u05d5\u05d9\u05e7\u05ea, \u05e9\u05dc \u05e9\u05e4\u05e2 \u05d0\u05dc\u05d5\u05e7\u05d9 \u05d0\u05dc \u05ea\u05d5\u05da \u05e0\u05e4\u05e9 \u05d4\u05d0\u05d3\u05dd \u05d5\u05d7\u05d9\u05d9\u05d5.\n\u05d3\u05d9\u05de\u05d5\u05d9 \u05de\u05e4\u05ea\u05d7 \u05dc\u05d4\u05d1\u05e0\u05ea \u05ea\u05d4\u05dc\u05d9\u05da \u05d6\u05d4 \u05de\u05d5\u05e4\u05d9\u05e2 \u05d1\u05de\u05d6\u05de\u05d5\u05e8 \u05e7\u05e6\u05e8 \u05d5\u05e2\u05de\u05d5\u05e7 \u05d1\u05ea\u05d4\u05d9\u05dc\u05d9\u05dd:\n\u201c\u05db\u05b0\u05bc\u05e9\u05b6\u05c1\u05de\u05b6\u05df \u05d4\u05b7\u05d8\u05bc\u05d5\u05b9\u05d1 \u05e2\u05b7\u05dc \u05d4\u05b8\u05e8\u05b9\u05d0\u05e9\u05c1,\n\u05d9\u05d5\u05b9\u05e8\u05b5\u05d3 \u05e2\u05b7\u05dc \u05d4\u05b7\u05d6\u05b8\u05bc\u05e7\u05b8\u05df, \u05d6\u05b0\u05e7\u05b7\u05df \u05d0\u05b7\u05d4\u05b2\u05e8\u05b9\u05df,\n\u05e9\u05b6\u05c1\u05d9\u05b9\u05bc\u05e8\u05b5\u05d3 \u05e2\u05b7\u05dc \u05e4\u05b4\u05bc\u05d9 \u05de\u05b4\u05d3\u05bc\u05d5\u05b9\u05ea\u05b8\u05d9\u05d5\u201d\n(\u05ea\u05d4\u05d9\u05dc\u05d9\u05dd \u05e7\u05dc\u05f4\u05d2, \u05d1\u05f3)\n\u05d6\u05d4\u05d5 \u05e4\u05e1\u05d5\u05e7 \u05d4\u05de\u05ea\u05d0\u05e8 \u05ea\u05e0\u05d5\u05e2\u05d4 \u05e9\u05dc \u05d9\u05e8\u05d9\u05d3\u05d4: \u05de\u05df \u05d4\u05e8\u05d0\u05e9(\u05d4\u05d7\u05db\u05de\u05d4), \u05d3\u05e8\u05da \u05d4\u05d6\u05e7\u05df, \u05d0\u05dc \u05ea\u05db\u05d5\u05e0\u05d5\u05ea \u05d4\u05e0\u05e4\u05e9 \u05d5\u05d4\u05e2\u05e9\u05d9\u05d4. \u05ea\u05e0\u05d5\u05e2\u05d4 \u05d6\u05d5 \u05e0\u05e2\u05e9\u05d9\u05ea \u05de\u05e4\u05ea\u05d7 \u05dc\u05d4\u05d1\u05e0\u05ea \u05de\u05d4\u05d5\u05ea\u05d4 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05e9\u05dc \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4.\n\u05d1. \u05d4\u05e9\u05de\u05df \u2013 \u05e9\u05e4\u05e2 \u05e9\u05d0\u05d9\u05e0\u05d5 \u05de\u05d0\u05d9\u05e8 \u05de\u05e2\u05e6\u05de\u05d5\n\u05e8\u05e9"\u05d9 \u05de\u05e4\u05e8\u05e9 \u05d0\u05ea \u05d4\u05e4\u05e1\u05d5\u05e7 \u05d1\u05d4\u05e7\u05e9\u05e8 \u05e9\u05dc \u05d1\u05e8\u05db\u05d4 \u05d5\u05e9\u05dc\u05de\u05d5\u05ea, \u05d5\u05d4\u05e9\u05de\u05df \u05de\u05e9\u05de\u05e9 \u05d0\u05e6\u05dc\u05d5 \u05e1\u05de\u05dc \u05dc\u05e8\u05d9\u05d1\u05d5\u05d9 \u05d5\u05d8\u05d5\u05d1 \u05d4\u05de\u05ea\u05e4\u05e9\u05d8\u05d9\u05dd \u05d1\u05db\u05dc \u05d4\u05d2\u05d5\u05e3. \u05d4\u05e9\u05de\u05df \u05d0\u05d9\u05e0\u05d5 \u05e7\u05d5\u05e4\u05e5, \u05d0\u05d9\u05e0\u05d5 \u05de\u05ea\u05e4\u05e8\u05e5 \u2013 \u05d4\u05d5\u05d0 \u05d9\u05d5\u05e8\u05d3.\n\u05ea\u05db\u05d5\u05e0\u05d4 \u05d6\u05d5 \u05d4\u05d9\u05d0 \u05de\u05d4\u05d5\u05ea\u05d9\u05ea \u05dc\u05d4\u05d1\u05e0\u05ea \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4:\n\u05d4\u05e9\u05e4\u05e2 \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9 \u05d0\u05d9\u05e0\u05e0\u05d5 \u05db\u05d5\u05d7 \u05d0\u05dc\u05d9\u05dd, \u05d0\u05dc\u05d0 \u05d0\u05d5\u05e8 \u05d4\u05de\u05d1\u05e7\u05e9 \u05db\u05dc\u05d9.\n\u05d2\u05dd \u05e8\u05d3"\u05e7 \u05de\u05d3\u05d2\u05d9\u05e9 \u05e9\u05d4\u05e9\u05de\u05df \u05de\u05e1\u05de\u05dc \u05d7\u05d9\u05d1\u05d5\u05e8 \u05d5\u05d4\u05e8\u05de\u05d5\u05e0\u05d9\u05d4, \u05de\u05e9\u05d5\u05dd \u05e9\u05d4\u05d5\u05d0 \u05de\u05ea\u05e4\u05e9\u05d8 \u05d5\u05d0\u05d9\u05e0\u05d5 \u05e0\u05e7\u05d8\u05e2. \u05db\u05d0\u05e9\u05e8 \u05d9\u05e9 \u05e4\u05d9\u05e8\u05d5\u05d3 \u2013 \u05d0\u05d9\u05df \u05d6\u05e8\u05d9\u05de\u05d4. \u05db\u05d0\u05e9\u05e8 \u05d9\u05e9 \u05d0\u05d7\u05d3\u05d5\u05ea \u2013 \u05d4\u05e9\u05de\u05df \u05d9\u05d5\u05e8\u05d3.\n\u05de\u05db\u05d0\u05df \u05d9\u05e1\u05d5\u05d3 \u05e8\u05d0\u05e9\u05d5\u05df:\n\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d0\u05d9\u05e0\u05e0\u05d4 \u05d9\u05e6\u05d9\u05e8\u05ea \u05d0\u05d5\u05e8, \u05d0\u05dc\u05d0 \u05d4\u05e1\u05e8\u05ea \u05d4\u05d7\u05e1\u05d9\u05de\u05d5\u05ea \u05dc\u05d6\u05e8\u05d9\u05de\u05ea\u05d5.\n\u05d2. \u201c\u05d4\u05e8\u05d0\u05e9\u201d \u2013 \u05d4\u05de\u05d5\u05d7\u05d9\u05df \u05d5\u05d4\u05ea\u05d5\u05d3\u05e2\u05d4 \u05d4\u05e2\u05dc\u05d9\u05d5\u05e0\u05d4\n\u05d1\u05e7\u05d1\u05dc\u05d4 \u05d5\u05d1\u05d7\u05e1\u05d9\u05d3\u05d5\u05ea, \u201c\u05d4\u05e8\u05d0\u05e9\u201d \u05d0\u05d9\u05e0\u05e0\u05d5 \u05e8\u05e7 \u05d0\u05d9\u05d1\u05e8 \u05e4\u05d9\u05d6\u05d9, \u05d0\u05dc\u05d0 \u05de\u05e9\u05dc \u05dc\u05de\u05d5\u05d7\u05d9\u05df \u2013 \u05d7\u05db\u05de\u05d4, \u05d1\u05d9\u05e0\u05d4 \u05d5\u05d3\u05e2\u05ea. \u05d0\u05dc\u05d5 \u05d4\u05dd \u05de\u05e7\u05d5\u05de\u05d5\u05ea \u05d4\u05ea\u05d5\u05d3\u05e2\u05d4, \u05d4\u05d4\u05d1\u05e0\u05d4, \u05d5\u05d4\u05e7\u05e9\u05e8 \u05e2\u05dd \u05d4\u05e0\u05e9\u05d2\u05d1.\n\u05d1\u05e1\u05e4\u05e8 \u05d4\u05d6\u05d5\u05d4\u05e8 (\u05d7\u05dc\u05e7 \u05d2\u05f3, \u05e0\u05e9\u05d0) \u05de\u05ea\u05d5\u05d0\u05e8 \u05d4\u05e9\u05de\u05df \u05db\u05d0\u05d5\u05e8 \u05d4\u05d7\u05db\u05de\u05d4 \u05d4\u05d9\u05d5\u05e8\u05d3 \u05de\u05df \u05d4\u05de\u05d5\u05d7\u05d9\u05df \u05d0\u05dc \u05e9\u05d0\u05e8 \u05d7\u05dc\u05e7\u05d9 \u05d4\u05e1\u05e4\u05d9\u05e8\u05d5\u05ea. \u05d4\u05d6\u05d5\u05d4\u05e8 \u05de\u05d3\u05d2\u05d9\u05e9 \u05e9\u05d4\u05d0\u05d5\u05e8 \u05d4\u05e2\u05dc\u05d9\u05d5\u05df \u05d0\u05d9\u05e0\u05e0\u05d5 \u05e9\u05d5\u05e8\u05d4 \u05d0\u05dc\u05d0 \u05d1\u05de\u05e7\u05d5\u05dd \u05e9\u05d9\u05e9 \u05d1\u05d5 \u05d4\u05de\u05e9\u05db\u05d4 \u05d4\u05d3\u05e8\u05d2\u05ea\u05d9\u05ea \u05d5\u05de\u05d3\u05d5\u05d3\u05d4.\n\u05db\u05dc\u05d5\u05de\u05e8:\n\u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05e4\u05d5\u05ea\u05d7\u05ea \u05d0\u05ea \u05d4\u05e8\u05d0\u05e9, \u05d0\u05ea \u05d4\u05ea\u05d5\u05d3\u05e2\u05d4 \u05d0\u05da \u05d0\u05d9\u05e0\u05e0\u05d4 \u05de\u05e1\u05ea\u05d9\u05d9\u05de\u05ea \u05e9\u05dd.\n\u05d3. \u05d4\u05d6\u05e7\u05df \u2013 \u05de\u05e2\u05d1\u05e8 \u05de\u05df \u05d4\u05ea\u05d5\u05d3\u05e2\u05d4 \u05d0\u05dc \u05d4\u05de\u05d9\u05d3\u05d5\u05ea\n\u05d4\u05e4\u05e1\u05d5\u05e7 \u05de\u05d3\u05d2\u05d9\u05e9: \u201c\u05d9\u05d5\u05e8\u05d3 \u05e2\u05dc \u05d4\u05d6\u05e7\u05df, \u05d6\u05e7\u05df \u05d0\u05d4\u05e8\u05df\u201d. \u05d1\u05e7\u05d1\u05dc\u05d4, \u05d4\u05d6\u05e7\u05df \u05de\u05e1\u05de\u05dc \u05d0\u05ea \u05d9\u05f4\u05d2 \u05ea\u05d9\u05e7\u05d5\u05e0\u05d9 \u05d3\u05d9\u05e7\u05e0\u05d0 \u2013 \u05de\u05e0\u05d2\u05e0\u05d5\u05df \u05d4\u05d4\u05de\u05ea\u05e7\u05d4 \u05d5\u05d4\u05d4\u05d5\u05e8\u05d3\u05d4 \u05e9\u05dc \u05d4\u05d0\u05d5\u05e8, \u05db\u05da \u05e9\u05dc\u05d0 \u05d9\u05e9\u05e8\u05d5\u05e3 \u05d0\u05ea \u05d4\u05db\u05dc\u05d9\u05dd.\n\u05d1\u05db\u05ea\u05d1\u05d9 \u05e2\u05e5 \u05d7\u05d9\u05d9\u05dd \u05de\u05d5\u05e1\u05d1\u05e8 \u05e9\u05d4\u05e9\u05e4\u05e2 \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9 \u05d7\u05d9\u05d9\u05d1 \u05dc\u05e2\u05d1\u05d5\u05e8 \u05e9\u05dc\u05d1 \u05e9\u05dc \u05e2\u05d9\u05d3\u05d5\u05df, \u05d0\u05d7\u05e8\u05ea \u05d0\u05d9\u05df \u05d4\u05db\u05dc\u05d9\u05dd \u05d4\u05ea\u05d7\u05ea\u05d5\u05e0\u05d9\u05dd \u05d9\u05db\u05d5\u05dc\u05d9\u05dd \u05dc\u05d4\u05db\u05d9\u05dc\u05d5.\n\u05d6\u05d4\u05d5 \u05d1\u05d3\u05d9\u05d5\u05e7 \u05ea\u05e4\u05e7\u05d9\u05d3 \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4:\n\u05dc\u05d0\u05e4\u05e9\u05e8 \u05dc\u05e9\u05e4\u05e2 \u05dc\u05e8\u05d3\u05ea \u05d1\u05e6\u05d5\u05e8\u05d4 \u05e9\u05d0\u05e4\u05e9\u05e8 \u05dc\u05d7\u05d9\u05d5\u05ea \u05d0\u05d5\u05ea\u05d4.\n\u05d4. \u201c\u05e2\u05dc \u05e4\u05d9 \u05de\u05d9\u05d3\u05d5\u05ea\u05d9\u05d5\u201d \u2013 \u05dc\u05d1 \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4\n\u05db\u05d0\u05df \u05de\u05d2\u05d9\u05e2 \u05d4\u05e4\u05e1\u05d5\u05e7 \u05dc\u05e9\u05d9\u05d0\u05d5: \u05d4\u05e9\u05de\u05df \u05d9\u05d5\u05e8\u05d3 \u05e2\u05dc \u05e4\u05d9 \u05de\u05d9\u05d3\u05d5\u05ea\u05d9\u05d5.\n\u05dc\u05d0 \u05dc\u05e4\u05d9 \u05e2\u05d5\u05e6\u05de\u05ea \u05d4\u05d0\u05d5\u05e8, \u05d0\u05dc\u05d0 \u05dc\u05e4\u05d9 \u05d4\u05db\u05dc\u05d9\u05dd.\n\u05e9\u05d1\u05e2 \u05d4\u05de\u05d9\u05d3\u05d5\u05ea \u2013 \u05d7\u05e1\u05d3, \u05d2\u05d1\u05d5\u05e8\u05d4, \u05ea\u05e4\u05d0\u05e8\u05ea, \u05e0\u05e6\u05d7, \u05d4\u05d5\u05d3, \u05d9\u05e1\u05d5\u05d3, \u05de\u05dc\u05db\u05d5\u05ea \u2013 \u05d4\u05df \u05e9\u05d1\u05e2\u05ea \u05e7\u05e0\u05d9 \u05d4\u05de\u05e0\u05d5\u05e8\u05d4 \u05e9\u05d1\u05e0\u05e4\u05e9 \u05d4\u05d0\u05d3\u05dd. \u05d4\u05de\u05e0\u05d5\u05e8\u05d4 \u05d0\u05d9\u05e0\u05d4 \u05de\u05e7\u05d5\u05e8 \u05d4\u05d0\u05d5\u05e8; \u05d4\u05d9\u05d0 \u05d4\u05db\u05dc\u05d9 \u05e9\u05de\u05db\u05d5\u05d5\u05df \u05d0\u05d5\u05ea\u05d5.\n\u05d1\u05dc\u05e7\u05d5\u05d8\u05d9 \u05ea\u05d5\u05e8\u05d4 \u05e9\u05dc \u05e8\u05d1\u05d9 \u05e9\u05e0\u05d9\u05d0\u05d5\u05e8 \u05d6\u05dc\u05de\u05df \u05de\u05dc\u05d0\u05d3\u05d9 \u05e0\u05d0\u05de\u05e8 \u05e9\u05e2\u05d1\u05d5\u05d3\u05ea \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d4\u05d9\u05d0 \u201c\u05dc\u05d4\u05de\u05e9\u05d9\u05da \u05de\u05d5\u05d7\u05d9\u05df \u05d1\u05dc\u05d1\u201d, \u05db\u05dc\u05d5\u05de\u05e8:\n\u05dc\u05d4\u05d5\u05e8\u05d9\u05d3 \u05d4\u05d1\u05e0\u05d4 \u05d0\u05dc \u05e8\u05d2\u05e9, \u05d5\u05e8\u05d2\u05e9 \u05d0\u05dc \u05d4\u05e0\u05d4\u05d2\u05d4.\n\u05d5\u05d6\u05d5\u05d4\u05d9 \u05e0\u05e7\u05d5\u05d3\u05ea \u05d4\u05de\u05d1\u05d7\u05df \u05e9\u05dc \u05ea\u05e4\u05d9\u05dc\u05d4 \u05d0\u05de\u05d9\u05ea\u05d9\u05ea:\n\u05d4\u05d0\u05dd \u05dc\u05d0\u05d7\u05e8\u05d9\u05d4 \u05d4\u05d0\u05d3\u05dd \u05d0\u05d5\u05d4\u05d1 \u05d0\u05d7\u05e8\u05ea, \u05d1\u05d5\u05d7\u05e8 \u05d0\u05d7\u05e8\u05ea, \u05de\u05d2\u05d9\u05d1 \u05d0\u05d7\u05e8\u05ea?\n\u05d5. \u05ea\u05e4\u05d9\u05dc\u05d4 \u05e9\u05d0\u05d9\u05e0\u05d4 \u05d9\u05d5\u05e8\u05d3\u05ea \u2013 \u05d5\u05e1\u05db\u05e0\u05ea\u05d4\n\u05e8\u05d1\u05d9 \u05e0\u05d7\u05de\u05df \u05de\u05d1\u05e8\u05e1\u05dc\u05d1 \u05de\u05d6\u05d4\u05d9\u05e8 \u05d1\u05dc\u05d9\u05e7\u05d5\u05d8\u05d9 \u05de\u05d5\u05d4\u05e8\u05f4\u05df \u05de\u05e4\u05e0\u05d9 \u05ea\u05e4\u05d9\u05dc\u05d4 \u05e9\u05e0\u05e9\u05d0\u05e8\u05ea \u05d1\u05de\u05d9\u05dc\u05d9\u05dd \u05d0\u05d5 \u05d1\u05d4\u05ea\u05dc\u05d4\u05d1\u05d5\u05ea \u05e8\u05d2\u05e2\u05d9\u05ea. \u05db\u05d0\u05e9\u05e8 \u05d4\u05d0\u05d5\u05e8 \u05d0\u05d9\u05e0\u05d5 \u05d9\u05d5\u05e8\u05d3 \u05d0\u05dc \u05d4\u05de\u05d9\u05d3\u05d5\u05ea, \u05d4\u05d5\u05d0 \u05de\u05ea\u05e4\u05d5\u05d2\u05d2 \u2013 \u05d5\u05dc\u05e2\u05d9\u05ea\u05d9\u05dd \u05d0\u05e3 \u05d9\u05d5\u05e6\u05e8 \u05e0\u05ea\u05e7 \u05d1\u05d9\u05df \u05d0\u05d9\u05d3\u05d9\u05d0\u05dc \u05dc\u05d7\u05d9\u05d9\u05dd.\n\u05dc\u05e2\u05d5\u05de\u05ea\u05d5, \u05ea\u05e4\u05d9\u05dc\u05d4 \u05e9\u05d1\u05d4 \u05d4\u05e9\u05de\u05df \u05d9\u05d5\u05e8\u05d3 \u05d1\u05d0\u05de\u05ea \u2013 \u05de\u05d7\u05d5\u05dc\u05dc\u05ea \u05e9\u05d9\u05e0\u05d5\u05d9 \u05d0\u05d9\u05d8\u05d9 \u05d0\u05da \u05d9\u05e6\u05d9\u05d1.\n\u05ea\u05e4\u05d9\u05dc\u05d4 \u05dc\u05dc\u05d0 \u05db\u05d5\u05d5\u05e0\u05d4 \u2013 \u05db\u05d0\u05e9\u05e8 \u05d4\u05e9\u05de\u05df \u05e0\u05d5\u05d6\u05dc \u05dc\u05de\u05e7\u05d5\u05dd \u05d4\u05dc\u05d0 \u05e0\u05db\u05d5\u05df\n\u05e8\u05d1\u05d9 \u05e0\u05d7\u05de\u05df \u05de\u05d1\u05e8\u05e1\u05dc\u05d1 \u05d7\u05d5\u05d6\u05e8 \u05e9\u05d5\u05d1 \u05d5\u05e9\u05d5\u05d1 \u05e2\u05dc \u05d4\u05d0\u05d6\u05d4\u05e8\u05d4 \u05de\u05e4\u05e0\u05d9 \u05ea\u05e4\u05d9\u05dc\u05d4 \u05e9\u05d0\u05d9\u05df \u05d1\u05d4 \u05d7\u05d9\u05d1\u05d5\u05e8 \u05e4\u05e0\u05d9\u05de\u05d9 \u05d0\u05de\u05d9\u05ea\u05d9. \u05d1\u05dc\u05d9\u05e7\u05d5\u05d8\u05d9 \u05de\u05d5\u05d4\u05e8\u05f4\u05df \u05d4\u05d5\u05d0 \u05de\u05dc\u05de\u05d3 \u05e9\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d0\u05d9\u05e0\u05e0\u05d4 \u05e0\u05de\u05d3\u05d3\u05ea \u05d1\u05e8\u05d9\u05d1\u05d5\u05d9 \u05d4\u05de\u05d9\u05dc\u05d9\u05dd \u05d0\u05d5 \u05d1\u05e2\u05d5\u05e6\u05de\u05ea \u05d4\u05e8\u05d2\u05e9, \u05d0\u05dc\u05d0 \u05d1\u05db\u05d9\u05d5\u05d5\u05df \u05d4\u05d6\u05e8\u05d9\u05de\u05d4 \u05e9\u05dc\u05d4. \u05db\u05d0\u05e9\u05e8 \u05d4\u05de\u05d9\u05dc\u05d9\u05dd \u05e0\u05d0\u05de\u05e8\u05d5\u05ea \u05de\u05df \u05d4\u05e4\u05d4 \u05d1\u05dc\u05d1\u05d3, \u05dc\u05dc\u05d0 \u05d7\u05d9\u05d1\u05d5\u05e8 \u05e9\u05dc \u05d4\u05dc\u05d1 \u05d5\u05d4\u05de\u05d9\u05d3\u05d5\u05ea, \u05e0\u05d5\u05e6\u05e8 \u05de\u05e6\u05d1 \u05de\u05e1\u05d5\u05db\u05df: \u05d4\u05d0\u05d5\u05e8 \u05d4\u05de\u05d1\u05d5\u05e7\u05e9 \u05d0\u05d9\u05e0\u05d5 \u05de\u05ea\u05dc\u05d1\u05e9 \u05d1\u05db\u05dc\u05d9 \u2013 \u05d5\u05d4\u05d5\u05d0 \u05e0\u05d5\u05e4\u05dc.\n\u05d1\u05e9\u05e4\u05ea \u05d4\u05e7\u05d1\u05dc\u05d4, \u05d0\u05d5\u05e8 \u05e9\u05d0\u05d9\u05e0\u05d5 \u05de\u05d5\u05e6\u05d0 \u05db\u05dc\u05d9 \u05de\u05ea\u05d5\u05e7\u05df \u05e0\u05e9\u05d0\u05d1 \u05d0\u05dc \u05d4\u05e1\u05d8\u05e8\u05d0 \u05d0\u05d7\u05e8\u05d0. \u05db\u05dc\u05d5\u05de\u05e8, \u05d0\u05d5\u05ea\u05d5 \u05db\u05d5\u05d7 \u05e0\u05e4\u05e9\u05d9 \u05e9\u05d4\u05d0\u05d3\u05dd \u05e2\u05d5\u05e8\u05e8 \u05d1\u05ea\u05e4\u05d9\u05dc\u05ea\u05d5 \u2013 \u05e8\u05e6\u05d5\u05df, \u05ea\u05e9\u05d5\u05e7\u05d4, \u05e8\u05d2\u05e9 \u2013 \u05d0\u05dd \u05d0\u05d9\u05e0\u05d5 \u05de\u05db\u05d5\u05d5\u05df \u05d0\u05dc \u05ea\u05d9\u05e7\u05d5\u05df \u05d4\u05de\u05d9\u05d3\u05d5\u05ea \u05d5\u05d4\u05d7\u05d9\u05d9\u05dd, \u05d4\u05d5\u05d0 \u05de\u05d6\u05d9\u05df \u05d3\u05d5\u05d5\u05e7\u05d0 \u05d0\u05ea \u05db\u05d5\u05d7\u05d5\u05ea \u05d4\u05d4\u05e1\u05ea\u05e8, \u05d4\u05e4\u05d9\u05e8\u05d5\u05d3 \u05d5\u05d4\u05d0\u05d5\u05e4\u05dc.\n\u05d6\u05d4\u05d5 \u05e2\u05d5\u05de\u05e7 \u05d3\u05d1\u05e8\u05d9\u05d5 \u05e9\u05dc \u05e8\u05d1\u05d9 \u05e0\u05d7\u05de\u05df, \u05db\u05d0\u05e9\u05e8 \u05d4\u05d5\u05d0 \u05de\u05ea\u05e8\u05d9\u05e2 \u05de\u05e4\u05e0\u05d9 \u05ea\u05e4\u05d9\u05dc\u05d4 \u05e9\u05d0\u05d9\u05e0\u05d4 \u05de\u05e9\u05e0\u05d4 \u05d0\u05ea \u05d4\u05d0\u05d3\u05dd:\n\u05dc\u05d0 \u05e8\u05e7 \u05e9\u05d4\u05d9\u05d0 \u05d0\u05d9\u05e0\u05d4 \u05e4\u05d5\u05e2\u05dc\u05ea \u05ea\u05d9\u05e7\u05d5\u05df \u2013 \u05d4\u05d9\u05d0 \u05e2\u05dc\u05d5\u05dc\u05d4 \u05dc\u05d7\u05d6\u05e7 \u05d0\u05ea \u05d4\u05d4\u05e4\u05da \u05de\u05de\u05e0\u05d5.\n\u05db\u05d0\u05e9\u05e8 \u05d0\u05d3\u05dd \u05de\u05ea\u05e4\u05dc\u05dc \u05de\u05ea\u05d5\u05da \u05db\u05e2\u05e1, \u05e7\u05d5\u05e8\u05d1\u05e0\u05d5\u05ea, \u05d3\u05e8\u05d9\u05e9\u05d4, \u05d0\u05d5 \u05d1\u05e8\u05d9\u05d7\u05d4 \u05de\u05df \u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea \u2013 \u05d2\u05dd \u05d0\u05dd \u05d4\u05de\u05d9\u05dc\u05d9\u05dd \u05e7\u05d3\u05d5\u05e9\u05d5\u05ea \u2013 \u05d4\u05e9\u05de\u05df \u05e0\u05e9\u05e4\u05da, \u05d0\u05da \u05dc\u05d0 \u05e2\u05dc \u05e9\u05d1\u05e2\u05ea \u05d4\u05e7\u05e0\u05d9\u05dd. \u05d4\u05d5\u05d0 \u05d6\u05d5\u05dc\u05d2 \u05d0\u05dc \u05de\u05e7\u05d5\u05de\u05d5\u05ea \u05e9\u05d1\u05d5\u05e8\u05d9\u05dd \u05d1\u05e0\u05e4\u05e9, \u05d5\u05e9\u05dd \u05d4\u05d5\u05d0 \u05e0\u05e2\u05e9\u05d4 \u05d3\u05dc\u05e7 \u05dc\u05e4\u05d7\u05d3, \u05dc\u05d9\u05d9\u05d0\u05d5\u05e9, \u05dc\u05e7\u05d9\u05d8\u05d5\u05d1 \u05d5\u05dc\u05d7\u05d5\u05dc\u05e9\u05d4 \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea. \u05d6\u05d5\u05d4\u05d9 \u05d1\u05d3\u05d9\u05d5\u05e7 \u05e4\u05e2\u05d5\u05dc\u05ea\u05d4 \u05e9\u05dc \u05d4\u05e1\u05d8\u05e8\u05d0 \u05d0\u05d7\u05e8\u05d0: \u05dc\u05d9\u05e0\u05d5\u05e7 \u05de\u05df \u05d4\u05d0\u05d5\u05e8 \u05e9\u05dc\u05d0 \u05d4\u05d5\u05db\u05e9\u05e8.\n\u05dc\u05e2\u05d5\u05de\u05ea \u05d6\u05d0\u05ea, \u05ea\u05e4\u05d9\u05dc\u05d4 \u05e9\u05d9\u05e9 \u05d1\u05d4 \u05db\u05d5\u05d5\u05e0\u05d4 \u2013 \u05e4\u05d9\u05e8\u05d5\u05e9\u05d4 \u05ea\u05e4\u05d9\u05dc\u05d4 \u05e9\u05de\u05db\u05d5\u05d5\u05e0\u05ea \u05dc\u05d4\u05d5\u05dc\u05db\u05ea \u05d4\u05e9\u05e4\u05e2 \u05d0\u05dc \u05d4\u05de\u05d9\u05d3\u05d5\u05ea. \u05d0\u05dc \u05ea\u05d9\u05e7\u05d5\u05df \u05d4\u05d7\u05e1\u05d3, \u05d0\u05dc \u05d1\u05d9\u05e8\u05d5\u05e8 \u05d4\u05d2\u05d1\u05d5\u05e8\u05d4, \u05d0\u05dc \u05d0\u05d9\u05d6\u05d5\u05df \u05d4\u05ea\u05e4\u05d0\u05e8\u05ea. \u05d6\u05d5 \u05ea\u05e4\u05d9\u05dc\u05d4 \u05e9\u05d1\u05d4 \u05d4\u05d0\u05d3\u05dd \u05de\u05d5\u05db\u05df \u05dc\u05d4\u05e9\u05ea\u05e0\u05d5\u05ea, \u05dc\u05d0 \u05e8\u05e7 \u05dc\u05d1\u05e7\u05e9 \u05e9\u05d9\u05e0\u05d5\u05d9.\n\u05db\u05d0\u05df \u05de\u05ea\u05d1\u05e8\u05e8 \u05e2\u05d5\u05de\u05e7 \u05d4\u05d3\u05d9\u05de\u05d5\u05d9:\n\u05d4\u05e9\u05de\u05df \u05d4\u05d5\u05d0 \u05d0\u05d5\u05ea\u05d5 \u05db\u05d5\u05d7 \u05d7\u05d9\u05d9\u05dd.\n\u05d4\u05db\u05d5\u05d5\u05e0\u05d4 \u05d4\u05d9\u05d0 \u05d4\u05e6\u05d9\u05e0\u05d5\u05e8.\n\u05d5\u05e9\u05d1\u05e2\u05ea \u05e7\u05e0\u05d9 \u05d4\u05de\u05e0\u05d5\u05e8\u05d4 \u05d4\u05dd \u05e0\u05e7\u05d5\u05d3\u05ea \u05d4\u05d4\u05db\u05e8\u05e2\u05d4.\n\u05db\u05d0\u05e9\u05e8 \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05de\u05db\u05d5\u05d5\u05e0\u05ea \u2013 \u05d4\u05d0\u05d5\u05e8 \u05de\u05d0\u05d9\u05e8.\n\u05db\u05d0\u05e9\u05e8 \u05d4\u05d9\u05d0 \u05d7\u05e1\u05e8\u05ea \u05db\u05d9\u05d5\u05d5\u05df \u2013 \u05d0\u05d5\u05ea\u05d5 \u05d0\u05d5\u05e8 \u05e2\u05e6\u05de\u05d5\n\u05e2\u05dc\u05d5\u05dc \u05dc\u05d4\u05d0\u05d9\u05e8 \u05d0\u05ea \u05d4\u05d7\u05d5\u05e9\u05da.\n\u05d5\u05dc\u05db\u05df, \u05dc\u05e4\u05d9 \u05e8\u05d1\u05d9 \u05e0\u05d7\u05de\u05df, \u05e2\u05d1\u05d5\u05d3\u05ea \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d0\u05d9\u05e0\u05e0\u05d4 \u201c\u05dc\u05e2\u05d5\u05e8\u05e8 \u05d0\u05d5\u05e8\u201d, \u05d0\u05dc\u05d0 \u05dc\u05e9\u05de\u05d5\u05e8 \u05e2\u05dc\u05d9\u05d5, \u05dc\u05dc\u05d5\u05d5\u05ea \u05d0\u05d5\u05ea\u05d5, \u05d5\u05dc\u05d4\u05d5\u05e8\u05d9\u05d3 \u05d0\u05d5\u05ea\u05d5 \u05dc\u05de\u05e7\u05d5\u05dd \u05e9\u05d1\u05d5 \u05d4\u05d5\u05d0 \u05e0\u05e2\u05e9\u05d4 \u05d7\u05d9\u05d9\u05dd.\n\u05d6\u05d5 \u05ea\u05e4\u05d9\u05dc\u05d4 \u05e9\u05d0\u05d9\u05e0\u05d4 \u05de\u05d7\u05d6\u05e7\u05ea \u05d0\u05ea \u05d4\u05d0\u05d5\u05e4\u05dc,\n\u05d0\u05dc\u05d0 \u05d4\u05d5\u05e4\u05db\u05ea \u05d2\u05dd \u05d0\u05d5\u05ea\u05d5 \u2013\n\u05dc\u05d0\u05d5\u05e8.\n\u05d6. \u05d4\u05d0\u05d3\u05dd \u05db\u05de\u05e0\u05d5\u05e8\u05d4 \u05d7\u05d9\u05d4\n\u05db\u05d0\u05e9\u05e8 \u05db\u05dc \u05d7\u05dc\u05e7\u05d9 \u05d4\u05e4\u05e1\u05d5\u05e7 \u05de\u05ea\u05d7\u05d1\u05e8\u05d9\u05dd, \u05de\u05ea\u05d2\u05dc\u05d4 \u05ea\u05e4\u05d9\u05e1\u05d4 \u05e2\u05de\u05d5\u05e7\u05d4:\n\u05d4\u05d0\u05d3\u05dd \u05e0\u05e7\u05e8\u05d0 \u05dc\u05d4\u05d9\u05d5\u05ea \u05de\u05e0\u05d5\u05e8\u05d4 \u05de\u05d4\u05dc\u05db\u05ea. \u05dc\u05d4\u05d0\u05d9\u05e8 \u05d0\u05ea \u05d4\u05e2\u05d5\u05dc\u05dd \u05d1\u05d7\u05db\u05de\u05ea\u05d5 \u05d5\u05d4\u05ea\u05e0\u05d4\u05d2\u05d5\u05ea\u05d5.\n\u05e8\u05d0\u05e9\u05d5 \u05e4\u05ea\u05d5\u05d7 \u05dc\u05e9\u05de\u05df \u05d4\u05e2\u05dc\u05d9\u05d5\u05df,\n\u05de\u05d9\u05d3\u05d5\u05ea\u05d9\u05d5 \u05e0\u05e7\u05d9\u05d5\u05ea \u05d5\u05e4\u05ea\u05d5\u05d7\u05d5\u05ea,\n\u05d5\u05d7\u05d9\u05d9\u05d5 \u2013 \u05de\u05d0\u05d9\u05e8\u05d9\u05dd.\n\u05db\u05d3\u05d1\u05e8\u05d9 \u05d4\u05e8\u05d1 \u05e7\u05d5\u05e7 \u05d1\u05d0\u05d5\u05e8\u05d5\u05ea \u05d4\u05e7\u05d5\u05d3\u05e9:\n\u05d4\u05d0\u05d5\u05e8 \u05d4\u05e2\u05dc\u05d9\u05d5\u05df \u05de\u05d1\u05e7\u05e9 \u05dc\u05d4\u05ea\u05d2\u05dc\u05d5\u05ea \u05d3\u05d5\u05d5\u05e7\u05d0 \u05d1\u05d7\u05d9\u05d9 \u05d4\u05de\u05e2\u05e9\u05d4, \u05d5\u05dc\u05d0 \u05dc\u05d4\u05d9\u05e9\u05d0\u05e8 \u05d1\u05de\u05e8\u05d5\u05de\u05d9\u05dd.\n\u05d7. \u05e1\u05d9\u05db\u05d5\u05dd: \u05ea\u05e4\u05d9\u05dc\u05d4 \u05db\u05d4\u05d5\u05dc\u05db\u05ea \u05e9\u05e4\u05e2\n\u05d4\u05ea\u05e4\u05d9\u05dc\u05d4, \u05d0\u05dd \u05db\u05df, \u05d0\u05d9\u05e0\u05e0\u05d4 \u05d1\u05e8\u05d9\u05d7\u05d4 \u05de\u05df \u05d4\u05e2\u05d5\u05dc\u05dd \u05d0\u05dc\u05d0 \u05d2\u05e9\u05e8.\n\u05d2\u05e9\u05e8 \u05d1\u05d9\u05df \u05e9\u05de\u05d9\u05dd \u05dc\u05d0\u05e8\u05e5,\n\u05d1\u05d9\u05df \u05ea\u05d5\u05d3\u05e2\u05d4 \u05dc\u05d4\u05ea\u05e0\u05d4\u05d2\u05d5\u05ea,\n\u05d1\u05d9\u05df \u05d4\u05e9\u05e8\u05d0\u05d4 \u05dc\u05de\u05e6\u05d9\u05d0\u05d5\u05ea.\n\u05d5\u05db\u05e9\u05e9\u05de\u05df \u05d4\u05d8\u05d5\u05d1 \u05d9\u05d5\u05e8\u05d3 \u05d1\u05d0\u05de\u05ea \u2013\n\u05e9\u05d1\u05e2\u05ea \u05e7\u05e0\u05d9 \u05d4\u05de\u05e0\u05d5\u05e8\u05d4 \u05e0\u05d3\u05dc\u05e7\u05d9\u05dd,\n\u05d5\u05d4\u05d0\u05d5\u05e8 \u05e9\u05de\u05d0\u05d9\u05e8 \u05d4\u05d7\u05d5\u05e6\u05d4\n\u05d4\u05d5\u05d0 \u05d0\u05d5\u05ea\u05d5 \u05d0\u05d5\u05e8\n\u05e9\u05d9\u05e8\u05d3 \u05d1\u05e9\u05e7\u05d8\n\u05e2\u05dc \u05e4\u05d9 \u05de\u05d9\u05d3\u05d5\u05ea\u05d9\u05d5 \u05e9\u05dc \u05d4\u05d0\u05d3\u05dd.',"","")
B.KZ=new A.cv(5,"\u05e4\u05e8\u05e9\u05ea \u05d4\u05db\u05d9\u05d5\u05e8: \u05d4\u05e2\u05d1\u05d5\u05d3\u05d4 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05e9\u05dc \u05d4\u05e0\u05e4\u05e9",'\u05e4\u05e8\u05e9\u05ea \u05d4\u05db\u05d9\u05d5\u05e8 \u2013 \u05d4\u05e2\u05d1\u05d5\u05d3\u05d4 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05e9\u05dc \u05d4\u05e0\u05e4\u05e9\n\u05d1\u05e4\u05e8\u05e9\u05ea \u05d4\u05db\u05d9\u05d5\u05e8 \u05d0\u05e0\u05d5 \u05e4\u05d5\u05d2\u05e9\u05d9\u05dd \u05db\u05dc\u05d9 \u05e9\u05e0\u05e8\u05d0\u05d4 \u05e2\u05dc \u05e4\u05e0\u05d9\u05d5 \u05e4\u05e9\u05d5\u05d8: \u05d4\u05db\u05d9\u05d5\u05e8 \u2013 \u05de\u05b7\u05d9\u05b4\u05dd \u05dc\u05e9\u05d8\u05d9\u05e4\u05ea \u05d4\u05db\u05d4\u05e0\u05d9\u05dd. \u05d0\u05da \u05db\u05e4\u05d9 \u05e9\u05dc\u05db\u05dc \u05d3\u05d1\u05e8 \u05d1\u05de\u05e7\u05d3\u05e9 \u05d9\u05e9 \u05de\u05e9\u05de\u05e2\u05d5\u05ea \u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05d5\u05e8\u05d5\u05d7\u05e0\u05d9\u05ea, \u05d2\u05dd \u05d4\u05db\u05d9\u05d5\u05e8 \u05d0\u05d9\u05e0\u05d5 \u05e8\u05e7 \u05db\u05dc\u05d9 \u05e4\u05d9\u05d6\u05d9, \u05d0\u05dc\u05d0 \u05de\u05e8\u05d0\u05d4 \u05dc\u05e0\u05e4\u05e9 \u05d4\u05d0\u05d3\u05dd \u05d5\u05dc\u05e2\u05d1\u05d5\u05d3\u05ea\u05d4 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05ea.\n\u05d4\u05db\u05d9\u05d5\u05e8 \u05db\u05de\u05e9\u05dc \u05dc\u05e0\u05e4\u05e9 \u05d4\u05de\u05d8\u05d4\u05e8\u05ea:\n\u05d4\u05db\u05d4\u05e0\u05d9\u05dd \u05d4\u05d9\u05d5 \u05e9\u05d5\u05d8\u05e4\u05d9\u05dd \u05d0\u05ea \u05d9\u05d3\u05d9\u05d4\u05dd \u05d5\u05e8\u05d2\u05dc\u05d9\u05d4\u05dd \u05dc\u05e4\u05e0\u05d9 \u05d4\u05db\u05e0\u05d9\u05e1\u05d4 \u05dc\u05e7\u05d5\u05d3\u05e9 \u05d4\u05e7\u05d5\u05d3\u05e9\u05d9\u05dd, \u05de\u05ea\u05d5\u05da \u05d4\u05db\u05e8\u05d4 \u05d1\u05db\u05da \u05e9\u05d4\u05d8\u05d4\u05e8\u05d4 \u05d4\u05d7\u05d9\u05e6\u05d5\u05e0\u05d9\u05ea \u05d4\u05d9\u05d0 \u05e8\u05e7 \u05d4\u05e9\u05ea\u05e7\u05e4\u05d5\u05ea \u05e9\u05dc \u05d8\u05d4\u05e8\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea. \u05d4\u05e0\u05e4\u05e9 \u05e9\u05dc\u05e0\u05d5, \u05db\u05de\u05d5 \u05d4\u05db\u05d9\u05d5\u05e8, \u05d6\u05e7\u05d5\u05e7\u05d4 \u05dc"\u05e9\u05e4\u05e9\u05d5\u05e3" \u05e2\u05d3\u05d9\u05df \u2013 \u05e9\u05d8\u05d9\u05e4\u05d4 \u05e9\u05dc \u05de\u05d7\u05e9\u05d1\u05d5\u05ea, \u05e8\u05d2\u05e9\u05d5\u05ea \u05d5\u05d3\u05d7\u05e4\u05d9\u05dd \u05e9\u05de\u05dc\u05db\u05dc\u05db\u05d9\u05dd \u05d0\u05ea \u05d4\u05de\u05e7\u05d5\u05dd \u05d4\u05e4\u05e0\u05d9\u05de\u05d9 \u05e9\u05d1\u05d5 \u05d0\u05e0\u05d5 \u05e0\u05e4\u05d2\u05e9\u05d9\u05dd \u05e2\u05dd \u05d4\u05e7\u05d3\u05d5\u05e9\u05d4. \u05d1\u05db\u05dc \u05d9\u05d5\u05dd \u05d0\u05e0\u05d5 \u05d9\u05db\u05d5\u05dc\u05d9\u05dd \u05dc\u05e2\u05e6\u05d5\u05e8, \u05dc\u05d4\u05e1\u05ea\u05db\u05dc \u05e4\u05e0\u05d9\u05de\u05d4, \u05d5\u05dc\u05e0\u05e7\u05d5\u05ea \u05d0\u05ea \u05e2\u05e6\u05de\u05e0\u05d5 \u05de\u05e8\u05d2\u05e9\u05d5\u05ea \u05e9\u05dc\u05d9\u05dc\u05d9\u05d9\u05dd, \u05d7\u05e8\u05d3\u05d5\u05ea, \u05e7\u05e0\u05d0\u05d4 \u05d0\u05d5 \u05db\u05e2\u05e1 \u2013 \u05db\u05d3\u05d9 \u05e9\u05e0\u05d5\u05db\u05dc \u05dc\u05e4\u05d2\u05d5\u05e9 \u05d0\u05ea \u05d4\u05e2\u05d5\u05dc\u05dd \u05d5\u05d1\u05de\u05d9\u05d5\u05d7\u05d3 \u05d0\u05ea \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4, \u05d1\u05de\u05e6\u05d1 \u05e9\u05dc \u05e4\u05ea\u05d9\u05d7\u05d5\u05ea \u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05d5\u05e0\u05e7\u05d9\u05d9\u05d4.\n\u05d4\u05db\u05d9\u05d5\u05e8 \u05db\u05db\u05dc\u05d9 \u05de\u05d3\u05d9\u05d8\u05d8\u05d9\u05d1\u05d9:\n\u05d4\u05de\u05d9\u05dd \u05d4\u05d6\u05d5\u05e8\u05de\u05d9\u05dd \u05ea\u05de\u05d9\u05d3 \u05de\u05d6\u05db\u05d9\u05e8\u05d9\u05dd \u05dc\u05e0\u05d5 \u05d0\u05ea \u05d4\u05d6\u05e8\u05d9\u05de\u05d4 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05e9\u05dc \u05d4\u05d7\u05d9\u05d9\u05dd. \u05d1\u05e8\u05d2\u05e2 \u05e9\u05d0\u05e0\u05d5 \u05de\u05d1\u05e6\u05e2\u05d9\u05dd \u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d0\u05d5 \u05ea\u05e8\u05d2\u05d5\u05dc \u05e0\u05e9\u05d9\u05de\u05d4 \u05ea\u05d5\u05da \u05d7\u05d9\u05d1\u05d5\u05e8 \u05dc\u05d3\u05d9\u05de\u05d5\u05d9 \u05d4\u05db\u05d9\u05d5\u05e8, \u05d0\u05e0\u05d5 \u05d9\u05db\u05d5\u05dc\u05d9\u05dd \u05dc\u05d3\u05de\u05d9\u05d9\u05df \u05db\u05d9\u05e6\u05d3 \u05d4\u05de\u05d9\u05dd \u05e9\u05d5\u05d8\u05e4\u05d9\u05dd \u05d0\u05ea \u05db\u05dc \u05d4\u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05d4\u05de\u05d9\u05d5\u05ea\u05e8\u05d5\u05ea, \u05db\u05dc \u05d4\u05d3\u05d0\u05d2\u05d5\u05ea \u05d5\u05d4\u05de\u05ea\u05d7\u05d9\u05dd, \u05d5\u05de\u05d5\u05ea\u05d9\u05e8\u05d9\u05dd \u05d0\u05d5\u05ea\u05e0\u05d5 \u05e4\u05e0\u05d5\u05d9\u05d9\u05dd \u05d5\u05de\u05e8\u05d5\u05db\u05d6\u05d9\u05dd \u05d1\u05e8\u05d2\u05e2 \u05d4\u05e0\u05d5\u05db\u05d7\u05d9.\n\u05ea\u05e8\u05d2\u05d9\u05dc \u05e7\u05e6\u05e8: \u05e2\u05de\u05d3\u05d5 \u05d1\u05e9\u05e7\u05d8, \u05e2\u05e6\u05de\u05d5 \u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05d5\u05d3\u05de\u05d9\u05d9\u05e0\u05d5 \u05d0\u05ea \u05d4\u05d9\u05d3\u05d9\u05d9\u05dd \u05d5\u05d4\u05e8\u05d2\u05dc\u05d9\u05d9\u05dd \u05e9\u05dc\u05db\u05dd \u05e9\u05d8\u05d5\u05e4\u05d5\u05ea \u05d1\u05de\u05d9\u05dd \u05d6\u05db\u05d9\u05dd. \u05db\u05dc \u05de\u05d7\u05e9\u05d1\u05d4 \u05d0\u05d5 \u05e8\u05d2\u05e9 \u05e9\u05de\u05e4\u05e8\u05d9\u05e2 \u05dc\u05db\u05dd, \u05db\u05de\u05d5 \u05d8\u05d9\u05e4\u05d4 \u05dc\u05db\u05dc\u05d5\u05da, \u05de\u05ea\u05de\u05d5\u05e1\u05e1 \u05d1\u05de\u05d9\u05dd. \u05e0\u05e9\u05de\u05d5 \u05e2\u05de\u05d5\u05e7, \u05d5\u05ea\u05d7\u05d5\u05d5 \u05d0\u05ea \u05d4\u05ea\u05d7\u05d5\u05e9\u05d4 \u05e9\u05dc \u05d8\u05d4\u05e8\u05d4 \u05d5\u05e8\u05d5\u05d2\u05e2 \u05e4\u05e0\u05d9\u05de\u05d9.\n\u05d4\u05db\u05d9\u05d5\u05e8 \u05db\u05de\u05e9\u05dc \u05dc\u05e2\u05d1\u05d5\u05d3\u05ea \u05d4\u05e8\u05e6\u05d5\u05df \u05d5\u05d4\u05db\u05d5\u05d5\u05e0\u05d4 \u05d1\u05ea\u05e4\u05d9\u05dc\u05d4:\n\u05d4\u05db\u05d4\u05df \u05dc\u05d0 \u05e8\u05e7 \u05e9\u05d5\u05d8\u05e3 \u05d0\u05ea \u05e2\u05e6\u05de\u05d5 \u2013 \u05d4\u05d5\u05d0 \u05de\u05db\u05d5\u05d5\u05df \u05d0\u05ea \u05e2\u05e6\u05de\u05d5 \u05dc\u05e9\u05e8\u05ea \u05d0\u05ea \u05d4\u05d0\u05dc \u05d1\u05de\u05e7\u05d3\u05e9. \u05db\u05da \u05d2\u05dd \u05d1\u05ea\u05e4\u05d9\u05dc\u05d4: \u05d4\u05e2\u05d1\u05d5\u05d3\u05d4 \u05e9\u05dc\u05e0\u05d5 \u05d0\u05d9\u05e0\u05d4 \u05e8\u05e7 \u05de\u05d9\u05dc\u05d9\u05dd, \u05d0\u05dc\u05d0 \u05db\u05d5\u05d5\u05e0\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea, \u05e8\u05e6\u05d5\u05df \u05dc\u05e9\u05e0\u05d5\u05ea \u05d0\u05ea \u05e2\u05e6\u05de\u05e0\u05d5, \u05dc\u05d4\u05d9\u05d8\u05d4\u05e8 \u05d5\u05dc\u05e4\u05ea\u05d5\u05d7 \u05d0\u05ea \u05d4\u05dc\u05d1. \u05d4\u05db\u05d9\u05d5\u05e8 \u05de\u05d6\u05db\u05d9\u05e8 \u05dc\u05e0\u05d5 \u05e9\u05db\u05d3\u05d9 \u05dc\u05d4\u05ea\u05d7\u05d1\u05e8 \u05dc\u05d0\u05e0\u05e8\u05d2\u05d9\u05d4 \u05d2\u05d1\u05d5\u05d4\u05d4 \u05e9\u05dc \u05ea\u05e4\u05d9\u05dc\u05d4 \u05d5\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4, \u05d0\u05e0\u05d5 \u05e6\u05e8\u05d9\u05db\u05d9\u05dd \u05e7\u05d5\u05d3\u05dd \u05dc\u05d8\u05d4\u05e8 \u05d0\u05ea \u05d4\u05db\u05dc\u05d9 \u05e9\u05dc\u05e0\u05d5 \u2013 \u05d0\u05ea \u05d4\u05e0\u05e4\u05e9 \u05e9\u05dc\u05e0\u05d5, \u05d0\u05ea \u05d4\u05e8\u05e6\u05d5\u05df \u05e9\u05dc\u05e0\u05d5, \u05d0\u05ea \u05d4\u05dc\u05d1 \u05e9\u05dc\u05e0\u05d5.\n\u05d7\u05d9\u05d1\u05d5\u05e8 \u05dc\u05e4\u05e8\u05e7\u05d8\u05d9\u05e7\u05d4 \u05d9\u05d5\u05de\u05d9\u05ea:\n\u05d4\u05ea\u05d7\u05d9\u05dc\u05d5 \u05d0\u05ea \u05d4\u05d9\u05d5\u05dd \u05d1\u05d3\u05e7\u05d4 \u05e9\u05dc "\u05e9\u05d8\u05d9\u05e4\u05ea \u05d4\u05db\u05d9\u05d5\u05e8 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea": \u05e2\u05e6\u05e8\u05d5, \u05e0\u05e9\u05de\u05d5, \u05d5\u05d3\u05de\u05d9\u05d9\u05e0\u05d5 \u05e9\u05d4\u05de\u05d9\u05dd \u05de\u05d8\u05d4\u05e8\u05d9\u05dd \u05d0\u05ea \u05db\u05dc \u05d4\u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05d4\u05de\u05d9\u05d5\u05ea\u05e8\u05d5\u05ea.\n\u05d1\u05d6\u05de\u05df \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4, \u05e9\u05d1\u05d5 \u05d1\u05ea\u05e9\u05d5\u05de\u05ea \u05dc\u05d1 \u05e2\u05dc \u05de\u05d4 \u05e9\u05d0\u05ea\u05dd "\u05e9\u05d5\u05d8\u05e4\u05d9\u05dd" \u05d1\u05ea\u05d5\u05da \u05e2\u05e6\u05de\u05db\u05dd \u2013 \u05e8\u05d2\u05e9\u05d5\u05ea \u05e9\u05dc\u05d9\u05dc\u05d9\u05d9\u05dd, \u05e4\u05d7\u05d3\u05d9\u05dd \u05d0\u05d5 \u05d3\u05d7\u05e4\u05d9\u05dd \u05dc\u05d0 \u05e8\u05e6\u05d5\u05d9\u05d9\u05dd.\n\u05d1\u05e1\u05d9\u05d5\u05dd, \u05d4\u05e8\u05d2\u05d9\u05e9\u05d5 \u05d0\u05ea \u05d4\u05de\u05e7\u05d5\u05dd \u05d4\u05e0\u05e7\u05d9 \u05e9\u05e4\u05d5\u05ea\u05d7 \u05d0\u05ea\u05db\u05dd \u05dc\u05de\u05e4\u05d2\u05e9 \u05e2\u05dd \u05d4\u05d0\u05d5\u05e8 \u05d5\u05d4\u05e7\u05d3\u05d5\u05e9\u05d4.',"","")
B.L1=new A.cv(6,"\u05e2\u05d1\u05d5\u05d3\u05ea \u05d4\u05e0\u05e4\u05e9 \u05d1\u05ea\u05e8\u05d5\u05de\u05ea \u05d4\u05d3\u05e9\u05df \u05d5\u05d1\u05d2\u05d3\u05d9 \u05d4\u05db\u05d4\u05df",'\u05e2\u05d1\u05d5\u05d3\u05ea \u05d4\u05e0\u05e4\u05e9 \u05d1\u05ea\u05e8\u05d5\u05de\u05ea \u05d4\u05d3\u05e9\u05df \u05d5\u05d1\u05d2\u05d3\u05d9 \u05d4\u05db\u05d4\u05df\n\u05e4\u05e8\u05e9\u05ea \u05ea\u05e8\u05d5\u05de\u05ea \u05d4\u05d3\u05e9\u05df \u05d5\u05e4\u05e8\u05e9\u05ea \u05e6\u05d5\u05d5 \u05d0\u05d9\u05e0\u05dd \u05e8\u05e7 \u05d4\u05d5\u05e8\u05d0\u05d5\u05ea \u05d1\u05dc\u05ea\u05d9 \u05e8\u05dc\u05d5\u05d5\u05e0\u05d8\u05d9\u05d5\u05ea \u05de\u05ea\u05e7\u05d5\u05e4\u05ea \u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9, \u05d0\u05dc\u05d0 \u05de\u05d3\u05e8\u05d9\u05da \u05dc\u05e2\u05d1\u05d5\u05d3\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05e9\u05dc \u05d4\u05d0\u05d3\u05dd.\n\u05e0\u05d9\u05e7\u05d5\u05d9 \u05d4\u05e0\u05e4\u05e9, \u05d4\u05db\u05e0\u05ea \u05d4\u05de\u05d9\u05d3\u05d5\u05ea \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05d5\u05ea, \u05d4\u05e2\u05dc\u05d0\u05ea \u05d4\u05e8\u05e6\u05d5\u05e0\u05d5\u05ea \u05d5\u05d4\u05d3\u05e8\u05da \u05dc\u05d4\u05ea\u05d7\u05d1\u05e8 \u05dc\u05d0\u05d5\u05e8 \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9.\n\u05ea\u05e8\u05d5\u05de\u05ea \u05d4\u05d3\u05e9\u05df - \u05e0\u05d9\u05e7\u05d5\u05d9 \u05d4\u05d0\u05ea\u05de\u05d5\u05dc \u05db\u05d3\u05d9 \u05dc\u05e4\u05e0\u05d5\u05ea \u05de\u05e7\u05d5\u05dd \u05dc\u05d0\u05e9 \u05d4\u05d7\u05d9\u05d9\u05dd\n\u05ea\u05e8\u05d5\u05de\u05ea \u05d4\u05d3\u05e9\u05df \u05d4\u05d9\u05d0 \u05d0\u05d7\u05ea \u05d4\u05e2\u05d1\u05d5\u05d3\u05d5\u05ea \u05d4\u05e8\u05d0\u05e9\u05d5\u05e0\u05d5\u05ea \u05e9\u05dc \u05d4\u05db\u05d4\u05df \u05d1\u05db\u05dc \u05d9\u05d5\u05dd:"\u05d5\u05b0\u05d4\u05b5\u05e8\u05b4\u05d9\u05dd \u05d0\u05b6\u05ea \u05d4\u05b7\u05d3\u05bc\u05b6\u05e9\u05c1\u05b6\u05df\u2026 \u05d5\u05b0\u05e9\u05c2\u05b8\u05de\u05d5\u05b9 \u05d0\u05b5\u05e6\u05b6\u05dc \u05d4\u05b7\u05de\u05bc\u05b4\u05d6\u05b0\u05d1\u05bc\u05b5\u05d7\u05b7" (\u05d5\u05d9\u05e7\u05e8\u05d0 \u05d5\', \u05d2\').\n\u05d3\u05d5\u05d5\u05e7\u05d0 \u05de\u05ea\u05d5\u05da \u05d4\u05d0\u05e9 \u05d4\u05d2\u05d3\u05d5\u05dc\u05d4 \u05e9\u05dc \u05e2\u05d1\u05d5\u05d3\u05ea \u05d4\u05d0\u05ea\u05de\u05d5\u05dc \u05e0\u05e9\u05d0\u05e8 \u05d3\u05e9\u05df - \u05d0\u05e4\u05e8.\n\u05e9\u05d0\u05e8\u05d9\u05d5\u05ea.\n\u05de\u05e9\u05d4\u05d5 \u05e9\u05db\u05d1\u05e8 \u05d1\u05e2\u05e8, \u05e9\u05db\u05d1\u05e8 \u05d4\u05d9\u05d4 \u05d7\u05d9, \u05e9\u05dc\u05de\u05e8\u05d5\u05ea \u05e9\u05d4\u05d9\u05d4 \u05de\u05e9\u05de\u05e2\u05d5\u05ea\u05d9 \u05db\u05e2\u05ea \u05d4\u05e4\u05da \u05dc\u05d7\u05d5\u05de\u05e8 \u05e9\u05e6\u05e8\u05d9\u05da \u05dc\u05e4\u05e0\u05d5\u05ea.\n\u05d5\u05db\u05d0\u05df \u05de\u05ea\u05d2\u05dc\u05d4 \u05d7\u05d5\u05e7 \u05e4\u05e0\u05d9\u05de\u05d9 \u05e2\u05de\u05d5\u05e7: \u05db\u05d3\u05d9 \u05dc\u05d4\u05d1\u05e2\u05d9\u05e8 \u05d2\u05d7\u05dc\u05d9\u05dd \u05d7\u05d3\u05e9\u05d5\u05ea \u05d7\u05d9\u05d9\u05d1\u05d9\u05dd \u05dc\u05e4\u05e0\u05d5\u05ea \u05d0\u05ea \u05d4\u05d0\u05e4\u05e8 \u05d4\u05d9\u05e9\u05df.\n\u05d0\u05dd \u05d4\u05d0\u05e4\u05e8 \u05e0\u05e9\u05d0\u05e8 \u05d5\u05de\u05e6\u05d8\u05d1\u05e8 \u05d4\u05d5\u05d0 \u05d7\u05d5\u05e0\u05e7 \u05d0\u05ea \u05d4\u05d2\u05d7\u05dc\u05d9\u05dd \u05d5\u05de\u05e4\u05e8\u05d9\u05e2 \u05dc\u05d0\u05e9.\n\u05d4\u05d0\u05e9 \u05d0\u05d5\u05dc\u05d9 \u05e2\u05d3\u05d9\u05d9\u05df \u05e7\u05d9\u05d9\u05de\u05ea, \u05d0\u05d1\u05dc \u05d4\u05d9\u05d0 \u05d7\u05e6\u05d9 \u05db\u05d1\u05d5\u05d9\u05d4 \u05de\u05ea\u05d7\u05ea \u05dc\u05e9\u05db\u05d1\u05d5\u05ea \u05e9\u05dc \u05de\u05d4 \u05e9\u05db\u05d1\u05e8 \u05d4\u05d9\u05d4.\n\u05e8\u05e7 \u05db\u05d0\u05e9\u05e8 \u05de\u05e4\u05e0\u05d9\u05dd \u05d0\u05ea \u05d4\u05d3\u05e9\u05df \u05de\u05ea\u05d2\u05dc\u05d5\u05ea \u05d4\u05d2\u05d7\u05dc\u05d9\u05dd \u05d4\u05dc\u05d5\u05d7\u05e9\u05d5\u05ea, \u05d5\u05e0\u05d9\u05ea\u05df \u05dc\u05d4\u05e6\u05d9\u05ea \u05de\u05d4\u05df \u05d0\u05e9 \u05d7\u05d6\u05e7\u05d4.\n\u05db\u05da \u05d1\u05d3\u05d9\u05d5\u05e7 \u05d1\u05e0\u05e4\u05e9 \u05d4\u05d0\u05d3\u05dd.\n\u05e0\u05d9\u05e7\u05d5\u05d9 \u05d4\u05d0\u05ea\u05de\u05d5\u05dc - \u05ea\u05e0\u05d0\u05d9 \u05dc\u05d7\u05d9\u05d5\u05ea \u05e9\u05dc \u05d4\u05d9\u05d5\u05dd\n\u05d4\u05d0\u05d3\u05dd \u05d0\u05d9\u05e0\u05d5 \u05e0\u05db\u05e0\u05e1 \u05dc\u05d9\u05d5\u05dd \u05d7\u05d3\u05e9 \u05db\u05e9\u05d4\u05d5\u05d0 \u05e8\u05d9\u05e7.\n\u05d4\u05d5\u05d0 \u05e0\u05d5\u05e9\u05d0 \u05e2\u05de\u05d5 \u05d0\u05ea \u05e9\u05d0\u05e8\u05d9\u05d5\u05ea \u05d4\u05d0\u05ea\u05de\u05d5\u05dc \u05d1\u05e6\u05d5\u05e8\u05ea \u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05e9\u05dc\u05d0 \u05e0\u05e1\u05d2\u05e8\u05d5, \u05e8\u05d2\u05e9\u05d5\u05ea \u05e9\u05dc\u05d0 \u05e2\u05d5\u05d1\u05d3\u05d5, \u05db\u05e2\u05e1\u05d9\u05dd, \u05e7\u05d9\u05e0\u05d0\u05d4, \u05d0\u05db\u05d6\u05d1\u05d5\u05ea.\n\u05db\u05dc \u05d0\u05dc\u05d5 \u05d4\u05dd \u201c\u05d0\u05e4\u05e8 \u05e0\u05e4\u05e9\u05d9\u201d.\n\u05d4\u05dd \u05ea\u05d5\u05e6\u05d0\u05d4 \u05e9\u05dc \u05ea\u05d4\u05dc\u05d9\u05db\u05d9\u05dd \u05d0\u05de\u05d9\u05ea\u05d9\u05d9\u05dd \u05d0\u05da \u05d4\u05dd \u05db\u05d1\u05e8 \u05d0\u05d9\u05e0\u05dd \u05e9\u05d9\u05d9\u05db\u05d9\u05dd \u05dc\u05e8\u05d2\u05e2 \u05d4\u05d6\u05d4.\n\u05d0\u05dd \u05dc\u05d0 \u05e0\u05e4\u05e0\u05d4 \u05d0\u05d5\u05ea\u05dd \u05d4\u05dd \u05d9\u05de\u05e9\u05d9\u05db\u05d5 \u05dc\u05d4\u05db\u05d1\u05d9\u05d3 \u05d5\u05dc\u05d4\u05e1\u05ea\u05d9\u05e8 \u05d0\u05ea \u05d4\u05d0\u05e9 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05e9\u05dc\u05e0\u05d5.\n\u05e0\u05d9\u05e7\u05d5\u05d9 \u05d0\u05d9\u05e0\u05d5 \u05d3\u05d9\u05db\u05d5\u05d9 - \u05d0\u05dc\u05d0 \u05e2\u05d9\u05d1\u05d5\u05d3 \u05d5\u05d4\u05e8\u05de\u05d4\n\u05ea\u05e8\u05d5\u05de\u05ea \u05d4\u05d3\u05e9\u05df \u05d0\u05d9\u05e0\u05d4 \u05d6\u05e8\u05d9\u05e7\u05d4 \u05e9\u05dc \u05d4\u05d0\u05e4\u05e8, \u05d0\u05dc\u05d0 \u05d4\u05e8\u05de\u05d4 \u05e9\u05dc\u05d5:"\u05d5\u05b0\u05d4\u05b5\u05e8\u05b4\u05d9\u05dd \u05d0\u05b6\u05ea \u05d4\u05b7\u05d3\u05bc\u05b6\u05e9\u05c1\u05b6\u05df"\n\u05d9\u05e9 \u05db\u05d0\u05df \u05db\u05d1\u05d5\u05d3 \u05dc\u05de\u05d4 \u05e9\u05d4\u05d9\u05d4. \u05d4\u05db\u05e8\u05d4 \u05d1\u05db\u05da \u05e9\u05d0\u05d9\u05e8\u05d5\u05e2\u05d9 \u05d4\u05d0\u05ea\u05de\u05d5\u05dc \u05e2\u05e9\u05d5 \u05d0\u05ea \u05e2\u05d1\u05d5\u05d3\u05ea\u05dd.\n\u05db\u05da \u05d2\u05dd \u05d1\u05e0\u05e4\u05e9: \u05d0\u05d9\u05e0\u05e0\u05d5 \u05de\u05d5\u05d7\u05e7\u05d9\u05dd \u05d0\u05ea \u05d4\u05d7\u05d5\u05d5\u05d9\u05d5\u05ea, \u05d0\u05dc\u05d0 \u05de\u05e8\u05d9\u05de\u05d9\u05dd \u05d0\u05d5\u05ea\u05df \u05dc\u05de\u05d5\u05d3\u05e2\u05d5\u05ea, \u05dc\u05d5\u05de\u05d3\u05d9\u05dd \u05de\u05d4\u05df,\u05d5\u05d0\u05d6 \u05de\u05e0\u05d9\u05d7\u05d9\u05dd \u05d0\u05d5\u05ea\u05df \u05d1\u05e6\u05d3 \u05db\u05d3\u05d9 \u05e9\u05dc\u05d0 \u05d9\u05db\u05e1\u05d5 \u05d0\u05ea \u05d4\u05d4\u05d5\u05d5\u05d4.\n\u05d4\u05d0\u05e4\u05e8 \u05d4\u05d5\u05e4\u05da \u05dc\u05d7\u05d5\u05db\u05de\u05d4 \u05d0\u05d1\u05dc \u05d4\u05d5\u05d0 \u05db\u05d1\u05e8 \u05dc\u05d0 \u05de\u05e0\u05d4\u05dc \u05d0\u05ea \u05d4\u05dc\u05d1.\n\u05d0\u05e9 \u05ea\u05de\u05d9\u05d3 - \u05d4\u05d7\u05d9\u05d5\u05ea \u05e6\u05e8\u05d9\u05db\u05d4 \u05d4\u05db\u05e0\u05ea \u05de\u05e7\u05d5\u05dd\n\u05de\u05d9\u05d3 \u05dc\u05d0\u05d7\u05e8 \u05ea\u05e8\u05d5\u05de\u05ea \u05d4\u05d3\u05e9\u05df \u05e0\u05d0\u05de\u05e8:"\u05d0\u05b5\u05e9\u05c1 \u05ea\u05bc\u05b8\u05de\u05b4\u05d9\u05d3 \u05ea\u05bc\u05d5\u05bc\u05e7\u05b7\u05d3\u2026 \u05dc\u05b9\u05d0 \u05ea\u05b4\u05db\u05b0\u05d1\u05bc\u05b6\u05d4" (\u05d5\u05d9\u05e7\u05e8\u05d0 \u05d5\', \u05d5\')\n\u05d1\u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9 \u05d4\u05d0\u05e9 \u05d0\u05d9\u05e0\u05d4 \u05e6\u05e8\u05d9\u05db\u05d4 \u05dc\u05d4\u05d9\u05d5\u05d5\u05e6\u05e8 \u05d4\u05d9\u05d0 \u05db\u05d1\u05e8 \u05e9\u05dd. \u05d1\u05dc\u05d1 \u05e9\u05dc\u05e0\u05d5 \u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05e0\u05d3\u05de\u05d4 \u05e9\u05d4\u05d9\u05d0 \u05db\u05d1\u05ea\u05d4 \u05d0\u05d1\u05dc \u05d4\u05d9\u05d0 \u05e9\u05dd \u05d5\u05db\u05d3\u05d9 \u05e9\u05ea\u05ea\u05d2\u05dc\u05d4 \u05e6\u05e8\u05d9\u05da \u05dc\u05e4\u05e0\u05d5\u05ea \u05dc\u05d4 \u05de\u05e7\u05d5\u05dd \u05de\u05d0\u05d9\u05e8\u05d5\u05e2\u05d9 \u05d4\u05e2\u05d1\u05e8 \u05d5\u05dc\u05d4\u05d0\u05de\u05d9\u05df \u05d4\u05d4\u05ea\u05d7\u05d3\u05e9\u05d5\u05ea \u05d4\u05d7\u05d9\u05d9\u05dd \u05d4\u05d9\u05d5\u05dd.\n\u05d4\u05d4\u05e1\u05ea\u05db\u05dc\u05d5\u05ea \u05d4\u05d6\u05d5 \u05d4\u05d9\u05d0 \u05e9\u05de\u05d1\u05d9\u05d0\u05d4 \u05e2\u05d9\u05de\u05d4 \u05d7\u05d9\u05d5\u05ea, \u05d9\u05e6\u05d9\u05e8\u05d4, \u05e9\u05de\u05d7\u05d4 \u05e2\u05de\u05d5\u05e7\u05d4, \u05ea\u05e9\u05d5\u05e7\u05d4 \u05dc\u05d7\u05d9\u05d9\u05dd, \u05d7\u05d9\u05d1\u05d5\u05e8 \u05dc\u05d0\u05dc\u05d5\u05e7\u05d5\u05ea.\n\u05db\u05d0\u05e9\u05e8 \u05de\u05e4\u05e0\u05d9\u05dd \u05d0\u05ea \u05d4\u05d0\u05e4\u05e8 \u05d4\u05d2\u05d7\u05dc\u05d9\u05dd \u05de\u05ea\u05d2\u05dc\u05d5\u05ea, \u05d5\u05d4\u05d0\u05e9 \u05de\u05ea\u05d7\u05d3\u05e9\u05ea \u05de\u05e2\u05e6\u05de\u05d4.\n\u05e2\u05d1\u05d5\u05d3\u05ea \u05d4\u05d1\u05d5\u05e7\u05e8 \u05e9\u05dc \u05d4\u05e0\u05e4\u05e9\n\u05d1\u05ea\u05d7\u05d9\u05dc\u05ea \u05d4\u05d9\u05d5\u05dd \u05d4\u05d7\u05d3\u05e9, \u05e6\u05e8\u05d9\u05da \u05dc\u05e2\u05d5\u05e8\u05e8 \u05e8\u05d2\u05e2 \u05e9\u05dc \u05ea\u05e8\u05d5\u05de\u05ea \u05d4\u05d3\u05e9\u05df \u05e4\u05e0\u05d9\u05de\u05d9\u05ea:\n\u05e9\u05d0\u05dc\u05d5 \u05d0\u05ea \u05e2\u05e6\u05de\u05db\u05dd \u05d1\u05e2\u05d3\u05d9\u05e0\u05d5\u05ea:\n\u05de\u05d4 \u05e0\u05e9\u05d0\u05e8 \u05d1\u05d9 \u05de\u05d0\u05ea\u05de\u05d5\u05dc?\n\u05de\u05d4 \u05e2\u05d3\u05d9\u05d9\u05df \u05d9\u05d5\u05e9\u05d1 \u05e2\u05dc \u05d4\u05dc\u05d1?\n\u05de\u05d4 \u05dc\u05d0 \u05e7\u05d9\u05d1\u05dc \u05de\u05d5\u05d3\u05e2\u05d5\u05ea?\n\u05e7\u05d7\u05d5 \u05e0\u05e9\u05d9\u05de\u05d4,\n\u05d4\u05e8\u05d9\u05de\u05d5 \u05d0\u05ea \u05d6\u05d4 \u05dc\u05de\u05d5\u05d3\u05e2\u05d5\u05ea \u05d5\u05ea\u05e0\u05d5 \u05dc\u05d6\u05d4 \u05dc\u05e9\u05d4\u05d5\u05ea \u05d1\u05de\u05d5\u05d3\u05e2\u05d5\u05ea \u05db\u05d3\u05d9 \u05dc\u05e4\u05e0\u05d5\u05ea \u05de\u05e7\u05d5\u05dd \u05dc\u05ea\u05d5\u05d1\u05e0\u05d5\u05ea \u05de\u05d0\u05ea\u05de\u05d5\u05dc \u05db\u05d3\u05d9 \u05dc\u05e4\u05e2\u05d5\u05dc \u05d1\u05e6\u05d5\u05e8\u05d4 \u05d7\u05d3\u05e9\u05d4   \u05dc\u05d0\u05d5\u05e8 \u05d4\u05ea\u05d5\u05d1\u05e0\u05d5\u05ea.\n\u05d0\u05dc \u05ea\u05d3\u05d7\u05d5 \u05d0\u05ea \u05d4\u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05e2\u05dc \u05d0\u05ea\u05de\u05d5\u05dc \u05d6\u05d4 \u05d4\u05e8\u05d2\u05e2 \u05dc\u05d4\u05ea\u05d1\u05d5\u05e0\u05df \u05db\u05d3\u05d9 \u05dc\u05d5\u05de\u05e8 \u05dc\u05e2\u05e6\u05de\u05d9 \u05de\u05d4 \u05e9\u05d4\u05d9\u05d4 \u05db\u05d5\u05d0\u05d1 \u05d5\u05de\u05d0\u05ea\u05d2\u05e8 \u05d0\u05ea\u05de\u05d5\u05dc \u05dc\u05d0 \u05d7\u05d9\u05d9\u05d1 \u05dc\u05d4\u05d9\u05de\u05e9\u05da \u05d4\u05d9\u05d5\u05dd. \u05dc\u05de\u05d3\u05ea\u05d9 \u05d0\u05ea \u05d4\u05e9\u05d9\u05e2\u05d5\u05e8 \u05e9\u05dc \u05d0\u05d9\u05e8\u05d5\u05e2\u05d9 \u05d4\u05e2\u05d1\u05e8 \u05d5\u05d0\u05e0\u05d9 \u05d9\u05db\u05d5\u05dc/\u05d4 \u05dc\u05d4\u05ea\u05d7\u05d3\u05e9 \u05e2\u05dd \u05d4\u05d9\u05d5\u05dd \u05d5\u05dc\u05d4\u05d1\u05e2\u05d9\u05e8 \u05d0\u05ea \u05d0\u05e9 \u05d4\u05e8\u05e6\u05d5\u05df, \u05d4\u05de\u05d5\u05d8\u05d9\u05d1\u05e6\u05d9\u05d4 \u05d5\u05d4\u05d4\u05e9\u05e8\u05d0\u05d4 \u05d1\u05ea\u05d5\u05db\u05d9. \u05d4\u05e2\u05d1\u05e8 \u05e2\u05d1\u05e8 \u05d5\u05d4\u05d9\u05d5\u05dd \u05d9\u05d5\u05dd \u05d7\u05d3\u05e9 \u05de\u05ea\u05d7\u05d9\u05dc.\n\u05dc\u05d4\u05e4\u05d5\u05da \u05d0\u05e4\u05e8 \u05dc\u05d0\u05d3\u05de\u05d4 \u05e9\u05dc \u05d7\u05d9\u05d9\u05dd\n\u05d4\u05d0\u05e4\u05e8 \u05d0\u05d9\u05e0\u05d5 \u05d0\u05d5\u05d9\u05d1 \u05d4\u05d5\u05d0 \u05ea\u05d5\u05e6\u05d0\u05d4 \u05e9\u05dc \u05d0\u05e9.\n\u05d4\u05d5\u05d0 \u05d4\u05e9\u05d9\u05e2\u05d5\u05e8 \u05e9\u05d4\u05d9\u05d9\u05e0\u05d5 \u05e6\u05e8\u05d9\u05db\u05d9\u05dd \u05dc\u05dc\u05de\u05d5\u05d3\n\u05d4\u05d5\u05d0 \u05e0\u05ea\u05df \u05dc\u05e0\u05d5 \u05de\u05ea\u05e0\u05d5\u05ea \u05dc\u05e6\u05d3 \u05db\u05d0\u05d1.\n\u05db\u05de\u05d5 \u05e9\u05d4\u05d0\u05e4\u05e8 \u05d1\u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9 \u05de\u05d6\u05db\u05d9\u05e8 \u05d0\u05ea \u05d4\u05d1\u05e9\u05e8 \u05e9\u05e0\u05d0\u05db\u05dc \u05dc\u05e6\u05d3 \u05d4\u05e7\u05e8\u05d1\u05df \u05e9\u05d0\u05d9\u05ea\u05d5 \u05d4\u05d2\u05d9\u05e2.\n\u05db\u05da \u05db\u05dc \u05dc\u05d9\u05de\u05d5\u05d3 \u05d1\u05d7\u05d9\u05d9\u05dd \u05de\u05d1\u05d9\u05d0 \u05d0\u05d9\u05ea\u05d5 \u05d0\u05d9\u05d6\u05d4 \u05db\u05d0\u05d1\n\u05d0\u05d1\u05dc \u05d1\u05e8\u05d2\u05e2 \u05e9\u05de\u05ea\u05d1\u05d5\u05e0\u05e0\u05d9\u05dd \u05d1\u05ea\u05d5\u05d1\u05e0\u05d5\u05ea \u05e9\u05e6\u05de\u05d7\u05d5\n\u05de\u05d4\u05d0\u05ea\u05d2\u05e8\u05d9\u05dd \u05d5\u05d4\u05db\u05d0\u05d1\n\u05d4\u05e1\u05d1\u05dc \u05e4\u05d5\u05d7\u05ea \u05d5\u05ea\u05d7\u05d5\u05e9\u05ea \u05d4\u05d5\u05d3\u05d9\u05d4 \u05d5\u05d7\u05db\u05de\u05ea \u05d7\u05d9\u05d9\u05dd\n\u05de\u05d2\u05d9\u05e2\u05d5\u05ea \u05d1\u05de\u05e7\u05d5\u05dd \u05d4\u05e1\u05d1\u05dc.\n\u05d4\u05ea\u05d5\u05d1\u05e0\u05d5\u05ea \u05e9\u05e0\u05d5\u05e6\u05e8\u05d5 \u05de\u05d4\u05db\u05d0\u05d1 \u05e0\u05d5\u05ea\u05e0\u05d5\u05ea \u05d0\u05ea \u05d4\u05db\u05d5\u05d7 \u05dc\u05d4\u05de\u05e9\u05d9\u05da.\n\u05db\u05d0\u05e9\u05e8 \u05de\u05d7\u05dc\u05d9\u05e4\u05d9\u05dd \u05d0\u05ea \u05ea\u05d7\u05d5\u05e9\u05ea \u05d4\u05db\u05d0\u05d1 \u05d1\u05de\u05d5\u05db\u05e0\u05d5\u05ea\n\u05dc\u05dc\u05de\u05d5\u05d3 \u05de\u05d0\u05d9\u05e8\u05d5\u05e2\u05d9 \u05d4\u05e2\u05d1\u05e8 \u05d1\u05de\u05e7\u05d5\u05dd \u05dc\u05d4\u05d9\u05d7\u05e0\u05e7 \u05de\u05e8\u05d2\u05d9\u05e9\u05d9\u05dd \u05de\u05d5\u05d6\u05e0\u05d9\u05dd \u05d5\u05de\u05d0\u05d9\u05e8\u05d9\u05dd.\n\u05d4\u05db\u05d0\u05d1 \u05d4\u05d5\u05e4\u05da \u05dc\u05e8\u05d2\u05d9\u05e9\u05d5\u05ea,\n\u05d4\u05e7\u05d5\u05e9\u05d9 \u05dc\u05d4\u05d1\u05e0\u05d4,\n\u05d4\u05e2\u05d1\u05e8 \u05dc\u05d1\u05e9\u05dc\u05d5\u05ea.\n\u05dc\u05e4\u05e0\u05d5\u05ea \u05db\u05d3\u05d9 \u05dc\u05d4\u05d9\u05d3\u05dc\u05e7\n\u05ea\u05e8\u05d5\u05de\u05ea \u05d4\u05d3\u05e9\u05df \u05de\u05dc\u05de\u05d3\u05ea \u05d0\u05d5\u05ea\u05e0\u05d5:\n\u05dc\u05de\u05e8\u05d5\u05ea \u05d4\u05e8\u05e6\u05d5\u05df \u05e9\u05d4\u05d0\u05e9 \u05ea\u05d3\u05dc\u05d5\u05e7 \u05dc\u05dc\u05d0 \u05e2\u05d1\u05d5\u05d3\u05d4 \u05ea\u05d5\u05d3\u05e2\u05ea\u05d9\u05ea, \u05e7\u05e9\u05d4 \u05dc\u05d4\u05ea\u05d7\u05d9\u05dc \u05d0\u05ea \u05d4\u05d9\u05d5\u05dd  \u05d1\u05d0\u05e9 \u05d3\u05d5\u05dc\u05e7\u05ea, \u05d1\u05dc\u05d9 \u05dc\u05e4\u05e0\u05d5\u05ea \u05d0\u05ea \u05de\u05d4 \u05e9\u05de\u05e1\u05ea\u05d9\u05e8 \u05d0\u05ea \u05d4\u05d2\u05d7\u05dc\u05d9\u05dd \u05d4\u05d7\u05d3\u05e9\u05d5\u05ea.\n\u05db\u05e9\u05de\u05e4\u05e0\u05d9\u05dd \u05dc\u05d2\u05d7\u05dc\u05d9\u05dd \u05de\u05e7\u05d5\u05dd \u05d4\u05d0\u05e9 \u05d7\u05d5\u05d6\u05e8\u05ea \u05dc\u05d1\u05e2\u05d5\u05e8.\n\u05d0\u05e9 \u05e9\u05dc \u05d7\u05d9\u05d5\u05ea, \u05d0\u05e9 \u05e9\u05dc \u05de\u05d5\u05d8\u05d9\u05d1\u05e6\u05d9\u05d4  \u05d5\u05d9\u05e6\u05d9\u05e8\u05d4, \u05d0\u05e9 \u05e9\u05dc \u05e9\u05de\u05d7\u05d4 \u05e2\u05de\u05d5\u05e7\u05d4 - \u05d0\u05e9 \u05ea\u05de\u05d9\u05d3.\n1. \u05d1\u05d2\u05d3\u05d9 \u05d4\u05db\u05d4\u05df \u2013 \u05de\u05d1\u05e0\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9 \u05e9\u05dc \u05d4\u05e0\u05e4\u05e9\n\u05d4\u05ea\u05d5\u05e8\u05d4 \u05de\u05e6\u05d5\u05d5\u05d4:\n"\u05d5\u05b0\u05e2\u05b8\u05e9\u05c2\u05d5\u05bc \u05dc\u05b0\u05d0\u05b7\u05d4\u05b2\u05e8\u05b9\u05df \u05d0\u05b6\u05ea \u05d1\u05b0\u05bc\u05d2\u05b8\u05d3\u05b8\u05d9\u05d5 \u05dc\u05b0\u05e7\u05b8\u05d3\u05b0\u05e9\u05c1\u05d5\u05b9 \u05dc\u05b0\u05db\u05b8\u05d1\u05d5\u05b9\u05d3" (\u05e9\u05de\u05d5\u05ea \u05db"\u05d7, \u05d1\')\n\u05d1\u05d2\u05d3\u05d9 \u05d4\u05db\u05d4\u05df \u05d0\u05d9\u05e0\u05dd \u05e8\u05e7 \u05dc\u05d1\u05d5\u05e9 \u05d7\u05d9\u05e6\u05d5\u05e0\u05d9 \u2013 \u05d4\u05dd \u05de\u05e4\u05ea \u05d3\u05e8\u05db\u05d9\u05dd \u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05dc\u05e0\u05e4\u05e9 \u05d4\u05d0\u05d3\u05dd. \u05dc\u05e4\u05d9 \u05e4\u05e8\u05e9\u05e0\u05d5\u05ea \u05d7\u05e1\u05d9\u05d3\u05d9\u05ea \u05d5\u05e8\u05de\u05d7"\u05dc:\n\u05d4\u05d0\u05d1\u05e0\u05d8 (\u05d4\u05d7\u05d2\u05d5\u05e8\u05d4) \u2013 \u05e8\u05d9\u05db\u05d5\u05d6 \u05db\u05d5\u05d7 \u05d4\u05e8\u05e6\u05d5\u05df \u05d5\u05e9\u05dc\u05d9\u05d8\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05e2\u05dc \u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05d5\u05e8\u05d2\u05e9\u05d5\u05ea (\u05e8\u05de\u05d7"\u05dc, \u05de\u05e1\u05d9\u05dc\u05ea \u05d9\u05e9\u05e8\u05d9\u05dd, \u05e4\u05e8\u05e7 \u05d5\').\n\u05d4\u05d7\u05d5\u05dc\u05e6\u05d4 (\u05dc\u05d1\u05df) \u2013 \u05d8\u05d5\u05d4\u05e8 \u05de\u05d9\u05d3\u05d5\u05ea \u05d5\u05e0\u05d9\u05e7\u05d5\u05d9 \u05e4\u05e0\u05d9\u05de\u05d9, \u05d4\u05db\u05e0\u05d4 \u05dc\u05e7\u05d1\u05dc\u05ea \u05d0\u05d5\u05e8 \u05d0\u05dc\u05d5\u05e7\u05d9 (\u05d4\u05e8\u05e9"\u05e9, \u05e9\u05dd).\n\u05d4\u05de\u05db\u05e0\u05e1\u05d9\u05d9\u05dd (\u05dc\u05d1\u05df) \u2013 \u05e6\u05e0\u05d9\u05e2\u05d5\u05ea \u05d5\u05d4\u05e1\u05d3\u05e8\u05ea \u05db\u05d5\u05d7\u05d5\u05ea \u05d1\u05e1\u05d9\u05e1\u05d9\u05d9\u05dd, \u05e9\u05dc\u05d9\u05d8\u05d4 \u05e2\u05dc \u05ea\u05e9\u05d5\u05e7\u05d5\u05ea \u05d4\u05d2\u05d5\u05e3.\n\u05d4\u05d0\u05e4\u05d5\u05d3 (\u05d4\u05e1\u05d9\u05e0\u05e8) \u2013 \u05d4\u05d1\u05d7\u05e0\u05d4 \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea, \u05e8\u05d0\u05d9\u05d9\u05ea \u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea \u05db\u05e4\u05d9 \u05e9\u05d4\u05d9\u05d0, \u05d5\u05e9\u05de\u05d9\u05e8\u05d4 \u05e2\u05dc \u05d9\u05d5\u05e9\u05e8\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea.\n\u05d4\u05de\u05e2\u05d8\u05d4 (\u05de\u05e2\u05d9\u05dc) \u2013 \u05d4\u05e8\u05d7\u05d1\u05ea \u05d4\u05d7\u05e1\u05d3 \u05d5\u05d4\u05d0\u05d4\u05d1\u05d4 \u05db\u05dc\u05e4\u05d9 \u05d0\u05d7\u05e8\u05d9\u05dd, \u05e9\u05dc\u05de\u05d5\u05ea \u05e4\u05e0\u05d9\u05de\u05d9\u05ea.\n\u05d4\u05e6\u05d9\u05e5 (\u05db\u05d9\u05e4\u05d4) \u05e2\u05dc \u05d4\u05e8\u05d0\u05e9 \u2013 \u05e1\u05de\u05dc \u05dc\u05db\u05d5\u05d5\u05e0\u05d4 \u05d8\u05d4\u05d5\u05e8\u05d4 \u05d5\u05de\u05d7\u05e9\u05d1\u05d4 \u05de\u05de\u05d5\u05e7\u05d3\u05ea \u05d1\u05e2\u05d1\u05d5\u05d3\u05ea \u05d4\u05e7\u05d5\u05d3\u05e9; \u05de\u05d2\u05df \u05e2\u05dc \u05d4\u05e9\u05db\u05dc \u05d5\u05d4\u05dc\u05d1 \u05d5\u05de\u05d3\u05d2\u05d9\u05e9 \u05e9\u05d4\u05e2\u05d1\u05d5\u05d3\u05d4 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05de\u05ea\u05d7\u05d9\u05dc\u05d4 \u05d1\u05de\u05d5\u05d3\u05e2\u05d5\u05ea (\u05e9\u05de\u05d5\u05ea \u05db"\u05d7, \u05d3\'; \u05e8\u05e9"\u05d9; \u05e8\u05de\u05d7"\u05dc, \u05de\u05e1\u05d9\u05dc\u05ea \u05d9\u05e9\u05e8\u05d9\u05dd, \u05e4\u05e8\u05e7 \u05d5\'; \u05d7\u05d1"\u05d3, \u05ea\u05d5\u05e8\u05ea \u05d4\u05d7\u05e1\u05d9\u05d3\u05d5\u05ea, \u05e4\u05e8\u05e9\u05ea \u05e6\u05d5).\n\u05de\u05d9\u05d3\u05d5 \u05d1\u05d3 \u2013 \u05d1\u05d3 \u05e6\u05de\u05d5\u05d3 \u05dc\u05e4\u05d9 \u05de\u05d9\u05d3\u05d5\u05ea\u05d9\u05d5 \u05e9\u05dc \u05d4\u05db\u05d4\u05df (\u05e9\u05de\u05d5\u05ea \u05db"\u05d7, \u05d1\'; \u05e8\u05e9"\u05d9; \u05e8\u05de\u05d1"\u05dd, \u05d4\u05dc\u05db\u05d5\u05ea \u05d1\u05d9\u05ea \u05d4\u05d1\u05d7\u05d9\u05e8\u05d4, \u05e4\u05e8\u05e7 \u05d8"\u05d5). \u05d4\u05d7\u05e1\u05d9\u05d3\u05d5\u05ea \u05de\u05e4\u05e8\u05e9\u05ea \u05d6\u05d0\u05ea \u05db\u05e1\u05de\u05dc \u05dc\u05e9\u05dc\u05d9\u05d8\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05d5\u05d4\u05e8\u05de\u05d5\u05e0\u05d9\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea: \u05d4\u05d0\u05d3\u05dd \u05e6\u05e8\u05d9\u05da \u201c\u05dc\u05dc\u05d1\u05d5\u05e9\u201d \u05d0\u05ea \u05de\u05d9\u05d3\u05d5\u05ea\u05d9\u05d5 \u05d4\u05e0\u05e4\u05e9\u05d9\u05d5\u05ea \u05d1\u05e6\u05d5\u05e8\u05d4 \u05de\u05e1\u05d5\u05d3\u05e8\u05ea, \u05de\u05d3\u05d5\u05d9\u05e7\u05ea \u05d5\u05de\u05db\u05d5\u05d5\u05e0\u05ea, \u05db\u05d3\u05d9 \u05dc\u05d1\u05e6\u05e2 \u05e2\u05d1\u05d5\u05d3\u05d4 \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea \u05d1\u05e6\u05d5\u05e8\u05d4 \u05e9\u05dc\u05de\u05d4.\n\u05db\u05dc \u05d0\u05d7\u05d3 \u05de\u05d4\u05d1\u05d2\u05d3\u05d9\u05dd \u05d4\u05d5\u05d0 \u05ea\u05d6\u05db\u05d5\u05e8\u05ea \u05dc\u05e2\u05d1\u05d5\u05d3\u05d4 \u05e0\u05e4\u05e9\u05d9\u05ea: \u05db\u05d0\u05e9\u05e8 \u05d4\u05d0\u05d3\u05dd \u05de\u05ea\u05e8\u05d2\u05dc \u05de\u05d5\u05d3\u05e2\u05d5\u05ea, \u05d3\u05e8\u05da \u05d8\u05e7\u05e1\u05d8 \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d5\u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea \u05d1\u05e4\u05e8\u05d8\u05d9 \u05d4\u05dc\u05d1\u05d5\u05e9, \u05d4\u05d5\u05d0 \u05dc\u05de\u05e2\u05e9\u05d4 "\u05dc\u05d5\u05d1\u05e9" \u05d0\u05ea \u05d4\u05d1\u05d2\u05d3\u05d9\u05dd \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05d9\u05dd \u2013 \u05de\u05d6\u05db\u05d9\u05e8 \u05dc\u05e2\u05e6\u05de\u05d9 \u05dc\u05e1\u05d3\u05e8 \u05d0\u05ea \u05d4\u05de\u05d9\u05d3\u05d5\u05ea, \u05dc\u05db\u05d5\u05d5\u05df \u05d0\u05ea \u05d4\u05e8\u05e6\u05d5\u05df, \u05d5\u05dc\u05d4\u05ea\u05d7\u05d1\u05e8 \u05dc\u05d0\u05d5\u05e8 \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9.\n2. \u05ea\u05d5\u05e8\u05ea \u05d4\u05e2\u05d5\u05dc\u05d4 \u2013 \u05d4\u05e2\u05dc\u05d0\u05ea \u05d4\u05e8\u05e6\u05d5\u05df \u05dc\u05d0\u05e9 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05ea\n\u05d4\u05ea\u05d5\u05e8\u05d4 \u05de\u05e6\u05d5\u05d5\u05d4:\n"\u05d5\u05b0\u05d4\u05b8\u05e2\u05b9\u05dc\u05b8\u05d4 \u05dc\u05b0\u05d0\u05b5\u05e9\u05c1 \u05ea\u05bc\u05b4\u05d4\u05b0\u05d9\u05b6\u05d4" (\u05d5\u05d9\u05e7\u05e8\u05d0 \u05d0\', 3)\n\u05dc\u05e4\u05d9 \u05d4\u05d7\u05e1\u05d9\u05d3\u05d5\u05ea, \u05d4\u05e7\u05e8\u05d1\u05ea \u05d4\u05e2\u05d5\u05dc\u05d4 \u05d4\u05d9\u05d0 \u05e1\u05de\u05dc \u05dc\u05d4\u05e2\u05dc\u05d0\u05ea \u05db\u05dc \u05d7\u05dc\u05e7\u05d9 \u05d4\u05d0\u05d3\u05dd \u2013 \u05de\u05d7\u05e9\u05d1\u05d5\u05ea, \u05e8\u05d2\u05e9\u05d5\u05ea \u05d5\u05ea\u05e9\u05d5\u05e7\u05d5\u05ea \u2013 \u05dc\u05d0\u05d5\u05e8 \u05e4\u05e0\u05d9\u05de\u05d9 \u05e9\u05de\u05d7\u05d5\u05d1\u05e8 \u05dc\u05e0\u05e9\u05de\u05d4 (\u05d7\u05d1"\u05d3, \u05e1\u05e4\u05e8 \u05ea\u05d4\u05dc\u05ea \u05d4\').\n\u05d4\u05d0\u05e9 \u05e9\u05dc\u05d0 \u05e0\u05db\u05d1\u05d9\u05ea \u2013 \u05de\u05e1\u05de\u05dc\u05ea \u05e9\u05d4\u05e8\u05e6\u05d5\u05df \u05d4\u05e4\u05e0\u05d9\u05de\u05d9 \u05dc\u05e2\u05d1\u05d5\u05d3 \u05d0\u05ea \u05d4\u05d1\u05d5\u05e8\u05d0 \u05ea\u05de\u05d9\u05d3 \u05e0\u05e9\u05d0\u05e8 \u05e7\u05d9\u05d9\u05dd, \u05d2\u05dd \u05de\u05d5\u05dc \u05e0\u05e4\u05d9\u05dc\u05d5\u05ea \u05d5\u05db\u05e9\u05dc\u05d9\u05dd. \u05d4\u05d0\u05e9 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05e9\u05dc \u05d4\u05e0\u05e9\u05de\u05d4 \u05ea\u05de\u05d9\u05d3 \u05e0\u05d9\u05ea\u05e0\u05ea \u05dc\u05d4\u05d3\u05dc\u05e7\u05d4 \u05de\u05d7\u05d3\u05e9 \u05d1\u05d0\u05de\u05e6\u05e2\u05d5\u05ea \u05ea\u05e4\u05d9\u05dc\u05d4, \u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d5\u05de\u05d5\u05d3\u05e2\u05d5\u05ea \u05e4\u05e0\u05d9\u05de\u05d9\u05ea (\u05e8\u05de\u05d7"\u05dc, \u05de\u05e1\u05d9\u05dc\u05ea \u05d9\u05e9\u05e8\u05d9\u05dd, \u05e4\u05e8\u05e7 \u05d5\').\n\u05db\u05da, \u05d4\u05e2\u05d5\u05dc\u05d4 \u05d0\u05d9\u05e0\u05d4 \u05e8\u05e7 \u05e7\u05e8\u05d1\u05df \u05d7\u05d9\u05e6\u05d5\u05e0\u05d9 \u2013 \u05d4\u05d9\u05d0 \u05ea\u05e8\u05d2\u05d5\u05dc \u05e4\u05e0\u05d9\u05de\u05d9 \u05e9\u05dc \u05d4\u05e2\u05dc\u05d0\u05ea \u05db\u05dc \u05d7\u05dc\u05e7\u05d9 \u05d4\u05e2\u05e6\u05de\u05d9 \u05dc\u05d0\u05d5\u05e8 \u05d5\u05e7\u05d3\u05d5\u05e9\u05d4.\n3. \u05d4\u05e6\u05d9\u05d5\u05d5\u05d9 \u2013 \u05d4\u05e4\u05e2\u05dc\u05ea \u05d4\u05e8\u05e6\u05d5\u05df \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\n\u05d4\u05ea\u05d5\u05e8\u05d4 \u05de\u05e6\u05d5\u05d5\u05d4:\n"\u05e6\u05b7\u05d5 \u05d0\u05b6\u05ea\u05be\u05d1\u05b0\u05bc\u05e0\u05b5\u05d9 \u05d9\u05b4\u05e9\u05b0\u05c2\u05e8\u05b8\u05d0\u05b5\u05dc" (\u05e9\u05de\u05d5\u05ea \u05db"\u05d8, \u05d0\')\n\u05d4\u05d7\u05e1\u05d9\u05d3\u05d5\u05ea \u05de\u05e4\u05e8\u05e9\u05ea: \u05d4\u05e6\u05d9\u05d5\u05d5\u05d9 \u05d0\u05d9\u05e0\u05d5 \u05e8\u05e7 \u05e4\u05e7\u05d5\u05d3\u05d4 \u05d7\u05d9\u05e6\u05d5\u05e0\u05d9\u05ea, \u05d0\u05dc\u05d0 \u05d4\u05d6\u05de\u05e0\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05dc\u05e0\u05e4\u05e9 \u05dc\u05e4\u05e2\u05d5\u05dc \u05d1\u05e8\u05e6\u05d5\u05df \u05de\u05d5\u05d3\u05e2 (\u05ea\u05d5\u05e8\u05ea \u05d4\u05d7\u05e1\u05d9\u05d3\u05d5\u05ea, \u05db\u05e8\u05da \u05d1\', \u05e4\u05e8\u05e9\u05ea \u05e6\u05d5).\n\u05d4\u05e6\u05d9\u05d5\u05d5\u05d9 \u05de\u05e2\u05d5\u05e8\u05e8 \u05d0\u05ea \u05d4\u05d0\u05d3\u05dd \u05dc\u05d4\u05e9\u05ea\u05de\u05e9 \u05d1\u05db\u05d5\u05d7\u05d5\u05ea \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05d9\u05dd \u05e9\u05dc\u05d5 \u2013 \u05dc\u05d0 \u05e8\u05e7 \u05dc\u05d1\u05e6\u05e2 \u05de\u05e6\u05d5\u05d5\u05ea \u05d0\u05d5\u05d8\u05d5\u05de\u05d8\u05d9\u05ea, \u05d0\u05dc\u05d0 \u05dc\u05d4\u05e4\u05e2\u05d9\u05dc \u05d0\u05ea \u05d4\u05e8\u05e6\u05d5\u05df \u05d5\u05d4\u05de\u05d5\u05d3\u05e2\u05d5\u05ea \u05d1\u05d0\u05d5\u05e4\u05df \u05e4\u05e2\u05d9\u05dc (\u05e8\u05de\u05d7"\u05dc, \u05de\u05e1\u05d9\u05dc\u05ea \u05d9\u05e9\u05e8\u05d9\u05dd, \u05e4\u05e8\u05e7 \u05d8"\u05d5).\n\u05d4\u05e6\u05d9\u05d5\u05d5\u05d9 \u05de\u05d4\u05d5\u05d5\u05d4 \u05d0\u05ea \u05d4\u05de\u05e4\u05ea\u05d7 \u05dc\u05d4\u05d3\u05dc\u05e7\u05ea \u05d4\u05d0\u05e9 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05d5\u05dc\u05d7\u05d9\u05d1\u05d5\u05e8 \u05d1\u05d9\u05df \u05d4\u05e8\u05e6\u05d5\u05df \u05d4\u05e4\u05e0\u05d9\u05de\u05d9 \u05dc\u05e4\u05e2\u05d5\u05dc\u05d5\u05ea \u05d1\u05e2\u05d5\u05dc\u05dd \u05d4\u05d7\u05d9\u05e6\u05d5\u05e0\u05d9.\n4. \u05ea\u05e8\u05d5\u05de\u05ea \u05d4\u05d3\u05e9\u05df \u2013 \u05e0\u05d9\u05e7\u05d5\u05d9 \u05e4\u05e0\u05d9\u05de\u05d9\n\u05d4\u05d3\u05e9\u05df, \u05e9\u05de\u05d5\u05e7\u05e8\u05d1 \u05d5\u05e2\u05d5\u05dc\u05d4 \u05d1\u05d0\u05e9, \u05de\u05e1\u05de\u05dc \u05d0\u05ea \u05ea\u05d4\u05dc\u05d9\u05da \u05d4\u05e0\u05d9\u05e7\u05d5\u05d9 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9:\n\u05db\u05dc \u05e8\u05d2\u05e9\u05d5\u05ea \u05e9\u05dc\u05d9\u05dc\u05d9\u05d9\u05dd, \u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05db\u05d5\u05d0\u05d1\u05d5\u05ea \u05d5\u05d4\u05ea\u05e0\u05d4\u05d2\u05d5\u05d9\u05d5\u05ea \u05d4\u05e8\u05e1\u05e0\u05d9\u05d5\u05ea \u05e0\u05e9\u05e8\u05e4\u05d9\u05dd \u05d1\u05d0\u05e9 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05ea.\n\u05de\u05d4 \u05e9\u05e0\u05e9\u05d0\u05e8 \u05d4\u05d5\u05d0 \u05d4\u05d0\u05e4\u05e8 \u2013 \u05d7\u05d5\u05db\u05de\u05d4, \u05e9\u05e7\u05d8 \u05e4\u05e0\u05d9\u05de\u05d9, \u05d5\u05ea\u05d5\u05d1\u05e0\u05d4 \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea.',"\u05ea\u05e8\u05d2\u05d5\u05dc: \u05e7\u05d7\u05d5 \u05e0\u05e9\u05d9\u05de\u05d4 \u05e2\u05de\u05d5\u05e7\u05d4 , \u05d3\u05de\u05d9\u05d9\u05e0\u05d5 \u05d0\u05ea \u05db\u05dc \u05d4\u05de\u05d9\u05d3\u05d5\u05ea \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05d5\u05ea \u2013 \u05d3\u05de\u05d9\u05d9\u05e0\u05d5 \u05e9\u05db\u05dc \u05d1\u05d2\u05d3 \u05de\u05e1\u05d3\u05e8 \u05d0\u05ea \u05d7\u05dc\u05e7\u05d9 \u05d4\u05e0\u05e4\u05e9 \u05d5\u05d0\u05ea \u05d4\u05e8\u05e6\u05d5\u05df \u05e9\u05dc\u05db\u05dd \u05dc\u05e2\u05d1\u05d5\u05d3 \u05d0\u05ea \u05d4\u05e7\u05d5\u05d3\u05e9.",'5. \u05e1\u05d9\u05db\u05d5\u05dd \u2013 \u05de\u05d1\u05e0\u05d4 \u05e2\u05d1\u05d5\u05d3\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea\n\u05dc\u05d1\u05d9\u05e9\u05ea \u05d1\u05d2\u05d3\u05d9\u05dd \u05e4\u05e0\u05d9\u05de\u05d9\u05d9\u05dd \u2013 \u05e1\u05d9\u05d3\u05d5\u05e8 \u05de\u05d9\u05d3\u05d5\u05ea, \u05e0\u05d9\u05e7\u05d5\u05d9, \u05e8\u05d9\u05db\u05d5\u05d6 \u05db\u05d5\u05d5\u05e0\u05d4 (\u05d7\u05d5\u05dc\u05e6\u05d4, \u05de\u05db\u05e0\u05e1\u05d9\u05d9\u05dd, \u05d4\u05ea\u05d0\u05d1\u05e0\u05d8, \u05d0\u05e4\u05d5\u05d3, \u05de\u05e2\u05d8\u05d4, \u05e6\u05d9\u05e5/\u05db\u05d9\u05e4\u05d4, \u05de\u05d9\u05d3\u05d5 \u05d1\u05d3).\n\u05d4\u05e2\u05d5\u05dc\u05d4 \u05d5\u05d4\u05d0\u05e9 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u2013 \u05d4\u05e2\u05dc\u05d0\u05ea \u05d4\u05e8\u05e6\u05d5\u05e0\u05d5\u05ea \u05d5\u05d4\u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05dc\u05d0\u05d5\u05e8, \u05e9\u05de\u05d9\u05e8\u05d4 \u05e2\u05dc \u05d4\u05d0\u05e9 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05e9\u05d0\u05d9\u05e0\u05d4 \u05e0\u05db\u05d1\u05d9\u05ea.\n\u05d4\u05e6\u05d5 \u2013 \u05d4\u05e4\u05e2\u05dc\u05ea \u05d4\u05e8\u05e6\u05d5\u05df \u05d4\u05de\u05d5\u05d3\u05e2 \u05d5\u05d4\u05db\u05d5\u05d5\u05e0\u05d4 \u05d1\u05e4\u05e2\u05d5\u05dc\u05d5\u05ea \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05d5\u05ea \u05d5\u05d4\u05d7\u05d9\u05e6\u05d5\u05e0\u05d9\u05d5\u05ea.\n\u05ea\u05e8\u05d5\u05de\u05ea \u05d4\u05d3\u05e9\u05df \u2013 \u05e9\u05d7\u05e8\u05d5\u05e8 \u05e2\u05d5\u05de\u05e1 \u05e0\u05e4\u05e9\u05d9 \u05d5\u05e9\u05d9\u05e0\u05d5\u05d9 \u05d7\u05d5\u05de\u05e8\u05d9\u05dd \u05e9\u05dc\u05d9\u05dc\u05d9\u05d9\u05dd \u05dc\u05d0\u05e4\u05e8 \u05e4\u05e0\u05d9\u05de\u05d9 \u05e9\u05dc \u05d7\u05d5\u05db\u05de\u05d4 \u05d5\u05d8\u05d5\u05d4\u05e8.\n\u05e1\u05d9\u05db\u05d5\u05dd \u05e8\u05d5\u05d7\u05e0\u05d9:\n\u05db\u05dc \u05e4\u05e8\u05d8 \u05d1\u05e4\u05e8\u05e9\u05d5\u05ea \u05ea\u05e8\u05d5\u05de\u05ea \u05d4\u05d3\u05e9\u05df \u05d5-\u05e6\u05d5\u05d5 \u05d4\u05d5\u05d0 \u05de\u05d3\u05e8\u05d9\u05da \u05dc\u05e2\u05d1\u05d5\u05d3\u05ea \u05e0\u05e4\u05e9 \u05d9\u05d5\u05de\u05d9\u05ea: \u05d4\u05db\u05e0\u05d4, \u05e0\u05d9\u05e7\u05d5\u05d9, \u05d4\u05ea\u05e2\u05dc\u05d5\u05ea \u05d5\u05d7\u05d9\u05d1\u05d5\u05e8 \u05e4\u05e0\u05d9\u05de\u05d9 \u05dc\u05d0\u05d5\u05e8 \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9. \u05d1\u05d2\u05d3\u05d9 \u05d4\u05db\u05d4\u05df, \u05d4\u05e6\u05d9\u05d5\u05d5\u05d9, \u05d4\u05e2\u05d5\u05dc\u05d4 \u05d5\u05d4\u05d0\u05e9 \u05de\u05e1\u05de\u05dc\u05d9\u05dd \u05d0\u05ea \u05d4\u05d3\u05e8\u05da \u05e9\u05d1\u05d4 \u05d4\u05d0\u05d3\u05dd \u05d9\u05db\u05d5\u05dc \u05dc\u05d0\u05e8\u05d2\u05df \u05d0\u05ea \u05e0\u05e4\u05e9\u05d5, \u05dc\u05e4\u05e2\u05d5\u05dc \u05d1\u05e8\u05e6\u05d5\u05df \u05de\u05d5\u05d3\u05e2 \u05d5\u05dc\u05d4\u05ea\u05d7\u05d1\u05e8 \u05dc\u05e7\u05d3\u05d5\u05e9\u05d4 \u05d1\u05db\u05dc \u05e8\u05d2\u05e2 \u05d1\u05d7\u05d9\u05d9\u05dd.\n\u05ea\u05e8\u05d5\u05de\u05ea \u05d4\u05d3\u05e9\u05df \u05d5\u05d1\u05d2\u05d3\u05d9 \u05d4\u05db\u05d4\u05df\n\u05de\u05d8\u05e8\u05d4: \u05e0\u05d9\u05e7\u05d5\u05d9 \u05e4\u05e0\u05d9\u05de\u05d9, \u05e1\u05d9\u05d3\u05d5\u05e8 \u05de\u05d9\u05d3\u05d5\u05ea \u05e0\u05e4\u05e9\u05d9\u05d5\u05ea, \u05d4\u05e2\u05dc\u05d0\u05ea \u05d4\u05e8\u05e6\u05d5\u05e0\u05d5\u05ea \u05dc\u05d0\u05d5\u05e8, \u05d5\u05d4\u05e4\u05e2\u05dc\u05d4 \u05de\u05d5\u05d3\u05e2\u05ea \u05e9\u05dc \u05d4\u05e6\u05d9\u05d5\u05d5\u05d9 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9.\n\u05e9\u05dc\u05d1 1: \u05d4\u05db\u05e0\u05d4 \u05d5\u05d4\u05db\u05e0\u05e1\u05ea \u05de\u05d5\u05d3\u05e2\u05d5\u05ea\n\u05e9\u05d1\u05d5 \u05d1\u05e0\u05d7\u05ea, \u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05e2\u05e6\u05d5\u05de\u05d5\u05ea, \u05d2\u05d1 \u05d6\u05e7\u05d5\u05e3 \u05d5\u05e0\u05e9\u05d9\u05de\u05d5\u05ea \u05e2\u05de\u05d5\u05e7\u05d5\u05ea.\n\u05d4\u05e8\u05d2\u05d9\u05e9\u05d5 \u05d0\u05ea \u05d4\u05d2\u05d5\u05e3 \u05d5\u05d4\u05e0\u05e9\u05d9\u05de\u05d4. \u05db\u05dc \u05e0\u05e9\u05d9\u05de\u05d4 \u05de\u05de\u05e7\u05d3\u05ea \u05d0\u05ea \u05ea\u05e9\u05d5\u05de\u05ea \u05d4\u05dc\u05d1 \u05e4\u05e0\u05d9\u05de\u05d4.\n\u05d0\u05de\u05e8\u05d5 \u05dc\u05e2\u05e6\u05de\u05db\u05dd \u05d1\u05dc\u05d1:\n"\u05d0\u05e0\u05d9 \u05e4\u05d5\u05ea\u05d7 \u05d0\u05ea \u05dc\u05d9\u05d1\u05d9 \u05d5\u05e0\u05e9\u05de\u05ea\u05d9 \u05dc\u05e2\u05d1\u05d5\u05d3\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea, \u05dc\u05e9\u05d7\u05e8\u05d5\u05e8 \u05d5\u05dc\u05d4\u05ea\u05e2\u05dc\u05d5\u05ea."\n\u05e9\u05dc\u05d1 2: \u05dc\u05d1\u05d9\u05e9\u05ea \u05d4\u05d1\u05d2\u05d3\u05d9\u05dd \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05d9\u05dd\n\u05d3\u05de\u05d9\u05d9\u05e0\u05d5 \u05e9\u05d0\u05ea\u05dd \u05dc\u05d5\u05d1\u05e9\u05d9\u05dd \u05d0\u05ea \u05d1\u05d2\u05d3\u05d9 \u05d4\u05db\u05d4\u05df \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05d9\u05dd:\n\u05d1\u05d2\u05d3\n\u05de\u05e9\u05de\u05e2\u05d5\u05ea \u05e4\u05e0\u05d9\u05de\u05d9\u05ea\n\u05e8\u05d9\u05db\u05d5\u05d6 \u05db\u05d5\u05d7 \u05d4\u05e8\u05e6\u05d5\u05df, \u05e9\u05dc\u05d9\u05d8\u05d4 \u05e2\u05dc \u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05d5\u05e8\u05d2\u05e9\u05d5\u05ea\n\u05d8\u05d5\u05d4\u05e8 \u05de\u05d9\u05d3\u05d5\u05ea \u05d5\u05e0\u05d9\u05e7\u05d5\u05d9 \u05e4\u05e0\u05d9\u05de\u05d9\n\u05de\u05db\u05e0\u05e1\u05d9\u05d9\u05dd (\u05dc\u05d1\u05df)\n\u05e6\u05e0\u05d9\u05e2\u05d5\u05ea, \u05d4\u05e1\u05d3\u05e8\u05ea \u05ea\u05e9\u05d5\u05e7\u05d5\u05ea \u05d4\u05d2\u05d5\u05e3\n\u05d0\u05e4\u05d5\u05d3 (\u05e1\u05d9\u05e0\u05e8)\n\u05d4\u05d1\u05d7\u05e0\u05d4 \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea, \u05e8\u05d0\u05d9\u05d9\u05ea \u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea\n\u05de\u05e2\u05d9\u05dc (\u05de\u05e2\u05d8\u05d4)\n\u05d4\u05e8\u05d7\u05d1\u05ea \u05d7\u05e1\u05d3 \u05d5\u05d0\u05d4\u05d1\u05d4 \u05db\u05dc\u05e4\u05d9 \u05d0\u05d7\u05e8\u05d9\u05dd\n\u05e6\u05d9\u05e5 (\u05db\u05d9\u05e4\u05d4) \u05e2\u05dc \u05d4\u05e8\u05d0\u05e9\n\u05db\u05d5\u05d5\u05e0\u05d4 \u05d8\u05d4\u05d5\u05e8\u05d4 \u05d5\u05de\u05d7\u05e9\u05d1\u05d4 \u05de\u05de\u05d5\u05e7\u05d3\u05ea \u05d1\u05e2\u05d1\u05d5\u05d3\u05ea \u05d4\u05e7\u05d5\u05d3\u05e9\n\u05de\u05d9\u05d3\u05d5 \u05d1\u05d3\n\u05e9\u05dc\u05d9\u05d8\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05d5\u05d4\u05e8\u05de\u05d5\u05e0\u05d9\u05d4, \u05d4\u05ea\u05d0\u05de\u05ea \u05d4\u05e8\u05e6\u05d5\u05df \u05d4\u05e4\u05e0\u05d9\u05de\u05d9 \u05dc\u05e4\u05e2\u05d5\u05dc\u05d4\n\u05e9\u05dc\u05d1 3: \u05d4\u05e2\u05dc\u05d0\u05ea \u05d4\u05e2\u05d5\u05dc\u05d4 \u2013 \u05d0\u05e9 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea\n\u05d3\u05de\u05d9\u05d9\u05e0\u05d5 \u05d0\u05e9 \u05e7\u05d8\u05e0\u05d4 \u05d1\u05dc\u05d1 \u2013 \u05d4\u05d0\u05e9 \u05d4\u05d9\u05d0 \u05d4\u05e8\u05e6\u05d5\u05df \u05dc\u05e2\u05d1\u05d5\u05d3 \u05d0\u05ea \u05d4\u05d1\u05d5\u05e8\u05d0, \u05d4\u05d0\u05e0\u05e8\u05d2\u05d9\u05d4 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05e9\u05dc\u05db\u05dd.\n\u05d4\u05e2\u05dc\u05d5 \u05d1\u05d0\u05e9 \u05db\u05dc \u05e8\u05d2\u05e9\u05d5\u05ea \u05e9\u05dc\u05d9\u05dc\u05d9\u05d9\u05dd, \u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05de\u05e4\u05e8\u05d9\u05e2\u05d5\u05ea, \u05de\u05ea\u05d7\u05d9\u05dd \u05d5\u05e4\u05d7\u05d3\u05d9\u05dd.\n\u05e8\u05d0\u05d5 \u05db\u05d9\u05e6\u05d3 \u05d4\u05d0\u05e9 \u05d4\u05d5\u05e4\u05db\u05ea \u05d0\u05ea \u05d4\u05e2\u05d5\u05de\u05e1 \u05d4\u05d6\u05d4 \u05dc\u05d0\u05e4\u05e8 \u2013 \u05ea\u05d7\u05d5\u05e9\u05ea \u05d7\u05d5\u05db\u05de\u05d4, \u05e9\u05e7\u05d8 \u05e4\u05e0\u05d9\u05de\u05d9, \u05ea\u05d5\u05d1\u05e0\u05d4.\n\u05d6\u05db\u05e8\u05d5: \u05d4\u05d0 \u05d0\u05e9 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05d0\u05d9\u05e0\u05d4 \u05e0\u05db\u05d1\u05d9\u05ea \u2013 \u05ea\u05de\u05d9\u05d3 \u05e0\u05d9\u05ea\u05df \u05dc\u05d4\u05d3\u05dc\u05d9\u05e7 \u05d0\u05d5\u05ea\u05d4 \u05de\u05d7\u05d3\u05e9 \u05d1\u05db\u05dc \u05de\u05e6\u05d1.\n\u05e9\u05dc\u05d1 4: \u05d4\u05e4\u05e2\u05dc\u05ea \u05d4\u05e6\u05d9\u05d5\u05d5\u05d9 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\n\u05d7\u05d6\u05e8\u05d5 \u05e2\u05dc \u05d4\u05de\u05e9\u05e4\u05d8:\n"\u05d0\u05e0\u05d9 \u05de\u05e4\u05e2\u05d9\u05dc \u05d0\u05ea \u05e8\u05e6\u05d5\u05e0\u05d9 \u05d4\u05de\u05d5\u05d3\u05e2 \u05dc\u05e2\u05d1\u05d5\u05d3\u05ea \u05d4\u05e7\u05d5\u05d3\u05e9, \u05d1\u05db\u05dc \u05de\u05d7\u05e9\u05d1\u05d4, \u05e8\u05d2\u05e9 \u05d5\u05de\u05e2\u05e9\u05d4."\n\u05d4\u05ea\u05d7\u05d1\u05e8\u05d5 \u05dc\u05db\u05d5\u05d5\u05e0\u05d4 \u2013 \u05db\u05dc \u05e4\u05e2\u05d5\u05dc\u05d4 \u05d4\u05d9\u05d5\u05dd, \u05d2\u05dd \u05d4\u05e7\u05d8\u05e0\u05d4 \u05d1\u05d9\u05d5\u05ea\u05e8, \u05d9\u05db\u05d5\u05dc\u05d4 \u05dc\u05d4\u05d9\u05d5\u05ea \u05d4\u05e2\u05dc\u05d0\u05d4 \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea \u05d0\u05dd \u05d4\u05d9\u05d0 \u05de\u05d1\u05d5\u05e6\u05e2\u05ea \u05de\u05ea\u05d5\u05da \u05de\u05d5\u05d3\u05e2\u05d5\u05ea \u05e4\u05e0\u05d9\u05de\u05d9\u05ea.\n\u05e9\u05dc\u05d1 5: \u05e1\u05d2\u05d9\u05e8\u05d4\n\u05e0\u05e9\u05de\u05d5 \u05db\u05de\u05d4 \u05e0\u05e9\u05d9\u05de\u05d5\u05ea \u05e2\u05de\u05d5\u05e7\u05d5\u05ea, \u05d3\u05de\u05d9\u05d9\u05e0\u05d5 \u05e9\u05db\u05dc \u05d4\u05d1\u05d2\u05d3\u05d9\u05dd \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05d9\u05dd \u05d5\u05d4\u05d0\u05e9 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05e0\u05e9\u05d0\u05e8\u05d9\u05dd \u05d1\u05ea\u05d5\u05db\u05db\u05dd \u2013 \u05de\u05d5\u05db\u05e0\u05d9\u05dd \u05dc\u05d9\u05d5\u05dd \u05de\u05dc\u05d0 \u05db\u05d5\u05d5\u05e0\u05d4.\n\u05d0\u05de\u05e8\u05d5 \u05dc\u05e2\u05e6\u05de\u05db\u05dd:\n"\u05d0\u05e0\u05d9 \u05de\u05d5\u05db\u05df \u05dc\u05d4\u05ea\u05de\u05d5\u05d3\u05d3 \u05e2\u05dd \u05d4\u05d9\u05d5\u05dd, \u05e2\u05dd \u05e2\u05e6\u05de\u05d9 \u05d5\u05e2\u05dd \u05e1\u05d1\u05d9\u05d1\u05ea\u05d9 \u05de\u05ea\u05d5\u05da \u05d8\u05d5\u05d4\u05e8, \u05e8\u05e6\u05d5\u05df \u05de\u05d5\u05d3\u05e2 \u05d5\u05d4\u05d1\u05e0\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea."\n\u05ea\u05e8\u05d2\u05d5\u05dc \u05d6\u05d4 \u05de\u05d0\u05e4\u05e9\u05e8 \u05e9\u05d9\u05dc\u05d5\u05d1 \u05d1\u05d9\u05df \u05d2\u05d5\u05e3, \u05e0\u05e4\u05e9 \u05d5\u05e8\u05d5\u05d7 \u2013 \u05d4\u05db\u05e0\u05ea \u05d4\u05de\u05d9\u05d3\u05d5\u05ea, \u05e0\u05d9\u05e7\u05d5\u05d9 \u05e8\u05d2\u05e9\u05d9, \u05d4\u05e2\u05dc\u05d0\u05ea \u05d4\u05e8\u05e6\u05d5\u05df \u05dc\u05d0\u05d5\u05e8, \u05d5\u05d4\u05e4\u05e2\u05dc\u05d4 \u05de\u05d5\u05d3\u05e2\u05ea \u05e9\u05dc \u05d4\u05e6\u05d9\u05d5\u05d5\u05d9 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9. \u05db\u05d3\u05d0\u05d9 \u05dc\u05d7\u05d6\u05d5\u05e8 \u05e2\u05dc\u05d9\u05d5 \u05dc\u05e4\u05d7\u05d5\u05ea \u05db\u05dc \u05d1\u05d5\u05e7\u05e8 \u05d0\u05d1\u05dc \u05d0\u05e4\u05e9\u05e8 \u05d5\u05db\u05d3\u05d0\u05d9 \u05d1\u05db\u05dc \u05de\u05e6\u05d1 \u05e9\u05dc \u05de\u05ea\u05d7 \u05d0\u05d5 \u05e7\u05d5\u05e9\u05d9 \u05e4\u05e0\u05d9\u05de\u05d9.')
B.KW=new A.cv(7,"\u05e4\u05e8\u05e9\u05ea \u05d4\u05ea\u05de\u05d9\u05d3: \u05e2\u05d1\u05d5\u05d3\u05ea \u05d4\u05e0\u05e4\u05e9 \u05e9\u05dc \u05d4\u05e8\u05e6\u05d9\u05e4\u05d5\u05ea","\u05e4\u05e8\u05e9\u05ea \u05d4\u05ea\u05de\u05d9\u05d3 \u2013 \u05e2\u05d1\u05d5\u05d3\u05ea \u05d4\u05e0\u05e4\u05e9 \u05e9\u05dc \u05d4\u05e8\u05e6\u05d9\u05e4\u05d5\u05ea\n\u05d1\u05e4\u05e8\u05e9\u05ea \u05d4\u05ea\u05de\u05d9\u05d3 \u05d0\u05e0\u05d5 \u05e4\u05d5\u05d2\u05e9\u05d9\u05dd \u05d0\u05ea \u05d0\u05d7\u05ea \u05d4\u05e2\u05d1\u05d5\u05d3\u05d5\u05ea \u05d4\u05e7\u05d1\u05d5\u05e2\u05d5\u05ea \u05d1\u05d9\u05d5\u05ea\u05e8 \u05e9\u05d4\u05ea\u05e7\u05d9\u05d9\u05de\u05d5 \u05d1\u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9: \u05d4\u05e7\u05e8\u05d1\u05ea \u05e7\u05d5\u05e8\u05d1\u05df \u05e7\u05d1\u05d5\u05e2, \u05d9\u05d5\u05dd\u05be\u05d9\u05d5\u05dd, \u05d1\u05dc\u05d9 \u05d3\u05e8\u05de\u05d4 \u05d5\u05d1\u05dc\u05d9 \u05d9\u05d5\u05e6\u05d0 \u05de\u05df \u05d4\u05db\u05dc\u05dc.\n\u05e9\u05e0\u05d9 \u05db\u05d1\u05e9\u05d9\u05dd \u05d1\u05db\u05dc \u05d9\u05d5\u05dd - \u05d0\u05d7\u05d3 \u05d1\u05d1\u05d5\u05e7\u05e8 \u05d5\u05d0\u05d7\u05d3 \u05d1\u05d9\u05df \u05d4\u05e2\u05e8\u05d1\u05d9\u05d9\u05dd.\n\u05d0\u05d9\u05df \u05db\u05d0\u05df \u05d7\u05d2\u05d9\u05d2\u05d9\u05d5\u05ea \u05de\u05d9\u05d5\u05d7\u05d3\u05ea, \u05d0\u05d9\u05df \u05d4\u05ea\u05e2\u05dc\u05d5\u05ea \u05d7\u05d3\u05be\u05e4\u05e2\u05de\u05d9\u05ea. \u05d9\u05e9 \u05e8\u05e6\u05e3.\n\u05d3\u05d5\u05d5\u05e7\u05d0 \u05d4\u05e8\u05e6\u05d9\u05e4\u05d5\u05ea \u05d4\u05d6\u05d5 \u05de\u05d2\u05dc\u05d4 \u05d0\u05ea \u05d4\u05e2\u05d5\u05de\u05e7. \u05e7\u05e8\u05d1\u05df \u05d4\u05ea\u05de\u05d9\u05d3 \u05d0\u05d9\u05e0\u05d5 \u05e8\u05e7 \u05de\u05e6\u05d5\u05d5\u05d4 \u05d8\u05db\u05e0\u05d9\u05ea, \u05d0\u05dc\u05d0 \u05d1\u05d9\u05d8\u05d5\u05d9 \u05e2\u05de\u05d5\u05e7 \u05e9\u05dc \u05e2\u05d1\u05d5\u05d3\u05ea \u05d4\u05e0\u05e4\u05e9. \u05d4\u05d5\u05d0 \u05de\u05dc\u05de\u05d3 \u05e9\u05e2\u05d1\u05d5\u05d3\u05ea \u05d4\u2019 \u05d0\u05d5 \u05e9\u05e0\u05e7\u05e8\u05d0 \u05dc\u05d4 \u05e2\u05d1\u05d5\u05d3\u05ea \u05d4\u05d0\u05d3\u05dd \u05e2\u05dd \u05d0\u05d9\u05e9\u05d9\u05d5\u05ea\u05d5 - \u05d0\u05d9\u05e0\u05d4 \u05e0\u05d1\u05e0\u05d9\u05ea \u05de\u05e8\u05d2\u05e2\u05d9 \u05e9\u05d9\u05d0, \u05d0\u05dc\u05d0 \u05de\u05d4\u05d9\u05db\u05d5\u05dc\u05ea \u05dc\u05d4\u05d9\u05e9\u05d0\u05e8 \u05de\u05d7\u05d5\u05d1\u05e8 \u05d2\u05dd \u05db\u05e9\u05d0\u05d9\u05df \u05d4\u05ea\u05e8\u05d2\u05e9\u05d5\u05ea.\n\u05dc\u05d4\u05de\u05e9\u05d9\u05da \u05dc\u05d1\u05d5\u05d0. \u05dc\u05d4\u05de\u05e9\u05d9\u05da \u05dc\u05d4\u05e0\u05d9\u05d7 \u05d0\u05ea \u05d4\u05dc\u05d1 \u05e2\u05dc \u05d4\u05de\u05d6\u05d1\u05d7. \u05dc\u05d4\u05de\u05e9\u05d9\u05da \u05dc\u05d4\u05d9\u05d5\u05ea \u05e0\u05d5\u05db\u05d7.\n\u05d4\u05ea\u05de\u05d9\u05d3 \u05db\u05ea\u05e4\u05d9\u05dc\u05d4, \u05db\u05de\u05d5\u05d3\u05e2\u05d5\u05ea \u05d5\u05db\u05e0\u05d9\u05e7\u05d5\u05d9 \u05e4\u05e0\u05d9\u05de\u05d9\n\u05d7\u05d6\u05f4\u05dc \u05e7\u05e9\u05e8\u05d5 \u05d0\u05ea \u05e7\u05e8\u05d1\u05df \u05d4\u05ea\u05de\u05d9\u05d3 \u05dc\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d4\u05e7\u05d1\u05d5\u05e2\u05d4 \u05e9\u05dc\u05e0\u05d5 - \u05ea\u05e4\u05d9\u05dc\u05ea \u05e9\u05d7\u05e8\u05d9\u05ea \u05d5\u05ea\u05e4\u05d9\u05dc\u05ea \u05de\u05e0\u05d7\u05d4. \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05ea\u05e4\u05e1\u05d4 \u05d0\u05ea \u05de\u05e7\u05d5\u05de\u05d5 \u05e9\u05dc \u05d4\u05e7\u05e8\u05d1\u05df, \u05d0\u05da \u05e9\u05de\u05e8\u05d4 \u05e2\u05dc \u05de\u05d4\u05d5\u05ea\u05d5: \u05d7\u05d9\u05d1\u05d5\u05e8 \u05d9\u05d5\u05de\u05d9\u05d5\u05de\u05d9 \u05e9\u05d0\u05d9\u05e0\u05d5 \u05ea\u05dc\u05d5\u05d9 \u05d1\u05de\u05e6\u05d1 \u05d4\u05e8\u05d5\u05d7.\n\u05d0\u05dc\u05d0 \u05e9\u05d4\u05ea\u05de\u05d9\u05d3 \u05d0\u05d9\u05e0\u05d5 \u05e8\u05e7 \u05d7\u05d9\u05d1\u05d5\u05e8 - \u05d4\u05d5\u05d0 \u05d2\u05dd \u05e0\u05d9\u05e7\u05d5\u05d9.\n\u05d1\u05de\u05d3\u05e8\u05e9 \u05d5\u05d1\u05e7\u05d1\u05dc\u05d4 \u05e2\u05d5\u05dc\u05d4 \u05e9\u05e7\u05e8\u05d1\u05df \u05d4\u05ea\u05de\u05d9\u05d3 \u05de\u05db\u05e4\u05e8 \u05e2\u05dc \u05e4\u05d2\u05de\u05d9\u05dd \u05e9\u05d0\u05d9\u05df \u05d4\u05d0\u05d3\u05dd \u05de\u05d5\u05d3\u05e2 \u05dc\u05d4\u05dd, \u05e2\u05dc \u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05d5\u05e1\u05d8\u05d9\u05d5\u05ea \u05d3\u05e7\u05d5\u05ea \u05e9\u05dc\u05d0 \u05e2\u05dc\u05d5 \u05dc\u05e4\u05e0\u05d9\u05d5 \u05db\u05dc\u05dc. \u05d0\u05dc\u05d5 \u05d0\u05d9\u05e0\u05dd \u05d7\u05d8\u05d0\u05d9\u05dd \u05d3\u05e8\u05de\u05d8\u05d9\u05d9\u05dd, \u05d0\u05dc\u05d0 \u05e9\u05d0\u05e8\u05d9\u05d5\u05ea \u05ea\u05d5\u05d3\u05e2\u05ea\u05d9\u05d5\u05ea: \u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05e9\u05dc\u05d0 \u05d8\u05d5\u05e4\u05dc\u05d5, \u05e8\u05d2\u05e9\u05d5\u05ea \u05e9\u05dc\u05d0 \u05e7\u05d9\u05d1\u05dc\u05d5 \u05de\u05e7\u05d5\u05dd, \u05db\u05d5\u05d5\u05e0\u05d5\u05ea \u05e9\u05e0\u05e9\u05d7\u05e7\u05d5 \u05d1\u05e9\u05e7\u05d8.\n\u05d0\u05e4\u05e9\u05e8 \u05dc\u05d5\u05de\u05e8 \u05d1\u05dc\u05e9\u05d5\u05df \u05e0\u05e4\u05e9\u05d9\u05ea: \u05d4\u05ea\u05de\u05d9\u05d3 \u05e4\u05d5\u05e2\u05dc \u05d2\u05dd \u05e2\u05dc \u05d4\u05e8\u05d5\u05d1\u05d3 \u05d4\u05dc\u05d0-\u05de\u05d5\u05d3\u05e2.\n\u05e2\u05dc \u05d0\u05d5\u05ea\u05dd \u05de\u05e7\u05d5\u05de\u05d5\u05ea \u05e9\u05d1\u05d4\u05dd \u05d4\u05ea\u05d7\u05de\u05e7\u05e0\u05d5 \u05de\u05e2\u05e6\u05d9\u05e8\u05d4, \u05d3\u05d9\u05dc\u05d2\u05e0\u05d5 \u05e2\u05dc \u05d1\u05d9\u05e8\u05d5\u05e8, \u05d5\u05d4\u05e9\u05d0\u05e8\u05e0\u05d5 \u05d3\u05d1\u05e8\u05d9\u05dd \u201c\u05e4\u05ea\u05d5\u05d7\u05d9\u05dd\u201d \u05d1\u05e0\u05e4\u05e9.\n\u05d4\u05dd \u05dc\u05d0 \u05e0\u05e2\u05dc\u05de\u05d5 \u2013 \u05d4\u05dd \u05e8\u05e7 \u05d9\u05e8\u05d3\u05d5 \u05dc\u05de\u05e2\u05de\u05e7\u05d9\u05dd.\n\u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d4\u05e7\u05d1\u05d5\u05e2\u05d4, \u05db\u05de\u05d5 \u05e7\u05e8\u05d1\u05df \u05d4\u05ea\u05de\u05d9\u05d3, \u05d0\u05d9\u05e0\u05d4 \u05de\u05e0\u05e1\u05d4 \u05dc\u05e9\u05dc\u05d5\u05e3 \u05d0\u05d5\u05ea\u05dd \u05d1\u05db\u05d5\u05d7.\n\u05d4\u05d9\u05d0 \u05d9\u05d5\u05e6\u05e8\u05ea \u05e9\u05d3\u05d4 \u05e0\u05e7\u05d9, \u05e9\u05d1\u05d5 \u05d4\u05d0\u05d5\u05e8 \u05e2\u05d5\u05e9\u05d4 \u05d0\u05ea \u05e2\u05d1\u05d5\u05d3\u05ea\u05d5.\n\u05d4\u05d4\u05ea\u05de\u05d3\u05d4 \u05e2\u05e6\u05de\u05d4 \u05d4\u05d9\u05d0 \u05e9\u05de\u05e0\u05e7\u05d4.\n\u05d1\u05d5\u05e7\u05e8 \u05d5\u05e2\u05e8\u05d1 \u2013 \u05de\u05d7\u05d6\u05d5\u05e8\u05d9 \u05d4\u05ea\u05d5\u05d3\u05e2\u05d4\n\u05e9\u05e0\u05d9 \u05d6\u05de\u05e0\u05d9 \u05d4\u05ea\u05de\u05d9\u05d3 \u05de\u05e9\u05e7\u05e4\u05d9\u05dd \u05e9\u05e0\u05d9 \u05de\u05e6\u05d1\u05d9\u05dd \u05d1\u05e0\u05e4\u05e9 \u05d4\u05d0\u05d3\u05dd.\n\u05d4\u05d1\u05d5\u05e7\u05e8 \u05e9\u05d9\u05d9\u05da \u05dc\u05de\u05d5\u05d3\u05e2: \u05db\u05d5\u05d5\u05e0\u05d4, \u05d1\u05d7\u05d9\u05e8\u05d4, \u05d4\u05ea\u05d7\u05dc\u05d4.\n\u05e9\u05dd \u05d4\u05d0\u05d3\u05dd \u05d9\u05db\u05d5\u05dc \u05dc\u05d4\u05e6\u05d9\u05d1 \u05db\u05d9\u05d5\u05d5\u05df \u05d5\u05dc\u05e0\u05e1\u05d7 \u05e8\u05e6\u05d5\u05df. \u05d4\u05d5\u05d0 \u05d6\u05de\u05df \u05d0\u05d5\u05e4\u05d8\u05d9\u05de\u05d9 \u05d9\u05d5\u05ea\u05e8\n\u05d4\u05e2\u05e8\u05d1 \u05e9\u05d9\u05d9\u05da \u05d9\u05d5\u05ea\u05e8 \u05dc\u05ea\u05ea\u05be\u05de\u05d5\u05d3\u05e2: \u05e2\u05d9\u05d9\u05e4\u05d5\u05ea, \u05e9\u05d7\u05e8\u05d5\u05e8, \u05d4\u05ea\u05e4\u05d6\u05e8\u05d5\u05ea. \u05d4\u05d7\u05d5\u05e9\u05da \u05d9\u05d5\u05e8\u05d3 \u05d5\u05d0\u05d9\u05ea\u05d5 \u05dc\u05e2\u05d9\u05ea\u05d9\u05dd \u05d4\u05e4\u05e1\u05d9\u05de\u05d9\u05d5\u05ea \u05d5\u05d4\u05e2\u05d9\u05d9\u05e4\u05d5\u05ea \u05d5\u05d0\u05d9\u05ea\u05d4 \u05d4\u05e2\u05e6\u05d1\u05d5\u05ea.\n\u05d3\u05d5\u05d5\u05e7\u05d0 \u05e9\u05dd \u05e4\u05d5\u05e2\u05dc \u05e7\u05e8\u05d1\u05df \u05d4\u05ea\u05de\u05d9\u05d3 \u05d1\u05d0\u05d5\u05e4\u05df \u05d4\u05e2\u05de\u05d5\u05e7 \u05d1\u05d9\u05d5\u05ea\u05e8 \u05dc\u05d0 \u05d3\u05e8\u05da \u05e9\u05ea\u05d3\u05dc\u05e0\u05d5\u05ea, \u05d0\u05dc\u05d0 \u05d3\u05e8\u05da \u05d4\u05e1\u05db\u05de\u05d4.\n\u05dc\u05d4\u05e0\u05d9\u05d7 \u05dc\u05d3\u05d1\u05e8\u05d9\u05dd \u05dc\u05e9\u05e7\u05d5\u05e2, \u05d5\u05dc\u05d4\u05d9\u05d5\u05ea \u05de\u05ea\u05d5\u05e7\u05e0\u05d9\u05dd \u05de\u05e2\u05e6\u05de\u05dd.\n\u05d1\u05de\u05d5\u05d1\u05df \u05d6\u05d4, \u05ea\u05e4\u05d9\u05dc\u05ea \u05de\u05e0\u05d7\u05d4 \u05d5\u05e2\u05e8\u05d1\u05d9\u05ea \u05d0\u05d9\u05e0\u05df \u201c\u05e4\u05d7\u05d5\u05ea\u05d5\u05ea\u201d \u05d0\u05dc\u05d0 \u05e9\u05d5\u05e0\u05d5\u05ea.\n\u05d4\u05df \u05e4\u05d5\u05e2\u05dc\u05d5\u05ea \u05d1\u05de\u05e7\u05d5\u05dd \u05e9\u05d1\u05d5 \u05d0\u05d9\u05df \u05de\u05d9\u05dc\u05d9\u05dd \u05d1\u05e8\u05d5\u05e8\u05d5\u05ea, \u05d0\u05d1\u05dc \u05d9\u05e9 \u05d0\u05de\u05ea.\n\u05d4\u05e7\u05e8\u05d1\u05df \u05db\u05e7\u05d9\u05e8\u05d5\u05d1 \u05e9\u05dc \u05de\u05d4 \u05e9\u05e0\u05e9\u05db\u05d7\n\u05d4\u05e7\u05e8\u05d1\u05df \u05d1\u05ea\u05d5\u05e8\u05d4 \u05d0\u05d9\u05e0\u05d5 \u05d4\u05e9\u05de\u05d3\u05d4, \u05d0\u05dc\u05d0 \u05e7\u05d9\u05e8\u05d5\u05d1.\n\u05dc\u05d0 \u05e8\u05e7 \u05e9\u05dc \u05d4\u05de\u05d5\u05d3\u05e2 \u05d5\u05d4\u05d9\u05e4\u05d4 \u05d0\u05dc\u05d0 \u05d2\u05dd \u05e9\u05dc \u05de\u05d4 \u05e9\u05e0\u05d3\u05d7\u05e7, \u05d4\u05d5\u05d6\u05e0\u05d7 \u05d0\u05d5 \u05e0\u05e9\u05db\u05d7.\n\u05db\u05da \u05d2\u05dd \u05d1\u05e2\u05d1\u05d5\u05d3\u05ea \u05d4\u05e0\u05e4\u05e9:\n\u05d0\u05d9\u05e0\u05e0\u05d5 \u05de\u05ea\u05e7\u05e0\u05d9\u05dd \u05e8\u05e7 \u05d0\u05ea \u05de\u05d4 \u05e9\u05d0\u05e0\u05d5 \u05e8\u05d5\u05d0\u05d9\u05dd, \u05d0\u05dc\u05d0 \u05d2\u05dd \u05d0\u05ea \u05de\u05d4 \u05e9\u05dc\u05d0 \u05e9\u05de\u05e0\u05d5 \u05dc\u05d1 \u05d0\u05dc\u05d9\u05d5.\n\u05e2\u05e6\u05dd \u05d4\u05e2\u05de\u05d9\u05d3\u05d4 \u05d4\u05d9\u05d5\u05de\u05d9\u05d5\u05de\u05d9\u05ea \u05dc\u05e4\u05e0\u05d9 \u05d4\u2019, \u05d1\u05dc\u05d9 \u05d3\u05e8\u05d9\u05e9\u05d4 \u05dc\u05d4\u05d1\u05d9\u05df \u05d4\u05db\u05d5\u05dc, \u05de\u05d0\u05e4\u05e9\u05e8\u05ea \u05e0\u05d9\u05e7\u05d5\u05d9 \u05e2\u05d3\u05d9\u05df \u05e9\u05dc \u05e9\u05db\u05d1\u05d5\u05ea \u05e2\u05de\u05d5\u05e7\u05d5\u05ea.\n\u05d6\u05d5 \u05e2\u05d1\u05d5\u05d3\u05d4 \u05e9\u05d0\u05d9\u05e0\u05d4 \u05d3\u05e8\u05de\u05d8\u05d9\u05ea \u05d0\u05da \u05d4\u05d9\u05d0 \u05d9\u05e1\u05d5\u05d3\u05d9\u05ea.\n\u05dc\u05d0 \u05ea\u05de\u05d9\u05d3 \u201c\u05e4\u05e8\u05d9\u05e6\u05d5\u05ea \u05d3\u05e8\u05da\u201d, \u05d0\u05dc\u05d0 \u05d8\u05d9\u05d4\u05d5\u05e8 \u05d0\u05d9\u05d8\u05d9.\n\u05d4\u05d7\u05e1\u05d9\u05d3 \u05d5\u05d4\u05d4\u05d2\u05de\u05d5\u05df\n\u05d7\u05d6\u05f4\u05dc \u05de\u05e1\u05e4\u05e8\u05d9\u05dd \u05d1\u05de\u05e1\u05db\u05ea \u05d1\u05e8\u05db\u05d5\u05ea \u05e2\u05dc \u05d7\u05e1\u05d9\u05d3 \u05d0\u05d7\u05d3 \u05e9\u05d4\u05d9\u05d4 \u05e2\u05d5\u05de\u05d3 \u05d5\u05de\u05ea\u05e4\u05dc\u05dc \u05d1\u05d3\u05e8\u05da.\n\u05e2\u05d1\u05e8 \u05de\u05d5\u05dc\u05d5 \u05d4\u05d2\u05de\u05d5\u05df \u05d5\u05e0\u05ea\u05df \u05dc\u05d5 \u05e9\u05dc\u05d5\u05dd \u2013 \u05d5\u05d4\u05d7\u05e1\u05d9\u05d3 \u05dc\u05d0 \u05d4\u05e9\u05d9\u05d1.\n\u05db\u05e9\u05e1\u05d9\u05d9\u05dd \u05d0\u05ea \u05ea\u05e4\u05d9\u05dc\u05ea\u05d5 \u05d2\u05e2\u05e8 \u05d1\u05d5 \u05d4\u05d4\u05d2\u05de\u05d5\u05df, \u05d5\u05d4\u05d7\u05e1\u05d9\u05d3 \u05d4\u05e9\u05d9\u05d1:\n\u05d0\u05d9\u05dc\u05d5 \u05d4\u05d9\u05d9\u05ea\u05d9 \u05e2\u05d5\u05de\u05d3 \u05dc\u05e4\u05e0\u05d9 \u05de\u05dc\u05da \u05d1\u05e9\u05e8 \u05d5\u05d3\u05dd \u2013 \u05d4\u05d0\u05dd \u05d4\u05d9\u05d9\u05ea\u05d9 \u05de\u05e4\u05e1\u05d9\u05e7 \u05d0\u05ea \u05d3\u05d1\u05e8\u05d9\u05d9?\n\u05d4\u05e1\u05d9\u05e4\u05d5\u05e8 \u05d4\u05d6\u05d4 \u05de\u05d0\u05d9\u05e8 \u05e8\u05d5\u05d1\u05d3 \u05e0\u05d5\u05e1\u05e3 \u05d1\u05ea\u05de\u05d9\u05d3:\n\u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d0\u05d9\u05e0\u05d4 \u05e8\u05e7 \u05ea\u05d2\u05d5\u05d1\u05d4 \u05de\u05d5\u05d3\u05e2\u05ea \u05dc\u05de\u05e6\u05d9\u05d0\u05d5\u05ea, \u05d0\u05dc\u05d0 \u05e9\u05de\u05d9\u05e8\u05d4 \u05e2\u05dc \u05e8\u05e6\u05e3 \u05e4\u05e0\u05d9\u05de\u05d9 \u05d2\u05dd \u05db\u05e9\u05d4\u05d7\u05d5\u05e5 \u05ea\u05d5\u05d1\u05e2 \u05ea\u05e9\u05d5\u05de\u05ea \u05dc\u05d1.\n\u05d1\u05d3\u05d9\u05d5\u05e7 \u05e9\u05dd \u05de\u05ea\u05e8\u05d7\u05e9 \u05d4\u05e0\u05d9\u05e7\u05d5\u05d9 \u05d4\u05e2\u05de\u05d5\u05e7 \u2013 \u05d1\u05de\u05e7\u05d5\u05dd \u05e9\u05d1\u05d5 \u05d4\u05d0\u05d3\u05dd \u05d0\u05d9\u05e0\u05d5 \u05e2\u05e1\u05d5\u05e7 \u05d1\u05dc\u05e4\u05ea\u05d5\u05e8, \u05d0\u05dc\u05d0 \u05d1\u05dc\u05e9\u05de\u05d5\u05e8 \u05e2\u05dc \u05d4\u05de\u05e8\u05db\u05d6.\n\u05d4\u05ea\u05de\u05d9\u05d3 \u05de\u05dc\u05de\u05d3 \u05e9\u05d4\u05e2\u05d1\u05d5\u05d3\u05d4 \u05d4\u05d0\u05de\u05d9\u05ea\u05d9\u05ea \u05d0\u05d9\u05e0\u05d4 \u05dc\u05d8\u05e4\u05dc \u05d1\u05db\u05dc \u05d3\u05d1\u05e8 \u05d1\u05de\u05d5\u05d3\u05e2,\n\u05d0\u05dc\u05d0 \u05dc\u05d9\u05e6\u05d5\u05e8 \u05de\u05e8\u05d7\u05d1 \u05e9\u05d1\u05d5 \u05d2\u05dd \u05de\u05d4 \u05e9\u05dc\u05d0 \u05d8\u05d5\u05e4\u05dc \u2013 \u05de\u05ea\u05d5\u05e7\u05df.\n\u05dc\u05d0 \u05d4\u05db\u05d5\u05dc \u05d3\u05d5\u05e8\u05e9 \u05e0\u05d9\u05ea\u05d5\u05d7.\n\u05d7\u05dc\u05e7 \u05de\u05df \u05d4\u05e8\u05d9\u05e4\u05d5\u05d9 \u05e7\u05d5\u05e8\u05d4 \u05de\u05e2\u05e6\u05dd \u05d4\u05d4\u05ea\u05de\u05d3\u05d4, \u05d4\u05e0\u05d5\u05db\u05d7\u05d5\u05ea \u05d5\u05d4\u05e7\u05e9\u05e8.","\u05ea\u05e8\u05d2\u05d5\u05dc: \u05ea\u05de\u05d9\u05d3 \u05e4\u05e0\u05d9\u05de\u05d9 \u05d9\u05d5\u05de\u05d9","\u05d1\u05d7\u05e8\u05d9 \u05d6\u05de\u05df \u05e7\u05d1\u05d5\u05e2 \u05d1\u05d9\u05d5\u05dd.\n\u05e9\u05d1\u05d9 \u05d1\u05e0\u05d5\u05d7\u05d5\u05ea \u05d5\u05d4\u05ea\u05de\u05e7\u05d3\u05d9 \u05d1\u05e0\u05e9\u05d9\u05de\u05d4.\n\u05d0\u05de\u05e8\u05d9 \u05d1\u05dc\u05d1: \u05d4\u05e8\u05d9\u05e0\u05d9 \u05e2\u05d5\u05de\u05d3\u05ea \u05dc\u05e4\u05e0\u05d9 \u05de\u05e7\u05d5\u05e8 \u05d4\u05d7\u05d9\u05d9\u05dd, \u05e2\u05dd \u05db\u05dc \u05de\u05d4 \u05e9\u05d9\u05d3\u05d5\u05e2 \u05dc\u05d9 \u2013 \u05d5\u05e2\u05dd \u05de\u05d4 \u05e9\u05d0\u05d9\u05e0\u05e0\u05d9 \u05d9\u05d5\u05d3\u05e2\u05ea.\n\u05d0\u05dc \u05ea\u05e0\u05e1\u05d9 \u05dc\u05e0\u05e7\u05d5\u05ea \u05d3\u05d1\u05e8. \u05ea\u05e0\u05d9 \u05dc\u05e7\u05e9\u05e8 \u05dc\u05e2\u05e9\u05d5\u05ea \u05d6\u05d0\u05ea.\n\u05e1\u05d9\u05d9\u05de\u05d9 \u05d1\u05d4\u05d5\u05d3\u05d9\u05d4 \u05e9\u05e7\u05d8\u05d4.\n\u05db\u05da \u05e0\u05d1\u05e0\u05d4 \u05de\u05e7\u05d3\u05e9 \u05e4\u05e0\u05d9\u05de\u05d9 \u05e9\u05d0\u05d9\u05e0\u05d5 \u05e2\u05d5\u05e1\u05e7 \u05e8\u05e7 \u05d1\u05ea\u05d5\u05d3\u05e2\u05d4 \u05d4\u05d2\u05dc\u05d5\u05d9\u05d4,\n\u05d0\u05dc\u05d0 \u05d2\u05dd \u05d1\u05de\u05e2\u05de\u05e7\u05d9\u05dd.\n\u05d6\u05d4\u05d5 \u05e1\u05d5\u05d3 \u05e7\u05e8\u05d1\u05df \u05d4\u05ea\u05de\u05d9\u05d3 \u2013 \u05ea\u05d9\u05e7\u05d5\u05df \u05e9\u05e7\u05d8, \u05de\u05ea\u05de\u05e9\u05da, \u05d5\u05de\u05e8\u05e4\u05d0.")
B.KO=new A.cv(8,"\u05e4\u05e8\u05e9\u05ea \u05d4\u05e7\u05d8\u05d5\u05e8\u05ea: \u05e8\u05d9\u05d7 \u05d4\u05e0\u05e9\u05de\u05d4 \u05d5\u05ea\u05d9\u05e7\u05d5\u05df \u05d4\u05d7\u05dc\u05e7\u05d9\u05dd","\u05e4\u05e8\u05e9\u05ea \u05d4\u05e7\u05d8\u05d5\u05e8\u05ea \u2013 \u05e8\u05d9\u05d7 \u05d4\u05e0\u05e9\u05de\u05d4, \u05d0\u05e9\u05de\u05d4 \u05d5\u05ea\u05d9\u05e7\u05d5\u05df \u05d4\u05d7\u05dc\u05e7\u05d9\u05dd \u05d4\u05d1\u05dc\u05ea\u05d9 \u05de\u05d1\u05d5\u05e8\u05e8\u05d9\u05dd\n\u05d4\u05e7\u05d8\u05d5\u05e8\u05ea \u05ea\u05d5\u05e4\u05e1\u05ea \u05de\u05e7\u05d5\u05dd \u05d9\u05d9\u05d7\u05d5\u05d3\u05d9 \u05d1\u05e2\u05d1\u05d5\u05d3\u05ea \u05d4\u05de\u05e7\u05d3\u05e9. \u05d0\u05d9\u05df \u05d4\u05d9\u05d0 \u05e0\u05d0\u05db\u05dc\u05ea, \u05d0\u05d9\u05df \u05d1\u05d4 \u05d7\u05dc\u05e7 \u05dc\u05db\u05d4\u05e0\u05d9\u05dd, \u05d5\u05d0\u05d9\u05df \u05d1\u05d4 \u05de\u05e8\u05d0\u05d4 \u05d7\u05d9\u05e6\u05d5\u05e0\u05d9 \u05de\u05e8\u05e9\u05d9\u05dd. \u05db\u05d5\u05dc\u05d4 \u05e8\u05d9\u05d7 \u2013 \u05d3\u05e7, \u05d7\u05de\u05e7\u05de\u05e7 \u05d5\u05e0\u05e2\u05dc\u05dd.\n\u05d7\u05d6\u05f4\u05dc \u05d0\u05de\u05e8\u05d5: \u201c\u05d0\u05d9\u05d6\u05d5 \u05d4\u05d9\u05d0 \u05e2\u05d1\u05d5\u05d3\u05d4 \u05e9\u05db\u05d5\u05dc\u05d4 \u05e8\u05d9\u05d7 \u05d5\u05d0\u05d9\u05df \u05d1\u05d4 \u05d0\u05db\u05d9\u05dc\u05d4? \u05d4\u05d5\u05d9 \u05d0\u05d5\u05de\u05e8 \u05d6\u05d5 \u05d4\u05e7\u05d8\u05d5\u05e8\u05ea\u201d (\u05d9\u05d5\u05de\u05d0 \u05db\u05d3 \u05e2\u05f4\u05d1).\n\u05d4\u05e8\u05d9\u05d7 \u05e9\u05d9\u05d9\u05da \u05dc\u05de\u05de\u05d3 \u05d4\u05e2\u05de\u05d5\u05e7 \u05d1\u05d9\u05d5\u05ea\u05e8 \u05e9\u05dc \u05d4\u05d0\u05d3\u05dd \u2013 \u05dc\u05de\u05e7\u05d5\u05dd \u05e9\u05d1\u05d5 \u05d0\u05d9\u05df \u05de\u05e2\u05e9\u05d4 \u05d5\u05d0\u05d9\u05df \u05d3\u05d9\u05d1\u05d5\u05e8, \u05d0\u05dc\u05d0 \u05ea\u05e0\u05d5\u05e2\u05d4 \u05e2\u05d3\u05d9\u05e0\u05d4 \u05e9\u05dc \u05e0\u05e9\u05de\u05d4.\n\u05d4\u05e7\u05d8\u05d5\u05e8\u05ea \u05e2\u05dc \u05e4\u05d9 \u05d4\u05e7\u05d1\u05dc\u05d4 \u05d5\u05d4\u05d7\u05e1\u05d9\u05d3\u05d5\u05ea\n\u05d4\u05d6\u05d5\u05d4\u05e8 \u05d4\u05e7\u05d3\u05d5\u05e9 \u05de\u05dc\u05de\u05d3 \u05e9\u05d4\u05e7\u05d8\u05d5\u05e8\u05ea \u05e4\u05d5\u05e2\u05dc\u05ea \u05d7\u05d9\u05d1\u05d5\u05e8 \u05d1\u05d9\u05df \u05d4\u05e2\u05d5\u05dc\u05de\u05d5\u05ea, \u05de\u05de\u05ea\u05d9\u05e7\u05d4 \u05d3\u05d9\u05e0\u05d9\u05dd \u05d5\u05de\u05d1\u05e8\u05d9\u05d7\u05d4 \u05db\u05d5\u05d7\u05d5\u05ea \u05e9\u05dc \u05e4\u05d9\u05e8\u05d5\u05d3 \u05d5\u05e7\u05d8\u05e8\u05d5\u05d2 (\u05d6\u05d5\u05d4\u05e8 \u05d7\u05dc\u05e7 \u05d1, \u05e8\u05d9\u05d7 \u05e2\u05f4\u05d1; \u05d7\u05dc\u05e7 \u05d2, \u05e8\u05dc\u05f4\u05d1 \u05e2\u05f4\u05d0).\n\u05d4\u05d9\u05d0 \u05e4\u05d5\u05e2\u05dc\u05ea \u05d1\u05de\u05e7\u05d5\u05dd \u05e9\u05d1\u05d5 \u05ea\u05e4\u05d9\u05dc\u05d4 \u05d1\u05d3\u05d9\u05d1\u05d5\u05e8 \u05db\u05d1\u05e8 \u05d0\u05d9\u05e0\u05d4 \u05de\u05e1\u05e4\u05d9\u05e7\u05d4 \u2013 \u05d1\u05de\u05e8\u05d7\u05d1 \u05e9\u05dc \u05e2\u05d5\u05de\u05e1 \u05e4\u05e0\u05d9\u05de\u05d9, \u05d1\u05dc\u05d1\u05d5\u05dc \u05d5\u05e0\u05d9\u05ea\u05d5\u05e7 \u05de\u05d4\u05d7\u05d9\u05d5\u05ea.\n\u05d4\u05e7\u05d8\u05d5\u05e8\u05ea \u05de\u05d5\u05e8\u05db\u05d1\u05ea \u05de\u05be\u05d9\u05f4\u05d0 \u05e1\u05de\u05de\u05e0\u05d9\u05dd (\u05db\u05e8\u05d9\u05ea\u05d5\u05ea \u05d5 \u05e2\u05f4\u05d1), \u05d5\u05d1\u05d9\u05e0\u05d9\u05d4\u05dd \u05d4\u05d7\u05dc\u05d1\u05e0\u05d4, \u05e9\u05e8\u05d9\u05d7\u05d4 \u05e8\u05e2. \u05d7\u05d6\u05f4\u05dc \u05de\u05d3\u05d2\u05d9\u05e9\u05d9\u05dd: \u05e7\u05d8\u05d5\u05e8\u05ea \u05d1\u05dc\u05e2\u05d3\u05d9\u05d4 \u2013 \u05e4\u05e1\u05d5\u05dc\u05d4.\n\u05de\u05db\u05d0\u05df \u05e2\u05d5\u05de\u05e7 \u05d4\u05dc\u05d9\u05de\u05d5\u05d3 \u05d4\u05d7\u05e1\u05d9\u05d3\u05d9:\n\u05d0\u05d9\u05df \u05e9\u05dc\u05de\u05d5\u05ea \u05d1\u05dc\u05d9 \u05e6\u05d9\u05e8\u05d5\u05e3 \u05d4\u05d7\u05dc\u05e7\u05d9\u05dd \u05d4\u05d1\u05dc\u05ea\u05d9 \u05de\u05ea\u05d5\u05e7\u05e0\u05d9\u05dd \u05e9\u05d1\u05d0\u05d3\u05dd.\n\u05d4\u05e7\u05d8\u05d5\u05e8\u05ea \u05d0\u05d9\u05e0\u05d4 \u201c\u05de\u05ea\u05e7\u05e0\u05ea\u201d \u05e2\u05dc \u05d9\u05d3\u05d9 \u05d3\u05d7\u05d9\u05d9\u05d4, \u05d0\u05dc\u05d0 \u05e2\u05dc \u05d9\u05d3\u05d9 \u05d4\u05db\u05dc\u05dc\u05d4 \u05d5\u05d4\u05e2\u05dc\u05d0\u05d4 \u05dc\u05e9\u05d5\u05e8\u05e9.\n\u05d4\u05e7\u05d8\u05d5\u05e8\u05ea, \u05d0\u05e9\u05de\u05d4 \u05d5\u05d7\u05de\u05dc\u05d4 \u05e2\u05e6\u05de\u05d9\u05ea\n\u05d0\u05d7\u05ea \u05d4\u05de\u05ea\u05e0\u05d5\u05ea \u05d4\u05e2\u05de\u05d5\u05e7\u05d5\u05ea \u05e9\u05dc \u05e2\u05d1\u05d5\u05d3\u05ea \u05d4\u05e7\u05d8\u05d5\u05e8\u05ea \u05d1\u05e0\u05e4\u05e9 \u05d4\u05d9\u05d0 \u05d4\u05d0\u05e4\u05e9\u05e8\u05d5\u05ea \u05dc\u05d4\u05ea\u05de\u05d5\u05d3\u05d3 \u05e2\u05dd \u05e8\u05d2\u05e9\u05d5\u05ea \u05d0\u05e9\u05de\u05d4.\n\u05d4\u05d0\u05e9\u05de\u05d4 \u05e0\u05d5\u05dc\u05d3\u05ea \u05db\u05d0\u05e9\u05e8 \u05d4\u05d0\u05d3\u05dd \u05de\u05d0\u05de\u05d9\u05df \u05e9\u05d9\u05e9 \u05d1\u05ea\u05d5\u05db\u05d5 \u05d7\u05dc\u05e7\u05d9\u05dd \u05e9\u05d0\u05d9\u05df \u05dc\u05d4\u05dd \u05de\u05e7\u05d5\u05dd \u05d1\u05e2\u05d1\u05d5\u05d3\u05ea \u05d4\u05f3.\n\u05d0\u05da \u05d4\u05e7\u05d8\u05d5\u05e8\u05ea \u05de\u05d2\u05dc\u05d4 \u05d0\u05de\u05ea \u05d0\u05d7\u05e8\u05ea:\n\u05d2\u05dd \u05d4\u05d7\u05dc\u05e7\u05d9\u05dd \u05d4\u05e4\u05d7\u05d5\u05ea \u05d9\u05e4\u05d9\u05dd \u05e9\u05d1\u05e0\u05d5 \u05d1\u05d0\u05d5 \u05de\u05d4\u05e9\u05dd.\n\u05d4\u05dd \u05dc\u05d0 \u05d8\u05e2\u05d5\u05ea. \u05d4\u05dd \u05e9\u05dc\u05d9\u05d7\u05d5\u05ea.\n\u05db\u05e9\u05dd \u05e9\u05d4\u05d7\u05dc\u05d1\u05e0\u05d4 \u05e0\u05e6\u05e8\u05db\u05ea \u05dc\u05e9\u05dc\u05de\u05d5\u05ea \u05d4\u05e7\u05d8\u05d5\u05e8\u05ea, \u05db\u05da \u05d2\u05dd \u05d4\u05db\u05e2\u05e1, \u05d4\u05e7\u05e0\u05d0\u05d4, \u05d4\u05e2\u05d9\u05d9\u05e4\u05d5\u05ea, \u05d4\u05d1\u05dc\u05d1\u05d5\u05dc, \u05d5\u05d4\u05d3\u05d7\u05e4\u05d9\u05dd \u05e9\u05dc\u05d0 \u05ea\u05de\u05d9\u05d3 \u05e0\u05e8\u05d0\u05d9\u05dd \u201c\u05e8\u05d5\u05d7\u05e0\u05d9\u05d9\u05dd\u201d \u2013 \u05db\u05d5\u05dc\u05dd \u05d7\u05d5\u05de\u05e8 \u05d2\u05dc\u05dd \u05dc\u05ea\u05d9\u05e7\u05d5\u05df.\n\u05d4\u05d0\u05e9\u05de\u05d4 \u05de\u05d1\u05e7\u05e9\u05ea \u05dc\u05d1\u05d8\u05dc.\n\u05d4\u05e7\u05d8\u05d5\u05e8\u05ea \u05de\u05d1\u05e7\u05e9\u05ea \u05dc\u05d4\u05e2\u05dc\u05d5\u05ea.\n\u05e8\u05d2\u05e9\u05d5\u05ea \u05d1\u05dc\u05ea\u05d9 \u05de\u05d1\u05d5\u05e8\u05e8\u05d9\u05dd \u05d5\u05de\u05d9\u05e0\u05d9\u05d5\u05ea \u05d1\u05dc\u05ea\u05d9 \u05de\u05d1\u05d5\u05e8\u05e8\u05ea\n\u05d1\u05e2\u05d5\u05de\u05e7 \u05e2\u05d1\u05d5\u05d3\u05ea \u05d4\u05e7\u05d8\u05d5\u05e8\u05ea \u05e0\u05de\u05e6\u05d0\u05ea \u05d2\u05dd \u05d4\u05d4\u05ea\u05de\u05d5\u05d3\u05d3\u05d5\u05ea \u05e2\u05dd \u05e8\u05d2\u05e9\u05d5\u05ea \u05d1\u05dc\u05ea\u05d9 \u05de\u05d1\u05d5\u05e8\u05e8\u05d9\u05dd \u2013 \u05e8\u05d2\u05e9\u05d5\u05ea \u05e9\u05d0\u05d9\u05df \u05dc\u05d4\u05dd \u05e9\u05dd \u05d1\u05e8\u05d5\u05e8, \u05db\u05d9\u05d5\u05d5\u05df \u05d0\u05d5 \u05d4\u05d1\u05e0\u05d4.\n\u05dc\u05e2\u05d9\u05ea\u05d9\u05dd \u05d0\u05dc\u05d5 \u05e8\u05d2\u05e9\u05d5\u05ea \u05e9\u05dc \u05de\u05e9\u05d9\u05db\u05d4, \u05d3\u05d7\u05d9\u05d9\u05d4, \u05ea\u05e9\u05d5\u05e7\u05d4, \u05d1\u05dc\u05d1\u05d5\u05dc, \u05d0\u05d5 \u05e2\u05d9\u05e8\u05d5\u05d1 \u05e9\u05dc \u05e7\u05d5\u05d3\u05e9 \u05d5\u05d7\u05d5\u05dc.\n\u05d2\u05dd \u05e2\u05d1\u05d5\u05d3\u05d4 \u05e2\u05dd \u05de\u05d9\u05e0\u05d9\u05d5\u05ea \u05d1\u05dc\u05ea\u05d9 \u05de\u05d1\u05d5\u05e8\u05e8\u05ea \u05e9\u05d9\u05d9\u05db\u05ea \u05dc\u05de\u05e8\u05d7\u05d1 \u05d6\u05d4.\n\u05dc\u05d0 \u05db\u05d4\u05e6\u05d3\u05e7\u05d4 \u05d5\u05dc\u05d0 \u05db\u05d4\u05d3\u05d7\u05e7\u05d4 \u2013 \u05d0\u05dc\u05d0 \u05db\u05d4\u05e7\u05e9\u05d1\u05d4 \u05e2\u05de\u05d5\u05e7\u05d4 \u05dc\u05e9\u05d5\u05e8\u05e9 \u05d4\u05d7\u05d9\u05d5\u05ea.\n\u05db\u05d5\u05d7 \u05d4\u05ea\u05e9\u05d5\u05e7\u05d4 \u05e9\u05d9\u05d9\u05da \u05dc\u05d9\u05e1\u05d5\u05d3 \u05d4\u05d7\u05d9\u05d9\u05dd. \u05db\u05d0\u05e9\u05e8 \u05d4\u05d5\u05d0 \u05d0\u05d9\u05e0\u05d5 \u05de\u05d1\u05d5\u05e8\u05e8, \u05d4\u05d5\u05d0 \u05e2\u05dc\u05d5\u05dc \u05dc\u05e2\u05d5\u05e8\u05e8 \u05d1\u05d5\u05e9\u05d4 \u05d5\u05d0\u05e9\u05de\u05d4; \u05d0\u05da \u05db\u05d0\u05e9\u05e8 \u05d4\u05d5\u05d0 \u05de\u05d5\u05e2\u05dc\u05d4 \u2013 \u05d4\u05d5\u05d0 \u05e0\u05e2\u05e9\u05d4 \u05de\u05e7\u05d5\u05e8 \u05e9\u05dc \u05d7\u05d9\u05d5\u05ea, \u05e7\u05e9\u05e8 \u05d5\u05d9\u05e6\u05d9\u05e8\u05d4.\n\u05d4\u05e7\u05d8\u05d5\u05e8\u05ea \u05de\u05dc\u05de\u05d3\u05ea:\n\u05d0\u05d9\u05df \u05e6\u05d5\u05e8\u05da \u05dc\u05d4\u05d9\u05d1\u05d4\u05dc \u05de\u05df \u05d4\u05d7\u05d5\u05dd \u05d4\u05e4\u05e0\u05d9\u05de\u05d9.\n\u05d0\u05d9\u05df \u05e6\u05d5\u05e8\u05da \u05dc\u05e9\u05e0\u05d5\u05d0 \u05d0\u05ea \u05d4\u05d3\u05d7\u05e3.\n\u05d4\u05e2\u05d1\u05d5\u05d3\u05d4 \u05d4\u05d9\u05d0 \u05dc\u05d6\u05e7\u05e7, \u05dc\u05d0 \u05dc\u05d1\u05d8\u05dc; \u05dc\u05d1\u05e8\u05e8, \u05dc\u05d0 \u05dc\u05d3\u05db\u05d0.\n\u05db\u05e4\u05d9 \u05e9\u05d4\u05e7\u05d8\u05d5\u05e8\u05ea \u05e2\u05d5\u05dc\u05d4 \u05d1\u05e2\u05e0\u05df \u05d3\u05e7, \u05db\u05da \u05d2\u05dd \u05d4\u05d1\u05d9\u05e8\u05d5\u05e8 - \u05d1\u05e2\u05d3\u05d9\u05e0\u05d5\u05ea, \u05d1\u05e0\u05e9\u05d9\u05de\u05d4, \u05d1\u05dc\u05d9 \u05db\u05d5\u05d7\u05e0\u05d9\u05d5\u05ea.\n\u05d4\u05e2\u05e8\u05d1\u05d4 \u05d5\u05e2\u05e0\u05d5\u05d5\u05ea \u05d4\u05d7\u05dc\u05e7\u05d9\u05dd \u05d4\u05e4\u05e9\u05d5\u05d8\u05d9\u05dd\n\u05d7\u05d6\u05f4\u05dc \u05d4\u05e9\u05d5\u05d5 \u05d6\u05d0\u05ea \u05dc\u05d0\u05e8\u05d1\u05e2\u05ea \u05d4\u05de\u05d9\u05e0\u05d9\u05dd: \u05d4\u05e2\u05e8\u05d1\u05d4 \u2013 \u05e9\u05d0\u05d9\u05df \u05d1\u05d4 \u05dc\u05d0 \u05d8\u05e2\u05dd \u05d5\u05dc\u05d0 \u05e8\u05d9\u05d7 \u2013 \u05d0\u05d9\u05e0\u05d4 \u05de\u05d9\u05d5\u05ea\u05e8\u05ea.\n\u05d1\u05dc\u05e2\u05d3\u05d9\u05d4 \u05d0\u05d9\u05df \u05d4\u05de\u05e6\u05d5\u05d5\u05d4 \u05e9\u05dc\u05de\u05d4. \u05d4\u05d9\u05d0 \u05de\u05e1\u05de\u05dc\u05ea \u05d0\u05ea \u05d4\u05e4\u05e9\u05d8\u05d5\u05ea, \u05d4\u05e2\u05e0\u05d5\u05d5\u05d4. \u05dc\u05dc\u05d0 \u05e2\u05e0\u05d5\u05d5\u05d4 \u05d0\u05d9\u05df \u05db\u05dc\u05d5\u05dd. \u05db\u05ea\u05d5\u05d1 \u05d1\u05de\u05e7\u05d5\u05dd \u05e9\u05d2\u05d0\u05d5\u05d5\u05d4 \u05e9\u05d5\u05e8\u05d4 \u05e9\u05db\u05d9\u05e0\u05d4 \u05d0\u05d9\u05e0\u05d4 \u05e9\u05d5\u05e8\u05d4 \u05d1\u05d5. \u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05d0\u05e0\u05d5 \u05de\u05e8\u05d2\u05d9\u05e9\u05d9\u05dd \u05db\u05dc \u05db\u05da \u05dc\u05d0 \u05de\u05d5\u05e6\u05dc\u05d7\u05d9\u05dd \u05d0\u05d1\u05dc \u05d4\u05e8\u05d2\u05e2\u05d9\u05dd \u05d4\u05d0\u05dc\u05d5 \u05d4\u05dd \u05d0\u05dc\u05d5 \u05e9\u05de\u05db\u05e0\u05d9\u05e1\u05d9\u05dd \u05d0\u05ea \u05e8\u05d5\u05d7 \u05d4\u05e9\u05dd \u05d1\u05ea\u05d5\u05da \u05d7\u05d9\u05d9\u05e0\u05d5 \u05d1\u05e6\u05d5\u05e8\u05d4 \u05d4\u05db\u05d9 \u05d7\u05d6\u05e7\u05d4. \u05d0\u05dd \u05ea\u05d9\u05e9\u05d0\u05dc\u05d5 \u05db\u05dc \u05d0\u05d3\u05dd \u05de\u05d5\u05e6\u05dc\u05d7 \u05db\u05de\u05d4 \u05e4\u05e2\u05de\u05d9\u05dd \u05d4\u05d5\u05d0 \u05e0\u05e4\u05dc \u05dc\u05e4\u05e0\u05d9 \u05e9\u05d4\u05e6\u05dc\u05d9\u05d7 \u05d5\u05d5\u05d3\u05d0\u05d9 \u05ea\u05d2\u05dc\u05d5 \u05e0\u05ea\u05d5\u05e0\u05d9\u05dd \u05e9\u05dc\u05d0 \u05d4\u05d0\u05de\u05e0\u05ea\u05dd. \u05d0\u05dc\u05d5\u05df \u05de\u05d0\u05e1\u05e7 \u05e4\u05e9\u05d8 \u05e8\u05d2\u05dc \u05e9\u05dc\u05d5\u05e9 \u05e4\u05e2\u05de\u05d9\u05dd \u05dc\u05e4\u05e0\u05d9 \u05e9\u05e0\u05e2\u05e9\u05d4 \u05d0\u05d7\u05d3 \u05d4\u05d0\u05e0\u05e9\u05d9\u05dd \u05d4\u05e2\u05e9\u05d9\u05e8\u05d9\u05dd \u05d1\u05e2\u05d5\u05dc\u05dd. \u05db\u05da \u05e9\u05e8\u05d2\u05e2\u05d9 \u05ea\u05d7\u05d5\u05e9\u05ea \u05d4\u05db\u05d9\u05e9\u05dc\u05d5\u05df \u05d7\u05e9\u05d5\u05d1\u05d9\u05dd \u05d1\u05d7\u05d9\u05d9\u05e0\u05d5 \u05db\u05de\u05d5 \u05e8\u05d2\u05e2\u05d9 \u05d4\u05d4\u05e6\u05dc\u05d7\u05d4. \u05d5\u05d4\u05e7\u05d8\u05d5\u05e8\u05ea \u05de\u05d6\u05db\u05d9\u05e8\u05d4 \u05dc\u05e0\u05d5 \u05dc\u05d4\u05ea\u05d7\u05d1\u05e8 \u05d0\u05dc \u05d4\u05d9\u05d5\u05e4\u05d9 \u05e9\u05dc \u05d7\u05d5\u05e1\u05e8 \u05d4\u05d4\u05e6\u05dc\u05d7\u05d4. \u05d0\u05dc \u05ea\u05d7\u05d5\u05e9\u05ea \u05d4\u05d0\u05e4\u05e1\u05d9\u05d5\u05ea. \u05e9\u05dd \u05d0\u05e0\u05d5 \u05e0\u05d5\u05ea\u05e0\u05d9\u05dd \u05dc\u05d1\u05d5\u05e8\u05d0 \u05dc\u05d4\u05d9\u05db\u05e0\u05e1 \u05d5\u05dc\u05d7\u05d5\u05dc\u05dc \u05e4\u05dc\u05d0\u05d9\u05dd \u05d1\u05d7\u05d9\u05d9\u05e0\u05d5.\n\u05d4\u05e2\u05e8\u05d1\u05d4 \u05de\u05d9\u05d9\u05e6\u05d2\u05ea \u05d0\u05ea \u05d0\u05d5\u05ea\u05dd \u05d7\u05dc\u05e7\u05d9\u05dd \u05d1\u05e0\u05e4\u05e9 \u05e9\u05d0\u05d9\u05df \u05d1\u05d4\u05dd \u05d7\u05d5\u05d5\u05d9\u05d4 \u05e9\u05dc \u05de\u05ea\u05d9\u05e7\u05d5\u05ea, \u05e7\u05d3\u05d5\u05e9\u05d4 \u05de\u05d5\u05e8\u05d2\u05e9\u05ea \u05d0\u05d5 \u05d4\u05e9\u05e8\u05d0\u05d4.\n\u05d5\u05d1\u05db\u05dc \u05d6\u05d0\u05ea \u2013 \u05d4\u05dd \u05e9\u05d9\u05d9\u05db\u05d9\u05dd.\n\u05db\u05da \u05d2\u05dd \u05d4\u05e8\u05d2\u05e9\u05d5\u05ea \u05d4\u05e4\u05e9\u05d5\u05d8\u05d9\u05dd, \u05d4\u05d2\u05d5\u05e4\u05e0\u05d9\u05d9\u05dd, \u05d4\u05e1\u05ea\u05de\u05d9\u05d9\u05dd \u05dc\u05db\u05d0\u05d5\u05e8\u05d4 \u2013 \u05d5\u05d0\u05e3 \u05d0\u05dc\u05d5 \u05e9\u05de\u05d1\u05d9\u05db\u05d9\u05dd \u05d0\u05d5\u05ea\u05e0\u05d5.\n\u05e2\u05e6\u05dd \u05d4\u05d9\u05d5\u05ea\u05dd \u05d7\u05dc\u05e7 \u05de\u05df \u05d4\u05d0\u05d3\u05dd \u2013 \u05e0\u05d5\u05ea\u05df \u05dc\u05d4\u05dd \u05de\u05e7\u05d5\u05dd \u05d1\u05e2\u05d1\u05d5\u05d3\u05ea \u05d4\u05f3.\n\u05e2\u05d1\u05d5\u05d3\u05ea \u05e0\u05e4\u05e9: \u05dc\u05d0 \u05e0\u05d2\u05d3 \u2013 \u05d0\u05dc\u05d0 \u05e2\u05dd\n\u05de\u05db\u05d0\u05df \u05e0\u05d5\u05dc\u05d3\u05ea \u05e2\u05de\u05d3\u05d4 \u05d7\u05d3\u05e9\u05d4:\n\u05d0\u05d9\u05df \u05de\u05d4 \u05dc\u05e1\u05dc\u05d5\u05d3 \u05de\u05df \u05d4\u05d7\u05dc\u05e7\u05d9\u05dd \u05d4\u05e4\u05d7\u05d5\u05ea \u05de\u05d5\u05d0\u05e8\u05d9\u05dd, \u05d5\u05d0\u05d9\u05df \u05e6\u05d5\u05e8\u05da \u05dc\u05d4\u05d9\u05dc\u05d7\u05dd \u05d1\u05d4\u05dd.\n\u05d2\u05dd \u05d0\u05dd \u05ea\u05e4\u05e7\u05d9\u05d3\u05dd \u05d4\u05d9\u05d7\u05d9\u05d3 \u05d4\u05d5\u05d0 \u05dc\u05ea\u05ea \u05dc\u05e0\u05d5 \u05d4\u05d6\u05d3\u05de\u05e0\u05d5\u05ea \u05dc\u05e6\u05de\u05d5\u05d7 \u05de\u05d4\u05dd \u2013\n\u05d2\u05dd \u05d0\u05d6 \u05d4\u05dd \u05de\u05e9\u05e8\u05ea\u05d9\u05dd \u05d0\u05ea \u05d4\u05e0\u05e9\u05de\u05d4 \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9\u05ea \u05e9\u05d1\u05ea\u05d5\u05db\u05e0\u05d5.\n\u05db\u05d0\u05e9\u05e8 \u05d4\u05d0\u05d3\u05dd \u05dc\u05d5\u05de\u05d3 \u05dc\u05e2\u05d1\u05d5\u05d3 \u05e2\u05dd \u05d7\u05dc\u05e7\u05d9\u05d5 \u05d1\u05e2\u05d3\u05d9\u05e0\u05d5\u05ea \u05d5\u05d1\u05d7\u05de\u05dc\u05d4,\n\u05e8\u05d2\u05e9\u05d5\u05ea \u05d4\u05d0\u05e9\u05de\u05d4 \u05de\u05ea\u05de\u05ea\u05e7\u05d9\u05dd,\n\u05d5\u05d4\u05e0\u05e4\u05e9 \u05d7\u05d5\u05d6\u05e8\u05ea \u05dc\u05e0\u05d5\u05e2 \u05de\u05ea\u05d5\u05da \u05d0\u05d4\u05d1\u05d4 \u05d5\u05dc\u05d0 \u05de\u05ea\u05d5\u05da \u05e4\u05d7\u05d3.\n\u05d4\u05e7\u05d8\u05d5\u05e8\u05ea \u05e9\u05e2\u05d5\u05e6\u05e8\u05ea \u05de\u05d2\u05e4\u05d4\n\u05d1\u05e4\u05e8\u05e9\u05ea \u05e7\u05e8\u05d7, \u05dc\u05d0\u05d7\u05e8 \u05de\u05d7\u05dc\u05d5\u05e7\u05ea \u05e7\u05e8\u05d7 \u05d5\u05e2\u05d3\u05ea\u05d5, \u05e4\u05d5\u05e8\u05e6\u05ea \u05de\u05d2\u05e4\u05d4 \u05d1\u05e2\u05dd. \u05de\u05e9\u05d4 \u05de\u05e6\u05d5\u05d5\u05d4 \u05d0\u05ea \u05d0\u05d4\u05e8\u05df:\n\u201c\u05e7\u05d7 \u05d0\u05ea \u05d4\u05de\u05d7\u05ea\u05d4\u2026 \u05d5\u05ea\u05df \u05e2\u05dc\u05d9\u05d4 \u05e7\u05d8\u05d5\u05e8\u05ea\u2026 \u05d5\u05d9\u05e2\u05de\u05d5\u05d3 \u05d1\u05d9\u05df \u05d4\u05de\u05ea\u05d9\u05dd \u05d5\u05d1\u05d9\u05df \u05d4\u05d7\u05d9\u05d9\u05dd \u05d5\u05ea\u05d9\u05e2\u05e6\u05e8 \u05d4\u05de\u05d2\u05e4\u05d4\u201d (\u05d1\u05de\u05d3\u05d1\u05e8 \u05d9\u05d6, \u05d9\u05d0\u2013\u05d9\u05d2).\n\u05d4\u05d6\u05d5\u05d4\u05e8 \u05e2\u05d5\u05de\u05d3 \u05e2\u05dc \u05db\u05da \u05e9\u05d0\u05d4\u05e8\u05df \u05dc\u05d0 \u05d4\u05ea\u05e4\u05dc\u05dc \u05d1\u05d3\u05d9\u05d1\u05d5\u05e8, \u05d0\u05dc\u05d0 \u05e4\u05e2\u05dc \u05d1\u05e7\u05d8\u05d5\u05e8\u05ea.\n\u05d4\u05e7\u05d8\u05d5\u05e8\u05ea \u05d9\u05e6\u05e8\u05d4 \u05d7\u05d9\u05e5 \u05e4\u05e0\u05d9\u05de\u05d9, \u05ea\u05d5\u05d3\u05e2\u05ea\u05d9, \u05d1\u05d9\u05df \u05de\u05d5\u05d5\u05ea \u05dc\u05d7\u05d9\u05d9\u05dd.\n\u05de\u05db\u05d0\u05df \u05dc\u05de\u05d3\u05d5 \u05d7\u05d6\u05f4\u05dc \u05e9\u05d4\u05e7\u05d8\u05d5\u05e8\u05ea \u05de\u05d2\u05d9\u05e0\u05d4 \u05de\u05e4\u05e0\u05d9 \u05d3\u05d9\u05e0\u05d9\u05dd \u05e7\u05e9\u05d9\u05dd, \u05d5\u05d0\u05e3 \u05de\u05dc\u05d0\u05da \u05d4\u05de\u05d5\u05d5\u05ea \u05e0\u05de\u05e1\u05e8 \u05dc\u05d4 \u05e1\u05d5\u05d3 \u05d6\u05d4 (\u05e9\u05d1\u05ea \u05e4\u05d8 \u05e2\u05f4\u05d0).\n\u05d1\u05e2\u05d1\u05d5\u05d3\u05ea \u05d4\u05e0\u05e4\u05e9: \u05d9\u05e9 \u05de\u05e6\u05d1\u05d9\u05dd \u05e9\u05d1\u05d4\u05dd \u05d0\u05d9\u05df \u05de\u05d9\u05dc\u05d9\u05dd. \u05d0\u05d9\u05df \u05d4\u05e1\u05d1\u05e8. \u05d0\u05d9\u05df \u201c\u05e2\u05d1\u05d5\u05d3\u05d4 \u05de\u05d3\u05d5\u05d9\u05d9\u05e7\u05ea\u201d \u05d1\u05de\u05d5\u05d1\u05df \u05d4\u05e8\u05d2\u05d9\u05dc.\n\u05d3\u05d5\u05d5\u05e7\u05d0 \u05d0\u05d6 \u05e0\u05d3\u05e8\u05e9\u05ea \u05e2\u05d1\u05d5\u05d3\u05ea \u05d4\u05e7\u05d8\u05d5\u05e8\u05ea \u2013 \u05e0\u05d5\u05db\u05d7\u05d5\u05ea \u05e9\u05e7\u05d8\u05d4, \u05d4\u05db\u05dc\u05d4, \u05d5\u05e0\u05e9\u05d9\u05de\u05d4. \u05d6\u05d5 \u05d9\u05db\u05d5\u05dc\u05d4 \u05dc\u05d4\u05d9\u05d5\u05ea \u05ea\u05e9\u05d5\u05d1\u05d4 \u05db\u05dc\u05db \u05de\u05d9 \u05e9\u05de\u05d7\u05e4\u05e9 \u05d8\u05d9\u05e4\u05d5\u05dc \u05e8\u05d2\u05e9\u05d9 \u05de\u05ea\u05d0\u05d9\u05dd \u05d5\u05de\u05e8\u05d2\u05d9\u05e9 \u05e9\u05d0\u05e3 \u05d0\u05d7\u05d3 \u05dc\u05d0 \u05de\u05d1\u05d9\u05df \u05d0\u05d5\u05ea\u05d5. \u05e9\u05dd \u05d4\u05e7\u05d1\u05dc\u05d4 \u05d4\u05e2\u05e6\u05de\u05d9\u05ea \u05e2\u05dc \u05db\u05dc \u05e8\u05d1\u05d3\u05d9\u05d4 \u05d4\u05d9\u05d0 \u05d4\u05d8\u05d9\u05e4\u05d5\u05dc \u05d4\u05e8\u05d2\u05e9\u05d9 \u05d4\u05db\u05d9 \u05d8\u05d5\u05d1.","\u05ea\u05e8\u05d2\u05d9\u05dc \u05d4\u05d8\u05de\u05e2\u05d4 - \u05e2\u05d1\u05d5\u05d3\u05ea \u05d4\u05e7\u05d8\u05d5\u05e8\u05ea \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05ea","\u05e9\u05d1\u05d5 \u05d1\u05d9\u05e9\u05d9\u05d1\u05d4 \u05e0\u05d5\u05d7\u05d4 \u05d1\u05d1\u05d9\u05ea \u05d0\u05d5 \u05d1\u05d8\u05d1\u05e2\n\u05e0\u05e9\u05d9\u05de\u05d4 \u05e2\u05de\u05d5\u05e7\u05d4 \u05d3\u05e8\u05da \u05d4\u05d0\u05e3 \u05d5\u05d4\u05d5\u05e6\u05d0\u05d4 \u05d0\u05d9\u05d8\u05d9\u05ea \u05d3\u05e8\u05da \u05d4\u05e4\u05d4 \u2013 3 \u05e4\u05e2\u05de\u05d9\u05dd.\n\u05d4\u05e2\u05dc\u05d9 \u05d1\u05e2\u05d3\u05d9\u05e0\u05d5\u05ea \u05e8\u05d2\u05e9, \u05d3\u05d7\u05e3 \u05d0\u05d5 \u05d1\u05dc\u05d1\u05d5\u05dc \u05e4\u05e0\u05d9\u05de\u05d9 \u05e9\u05d0\u05d9\u05e0\u05d5 \u05de\u05d1\u05d5\u05d0\u05e8 \u05e2\u05d3\u05d9\u05d9\u05df, \u05db\u05d5\u05dc\u05dc \u05e8\u05d2\u05e9\u05d5\u05ea \u05de\u05d9\u05e0\u05d9\u05d9\u05dd \u05d0\u05d5 \u05ea\u05e9\u05d5\u05e7\u05d5\u05ea \u05d1\u05dc\u05ea\u05d9 \u05d1\u05e8\u05d5\u05e8\u05d5\u05ea.\n\u05d1\u05d3\u05de\u05d9\u05d5\u05df, \u05d4\u05e0\u05d9\u05d7\u05d9 \u05d0\u05d5\u05ea\u05d5 \u05d1\u05ea\u05d5\u05da \u05de\u05d7\u05ea\u05d4 \u05e9\u05dc \u05d6\u05d4\u05d1.\n\u05d0\u05de\u05e8\u05d9 \u05d1\u05dc\u05d1:\n\u201c\u05d2\u05dd \u05d6\u05d4 \u05d1\u05d0 \u05de\u05d4\u05e9\u05dd. \u05d2\u05dd \u05d6\u05d4 \u05de\u05d1\u05e7\u05e9 \u05ea\u05d9\u05e7\u05d5\u05df \u05d5\u05dc\u05d0 \u05d3\u05d7\u05d9\u05d9\u05d4.\u201d\n\u05d3\u05de\u05d9\u05d9\u05e0\u05d9 \u05e2\u05e0\u05df \u05d3\u05e7 \u05d4\u05e2\u05d5\u05dc\u05d4 \u2013 \u05dc\u05dc\u05d0 \u05de\u05d0\u05de\u05e5, \u05dc\u05dc\u05d0 \u05e9\u05d9\u05e4\u05d5\u05d8.\n\u05e1\u05d9\u05d9\u05de\u05d9 \u05d1\u05d4\u05d5\u05d3\u05d9\u05d4 \u05e2\u05dc \u05d4\u05d9\u05db\u05d5\u05dc\u05ea \u05dc\u05e4\u05d2\u05d5\u05e9 \u05d0\u05ea \u05e2\u05e6\u05de\u05da \u05d1\u05d7\u05de\u05dc\u05d4, \u05d5\u05dc\u05d4\u05d1\u05d9\u05df \u05e9\u05db\u05dc \u05d7\u05dc\u05e7 \u05de\u05e9\u05e8\u05ea \u05d0\u05ea \u05d4\u05e0\u05e9\u05de\u05d4.\n\u05d4\u05e7\u05d8\u05d5\u05e8\u05ea \u05de\u05dc\u05de\u05d3\u05ea \u05e9\u05e2\u05d1\u05d5\u05d3\u05ea \u05d4\u05f3 \u05d4\u05e2\u05de\u05d5\u05e7\u05d4 \u05d1\u05d9\u05d5\u05ea\u05e8 \u05d0\u05d9\u05e0\u05d4 \u05d6\u05d9\u05db\u05d5\u05da \u05db\u05d5\u05d7\u05e0\u05d9, \u05d0\u05dc\u05d0 \u05d1\u05d9\u05e8\u05d5\u05e8 \u05e2\u05d3\u05d9\u05df \u05e9\u05dc \u05d4\u05d7\u05d9\u05d9\u05dd \u05e2\u05e6\u05de\u05dd.\n\u05dc\u05d0 \u05db\u05dc \u05de\u05d4 \u05e9\u05d1\u05d0 \u05d1\u05ea\u05d5\u05db\u05e0\u05d5 \u05e0\u05d5\u05e2\u05d3 \u05dc\u05d4\u05d9\u05d5\u05ea \u05d9\u05e4\u05d4 \u2013 \u05d0\u05da \u05db\u05dc \u05de\u05d4 \u05e9\u05d1\u05d0, \u05e0\u05d5\u05e9\u05d0 \u05d1\u05ea\u05d5\u05db\u05d5 \u05d0\u05e4\u05e9\u05e8\u05d5\u05ea \u05dc\u05d0\u05d5\u05e8.\n\u05e7\u05e8\u05d9\u05d0\u05ea \u05e4\u05e1\u05d5\u05e7\u05d9 \u05d3\u05d6\u05de\u05e8\u05d4.\n\u05e4\u05e1\u05d5\u05e7\u05d9\u05dd \u05d0\u05dc\u05d5, \u05d4\u05dc\u05e7\u05d5\u05d7\u05d9\u05dd \u05de\u05e1\u05e4\u05e8 \u05ea\u05d4\u05d9\u05dc\u05d9\u05dd, \u05de\u05de\u05dc\u05d0\u05d9\u05dd \u05d0\u05d5\u05ea\u05e0\u05d5 \u05d1\u05ea\u05d7\u05d5\u05e9\u05ea \u05d4\u05d5\u05d3\u05d9\u05d4, \u05d7\u05d9\u05d1\u05d5\u05e8 \u05d5\u05ea\u05d5\u05d3\u05e2\u05d4 \u05d0\u05dc\u05d5\u05e7\u05d9\u05ea.")
B.L3=new A.cv(9,"\u05e9\u05d9\u05e8 \u05d7\u05e0\u05d5\u05db\u05ea \u05d4\u05d1\u05d9\u05ea \u05dc\u05d3\u05d5\u05d3: \u05dc\u05d4\u05ea\u05d7\u05d9\u05dc \u05de\u05d7\u05d3\u05e9","\u05de\u05d6\u05de\u05d5\u05e8 \u201c\u05e9\u05d9\u05e8 \u05d7\u05e0\u05d5\u05db\u05ea \u05d4\u05d1\u05d9\u05ea \u05dc\u05d3\u05d5\u05d3\u201d (\u05ea\u05d4\u05d9\u05dc\u05d9\u05dd \u05dc\u2019) \u05d4\u05d5\u05d0 \u05d4\u05e8\u05d1\u05d4 \u05de\u05e2\u05d1\u05e8 \u05dc\u05e9\u05d9\u05e8 \u05e2\u05dc \u05d7\u05e0\u05d5\u05db\u05ea \u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9 \u05d4\u05e4\u05d9\u05d6\u05d9. \u05d6\u05d4\u05d5 \u05de\u05d6\u05de\u05d5\u05e8 \u05e2\u05dc \u05d7\u05e0\u05d5\u05db\u05ea \u05d4\u05dc\u05d1, \u05e2\u05dc \u05d4\u05d9\u05db\u05d5\u05dc\u05ea \u05e9\u05dc \u05d4\u05d0\u05d3\u05dd \u05dc\u05d4\u05ea\u05d7\u05d9\u05dc \u05de\u05d7\u05d3\u05e9 \u05db\u05dc \u05d9\u05d5\u05dd, \u05db\u05dc \u05e8\u05d2\u05e2. \u05dc\u05d7\u05e0\u05da \u05d0\u05ea \u05e2\u05e6\u05de\u05e0\u05d5 \u05dc\u05d0\u05d5\u05e8 \u05d4\u05e0\u05e1\u05d9\u05d1\u05d5\u05ea \u05d5\u05d4\u05dc\u05d9\u05de\u05d5\u05d3 \u05e9\u05dc\u05de\u05d3\u05e0\u05d5 \u05d2\u05dd \u05de\u05d4\u05db\u05d0\u05d1 \u05e2\u05d3 \u05d4\u05d9\u05d5\u05dd \u05d5\u05de\u05e9\u05dd \u05dc\u05de\u05e9\u05d5\u05da \u05e8\u05d9\u05e4\u05d5\u05d9 \u05dc\u05e0\u05e4\u05e9\u05e0\u05d5.\n\u05d3\u05d5\u05d3 \u05d4\u05de\u05dc\u05da \u05dc\u05d0 \u05e9\u05e8 \u05db\u05d0\u05df \u05de\u05ea\u05d5\u05da \u05e9\u05dc\u05de\u05d5\u05ea. \u05dc\u05d4\u05e4\u05da. \u05d4\u05d5\u05d0 \u05e9\u05e8 \u05de\u05ea\u05d5\u05da \u05e0\u05e4\u05d9\u05dc\u05d4, \u05de\u05ea\u05d5\u05da \u05db\u05d0\u05d1, \u05de\u05ea\u05d5\u05da \u05e8\u05d2\u05e2\u05d9\u05dd \u05e9\u05d1\u05d4\u05dd \u201c\u05e9\u05b4\u05c1\u05d5\u05b7\u05bc\u05e2\u05b0\u05ea\u05b4\u05bc\u05d9 \u05d0\u05b5\u05dc\u05b6\u05d9\u05da\u05b8 \u05d5\u05b7\u05ea\u05b4\u05bc\u05e8\u05b0\u05e4\u05b8\u05bc\u05d0\u05b5\u05e0\u05b4\u05d9\u201d. \u05d5\u05de\u05ea\u05d5\u05da \u05d4\u05de\u05e7\u05d5\u05de\u05d5\u05ea \u05d4\u05dc\u05dc\u05d5 \u05d4\u05d5\u05d0 \u05de\u05d2\u05dc\u05d4 \u05d0\u05ea \u05e1\u05d5\u05d3 \u05d4\u05d4\u05ea\u05d7\u05d3\u05e9\u05d5\u05ea:\n\u05d4\u05d1\u05d9\u05ea \u05d4\u05d0\u05de\u05d9\u05ea\u05d9 \u05e9\u05d6\u05e7\u05d5\u05e7 \u05dc\u05d7\u05e0\u05d5\u05db\u05ea \u05d4\u05d1\u05d9\u05ea \u05d4\u05d5\u05d0 \u05d4\u05e0\u05e4\u05e9.\n\u05db\u05dc \u05d9\u05d5\u05dd \u05d0\u05e0\u05d7\u05e0\u05d5 \u05e7\u05de\u05d9\u05dd \u05e2\u05dd \u201c\u05d1\u05d9\u05ea\u201d \u05e4\u05e0\u05d9\u05de\u05d9: \u05de\u05d7\u05e9\u05d1\u05d5\u05ea, \u05e8\u05d2\u05e9\u05d5\u05ea, \u05d6\u05d9\u05db\u05e8\u05d5\u05e0\u05d5\u05ea, \u05e4\u05d7\u05d3\u05d9\u05dd, \u05ea\u05e7\u05d5\u05d5\u05ea.\n\u05d5\u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05d4\u05d1\u05d9\u05ea \u05d4\u05d6\u05d4 \u05de\u05e8\u05d2\u05d9\u05e9 \u05e1\u05d3\u05d5\u05e7, \u05e2\u05d9\u05d9\u05e3, \u05de\u05dc\u05d0 \u05d0\u05d1\u05e7 \u05e9\u05dc \u05d0\u05ea\u05de\u05d5\u05dc.\n\u05d5\u05d3\u05d5\u05d3 \u05de\u05d6\u05db\u05d9\u05e8 \u05dc\u05e0\u05d5: \u05d0\u05e4\u05e9\u05e8 \u05dc\u05d7\u05e0\u05d5\u05da \u05d0\u05d5\u05ea\u05d5 \u05de\u05d7\u05d3\u05e9.\n\u201c\u05d4\u05b8\u05e4\u05b7\u05db\u05b0\u05ea\u05b8\u05bc \u05de\u05b4\u05e1\u05b0\u05e4\u05b0\u05bc\u05d3\u05b4\u05d9 \u05dc\u05b0\u05de\u05b8\u05d7\u05d5\u05b9\u05dc \u05dc\u05b4\u05d9\u201d\n\u05d4\u05d9\u05db\u05d5\u05dc\u05ea \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9\u05ea \u05dc\u05d4\u05e4\u05d5\u05da \u05de\u05e6\u05d9\u05d0\u05d5\u05ea \u05dc\u05d0 \u05e0\u05e2\u05dc\u05de\u05ea, \u05d0\u05d1\u05dc \u05d4\u05d9\u05d0 \u05d2\u05dd \u05e2\u05d5\u05d1\u05e8\u05ea \u05d3\u05e8\u05db\u05e0\u05d5.\n\u05d4\u05d0\u05d3\u05dd \u05de\u05e7\u05d1\u05dc \u05d4\u05d6\u05d3\u05de\u05e0\u05d5\u05ea \u05dc\u05d4\u05e4\u05d5\u05da \u05d0\u05ea \u05d4\u05e1\u05d9\u05e4\u05d5\u05e8 \u05e9\u05dc\u05d5 \u05dc\u05d0 \u05dc\u05de\u05d7\u05d5\u05e7 \u05db\u05d0\u05d1, \u05d0\u05dc\u05d0 \u05dc\u05e8\u05e7\u05d5\u05d3 \u05d0\u05d9\u05ea\u05d5 \u05de\u05d7\u05d3\u05e9.\n\u05d9\u05e9 \u05db\u05d0\u05df \u05ea\u05e0\u05d5\u05e2\u05d4 \u05e2\u05de\u05d5\u05e7\u05d4: \u05dc\u05d0 \u05dc\u05d4\u05d9\u05e9\u05d0\u05e8 \u05e0\u05d0\u05de\u05df \u05dc\u05d2\u05e8\u05e1\u05d4 \u05d4\u05d9\u05e9\u05e0\u05d4 \u05e9\u05dc \u05e2\u05e6\u05de\u05e0\u05d5.\n\u201c\u05d1\u05b8\u05bc\u05e2\u05b6\u05e8\u05b6\u05d1 \u05d9\u05b8\u05dc\u05b4\u05d9\u05df \u05d1\u05b6\u05bc\u05db\u05b4\u05d9 \u05d5\u05b0\u05dc\u05b7\u05d1\u05b9\u05bc\u05e7\u05b6\u05e8 \u05e8\u05b4\u05e0\u05b8\u05bc\u05d4\u201d\n\u05d6\u05d4 \u05dc\u05d0 \u05e8\u05e7 \u05ea\u05d9\u05d0\u05d5\u05e8 \u05e9\u05dc \u05d6\u05de\u05df \u05d6\u05d4 \u05d7\u05d5\u05e7 \u05e8\u05d5\u05d7\u05e0\u05d9.\n\u05d4\u05e2\u05e8\u05d1 \u05d4\u05d5\u05d0 \u05de\u05e6\u05d1 \u05ea\u05d5\u05d3\u05e2\u05d4: \u05d7\u05d5\u05e9\u05da, \u05d1\u05dc\u05d1\u05d5\u05dc, \u05db\u05d9\u05d5\u05d5\u05e5.\n\u05d5\u05d4\u05d1\u05d5\u05e7\u05e8? \u05d4\u05d5\u05d0 \u05d0\u05e4\u05e9\u05e8\u05d5\u05ea.\n\u05db\u05dc \u05d1\u05d5\u05e7\u05e8 \u05d4\u05d5\u05d0 \u05d7\u05e0\u05d5\u05db\u05ea \u05d4\u05d1\u05d9\u05ea \u05de\u05d7\u05d3\u05e9.\n\u05db\u05dc \u05d9\u05e7\u05d9\u05e6\u05d4 \u05d4\u05d9\u05d0 \u05d0\u05de\u05d9\u05e8\u05d4:\n\u05d0\u05e0\u05d9 \u05dc\u05d0 \u05d7\u05d9\u05d9\u05d1 \u05dc\u05d4\u05de\u05e9\u05d9\u05da \u05d0\u05ea \u05d0\u05ea\u05de\u05d5\u05dc.\n\u05d5\u05d6\u05d4 \u05d0\u05d5\u05dc\u05d9 \u05d4\u05de\u05e1\u05e8 \u05d4\u05db\u05d9 \u05e2\u05de\u05d5\u05e7 \u05e9\u05dc \u05d4\u05de\u05d6\u05de\u05d5\u05e8: \u05dc\u05d0 \u05de\u05e9\u05e0\u05d4 \u05db\u05de\u05d4 \u05e2\u05de\u05d5\u05e7 \u05d9\u05e8\u05d3\u05ea\n\u05d4\u05d4\u05ea\u05d7\u05d3\u05e9\u05d5\u05ea \u05d0\u05d9\u05e0\u05d4 \u05ea\u05dc\u05d5\u05d9\u05d4 \u05d1\u05e2\u05d1\u05e8 \u05e9\u05dc\u05da, \u05d0\u05dc\u05d0 \u05d1\u05d9\u05db\u05d5\u05dc\u05ea \u05e9\u05dc\u05da \u05dc\u05d4\u05d9\u05e4\u05ea\u05d7 \u05de\u05d7\u05d3\u05e9.\n\u05d7\u05e0\u05d5\u05db\u05d4 \u05de\u05dc\u05e9\u05d5\u05df \u05d7\u05d9\u05e0\u05d5\u05da, \u05de\u05dc\u05e9\u05d5\u05df \u05d4\u05ea\u05d7\u05dc\u05d4.\n\u05d5\u05d4\u05dc\u05d1 \u05db\u05de\u05d5 \u05d1\u05d9\u05ea \u05e6\u05e8\u05d9\u05da \u05d7\u05e0\u05d5\u05db\u05d4 \u05de\u05ea\u05de\u05d3\u05ea.\n\u05d0\u05d5\u05dc\u05d9 \u05d6\u05d5 \u05d4\u05e2\u05d1\u05d5\u05d3\u05d4 \u05e9\u05dc\u05e0\u05d5: \u05dc\u05d0 \u05dc\u05d7\u05db\u05d5\u05ea \u05dc\u05e8\u05d2\u05e2\u05d9\u05dd \u05d2\u05d3\u05d5\u05dc\u05d9\u05dd \u05e9\u05dc \u05e9\u05d9\u05e0\u05d5\u05d9,\n\u05d0\u05dc\u05d0 \u05dc\u05d4\u05e1\u05db\u05d9\u05dd \u05d1\u05db\u05dc \u05d9\u05d5\u05dd \u05e7\u05d8\u05df\n\u05dc\u05d4\u05d3\u05dc\u05d9\u05e7 \u05e0\u05e8.\n\u05e0\u05e8 \u05e9\u05dc \u05de\u05d7\u05e9\u05d1\u05d4 \u05d7\u05d3\u05e9\u05d4.\n\u05e0\u05e8 \u05e9\u05dc \u05e0\u05e9\u05d9\u05de\u05d4.\n\u05e0\u05e8 \u05e9\u05dc \u05ea\u05e7\u05d5\u05d5\u05d4.\n\u05d5\u05db\u05e9\u05de\u05d3\u05dc\u05d9\u05e7\u05d9\u05dd \u05de\u05d8\u05d0\u05e4\u05d5\u05e8\u05d5\u05ea \u05de\u05e1\u05e4\u05d9\u05e7 \u05e0\u05e8\u05d5\u05ea \u05db\u05dc\u05d5\u05de\u05e8 \u05ea\u05d5\u05d1\u05e0\u05d5\u05ea\n\u05d4\u05d1\u05d9\u05ea \u05db\u05d1\u05e8 \u05dc\u05d0 \u05d0\u05d5\u05ea\u05d5 \u05d1\u05d9\u05ea.\n\u05d6\u05d5 \u05db\u05d1\u05e8 \u05e0\u05e4\u05e9 \u05de\u05d7\u05d5\u05d3\u05e9\u05ea.","","")
B.KN=new A.cv(10,"\u05d9\u05e9\u05d9\u05d1\u05d4 \u05d5\u05e2\u05de\u05d9\u05d3\u05d4 \u05d1\u05ea\u05e4\u05d9\u05dc\u05d4: \u05d3\u05d9\u05e0\u05de\u05d9\u05e7\u05ea \u05d4\u05d2\u05d5\u05e3 \u05d5\u05d4\u05e0\u05e4\u05e9","\u05d9\u05e9\u05d9\u05d1\u05d4 \u05d5\u05e2\u05de\u05d9\u05d3\u05d4 \u05d1\u05ea\u05e4\u05d9\u05dc\u05d4 \u2013 \u05d1\u05d9\u05df \u05db\u05d1\u05d5\u05d3, \u05e8\u05d9\u05db\u05d5\u05d6 \u05d5\u05e7\u05e9\u05e8 \u05e8\u05d5\u05d7\u05e0\u05d9\n\u05db\u05d9\u05e6\u05d3 \u05db\u05d3\u05d0\u05d9 \u05dc\u05e9\u05d1\u05ea \u05d1\u05ea\u05e4\u05d9\u05dc\u05d4?\n\u05db\u05d3\u05d0\u05d9 \u05dc\u05e9\u05d1\u05ea \u05e2\u05dd \u05e8\u05d2\u05dc\u05d9\u05d9\u05dd \u05e2\u05dc \u05d4\u05e8\u05e6\u05e4\u05d4 \u05d5\u05d9\u05d3\u05d9\u05d9\u05dd \u05de\u05d5\u05e4\u05e0\u05d5\u05ea \u05db\u05dc\u05e4\u05d9 \u05d4\u05e9\u05de\u05d9\u05d9\u05dd. \u05d9\u05e9\u05d9\u05d1\u05d4 \u05d6\u05d5 \u05de\u05db\u05d5\u05d5\u05e0\u05ea \u05d0\u05ea \u05d4\u05d2\u05d5\u05e3 \u05dc\u05d7\u05d1\u05e8 \u05e9\u05de\u05d9\u05d9\u05dd \u05dc\u05d0\u05e8\u05e5. \u05de\u05db\u05d5\u05d5\u05e0\u05ea \u05d0\u05ea \u05d4\u05ea\u05d5\u05d3\u05e2\u05d4 \u05e9\u05dc\u05e0\u05d5 \u05dc\u05e2\u05d5\u05dc\u05dd \u05db\u05d9\u05d7\u05e1\u05d9 \u05d2\u05d5\u05de\u05dc\u05d9\u05df \u05d1\u05d9\u05df \u05d4\u05d0\u05d3\u05dd \u05dc\u05db\u05d5\u05d7\u05d5\u05ea \u05e0\u05e9\u05d2\u05d1\u05d9\u05dd \u05de\u05d1\u05d9\u05e0\u05ea\u05e0\u05d5.\n\u05de\u05de\u05e9\u05d4 \u05e8\u05d1\u05e0\u05d5 \u05dc\u05de\u05d3\u05e0\u05d5 \u05dc\u05d4\u05e8\u05d9\u05dd \u05d9\u05d3\u05d9\u05d9\u05dd \u05dc\u05e9\u05de\u05d9\u05d9\u05dd. \u05db\u05de\u05d5\u05d1\u05df \u05d6\u05d5 \u05e4\u05e2\u05d5\u05dc\u05d4 \u05e7\u05e9\u05d4 \u05dc\u05d0\u05d5\u05e8\u05da \u05d6\u05de\u05df.\n\u05d0\u05da \u05d4\u05d9\u05d0 \u05e2\u05d5\u05d6\u05e8\u05ea \u05dc\u05ea\u05d5\u05d3\u05e2\u05d4 \u05dc\u05e8\u05e6\u05d5\u05ea \u05dc\u05d4\u05ea\u05de\u05ea\u05d7 \u05dc\u05d2\u05d1\u05d5\u05dc\u05d5\u05ea \u05ea\u05d5\u05d3\u05e2\u05d4 \u05d0\u05d5 \u05d0\u05de\u05d5\u05e0\u05d4 \u05d7\u05d3\u05e9\u05d9\u05dd. \u05dc\u05d2\u05e2\u05ea \u05d1\u05e9\u05de\u05d9\u05d9\u05dd.\n\u05d1\u05db\u05dc\u05dc \u05db\u05dc \u05ea\u05e0\u05d5\u05e2\u05d5\u05ea \u05d4\u05d2\u05d5\u05e3 \u05d1\u05d6\u05de\u05df \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05e2\u05d5\u05d6\u05e8\u05d9\u05dd \u05dc\u05e0\u05d5 \u05dc\u05d9\u05d9\u05e6\u05e8 \u05ea\u05d5\u05d3\u05e2\u05d4 \u05de\u05e1\u05d5\u05d9\u05d9\u05de\u05ea. \u05e2\u05dc \u05db\u05da \u05d1\u05d4\u05de\u05e9\u05da \u05d4\u05e4\u05e8\u05e7.\n\u05d1\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9\u05ea \u05d9\u05e9 \u05d3\u05d9\u05e0\u05de\u05d9\u05e7\u05d4 \u05d9\u05d9\u05d7\u05d5\u05d3\u05d9\u05ea \u05e9\u05dc \u05e2\u05de\u05d9\u05d3\u05d4 \u05d5\u05d9\u05e9\u05d9\u05d1\u05d4, \u05d4\u05de\u05e9\u05e7\u05e4\u05ea \u05e8\u05d1\u05d3\u05d9\u05dd \u05e2\u05de\u05d5\u05e7\u05d9\u05dd \u05e9\u05dc \u05de\u05e9\u05de\u05e2\u05d5\u05ea, \u05d7\u05d5\u05d5\u05d9\u05d4 \u05e8\u05d2\u05e9\u05d9\u05ea, \u05d5\u05d4\u05ea\u05d7\u05d1\u05e8\u05d5\u05ea \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea. \u05d4\u05de\u05e2\u05d1\u05e8 \u05d1\u05d9\u05df \u05d4\u05de\u05e6\u05d1\u05d9\u05dd \u05d0\u05d9\u05e0\u05d5 \u05e8\u05e7 \u05d8\u05db\u05e0\u05d9, \u05d0\u05dc\u05d0 \u05de\u05d4\u05d5\u05d5\u05d4 \u05db\u05dc\u05d9 \u05dc\u05e2\u05d9\u05e6\u05d5\u05d1 \u05d4\u05d7\u05d5\u05d5\u05d9\u05d4 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05e9\u05dc \u05d4\u05de\u05ea\u05e4\u05dc\u05dc, \u05ea\u05d5\u05da \u05e9\u05d9\u05dc\u05d5\u05d1 \u05e9\u05dc \u05db\u05d1\u05d5\u05d3, \u05d9\u05e8\u05d0\u05d4, \u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea \u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05d5\u05ea\u05d7\u05d5\u05e9\u05ea \u05e7\u05d4\u05d9\u05dc\u05d4.\n\u05e2\u05de\u05d9\u05d3\u05d4 \u2013 \u05e0\u05d5\u05db\u05d7\u05d5\u05ea \u05de\u05d5\u05dc \u05d4\u05d0\u05dc\u05d5\u05d4\u05d9\n\u05d4\u05e2\u05de\u05d9\u05d3\u05d4 \u05de\u05e1\u05de\u05dc\u05ea \u05d0\u05ea \u05e2\u05de\u05d9\u05d3\u05ea \u05d4\u05d0\u05d3\u05dd \u05dc\u05e4\u05e0\u05d9 \u05d1\u05d5\u05e8\u05d0\u05d5. \u05db\u05e9\u05dd \u05e9\u05d0\u05d3\u05dd \u05e0\u05d9\u05e6\u05d1 \u05d1\u05d9\u05e8\u05d0\u05d4 \u05de\u05d5\u05dc \u05de\u05dc\u05da \u05d1\u05e9\u05e8 \u05d5\u05d3\u05dd, \u05db\u05da \u05d1\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d0\u05e0\u05d5 \u05e2\u05d5\u05de\u05d3\u05d9\u05dd \u05db\u05e1\u05de\u05dc \u05e9\u05dc \u05db\u05d1\u05d5\u05d3, \u05de\u05d7\u05d5\u05d9\u05d1\u05d5\u05ea \u05d5\u05d4\u05ea\u05de\u05e1\u05e8\u05d5\u05ea.\n\u05ea\u05e4\u05d9\u05dc\u05ea \u05e9\u05de\u05d5\u05e0\u05d4 \u05e2\u05e9\u05e8\u05d4 (\u05e2\u05de\u05d9\u05d3\u05d4) - \u05e8\u05d2\u05e2 \u05d4\u05e9\u05d9\u05d0 \u05e9\u05dc \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4, \u05e9\u05d1\u05d5 \u05db\u05dc \u05d0\u05d3\u05dd \u05e0\u05d9\u05e6\u05d1 \u05d1\u05d3\u05de\u05de\u05d4 \u05de\u05d5\u05d7\u05dc\u05d8\u05ea \u05dc\u05e4\u05e0\u05d9 \u05d4\u05e7\u05d1\"\u05d4, \u05dc\u05dc\u05d0 \u05ea\u05d9\u05d5\u05d5\u05da, \u05de\u05ea\u05d5\u05da \u05e8\u05d9\u05db\u05d5\u05d6 \u05e2\u05de\u05d5\u05e7.\n\u05e7\u05d3\u05d5\u05e9\u05d4 \u05d5\u05e7\u05d3\u05d9\u05e9 - \u05e7\u05d8\u05e2\u05d9\u05dd \u05d4\u05de\u05d3\u05d2\u05d9\u05e9\u05d9\u05dd \u05d0\u05ea \u05e8\u05d5\u05de\u05de\u05d5\u05ea \u05d4' \u05e0\u05d0\u05de\u05e8\u05d9\u05dd \u05d1\u05e2\u05de\u05d9\u05d3\u05d4, \u05de\u05ea\u05d5\u05da \u05e9\u05d5\u05ea\u05e4\u05d5\u05ea \u05db\u05dc\u05dc\u05d9\u05ea \u05d1\u05d0\u05de\u05d9\u05e8\u05ea\u05dd \u05d5\u05d4\u05d1\u05e2\u05ea \u05d0\u05d7\u05d3\u05d5\u05ea \u05e2\u05dd \u05d4\u05e6\u05d9\u05d1\u05d5\u05e8.\n\u05e7\u05e8\u05d9\u05d0\u05ea \u05d4\u05ea\u05d5\u05e8\u05d4 - \u05d1\u05e8\u05d2\u05e2 \u05e9\u05d4\u05e1\u05e4\u05e8 \u05d4\u05e7\u05d3\u05d5\u05e9 \u05e0\u05d9\u05e9\u05d0 \u05d0\u05d5 \u05e0\u05e4\u05ea\u05d7, \u05d0\u05e0\u05d5 \u05de\u05ea\u05e8\u05d5\u05de\u05de\u05d9\u05dd \u05de\u05ea\u05d5\u05da \u05db\u05d1\u05d5\u05d3 \u05dc\u05de\u05e2\u05de\u05d3 \u05e7\u05d1\u05dc\u05ea \u05d4\u05ea\u05d5\u05e8\u05d4.\n\u05d9\u05e9\u05d9\u05d1\u05d4 - \u05d4\u05e4\u05e0\u05de\u05d4 \u05d5\u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea\n\u05d4\u05d9\u05e9\u05d9\u05d1\u05d4 \u05de\u05d2\u05dc\u05de\u05ea \u05de\u05e6\u05d1 \u05e9\u05dc \u05dc\u05d9\u05de\u05d5\u05d3, \u05e8\u05d5\u05d2\u05e2 \u05d5\u05d7\u05d9\u05d1\u05d5\u05e8 \u05e4\u05e0\u05d9\u05de\u05d9. \u05d4\u05d9\u05d0 \u05de\u05d0\u05e4\u05e9\u05e8\u05ea \u05dc\u05d0\u05d3\u05dd \u05dc\u05d4\u05d8\u05de\u05d9\u05e2 \u05d0\u05ea \u05de\u05d9\u05dc\u05d5\u05ea \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d5\u05dc\u05d7\u05d5\u05d5\u05ea \u05d0\u05d5\u05ea\u05df \u05d1\u05e9\u05e7\u05d8 \u05d5\u05d1\u05e0\u05d9\u05e0\u05d5\u05d7\u05d5\u05ea.\n_---------------------------------","","")
B.L_=new A.cv(11,"\u05d4\u05d5\u05d3 \u05d5\u05d7\u05d3\u05d5\u05d5\u05d4: \u05d1\u05d9\u05df \u05d9\u05e8\u05d0\u05d4 \u05dc\u05e9\u05de\u05d7\u05d4",'\u201c\u05d4\u05d5\u05b9\u05d3 \u05d5\u05b0\u05d4\u05b8\u05d3\u05b8\u05e8 \u05dc\u05b0\u05e4\u05b8\u05e0\u05b8\u05d9\u05d5, \u05e2\u05b9\u05d6 \u05d5\u05b0\u05d7\u05b6\u05d3\u05b0\u05d5\u05b8\u05d4 \u05d1\u05b4\u05bc\u05de\u05b0\u05e7\u05d5\u05b9\u05de\u05d5\u05b9\u201d  \u05e4\u05e1\u05d5\u05e7 \u05e9\u05de\u05d7\u05d6\u05d9\u05e7 \u05d1\u05ea\u05d5\u05db\u05d5 \u05ea\u05e0\u05d5\u05e2\u05d4 \u05e9\u05dc\u05de\u05d4 \u05e9\u05dc \u05e0\u05e4\u05e9: \u05de\u05df \u05d4\u05d9\u05e8\u05d0\u05d4 \u05d0\u05dc \u05d4\u05e9\u05de\u05d7\u05d4, \u05de\u05df \u05d4\u05d4\u05ea\u05db\u05d5\u05d5\u05e6\u05d5\u05ea \u05d0\u05dc \u05d4\u05d4\u05ea\u05e8\u05d7\u05d1\u05d5\u05ea.\n\u05d9\u05e9 \u05e8\u05d2\u05e2\u05d9\u05dd \u05d1\u05d7\u05d9\u05d9\u05dd \u05e9\u05d1\u05d4\u05dd \u05d4\u05d0\u05d3\u05dd \u05e2\u05d5\u05de\u05d3 \u05de\u05d5\u05dc \u05d4\u05dc\u05d0\u05be\u05e0\u05d5\u05d3\u05e2. \u05de\u05d5\u05dc \u05de\u05e6\u05d9\u05d0\u05d5\u05ea \u05e9\u05d0\u05d9\u05df \u05d1\u05d4 \u05e9\u05dc\u05d9\u05d8\u05d4, \u05de\u05d5\u05dc \u05db\u05d5\u05d7\u05d5\u05ea \u05d2\u05d3\u05d5\u05dc\u05d9\u05dd \u05de\u05de\u05e0\u05d5, \u05de\u05d5\u05dc \u05e9\u05d0\u05dc\u05d5\u05ea \u05e9\u05d0\u05d9\u05df \u05dc\u05d4\u05df \u05ea\u05e9\u05d5\u05d1\u05d4 \u05de\u05d9\u05d9\u05d3\u05d9\u05ea.\n\u05e9\u05dd \u05de\u05ea\u05d2\u05dc\u05d4 \u05d4\u05d5\u05d3 \u05d5\u05d4\u05d3\u05e8 \u05dc\u05e4\u05e0\u05d9\u05d5.\n\u05d4"\u05d4\u05d5\u05d3" \u05d4\u05d5\u05d0 \u05dc\u05d0 \u05e8\u05e7 \u05d9\u05d5\u05e4\u05d9 \u05d4\u05d5\u05d0 \u05d2\u05dd \u05d4\u05d4\u05db\u05e8\u05d4 \u05d1\u05e9\u05d1\u05e8\u05d9\u05e8\u05d9\u05d5\u05ea, \u05d1\u05d4\u05e9\u05ea\u05d0\u05d5\u05ea, \u05d1\u05d9\u05e8\u05d0\u05d4.\n\u05d4\u05d5\u05d0 \u05d4\u05de\u05e7\u05d5\u05dd \u05e9\u05d1\u05d5 \u05d4\u05d0\u05d3\u05dd \u05de\u05e8\u05d2\u05d9\u05e9 \u05e7\u05d8\u05df \u05de\u05d5\u05dc \u05d2\u05d3\u05dc\u05d5\u05ea \u05d4\u05d1\u05e8\u05d9\u05d0\u05d4, \u05de\u05d5\u05dc \u05de\u05dc\u05da \u05d4\u05e2\u05d5\u05dc\u05dd.\n\u05d5\u05d4"\u05d4\u05d3\u05e8" \u05d4\u05d5\u05d0 \u05d4\u05e1\u05d3\u05e8 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9 \u05e9\u05de\u05ea\u05e2\u05d5\u05e8\u05e8 \u05de\u05ea\u05d5\u05da \u05d6\u05d4 \u2013 \u05de\u05d5\u05e1\u05e8 \u05e2\u05d3\u05d9\u05df, \u05e7\u05d5\u05dc \u05e4\u05e0\u05d9\u05de\u05d9 \u05e9\u05d0\u05d5\u05de\u05e8: \u05d9\u05e9 \u05d3\u05e8\u05da \u05e0\u05db\u05d5\u05e0\u05d4, \u05d9\u05e9 \u05d0\u05de\u05ea, \u05d9\u05e9 \u05e0\u05d5\u05db\u05d7\u05d5\u05ea \u05e9\u05de\u05d1\u05e7\u05e9\u05ea \u05de\u05de\u05e0\u05d9 \u05dc\u05d9\u05d9\u05e9\u05e8 \u05e7\u05d5.\n\u05d6\u05d5 \u05d9\u05e8\u05d0\u05d4 \u05dc\u05d0 \u05de\u05e9\u05ea\u05e7\u05ea, \u05d0\u05dc\u05d0 \u05d9\u05e8\u05d0\u05d4 \u05e9\u05de\u05e2\u05d3\u05e0\u05ea.\n\u05d9\u05e8\u05d0\u05d4 \u05e9\u05de\u05d6\u05db\u05d9\u05e8\u05d4 \u05dc\u05d0\u05d3\u05dd \u05e9\u05d4\u05d5\u05d0 \u05dc\u05d0 \u05d4\u05de\u05e8\u05db\u05d6, \u05d0\u05dc\u05d0 \u05d7\u05dc\u05e7 \u05de\u05de\u05e9\u05d4\u05d5 \u05d2\u05d3\u05d5\u05dc \u05d9\u05d5\u05ea\u05e8.\n\u05d0\u05d1\u05dc \u05d4\u05e4\u05e1\u05d5\u05e7 \u05dc\u05d0 \u05e0\u05e2\u05e6\u05e8 \u05e9\u05dd.\n\u201c\u05e2\u05b9\u05d6 \u05d5\u05b0\u05d7\u05b6\u05d3\u05b0\u05d5\u05b8\u05d4 \u05d1\u05b4\u05bc\u05de\u05b0\u05e7\u05d5\u05b9\u05de\u05d5\u05b9\u201d  \u05db\u05e9\u05d4\u05d0\u05d3\u05dd \u05e0\u05db\u05e0\u05e1 \u05d0\u05dc \u05d4"\u05de\u05e7\u05d5\u05dd".\n\u05de\u05d4\u05d5 \u05d4\u05de\u05e7\u05d5\u05dd ? \u05d4\u05de\u05e7\u05d5\u05dd \u05d4\u05d5\u05d0 \u05d0\u05d7\u05d3 \u05de\u05e9\u05de\u05d5\u05ea\u05d9\u05d5 \u05e9\u05dc \u05d4\u05e7\u05d3\u05d5\u05e9 \u05d1\u05e8\u05d5\u05da \u05d4\u05d5\u05d0.\n\u05d6\u05d4\u05d5 \u05d4\u05de\u05e7\u05d5\u05dd \u05e9\u05d1\u05d5 \u05d9\u05e9 \u05d4\u05ea\u05d0\u05de\u05d4.\n\u05d4\u05ea\u05d0\u05de\u05d4 \u05d1\u05d9\u05df \u05d4\u05e4\u05e0\u05d9\u05dd \u05dc\u05d7\u05d5\u05e5.\n\u05d1\u05d9\u05df \u05d4\u05e8\u05e6\u05d5\u05df \u05dc\u05e4\u05e2\u05d5\u05dc\u05d4.\n\u05d1\u05d9\u05df \u05d4\u05d9\u05d3\u05d9\u05e2\u05d4 \u05dc\u05d1\u05d9\u05df \u05d4\u05d1\u05d7\u05d9\u05e8\u05d4 \u05dc\u05d7\u05d9\u05d5\u05ea \u05dc\u05e4\u05d9\u05d4.\n\u05db\u05d0\u05e9\u05e8 \u05d0\u05d3\u05dd \u05e2\u05d5\u05e9\u05d4 \u05d0\u05ea \u05d4\u05d3\u05d1\u05e8 \u05d4\u05e0\u05db\u05d5\u05df\n\u05dc\u05d0 \u05e8\u05e7 \u05d7\u05d9\u05e6\u05d5\u05e0\u05d9\u05ea, \u05d0\u05dc\u05d0 \u05de\u05ea\u05d5\u05da \u05d4\u05ea\u05db\u05d5\u05d5\u05e0\u05d5\u05ea, \u05de\u05ea\u05d5\u05da \u05ea\u05e4\u05d9\u05dc\u05d4, \u05de\u05ea\u05d5\u05da \u05dc\u05d9\u05de\u05d5\u05d3, \u05de\u05ea\u05d5\u05da \u05e9\u05d9\u05e0\u05d5\u05d9 \u05ea\u05d5\u05d3\u05e2\u05ea\u05d9, \u05d5\u05de\u05ea\u05d5\u05da \u05e4\u05e2\u05d5\u05dc\u05d4 \u05e9\u05de\u05de\u05e9\u05d9\u05db\u05d4 \u05d0\u05ea \u05db\u05dc \u05d6\u05d4 \u05d0\u05dc \u05d4\u05d7\u05d9\u05d9\u05dd \u2013\n\u05e9\u05dd \u05de\u05ea\u05d2\u05dc\u05d4 \u05de\u05e9\u05d4\u05d5 \u05d0\u05d7\u05e8 \u05dc\u05d2\u05de\u05e8\u05d9:\n\u05e2\u05d5\u05d6  \u05d1\u05ea\u05d5\u05e8\u05d4 \u05d4\u05d5\u05d0 \u05db\u05d5\u05d7 \u05e4\u05e0\u05d9\u05de\u05d9, \u05d9\u05e6\u05d9\u05d1\u05d5\u05ea, \u05e2\u05de\u05d5\u05d3 \u05e9\u05d3\u05e8\u05d4.\n\u05db\u05d5\u05d7 \u05e9\u05dc\u05d0 \u05ea\u05dc\u05d5\u05d9 \u05d1\u05ea\u05e0\u05d0\u05d9\u05dd \u05d7\u05d9\u05e6\u05d5\u05e0\u05d9\u05d9\u05dd, \u05d0\u05dc\u05d0 \u05e0\u05d5\u05d1\u05e2 \u05de\u05d4\u05dc\u05d9\u05de\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea.\n\u05d5\u05d7\u05d3\u05d5\u05d5\u05d4 \u05d4\u05d9\u05d0 \u05e9\u05de\u05d7\u05d4 \u05e2\u05de\u05d5\u05e7\u05d4, \u05dc\u05d0 \u05e8\u05d2\u05e2\u05d9\u05ea.\n\u05e9\u05de\u05d7\u05d4 \u05e9\u05dc \u05d3\u05d9\u05d5\u05e7.\n\u05e9\u05dc \u05ea\u05d7\u05d5\u05e9\u05ea "\u05d0\u05e0\u05d9 \u05d1\u05de\u05e7\u05d5\u05dd \u05e9\u05dc\u05d9".\n\u05d5\u05db\u05d0\u05df \u05de\u05ea\u05d4\u05e4\u05da \u05d4\u05e1\u05d5\u05d3:\n\u05d4\u05d9\u05e8\u05d0\u05d4 \u05dc\u05d0 \u05e1\u05d5\u05ea\u05e8\u05ea \u05d0\u05ea \u05d4\u05e9\u05de\u05d7\u05d4 \u05d4\u05d9\u05d0 \u05de\u05d5\u05dc\u05d9\u05d3\u05d4 \u05d0\u05d5\u05ea\u05d4.\n\u05d4\u05d4\u05db\u05e8\u05d4 \u05d1\u05de\u05e9\u05d4\u05d5 \u05d2\u05d3\u05d5\u05dc \u05de\u05de\u05e0\u05d9, \u05d3\u05d5\u05d5\u05e7\u05d0 \u05d4\u05d9\u05d0 \u05d6\u05d5 \u05e9\u05de\u05d5\u05d1\u05d9\u05dc\u05d4 \u05d0\u05d5\u05ea\u05d9 \u05dc\u05de\u05e6\u05d5\u05d0 \u05d0\u05ea \u05de\u05e7\u05d5\u05de\u05d9 \u05d1\u05ea\u05d5\u05db\u05d5.\n\u05d5\u05db\u05e9\u05d0\u05e0\u05d9 \u05d1\u05de\u05e7\u05d5\u05dd \u2013 \u05d9\u05e9 \u05d1\u05d9 \u05d2\u05dd \u05e2\u05d5\u05d6 \u05d5\u05d2\u05dd \u05d7\u05d3\u05d5\u05d5\u05d4.\n\u05d6\u05d4 \u05de\u05d4\u05dc\u05da \u05e2\u05d3\u05d9\u05df \u05e9\u05dc \u05e0\u05e4\u05e9:\n\u05dc\u05d4\u05e1\u05db\u05d9\u05dd \u05dc\u05e4\u05d2\u05d5\u05e9 \u05d0\u05ea \u05d7\u05d5\u05e1\u05e8 \u05d4\u05d5\u05d5\u05d3\u05d0\u05d5\u05ea \u05d1\u05d9\u05e8\u05d0\u05d4\n\u05d0\u05d1\u05dc \u05dc\u05d0 \u05dc\u05d4\u05d9\u05e9\u05d0\u05e8 \u05e9\u05dd, \u05d0\u05dc\u05d0 \u05dc\u05d4\u05d9\u05db\u05e0\u05e1 \u05d0\u05dc \u05d4\u05de\u05e7\u05d5\u05dd \u05e9\u05dc \u05e4\u05e2\u05d5\u05dc\u05d4 \u05e0\u05db\u05d5\u05e0\u05d4.\n\u05d5\u05e9\u05dd, \u05d1\u05d3\u05d9\u05d5\u05e7 \u05e9\u05dd\n\u05dc\u05d0\u05d8 \u05dc\u05d0\u05d8 \u05de\u05ea\u05d2\u05dc\u05d4 \u05e9\u05de\u05d7\u05d4 \u05e9\u05dc\u05d0 \u05ea\u05dc\u05d5\u05d9\u05d4 \u05d1\u05d3\u05d1\u05e8,\n\u05d5\u05db\u05d5\u05d7 \u05e9\u05dc\u05d0 \u05e0\u05e9\u05d1\u05e8.',"","")
B.KS=new A.cv(12,"\u05e8\u05d1\u05d9 \u05e0\u05d7\u05de\u05df: \u05ea\u05e4\u05d9\u05dc\u05d4 \u05d1\u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05e2\u05e6\u05d5\u05de\u05d5\u05ea",'\u05e8\u05d1\u05d9 \u05e0\u05d7\u05de\u05df \u05de\u05dc\u05de\u05d3 \u05e2\u05dc \u05ea\u05e4\u05d9\u05dc\u05d4 \u05d1\u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05e2\u05e6\u05d5\u05de\u05d5\u05ea\n\u05e8\u05d1\u05d9 \u05e0\u05d7\u05de\u05df \u05de\u05d1\u05e8\u05e1\u05dc\u05d1 \u05de\u05e1\u05d1\u05d9\u05e8 \u05e9\u05d9\u05e9 \u05e8\u05d2\u05e2\u05d9\u05dd \u05e9\u05d1\u05d4\u05dd \u05d4\u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05d4\u05d7\u05d9\u05e6\u05d5\u05e0\u05d9\u05d5\u05ea \u05e8\u05e7 \u05de\u05e4\u05e8\u05d9\u05e2\u05d5\u05ea \u05dc\u05e0\u05d5.\n\u05d4\u05df \u05de\u05ea\u05e8\u05d5\u05e6\u05e6\u05d5\u05ea, \u05de\u05d7\u05e4\u05e9\u05d5\u05ea \u05de\u05d9 \u05e0\u05db\u05e0\u05e1, \u05de\u05d9 \u05d9\u05e6\u05d0, \u05d0\u05d9\u05da \u05d0\u05e0\u05d9 \u05e0\u05e8\u05d0\u05d4, \u05de\u05d4 \u05d0\u05d7\u05e8\u05d9\u05dd \u05e2\u05d5\u05e9\u05d9\u05dd \u2013 \u05d5\u05d4\u05dc\u05d1 \u05dc\u05d0 \u05de\u05e6\u05dc\u05d9\u05d7 \u05dc\u05d4\u05ea\u05e8\u05db\u05d6.\n\u05d5\u05db\u05e9\u05d4\u05dc\u05d1 \u05dc\u05d0 \u05de\u05e8\u05d5\u05db\u05d6 \u2013 \u05d4\u05e0\u05e9\u05de\u05d4 \u05dc\u05d0 \u05e0\u05e4\u05ea\u05d7\u05ea.\n\u05dc\u05db\u05df \u05d4\u05d5\u05d0 \u05de\u05dc\u05de\u05d3 \u05dc\u05d4\u05ea\u05e4\u05dc\u05dc \u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05d1\u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05e2\u05e6\u05d5\u05de\u05d5\u05ea, \u05d0\u05d5 \u05e2\u05dd \u05e1\u05d9\u05d3\u05d5\u05e8 \u05e4\u05ea\u05d5\u05d7 \u05de\u05d5\u05dc \u05d4\u05e4\u05e0\u05d9\u05dd, \u05d0\u05e4\u05d9\u05dc\u05d5 \u05d0\u05dd \u05d0\u05d9\u05df \u05e6\u05d5\u05e8\u05da \u05dc\u05d4\u05e1\u05ea\u05db\u05dc \u05d1\u05ea\u05d5\u05da \u05d4\u05de\u05d9\u05dc\u05d9\u05dd \u05db\u05dc \u05d4\u05d6\u05de\u05df.\n\u05dc\u05d0 \u05db\u05d9 \u05e6\u05e8\u05d9\u05da \u05dc\u05d1\u05e8\u05d5\u05d7 \u05de\u05d4\u05e2\u05d5\u05dc\u05dd, \u05d0\u05dc\u05d0 \u05db\u05d9 \u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05db\u05d3\u05d9 \u05dc\u05e8\u05d0\u05d5\u05ea \u05e4\u05e0\u05d9\u05de\u05d4 \u2013 \u05e6\u05e8\u05d9\u05da \u05dc\u05e2\u05e6\u05d5\u05dd \u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05d4\u05d7\u05d5\u05e6\u05d4.\n\u05db\u05e9\u05d0\u05d3\u05dd \u05e2\u05d5\u05e6\u05dd \u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05d1\u05ea\u05e4\u05d9\u05dc\u05d4, \u05d4\u05d5\u05d0 \u05db\u05d0\u05d9\u05dc\u05d5 \u05d0\u05d5\u05de\u05e8:\n"\u05e8\u05d9\u05d1\u05d5\u05e0\u05d5 \u05e9\u05dc \u05e2\u05d5\u05dc\u05dd, \u05e2\u05db\u05e9\u05d9\u05d5 \u05d6\u05d4 \u05e8\u05e7 \u05d0\u05e0\u05d9 \u05d5\u05d0\u05ea\u05d4.\n\u05d0\u05d9\u05df \u05e2\u05d5\u05dc\u05dd. \u05d0\u05d9\u05df \u05e8\u05e2\u05e9. \u05d0\u05d9\u05df \u05d0\u05e0\u05e9\u05d9\u05dd.\n\u05d0\u05e0\u05d9 \u05d7\u05d5\u05d6\u05e8 \u05d0\u05dc \u05d4\u05dc\u05d1 \u05e9\u05dc\u05d9."\n\u05d4\u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05d4\u05d7\u05d9\u05e6\u05d5\u05e0\u05d9\u05d5\u05ea \u05e8\u05d5\u05d0\u05d5\u05ea \u05d0\u05ea \u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea,\n\u05d0\u05d1\u05dc \u05d4\u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05d5\u05ea \u2013 \u05d0\u05dc\u05d5 \u05e9\u05d1\u05e2\u05d5\u05de\u05e7 \u05d4\u05dc\u05d1 \u2013 \u05e8\u05d5\u05d0\u05d5\u05ea \u05d0\u05ea \u05d4\u05d0\u05de\u05ea.\n\u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d1\u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05e2\u05e6\u05d5\u05de\u05d5\u05ea \u05de\u05d7\u05d6\u05d9\u05e8\u05d4 \u05d0\u05d5\u05ea\u05e0\u05d5 \u05d0\u05dc \u05d4\u05de\u05e7\u05d5\u05dd \u05e9\u05d1\u05d5 \u05d4\u05d3\u05d9\u05d1\u05d5\u05e8 \u05e0\u05d4\u05e4\u05da \u05dc\u05e0\u05e9\u05d9\u05de\u05d4,\n\u05d5\u05d4\u05e0\u05e9\u05de\u05d4 \u05e0\u05d4\u05e4\u05db\u05ea \u05dc\u05de\u05d9\u05dc\u05d4.\n\u05d5\u05de\u05d4 \u05e2\u05dd \u05e1\u05d9\u05d3\u05d5\u05e8?\n\u05e8\u05d1\u05d9 \u05e0\u05d7\u05de\u05df \u05de\u05e1\u05d1\u05d9\u05e8 \u05e9\u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05d4\u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05dc\u05d0 \u05e8\u05d2\u05d5\u05e2\u05d5\u05ea, \u05d5\u05d4\u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05de\u05e1\u05ea\u05d5\u05d1\u05d1\u05d5\u05ea.\n\u05d4\u05de\u05d9\u05dc\u05d9\u05dd \u05d1\u05d5\u05e8\u05d7\u05d5\u05ea.\n\u05d4\u05ea\u05d5\u05d3\u05e2\u05d4 \u05de\u05e8\u05d7\u05e4\u05ea.\n\u05d5\u05d0\u05d6 \u05e2\u05d6\u05e8\u05d4 \u05e4\u05e9\u05d5\u05d8\u05d4 \u05d5\u05e7\u05d8\u05e0\u05d4 \u2013 \u05dc\u05d4\u05ea\u05e4\u05dc\u05dc \u05de\u05ea\u05d5\u05da \u05d4\u05e1\u05d9\u05d3\u05d5\u05e8.\n\u05dc\u05d0 \u05db\u05e1\u05d3\u05e8 \u05d4\u05dc\u05db\u05ea\u05d9 \u05d1\u05dc\u05d1\u05d3, \u05d0\u05dc\u05d0 \u05db\u05e2\u05d5\u05d2\u05df.\n\u05d4\u05e1\u05d9\u05d3\u05d5\u05e8 \u05de\u05d7\u05d6\u05d9\u05e7 \u05d0\u05d5\u05ea\u05e0\u05d5 \u05d1\u05d0\u05de\u05d9\u05e8\u05d4:\n"\u05d9\u05e9 \u05d3\u05e8\u05da. \u05d9\u05e9 \u05e0\u05ea\u05d9\u05d1.\n\u05d4\u05e0\u05d4 \u05d4\u05de\u05d9\u05dc\u05d9\u05dd \u05e9\u05d0\u05de\u05e8\u05d5 \u05d3\u05d5\u05e8\u05d5\u05ea \u05e2\u05dc \u05d3\u05d5\u05e8\u05d5\u05ea.\n\u05d0\u05e0\u05d9 \u05e9\u05d9\u05d9\u05da. \u05d0\u05e0\u05d9 \u05d7\u05dc\u05e7. \u05d0\u05e0\u05d9 \u05dc\u05d0 \u05dc\u05d1\u05d3."\n\u05d4\u05de\u05d9\u05dc\u05d9\u05dd \u05d4\u05db\u05ea\u05d5\u05d1\u05d5\u05ea \u05de\u05d7\u05d6\u05d9\u05e8\u05d5\u05ea \u05d0\u05d5\u05ea\u05e0\u05d5 \u05d0\u05dc \u05d4\u05d9\u05e6\u05d9\u05d1\u05d5\u05ea,\n\u05d0\u05dc \u05d4\u05d3\u05d9\u05d5\u05e7,\n\u05d0\u05dc \u05d4\u05e8\u05d2\u05e2 \u05e9\u05d1\u05d5 \u05d4\u05dc\u05d1 \u05d9\u05db\u05d5\u05dc \u05dc\u05e0\u05e9\u05d5\u05dd \u05de\u05d7\u05d3\u05e9.\n\u05de\u05ea\u05d9 \u05dc\u05e2\u05e6\u05d5\u05dd \u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05d5\u05de\u05ea\u05d9 \u05dc\u05d4\u05e1\u05ea\u05db\u05dc \u05d1\u05e1\u05d9\u05d3\u05d5\u05e8?\n\u05db\u05e9\u05d0\u05e0\u05d9 \u05de\u05e8\u05d2\u05d9\u05e9 \u05e9\u05d4\u05dc\u05d1 \u05e4\u05ea\u05d5\u05d7 \u05d5\u05d4\u05d3\u05d9\u05d1\u05d5\u05e8 \u05d6\u05d5\u05e8\u05dd \u2192 \u05e2\u05e6\u05d5\u05dd \u05e2\u05d9\u05e0\u05d9\u05d9\u05dd.\n\u05db\u05e9\u05d0\u05e0\u05d9 \u05de\u05e8\u05d2\u05d9\u05e9 \u05e9\u05d4\u05de\u05d7\u05e9\u05d1\u05d4 \u05d1\u05d5\u05e8\u05d7\u05ea, \u05e9\u05d0\u05d9\u05df \u05d0\u05d7\u05d9\u05d6\u05d4, \u05e9\u05d4\u05dc\u05d1 \u05e2\u05de\u05d5\u05e1 \u2192 \u05ea\u05e4\u05d9\u05dc\u05d4 \u05de\u05ea\u05d5\u05da \u05e1\u05d9\u05d3\u05d5\u05e8.\n\u05e9\u05e0\u05d9 \u05d4\u05de\u05e6\u05d1\u05d9\u05dd \u05d0\u05de\u05d9\u05ea\u05d9\u05d9\u05dd, \u05e9\u05e0\u05d9\u05d4\u05dd \u05e2\u05d1\u05d5\u05d3\u05ea \u05e7\u05d5\u05d3\u05e9.\n\u05d1\u05e1\u05d5\u05e3 \u05d4\u05db\u05d5\u05dc \u05d7\u05d5\u05d6\u05e8 \u05dc\u05e0\u05e7\u05d5\u05d3\u05d4 \u05d0\u05d7\u05ea:\n\u05e2\u05d1\u05d5\u05d3\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05d4\u05d9\u05d0 \u05dc\u05dc\u05de\u05d5\u05d3 \u05dc\u05d4\u05e7\u05e9\u05d9\u05d1 \u05dc\u05e2\u05e6\u05de\u05d9.\n\u05dc\u05d4\u05d9\u05d5\u05ea \u05e2\u05d3\u05d9\u05df \u05e2\u05dd \u05d4\u05e0\u05e9\u05de\u05d4.\n\u05dc\u05d3\u05e2\u05ea \u05de\u05ea\u05d9 \u05d4\u05d9\u05d0 \u05de\u05d1\u05e7\u05e9\u05ea \u05e9\u05e7\u05d8,\n\u05d5\u05de\u05ea\u05d9 \u05d4\u05d9\u05d0 \u05de\u05d1\u05e7\u05e9\u05ea \u05d4\u05e0\u05d7\u05d9\u05d4.\n\u05db\u05de\u05d5 \u05e9\u05d0\u05de\u05e8 \u05e8\u05d1\u05d9 \u05e0\u05d7\u05de\u05df:\n"\u05e2\u05d9\u05e7\u05e8 \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u2013 \u05e9\u05d9\u05ea\u05e4\u05dc\u05dc \u05de\u05df \u05d4\u05dc\u05d1."\n\u05d5\u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05d1\u05e9\u05d1\u05d9\u05dc \u05d4\u05dc\u05d1 \u2013 \u05e6\u05e8\u05d9\u05da \u05e8\u05d2\u05e2 \u05dc\u05e2\u05e6\u05d5\u05dd \u05e2\u05d9\u05e0\u05d9\u05d9\u05dd.\n\u05d5\u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05d1\u05e9\u05d1\u05d9\u05dc \u05d4\u05dc\u05d1 \u2013 \u05e6\u05e8\u05d9\u05da \u05dc\u05d7\u05d6\u05d5\u05e8 \u05d0\u05dc \u05d4\u05de\u05d9\u05dc\u05d9\u05dd \u05e9\u05d1\u05e1\u05e4\u05e8.\n\u05e9\u05e0\u05d6\u05db\u05d4 \u05dc\u05d4\u05ea\u05e4\u05dc\u05dc \u05e4\u05e0\u05d9\u05de\u05d4.\n\u05de\u05ea\u05d5\u05da \u05d0\u05de\u05ea.\n\u05d1\u05e4\u05e9\u05d8\u05d5\u05ea.\n\u05d1\u05d0\u05d4\u05d1\u05d4. \u2728\n\u05e7\u05e8\u05d9\u05d0\u05ea \u05e9\u05de\u05e2 \u05d5\u05d1\u05e8\u05db\u05d5\u05ea\u05d9\u05d4 - \u05e8\u05d2\u05e2 \u05e9\u05dc \u05e7\u05d1\u05dc\u05ea \u05e2\u05d5\u05dc \u05de\u05dc\u05db\u05d5\u05ea \u05e9\u05de\u05d9\u05d9\u05dd, \u05d4\u05e0\u05e2\u05e9\u05d4 \u05de\u05ea\u05d5\u05da \u05d9\u05e9\u05d9\u05d1\u05d4 \u05db\u05d3\u05d9 \u05dc\u05d0\u05e4\u05e9\u05e8 \u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea \u05d5\u05e9\u05e7\u05d9\u05e2\u05d4 \u05d1\u05de\u05e9\u05de\u05e2\u05d5\u05ea \u05d4\u05de\u05d9\u05dc\u05d9\u05dd.\n\u05e7\u05e8\u05d9\u05d0\u05ea \u05d4\u05ea\u05d5\u05e8\u05d4 \u05d5\u05d4\u05d4\u05e4\u05d8\u05e8\u05d4 - \u05d4\u05e6\u05d9\u05d1\u05d5\u05e8 \u05d9\u05d5\u05e9\u05d1 \u05d5\u05de\u05d0\u05d6\u05d9\u05df, \u05de\u05de\u05e9\u05d9\u05da \u05de\u05e1\u05d5\u05e8\u05ea \u05e2\u05ea\u05d9\u05e7\u05ea \u05d9\u05d5\u05de\u05d9\u05df \u05e9\u05dc \u05dc\u05d9\u05de\u05d5\u05d3 \u05ea\u05d5\u05e8\u05d4 \u05de\u05ea\u05d5\u05da \u05d4\u05e7\u05e9\u05d1\u05d4.\n\u05ea\u05d4\u05d9\u05dc\u05d9\u05dd \u05d5\u05e1\u05dc\u05d9\u05d7\u05d5\u05ea - \u05ea\u05d7\u05e0\u05d5\u05e0\u05d9\u05dd \u05d0\u05d9\u05e9\u05d9\u05d9\u05dd \u05e9\u05e0\u05d0\u05de\u05e8\u05d9\u05dd \u05dc\u05e2\u05d9\u05ea\u05d9\u05dd \u05de\u05ea\u05d5\u05da \u05d9\u05e9\u05d9\u05d1\u05d4, \u05db\u05de\u05d1\u05d8\u05d0\u05d9\u05dd \u05e9\u05d9\u05d7 \u05e7\u05e8\u05d5\u05d1 \u05e2\u05dd \u05d4\u05e7\u05d1"\u05d4.\n\u05d4\u05d6\u05e8\u05d9\u05de\u05d4 \u05d1\u05d9\u05df \u05d9\u05e9\u05d9\u05d1\u05d4 \u05dc\u05e2\u05de\u05d9\u05d3\u05d4 - \u05e7\u05e6\u05d1 \u05e9\u05dc \u05d4\u05ea\u05e2\u05dc\u05d5\u05ea \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea\n\u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9\u05ea \u05d0\u05d9\u05e0\u05d4 \u05de\u05e7\u05d5\u05d1\u05e2\u05ea \u05d1\u05de\u05e6\u05d1 \u05d0\u05d7\u05d3 \u05d0\u05dc\u05d0 \u05d4\u05d9\u05d0 \u05e0\u05e2\u05d4 \u05d1\u05d9\u05df \u05d9\u05e9\u05d9\u05d1\u05d4 \u05dc\u05e2\u05de\u05d9\u05d3\u05d4, \u05d9\u05d5\u05e6\u05e8\u05ea \u05d7\u05d5\u05d5\u05d9\u05d9\u05ea \u05ea\u05e4\u05d9\u05dc\u05d4 \u05d3\u05d9\u05e0\u05de\u05d9\u05ea, \u05e9\u05d1\u05d4 \u05d4\u05d0\u05d3\u05dd \u05e0\u05e2 \u05d1\u05d9\u05df \u05db\u05d1\u05d5\u05d3 \u05dc\u05d9\u05e8\u05d0\u05d4, \u05d1\u05d9\u05df \u05e8\u05d5\u05d2\u05e2 \u05d5\u05d9\u05e9\u05d5\u05d1 \u05d4\u05d3\u05e2\u05ea \u05d4\u05de\u05d5\u05e9\u05d2\u05d9\u05dd \u05d1\u05de\u05e0\u05d5\u05d7\u05d4 / \u05d1\u05d9\u05e9\u05d9\u05d1\u05d4 \u05d5\u05e9\u05d5\u05d1 \u05dc\u05d4\u05ea\u05e2\u05dc\u05d5\u05ea \u05d1\u05e2\u05de\u05d9\u05d3\u05d4.  \u05d1\u05d9\u05df \u05e9\u05d9\u05d7 \u05d0\u05d9\u05e9\u05d9 \u05dc\u05d4\u05e9\u05ea\u05ea\u05e4\u05d5\u05ea \u05e7\u05d4\u05d9\u05dc\u05ea\u05d9\u05ea. \u05e8\u05d2\u05e2\u05d9 \u05d4\u05e2\u05de\u05d9\u05d3\u05d4 \u05de\u05e2\u05dc\u05d9\u05dd \u05d0\u05ea \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05dc\u05e8\u05d5\u05d1\u05d3 \u05e9\u05dc \u05d4\u05d5\u05d3 \u05d5\u05d4\u05d3\u05e8, \u05d1\u05e2\u05d5\u05d3 \u05d4\u05d9\u05e9\u05d9\u05d1\u05d4 \u05de\u05d7\u05d6\u05d9\u05e8\u05d4 \u05d0\u05ea \u05d4\u05d0\u05d3\u05dd \u05dc\u05e2\u05d5\u05de\u05e7 \u05e4\u05e0\u05d9\u05de\u05d9 \u05e9\u05dc \u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea \u05d5\u05dc\u05de\u05d9\u05d3\u05d4.\n\u05db\u05da \u05e0\u05d5\u05e6\u05e8\u05ea \u05d7\u05d5\u05d5\u05d9\u05d4 \u05e9\u05dc\u05de\u05d4, \u05e9\u05d1\u05d4 \u05d4\u05d2\u05d5\u05e3 \u05d5\u05d4\u05e0\u05e4\u05e9 \u05de\u05e9\u05ea\u05ea\u05e4\u05d9\u05dd \u05d9\u05d7\u05d3 \u05d1\u05de\u05e1\u05e2 \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4. \u05de\u05e1\u05e2 \u05e9\u05dc \u05de\u05e4\u05d2\u05e9 \u05e2\u05dd \u05d4\u05e7\u05d3\u05d5\u05e9\u05d4, \u05e2\u05dd \u05e2\u05e6\u05de\u05e0\u05d5 \u05d5\u05e2\u05dd \u05d4\u05e7\u05d4\u05d9\u05dc\u05d4 \u05e9\u05e1\u05d1\u05d9\u05d1\u05e0\u05d5.',"","")
B.L5=new A.cv(13,"\u05e0\u05e2\u05e0\u05d5\u05e2\u05d9\u05dd \u05d1\u05ea\u05e4\u05d9\u05dc\u05d4: \u05d3\u05d1\u05e7\u05d5\u05ea \u05d4\u05d2\u05d5\u05e3 \u05d5\u05d4\u05e0\u05e4\u05e9",'\u05e0\u05e2\u05e0\u05d5\u05e2\u05d9\u05dd \u05d1\u05ea\u05e4\u05d9\u05dc\u05d4\n\u05d4\u05e0\u05e2\u05e0\u05d5\u05e2 \u05d1\u05ea\u05e4\u05d9\u05dc\u05d4 \u05e0\u05d5\u05ea\u05df \u05dc\u05e0\u05d5 \u05e6\u05d5\u05d4\u05e8 \u05dc\u05e8\u05e6\u05d5\u05df \u05d4\u05d2\u05d3\u05d5\u05dc \u05dc\u05d4\u05ea\u05d7\u05d1\u05e8 \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea. \u05e9\u05d0\u05dc\u05d4 \u05d8\u05d5\u05d1\u05d4 \u05d4\u05d9\u05d0 \u05d4\u05e0\u05e2\u05e0\u05d5\u05e2 \u05e6\u05e8\u05d9\u05da \u05dc\u05d4\u05d9\u05d5\u05ea \u05d9\u05d6\u05d5\u05dd \u05d5\u05d4\u05d0\u05dd \u05d4\u05d5\u05d0 \u05d2\u05d5\u05d6\u05dc \u05de\u05d4\u05de\u05d7\u05e9\u05d1\u05d4 \u05e2\u05dc \u05d4\u05de\u05d9\u05dc\u05d9\u05dd \u05d4\u05d0\u05dd \u05d4\u05d5\u05d0 \u05e8\u05d0\u05d5\u05d9.\n\u05d0\u05d5 \u05e0\u05e2\u05e0\u05d5\u05e2 \u05de\u05e1\u05d5\u05d2 \u05d0\u05d7\u05e8 \u05d4\u05d5\u05d0 \u05d4\u05e7\u05d3\u05d5\u05e9. \u05d6\u05d4 \u05e9\u05e4\u05e9\u05d5\u05d8 \u05e0\u05d5\u05d1\u05e2 \u05de\u05ea\u05d5\u05da \u05d4\u05d0\u05e7\u05e1\u05d8\u05d6\u05d4 \u05d0\u05dc\u05d9\u05d4 \u05d0\u05e0\u05d5 \u05e0\u05db\u05e0\u05e1\u05d9\u05dd.\n\u05e0\u05e0\u05e1\u05d4 \u05dc\u05d4\u05d1\u05d9\u05df \u05d9\u05d5\u05ea\u05e8 \u05d3\u05e8\u05da \u05d4\u05e1\u05d9\u05e4\u05d5\u05e8\u05d9\u05dd \u05d4\u05d1\u05d0\u05d9\u05dd:\n\u05e8\u05d1\u05d9 \u05dc\u05d5\u05d9 \u05d9\u05e6\u05d7\u05e7 \u05d4\u05d9\u05d4 \u05de\u05ea\u05d7\u05d9\u05dc \u05dc\u05d4\u05ea\u05e4\u05dc\u05dc \u05d1\u05e7\u05e6\u05d4 \u05d0\u05d7\u05d3 \u05e9\u05dc \u05d4\u05d7\u05d3\u05e8 \u05d5\u05de\u05d5\u05e6\u05d0 \u05d0\u05ea \u05e2\u05e6\u05de\u05d5 \u05d1\u05db\u05dc \u05de\u05d9\u05e0\u05d9 \u05e7\u05e6\u05d5\u05d5\u05ea \u05e9\u05dc \u05d4\u05d7\u05d3\u05e8 \u05d1\u05d6\u05de\u05df \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4. \u05d4\u05d5\u05d0 \u05dc\u05d0 \u05e8\u05e7 \u05d4\u05d9\u05d4 \u05de\u05ea\u05e0\u05e2\u05e0\u05e2 \u05d0\u05d5 \u05d4\u05d9\u05d4 \u05e7\u05d5\u05e4\u05e5 \u05d5\u05e8\u05d5\u05e7\u05d3 \u05d5\u05e0\u05db\u05e0\u05e1 \u05dc\u05de\u05e6\u05d1 \u05d0\u05e7\u05e1\u05d8\u05d8\u05d9 \u05e2\u05d3 \u05db\u05d3\u05d9 \u05db\u05da \u05e9\u05dc\u05d0 \u05d9\u05db\u05d5\u05dc \u05d4\u05d9\u05d4 \u05dc\u05d6\u05db\u05d5\u05e8 \u05d0\u05d9\u05da \u05d4\u05d2\u05d9\u05e2 \u05dc\u05e7\u05e6\u05d4 \u05d4\u05e9\u05e0\u05d9 \u05e9\u05dc \u05d4\u05d7\u05d3\u05e8. \u05db\u05dc\u05d5\u05de\u05e8 \u05db\u05dc \u05d4\u05d4\u05ea\u05dc\u05d4\u05d1\u05d5\u05ea \u05e9\u05dc\u05d5 \u05d4\u05d9\u05ea\u05d4 \u05de\u05e6\u05d5\u05d9\u05d4 \u05d1\u05ea\u05d5\u05da \u05d4\u05de\u05d9\u05dc\u05d9\u05dd. \u05d5\u05d4\u05d2\u05d5\u05e3 \u05e4\u05e9\u05d5\u05d8 \u05e9\u05d9\u05ea\u05e3 \u05e4\u05e2\u05d5\u05dc\u05d4 \u05e2\u05dd \u05d4\u05d4\u05ea\u05dc\u05d4\u05d1\u05d5\u05ea \u05d4\u05ea\u05d5\u05d3\u05e2\u05ea\u05d9\u05ea.\n\u05d4\u05e1\u05d9\u05e4\u05d5\u05e8 \u05d4\u05d1\u05d0 \u05e2\u05dc \u05d4\u05d1\u05e2\u05dc \u05e9\u05dd \u05d8\u05d5\u05d1 \u05d2\u05dd \u05de\u05de\u05d7\u05d9\u05e9 \u05d0\u05ea \u05d4\u05e2\u05e0\u05d9\u05d9\u05df.\n\u05de\u05b7\u05e2\u05b2\u05e9\u05c2\u05b6\u05d4 \u05d5\u05bc\u05d1\u05b8\u05dc\u05b8\u05d4 \u05e1\u05b4\u05d3\u05bc\u05d5\u05bc\u05e8\u05d5\u05b9 \u05e9\u05c1\u05b6\u05dc \u05d4\u05b7\u05d1\u05bc\u05b7\u05e2\u05b7\u05dc \u05e9\u05c1\u05b5\u05dd \u05d8\u05d5\u05b9\u05d1, \u05d5\u05bc\u05d1\u05b4\u05e7\u05bc\u05b0\u05e9\u05c1\u05d5\u05bc \u05ea\u05bc\u05b7\u05dc\u05b0\u05de\u05b4\u05d9\u05d3\u05b8\u05d9\u05d5 \u05dc\u05b4\u05de\u05b0\u05e6\u05b9\u05d0 \u05dc\u05d5\u05b9 \u05e1\u05b4\u05d3\u05bc\u05d5\u05bc\u05e8 \u05de\u05b0\u05ea\u05bb\u05e7\u05bc\u05b8\u05df. \u05d4\u05b4\u05e1\u05b0\u05ea\u05bc\u05d5\u05b9\u05d1\u05b0\u05d1\u05d5\u05bc \u05de\u05b4\u05d1\u05bc\u05b7\u05d9\u05b4\u05ea \u05dc\u05b0\u05d1\u05b7\u05d9\u05b4\u05ea, \u05e2\u05b7\u05d3 \u05e9\u05c1\u05b6\u05d4\u05b4\u05d2\u05bc\u05b4\u05d9\u05e2\u05d5\u05bc \u05dc\u05b0\u05d1\u05b5\u05d9\u05ea\u05d5\u05b9 \u05e9\u05c1\u05b6\u05dc \u05e8\u05d5\u05b9\u05e2\u05b6\u05d4 \u05d4\u05b8\u05e2\u05b2\u05d9\u05b8\u05e8\u05b8\u05d4. \u05e7\u05b4\u05d1\u05bc\u05b5\u05dc \u05d4\u05b8\u05e8\u05d5\u05b9\u05e2\u05b6\u05d4 \u05d0\u05b6\u05ea \u05d0\u05d5\u05b9\u05e8\u05b0\u05d7\u05b8\u05d9\u05d5 \u05d1\u05bc\u05b0\u05e1\u05b5\u05d1\u05b6\u05e8 \u05e4\u05bc\u05b8\u05e0\u05b4\u05d9\u05dd \u05d9\u05b8\u05e4\u05d5\u05b9\u05ea, \u05d5\u05b0\u05db\u05b7\u05d0\u05b2\u05e9\u05c1\u05b6\u05e8 \u05d2\u05bc\u05b4\u05dc\u05bc\u05d5\u05bc \u05dc\u05d5\u05b9 \u05d0\u05d5\u05b9\u05e8\u05b0\u05d7\u05b8\u05d9\u05d5 \u05d0\u05b6\u05ea \u05e1\u05b4\u05d1\u05bc\u05b7\u05ea \u05d1\u05bc\u05d5\u05b9\u05d0\u05b8\u05dd, \u05d0\u05b8\u05de\u05b7\u05e8 \u05dc\u05b8\u05d4\u05b6\u05dd \u05d1\u05bc\u05b0\u05e9\u05c2\u05b4\u05de\u05b0\u05d7\u05b8\u05d4, \u05db\u05bc\u05b4\u05d9 \u05d9\u05b5\u05e9\u05c1 \u05dc\u05d5\u05b9 \u05e1\u05b4\u05d3\u05bc\u05d5\u05bc\u05e8 \u05e9\u05c1\u05b6\u05e7\u05bc\u05b4\u05d1\u05bc\u05b5\u05dc \u05d9\u05b0\u05e8\u05bb\u05e9\u05bc\u05c1\u05b8\u05d4 \u05de\u05b4\u05e1\u05bc\u05b8\u05d1\u05d5\u05b9 (\u05e9\u05c1\u05b6\u05d4\u05b8\u05d9\u05b8\u05d4 \u05de\u05b7\u05d2\u05bc\u05b4\u05d9\u05d3), \u05d5\u05b0\u05d4\u05d5\u05bc\u05d0 \u05e7\u05b4\u05d1\u05bc\u05b5\u05dc \u05d0\u05b6\u05ea \u05d4\u05b7\u05e1\u05bc\u05b4\u05d3\u05bc\u05d5\u05bc\u05e8 \u05de\u05b5\u05d0\u05b2\u05d1\u05b4\u05d9 \u05e1\u05b8\u05d1\u05d5\u05b9 (\u05e9\u05c1\u05b6\u05d4\u05b8\u05d9\u05b8\u05d4 \u05e8\u05b7\u05d1 \u05e7\u05b0\u05d4\u05b4\u05dc\u05bc\u05b8\u05d4), \u05d5\u05b7\u05d0\u05b2\u05d1\u05b4\u05d9 \u05e1\u05b8\u05d1\u05d5\u05b9 \u05e7\u05b4\u05d1\u05bc\u05b5\u05dc \u05d0\u05b6\u05ea \u05d6\u05b6\u05d4 \u05de\u05b5\u05d0\u05b2\u05d1\u05b4\u05d9 \u05e1\u05b8\u05d1\u05d5\u05b9, \u05d5\u05bc\u05d1\u05b0\u05e2\u05b6\u05e6\u05b6\u05dd \u05db\u05bc\u05bb\u05dc\u05bc\u05b8\u05dd \u05e7\u05b4\u05d1\u05bc\u05b0\u05dc\u05d5\u05bc \u05d0\u05b6\u05ea \u05d6\u05b6\u05d4 \u05d1\u05bc\u05b7\u05d9\u05bc\u05b0\u05e8\u05bb\u05e9\u05bc\u05c1\u05b8\u05d4 \u05de\u05d4\u05de\u05d4\u05e8"\u05dd \u05de\u05b4\u05d9\u05e0\u05b0\u05e5 \u05d6\u05e6"\u05dc, \u05e1\u05b4\u05d3\u05bc\u05d5\u05bc\u05e8 \u05e9\u05c1\u05b6\u05db\u05bc\u05b8\u05ea\u05b7\u05d1 \u05d1\u05bc\u05b0\u05de\u05d5\u05b9 \u05d9\u05b8\u05d3\u05b8\u05d9\u05d5! \u05d5\u05b0\u05d4\u05d5\u05b9\u05e1\u05b4\u05d9\u05e3 \u05d4\u05b8\u05e8\u05d5\u05b9\u05e2\u05b6\u05d4 \u05e9\u05c1\u05b6\u05d4\u05d5\u05bc\u05d0 \u05e2\u05b7\u05e6\u05b0\u05de\u05d5\u05b9 \u05d0\u05b5\u05d9\u05e0\u05b6\u05e0\u05bc\u05d5\u05bc \u05d9\u05d5\u05b9\u05d3\u05b5\u05e2\u05b7 \u05e7\u05b0\u05e8\u05b9\u05d0 \u05d5\u05bc\u05db\u05b0\u05ea\u05b9\u05d1 \u05d5\u05b0\u05d0\u05b5\u05d9\u05e0\u05d5\u05b9 \u05d9\u05d5\u05b9\u05d3\u05b5\u05e2\u05b7 \u05dc\u05b0\u05d4\u05b4\u05ea\u05b0\u05e4\u05bc\u05b7\u05dc\u05bc\u05b5\u05dc \u05db\u05bc\u05b0\u05dc\u05b8\u05dc\u2026\n\u05d7\u05b8\u05e9\u05c1\u05b0\u05d1\u05d5\u05bc \u05ea\u05bc\u05b7\u05dc\u05b0\u05de\u05b4\u05d9\u05d3\u05b5\u05d9 \u05d4\u05b7\u05d1\u05bc\u05b7\u05e2\u05b7\u05dc \u05e9\u05c1\u05b5\u05dd \u05d8\u05d5\u05b9\u05d1, \u05d0\u05b4\u05dd \u05d0\u05b4\u05d9\u05e9\u05c1 \u05d6\u05b6\u05d4 \u05d0\u05b5\u05d9\u05e0\u05d5\u05b9 \u05d9\u05d5\u05b9\u05d3\u05b5\u05e2\u05b7 \u05e7\u05b0\u05e8\u05b9\u05d0 \u05d5\u05bc\u05db\u05b0\u05ea\u05b9\u05d1, \u05d1\u05bc\u05b8\u05e8\u05d5\u05bc\u05e8 \u05e9\u05c1\u05b6\u05e8\u05b8\u05d0\u05d5\u05bc\u05d9 \u05e9\u05c1\u05b6\u05d4\u05b7\u05d1\u05bc\u05b7\u05e2\u05b7\u05dc \u05e9\u05c1\u05b5\u05dd \u05d8\u05d5\u05b9\u05d1 \u05d9\u05b4\u05e9\u05c1\u05b0\u05ea\u05bc\u05b7\u05de\u05bc\u05b5\u05e9\u05c1 \u05d1\u05bc\u05d5\u05b9 \u05dc\u05b4\u05ea\u05b0\u05e4\u05b4\u05dc\u05bc\u05b8\u05ea\u05d5\u05b9. \u05e9\u05c1\u05b4\u05db\u05b0\u05e0\u05b0\u05e2\u05d5\u05bc \u05d0\u05b6\u05ea \u05d4\u05b8\u05e8\u05d5\u05b9\u05e2\u05b6\u05d4 \u05dc\u05b8\u05ea\u05b5\u05ea \u05d0\u05b6\u05ea \u05d4\u05b7\u05e1\u05bc\u05b4\u05d3\u05bc\u05d5\u05bc\u05e8 \u05de\u05b7\u05ea\u05bc\u05b8\u05e0\u05b8\u05d4 \u05dc\u05b7\u05d1\u05bc\u05b7\u05e2\u05b7\u05dc \u05e9\u05c1\u05b5\u05dd \u05d8\u05d5\u05b9\u05d1, \u05d5\u05bc\u05d1\u05b0\u05e9\u05c2\u05b4\u05de\u05b0\u05d7\u05b8\u05d4 \u05e8\u05b8\u05e6\u05d5\u05bc \u05dc\u05b0\u05e8\u05b7\u05d1\u05bc\u05b8\u05dd \u05dc\u05b0\u05d1\u05b7\u05e9\u05bc\u05c2\u05b5\u05e8 \u05dc\u05d5\u05b9 \u05e2\u05b7\u05dc \u05d4\u05b8\u05d0\u05d5\u05b9\u05e6\u05b8\u05e8 \u05d4\u05b7\u05d2\u05bc\u05b8\u05d3\u05d5\u05b9\u05dc \u05e9\u05c1\u05b6\u05d4\u05b4\u05d2\u05bc\u05b4\u05d9\u05e2\u05b7 \u05dc\u05b4\u05d9\u05d3\u05b5\u05d9\u05d4\u05b6\u05dd. \u05d2\u05bc\u05b8\u05e0\u05b0\u05d6\u05d5\u05bc \u05d0\u05b6\u05ea \u05d4\u05b7\u05e1\u05bc\u05b4\u05d3\u05bc\u05d5\u05bc\u05e8 \u05d4\u05b7\u05d9\u05bc\u05b8\u05e9\u05c1\u05b8\u05df, \u05d5\u05b0\u05d4\u05b4\u05e0\u05bc\u05b4\u05d9\u05d7\u05d5\u05bc \u05d0\u05b6\u05ea \u05d4\u05b7\u05e1\u05bc\u05b4\u05d3\u05bc\u05d5\u05bc\u05e8 \u05d4\u05b6\u05d7\u05b8\u05d3\u05b8\u05e9\u05c1 \u05d1\u05bc\u05b0\u05e2\u05b7\u05de\u05bc\u05d5\u05bc\u05d3 \u05d4\u05b7\u05ea\u05bc\u05b0\u05e4\u05b4\u05dc\u05bc\u05b8\u05d4 \u05e9\u05c1\u05b6\u05dc \u05e8\u05b7\u05d1\u05bc\u05b8\u05dd.\n\u05d4\u05b4\u05d2\u05bc\u05b4\u05d9\u05e2\u05b7 \u05d6\u05b0\u05de\u05b7\u05df \u05d4\u05b7\u05ea\u05bc\u05b0\u05e4\u05b4\u05dc\u05bc\u05b8\u05d4 \u05d5\u05b0\u05d4\u05b4\u05e0\u05bc\u05b5\u05d4 \u05d4\u05b7\u05d1\u05bc\u05b7\u05e2\u05b7\u05dc \u05e9\u05c1\u05b5\u05dd \u05d8\u05d5\u05b9\u05d1 \u05de\u05b4\u05ea\u05b0\u05d1\u05bc\u05d5\u05b9\u05e0\u05b5\u05df \u05d1\u05bc\u05b7\u05e1\u05bc\u05b4\u05d3\u05bc\u05d5\u05bc\u05e8 \u05d4\u05b6\u05d7\u05b8\u05d3\u05b8\u05e9\u05c1 \u05e9\u05c1\u05b6\u05e2\u05b7\u05dc \u05e2\u05b7\u05de\u05bc\u05d5\u05bc\u05d3 \u05d4\u05b7\u05ea\u05bc\u05b0\u05e4\u05b4\u05dc\u05bc\u05b8\u05d4 \u05e9\u05c1\u05b6\u05dc\u05bc\u05d5\u05b9 \u05e9\u05c1\u05b8\u05e2\u05b8\u05d4 \u05d0\u05b2\u05e8\u05bb\u05db\u05bc\u05b8\u05d4. \u05dc\u05b0\u05d0\u05b7\u05d7\u05b7\u05e8 \u05de\u05b4\u05db\u05bc\u05b5\u05df, \u05d4\u05d5\u05b9\u05e8\u05b8\u05d4 \u05dc\u05b4\u05e9\u05c1\u05b0\u05dc\u05b4\u05d9\u05d7\u05b7 \u05d4\u05b7\u05e6\u05bc\u05b4\u05d1\u05bc\u05d5\u05bc\u05e8 \u05dc\u05b0\u05d4\u05b7\u05ea\u05b0\u05d7\u05b4\u05d9\u05dc \u05d1\u05bc\u05b7\u05ea\u05bc\u05b0\u05e4\u05b4\u05dc\u05bc\u05b8\u05d4. \u05d0\u05d5\u05bc\u05dc\u05b8\u05dd \u05db\u05bc\u05b7\u05d0\u05b2\u05e9\u05c1\u05b6\u05e8 \u05d4\u05b4\u05d2\u05bc\u05b4\u05d9\u05e2\u05b7 \u05d4\u05b7\u05d1\u05bc\u05b7\u05e2\u05b7\u05dc \u05e9\u05c1\u05b5\u05dd \u05d8\u05d5\u05b9\u05d1 \u05dc\u05b4\u05ea\u05b0\u05e4\u05b4\u05dc\u05bc\u05b7\u05ea \u05d4\u05b8\u05e2\u05b2\u05de\u05b4\u05d9\u05d3\u05b8\u05d4, \u05d7\u05b8\u05e8\u05b0\u05d3\u05d5\u05bc \u05d4\u05b7\u05de\u05bc\u05b4\u05ea\u05b0\u05e4\u05bc\u05b7\u05dc\u05bc\u05b0\u05dc\u05b4\u05d9\u05dd \u05dc\u05b0\u05de\u05b7\u05d4 \u05e9\u05bc\u05c1\u05b6\u05e7\u05bc\u05d5\u05b9\u05e8\u05b6\u05d4 \u05dc\u05b0\u05e8\u05b7\u05d1\u05bc\u05b8\u05dd \u05d1\u05bc\u05b7\u05ea\u05bc\u05b0\u05e4\u05b4\u05dc\u05bc\u05b8\u05d4. \u05e4\u05bc\u05b8\u05e0\u05b8\u05d9\u05d5 \u05e0\u05b4\u05ea\u05b0\u05db\u05bc\u05b7\u05e8\u05b0\u05db\u05bc\u05b0\u05de\u05d5\u05bc, \u05d5\u05bc\u05de\u05b4\u05e6\u05b0\u05d7\u05d5\u05b9 \u05d4\u05b4\u05ea\u05b0\u05de\u05b7\u05dc\u05bc\u05b5\u05d0 \u05d1\u05bc\u05b4\u05e7\u05b0\u05de\u05b8\u05d8\u05b4\u05d9\u05dd \u05d5\u05b0\u05d6\u05b5\u05e2\u05b8\u05d4. \u05e0\u05b4\u05e8\u05b0\u05d0\u05b6\u05d4 \u05d4\u05b8\u05d9\u05b8\u05d4 \u05db\u05bc\u05b0\u05d0\u05b4\u05dc\u05bc\u05d5\u05bc \u05d4\u05d5\u05bc\u05d0 \u05e2\u05d5\u05b9\u05de\u05b5\u05d3 \u05dc\u05b0\u05d4\u05b4\u05ea\u05b0\u05e2\u05b7\u05dc\u05bc\u05b5\u05e3. \u05d4\u05b4\u05de\u05b0\u05ea\u05bc\u05b4\u05d9\u05e0\u05d5\u05bc \u05d4\u05b7\u05d7\u05b2\u05e1\u05b4\u05d9\u05d3\u05b4\u05d9\u05dd \u05e2\u05b7\u05d3 \u05e9\u05c1\u05b6\u05e1\u05bc\u05b4\u05d9\u05bc\u05b5\u05dd \u05e8\u05b7\u05d1\u05bc\u05b8\u05dd \u05dc\u05b0\u05d4\u05b4\u05ea\u05b0\u05e4\u05bc\u05b7\u05dc\u05bc\u05b5\u05dc. \u05d5\u05bc\u05dc\u05b0\u05d4\u05b7\u05e4\u05b0\u05ea\u05bc\u05b8\u05e2\u05b7\u05ea \u05db\u05bc\u05bb\u05dc\u05bc\u05b8\u05dd \u05de\u05b4\u05d9\u05bc\u05b8\u05d3 \u05d1\u05bc\u05b0\u05e1\u05b7\u05d9\u05bc\u05b0\u05de\u05d5\u05b9 \u05d0\u05b6\u05ea \u05ea\u05bc\u05b0\u05e4\u05b4\u05dc\u05bc\u05b8\u05ea\u05d5\u05b9 \u05e6\u05b4\u05d5\u05bc\u05b8\u05d4 \u05d1\u05bc\u05b0\u05ea\u05b9\u05e7\u05b6\u05e3 \u05dc\u05b0\u05d4\u05b7\u05d7\u05b0\u05d6\u05b4\u05d9\u05e8 \u05dc\u05b8\u05e8\u05d5\u05b9\u05e2\u05b6\u05d4 \u05d0\u05b6\u05ea \u05e1\u05b4\u05d3\u05bc\u05d5\u05bc\u05e8\u05d5\u05b9, \u05d5\u05b0\u05d4\u05d5\u05b9\u05e1\u05b4\u05d9\u05e3 \u05d5\u05b0\u05d0\u05b8\u05de\u05b7\u05e8: \u05d0\u05b5\u05d9\u05df \u05ea\u05bc\u05b0\u05e4\u05b4\u05dc\u05bc\u05b8\u05d4 \u05e0\u05b8\u05d0\u05b8\u05d4 \u05d9\u05d5\u05b9\u05ea\u05b5\u05e8 \u05de\u05b4\u05ea\u05bc\u05b0\u05e4\u05b4\u05dc\u05bc\u05b8\u05ea\u05d5\u05b9 \u05e9\u05c1\u05b6\u05dc \u05e8\u05d5\u05b9\u05e2\u05b6\u05d4!\n\u05ea\u05bc\u05b8\u05de\u05b0\u05d4\u05d5\u05bc \u05d4\u05b7\u05d7\u05b2\u05e1\u05b4\u05d9\u05d3\u05b4\u05d9\u05dd, \u05d0\u05d5\u05bc\u05dc\u05b8\u05dd \u05de\u05b4\u05d9\u05bc\u05b8\u05d3 \u05e2\u05b8\u05e9\u05c2\u05d5\u05bc \u05db\u05bc\u05b0\u05de\u05b4\u05e6\u05b0\u05d5\u05b7\u05ea \u05e8\u05b7\u05d1\u05bc\u05b8\u05dd. \u05d4\u05b8\u05dc\u05b0\u05db\u05d5\u05bc \u05dc\u05b0\u05d1\u05b5\u05d9\u05ea \u05d4\u05b8\u05e8\u05d5\u05b9\u05e2\u05b6\u05d4, \u05d4\u05b6\u05d7\u05b0\u05d6\u05b4\u05d9\u05e8\u05d5\u05bc \u05dc\u05d5\u05b9 \u05d0\u05b6\u05ea \u05e1\u05b4\u05d3\u05bc\u05d5\u05bc\u05e8\u05d5\u05b9, \u05d5\u05b0\u05e2\u05b8\u05de\u05b0\u05d3\u05d5\u05bc \u05d1\u05bc\u05b4\u05de\u05b0\u05e7\u05d5\u05b9\u05dd \u05de\u05b4\u05e1\u05b0\u05ea\u05bc\u05d5\u05b9\u05e8 \u05dc\u05b4\u05e8\u05b0\u05d0\u05d5\u05b9\u05ea \u05d0\u05b5\u05d9\u05da\u05b0 \u05d4\u05d5\u05bc\u05d0 \u05de\u05b4\u05ea\u05b0\u05e4\u05bc\u05b7\u05dc\u05bc\u05b5\u05dc.\n\u05d1\u05bc\u05b0\u05d4\u05b7\u05d2\u05bc\u05b4\u05d9\u05e2\u05b7 \u05d6\u05b0\u05de\u05b7\u05df \u05d4\u05b7\u05ea\u05bc\u05b0\u05e4\u05b4\u05dc\u05bc\u05b8\u05d4, \u05e0\u05b8\u05d8\u05b7\u05dc \u05d4\u05b8\u05e8\u05d5\u05b9\u05e2\u05b6\u05d4 \u05d0\u05b6\u05ea \u05e1\u05b4\u05d3\u05bc\u05d5\u05bc\u05e8\u05d5\u05b9, \u05d4\u05b4\u05e0\u05bc\u05b4\u05d9\u05d7\u05d5\u05b9 \u05e2\u05b7\u05dc \u05e2\u05b7\u05de\u05bc\u05d5\u05bc\u05d3 \u05d4\u05b7\u05ea\u05bc\u05b0\u05e4\u05b4\u05dc\u05bc\u05b8\u05d4 \u05e9\u05c1\u05b6\u05d1\u05bc\u05b0\u05d7\u05b7\u05d3\u05b0\u05e8\u05d5\u05b9. \u05d4\u05b4\u05ea\u05b0\u05e2\u05b7\u05d8\u05bc\u05b5\u05e3 \u05d1\u05bc\u05b7\u05d8\u05bc\u05b7\u05dc\u05bc\u05b4\u05d9\u05ea, \u05d7\u05b8\u05d1\u05b7\u05e9\u05c1 \u05d0\u05b6\u05ea \u05d4\u05b7\u05ea\u05bc\u05b0\u05e4\u05b4\u05dc\u05bc\u05b4\u05d9\u05df \u05e9\u05c1\u05b6\u05dc\u05bc\u05d5\u05b9, \u05e4\u05bc\u05b8\u05ea\u05b7\u05d7 \u05d0\u05b6\u05ea \u05e1\u05b4\u05d3\u05bc\u05d5\u05bc\u05e8\u05d5\u05b9 \u05e1\u05b0\u05ea\u05b8\u05dd \u05d1\u05bc\u05b0\u05d0\u05b7\u05e7\u05b0\u05e8\u05b7\u05d0\u05d9. \u05e2\u05b8\u05e6\u05b7\u05dd \u05e2\u05b5\u05d9\u05e0\u05b8\u05d9\u05d5, \u05d5\u05b0\u05d4\u05b5\u05d7\u05b5\u05dc \u05de\u05b4\u05ea\u05b0\u05e0\u05b7\u05e2\u05b2\u05e0\u05b5\u05e2\u05b7 \u05d1\u05bc\u05b0\u05d7\u05b8\u05d6\u05b0\u05e7\u05b8\u05d4 \u05e7\u05b8\u05d3\u05b4\u05d9\u05de\u05b8\u05d4 \u05d5\u05b0\u05d0\u05b8\u05d7\u05d5\u05b9\u05e8\u05b8\u05d4, \u05db\u05bc\u05b7\u05d0\u05b2\u05e9\u05c1\u05b6\u05e8 \u05d1\u05bc\u05b0\u05de\u05b6\u05e9\u05c1\u05b6\u05da\u05b0 \u05d4\u05b7\u05ea\u05bc\u05b0\u05e4\u05b4\u05dc\u05bc\u05b8\u05d4 \u05ea\u05bc\u05b0\u05e0\u05d5\u05bc\u05e2\u05d5\u05b9\u05ea\u05b8\u05d9\u05d5 \u05d4\u05b8\u05dc\u05b0\u05db\u05d5\u05bc \u05d5\u05b0\u05d4\u05b4\u05ea\u05b0\u05d7\u05b7\u05d6\u05bc\u05b0\u05e7\u05d5\u05bc. \u05dc\u05b0\u05d0\u05b7\u05d7\u05b7\u05e8 \u05e9\u05c1\u05b8\u05e2\u05b8\u05d4 \u05d0\u05b2\u05e8\u05bb\u05db\u05bc\u05b8\u05d4 \u05e9\u05c1\u05b6\u05dc \u05d4\u05b4\u05ea\u05b0\u05e0\u05b7\u05e2\u05b7\u05e0\u05b0\u05e2\u05d5\u05bc\u05ea \u05de\u05b4\u05e6\u05bc\u05b7\u05d3 \u05d0\u05b6\u05dc \u05e6\u05b7\u05d3 \u05d1\u05bc\u05b0\u05e2\u05b5\u05d9\u05e0\u05b7\u05d9\u05b4\u05dd \u05e2\u05b2\u05e6\u05d5\u05bc\u05de\u05d5\u05b9\u05ea \u05d5\u05bc\u05d1\u05b0\u05dc\u05b4\u05d9 \u05d0\u05b9\u05de\u05b6\u05e8 \u05d5\u05bc\u05d3\u05b0\u05d1\u05b8\u05e8\u05b4\u05d9\u05dd, \u05e1\u05b4\u05d9\u05bc\u05b5\u05dd \u05d4\u05b8\u05e8\u05d5\u05b9\u05e2\u05b6\u05d4 \u05ea\u05bc\u05b0\u05e4\u05b4\u05dc\u05bc\u05b8\u05ea\u05d5\u05b9, \u05e1\u05b8\u05d2\u05b7\u05e8 \u05d0\u05b6\u05ea \u05e1\u05b4\u05d3\u05bc\u05d5\u05bc\u05e8\u05d5\u05b9, \u05e4\u05bc\u05b8\u05e9\u05c1\u05b7\u05d8 \u05d8\u05b7\u05dc\u05bc\u05b4\u05d9\u05ea\u05d5\u05b9, \u05d7\u05b8\u05dc\u05b7\u05e5 \u05d0\u05b6\u05ea \u05ea\u05bc\u05b0\u05e4\u05b4\u05dc\u05bc\u05b8\u05d9\u05d5 \u05d5\u05b0\u05d4\u05b8\u05dc\u05b7\u05da\u05b0 \u05dc\u05b0\u05d3\u05b7\u05e8\u05b0\u05db\u05bc\u05d5\u05b9.\n\u05d4\u05b7\u05d7\u05b2\u05e1\u05b4\u05d9\u05d3\u05b4\u05d9\u05dd \u05e9\u05c1\u05b6\u05dc\u05bc\u05b9\u05d0 \u05d4\u05b5\u05d1\u05b4\u05d9\u05e0\u05d5\u05bc \u05db\u05bc\u05b0\u05dc\u05b8\u05dc \u05d5\u05bc\u05db\u05b0\u05dc\u05b8\u05dc \u05d0\u05b6\u05ea \u05d3\u05bc\u05b6\u05e8\u05b6\u05da\u05b0 \u05ea\u05bc\u05b0\u05e4\u05b4\u05dc\u05bc\u05b8\u05ea\u05d5\u05b9 \u05e9\u05c1\u05b6\u05dc \u05d4\u05b8\u05e8\u05d5\u05b9\u05e2\u05b6\u05d4, \u05d5\u05b0\u05e2\u05d5\u05b9\u05d3 \u05d9\u05d5\u05b9\u05ea\u05b5\u05e8 \u05dc\u05b9\u05d0 \u05d4\u05b5\u05d1\u05b4\u05d9\u05e0\u05d5\u05bc \u05de\u05b7\u05d4 \u05d9\u05bc\u05b9\u05e4\u05b4\u05d9 \u05de\u05b8\u05e6\u05b8\u05d0 \u05e8\u05b7\u05d1\u05bc\u05b8\u05dd \u05d1\u05bc\u05b4\u05ea\u05b0\u05e4\u05b4\u05dc\u05bc\u05b8\u05d4 \u05e9\u05c1\u05b6\u05db\u05bc\u05b8\u05d6\u05b9\u05d0\u05ea, \u05dc\u05b9\u05d0 \u05d4\u05b4\u05ea\u05b0\u05d0\u05b7\u05e4\u05bc\u05b0\u05e7\u05d5\u05bc. \u05d4\u05b5\u05dd \u05e2\u05b8\u05e6\u05b0\u05e8\u05d5\u05bc \u05d0\u05b6\u05ea \u05d4\u05b6\u05d7\u05b8\u05e1\u05b4\u05d9\u05d3 \u05d5\u05b0\u05e9\u05c1\u05b8\u05d0\u05b2\u05dc\u05d5\u05bc \u05d0\u05d5\u05b9\u05ea\u05d5\u05b9: \u05dc\u05b4\u05ea\u05b0\u05e4\u05b4\u05dc\u05bc\u05b8\u05d4 \u05d6\u05d5\u05b9 \u05de\u05b8\u05d4 \u05e2\u05d5\u05b9\u05e9\u05c2\u05b8\u05d4?\n\u05e2\u05b8\u05e0\u05b8\u05d4 \u05dc\u05b8\u05d4\u05b6\u05dd \u05d4\u05b8\u05e8\u05d5\u05b9\u05e2\u05b6\u05d4: \u05d9\u05b0\u05d4\u05d5\u05bc\u05d3\u05b4\u05d9 \u05e4\u05bc\u05b8\u05e9\u05c1\u05d5\u05bc\u05d8 \u05d0\u05b2\u05e0\u05b4\u05d9, \u05d1\u05bc\u05b0\u05e1\u05b7\u05da\u05b0 \u05d4\u05b7\u05db\u05bc\u05b9\u05dc \u05e8\u05d5\u05b9\u05e2\u05b5\u05d4 \u05e6\u05b9\u05d0\u05df, \u05d0\u05b2\u05d1\u05b8\u05dc \u05d6\u05b8\u05db\u05b4\u05d9\u05ea\u05b4\u05d9 \u05dc\u05b0\u05d4\u05b4\u05ea\u05b0\u05d9\u05b7\u05d7\u05b5\u05e1 \u05dc\u05b4\u05d2\u05b0\u05d3\u05d5\u05b9\u05dc\u05b4\u05d9\u05dd \u05d5\u05b0\u05e6\u05b7\u05d3\u05bc\u05b4\u05d9\u05e7\u05b4\u05d9\u05dd. \u05d1\u05bc\u05b4\u05d4\u05b0\u05d9\u05d5\u05b9\u05ea\u05b4\u05d9 \u05d9\u05b6\u05dc\u05b6\u05d3 \u05d4\u05b8\u05dc\u05b7\u05db\u05b0\u05ea\u05bc\u05b4\u05d9 \u05e2\u05b4\u05dd \u05e1\u05b8\u05d1\u05b4\u05d9 \u05dc\u05b0\u05d1\u05b5\u05d9\u05ea \u05d4\u05b7\u05db\u05bc\u05b0\u05e0\u05b6\u05e1\u05b6\u05ea. \u05d5\u05b0\u05db\u05b7\u05d0\u05b2\u05e9\u05c1\u05b6\u05e8 \u05d4\u05d5\u05bc\u05d0 \u05d4\u05b8\u05d9\u05b8\u05d4 \u05de\u05b4\u05ea\u05b0\u05e4\u05bc\u05b7\u05dc\u05bc\u05b5\u05dc \u05d5\u05b0\u05e1\u05b4\u05d3\u05bc\u05d5\u05bc\u05e8\u05d5\u05b9 \u05d1\u05bc\u05b0\u05d9\u05b8\u05d3\u05d5\u05b9 \u05e2\u05b8\u05d8\u05d5\u05bc\u05e3 \u05d1\u05bc\u05b0\u05d8\u05b7\u05dc\u05bc\u05b4\u05d9\u05ea \u05d5\u05bc\u05de\u05b0\u05e2\u05bb\u05d8\u05bc\u05b8\u05e8 \u05d1\u05bc\u05b4\u05ea\u05b0\u05e4\u05b4\u05dc\u05bc\u05b4\u05d9\u05df, \u05d4\u05d5\u05bc\u05d0 \u05e0\u05b4\u05d3\u05b0\u05de\u05b8\u05d4 \u05d1\u05bc\u05b0\u05e2\u05b5\u05d9\u05e0\u05b7\u05d9 \u05db\u05bc\u05b0\u05de\u05b7\u05dc\u05b0\u05d0\u05b7\u05da\u05b0 \u05d0\u05b1\u05dc\u05b9\u05e7\u05b4\u05d9\u05dd. \u05d4\u05b8\u05d9\u05b4\u05d9\u05ea\u05b4\u05d9 \u05e8\u05b7\u05e7 \u05e2\u05d5\u05b9\u05de\u05b5\u05d3 \u05dc\u05b0\u05e6\u05b4\u05d3\u05bc\u05d5\u05b9, \u05de\u05b4\u05ea\u05b0\u05d1\u05bc\u05d5\u05b9\u05e0\u05b5\u05df \u05d1\u05bc\u05d5\u05b9 \u05d5\u05bc\u05de\u05b4\u05ea\u05b0\u05e4\u05bc\u05b7\u05dc\u05bc\u05b5\u05d0 \u05d0\u05b5\u05d9\u05da\u05b0 \u05d4\u05d5\u05bc\u05d0 \u05de\u05b4\u05ea\u05b0\u05e4\u05bc\u05b7\u05dc\u05bc\u05b5\u05dc \u05d5\u05bc\u05de\u05b4\u05ea\u05b0\u05e0\u05d5\u05b9\u05e2\u05b5\u05e2\u05b7, \u05db\u05bc\u05b0\u05d0\u05b4\u05dc\u05bc\u05d5\u05bc \u05d4\u05d5\u05bc\u05d0 \u05de\u05b0\u05d3\u05b7\u05d1\u05bc\u05b5\u05e8 \u05e2\u05b4\u05dd \u05d4\u05b7\u05e9\u05bc\u05c1\u05b5\u05dd \u05e4\u05bc\u05b8\u05e0\u05b4\u05d9\u05dd \u05d1\u05bc\u05b0\u05e4\u05b8\u05e0\u05b4\u05d9\u05dd \u05d1\u05bc\u05b4\u05d3\u05b0\u05d1\u05b5\u05e7\u05d5\u05bc\u05ea \u05d1\u05bc\u05b0\u05d0\u05b7\u05d4\u05b2\u05d1\u05b8\u05d4 \u05d5\u05bc\u05d1\u05b0\u05e9\u05c2\u05b4\u05de\u05b0\u05d7\u05b8\u05d4. \u05d5\u05bc\u05de\u05b7\u05d4 \u05e0\u05bc\u05b8\u05d0\u05d5\u05b9\u05ea \u05d4\u05b8\u05d9\u05d5\u05bc \u05e4\u05bc\u05b8\u05e0\u05b8\u05d9\u05d5 \u05db\u05bc\u05b7\u05d0\u05b2\u05e9\u05c1\u05b6\u05e8 \u05e2\u05b5\u05d9\u05e0\u05b8\u05d9\u05d5 \u05e2\u05b2\u05e6\u05d5\u05bc\u05de\u05d5\u05b9\u05ea. \u05d0\u05b5\u05d9\u05d6\u05d5\u05b9 \u05e7\u05b0\u05d3\u05bb\u05e9\u05bc\u05c1\u05b8\u05d4 \u05d5\u05b0\u05d7\u05d5\u05bc\u05d8 \u05e9\u05c1\u05b6\u05dc \u05d7\u05b6\u05e1\u05b6\u05d3 \u05d4\u05b8\u05d9\u05d5\u05bc \u05de\u05b0\u05e9\u05c1\u05d5\u05bc\u05db\u05b4\u05d9\u05dd \u05e2\u05b7\u05dc \u05e4\u05bc\u05b8\u05e0\u05b8\u05d9\u05d5. \u05d4\u05b8\u05d9\u05b4\u05d9\u05ea\u05b4\u05d9 \u05e8\u05d5\u05b9\u05e2\u05b5\u05d3 \u05de\u05b5\u05d4\u05b4\u05ea\u05b0\u05e8\u05b7\u05d2\u05bc\u05b0\u05e9\u05c1\u05d5\u05bc\u05ea \u05d5\u05b0\u05d4\u05b6\u05d7\u05b0\u05dc\u05b7\u05d8\u05b0\u05ea\u05bc\u05b4\u05d9 \u05e9\u05c1\u05b6\u05db\u05bc\u05b7\u05d0\u05b2\u05e9\u05c1\u05b6\u05e8 \u05d0\u05b6\u05d2\u05b0\u05d3\u05bc\u05b7\u05dc \u05d0\u05b6\u05ea\u05b0\u05e4\u05bc\u05b7\u05dc\u05bc\u05b5\u05dc \u05db\u05bc\u05b8\u05de\u05d5\u05b9\u05d4\u05d5\u05bc.\n\u05dc\u05b0\u05e6\u05b7\u05e2\u05b2\u05e8\u05b4\u05d9 \u05dc\u05b9\u05d0 \u05dc\u05b8\u05de\u05b7\u05d3\u05b0\u05ea\u05bc\u05b4\u05d9 \u05ea\u05bc\u05d5\u05b9\u05e8\u05b8\u05d4, \u05d5\u05b0\u05d0\u05b5\u05d9\u05e0\u05b6\u05e0\u05bc\u05b4\u05d9 \u05d9\u05d5\u05b9\u05d3\u05b5\u05e2\u05b7 \u05e7\u05b0\u05e8\u05b9\u05d0 \u05d5\u05bc\u05db\u05b0\u05ea\u05b9\u05d1, \u05d4\u05b4\u05e0\u05b0\u05e0\u05b4\u05d9 \u05e8\u05d5\u05b9\u05e2\u05b6\u05d4 \u05e4\u05bc\u05b8\u05e9\u05c1\u05d5\u05bc\u05d8. \u05d0\u05d5\u05bc\u05dc\u05b8\u05dd \u05d6\u05b8\u05db\u05b4\u05d9\u05ea\u05b4\u05d9 \u05dc\u05b0\u05e7\u05b7\u05d1\u05bc\u05b5\u05dc \u05d0\u05b6\u05ea \u05d4\u05b7\u05e1\u05bc\u05b4\u05d3\u05bc\u05d5\u05bc\u05e8 \u05d4\u05b7\u05d9\u05bc\u05b8\u05e7\u05b8\u05e8 \u05d4\u05b7\u05d6\u05bc\u05b6\u05d4 \u05d1\u05bc\u05b4\u05d9\u05e8\u05bb\u05e9\u05bc\u05c1\u05b8\u05d4! \u05d5\u05b0\u05d6\u05d5\u05b9 \u05d3\u05bc\u05b7\u05e8\u05b0\u05db\u05bc\u05b4\u05d9 \u05d1\u05bc\u05b7\u05e7\u05bc\u05b9\u05d3\u05b6\u05e9\u05c1 \u05db\u05bc\u05b7\u05d0\u05b2\u05e9\u05c1\u05b6\u05e8 \u05d4\u05b7\u05e6\u05bc\u05b4\u05d1\u05bc\u05d5\u05bc\u05e8 \u05de\u05b4\u05ea\u05b0\u05db\u05bc\u05b7\u05e0\u05bc\u05b5\u05e1 \u05d1\u05bc\u05b0\u05d1\u05b8\u05ea\u05bc\u05b5\u05d9 \u05db\u05bc\u05b0\u05e0\u05b5\u05e1\u05b4\u05d9\u05bc\u05d5\u05b9\u05ea, \u05d0\u05b2\u05e0\u05b4\u05d9 \u05dc\u05d5\u05b9\u05e7\u05b5\u05d7\u05b7 \u05d0\u05b6\u05ea \u05e1\u05b4\u05d3\u05bc\u05d5\u05bc\u05e8\u05b4\u05d9, \u05de\u05b7\u05e0\u05bc\u05b4\u05d9\u05d7\u05d5\u05b9 \u05e2\u05b7\u05dc \u05e2\u05b7\u05de\u05bc\u05d5\u05bc\u05d3 \u05d4\u05b7\u05ea\u05bc\u05b0\u05e4\u05b4\u05dc\u05bc\u05b8\u05d4 \u05e9\u05c1\u05b6\u05dc \u05e1\u05b8\u05d1\u05b4\u05d9, \u05e2\u05d5\u05b9\u05e6\u05b5\u05dd \u05e2\u05b5\u05d9\u05e0\u05b7\u05d9, \u05d5\u05bc\u05d1\u05b0\u05dc\u05b4\u05d9 \u05d0\u05b9\u05de\u05b6\u05e8 \u05d5\u05bc\u05d3\u05b0\u05d1\u05b8\u05e8\u05b4\u05d9\u05dd \u05d0\u05b2\u05e0\u05b4\u05d9 \u05de\u05b4\u05ea\u05b0\u05e0\u05b7\u05e2\u05b2\u05e0\u05b5\u05e2\u05b7, \u05db\u05bc\u05b7\u05d0\u05b2\u05e9\u05c1\u05b6\u05e8 \u05dc\u05b4\u05d1\u05bc\u05b4\u05d9 \u05e4\u05bc\u05d5\u05b9\u05e0\u05b6\u05d4 \u05dc\u05b7\u05e7\u05bc\u05b8\u05d3\u05d5\u05b9\u05e9\u05c1 \u05d1\u05bc\u05b8\u05e8\u05d5\u05bc\u05da\u05b0 \u05d4\u05d5\u05bc\u05d0 \u05e9\u05c1\u05b6\u05d9\u05bc\u05b0\u05e7\u05b7\u05d1\u05bc\u05b5\u05dc \u05db\u05bc\u05b7\u05d5\u05bc\u05b8\u05e0\u05b8\u05ea\u05b4\u05d9 \u05d4\u05b7\u05d8\u05bc\u05b0\u05d4\u05d5\u05b9\u05e8\u05b8\u05d4 \u05db\u05bc\u05b4\u05ea\u05b0\u05e4\u05b4\u05dc\u05bc\u05b8\u05d4 \u05d0\u05b2\u05de\u05b4\u05ea\u05bc\u05b4\u05d9\u05ea.\n\u05d4\u05b8\u05e8\u05d5\u05b9\u05e2\u05b6\u05d4 \u05e1\u05b4\u05d9\u05bc\u05b5\u05dd \u05e1\u05b4\u05e4\u05bc\u05d5\u05bc\u05e8\u05d5\u05b9. \u05d4\u05b7\u05d7\u05b2\u05e1\u05b4\u05d9\u05d3\u05b4\u05d9\u05dd \u05e9\u05c1\u05b8\u05d1\u05d5\u05bc \u05dc\u05b0\u05e8\u05b7\u05d1\u05bc\u05b8\u05dd, \u05d5\u05b0\u05d4\u05b4\u05e0\u05bc\u05b5\u05d4 \u05d4\u05d5\u05bc\u05d0 \u05de\u05b0\u05e7\u05b7\u05d1\u05bc\u05b5\u05dc \u05e4\u05bc\u05b0\u05e0\u05b5\u05d9\u05d4\u05b6\u05dd \u05d1\u05bc\u05b0\u05d7\u05b4\u05d9\u05bc\u05d5\u05bc\u05da\u05b0, \u05d5\u05b0\u05d0\u05d5\u05b9\u05de\u05b5\u05e8 \u05dc\u05b8\u05d4\u05b6\u05dd: \u05e8\u05b0\u05d0\u05b4\u05d9\u05ea\u05b6\u05dd \u05d0\u05b6\u05ea \u05ea\u05bc\u05b0\u05e4\u05b4\u05dc\u05bc\u05b7\u05ea \u05d4\u05b8\u05e8\u05d5\u05b9\u05e2\u05b6\u05d4 \u05e9\u05c1\u05b6\u05d0\u05b5\u05d9\u05e0\u05d5\u05b9 \u05d9\u05d5\u05b9\u05d3\u05b5\u05e2\u05b7 \u05dc\u05b0\u05d4\u05b4\u05ea\u05b0\u05e4\u05bc\u05b7\u05dc\u05bc\u05b5\u05dc \u05db\u05bc\u05b0\u05dc\u05b8\u05dc. \u05d9\u05d5\u05b9\u05d3\u05b5\u05e2\u05b7 \u05d4\u05d5\u05bc\u05d0 \u05e8\u05b7\u05e7 \u05d0\u05b6\u05ea \u05ea\u05bc\u05b0\u05e0\u05d5\u05bc\u05e2\u05d5\u05b9\u05ea \u05d4\u05b7\u05ea\u05bc\u05b0\u05e4\u05b4\u05dc\u05bc\u05b8\u05d4, \u05d5\u05b0\u05db\u05bb\u05dc\u05bc\u05b0\u05db\u05b6\u05dd \u05ea\u05bc\u05b0\u05de\u05b5\u05d4\u05b4\u05d9\u05dd \u05d5\u05b0\u05e9\u05c1\u05d5\u05b9\u05d0\u05b2\u05dc\u05b4\u05d9\u05dd, \u05de\u05b6\u05d4 \u05e2\u05b5\u05e8\u05b6\u05da\u05b0 \u05d1\u05bc\u05b4\u05ea\u05b0\u05e0\u05d5\u05bc\u05e2\u05d5\u05b9\u05ea \u05d4\u05b7\u05ea\u05bc\u05b0\u05e4\u05b4\u05dc\u05bc\u05b8\u05d4, \u05db\u05bc\u05b7\u05d0\u05b2\u05e9\u05c1\u05b6\u05e8 \u05d0\u05b5\u05d9\u05df \u05d0\u05d5\u05b9\u05de\u05b0\u05e8\u05b4\u05d9\u05dd \u05d0\u05b6\u05ea \u05d0\u05d5\u05b9\u05ea\u05b4\u05d9\u05bc\u05d5\u05b9\u05ea \u05d4\u05b7\u05ea\u05bc\u05b0\u05e4\u05b4\u05dc\u05bc\u05b8\u05d4? \u05d0\u05d5\u05bc\u05dc\u05b8\u05dd \u05d4\u05b7\u05d0\u05b4\u05dd \u05d0\u05b7\u05ea\u05bc\u05b6\u05dd \u05de\u05b7\u05db\u05bc\u05b4\u05d9\u05e8\u05b4\u05d9\u05dd \u05de\u05b4\u05d9\u05e9\u05c1\u05b6\u05d4\u05d5\u05bc \u05e9\u05c1\u05b6\u05d1\u05bc\u05b6\u05d0\u05b1\u05de\u05b6\u05ea \u05d9\u05d5\u05b9\u05d3\u05b5\u05e2\u05b7 \u05dc\u05b0\u05d4\u05b4\u05ea\u05b0\u05e4\u05bc\u05b7\u05dc\u05bc\u05b5\u05dc?!\n\u05d5\u05b0\u05d4\u05d5\u05b9\u05e1\u05b4\u05d9\u05e3 \u05d4\u05b7\u05d1\u05bc\u05b7\u05e2\u05b7\u05dc \u05e9\u05c1\u05b5\u05dd \u05d8\u05d5\u05b9\u05d1 \u05d5\u05b0\u05d0\u05b8\u05de\u05b7\u05e8: \u05de\u05b9\u05e9\u05c1\u05b6\u05d4 \u05e8\u05b7\u05d1\u05bc\u05b5\u05e0\u05d5\u05bc, \u05e8\u05b7\u05d1\u05bc\u05b8\u05df \u05e9\u05c1\u05b6\u05dc \u05e0\u05b0\u05d1\u05b4\u05d9\u05d0\u05b4\u05d9\u05dd, \u05d1\u05bc\u05b4\u05e7\u05bc\u05b5\u05e9\u05c1 \u05dc\u05b0\u05d4\u05b8\u05e7\u05b4\u05d9\u05dd \u05d0\u05b6\u05ea \u05d4\u05b7\u05de\u05bc\u05b4\u05e9\u05c1\u05b0\u05db\u05bc\u05b8\u05df, \u05d5\u05b0\u05d4\u05b8\u05d9\u05b8\u05d4 \u05de\u05b8\u05dc\u05b5\u05d0 \u05d0\u05b5\u05d9\u05de\u05b8\u05d4 \u05d5\u05b0\u05d9\u05b4\u05e8\u05b0\u05d0\u05b8\u05d4, \u05d1\u05bc\u05b0\u05d0\u05d5\u05b9\u05de\u05b0\u05e8\u05d5\u05b9: \u05d0\u05b5\u05d9\u05da\u05b0 \u05d0\u05b6\u05e4\u05b0\u05e9\u05c1\u05b8\u05e8 \u05dc\u05b0\u05d4\u05b8\u05e7\u05b4\u05d9\u05dd \u05d1\u05bc\u05b7\u05d9\u05b4\u05ea \u05dc\u05b0\u05d4\u05b7\u05e9\u05bc\u05c1\u05b5\u05dd? \u05d4\u05b2\u05e8\u05b5\u05d9 "\u05d4\u05b7\u05e9\u05bc\u05c1\u05b8\u05de\u05b7\u05d9\u05b4\u05dd \u05d5\u05bc\u05e9\u05c1\u05b0\u05de\u05b5\u05d9 \u05d4\u05b7\u05e9\u05bc\u05c1\u05b8\u05de\u05b7\u05d9\u05b4\u05dd \u05dc\u05b9\u05d0 \u05d9\u05b0\u05db\u05b7\u05dc\u05b0\u05db\u05bc\u05b0\u05dc\u05d5\u05bc\u05da\u05b8", \u05d0\u05b8\u05d6 \u05d0\u05b5\u05d9\u05da\u05b0 \u05d9\u05b0\u05e6\u05b7\u05de\u05b0\u05e6\u05b5\u05dd \u05d4\u05b7\u05e7\u05bc\u05b8\u05d3\u05d5\u05b9\u05e9\u05c1 \u05d1\u05bc\u05b8\u05e8\u05d5\u05bc\u05da\u05b0 \u05d4\u05d5\u05bc\u05d0 \u05d0\u05b6\u05ea \u05e9\u05c1\u05b0\u05db\u05b4\u05d9\u05e0\u05b8\u05ea\u05d5\u05b9 \u05d1\u05bc\u05b0\u05ea\u05d5\u05b9\u05da\u05b0 \u05de\u05b4\u05e9\u05c1\u05b0\u05db\u05bc\u05b8\u05df? \u05d5\u05bc\u05d1\u05b0\u05db\u05b8\u05dc \u05d6\u05b9\u05d0\u05ea \u05d4\u05b5\u05e7\u05b4\u05d9\u05dd \u05de\u05b4\u05e9\u05c1\u05b0\u05db\u05bc\u05b8\u05df, \u05db\u05bc\u05b4\u05d9 \u05d4\u05b7\u05e9\u05bc\u05c1\u05b5\u05dd \u05e6\u05b4\u05d5\u05bc\u05b8\u05d4\u05bc, \u05dc\u05b7\u05e2\u05b2\u05e9\u05c2\u05d5\u05b9\u05ea \u05dc\u05d5\u05b9 \u05de\u05b4\u05e9\u05c1\u05b0\u05db\u05bc\u05b8\u05df \u05d1\u05bc\u05d5\u05b9 \u05d9\u05b4\u05e9\u05c1\u05b0\u05db\u05bc\u05b9\u05df.\n\u05d5\u05b0\u05d4\u05d5\u05b9\u05e1\u05b4\u05d9\u05e3 \u05d4\u05b7\u05d1\u05bc\u05b7\u05e2\u05b7\u05dc \u05e9\u05c1\u05b5\u05dd \u05d8\u05d5\u05b9\u05d1: \u05d2\u05bc\u05b7\u05dd \u05d0\u05b2\u05e0\u05b7\u05d7\u05b0\u05e0\u05d5\u05bc \u05d0\u05b5\u05d9\u05e0\u05b6\u05e0\u05bc\u05d5\u05bc \u05d9\u05d5\u05b9\u05d3\u05b0\u05e2\u05b4\u05d9\u05dd \u05d0\u05b5\u05d9\u05da\u05b0 \u05dc\u05b7\u05e2\u05b2\u05d1\u05b9\u05d3 \u05d0\u05b6\u05ea \u05d4\u05b7\u05e9\u05bc\u05c1\u05b5\u05dd. \u05d0\u05b2\u05e0\u05b7\u05d7\u05b0\u05e0\u05d5\u05bc \u05de\u05b0\u05d1\u05b4\u05d9\u05e0\u05b4\u05d9\u05dd \u05e9\u05c1\u05b6\u05e2\u05b2\u05d1\u05d5\u05b9\u05d3\u05b8\u05ea\u05b5\u05e0\u05d5\u05bc \u05d0\u05b5\u05d9\u05e0\u05b8\u05d4\u05bc \u05e9\u05c1\u05b0\u05dc\u05b5\u05de\u05b8\u05d4. \u05d5\u05bc\u05d1\u05b6\u05d0\u05b1\u05de\u05b6\u05ea \u05db\u05bc\u05b8\u05dc \u05de\u05b7\u05e2\u05b2\u05e9\u05c2\u05b5\u05d9\u05e0\u05d5\u05bc \u05d4\u05b5\u05dd \u05db\u05bc\u05b0\u05de\u05d5\u05b9 \u05ea\u05bc\u05b0\u05e0\u05d5\u05bc\u05e2\u05d5\u05b9\u05ea \u05d7\u05b4\u05d9\u05e6\u05d5\u05b9\u05e0\u05b4\u05d9\u05bc\u05d5\u05b9\u05ea \u05d1\u05bc\u05b4\u05dc\u05b0\u05d1\u05b7\u05d3, \u05db\u05bc\u05b7\u05d0\u05b2\u05e9\u05c1\u05b6\u05e8 \u05d7\u05d5\u05b9\u05d1\u05b8\u05d4 \u05d2\u05bc\u05b0\u05d3\u05d5\u05b9\u05dc\u05b8\u05d4 \u05de\u05d5\u05bc\u05d8\u05b6\u05dc\u05b6\u05ea \u05e2\u05b8\u05dc\u05b5\u05d9\u05e0\u05d5\u05bc \u05d1\u05bc\u05b7\u05e2\u05b2\u05d1\u05d5\u05b9\u05d3\u05b8\u05d4 \u05d0\u05b2\u05de\u05b4\u05ea\u05bc\u05b4\u05d9\u05ea \u05d5\u05bc\u05e4\u05b0\u05e0\u05b4\u05d9\u05de\u05b4\u05d9\u05ea \u05db\u05bc\u05b0\u05dc\u05b7\u05e4\u05bc\u05b5\u05d9 \u05d4\u05b7\u05e7\u05bc\u05b8\u05d3\u05d5\u05b9\u05e9\u05c1 \u05d1\u05bc\u05b8\u05e8\u05d5\u05bc\u05da\u05b0 \u05d4\u05d5\u05bc\u05d0. \u05d5\u05bc\u05d1\u05b0\u05db\u05b8\u05dc \u05d0\u05b9\u05e4\u05b6\u05df, \u05d0\u05b8\u05e0\u05d5\u05bc \u05d7\u05b7\u05d9\u05bc\u05b8\u05d1\u05b4\u05d9\u05dd \u05dc\u05b7\u05e2\u05b2\u05e9\u05c2\u05d5\u05b9\u05ea \u05d0\u05b6\u05ea \u05db\u05bc\u05b8\u05dc \u05d0\u05b2\u05e9\u05c1\u05b6\u05e8 \u05d1\u05bc\u05b4\u05d9\u05db\u05b8\u05dc\u05b0\u05ea\u05bc\u05b5\u05e0\u05d5\u05bc, \u05d5\u05b0\u05d0\u05b4\u05dd \u05e0\u05b7\u05e2\u05b2\u05e9\u05c2\u05b6\u05d4 \u05de\u05b4\u05e6\u05bc\u05b4\u05d3\u05bc\u05b5\u05e0\u05d5\u05bc \u05de\u05b7\u05d4 \u05e9\u05c1\u05b6\u05e0\u05bc\u05d5\u05bc\u05db\u05b7\u05dc \u05de\u05bb\u05d1\u05b0\u05d8\u05b8\u05d7 \u05dc\u05b8\u05e0\u05d5\u05bc \u05e9\u05c1\u05b6\u05d1\u05bc\u05b0\u05e1\u05d5\u05b9\u05e4\u05d5\u05b9 \u05e9\u05c1\u05b6\u05dc \u05d3\u05bc\u05b8\u05d1\u05b8\u05e8, \u05d0\u05b7\u05e3 \u05d0\u05b4\u05dd \u05dc\u05b9\u05d0 \u05e0\u05b7\u05d2\u05bc\u05b4\u05d9\u05e2\u05b7 \u05dc\u05b4\u05e9\u05c1\u05b0\u05dc\u05b5\u05de\u05d5\u05bc\u05ea \u05d1\u05bc\u05b0\u05de\u05b7\u05e2\u05b2\u05e9\u05c2\u05b5\u05e0\u05d5\u05bc, \u05ea\u05bc\u05b4\u05e9\u05c1\u05b0\u05e8\u05b6\u05d4 \u05e9\u05c1\u05b0\u05db\u05b4\u05d9\u05e0\u05b8\u05d4 \u05d1\u05bc\u05b0\u05de\u05b7\u05e2\u05b2\u05e9\u05c2\u05b5\u05d9 \u05d9\u05b8\u05d3\u05b5\u05d9\u05e0\u05d5\u05bc.',"","")
B.KR=new A.cv(14,"\u05de\u05e7\u05d5\u05dd \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4: \u05dc\u05de\u05e6\u05d5\u05d0 \u05d0\u05ea \u05d4\u05d9\u05e2\u05e8",'\u05d4\u05d0\u05dd \u05d9\u05e9 \u05d7\u05e9\u05d9\u05d1\u05d5\u05ea \u05dc\u05de\u05e7\u05d5\u05dd \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4.\n\u05e8\u05d1\u05d9\u05dd \u05de\u05e2\u05d3\u05d9\u05e4\u05d9\u05dd \u05dc\u05d4\u05ea\u05e4\u05dc\u05dc \u05d1\u05d8\u05d1\u05e2 \u05d0\u05d5 \u05d1\u05d1\u05d9\u05ea \u05d5\u05dc\u05d0 \u05d1\u05d1\u05d9\u05ea \u05d4\u05db\u05e0\u05e1\u05ea.\n\u05de\u05e2\u05d1\u05e8 \u05dc\u05e8\u05e6\u05d9\u05d5\u05e0\u05dc \u05d4\u05d4\u05dc\u05db\u05ea\u05d9 \u05e0\u05e0\u05e1\u05d4 \u05dc\u05d4\u05d1\u05d9\u05df \u05de\u05e0\u05e7\u05d5\u05d3\u05ea \u05de\u05d1\u05d8 \u05e8\u05d2\u05e9\u05d9\u05ea \u05d9\u05d5\u05ea\u05e8.\n\u05d4\u05d9\u05db\u05df \u05d0\u05ea\u05dd \u05de\u05e8\u05d2\u05d9\u05e9\u05d9\u05dd \u05d4\u05e9\u05e8\u05d0\u05d4 \u05d5\u05d7\u05d9\u05d1\u05d5\u05e8 \u05e2\u05de\u05d5\u05e7 \u05d9\u05d5\u05ea\u05e8 \u05d0\u05dc \u05d4\u05e7\u05d1"\u05d4?\n\u05d4\u05e1\u05d9\u05e4\u05d5\u05e8 \u05d4\u05d1\u05d0 \u05d0\u05d5\u05dc\u05d9 \u05d9\u05d0\u05d9\u05e8 \u05de\u05e2\u05d8 \u05d0\u05ea \u05d4\u05e2\u05e0\u05d9\u05d9\u05df.\n\u05e1\u05d9\u05e4\u05d5\u05e8 \u05d7\u05e1\u05d9\u05d3\u05d9 \u05de\u05e4\u05d5\u05e8\u05e1\u05dd \u05de\u05e1\u05e4\u05e8 \u05e2\u05dc \u05e8\u05d1\u05d9 \u05d9\u05e9\u05e8\u05d0\u05dc \u05d1\u05e2\u05dc \u05e9\u05dd \u05d8\u05d5\u05d1, \u05e9\u05db\u05e9\u05d4\u05d9\u05d4 \u05e8\u05d5\u05d0\u05d4 \u05e9\u05e4\u05d5\u05e8\u05e2\u05e0\u05d5\u05ea \u05de\u05ea\u05e8\u05d2\u05e9\u05ea \u05dc\u05d1\u05d5\u05d0 \u05e2\u05dc \u05d9\u05e9\u05e8\u05d0\u05dc, \u05d4\u05d9\u05d4 \u05d4\u05d5\u05dc\u05da \u05dc\u05de\u05e7\u05d5\u05dd \u05d0\u05d7\u05d3 \u05d1\u05d9\u05e2\u05e8 \u05d5\u05de\u05ea\u05d9\u05d9\u05d7\u05d3 \u05e2\u05dd \u05e0\u05e4\u05e9\u05d5. \u05e9\u05dd \u05d4\u05d9\u05d4 \u05de\u05d3\u05dc\u05d9\u05e7 \u05d0\u05e9, \u05d0\u05d5\u05de\u05e8 \u05ea\u05e4\u05d9\u05dc\u05d4 \u05d0\u05d7\u05ea, \u05d5\u05e0\u05e1 \u05d4\u05d9\u05d4 \u05de\u05ea\u05e8\u05d7\u05e9, \u05d5\u05d4\u05d2\u05d6\u05d9\u05e8\u05d4 \u05d4\u05d9\u05d9\u05ea\u05d4 \u05de\u05ea\u05d1\u05d8\u05dc\u05ea.\n\u05dc\u05d0\u05d7\u05e8 \u05d6\u05de\u05df, \u05db\u05e9\u05d4\u05d9\u05d4 \u05ea\u05dc\u05de\u05d9\u05d3\u05d5 \u05e8\u05d1\u05d9 \u05d3\u05d5\u05d1 \u05d1\u05e8, \u05d4\u05de\u05d2\u05d9\u05d3 \u05de\u05de\u05d6\u05e8\u05d9\u05e5\', \u05e6\u05e8\u05d9\u05da \u05dc\u05d1\u05e7\u05e9 \u05e8\u05d7\u05de\u05d9\u05dd \u05e2\u05dc \u05d9\u05e9\u05e8\u05d0\u05dc, \u05d4\u05d9\u05d4 \u05d4\u05d5\u05dc\u05da \u05dc\u05d0\u05d5\u05ea\u05d5 \u05de\u05e7\u05d5\u05dd \u05d1\u05d9\u05e2\u05e8 \u05d5\u05d0\u05d5\u05de\u05e8: \u05e8\u05d9\u05d1\u05d5\u05e0\u05d5 \u05e9\u05dc \u05e2\u05d5\u05dc\u05dd, \u05d4\u05d8\u05d4 \u05d0\u05d5\u05d6\u05e0\u05da. \u05d0\u05d9\u05e0\u05d9 \u05d9\u05d5\u05d3\u05e2 \u05db\u05d9\u05e6\u05d3 \u05de\u05d3\u05dc\u05d9\u05e7\u05d9\u05dd \u05d0\u05ea \u05d4\u05d0\u05e9, \u05d0\u05d1\u05dc \u05e2\u05d3\u05d9\u05d9\u05df \u05d9\u05db\u05d5\u05dc \u05d0\u05e0\u05d9 \u05dc\u05d5\u05de\u05e8 \u05d0\u05ea \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4, \u05d5\u05d4\u05e0\u05e1 \u05d4\u05d9\u05d4 \u05de\u05ea\u05e8\u05d7\u05e9.\n\u05d5\u05dc\u05d0\u05d7\u05e8 \u05d6\u05de\u05df \u05d4\u05d9\u05d4 \u05e8\u05d1\u05d9 \u05de\u05e9\u05d4 \u05dc\u05d9\u05d9\u05d1 \u05de\u05e1\u05d0\u05e1\u05d5\u05d1 \u05d4\u05d5\u05dc\u05da \u05d0\u05e3 \u05d4\u05d5\u05d0, \u05db\u05d3\u05d9 \u05dc\u05d4\u05e6\u05d9\u05dc \u05d0\u05ea \u05e2\u05de\u05d5, \u05d0\u05dc \u05d4\u05d9\u05e2\u05e8 \u05d5\u05d0\u05d5\u05de\u05e8: \u05d0\u05d9\u05e0\u05d9 \u05d9\u05d5\u05d3\u05e2 \u05db\u05d9\u05e6\u05d3 \u05de\u05d3\u05dc\u05d9\u05e7\u05d9\u05dd \u05d0\u05ea \u05d4\u05d0\u05e9, \u05d0\u05d9\u05e0\u05d9 \u05d9\u05d5\u05d3\u05e2 \u05d0\u05ea \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4, \u05d0\u05d1\u05dc \u05d9\u05db\u05d5\u05dc \u05d0\u05e0\u05d9 \u05dc\u05de\u05e6\u05d5\u05d0 \u05d0\u05ea \u05d4\u05de\u05e7\u05d5\u05dd, \u05d5\u05e6\u05e8\u05d9\u05da \u05e9\u05d9\u05d4\u05d0 \u05d3\u05d9 \u05d1\u05db\u05da. \u05d5\u05d3\u05d9 \u05d4\u05d9\u05d4 \u05d1\u05db\u05da: \u05e9\u05d5\u05d1 \u05de\u05ea\u05e8\u05d7\u05e9 \u05d4\u05d9\u05d4 \u05e0\u05e1.\n\u05d5\u05d4\u05d2\u05d9\u05e2 \u05d6\u05de\u05e0\u05d5 \u05e9\u05dc \u05e8\u05d1\u05d9 \u05d9\u05e9\u05e8\u05d0\u05dc \u05de\u05e8\u05d5\u05d6\'\u05d9\u05df \u05dc\u05d1\u05d8\u05dc \u05d0\u05ea \u05d4\u05d2\u05d6\u05d9\u05e8\u05d4. \u05d9\u05d5\u05e9\u05d1 \u05d4\u05d9\u05d4 \u05d1\u05db\u05d5\u05e8\u05e1\u05ea\u05d5, \u05e8\u05d0\u05e9\u05d5 \u05e0\u05ea\u05d5\u05df \u05d1\u05d9\u05df \u05db\u05e4\u05d5\u05ea \u05d9\u05d3\u05d9\u05d5, \u05d5\u05de\u05e9\u05d9\u05d7 \u05e2\u05dd \u05d4\u05e7\u05d3\u05d5\u05e9  \u05d1\u05e8\u05d5\u05da \u05d4\u05d5\u05d0: \u05d0\u05d9\u05e0\u05d9 \u05d9\u05db\u05d5\u05dc \u05dc\u05d4\u05d3\u05dc\u05d9\u05e7 \u05d0\u05ea \u05d4\u05d0\u05e9, \u05d0\u05d9\u05e0\u05d9 \u05d9\u05d5\u05d3\u05e2 \u05d0\u05ea \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4, \u05d0\u05e3 \u05d0\u05d9\u05e0\u05d9 \u05d9\u05d5\u05d3\u05e2 \u05dc\u05de\u05e6\u05d5\u05d0 \u05d0\u05ea \u05d4\u05de\u05e7\u05d5\u05dd \u05d1\u05d9\u05e2\u05e8. \u05d0\u05d9\u05e0\u05d9 \u05d9\u05d5\u05d3\u05e2 \u05d0\u05dc\u05d0 \u05dc\u05e1\u05e4\u05e8 \u05e1\u05d9\u05e4\u05d5\u05e8 \u05d6\u05d4. \u05e6\u05e8\u05d9\u05da \u05e9\u05d9\u05d4\u05d9\u05d4 \u05d3\u05d9 \u05d1\u05db\u05da. \u05d5\u05d3\u05d9 \u05d4\u05d9\u05d4 \u05d1\u05db\u05da.\n(\u05de\u05ea\u05d5\u05da \u05d4\u05d4\u05e7\u05d3\u05de\u05d4 \u05dc\u05e1\u05e4\u05e8 "\u05e9\u05e2\u05e8\u05d9 \u05d4\u05d9\u05e2\u05e8" \u05de\u05d0\u05ea \u05d0\u05dc\u05d9 \u05d5\u05d9\u05d6\u05dc, \u05d1\u05d4\u05d5\u05e6\' \u05e2\u05dd \u05e2\u05d5\u05d1\u05d3)\n\u05d4\u05d4\u05ea\u05e8\u05d7\u05e9\u05d5\u05ea \u05d4\u05d0\u05de\u05d9\u05ea\u05d9\u05ea, \u05e7\u05d5\u05e8\u05d9\u05ea \u05d1\u05b0\u05bc\u05de\u05e7\u05d5\u05dd, \u05d1\u05de\u05e8\u05d7\u05d1, \u05e9\u05d9\u05e9 \u05d1\u05d5 \u05de\u05e4\u05d2\u05e9 \u05d0\u05de\u05d9\u05ea\u05d9 \u05e9\u05dc \u05de\u05d5\u05e8\u05d4 \u05d5\u05ea\u05dc\u05de\u05d9\u05d3\u05d9\u05dd, \u05e9\u05dc \u05dc\u05d9\u05de\u05d5\u05d3 \u05de\u05e9\u05d5\u05ea\u05e3, \u05d5\u05d3\u05d9\u05d1\u05d5\u05e8 \u05e4\u05e0\u05d9\u05de\u05d9,\n\u05e9\u05dd \u05e0\u05de\u05e6\u05d0 \u05d4\u05d9\u05e2\u05e8 \u05e6\u05d5\u05e4\u05df \u05d4\u05e1\u05d5\u05d3\u05d5\u05ea,\n\u05e9\u05dd \u05e0\u05d9\u05ea\u05df \u05dc\u05d4\u05d3\u05dc\u05d9\u05e7 \u05d0\u05ea \u05d4\u05d0\u05e9, \u05dc\u05d2\u05dc\u05d5\u05ea \u05d0\u05d5\u05e8\u05d5\u05ea \u05d1\u05dc\u05d9\u05de\u05d5\u05d3, \u05dc\u05d4\u05e6\u05d9\u05ea \u05e0\u05d9\u05e6\u05d5\u05e6\u05d5\u05ea \u05d1\u05dc\u05d1\u05d1\u05d5\u05ea.\n\u05db\u05d0\u05df \u05d1\u05d1\u05dc\u05d5\u05d2, \u05d0\u05e0\u05d5 \u05d9\u05d5\u05d3\u05e2\u05d9\u05dd \u05e9\u05d6\u05d4\u05d5 \u05d0\u05d9\u05e0\u05d5 \u05d4\u05d9\u05e2\u05e8, \u05d5\u05d0\u05d9\u05e0\u05e0\u05d5 \u05d9\u05db\u05d5\u05dc\u05d9\u05dd \u05dc\u05d4\u05d3\u05dc\u05d9\u05e7 \u05db\u05d0\u05df \u05d0\u05ea \u05d4\u05d0\u05e9,\n\u05d0\u05d1\u05dc \u05d0\u05e0\u05d5 \u05d9\u05db\u05d5\u05dc\u05d9\u05dd \u05dc\u05e1\u05e4\u05e8 \u05d0\u05ea \u05d4\u05e1\u05d9\u05e4\u05d5\u05e8,\n\u05e2\u05dc \u05d4\u05d0\u05e9 \u05d4\u05d3\u05d5\u05dc\u05e7\u05ea \u05d1\u05d9\u05e2\u05e8\n\u05e2\u05dc \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d4\u05e0\u05d9\u05e9\u05d0\u05ea \u05d1\u05dc\u05d1\u05d1\u05d5\u05ea\n\u05d5\u05d2\u05dd \u05d6\u05d4 \u05d3\u05d1\u05e8 \u05d2\u05d3\u05d5\u05dc\u2026\n\u05ea\u05d5\u05d3\u05e2\u05d4 \u05d0\u05dc\u05d5\u05e7\u05d9\u05ea: \u05d1\u05d9\u05d8\u05d7\u05d5\u05df \u05d5\u05d0\u05de\u05d5\u05e0\u05d4\n\u05e7\u05e8\u05d9\u05d0\u05ea \u05d4\u05e4\u05e1\u05d5\u05e7\u05d9\u05dd \u05de\u05e2\u05de\u05d9\u05e7\u05d4 \u05d0\u05ea \u05d4\u05d0\u05de\u05d5\u05e0\u05d4 \u05e9\u05d0\u05e0\u05d5 \u05de\u05e6\u05d5\u05d9\u05d9\u05dd \u05d1\u05e4\u05d9\u05e7\u05d5\u05d7\u05d5 \u05d4\u05d0\u05d5\u05d4\u05d1 \u05d5\u05d4\u05de\u05d2\u05df \u05e9\u05dc \u05db\u05d5\u05d7 \u05e2\u05dc\u05d9\u05d5\u05df, \u05d4\u05de\u05e1\u05d5\u05d2\u05dc \u05dc\u05ea\u05e7\u05df \u05d0\u05ea \u05d4\u05e2\u05d5\u05dc\u05dd \u05d5\u05dc\u05d4\u05d9\u05d8\u05d9\u05d1 \u05e2\u05de\u05e0\u05d5. \u05de\u05ea\u05d5\u05da \u05ea\u05d7\u05d5\u05e9\u05ea \u05d4\u05d1\u05d9\u05d8\u05d7\u05d5\u05df \u05d4\u05d6\u05d5, \u05d0\u05e0\u05d5 \u05e0\u05d9\u05d2\u05e9\u05d9\u05dd \u05dc\u05d9\u05d5\u05dd \u05d4\u05d7\u05d3\u05e9 \u05de\u05dc\u05d0\u05d9 \u05e2\u05d5\u05e6\u05de\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05d5\u05d0\u05de\u05d5\u05e0\u05d4.\n\u05d7\u05d9\u05d1\u05d5\u05e8 \u05d0\u05dc \u05d4\u05d1\u05d5\u05e8\u05d0 \u05d4\u05d7\u05d9\u05e6\u05d5\u05e0\u05d9 \u05d5\u05d4\u05e4\u05e0\u05d9\u05de\u05d9\n\u05e9\u05dd \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9\u05dd \u05d1\u05d9\u05d4\u05d3\u05d5\u05ea \u05de\u05d5\u05e8\u05db\u05d1 \u05de\u05e9\u05de\u05d5\u05ea \u05e8\u05d1\u05d9\u05dd.\n\u05db\u05dc \u05e9\u05dd \u05de\u05e1\u05de\u05dc \u05e6\u05d5\u05e8\u05ea \u05d4\u05ea\u05e7\u05e9\u05e8\u05d5\u05ea \u05d0\u05d7\u05e8\u05ea.\n\u05d0\u05da \u05d4\u05e9\u05dd \u05d4\u05de\u05e8\u05db\u05d6\u05d9 \u05d3\u05e8\u05db\u05d5 \u05d0\u05e0\u05d5 \u05e4\u05d5\u05e0\u05d9\u05dd \u05d0\u05dc \u05d4\u05d1\u05d5\u05e8\u05d0 \u05d4\u05d5\u05d0 \u05d9-\u05d4-\u05d5-\u05d4\n\u05d4\u05de\u05e1\u05de\u05dc \u05d0\u05ea \u05d4\u05e7\u05e9\u05e8 \u05d4\u05d3\u05d5 \u05e1\u05ea\u05e8\u05d9 \u05d1\u05d9\u05e0\u05e0\u05d5 \u05dc\u05d1\u05d9\u05df \u05d4\u05d1\u05d5\u05e8\u05d0.\n\u05d4\u05d0\u05d5\u05ea\u05d9\u05d5\u05ea \u05d9\u05d4 \u05e9\u05dc \u05ea\u05d7\u05d9\u05dc\u05ea \u05d4\u05e9\u05dd \u05d4\u05e7\u05d3\u05d5\u05e9 \u05de\u05e1\u05de\u05dc\u05d5\u05ea \u05d0\u05ea \u05d0\u05ea \u05d9\u05d3 \u05d4\u05d1\u05d5\u05e8\u05d0 \u05d1\u05de\u05e6\u05d9\u05d0\u05d5\u05ea. \u05d4\u05d0\u05d5\u05ea\u05d9\u05d5\u05ea \u05d1\u05e1\u05d5\u05e3 \u05d5\u05d4 \u05de\u05e1\u05de\u05dc\u05d5\u05ea \u05d0\u05ea \u05d4\u05e6\u05d9\u05e4\u05d9\u05d9\u05d4 \u05e9\u05dc \u05d4\u05d1\u05d5\u05e8\u05d0 \u05de\u05d0\u05d9\u05ea\u05e0\u05d5 \u05dc\u05e7\u05d7\u05ea \u05d7\u05dc\u05e7 \u05d1\u05d1\u05e8\u05d9\u05d0\u05ea \u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea\n\u05d4\u05d1\u05d5\u05e8\u05d0 \u05d4\u05d7\u05d9\u05e6\u05d5\u05e0\u05d9:\n\u05d6\u05d5\u05d4\u05d9 \u05d4\u05ea\u05d7\u05d5\u05e9\u05d4 \u05e9\u05d0\u05e0\u05d5 \u05e2\u05d8\u05d5\u05e4\u05d9\u05dd \u05d1\u05d0\u05d5\u05e8 \u05d0\u05d9\u05e0\u05e1\u05d5\u05e4\u05d9, \u05d4\u05de\u05e2\u05d5\u05e8\u05e8 \u05d1\u05e0\u05d5 \u05d0\u05de\u05d5\u05e0\u05d4 \u05db\u05d9 \u05d0\u05e4\u05e9\u05e8\u05d5\u05d9\u05d5\u05ea \u05d7\u05d9\u05d5\u05d1\u05d9\u05d5\u05ea \u05d1\u05dc\u05ea\u05d9 \u05de\u05d5\u05d2\u05d1\u05dc\u05d5\u05ea \u05d6\u05de\u05d9\u05e0\u05d5\u05ea \u05dc\u05e0\u05d5.\n\u05d4\u05d1\u05d5\u05e8\u05d0 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9:\n\u05d6\u05d5 \u05d4\u05ea\u05d5\u05d1\u05e0\u05d4 \u05db\u05d9 \u05d0\u05e0\u05d5 \u05e2\u05e6\u05de\u05e0\u05d5 \u05d1\u05e2\u05dc\u05d9 \u05d9\u05db\u05d5\u05dc\u05ea \u05d5\u05db\u05d5\u05d7, \u05de\u05e9\u05d5\u05dd \u05e9\u05d0\u05e0\u05d5 \u05de\u05d7\u05d5\u05d1\u05e8\u05d9\u05dd \u05dc\u05d1\u05e8\u05d9\u05d0\u05d4 \u05de\u05de\u05e7\u05d5\u05dd \u05e2\u05de\u05d5\u05e7 \u05d5\u05d9\u05e6\u05d9\u05d1.\n\u05d3\u05d9\u05d1\u05d5\u05e8 \u05de\u05d4\u05dc\u05d1 - \u05dc\u05d9\u05de\u05d5\u05d3 \u05de\u05e8\u05d1\u05d9 \u05dc\u05d5\u05d9 \u05d9\u05e6\u05d7\u05e7 \u05de\u05d1\u05e8\u05d3\u05d9\u05e6\u05d1\n\u05d9\u05d7\u05d3 \u05e2\u05dd \u05db\u05dc \u05d4\u05d7\u05e9\u05d9\u05d1\u05d5\u05ea \u05e9\u05dc \u05e7\u05d1\u05dc\u05ea \u05d4\u05d4\u05e9\u05e8\u05d0\u05d4 \u05d5\u05d4\u05ea\u05d6\u05db\u05d5\u05e8\u05ea \u05de\u05d4\u05e1\u05d9\u05d3\u05d5\u05e8 \u05dc\u05d4\u05ea\u05e4\u05dc\u05dc \u05e2\u05dc \u05db\u05dc \u05de\u05d4 \u05e9\u05d7\u05e9\u05d5\u05d1, \u05dc\u05d0 \u05e4\u05d7\u05d5\u05ea \u05d7\u05e9\u05d5\u05d1 \u05d4\u05d3\u05d9\u05d1\u05d5\u05e8 \u05de\u05d4\u05dc\u05d1.\n\u05e8\u05d1\u05d9 \u05dc\u05d5\u05d9 \u05d9\u05e6\u05d7\u05e7 \u05db\u05de\u05d5 \u05d2\u05dd \u05d4\u05d1\u05e2\u05e9"\u05d8, \u05e8\u05d1\u05d9 \u05e0\u05d7\u05de\u05df, \u05e8\u05d1\u05d9 \u05d6\u05d5\u05e9\u05d0 \u05d5\u05e2\u05d5\u05d3 \u05d4\u05e8\u05d1\u05d5 \u05dc\u05d3\u05d1\u05e8 \u05e2\u05dc \u05db\u05da.\n\u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05d6\u05d4 \u05d0\u05e4\u05d9\u05dc\u05d5 \u05e0\u05e9\u05de\u05e2 \u05d4\u05d7\u05d5\u05e6\u05e4\u05d4. \u05d5\u05e8\u05d1\u05d9 \u05e0\u05d7\u05de\u05df \u05d2\u05dd \u05d4\u05e1\u05d1\u05d9\u05e8 \u05d0\u05ea \u05e8\u05e2\u05d9\u05d5\u05df \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d1\u05de\u05d4\u05d5\u05ea\u05d4 \u05db\u05d7\u05d5\u05e6\u05e4\u05d4. \u05e8\u05e7 \u05d4\u05d5\u05d0 \u05e7\u05d9\u05d3\u05e9 \u05d0\u05ea \u05d7\u05d5\u05e6\u05e4\u05ea \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d1\u05e7\u05d5\u05e8\u05d0\u05d5 \u05dc\u05d4 \u05d7\u05d5\u05e6\u05e4\u05d4 \u05e7\u05d3\u05d5\u05e9\u05d4. \u05d0\u05d5 \u05e2\u05d6\u05d5\u05ea \u05d3\u05e7\u05d3\u05d5\u05e9\u05d4.\n\u05d4\u05e1\u05d9\u05e4\u05d5\u05e8 \u05d4\u05d1\u05d0 \u05e9\u05dc \u05e8\u05d1\u05d9 \u05dc\u05d5\u05d9 \u05d9\u05e6\u05d7\u05e7 \u05de\u05de\u05d7\u05d9\u05e9 \u05d0\u05ea \u05d4\u05e2\u05e0\u05d9\u05d9\u05df\n\u05d1\u05ea\u05e4\u05d9\u05dc\u05d5\u05ea \u05d4\u05d9\u05de\u05d9\u05dd \u05d4\u05e0\u05d5\u05e8\u05d0\u05d9\u05dd \u05e0\u05d4\u05d2 \u05e8\u05d1\u05d9 \u05dc\u05d5\u05d9 \u05d9\u05e6\u05d7\u05e7 \u05de\u05d1\u05e8\u05d3\u05d9\u05d8\u05e9\u05d5\u05d1 \u05dc\u05e9\u05de\u05e9 \u05d7\u05d6\u05df \u05d4\u05e2\u05d5\u05d1\u05e8 \u05dc\u05e4\u05e0\u05d9 \u05d4\u05ea\u05d9\u05d1\u05d4 \u05db\u05d1\u05e2\u05dc \u05ea\u05e4\u05d9\u05dc\u05d4. \u05d1\u05d6\u05de\u05e0\u05d9\u05dd \u05d0\u05dc\u05d4 \u05e0\u05d4\u05d2 \u05dc\u05d4\u05d5\u05e1\u05d9\u05e3 \u05d0\u05dc \u05d4\u05ea\u05e4\u05d9\u05dc\u05d5\u05ea \u05e9\u05d1\u05e1\u05d9\u05d3\u05d5\u05e8 \u05de\u05d9\u05dc\u05d9\u05dd \u05e9\u05d7\u05d9\u05d1\u05e8 \u05d5\u05e9\u05e8 \u05d1\u05e0\u05e2\u05d9\u05de\u05d4. \u05d1\u05de\u05d9\u05dc\u05d9\u05dd \u05d0\u05dc\u05d4 \u05d1\u05d9\u05e7\u05e9 \u05de\u05d7\u05d9\u05dc\u05d4 \u05d1\u05e2\u05d1\u05d5\u05e8 \u05d4\u05e6\u05d9\u05d1\u05d5\u05e8, \u05d5\u05d0\u05e3 \u05d4\u05ea\u05d5\u05d5\u05db\u05d7 \u05e2\u05dd \u05d0\u05dc\u05d5\u05d4\u05d9\u05dd \u05d5\u05ea\u05d1\u05e2 \u05e6\u05d3\u05e7 \u05d5\u05e9\u05d9\u05e0\u05d5\u05d9 \u05dc\u05d8\u05d5\u05d1\u05d4.\n\u05d1\u05d9\u05de\u05d9 \u05de\u05dc\u05d7\u05de\u05ea \u05d4\u05e2\u05d5\u05dc\u05dd \u05d4\u05e8\u05d0\u05e9\u05d5\u05e0\u05d4, \u05e9\u05e0\u05d9\u05dd \u05e8\u05d1\u05d5\u05ea \u05d0\u05d7\u05e8\u05d9 \u05de\u05d5\u05ea\u05d5 \u05e9\u05dc \u05e8\' \u05dc\u05d5\u05d9 \u05d9\u05e6\u05d7\u05e7, \u05e9\u05e8\u05d5 \u05de\u05d5\u05d6\u05d9\u05e7\u05d0\u05d9\u05dd \u05d9\u05d4\u05d5\u05d3\u05d9\u05dd \u05d0\u05ea \u05de\u05d9\u05dc\u05d5\u05ea\u05d9\u05d5 \u05e9\u05dc \u05d4\u05e8\u05d1\u05d9, \u05d5\u05d4\u05d6\u05db\u05d9\u05e8\u05d5 \u05d0\u05ea \u05d4\u05d0\u05d5\u05de\u05d5\u05ea \u05d4\u05de\u05ea\u05e0\u05e6\u05d7\u05d5\u05ea \u05d1\u05de\u05dc\u05d7\u05de\u05d4. \u05d9\u05e6\u05d9\u05e8\u05ea\u05dd \u05e0\u05d2\u05e2\u05d4 \u05d1\u05dc\u05d1\u05dd \u05e9\u05dc \u05e8\u05d1\u05d9\u05dd \u05d1\u05d3\u05d5\u05e8\u05d5\u05ea \u05d4\u05d0\u05d7\u05e8\u05d5\u05e0\u05d9\u05dd, \u05d5\u05db\u05da \u05d4\u05dd \u05e9\u05e8\u05d5:\n\u05d8\u05d0\u05d8\u05e2\u05e0\u05d9\u05d5! \u05d0\u05d1\u05d0\u05dc\'\u05d4\n\u05db\u05de\u05d4 \u05d0\u05d5\u05de\u05d5\u05ea \u05d9\u05e9 \u05d1\u05e2\u05d5\u05dc\u05dd!\n\u05e4\u05e8\u05e1\u05d9\u05dd, \u05d1\u05d1\u05dc\u05d9\u05dd, \u05d0\u05d3\u05d5\u05de\u05d9\u05dd.\n\u05d1\u05d5\u05e7\u05e8 \u05d8\u05d5\u05d1 \u05dc\u05da, \u05e8\u05d9\u05d1\u05d5\u05e0\u05d5 \u05e9\u05dc \u05e2\u05d5\u05dc\u05dd!\n\u05d0\u05e0\u05d9, \u05dc\u05d5\u05d9 \u05d9\u05e6\u05d7\u05e7 \u05d1\u05df \u05e9\u05e8\u05d4 \u05de\u05d1\u05e8\u05d3\u05d9\u05d8\u05e9\u05d5\u05d1\n\u05d1\u05d0\u05ea\u05d9 \u05d0\u05dc\u05d9\u05da \u05d1\u05d3\u05d9\u05df \u05ea\u05d5\u05e8\u05d4\n\u05d1\u05e2\u05d1\u05d5\u05e8 \u05e2\u05dd \u05d9\u05e9\u05e8\u05d0\u05dc \u05e9\u05dc\u05da.\n\u05de\u05d3\u05d5\u05e2 \u05e0\u05d8\u05e4\u05dc\u05ea \u05d3\u05d5\u05d5\u05e7\u05d0 \u05dc\u05e2\u05de\u05da \u05d9\u05e9\u05e8\u05d0\u05dc!\n\u05e8\u05e7 \u05e6\u05e8\u05d9\u05da \u05de\u05e9\u05d4\u05d5, \u05de\u05d9\u05d3 \u2013 "\u05d0\u05b1\u05de\u05b9\u05e8 \u05d0\u05b6\u05dc \u05d1\u05bc\u05b0\u05e0\u05b5\u05d9 \u05d9\u05b4\u05e9\u05c2\u05b0\u05e8\u05b8\u05d0\u05b5\u05dc."\n\u05e9\u05d5\u05d1 \u05e7\u05e8\u05d4 \u05d3\u05d1\u05e8 \u05de\u05d4 \u2013 "\u05e6\u05b7\u05d5 \u05d0\u05b6\u05ea \u05d1\u05bc\u05b0\u05e0\u05b5\u05d9 \u05d9\u05b4\u05e9\u05c2\u05b0\u05e8\u05b8\u05d0\u05b5\u05dc."\n\u05d5\u05e9\u05d5\u05d1 \u2013 "\u05d3\u05bc\u05b7\u05d1\u05bc\u05b5\u05e8 \u05d0\u05b6\u05dc \u05d1\u05bc\u05b0\u05e0\u05b5\u05d9 \u05d9\u05b4\u05e9\u05c2\u05b0\u05e8\u05b8\u05d0\u05b5\u05dc."\n\u05d0\u05d1\u05d0\'\u05dc\u05d4!\n\u05db\u05de\u05d4 \u05d0\u05d5\u05de\u05d5\u05ea \u05d9\u05e9 \u05d1\u05e2\u05d5\u05dc\u05dd!\n\u05e4\u05e8\u05e1\u05d9\u05dd, \u05d1\u05d1\u05dc\u05d9\u05dd, \u05d0\u05d3\u05d5\u05de\u05d9\u05dd.\n\u05e8\u05d5\u05e1\u05d9\u05dd, \u05d2\u05e8\u05de\u05e0\u05d9\u05dd, \u05d0\u05e0\u05d2\u05dc\u05d9\u05dd.\n\u05d4\u05e8\u05d5\u05e1\u05d9\u05dd, \u05de\u05d4 \u05d0\u05d5\u05de\u05e8\u05d9\u05dd?\n"\u05d4\u05e7\u05d9\u05e1\u05e8 \u05e9\u05dc\u05e0\u05d5 \u05e7\u05d9\u05e1\u05e8 \u05d4\u05d5\u05d0!"\n\u05d4\u05d2\u05e8\u05de\u05e0\u05d9\u05dd, \u05de\u05d4 \u05d0\u05d5\u05de\u05e8\u05d9\u05dd \u05d4\u05dd?\n"\u05d4\u05de\u05dc\u05da \u05e9\u05dc\u05e0\u05d5 \u05d4\u05d5\u05d0 \u05de\u05dc\u05da!"\n\u05d4\u05d0\u05e0\u05d2\u05dc\u05d9\u05dd, \u05de\u05d4 \u05d4\u05dd \u05d0\u05d5\u05de\u05e8\u05d9\u05dd?\n"\u05d4\u05de\u05dc\u05db\u05d5\u05ea \u05e9\u05dc\u05e0\u05d5 \u05d4\u05d9\u05d0 \u05de\u05dc\u05db\u05d5\u05ea!"\n\u05d0\u05da \u05d0\u05e0\u05d9, \u05dc\u05d5\u05d9 \u05d9\u05e6\u05d7\u05e7 \u05d1\u05df \u05e9\u05e8\u05d4 \u05de\u05d1\u05e8\u05d3\u05d9\u05e6\'\u05d1 \u05d0\u05d5\u05de\u05e8:\n"\u05d9\u05b4\u05ea\u05b0\u05d2\u05bc\u05b7\u05d3\u05bc\u05b7\u05dc \u05d5\u05b0\u05d9\u05b4\u05ea\u05b0\u05e7\u05b7\u05d3\u05bc\u05b7\u05e9\u05c1 \u05e9\u05c1\u05b0\u05de\u05b5\u05d4\u05bc \u05e8\u05b7\u05d1\u05bc\u05b8\u05d0!"\n\u05d0\u05e0\u05d9, \u05dc\u05f1-\u05d9\u05e6\u05d7\u05e7 \u05d1\u05df-\ufb2b\u05e8\u05d4 \u05de\u05d1\u05e8\u05d3\u05d9\u05e6\'\u05d1 \u05d0\u05d5\u05de\u05e8\u05c3\n"\u05d9\u05b4\u05ea\u05b0\u05d2\u05bc\u05b7\u05d3\u05bc\u05b7\u05dc \u05d5\u05b0\u05d9\u05b4\u05ea\u05b0\u05e7\u05b7\u05d3\u05bc\u05b7\u05e9\u05c1 \u05e9\u05c1\u05b0\u05de\u05b5\u05d4\u05bc \u05e8\u05b7\u05d1\u05bc\u05b8\u05d0!"\u200f\n\u05d0\u05e0\u05d9, \u05dc\u05f1-\u05d9\u05e6\u05d7\u05e7 \u05d1\u05df-\ufb2b\u05e8\u05d4 \u05de\u05d1\u05e8\u05d3\u05d9\u05e6\u05d1, \u05d0\u05d5\u05de\u05e8\u05c3\n"\u05dc\u05d0 \u05d0\u05d6\u05d5\u05d6 \u05de\u05de\u05e7\u05d5\u05de\u05d9!\u200f\n\u05e2\u05d3 \u05e9\u05d9\u05b4\u05ea\u05b0\u05d2\u05bc\u05b7\u05d3\u05bc\u05b7\u05dc \u05d5\u05b0\u05d9\u05b4\u05ea\u05b0\u05e7\u05b7\u05d3\u05bc\u05b7\u05e9\u05c1 \u05e9\u05c1\u05b0\u05de\u05b5\u05d4\u05bc \u05e8\u05b7\u05d1\u05bc\u05b8\u05d0!"\u200f\n"\u05dc\u05d0 \u05d0\u05d6\u05d5\u05d6 \u05de\u05de\u05e7\u05d5\u05de\u05d9!\n\u05de\u05de\u05e7\u05d5\u05de\u05d9 \u05dc\u05d0 \u05d0\u05d6\u05d5\u05d6!\n\u05e2\u05d3 \u05e9\u05e1\u05d5\u05e3 \u05d9\u05d4\u05d9\u05d4 \u05dc\u05db\u05da!\n\u05e2\u05d3 \u05e9\u05e7\u05e5 \u05d9\u05d4\u05d9\u05d4 \u05dc\u05db\u05da!\n\u05e2\u05d3 \u05e9\u05d9\u05b4\u05ea\u05b0\u05d2\u05bc\u05b7\u05d3\u05bc\u05b7\u05dc \u05d5\u05b0\u05d9\u05b4\u05ea\u05b0\u05e7\u05b7\u05d3\u05bc\u05b7\u05e9\u05c1 \u05e9\u05c1\u05b0\u05de\u05b5\u05d4\u05bc \u05e8\u05b7\u05d1\u05bc\u05b8\u05d0!\n\u05d4\u05d3\u05d9\u05d1\u05d5\u05e8 \u05d4\u05d1\u05dc\u05ea\u05d9 \u05de\u05ea\u05e4\u05e9\u05e8 \u05e9\u05dc \u05e8\u05d1\u05d9 \u05dc\u05d5\u05d9 \u05de\u05dc\u05de\u05d3 \u05d0\u05d5\u05ea\u05e0\u05d5 \u05dc\u05d1\u05d5\u05d0 \u05e2\u05dd \u05db\u05dc \u05d4\u05dc\u05d1. \u05e2\u05dd \u05db\u05dc \u05d4\u05ea\u05e1\u05db\u05d5\u05dc, \u05e2\u05dd \u05db\u05dc \u05d4\u05db\u05e2\u05e1 \u05d5\u05dc\u05e2\u05d1\u05d3 \u05d0\u05d5\u05ea\u05d5 \u05de\u05d5\u05dc \u05e8\u05d9\u05d1\u05d5\u05e0\u05d5 \u05e9\u05dc \u05e2\u05d5\u05dc\u05dd. \u05dc\u05d0 \u05dc\u05e8\u05e7 \u05dc\u05d4\u05ea\u05d7\u05e0\u05d7\u05df \u05d5\u05dc\u05d4\u05ea\u05d9\u05e4\u05d9\u05e3 \u05d1\u05de\u05d9\u05dc\u05d9\u05dd \u05d9\u05e4\u05d5\u05ea \u05e9\u05dc \u05d4\u05dc\u05dc \u05e9\u05dc\u05e2\u05d9\u05ea\u05d9\u05dd \u05dc\u05d0 \u05de\u05d7\u05d5\u05d1\u05e8\u05d5\u05ea \u05dc\u05de\u05e6\u05d9\u05d0\u05d5\u05ea \u05d4\u05e8\u05d2\u05e9\u05d9\u05ea \u05e9\u05dc\u05e0\u05d5.\n\u05d3\u05d9\u05d1\u05d5\u05e8 \u05d6\u05d4 \u05de\u05d6\u05db\u05d9\u05e8 \u05d0\u05ea \u05d4\u05de\u05d9\u05dc\u05d9\u05dd \u05e9\u05dc \u05d3\u05d5\u05d3 \u05d4\u05de\u05dc\u05da \u05d9\u05e1\u05d5\u05e8 \u05d9\u05e1\u05e8\u05e0\u05d9 \u05d9\u05e4\u05d4 \u05d5\u05dc\u05de\u05d5\u05d5\u05ea \u05dc\u05d0 \u05e0\u05ea\u05e0\u05e0\u05d9.\n\u05d0\u05da \u05db\u05d9\u05e6\u05d3 \u05de\u05d2\u05d9\u05e2\u05d9\u05dd \u05e8\u05d2\u05e9\u05d9\u05ea \u05dc\u05de\u05e7\u05d5\u05dd \u05d0\u05d5\u05ea\u05e0\u05d8\u05d9 \u05e9\u05dc \u05d0\u05de\u05d9\u05e8\u05d4 \u05de\u05db\u05dc \u05d4\u05dc\u05d1 \u05e9\u05d0\u05db\u05df \u05d0\u05e0\u05d9 \u05e8\u05d5\u05d0\u05d4 \u05e9\u05d0\u05ea\u05d4 \u05d4\u05d5\u05d0 \u05d6\u05d4 \u05e9\u05d9\u05d9\u05e1\u05e8 \u05d0\u05d5\u05ea\u05d9 \u05d0\u05ea\u05d4 \u05d2\u05dd \u05d4\u05e6\u05dc\u05ea \u05d0\u05d5\u05ea\u05d9.\n\u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05e7\u05e9\u05d4 \u05dc\u05e0\u05d5 \u05dc\u05d4\u05ea\u05d7\u05d1\u05e8 \u05d0\u05dc \u05e8\u05d2\u05e2 \u05d4\u05d4\u05e6\u05dc\u05d4 \u05dc\u05dc\u05d0 \u05e2\u05d9\u05d1\u05d5\u05d3 \u05e8\u05d2\u05e9\u05d9 \u05de\u05d5\u05dc \u05e8\u05d9\u05d1\u05d5\u05e0\u05d5 \u05e9\u05dc \u05e2\u05d5\u05dc\u05dd \u05e9\u05dc \u05e8\u05d2\u05e2 \u05d4\u05d9\u05d9\u05e1\u05d5\u05e8\u05d9\u05dd.\n\u05d0\u05ea \u05d4\u05d9\u05d9\u05e1\u05d5\u05e8\u05d9\u05dd \u05d0\u05e0\u05d5 \u05e0\u05d5\u05d8\u05d9\u05dd \u05dc\u05e2\u05d1\u05d3 \u05de\u05d5\u05dc \u05d4\u05e4\u05e1\u05d9\u05db\u05d5\u05dc\u05d5\u05d2 \u05d0\u05d5 \u05d0\u05d3\u05dd \u05e7\u05e8\u05d5\u05d1.\n\u05d0\u05da \u05d7\u05e9\u05d5\u05d1 \u05dc\u05e2\u05d1\u05d5\u05d3 \u05d0\u05d5\u05ea\u05dd \u05d2\u05dd \u05de\u05d5\u05dc \u05e8\u05d9\u05d1\u05d5\u05e0\u05d5 \u05e9\u05dc \u05e2\u05d5\u05dc\u05dd.\n\u05d0\u05d7\u05e8\u05ea \u05d4\u05e0\u05ea\u05e7 \u05d4\u05ea\u05d5\u05d3\u05e2\u05ea\u05d9, \u05d4\u05e8\u05d2\u05e9\u05d9 \u05d5\u05d4\u05d0\u05de\u05d5\u05e0\u05d9 \u05d4\u05d5\u05d0 \u05db\u05de\u05e2\u05d8 \u05d1\u05dc\u05ea\u05d9 \u05e0\u05de\u05e0\u05e2.\n\u05d1\u05d3\u05d9\u05d5\u05e7 \u05db\u05de\u05d5 \u05e2\u05dd \u05d0\u05d3\u05dd \u05e7\u05e8\u05d5\u05d1 \u05e9\u05e4\u05d2\u05e2\u05e0\u05d5 \u05d0\u05d7\u05d3 \u05d1\u05e9\u05e0\u05d9 \u05d5\u05dc\u05d0 \u05d4\u05d9\u05ea\u05d4 \u05e9\u05d9\u05d7\u05ea \u05e2\u05d9\u05d1\u05d5\u05d3 \u05d5\u05de\u05d7\u05d9\u05dc\u05d4, \u05d4\u05d9\u05d7\u05e1\u05d9\u05dd \u05dc\u05d0 \u05d9\u05d5\u05db\u05dc\u05d5 \u05dc\u05d4\u05ea\u05d7\u05d9\u05dc \u05dc\u05d7\u05d6\u05d5\u05e8 \u05dc\u05e7\u05d3\u05de\u05d5\u05ea\u05dd \u05d0\u05d5 \u05dc\u05d4\u05e9\u05ea\u05e4\u05e8.\n\u05d4\u05e1\u05d5\u05d3 \u05d1\u05dc\u05d7\u05d9\u05d5\u05ea \u05d1\u05dc\u05d9 \u05dc\u05d4\u05d1\u05d9\u05df \u05d4\u05db\u05d5\u05dc\n\u05de\u05ea\u05d5\u05da \u05d4\u05e6\u05d5\u05e8\u05da \u05d4\u05d0\u05e0\u05d5\u05e9\u05d9 \u05d4\u05d1\u05e1\u05d9\u05e1\u05d9 \u05dc\u05d1\u05d4\u05d9\u05e8\u05d5\u05ea \u05d5\u05dc\u05e9\u05dc\u05d9\u05d8\u05d4 \u05d0\u05e0\u05d7\u05e0\u05d5 \u05dc\u05e2\u05d9\u05ea\u05d9\u05dd \u05de\u05e0\u05e1\u05d9\u05dd \u05dc\u05e1\u05d3\u05e8 \u05d2\u05dd \u05d0\u05ea \u05d4\u05d4\u05d9\u05d1\u05d8 \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9. \u05d1\u05d5\u05e0\u05d9\u05dd \u05e9\u05d9\u05d8\u05d5\u05ea, \u05ea\u05e4\u05d9\u05e1\u05d5\u05ea, \u05db\u05dc\u05dc\u05d9\u05dd \u05d5\u05d8\u05e7\u05e1\u05d9\u05dd \u05db\u05d3\u05d9 \u05dc\u05d4\u05db\u05e0\u05d9\u05e1 \u05d0\u05ea \u05d7\u05d9\u05d9 \u05d4\u05e0\u05e4\u05e9 \u05d5\u05d4\u05d0\u05dc\u05d5\u05e7\u05d5\u05ea \u05d0\u05dc \u05ea\u05d5\u05da \u05de\u05e1\u05d2\u05e8\u05d5\u05ea \u05e9\u05e0\u05d5\u05db\u05dc \u05dc\u05d4\u05d1\u05d9\u05df \u05d5\u05dc\u05e9\u05dc\u05d5\u05d8 \u05d1\u05d4\u05df.\n\u05d0\u05e4\u05d9\u05dc\u05d5 \u05d0\u05ea \u05d0\u05dc\u05d5\u05d4\u05d9\u05dd \u05e2\u05e6\u05de\u05d5 \u05d0\u05e0\u05d7\u05e0\u05d5 \u05de\u05e6\u05de\u05e6\u05de\u05d9\u05dd \u05dc\u05de\u05e9\u05d5\u05d5\u05d0\u05d5\u05ea: \u05ea\u05e2\u05e9\u05d4 \u05d8\u05d5\u05d1 - \u05ea\u05e7\u05d1\u05dc \u05d8\u05d5\u05d1. \u05ea\u05ea\u05e8\u05d7\u05e7 \u05de\u05e8\u05e2 - \u05ea\u05d9\u05e0\u05e6\u05dc. \u05d0\u05e0\u05d5 \u05e8\u05d5\u05e6\u05d9\u05dd \u05dc\u05d4\u05d0\u05de\u05d9\u05df \u05db\u05d9 \u05db\u05dc \u05e8\u05e9\u05e2 \u05d9\u05d5\u05de\u05d5 \u05d9\u05d2\u05d9\u05e2 .\n\u05d0\u05d1\u05dc \u05dc\u05d3\u05e2\u05ea\u05d9 \u05d3\u05d5\u05d5\u05e7\u05d0 \u05d1\u05db\u05da \u05e9\u05d0\u05d9\u05e0\u05e0\u05d5 \u05d9\u05db\u05d5\u05dc\u05d9\u05dd \u05dc\u05d4\u05d1\u05d9\u05df \u05d0\u05ea \u05d0\u05dc\u05d5\u05d4\u05d9\u05dd \u05d8\u05de\u05d5\u05df \u05d9\u05d5\u05e4\u05d9\u05d5. \u05d3\u05d5\u05d5\u05e7\u05d0 \u05d1\u05d0\u05d9\u05e0\u05e1\u05d5\u05e4\u05d9\u05d5\u05ea, \u05d1\u05d7\u05d9\u05d3\u05d4, \u05d1\u05e1\u05d5\u05d3 - \u05e0\u05de\u05e6\u05d0\u05ea \u05d4\u05e7\u05d3\u05d5\u05e9\u05d4.\n\u05de\u05d4\u05d5 \u05e2\u05d9\u05d5\u05df \u05ea\u05e4\u05d9\u05dc\u05d4?\n\u05d0\u05dc\u05d5 \u05d3\u05d1\u05e8\u05d9\u05dd \u05e9\u05d0\u05d3\u05dd \u05d0\u05d5\u05db\u05dc \u05e4\u05e8\u05d5\u05ea\u05d9\u05d4\u05dd \u05d1\u05e2\u05d5\u05dc\u05dd \u05d4\u05d6\u05d4, \u05d5\u05d4\u05e7\u05e8\u05df \u05e7\u05d9\u05d9\u05de\u05ea \u05dc\u05d5 \u05dc\u05e2\u05d5\u05dc\u05dd \u05d4\u05d1\u05d0.\n\u05d5\u05d1\u05ea\u05d5\u05db\u05dd: \u05e2\u05d9\u05d5\u05df \u05ea\u05e4\u05d9\u05dc\u05d4 - \u05dc\u05d0 \u05d0\u05de\u05d9\u05e8\u05ea \u05de\u05d9\u05dc\u05d9\u05dd \u05de\u05ea\u05d5\u05da \u05d4\u05e8\u05d2\u05dc, \u05d0\u05dc\u05d0 \u05e2\u05de\u05d9\u05d3\u05d4 \u05de\u05d5\u05dc \u05d4\u05de\u05d9\u05dc\u05d4 \u05db\u05de\u05d5 \u05de\u05d5\u05dc \u05d7\u05dc\u05d5\u05df \u05e4\u05ea\u05d5\u05d7 \u05dc\u05e0\u05e9\u05de\u05d4.\n\u05d1\u05de\u05e1\u05d5\u05e8\u05ea \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9\u05ea, \u05de\u05d4 \u05e9\u05de\u05db\u05d5\u05e0\u05d4 \u05db\u05d9\u05d5\u05dd \u201c\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4\u201d \u05d4\u05d5\u05d0 \u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea \u05d0\u05d5 \u05d4\u05ea\u05d1\u05d5\u05d3\u05d3\u05d5\u05ea: \u05e8\u05d2\u05e2 \u05d1\u05d5 \u05d4\u05d0\u05d3\u05dd \u05de\u05ea\u05db\u05e0\u05e1 \u05d0\u05dc \u05e4\u05e0\u05d9\u05de\u05d9\u05d5\u05ea\u05d5, \u05de\u05e7\u05e9\u05d9\u05d1 \u05dc\u05e0\u05e9\u05d9\u05de\u05ea\u05d5, \u05d1\u05d5\u05d7\u05df \u05d0\u05ea \u05e2\u05d5\u05dc\u05de\u05d5 \u05d4\u05e8\u05d2\u05e9\u05d9, \u05d5\u05de\u05e0\u05d9\u05d7 \u05dc\u05de\u05d9\u05dc\u05d4 \u05d0\u05d7\u05ea \u05dc\u05d2\u05dc\u05d5\u05ea \u05dc\u05d5 \u05d0\u05ea \u05e2\u05e6\u05de\u05d5 \u05de\u05d7\u05d3\u05e9.\n\u05d4\u05de\u05d9\u05dc\u05d4 \u201c\u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea\u201d \u05de\u05e8\u05de\u05d6\u05ea \u05e2\u05dc \u201c\u05ea\u05d1\u05d5\u05e0\u05d4\u201d \u05d5\u05db\u05e4\u05d9 \u05e9\u05e0\u05d0\u05de\u05e8: \u201c\u05e8\u05d0\u05e9\u05d9\u05ea \u05d7\u05db\u05de\u05d4 \u05d9\u05e8\u05d0\u05ea \u05d4\u2019\u201d - \u05de\u05d9 \u05e9\u05de\u05ea\u05d1\u05d5\u05e0\u05df \u05d1\u05d0\u05de\u05ea, \u05d6\u05d5\u05db\u05d4 \u05dc\u05d4\u05d0\u05e8\u05d4 \u05e9\u05dc \u05d4\u05d1\u05e0\u05d4 \u05d7\u05d3\u05e9\u05d4.\n\u05d0\u05da \u05d4\u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea \u05d0\u05d9\u05e0\u05d4 \u05e8\u05e7 \u05de\u05d7\u05e9\u05d1\u05d4 \u05de\u05d5\u05e4\u05e9\u05d8\u05ea; \u05d4\u05d9\u05d0 \u05de\u05e4\u05d2\u05e9 \u05d7\u05d9 \u05e2\u05dd \u05d4\u05d2\u05d5\u05e3, \u05e2\u05dd \u05d4\u05e0\u05e9\u05d9\u05de\u05d4, \u05d5\u05e2\u05dd \u05d6\u05d9\u05db\u05e8\u05d5\u05e0\u05d5\u05ea \u05e9\u05de\u05d5\u05e0\u05d7\u05d9\u05dd \u05e2\u05de\u05d5\u05e7 \u05de\u05ea\u05d7\u05ea \u05dc\u05e4\u05e0\u05d9 \u05d4\u05e9\u05d8\u05d7.\n\u05dc\u05db\u05df, \u05d1\u05db\u05dc \u05e4\u05e2\u05dd \u05e9\u05d0\u05ea\u05dd \u05de\u05e2\u05d9\u05d9\u05e0\u05d9\u05dd \u05d1\u05de\u05d9\u05dc\u05d5\u05ea \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05e9\u05d0\u05dc\u05d5:\n\u05d0\u05d9\u05da \u05d4\u05de\u05d9\u05dc\u05d4 \u05e4\u05d5\u05d2\u05e9\u05ea \u05d0\u05d5\u05ea\u05d9 \u05e2\u05db\u05e9\u05d9\u05d5?\n\u2013 \u05d4\u05d0\u05dd \u05d4\u05d9\u05d0 \u05de\u05d9\u05d9\u05e6\u05e8\u05ea \u05e8\u05d2\u05e9 \u05d7\u05d9\u05d5\u05d1\u05d9, \u05d4\u05ea\u05e8\u05d7\u05d1\u05d5\u05ea, \u05d7\u05de\u05d9\u05de\u05d5\u05ea?\n\u2013 \u05d0\u05d5 \u05d0\u05d5\u05dc\u05d9 \u05d4\u05d9\u05d0 \u05de\u05e2\u05d5\u05e8\u05e8\u05ea \u05d0\u05d9\u05be\u05e0\u05d5\u05d7\u05d5\u05ea, \u05db\u05d9\u05d5\u05d5\u05e5 \u05e7\u05dc, \u05d6\u05d9\u05db\u05e8\u05d5\u05df \u05e9\u05de\u05d1\u05e7\u05e9 \u05de\u05e7\u05d5\u05dd?\n\u2013 \u05de\u05d4 \u05e7\u05d5\u05e8\u05d4 \u05d1\u05e0\u05e9\u05d9\u05de\u05d4? \u05d4\u05d0\u05dd \u05d4\u05d9\u05d0 \u05e0\u05e4\u05ea\u05d7\u05ea \u05d0\u05d5 \u05de\u05ea\u05e7\u05e6\u05e8\u05ea?\n\u2013 \u05d0\u05d9\u05dc\u05d5 \u05d0\u05e1\u05d5\u05e6\u05d9\u05d0\u05e6\u05d9\u05d5\u05ea \u05d4\u05de\u05d9\u05dc\u05d4 \u05de\u05e2\u05dc\u05d4? \u05de\u05d9 \u05de\u05d5\u05e4\u05d9\u05e2 \u05d1\u05ea\u05d5\u05d3\u05e2\u05d4? \u05d0\u05d9\u05d6\u05d5 \u05ea\u05de\u05d5\u05e0\u05d4? \u05d0\u05d9\u05d6\u05d5 \u05ea\u05d7\u05d5\u05e9\u05d4?\n\u05dc\u05e2\u05d9\u05ea\u05d9\u05dd \u05de\u05d9\u05dc\u05d4 \u05d0\u05d7\u05ea \u05d9\u05db\u05d5\u05dc\u05d4 \u05dc\u05e2\u05d5\u05e8\u05e8 \u05e9\u05dc\u05d5\u05d5\u05d4 \u05e2\u05de\u05d5\u05e7\u05d4, \u05d5\u05dc\u05e2\u05d9\u05ea\u05d9\u05dd \u05d3\u05d5\u05d5\u05e7\u05d0 \u05dc\u05e2\u05d5\u05e8\u05e8 \u05db\u05d0\u05d1 \u05d5\u05e9\u05e0\u05d9\u05d4\u05dd \u05de\u05d4\u05d5\u05d5\u05d9\u05dd \u05d7\u05dc\u05e7 \u05de\u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea \u05d0\u05de\u05d9\u05ea\u05d9\u05ea.\n\u05d4\u05e2\u05d9\u05e7\u05e8 \u05d4\u05d5\u05d0 \u05dc\u05d0 \u05dc\u05d1\u05e8\u05d5\u05d7. \u05dc\u05d0 \u05dc\u05d4\u05e1\u05d9\u05d7. \u05e8\u05e7 \u05dc\u05e8\u05d0\u05d5\u05ea. \u05e8\u05e7 \u05dc\u05d4\u05d9\u05d5\u05ea.\n\u05d0\u05e4\u05e9\u05e8 \u05dc\u05d4\u05e9\u05ea\u05de\u05e9 \u05d1\u05ea\u05e8\u05d2\u05d5\u05dc \u05e7\u05e6\u05e8:\n1. \u05d1\u05d7\u05e8\u05d5 \u05de\u05d9\u05dc\u05d4 \u05d0\u05d7\u05ea \u05de\u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05de\u05d9\u05dc\u05d4 \u05e9\u05de\u05d3\u05d1\u05e8\u05ea \u05d0\u05dc\u05d9\u05db\u05dd \u05d0\u05d5 \u05d3\u05d5\u05d5\u05e7\u05d0 \u05de\u05d0\u05ea\u05d2\u05e8\u05ea \u05d0\u05ea\u05db\u05dd.\n2. \u05d0\u05de\u05e8\u05d5 \u05d0\u05d5\u05ea\u05d4 \u05d1\u05e7\u05d5\u05dc \u05d0\u05d5 \u05d1\u05dc\u05d1, \u05d1\u05e0\u05e9\u05d9\u05de\u05d4 \u05d0\u05d9\u05d8\u05d9\u05ea. \u05d0\u05de\u05d9\u05e8\u05d4 \u05d1\u05e7\u05d5\u05dc \u05e2\u05d5\u05d6\u05e8\u05ea \u05dc\u05d4\u05ea\u05d1\u05d5\u05e0\u05df \u05d1\u05e7\u05e6\u05d1 \u05d4\u05e0\u05e9\u05d9\u05de\u05d4 \u05db\u05d3\u05d9 \u05dc\u05d4\u05e2\u05e8\u05d9\u05da \u05d0\u05ea \u05de\u05e6\u05d1 \u05d4\u05e0\u05e9\u05d9\u05de\u05d4 \u05d5\u05db\u05da \u05dc\u05d4\u05d1\u05d9\u05df \u05d9\u05d5\u05ea\u05e8 \u05e2\u05dc \u05e8\u05de\u05ea \u05d4\u05e8\u05d2\u05d9\u05e2\u05d4 \u05e9\u05dc\u05db\u05dd. \u05de\u05e9\u05d9\u05db\u05ea \u05d4\u05d0\u05d5\u05ea\u05d9\u05d5\u05ea \u05d2\u05dd \u05e2\u05d5\u05d6\u05e8\u05ea \u05dc\u05d4\u05e1\u05d3\u05d9\u05e8 \u05e0\u05e9\u05d9\u05de\u05d4 \u05d1\u05d6\u05de\u05e0\u05d9\u05dd \u05e9\u05dc \u05d7\u05d5\u05e1\u05e8 \u05e9\u05dc\u05d5\u05d5\u05d4.\n3. \u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5 \u05d1\u05de\u05d4 \u05e9\u05e7\u05d5\u05e8\u05d4 \u05ea\u05d7\u05d5\u05e9\u05ea\u05d9\u05ea, \u05e8\u05d2\u05e9\u05d9\u05ea, \u05de\u05d7\u05e9\u05d1\u05ea\u05d9\u05ea.\n4. \u05ea\u05e0\u05d5 \u05dc\u05d0\u05e1\u05d5\u05e6\u05d9\u05d0\u05e6\u05d9\u05d5\u05ea \u05dc\u05e2\u05dc\u05d5\u05ea \u05d1\u05dc\u05d9 \u05e9\u05d9\u05e4\u05d5\u05d8.\n5. \u05e9\u05d0\u05dc\u05d5: \u201c\u05de\u05d4 \u05d4\u05de\u05d9\u05dc\u05d4 \u05d4\u05d6\u05d0\u05ea \u05de\u05d2\u05dc\u05d4 \u05dc\u05d9 \u05e2\u05dc \u05e2\u05e6\u05de\u05d9? \u05de\u05d4 \u05d4\u05d9\u05d0 \u05de\u05d1\u05e7\u05e9\u05ea \u05dc\u05e8\u05e4\u05d0 \u05d0\u05d5 \u05dc\u05d7\u05d6\u05e7 \u05d1\u05d9?\u201d\n\u05d5\u05db\u05d0\u05df \u05de\u05d2\u05d9\u05e2 \u05e9\u05dc\u05d1 \u05e0\u05d5\u05e1\u05e3:\n\u05de\u05e2\u05db\u05e9\u05d9\u05d5 \u05d1\u05db\u05dc \u05e4\u05e2\u05dd \u05e9\u05ea\u05e7\u05e8\u05d0\u05d5 \u05d0\u05ea \u05d4\u05d1\u05d9\u05d8\u05d5\u05d9 \u201c\u05e2\u05d9\u05d5\u05df \u05ea\u05e4\u05d9\u05dc\u05d4\u201d, \u05ea\u05e0\u05d5 \u05dc\u05d5 \u05dc\u05d4\u05e6\u05d9\u05ea \u05d1\u05ea\u05d5\u05db\u05db\u05dd \u05d0\u05ea \u05d4\u05d6\u05d9\u05db\u05e8\u05d5\u05df \u05d4\u05d6\u05d4:\n\u05d4\u05d6\u05d9\u05db\u05e8\u05d5\u05df \u05e9\u05dc \u05d4\u05de\u05d1\u05d8 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9, \u05e9\u05dc \u05d4\u05e0\u05e9\u05d9\u05de\u05d4 \u05d4\u05e8\u05db\u05d4, \u05e9\u05dc \u05d4\u05d4\u05e7\u05e9\u05d1\u05d4 \u05dc\u05de\u05d9\u05dc\u05d4 \u05d5\u05dc\u05de\u05d4 \u05e9\u05d4\u05d9\u05d0 \u05e2\u05d5\u05e9\u05d4 \u05d1\u05db\u05dd.\n\u05d4\u05d1\u05d9\u05d8\u05d5\u05d9 \u05e2\u05e6\u05de\u05d5 \u05d9\u05d4\u05e4\u05d5\u05da \u05dc\u05d0\u05d5\u05ea \u05e4\u05e0\u05d9\u05de\u05d9, \u05db\u05de\u05d5 \u05e0\u05e8 \u05e7\u05d8\u05df \u05e9\u05de\u05d6\u05db\u05d9\u05e8:\n\u05dc\u05d0 \u05dc\u05e8\u05d5\u05e5 \u05e2\u05dc \u05d0\u05d5\u05d8\u05d5\u05de\u05d8.\n\u05dc\u05d0 \u05dc\u05d5\u05de\u05e8 \u05de\u05d9\u05dc\u05d9\u05dd \u05e8\u05d9\u05e7\u05d5\u05ea.\n\u05d0\u05dc\u05d0 \u05dc\u05e2\u05e6\u05d5\u05e8 \u05d5\u05dc\u05d4\u05ea\u05d1\u05d5\u05e0\u05df.\n\u05db\u05da \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d4\u05d5\u05e4\u05db\u05ea \u05de\u05de\u05e1\u05d2\u05e8\u05ea \u05d8\u05e7\u05e1\u05d8\u05d5\u05d0\u05dc\u05d9\u05ea \u05dc\u05de\u05e1\u05e2 \u05e0\u05e4\u05e9\u05d9.\n\u05d5\u05db\u05da \u05d4\u05d0\u05d3\u05dd \u05d6\u05d5\u05db\u05d4 \u05dc\u05d0 \u05e8\u05e7 \u05dc\u05d4\u05ea\u05e2\u05dc\u05d5\u05ea \u05e8\u05d2\u05e2\u05d9\u05ea, \u05d0\u05dc\u05d0 \u05dc\u05e4\u05d9\u05e8\u05d5\u05ea \u05e9\u05dc \u05d1\u05d4\u05d9\u05e8\u05d5\u05ea, \u05e8\u05d9\u05e4\u05d5\u05d9 \u05d5\u05d7\u05db\u05de\u05d4 \u05db\u05d0\u05df \u05d5\u05e2\u05db\u05e9\u05d9\u05d5. \u05d5\u05d4\u05e7\u05e8\u05df \u05e7\u05d9\u05d9\u05de\u05ea \u05dc\u05e2\u05d5\u05dc\u05dd \u05d4\u05d1\u05d0 - \u05d4\u05ea\u05d5\u05d1\u05e0\u05d4 \u05d4\u05d7\u05d3\u05e9\u05d4 \u05ea\u05de\u05e9\u05d9\u05da \u05dc\u05dc\u05d5\u05d5\u05ea \u05d0\u05d5\u05ea\u05e0\u05d5 \u05d2\u05dd \u05d1\u05e2\u05ea\u05d9\u05d3. \u05db\u05da \u05d0\u05e0\u05d5 \u05de\u05ea\u05db\u05e0\u05ea\u05d9\u05dd \u05d0\u05ea \u05e2\u05e6\u05de\u05e0\u05d5 \u05dc\u05d7\u05d9\u05d5\u05ea \u05d7\u05d9\u05d9\u05dd \u05e8\u05d2\u05d5\u05e2\u05d9\u05dd \u05d5\u05ea\u05d1\u05d5\u05e0\u05d9\u05d9\u05dd.\n\ud83d\udcab \u05dc\u05d4\u05ea\u05d7\u05d9\u05dc \u05de\u05d7\u05d3\u05e9: \u05db\u05d5\u05d7\u05d5 \u05e9\u05dc \u05e7\u05e8\u05d1\u05df \u05d4\u05ea\u05de\u05d9\u05d3 \u05dc\u05d4\u05ea\u05e0\u05e7\u05d5\u05ea \u05d5\u05dc\u05e4\u05ea\u05d5\u05d7 \u05d3\u05e3 \u05d7\u05d3\u05e9\n\u05d0\u05d7\u05d3 \u05d4\u05e1\u05d5\u05d3\u05d5\u05ea \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9\u05d9\u05dd \u05d4\u05e4\u05d7\u05d5\u05ea \u05de\u05d3\u05d5\u05d1\u05e8\u05d9\u05dd \u05d1\u05e9\u05d7\u05e8\u05d9\u05ea, \u05d4\u05d5\u05d0 \u05d4\u05db\u05d5\u05d7 \u05d4\u05de\u05d8\u05d4\u05e8 \u05e9\u05dc \u05d1\u05e8\u05db\u05ea \u05e7\u05e8\u05d1\u05df \u05d4\u05ea\u05de\u05d9\u05d3. \u05d2\u05dd \u05db\u05d9\u05d5\u05dd, \u05db\u05e9\u05d0\u05d9\u05df \u05dc\u05e0\u05d5 \u05de\u05e7\u05d3\u05e9 \u05d5\u05d0\u05d9\u05df \u05dc\u05e0\u05d5 \u05de\u05d6\u05d1\u05d7, \u05d4\u05de\u05d9\u05dc\u05d9\u05dd \u05e2\u05e6\u05de\u05df, \u05de\u05ea\u05d5\u05da \u05db\u05d5\u05d5\u05e0\u05d4 \u05d5\u05ea\u05d5\u05d3\u05e2\u05d4 \u05e0\u05db\u05d5\u05e0\u05d4, \u05de\u05e9\u05de\u05e9\u05d5\u05ea \u05dc\u05e0\u05d5 \u05de\u05d6\u05d1\u05d7 \u05e4\u05e0\u05d9\u05de\u05d9 - \u05de\u05e7\u05d5\u05dd \u05d1\u05d5 \u05d0\u05e0\u05d5 \u05de\u05e7\u05e8\u05d9\u05d1\u05d9\u05dd \u05d0\u05ea \u05de\u05d4 \u05e9\u05db\u05d5\u05d1\u05dc \u05d0\u05d5\u05ea\u05e0\u05d5, \u05db\u05d3\u05d9 \u05e9\u05e0\u05d5\u05db\u05dc \u05dc\u05e6\u05d0\u05ea \u05dc\u05d7\u05d5\u05e4\u05e9\u05d9.\n\u05e7\u05e8\u05d1\u05df \u05d4\u05ea\u05de\u05d9\u05d3 \u05d4\u05d9\u05d4 \u05e7\u05e8\u05d1\u05df \u05e6\u05d9\u05d1\u05d5\u05e8 \u05e9\u05d4\u05d5\u05e7\u05e8\u05d1 \u05d1\u05db\u05dc \u05d1\u05d5\u05e7\u05e8 (\u05d5\u05d1\u05e2\u05e8\u05d1), \u05d5\u05d4\u05d5\u05d0 \u05e0\u05d7\u05e9\u05d1 \u05dc\u05d9\u05e1\u05d5\u05d3 \u05ea\u05de\u05d9\u05d3\u05d9 \u05d4\u05de\u05d7\u05d6\u05d9\u05e7 \u05d0\u05ea \u05d4\u05e7\u05e9\u05e8 \u05d4\u05d7\u05d9 \u05d1\u05d9\u05df \u05d4\u05e2\u05dd \u05dc\u05d1\u05d9\u05df \u05d0\u05dc\u05d5\u05d4\u05d9\u05d5. \u05d7\u05db\u05de\u05d9\u05dd \u05d0\u05de\u05e8\u05d5 \u05e2\u05dc\u05d9\u05d5: "\u05d4\u05ea\u05de\u05d9\u05d3 \u05e9\u05dc \u05d4\u05d1\u05d5\u05e7\u05e8 \u05de\u05db\u05e4\u05e8 \u05e2\u05dc \u05e2\u05d5\u05d5\u05e0\u05d5\u05ea \u05d4\u05dc\u05d9\u05dc\u05d4, \u05d5\u05ea\u05de\u05d9\u05d3 \u05e9\u05dc \u05d1\u05d9\u05df \u05d4\u05e2\u05e8\u05d1\u05d9\u05d9\u05dd \u05e2\u05dc \u05e2\u05d5\u05d5\u05e0\u05d5\u05ea \u05d4\u05d9\u05d5\u05dd".\n\u05db\u05d0\u05e9\u05e8 \u05d0\u05e0\u05d5 \u05d0\u05d5\u05de\u05e8\u05d9\u05dd \u05d1\u05d1\u05d5\u05e7\u05e8 \u05d0\u05ea \u05e1\u05d3\u05e8 \u05e7\u05e8\u05d1\u05e0\u05d5\u05ea, \u05d5\u05d1\u05ea\u05d5\u05db\u05dd \u05d0\u05ea \u05e4\u05e1\u05d5\u05e7\u05d9 \u05e7\u05e8\u05d1\u05df \u05d4\u05ea\u05de\u05d9\u05d3, \u05d0\u05e0\u05d7\u05e0\u05d5 \u05dc\u05d0 \u05e8\u05e7 \u05de\u05e9\u05d7\u05d6\u05e8\u05d9\u05dd \u05e4\u05e2\u05d5\u05dc\u05d4 \u05d4\u05d9\u05e1\u05d8\u05d5\u05e8\u05d9\u05ea, \u05d0\u05dc\u05d0 \u05e2\u05d5\u05e9\u05d9\u05dd \u05e4\u05e2\u05d5\u05dc\u05d4 \u05e0\u05e4\u05e9\u05d9\u05ea \u05e2\u05de\u05d5\u05e7\u05d4:\n\u05d0\u05e0\u05d5 \u05de\u05e9\u05d9\u05dc\u05d9\u05dd \u05de\u05e2\u05dc\u05d9\u05e0\u05d5 \u05d0\u05ea \u05d8\u05e2\u05d5\u05d9\u05d5\u05ea \u05d4\u05d0\u05ea\u05de\u05d5\u05dc, \u05ea\u05d7\u05d5\u05e9\u05d5\u05ea \u05d4\u05d0\u05e9\u05dd, \u05d4\u05db\u05d9\u05e9\u05dc\u05d5\u05e0\u05d5\u05ea, \u05d4\u05d4\u05d7\u05de\u05e6\u05d5\u05ea - \u05d5\u05de\u05e7\u05e8\u05d9\u05d1\u05d9\u05dd \u05d0\u05d5\u05ea\u05df.\n\u05dc\u05d0 \u05db\u05d4\u05dc\u05e7\u05d0\u05d4 \u05e2\u05e6\u05de\u05d9\u05ea  \u05d0\u05dc\u05d0 \u05db\u05de\u05e2\u05e9\u05d4 \u05e9\u05dc \u05e9\u05d7\u05e8\u05d5\u05e8:\n\u201c\u05d6\u05d4 \u05de\u05d4 \u05e9\u05d4\u05d9\u05d4. \u05d0\u05e0\u05d9 \u05de\u05d5\u05e1\u05e8 \u05d0\u05ea \u05d6\u05d4. \u05d0\u05e0\u05d9 \u05e4\u05d5\u05ea\u05d7 \u05d3\u05e3 \u05d7\u05d3\u05e9.\u201d\n\u2601\ufe0f \u05ea\u05d5\u05d3\u05e2\u05ea \u05d0\u05e9\u05de\u05d4 \u05d4\u05d9\u05d0 \u05dc\u05d0 \u05dc\u05e7\u05d9\u05d7\u05ea \u05d0\u05d7\u05e8\u05d9\u05d5\u05ea\n\u05dc\u05e2\u05d9\u05ea\u05d9\u05dd, \u05d3\u05d5\u05d5\u05e7\u05d0 \u05d0\u05e0\u05e9\u05d9\u05dd \u05e8\u05d5\u05d7\u05e0\u05d9\u05d9\u05dd, \u05e9\u05d5\u05d0\u05e4\u05d9 \u05d0\u05de\u05ea \u05d5\u05de\u05d5\u05e1\u05e8\u05d9\u05d5\u05ea, \u05e0\u05d5\u05e9\u05d0\u05d9\u05dd \u05e2\u05de\u05dd \u05e8\u05d2\u05e9\u05d5\u05ea \u05d0\u05e9\u05dd \u05e2\u05d3\u05d9\u05e0\u05d9\u05dd:\n\u2013 \u05e2\u05dc \u05db\u05da \u05e9\u05dc\u05d0 \u05e0\u05d4\u05d2\u05d5 \u05db\u05e8\u05d0\u05d5\u05d9\n\u2013 \u05e2\u05dc \u05e9\u05dc\u05d0 \u05d4\u05e7\u05e9\u05d9\u05d1\u05d5 \u05de\u05e1\u05e4\u05d9\u05e7\n\u2013 \u05e2\u05dc \u05db\u05e2\u05e1 \u05de\u05d9\u05d5\u05ea\u05e8\n\u2013 \u05e2\u05dc \u05de\u05d7\u05e9\u05d1\u05d4 \u05dc\u05d0 \u05e8\u05d0\u05d5\u05d9\u05d4\n\u2013 \u05e2\u05dc \u05d7\u05d5\u05e1\u05e8 \u05e9\u05dc\u05d9\u05d8\u05d4 \u05d0\u05d5 \u05d7\u05d5\u05e1\u05e8 \u05e0\u05d5\u05db\u05d7\u05d5\u05ea\n\u05d4\u05d1\u05e2\u05d9\u05d4 \u05d4\u05d9\u05d0 \u05e9\u05d4\u05d0\u05e9\u05de\u05d4 \u05dc\u05d0 \u05de\u05ea\u05e7\u05e0\u05ea \u05db\u05dc\u05d5\u05dd \u05d0\u05dc\u05d0 \u05dc\u05d4\u05e4\u05da.\u05d4\u05d9\u05d0 \u05de\u05e9\u05d0\u05d9\u05e8\u05d4 \u05d0\u05d5\u05ea\u05e0\u05d5 \u05ea\u05e7\u05d5\u05e2\u05d9\u05dd \u05d1\u05e2\u05d1\u05e8.\n\u05e4\u05e2\u05de\u05d9\u05d9\u05dd \u05d1\u05d9\u05d5\u05dd \u05d9\u05e9 \u05dc\u05e0\u05d5 \u05d4\u05d6\u05d3\u05de\u05e0\u05d5\u05ea \u05dc\u05d4\u05ea\u05d7\u05d9\u05dc \u05de\u05d7\u05d3\u05e9. \u05dc\u05d4\u05ea\u05e0\u05e7\u05d5\u05ea \u05de\u05ea\u05d7\u05d5\u05e9\u05ea \u05d0\u05e9\u05de\u05d4 \u05db\u05d3\u05d9 \u05e9\u05d9\u05d4\u05d9\u05d4 \u05dc\u05e0\u05d5 \u05db\u05d7 \u05dc\u05d4\u05de\u05e9\u05d9\u05da \u05d0\u05ea \u05de\u05e1\u05e2 \u05d4\u05d4\u05e9\u05ea\u05db\u05dc\u05dc\u05d5\u05ea \u05d4\u05dc\u05d0\u05d4. \u05ea\u05d5\u05d3\u05e2\u05ea \u05e7\u05e8\u05d1\u05df \u05d4\u05ea\u05de\u05d9\u05d3, \u05e9\u05de\u05d5 \u05de\u05e2\u05d9\u05d3 \u05e2\u05dc\u05d9\u05d5 - "\u05ea\u05de\u05d9\u05d3" - \u05d4\u05d5\u05d0 \u05d0\u05d5\u05de\u05e8:\n\u05d1\u05db\u05dc \u05d9\u05d5\u05dd \u05d9\u05e9 \u05dc\u05da \u05d4\u05d6\u05d3\u05de\u05e0\u05d5\u05ea \u05d7\u05d3\u05e9\u05d4.\n\u05d1\u05db\u05dc \u05d1\u05d5\u05e7\u05e8 \u05d0\u05e0\u05d5 \u05d0\u05d7\u05e8\u05d9\u05dd. \u05d4\u05e9\u05dd \u05e0\u05d5\u05ea\u05df \u05dc\u05da \u05d7\u05d9\u05d9\u05dd \u05d7\u05d3\u05e9\u05d9\u05dd - \u05ea\u05e0/\u05d9 \u05d2\u05dd \u05d0\u05ea(\u05d4 \u05dc\u05e2\u05e6\u05de\u05da \u05d7\u05d9\u05d9\u05dd \u05d7\u05d3\u05e9\u05d9\u05dd.\n\u05d4\u05e7\u05e8\u05d1\u05df \u05d4\u05e4\u05e0\u05d9\u05de\u05d9 \u05e9\u05dc\u05e0\u05d5 \u05d4\u05d5\u05d0 \u05d4\u05d4\u05e1\u05db\u05de\u05d4 \u05dc\u05d4\u05e0\u05d9\u05d7 \u05dc\u05de\u05d4 \u05e9\u05d4\u05d9\u05d4, \u05dc\u05d0 \u05d1\u05d1\u05e8\u05d9\u05d7\u05d4, \u05d0\u05dc\u05d0 \u05d1\u05d9\u05d3\u05d9\u05e2\u05d4 \u05e9\u05d0\u05dd \u05d0\u05e0\u05d9 \u05e0\u05d5\u05e9\u05d0 \u05db\u05d5\u05d5\u05e0\u05d4 \u05d8\u05d5\u05d1\u05d4 \u05d5\u05de\u05d5\u05db\u05df \u05dc\u05d4\u05ea\u05e7\u05d3\u05e9 \u05de\u05d7\u05d3\u05e9, \u05d0\u05d6 \u05d9\u05e9 \u05dc\u05d9 \u05de\u05e7\u05d5\u05dd \u05d7\u05d3\u05e9 \u05dc\u05d4\u05ea\u05d7\u05d9\u05dc \u05de\u05de\u05e0\u05d5.\n\u2728 \u05ea\u05e8\u05d2\u05d9\u05dc \u05d4\u05d8\u05de\u05e2\u05d4: \u05e7\u05e8\u05d1\u05df \u05d4\u05ea\u05de\u05d9\u05d3 \u05d4\u05d0\u05d9\u05e9\u05d9 \u05e9\u05dc\u05da\n\u05e9\u05d1/\u05d9 \u05d1\u05de\u05e7\u05d5\u05dd \u05e9\u05e7\u05d8. \u05e2\u05e6\u05d5\u05dd/\u05d9 \u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05d5\u05e0\u05e9\u05d5\u05dd/\u05d9 \u05e2\u05de\u05d5\u05e7.\n\u05d3\u05de\u05d9\u05d9\u05df/\u05d9 \u05de\u05d6\u05d1\u05d7 \u05e4\u05e0\u05d9\u05de\u05d9 \u05d1\u05ea\u05d5\u05da \u05d4\u05dc\u05d1 \u05e9\u05dc\u05da, \u05e9\u05de\u05d5\u05db\u05df \u05dc\u05dc\u05de\u05d5\u05d3 \u05de\u05d4\u05d8\u05e2\u05d5\u05d9\u05d5\u05ea \u05d5\u05d0\u05d6 \u05dc\u05e9\u05d7\u05e8\u05e8 \u05d0\u05ea \u05d4\u05db\u05d0\u05d1 \u05de\u05d4\u05df.\n\u05d7\u05e9\u05d5\u05d1/\u05d7\u05e9\u05d1\u05d9 \u05e2\u05dc \u05d3\u05d1\u05e8 \u05d0\u05d7\u05d3 \u05de\u05d4\u05d9\u05d5\u05dd \u05d0\u05d5 \u05de\u05d4\u05dc\u05d9\u05dc\u05d4 \u05d4\u05e7\u05d5\u05d3\u05dd \u05e9\u05d0\u05ea/\u05d4 \u05de\u05e8\u05d2\u05d9\u05e9/\u05d4 \u05d0\u05e9\u05de\u05d4 \u05e2\u05dc\u05d9\u05d5, \u05d0\u05db\u05d6\u05d1\u05d4 \u05d0\u05d5 \u05db\u05d1\u05d3\u05d5\u05ea.\n\u05d4\u05e6\u05e2/\u05d9 \u05d0\u05ea \u05d6\u05d4 \u05db\u05e7\u05e8\u05d1\u05df. \u05de\u05de\u05e9 \u05d0\u05de\u05d5\u05e8/\u05d9 \u05d1\u05dc\u05d1:\n"\u05e8\u05d9\u05d1\u05d5\u05e0\u05d5 \u05e9\u05dc \u05e2\u05d5\u05dc\u05dd, \u05d0\u05e0\u05d9 \u05e8\u05d5\u05e6\u05d4 \u05dc\u05d0 \u05dc\u05d7\u05d6\u05d5\u05e8 \u05e2\u05dc \u05d4\u05d8\u05e2\u05d5\u05ea \u05d4\u05d6\u05d5, \u05dc\u05dc\u05de\u05d5\u05d3 \u05de\u05de\u05e0\u05d4 \u05de\u05d4 \u05e9\u05d4\u05d9\u05d0 \u05d4\u05d9\u05d9\u05ea\u05d4 \u05e6\u05e8\u05d9\u05db\u05d4 \u05dc\u05dc\u05de\u05d3 \u05d0\u05d5\u05ea\u05d9 \u05d5\u05dc\u05e9\u05d7\u05e8\u05e8 \u05d0\u05ea \u05d4\u05ea\u05d7\u05d5\u05e9\u05d4 \u05d4\u05d6\u05d5. \u05d0\u05e0\u05d9 \u05de\u05d1\u05e7\u05e9/\u05ea \u05dc\u05e4\u05ea\u05d5\u05d7 \u05d0\u05ea \u05d4\u05d9\u05d5\u05dd \u05d4\u05d6\u05d4 \u05db\u05d3\u05e3 \u05d7\u05d3\u05e9. \u05d0\u05e0\u05d9 \u05d1\u05d5\u05d7\u05e8/\u05ea \u05d1\u05d7\u05d9\u05d9\u05dd."\n\u05e0\u05e9\u05d5\u05e3/\u05d9 \u05d4\u05d7\u05d5\u05e6\u05d4 \u05e2\u05de\u05d5\u05e7 \u05d5\u05e9\u05d7\u05e8\u05e8/\u05d9.\n\u05e4\u05ea\u05d7/\u05d9 \u05e2\u05d9\u05e0\u05d9\u05d9\u05dd. \u05d7\u05d9\u05d9\u05da/\u05d9 \u05dc\u05e2\u05e6\u05de\u05da. \u05e2\u05db\u05e9\u05d9\u05d5 \u05d0\u05ea/\u05d4 \u05e0\u05e7\u05d9/\u05d4. \u05d4\u05d9\u05d5\u05dd \u05d4\u05ea\u05d7\u05d9\u05dc.\n\u05db\u05da, \u05d1\u05db\u05dc \u05d1\u05d5\u05e7\u05e8, \u05d2\u05dd \u05d0\u05dd \u05d0\u05ea/\u05d4 \u05dc\u05d0 \u05d6\u05d5\u05db\u05e8/\u05ea \u05d0\u05ea \u05db\u05dc \u05d4\u05de\u05d9\u05dc\u05d9\u05dd \u05e9\u05dc \u05d4\u05e7\u05e8\u05d1\u05df \u05ea\u05d5\u05db\u05dc \u05dc\u05d6\u05db\u05d5\u05e8 \u05d0\u05ea \u05d4\u05db\u05d5\u05d5\u05e0\u05d4:\n\u05d0\u05e0\u05d9 \u05de\u05e7\u05e8\u05d9\u05d1 \u05d0\u05ea \u05d4\u05db\u05d0\u05d1 \u05e2\u05dc \u05d4\u05d8\u05e2\u05d5\u05d9\u05d5\u05ea \u05e9\u05dc\u05d9. \u05de\u05e2\u05db\u05e9\u05d9\u05d5 \u05d0\u05e0\u05d9 \u05e0\u05d5\u05dc\u05d3\u05ea\u05d9 \u05de\u05d7\u05d3\u05e9 \u05e2\u05dd \u05d4\u05ea\u05d5\u05d1\u05e0\u05d5\u05ea \u05e9\u05d4\u05d8\u05e2\u05d5\u05d9\u05d5\u05ea \u05d4\u05d1\u05d9\u05d0\u05d5 \u05dc\u05d7\u05d9\u05d9.\n\ud83d\udd4a\ufe0f \u05e9\u05d9\u05d4\u05d9\u05d4 \u05dc\u05da \u05d1\u05d5\u05e7\u05e8 \u05d8\u05d4\u05d5\u05e8 \u05d5\u05d9\u05d5\u05dd \u05d7\u05d3\u05e9, \u05de\u05dc\u05d0 \u05d0\u05d5\u05e8.\n\u05d9\u05e9\u05de\u05d7 \u05dc\u05d1 \u05de\u05d1\u05e7\u05e9\u05d9 \u05d4\'\n\u05d4\u05e4\u05e1\u05d5\u05e7 \u05d1\u05ea\u05d4\u05dc\u05d9\u05dd \u05d0\u05d5\u05de\u05e8: "\u05d9\u05e9\u05de\u05d7 \u05dc\u05d1 \u05de\u05d1\u05e7\u05e9\u05d9 \u05d4\', \u05d3\u05d9\u05e8\u05e9\u05d5 \u05d4\' \u05d5\u05e2\u05d5\u05d6\u05d5, \u05d1\u05e7\u05e9\u05d5 \u05e4\u05e0\u05d9\u05d5 \u05ea\u05de\u05d9\u05d3."\n\u05d1\u05de\u05d1\u05d8 \u05e8\u05d0\u05e9\u05d5\u05df \u05e0\u05d3\u05de\u05d4 \u05e9\u05d4\u05e4\u05e1\u05d5\u05e7 \u05de\u05d3\u05d1\u05e8 \u05e2\u05dc \u05de\u05e6\u05d9\u05d0\u05d5\u05ea \u05d0\u05d5\u05d1\u05d9\u05d9\u05e7\u05d8\u05d9\u05d1\u05d9\u05ea: \u05d9\u05e9 \u05d0\u05dc\u05d5\u05e7\u05d9\u05dd, \u05d9\u05e9 \u05d0\u05ea \u05e2\u05d5\u05d6\u05d5, \u05d9\u05e9 \u05d0\u05ea \u05e4\u05e0\u05d9\u05d5 \u05d5\u05de\u05d9 \u05e9\u05de\u05d1\u05e7\u05e9 \u05d0\u05d5\u05ea\u05dd, \u05e9\u05de\u05d7.\n\u05d0\u05da \u05d0\u05dd \u05e0\u05ea\u05d1\u05d5\u05e0\u05df \u05dc\u05e2\u05d5\u05de\u05e7, \u05d1\u05d0\u05d5\u05e8 \u05d4\u05d7\u05e1\u05d9\u05d3\u05d5\u05ea \u05e0\u05d2\u05dc\u05d4 \u05e9\u05d4\u05de\u05e8\u05db\u05d6 \u05d0\u05d9\u05e0\u05e0\u05d5 \u05d4\u05e9\u05d0\u05dc\u05d4 \u05d0\u05dd \u05d4\u05d0\u05dc\u05d5\u05e7\u05d5\u05ea \u05e7\u05d9\u05d9\u05de\u05ea \u05d0\u05d5 \u05dc\u05d0, \u05d0\u05dc\u05d0 \u05e2\u05e6\u05dd \u05ea\u05e0\u05d5\u05e2\u05ea \u05d4\u05dc\u05d1. \u05db\u05de\u05d4 \u05d4\u05d0\u05d3\u05dd \u05de\u05d1\u05e7\u05e9 \u05dc\u05d4\u05ea\u05d7\u05d1\u05e8 \u05d0\u05dc \u05e2\u05d5\u05dc\u05dd \u05e0\u05e9\u05d2\u05d1, \u05d0\u05dc \u05de\u05d9\u05de\u05d3 \u05d0\u05d7\u05e8 \u05db\u05da \u05d4\u05d5\u05d0 \u05de\u05ea\u05d2\u05dc\u05d4 \u05d0\u05dc\u05d9\u05d5 \u05d9\u05d5\u05ea\u05e8.\n"\u05d9\u05e9\u05de\u05d7 \u05dc\u05d1 \u05de\u05d1\u05e7\u05e9\u05d9 \u05d4\'" - \u05d4\u05e9\u05de\u05d7\u05d4 \u05d0\u05d9\u05e0\u05d4 \u05e4\u05d5\u05e2\u05dc \u05d9\u05d5\u05e6\u05d0 \u05e9\u05dc \u05d4\u05e9\u05d2\u05d4, \u05e9\u05dc \u05d4\u05d2\u05e2\u05d4 \u05dc\u05d9\u05e2\u05d3. \u05d4\u05d9\u05d0 \u05d0\u05d9\u05e0\u05e0\u05d4 \u05e9\u05de\u05d7\u05d4 \u05e9\u05dc \u05de\u05d9\u05e9\u05d4\u05d5 \u05e9\u05db\u05d1\u05e8 \u05d6\u05db\u05d4 \u05dc\u05e0\u05e1 \u05d0\u05d5 \u05dc\u05d2\u05d9\u05dc\u05d5\u05d9, \u05d0\u05dc\u05d0 \u05e9\u05dc \u05de\u05d9 \u05e9\u05e2\u05d3\u05d9\u05d9\u05df \u05de\u05d7\u05e4\u05e9. \u05e9\u05de\u05d7\u05ea \u05d4\u05d7\u05d9\u05e4\u05d5\u05e9.\n\u05d4\u05e9\u05de\u05d7\u05d4 \u05e0\u05d5\u05dc\u05d3\u05ea \u05de\u05e2\u05e6\u05dd \u05d4\u05d9\u05d5\u05ea\u05d9 \u05d0\u05d3\u05dd \u05e9\u05de\u05d1\u05e7\u05e9 \u05dc\u05d4\u05ea\u05e7\u05d3\u05dd. \u05d4\u05e2\u05d5\u05d1\u05d3\u05d4 \u05e9\u05d1\u05dc\u05d1 \u05e9\u05dc\u05d9 \u05e4\u05d5\u05e2\u05de\u05ea \u05e0\u05e7\u05d5\u05d3\u05ea \u05d2\u05e2\u05d2\u05d5\u05e2, \u05e8\u05e6\u05d5\u05df \u05dc\u05e4\u05e8\u05d5\u05e5 \u05d0\u05ea \u05d2\u05d1\u05d5\u05dc\u05d5\u05ea \u05d4\u05d7\u05d5\u05de\u05e8 \u05d5\u05d4\u05d6\u05de\u05df, \u05de\u05dc\u05de\u05d3\u05ea \u05e9\u05d9\u05e9 \u05d1\u05d9 \u05e7\u05e9\u05e8 \u05d7\u05d9 \u05dc\u05d0\u05d9\u05e0\u05e1\u05d5\u05e3. \u05e2\u05e6\u05dd \u05d4\u05d7\u05d9\u05e4\u05d5\u05e9 \u05de\u05d7\u05d1\u05e8 \u05d0\u05d5\u05ea\u05d9 \u05db\u05d1\u05e8 \u05e2\u05ea\u05d4 \u05d0\u05dc \u05d0\u05d5\u05ea\u05d5 \u05de\u05d9\u05de\u05d3.\n"\u05d3\u05d9\u05e8\u05e9\u05d5 \u05d4\' \u05d5\u05e2\u05d5\u05d6\u05d5" - \u05d4\u05d3\u05e8\u05d9\u05e9\u05d4 \u05d0\u05d9\u05e0\u05e0\u05d4 \u05e8\u05e7 \u05d0\u05d7\u05e8 \u05d7\u05d5\u05d5\u05d9\u05d4 \u05de\u05e8\u05d5\u05de\u05de\u05ea, \u05d0\u05dc\u05d0 \u05d0\u05d7\u05e8 \u05d4\u05e2\u05d5\u05d6, \u05d4\u05db\u05d5\u05d7 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9 \u05e9\u05d4\u05de\u05de\u05d3 \u05d4\u05e0\u05e9\u05d2\u05d1 \u05de\u05e2\u05e0\u05d9\u05e7 \u05dc\u05d9. \u05ea\u05e4\u05d9\u05dc\u05d4 \u05d0\u05d9\u05e0\u05d4 \u05e0\u05d9\u05e1\u05d9\u05d5\u05df \u05dc\u05d1\u05e8\u05d5\u05d7 \u05de\u05d4\u05e2\u05d5\u05dc\u05dd \u05d0\u05dc \u05de\u05d7\u05d5\u05d6\u05d5\u05ea \u05d0\u05d7\u05e8\u05d9\u05dd, \u05d0\u05dc\u05d0 \u05d4\u05d9\u05d0 \u05e0\u05d5\u05e2\u05d3\u05d4 \u05dc\u05d4\u05d7\u05d6\u05d9\u05e8 \u05d0\u05d5\u05ea\u05d9 \u05dc\u05e2\u05d5\u05dc\u05dd \u05d4\u05d6\u05d4 \u05e2\u05dd \u05e2\u05d5\u05d6 \u05d5\u05ea\u05d5\u05e7\u05e3 \u05d7\u05d3\u05e9\u05d9\u05dd \u05dc\u05d7\u05d9\u05e4\u05d5\u05e9 \u05d5\u05ea\u05e7\u05d5\u05d5\u05d4 \u05ea\u05de\u05d9\u05d3\u05d9\u05d9\u05dd.\n\u05db\u05dc \u05d3\u05e8\u05d9\u05e9\u05d4 \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea \u05d0\u05de\u05d9\u05ea\u05d9\u05ea \u05de\u05d5\u05dc\u05d9\u05d3\u05d4 \u05d1\u05ea\u05d5\u05db\u05d9 \u05e2\u05de\u05d5\u05d3 \u05e9\u05d3\u05e8\u05d4 \u05db\u05d5\u05d7 \u05e2\u05de\u05d9\u05d3\u05d4, \u05d9\u05e6\u05d9\u05d1\u05d5\u05ea.\n"\u05d1\u05e7\u05e9\u05d5 \u05e4\u05e0\u05d9\u05d5 \u05ea\u05de\u05d9\u05d3" - \u05d4\u05e4\u05e0\u05d9\u05dd  \u05de\u05e1\u05de\u05dc\u05d5\u05ea \u05d0\u05ea \u05e4\u05e0\u05d9\u05de\u05d9\u05d5\u05ea \u05d4\u05d3\u05d1\u05e8. \u05dc\u05d0 \u05e4\u05e0\u05d9\u05dd \u05e4\u05d9\u05d6\u05d9\u05d5\u05ea. \u05d4\u05d7\u05d9\u05e4\u05d5\u05e9 \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9 \u05d0\u05d9\u05e0\u05e0\u05d5 \u05de\u05ea\u05de\u05e6\u05d4 \u05d1\u05e8\u05d2\u05e2\u05d9 \u05e9\u05d9\u05d0, \u05d1\u05d7\u05d5\u05d5\u05d9\u05d5\u05ea \u05de\u05d9\u05e1\u05d8\u05d9\u05d5\u05ea \u05d0\u05d5 \u05d1\u05d4\u05e9\u05e8\u05d0\u05d5\u05ea \u05d7\u05d5\u05dc\u05e4\u05d5\u05ea, \u05d0\u05dc\u05d0 \u05d1\u05d4\u05d1\u05e0\u05d4 \u05e9\u05db\u05dc \u05de\u05e7\u05d5\u05dd \u05d5\u05db\u05dc \u05d6\u05de\u05df \u05e0\u05d5\u05e9\u05d0\u05d9\u05dd \u05d1\u05e7\u05e8\u05d1\u05dd \u05d0\u05e4\u05e9\u05e8\u05d5\u05ea \u05dc\u05d2\u05d9\u05dc\u05d5\u05d9 \u05e4\u05e0\u05d9\u05dd. \u05dc\u05d1\u05e7\u05e9 "\u05ea\u05de\u05d9\u05d3" \u05e4\u05d9\u05e8\u05d5\u05e9\u05d5 \u05dc\u05d4\u05e4\u05d5\u05da \u05d0\u05ea \u05db\u05dc \u05e9\u05d2\u05e8\u05ea \u05d7\u05d9\u05d9 \u05db\u05de\u05d5 \u05d0\u05db\u05d9\u05dc\u05d4, \u05e9\u05d9\u05d7\u05d4, \u05e2\u05d1\u05d5\u05d3\u05d4, \u05d9\u05d7\u05e1\u05d9\u05dd \u05d0\u05d9\u05e9\u05d9\u05d9\u05dd \u05dc\u05de\u05e8\u05d7\u05d1 \u05e9\u05d1\u05d5 \u05d0\u05e0\u05d5 \u05de\u05d1\u05e7\u05e9\u05d9\u05dd \u05d5\u05de\u05d2\u05dc\u05d9\u05dd \u05e0\u05d5\u05db\u05d7\u05d5\u05ea.\n\u05d5\u05db\u05d0\u05df \u05d1\u05d0\u05d4 \u05d4\u05d1\u05e0\u05d4 \u05d7\u05e9\u05d5\u05d1\u05d4: \u05d4\u05d0\u05de\u05d5\u05e0\u05d4 \u05d1\u05d4\' \u05d0\u05d9\u05e0\u05e0\u05d4 \u05ea\u05e0\u05d0\u05d9 \u05de\u05d5\u05e7\u05d3\u05dd \u05dc\u05d9\u05db\u05d5\u05dc\u05ea \u05dc\u05d4\u05ea\u05e4\u05dc\u05dc, \u05d0\u05dc\u05d0 \u05d4\u05d9\u05d0 \u05e2\u05e6\u05de\u05d4 \u05e4\u05d5\u05e2\u05dc \u05d9\u05d5\u05e6\u05d0 \u05e9\u05dc \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4.\n\u05e2\u05dc \u05db\u05da \u05d0\u05de\u05e8 \u05d4\u05d1\u05e2\u05e9"\u05d8 (\u05db\u05ea\u05e8 \u05e9\u05dd \u05d8\u05d5\u05d1, \u05e8\u05e0"\u05d5): \u201c\u05d1\u05de\u05e7\u05d5\u05dd \u05e9\u05de\u05d7\u05e9\u05d1\u05ea\u05d5 \u05e9\u05dc \u05d0\u05d3\u05dd \u05e9\u05dd \u05d4\u05d5\u05d0 \u05e0\u05de\u05e6\u05d0\u201d. \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d4\u05d9\u05d0 \u05ea\u05e0\u05d5\u05e2\u05d4 \u05e9\u05de\u05de\u05e7\u05de\u05ea \u05d0\u05ea \u05d4\u05d0\u05d3\u05dd \u05d1\u05de\u05de\u05d3 \u05d0\u05dc\u05d5\u05e7\u05d9, \u05d5\u05de\u05de\u05d9\u05dc\u05d0 \u05d4\u05d9\u05d0 \u05e2\u05e6\u05de\u05d4 \u05de\u05d5\u05dc\u05d9\u05d3\u05d4 \u05d0\u05de\u05d5\u05e0\u05d4. \u05d2\u05dd \u05d0\u05dd \u05d0\u05d3\u05dd \u05de\u05ea\u05d7\u05d9\u05dc \u05d0\u05ea \u05ea\u05e4\u05d9\u05dc\u05ea\u05d5 \u05d1\u05dc\u05d9 \u05d0\u05de\u05d5\u05e0\u05d4, \u05e2\u05e6\u05dd \u05d4\u05e4\u05e0\u05d9\u05d4 \u05d0\u05dc \u05d4\u05e0\u05e9\u05d2\u05d1 \u05d9\u05d5\u05e6\u05e8\u05ea \u05de\u05e6\u05d9\u05d0\u05d5\u05ea \u05e9\u05dc \u05d7\u05d9\u05d1\u05d5\u05e8 \u05d5\u05d0\u05de\u05d5\u05df.\n\u05e8\u05d1\u05d9 \u05e0\u05d7\u05de\u05df \u05de\u05d1\u05e8\u05e1\u05dc\u05d1 \u05d7\u05d9\u05d3\u05d3 \u05d0\u05ea \u05d6\u05d4 \u05d1\u05dc\u05e9\u05d5\u05e0\u05d5: \u201c\u05e2\u05dc \u05d9\u05d3\u05d9 \u05ea\u05e4\u05d9\u05dc\u05d4 \u05d6\u05d5\u05db\u05d9\u05df \u05dc\u05d0\u05de\u05d5\u05e0\u05d4\u201d (\u05dc\u05d9\u05e7\u05d5\u05d8\u05d9 \u05de\u05d5\u05d4\u05e8"\u05df \u05ea\u05e0\u05d9\u05e0\u05d0, \u05de"\u05d1). \u05db\u05dc\u05d5\u05de\u05e8, \u05dc\u05d0 \u05e9\u05d4\u05d0\u05de\u05d5\u05e0\u05d4 \u05e7\u05d5\u05d3\u05de\u05ea \u05d5\u05de\u05d0\u05e4\u05e9\u05e8\u05ea \u05d0\u05ea \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4, \u05d0\u05dc\u05d0 \u05e9\u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05e2\u05e6\u05de\u05d4 \u05e4\u05d5\u05ea\u05d7\u05ea \u05d0\u05ea \u05d4\u05dc\u05d1 \u05dc\u05d0\u05de\u05d5\u05e0\u05d4 \u05d7\u05d3\u05e9\u05d4.\n\u05d5\u05d1\u05d7\u05e1\u05d9\u05d3\u05d5\u05ea \u05d7\u05d1"\u05d3 \u05de\u05d5\u05e1\u05d1\u05e8 (\u05ea\u05e0\u05d9\u05d0, \u05e4\u05e8\u05e7 \u05de"\u05d0) \u05e9\u05d4\u05e2\u05d1\u05d5\u05d3\u05d4 \u05d0\u05d9\u05e0\u05d4 \u05ea\u05dc\u05d5\u05d9\u05d4 \u05d1"\u05d4\u05e9\u05d2\u05d4" \u05de\u05d5\u05e7\u05d3\u05de\u05ea, \u05d0\u05dc\u05d0 \u05d1\u05e2\u05e6\u05dd \u05d4\u05e4\u05e0\u05d9\u05d9\u05d4 \u05d0\u05dc \u05d4\' \u05db\u05e4\u05d9 \u05e9\u05d0\u05e0\u05d9 \u05de\u05d1\u05d9\u05df \u05d5\u05de\u05e8\u05d2\u05d9\u05e9 \u05d1\u05e8\u05d2\u05e2 \u05d6\u05d4. \u05d4\u05d4\u05de\u05e9\u05db\u05d4 \u05e9\u05dc \u05d4\u05d0\u05de\u05d5\u05e0\u05d4 \u05de\u05ea\u05d2\u05dc\u05d4 \u05d3\u05d5\u05d5\u05e7\u05d0 \u05de\u05ea\u05d5\u05da \u05d3\u05d9\u05d1\u05d5\u05e8\u05d9 \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4, \u05d2\u05dd \u05d0\u05dd \u05d1\u05ea\u05d7\u05d9\u05dc\u05ea\u05dd \u05d4\u05d0\u05d3\u05dd \u05e2\u05d3\u05d9\u05d9\u05df \u05de\u05e1\u05d5\u05e4\u05e7.\n\u05db\u05da \u05de\u05ea\u05d2\u05dc\u05d4 \u05db\u05d5\u05d7 \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4: \u05ea\u05e4\u05d9\u05dc\u05d4 \u05d0\u05d9\u05e0\u05d4 \u05de\u05d1\u05d5\u05e1\u05e1\u05ea \u05e2\u05dc \u05d4\u05e9\u05d0\u05dc\u05d4 \u05d4\u05e4\u05d9\u05dc\u05d5\u05e1\u05d5\u05e4\u05d9\u05ea "\u05d4\u05d0\u05dd \u05d9\u05e9 \u05d0\u05dc\u05d5\u05e7\u05d9\u05dd", \u05d0\u05dc\u05d0 \u05e2\u05dc \u05ea\u05e0\u05d5\u05e2\u05ea \u05d4\u05dc\u05d1 \u05d4\u05e4\u05e9\u05d5\u05d8\u05d4 - \u05d4\u05d0\u05dd \u05d0\u05e0\u05d9 \u05de\u05d1\u05e7\u05e9. \u05d4\u05d0\u05dd \u05d0\u05e0\u05d9 \u05e4\u05ea\u05d5\u05d7, \u05e9\u05d5\u05d0\u05e3, \u05e0\u05de\u05e9\u05da. \u05d4\u05e9\u05de\u05d7\u05d4 \u05e9\u05d1\u05dc\u05d1 \u05e0\u05d5\u05dc\u05d3\u05ea \u05dc\u05d0 \u05de\u05e4\u05e0\u05d9 \u05e9\u05d0\u05e0\u05d9 \u05db\u05d1\u05e8 \u05e0\u05de\u05e6\u05d0 \u05d1\u05de\u05d9\u05de\u05d3 \u05d0\u05d7\u05e8, \u05d0\u05dc\u05d0 \u05de\u05e4\u05e0\u05d9 \u05e9\u05d0\u05e0\u05d9 \u05e4\u05d5\u05e0\u05d4 \u05d0\u05dc\u05d9\u05d5, \u05e4\u05d5\u05ea\u05d7 \u05d0\u05dc\u05d9\u05d5 \u05d7\u05dc\u05d5\u05df, \u05de\u05d0\u05e4\u05e9\u05e8 \u05dc\u05d5 \u05dc\u05e0\u05e9\u05d5\u05d1 \u05dc\u05ea\u05d5\u05da \u05e2\u05d5\u05dc\u05de\u05d9.\n\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d0\u05dd \u05db\u05df \u05d0\u05d9\u05e0\u05e0\u05d4 \u05ea\u05d5\u05e6\u05d0\u05d4 \u05d0\u05dc\u05d0 \u05de\u05e1\u05e2. \u05dc\u05d0 \u05d4\u05d5\u05db\u05d7\u05d4 \u05dc\u05d0\u05de\u05d5\u05e0\u05d4 \u05d0\u05dc\u05d0 \u05d1\u05e7\u05e9\u05d4 \u05dc\u05db\u05d5\u05d7\u05d5\u05ea \u05d0\u05de\u05d5\u05e0\u05d4. \u05dc\u05d0 \u05de\u05e2\u05e0\u05d4 \u05e1\u05d5\u05e4\u05d9 \u05d0\u05dc\u05d0 \u05ea\u05e0\u05d5\u05e2\u05d4 \u05de\u05ea\u05de\u05d3\u05ea.\n\u05d5\u05d1\u05ea\u05d5\u05da \u05d4\u05ea\u05e0\u05d5\u05e2\u05d4 \u05d4\u05d6\u05d5, \u05e9\u05dc \u05d1\u05e7\u05e9\u05ea \u05d4\', \u05e9\u05dc \u05d3\u05e8\u05d9\u05e9\u05ea \u05e2\u05d5\u05d6\u05d5 \u05d5\u05e0\u05d5\u05db\u05d7\u05d5\u05ea\u05d5 \u05d1\u05d7\u05d9\u05d9 \u05d5\u05e9\u05dc \u05d7\u05d9\u05e4\u05d5\u05e9 \u05e4\u05e0\u05d9\u05d5 \u05d1\u05db\u05dc \u05e8\u05d2\u05e2 \u05d4\u05dc\u05d1 \u05e9\u05de\u05d7, \u05db\u05d9 \u05d0\u05e0\u05d9 \u05d7\u05d9 \u05d1\u05de\u05d2\u05e2 \u05e2\u05dd \u05d4\u05d0\u05d9\u05e0\u05e1\u05d5\u05e3.\n\u05de\u05e1\u05d5\u05e4\u05e8 \u05e2\u05dc \u05e8\u05d1\u05d9 \u05dc\u05d5\u05d9 \u05d9\u05e6\u05d7\u05e7 \u05de\u05d1\u05e8\u05d3\u05d9\u05e6\'\u05d1, \u05e1\u05e0\u05d2\u05d5\u05e8\u05df \u05e9\u05dc \u05d9\u05e9\u05e8\u05d0\u05dc, \u05e9\u05e4\u05e2\u05dd \u05e4\u05d2\u05e9 \u05d0\u05d3\u05dd \u05e4\u05e9\u05d5\u05d8 \u05d1\u05e9\u05d5\u05e7 \u05d5\u05e9\u05d0\u05dc\u05d5:\n"\u05de\u05d3\u05d5\u05e2 \u05d0\u05d9\u05e0\u05da \u05de\u05ea\u05e4\u05dc\u05dc?"\n\u05e2\u05e0\u05d4 \u05dc\u05d5 \u05d4\u05d0\u05d9\u05e9 \u05d1\u05ea\u05de\u05d9\u05de\u05d5\u05ea: "\u05e8\u05d1\u05d9, \u05d0\u05d9\u05e0\u05e0\u05d9 \u05d9\u05d5\u05d3\u05e2 \u05d0\u05dd \u05d1\u05db\u05dc\u05dc \u05d9\u05e9 \u05d0\u05dc\u05d5\u05e7\u05d9\u05dd \u05e9\u05e9\u05d5\u05de\u05e2 \u05d0\u05d5\u05ea\u05d9. \u05d0\u05d9\u05da \u05d0\u05ea\u05e4\u05dc\u05dc \u05d0\u05dc\u05d9\u05d5?"\n\u05d7\u05d9\u05d9\u05da \u05e8\u05d1\u05d9 \u05dc\u05d5\u05d9 \u05d9\u05e6\u05d7\u05e7 \u05d5\u05d0\u05de\u05e8 \u05dc\u05d5:\n"\u05d0\u05ea\u05d4 \u05d0\u05d9\u05e0\u05da \u05d9\u05d5\u05d3\u05e2 \u05d0\u05dd \u05d9\u05e9 \u05d0\u05dc\u05d5\u05e7\u05d9\u05dd, \u05d5\u05d0\u05e0\u05d9 \u05d0\u05d5\u05de\u05e8 \u05dc\u05da, \u05d3\u05d5\u05d5\u05e7\u05d0 \u05de\u05e9\u05d5\u05dd \u05db\u05da \u05e2\u05dc\u05d9\u05da \u05dc\u05d4\u05ea\u05e4\u05dc\u05dc. \u05ea\u05d0\u05de\u05e8 \u05dc\u05e4\u05e0\u05d9\u05d5: \'\u05e8\u05d9\u05d1\u05d5\u05e0\u05d5 \u05e9\u05dc \u05e2\u05d5\u05dc\u05dd, \u05d0\u05d9\u05e0\u05e0\u05d9 \u05d9\u05d5\u05d3\u05e2 \u05d0\u05dd \u05d0\u05ea\u05d4 \u05e7\u05d9\u05d9\u05dd, \u05d0\u05d1\u05dc \u05d0\u05dd \u05d0\u05db\u05df \u05d0\u05ea\u05d4 \u05e7\u05d9\u05d9\u05dd \u05d2\u05dc\u05d4 \u05d0\u05ea \u05e2\u05e6\u05de\u05da \u05d0\u05dc\u05d9!\' \u05d6\u05d5 \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d4\u05d9\u05e7\u05e8\u05d4 \u05d1\u05d9\u05d5\u05ea\u05e8."\n\u05d4\u05d0\u05d9\u05e9 \u05e9\u05de\u05e2, \u05e4\u05ea\u05d7 \u05d0\u05ea \u05e4\u05d9\u05d5 \u05d5\u05d4\u05ea\u05d7\u05d9\u05dc \u05dc\u05de\u05dc\u05de\u05dc \u05d1\u05dc\u05d7\u05e9 \u05d0\u05ea \u05de\u05d9\u05dc\u05d5\u05ea\u05d9\u05d5 \u05e9\u05dc \u05d4\u05e6\u05d3\u05d9\u05e7. \u05d5\u05d3\u05de\u05e2\u05d5\u05ea \u05d6\u05dc\u05d2\u05d5 \u05de\u05e2\u05d9\u05e0\u05d9\u05d5. \u05d1\u05d0\u05d5\u05ea\u05d5 \u05e8\u05d2\u05e2, \u05dc\u05e8\u05d0\u05e9\u05d5\u05e0\u05d4 \u05d1\u05d7\u05d9\u05d9\u05d5, \u05d4\u05e8\u05d2\u05d9\u05e9 \u05e9\u05d0\u05d9\u05e0\u05e0\u05d5 \u05dc\u05d1\u05d3.\n\u05e1\u05d9\u05e4\u05d5\u05e8 \u05d6\u05d4 \u05de\u05dc\u05de\u05d3 \u05d1\u05d3\u05d9\u05d5\u05e7 \u05d0\u05ea \u05de\u05d4 \u05e9\u05d0\u05de\u05e8\u05d5 \u05d4\u05d1\u05e2\u05e9"\u05d8 \u05d5\u05e8\u05d1\u05d9 \u05e0\u05d7\u05de\u05df: \u05d4\u05d0\u05de\u05d5\u05e0\u05d4 \u05d0\u05d9\u05e0\u05e0\u05d4 \u05ea\u05e0\u05d0\u05d9 \u05de\u05d5\u05e7\u05d3\u05dd \u05dc\u05ea\u05e4\u05d9\u05dc\u05d4, \u05d0\u05dc\u05d0 \u05ea\u05d5\u05e6\u05d0\u05d4 \u05e9\u05dc\u05d4.\n\u05d2\u05dd \u05d0\u05d3\u05dd \u05e9\u05d0\u05d9\u05e0\u05e0\u05d5 \u05d1\u05d8\u05d5\u05d7, \u05d5\u05d0\u05e3 \u05e0\u05d5\u05d8\u05d4 \u05dc\u05db\u05e4\u05d5\u05e8, \u05d0\u05dd \u05e8\u05e7 \u05e4\u05d5\u05e0\u05d4 \u05d5\u05de\u05ea\u05e4\u05dc\u05dc \u05db\u05e4\u05d9 \u05e9\u05d4\u05d5\u05d0, \u05de\u05ea\u05d5\u05db\u05d5 \u05de\u05ea\u05e2\u05d5\u05e8\u05e8\u05ea \u05e0\u05e7\u05d5\u05d3\u05ea \u05d0\u05de\u05d5\u05e0\u05d4 \u05d7\u05d9\u05d4 \u05e9\u05d9\u05e9 \u05de\u05e9\u05d4\u05d5 \u05de\u05e2\u05d1\u05e8 \u05dc\u05de\u05d4 \u05e9\u05d0\u05e0\u05d9 \u05e8\u05d5\u05d0\u05d4 \u05d0\u05d5 \u05d9\u05db\u05d5\u05dc \u05dc\u05d4\u05e1\u05d1\u05d9\u05e8.\n"\u05d0\u05e9\u05d0 \u05e2\u05d9\u05e0\u05d9 \u05d0\u05dc \u05d4\u05d4\u05e8\u05d9\u05dd \u05de\u05d0\u05d9\u05df \u05d9\u05d1\u05d5\u05d0 \u05e2\u05d6\u05e8\u05d9"\n\u05d9\u05e9 \u05de\u05e9\u05d4\u05d5 \u05db\u05dc \u05db\u05da \u05de\u05e8\u05d2\u05e9 \u05d1\u05d9\u05d3\u05d9\u05e2\u05d4 \u05e9\u05d9\u05e9 \u05de\u05e9\u05d4\u05d5 \u05e9\u05d4\u05d5\u05d0 \u05de\u05e2\u05dc\u05d9\u05e0\u05d5, \u05e9\u05d0\u05d9\u05df \u05dc\u05e0\u05d5 \u05e9\u05dc\u05d9\u05d8\u05d4 \u05e2\u05dc\u05d9\u05d5, \u05d0\u05d1\u05dc \u05db\u05df \u05d9\u05e9 \u05dc\u05e0\u05d5 \u05e7\u05e8\u05d9\u05d0\u05d4 \u05d0\u05dc\u05d9\u05d5 - \u05d9\u05e8\u05d0\u05ea \u05db\u05d1\u05d5\u05d3, \u05e4\u05dc\u05d9\u05d0\u05d4, \u05d4\u05ea\u05de\u05e1\u05e8\u05d5\u05ea. \u05d3\u05d5\u05d5\u05e7\u05d0 \u05d7\u05d5\u05e1\u05e8 \u05d4\u05d4\u05d1\u05e0\u05d4 \u05d4\u05d5\u05d0 \u05d4\u05e0\u05d5\u05e9\u05d0 \u05ea\u05e7\u05d5\u05d5\u05d4 \u05db\u05d9 \u05d1\u05e8\u05d2\u05e2\u05d9\u05dd \u05d4\u05db\u05d9 \u05e7\u05e9\u05d9\u05dd \u05de\u05d4\u05d0\u05d9\u05df \u05d9\u05d1\u05d5\u05d0 \u05e2\u05d6\u05e8\u05d9. \u05d4\u05de\u05d9\u05e1\u05d8\u05d9\u05e7\u05d4 \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9\u05ea \u05d1\u05e7\u05d1\u05dc\u05d4 \u05d5\u05d1\u05d7\u05e1\u05d9\u05d3\u05d5\u05ea \u05dc\u05d9\u05de\u05d3\u05d5 \u05dc\u05e7\u05e8\u05d5\u05d0 \u05d0\u05ea \u05d4\u05e4\u05e1\u05d5\u05e7 \u05d0\u05e9\u05d0 \u05e2\u05d9\u05e0\u05d9 \u05d0\u05dc \u05d4\u05d4\u05e8\u05d9\u05dd \u05de\u05d0\u05d9\u05df \u05d9\u05d1\u05d5\u05d0 \u05e2\u05d6\u05e8\u05d9. \u05dc\u05d0 \u05de\u05d4\u05d9\u05db\u05df \u05d9\u05d1\u05d5\u05d0 \u05e2\u05d6\u05e8\u05d9 \u05d0\u05dc\u05d0 \u05e2\u05d6\u05e8\u05d9 \u05d9\u05d1\u05d5\u05d0 \u05d3\u05d5\u05d5\u05e7\u05d0 \u05de\u05d4\u05d0\u05d9\u05df. \u05db\u05dc\u05d5\u05de\u05e8 \u05de\u05d4\u05de\u05e7\u05d5\u05dd \u05d4\u05e0\u05e1\u05ea\u05e8 \u05de\u05d4\u05e2\u05d9\u05df \u05d5\u05d4\u05d4\u05d1\u05e0\u05d4.\n\u05d5\u05d0\u05d5\u05dc\u05d9 \u05db\u05da \u05e6\u05e8\u05d9\u05db\u05d9\u05dd \u05dc\u05d4\u05d9\u05d5\u05ea \u05d4\u05d7\u05d9\u05d9\u05dd \u05e2\u05e6\u05de\u05dd. \u05d0\u05d5\u05dc\u05d9 \u05d4\u05d9\u05d5\u05e4\u05d9 \u05e9\u05dc \u05d4\u05d7\u05d9\u05d9\u05dd \u05d4\u05d5\u05d0 \u05dc\u05d0 \u05d1\u05d9\u05db\u05d5\u05dc\u05ea \u05dc\u05d4\u05db\u05e0\u05d9\u05e1 \u05d0\u05d5\u05ea\u05dd \u05dc\u05de\u05e1\u05d2\u05e8\u05ea \u05d1\u05e8\u05d5\u05e8\u05d4 \u05d0\u05d5 \u05dc\u05e9\u05dc\u05d5\u05d8 \u05d1\u05d4\u05dd \u05d0\u05dc\u05d0 \u05d1\u05db\u05da \u05e9\u05ea\u05de\u05d9\u05d3 \u05d9\u05e9 \u05d1\u05d4\u05dd \u05e9\u05db\u05d1\u05d4 \u05e0\u05d5\u05e1\u05e4\u05ea, \u05ea\u05d5\u05d1\u05e0\u05d4 \u05d7\u05d3\u05e9\u05d4, \u05d7\u05d5\u05d5\u05d9\u05d4 \u05e9\u05dc\u05d0 \u05d7\u05d5\u05d5\u05d9\u05e0\u05d5. \u05d1\u05db\u05dc \u05d9\u05d5\u05dd \u05d0\u05e4\u05e9\u05e8 \u05dc\u05d2\u05dc\u05d5\u05ea \u05d3\u05d1\u05e8 \u05de\u05d4 \u05e0\u05d5\u05e1\u05e3 \u05d1\u05dc\u05d1, \u05d1\u05e2\u05d5\u05dc\u05dd, \u05d1\u05d0\u05d7\u05e8\u05d9\u05dd.\n\u05d0\u05d6 \u05d0\u05d5\u05dc\u05d9 \u05d4\u05d1\u05d4\u05d9\u05e8\u05d5\u05ea \u05d5\u05d4\u05e9\u05dc\u05d9\u05d8\u05d4 \u05d0\u05d9\u05e0\u05dd \u05d4\u05de\u05d8\u05e8\u05d4. \u05d0\u05d5\u05dc\u05d9 \u05de\u05d4\u05d5\u05ea \u05d4\u05d7\u05d9\u05d9\u05dd \u05dc\u05d0 \u05d1\u05de\u05e6\u05d9\u05d0\u05ea \u05e9\u05dc\u05d9\u05d8\u05d4 \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea \u05d0\u05d5 \u05d2\u05e9\u05de\u05d9\u05ea \u05d1\u05d0\u05de\u05e6\u05e2\u05d9\u05dd \u05d3\u05ea\u05d9\u05d9\u05dd, \u05db\u05dc\u05db\u05dc\u05d9\u05d9\u05dd \u05d0\u05d5 \u05d8\u05db\u05e0\u05d9\u05d9\u05dd, \u05d0\u05dc\u05d0 \u05d4\u05d3\u05e8\u05da \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9\u05ea \u05d4\u05d0\u05de\u05d9\u05ea\u05d9\u05ea \u05d0\u05dc\u05d0 \u05d4\u05e1\u05e7\u05e8\u05e0\u05d5\u05ea \u05d5\u05d4\u05ea\u05e7\u05d5\u05d5\u05d4 \u05d4\u05d0\u05d9\u05e0\u05e1\u05d5\u05e4\u05d9\u05ea.\n\u05dc\u05d0 \u05dc\u05e0\u05e6\u05d7 \u05d0\u05ea \u05d4\u05e1\u05d5\u05d3 \u05d0\u05dc\u05d0 \u05dc\u05d4\u05d9\u05db\u05e0\u05e1 \u05dc\u05ea\u05d5\u05db\u05d5. \u05dc\u05d0 \u05dc\u05d4\u05d1\u05d9\u05df \u05d4\u05db\u05d5\u05dc \u05d0\u05dc\u05d0 \u05dc\u05d4\u05e1\u05db\u05d9\u05dd \u05dc\u05d4\u05de\u05e9\u05d9\u05da \u05dc\u05dc\u05db\u05ea \u05d1\u05d1\u05d9\u05d8\u05d7\u05d5\u05df \u05d5\u05e9\u05de\u05d7\u05d4, \u05d2\u05dd \u05db\u05e9\u05dc\u05d0 \u05de\u05d1\u05d9\u05e0\u05d9\u05dd.\n\u05dc\u05d0 \u05dc\u05d3\u05dc\u05d2 \u05e2\u05dc \u05d4\u05e1\u05d5\u05dc\u05dd: \u05e1\u05d5\u05d3 \u05d4\u05d4\u05db\u05e0\u05d4 \u05dc\u05ea\u05e4\u05d9\u05dc\u05d4\n\u05d1\u05e7\u05e8\u05d1 \u05d7\u05e1\u05d9\u05d3\u05d9\u05dd \u05d0\u05de\u05d9\u05ea\u05d9\u05d9\u05dd, \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d0\u05d9\u05e0\u05e0\u05d4 \u05e8\u05e7 \u05e8\u05d2\u05e2 \u05e2\u05de\u05d9\u05d3\u05d4 \u05dc\u05e4\u05e0\u05d9 \u05d4\'. \u05d4\u05d9\u05d0 \u05de\u05e1\u05e2. \u05d5\u05d1\u05de\u05e1\u05e2 \u2013 \u05d4\u05d3\u05e8\u05da \u05e2\u05e6\u05de\u05d4 \u05d4\u05d9\u05d0 \u05d7\u05dc\u05e7 \u05d1\u05dc\u05ea\u05d9 \u05e0\u05e4\u05e8\u05d3 \u05de\u05d4\u05d9\u05e2\u05d3. \u05db\u05dc \u05de\u05d9\u05dc\u05d4, \u05db\u05dc \u05e4\u05e1\u05d5\u05e7, \u05db\u05dc \u05d1\u05e8\u05db\u05d4 \u2013 \u05d4\u05d9\u05d0 \u05e9\u05dc\u05d1 \u05d1\u05e1\u05d5\u05dc\u05dd \u05d4\u05de\u05d5\u05d1\u05d9\u05dc \u05d0\u05ea \u05d4\u05e0\u05e4\u05e9 \u05d0\u05dc \u05de\u05e7\u05d5\u05de\u05d4 \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9. \u05dc\u05d3\u05dc\u05d2 \u05e2\u05dc \u05e9\u05dc\u05d1\u05d9\u05dd \u05d4\u05d5\u05d0 \u05dc\u05d0 \u05e8\u05e7 \u05dc\u05d4\u05d7\u05e1\u05d9\u05e8, \u05d0\u05dc\u05d0 \u05dc\u05e1\u05db\u05df \u05d0\u05ea \u05db\u05dc \u05d4\u05de\u05d1\u05e0\u05d4.\n\u05d4\u05e2\u05d5\u05dc\u05dd \u05dc\u05d0 \u05e0\u05d1\u05e8\u05d0 \u05d1\u05e9\u05de\u05d5\u05e0\u05d4 \u05e2\u05e9\u05e8\u05d4\n\u05d4\u05e8\u05d1\u05d9 \u05e8\' \u05e9\u05de\u05e2\u05dc\u05e7\u05d0 \u05de\u05e0\u05d9\u05e7\u05dc\u05e9\u05d1\u05d5\u05e8\u05d2 \u05d4\u05d9\u05d4 \u05e8\u05d2\u05d9\u05dc \u05dc\u05d5\u05de\u05e8:\n"\u05de\u05d9 \u05e9\u05de\u05ea\u05e4\u05dc\u05dc \u05e9\u05de\u05d5\u05e0\u05d4 \u05e2\u05e9\u05e8\u05d4 \u05d1\u05dc\u05d9 \u05e4\u05e1\u05d5\u05e7\u05d9 \u05d3\u05d6\u05de\u05e8\u05d4 \u2013 \u05db\u05de\u05d5 \u05d0\u05d3\u05dd \u05e9\u05e0\u05db\u05e0\u05e1 \u05d0\u05dc \u05d4\u05de\u05dc\u05da \u05d1\u05dc\u05d9 \u05e9\u05e0\u05d8\u05dc \u05d9\u05d3\u05d9\u05d9\u05dd, \u05d1\u05dc\u05d9 \u05dc\u05d1\u05d5\u05e9 \u05de\u05ea\u05d0\u05d9\u05dd, \u05d1\u05dc\u05d9 \u05e9\u05d4\u05de\u05dc\u05da \u05d1\u05db\u05dc\u05dc \u05d4\u05d1\u05d7\u05d9\u05df \u05d1\u05d5 \u05e0\u05db\u05e0\u05e1."\n\u05d4\u05d5\u05d0 \u05e1\u05d9\u05e4\u05e8 \u05e9\u05d1\u05e0\u05e2\u05d5\u05e8\u05d9\u05d5, \u05db\u05e9\u05e0\u05d9\u05e1\u05d4 "\u05dc\u05e7\u05e6\u05e8", \u05d4\u05e8\u05d2\u05d9\u05e9 \u05e9\u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 "\u05dc\u05d0 \u05ea\u05e4\u05e1\u05d4" \u2013 \u05db\u05d0\u05d9\u05dc\u05d5 \u05d4\u05e0\u05e4\u05e9 \u05d3\u05d9\u05d1\u05e8\u05d4 \u05d0\u05da \u05d4\u05e7\u05d5\u05dc \u05dc\u05d0 \u05e0\u05e9\u05de\u05e2 \u05dc\u05de\u05e2\u05dc\u05d4. \u05e8\u05e7 \u05db\u05e9\u05dc\u05de\u05d3 \u05dc\u05d4\u05db\u05d9\u05df \u05d0\u05ea \u05e2\u05e6\u05de\u05d5 \u05d1\u05d0\u05d4\u05d1\u05d4, \u05d1\u05e9\u05d9\u05e8\u05d4, \u05d1\u05ea\u05d5\u05d3\u05d4 \u2013 \u05d4\u05e8\u05d2\u05d9\u05e9 \u05e9\u05d4\u05d5\u05d0 \u05d1\u05d0\u05de\u05ea \u05de\u05d3\u05d1\u05e8 \u05e2\u05dd \u05d4\u05e9\u05dd.\n\u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05db\u05ea\u05d4\u05dc\u05d9\u05da \u05e9\u05dc \u05e2\u05dc\u05d9\u05d9\u05ea \u05d4\u05e0\u05e9\u05de\u05d4\n\u05d1\u05ea\u05d5\u05e8\u05ea \u05d7\u05d1"\u05d3 \u05e0\u05db\u05ea\u05d1 (\u05ea\u05e0\u05d9\u05d0, \u05e4\u05e8\u05e7 \u05dc\u05d8) \u05e9\u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05de\u05e1\u05d5\u05d3\u05e8\u05ea \u05e2\u05dc \u05e4\u05d9 \u05e2\u05d5\u05dc\u05de\u05d5\u05ea:\n\u05e7\u05e8\u05d1\u05e0\u05d5\u05ea \u2013 \u05de\u05e2\u05d5\u05dc\u05dd \u05d4\u05e2\u05e9\u05d9\u05d9\u05d4\n\u05e4\u05e1\u05d5\u05e7\u05d9 \u05d3\u05d6\u05de\u05e8\u05d4 \u2013 \u05de\u05e2\u05d5\u05dc\u05dd \u05d4\u05d9\u05e6\u05d9\u05e8\u05d4\n\u05d1\u05e8\u05db\u05d5\u05ea \u05e7\u05e8\u05d9\u05d0\u05ea \u05e9\u05de\u05e2 \u2013 \u05de\u05e2\u05d5\u05dc\u05dd \u05d4\u05d1\u05e8\u05d9\u05d0\u05d4\n\u05e9\u05de\u05d5\u05e0\u05d4 \u05e2\u05e9\u05e8\u05d4 \u2013 \u05de\u05e2\u05d5\u05dc\u05dd \u05d4\u05d0\u05e6\u05d9\u05dc\u05d5\u05ea\n\u05d0\u05dd \u05ea\u05d3\u05dc\u05d2 \u05e2\u05dc \u05e9\u05dc\u05d1 \u2013 \u05ea\u05d9\u05e9\u05d0\u05e8 \u05d1\u05d0\u05d5\u05ea\u05d5 \u05e2\u05d5\u05dc\u05dd. \u05db\u05dc\u05d5\u05de\u05e8, \u05de\u05d9 \u05e9\u05de\u05ea\u05e4\u05dc\u05dc \u05de\u05d4\u05e8 \u05db\u05d3\u05d9 "\u05dc\u05d4\u05d2\u05d9\u05e2" \u05dc\u05e9\u05de\u05d5\u05e0\u05d4 \u05e2\u05e9\u05e8\u05d4, \u05e2\u05dc\u05d5\u05dc \u05dc\u05d4\u05d9\u05e9\u05d0\u05e8 \u05ea\u05e7\u05d5\u05e2 \u05d1\u05e2\u05d5\u05dc\u05dd \u05d4\u05e2\u05e9\u05d9\u05d9\u05d4 \u05d2\u05dd \u05db\u05e9\u05d4\u05d5\u05d0 \u05db\u05d1\u05e8 \u05e2\u05d5\u05de\u05d3 \u05d1\u05e2\u05de\u05d9\u05d3\u05d4.\n\u05db\u05de\u05d5 \u05d0\u05d3\u05dd \u05e9\u05de\u05e0\u05e1\u05d4 \u05dc\u05ea\u05e7\u05e9\u05e8 \u05e2\u05dd \u05de\u05d9\u05e9\u05d4\u05d5 \u05d1\u05e7\u05d5\u05de\u05d4 \u05e8\u05d1\u05d9\u05e2\u05d9\u05ea, \u05d0\u05d1\u05dc \u05e0\u05e9\u05d0\u05e8 \u05d1\u05dc\u05d5\u05d1\u05d9.\n\u05d4\u05d1\u05e7\u05e9\u05d4 "\u05d6\u05b8\u05db\u05b0\u05e8\u05b5\u05e0\u05d5\u05bc \u05d1\u05bc\u05b4\u05e4\u05b0\u05e7\u05d5\u05bc\u05d3\u05b7\u05ea \u05d9\u05b0\u05e9\u05c1\u05d5\u05bc\u05e2\u05b8\u05d4 \u05d5\u05b0\u05e8\u05b7\u05d7\u05b2\u05de\u05b4\u05d9\u05dd \u05de\u05b4\u05e9\u05bc\u05c1\u05b0\u05de\u05d9 \u05e9\u05c1\u05b0\u05de\u05b5\u05d9 \u05e7\u05b6\u05d3\u05b6\u05dd, \u05d5\u05b0\u05d6\u05b8\u05db\u05d5\u05b9\u05e8 \u05dc\u05b8\u05e0\u05d5\u05bc \u05d0\u05b7\u05d4\u05b2\u05d1\u05b7\u05ea \u05d4\u05b7\u05e7\u05bc\u05b7\u05d3\u05b0\u05de\u05d5\u05b9\u05e0\u05b4\u05d9\u05dd" \u05de\u05d1\u05d8\u05d0\u05ea \u05e2\u05e0\u05d5\u05d5\u05d4 \u05e2\u05de\u05d5\u05e7\u05d4, \u05e9\u05d4\u05d9\u05d0 \u05d4\u05d1\u05e1\u05d9\u05e1 \u05dc\u05ea\u05e7\u05e9\u05d5\u05e8\u05ea \u05e9\u05dc\u05e0\u05d5 \u05e2\u05dd \u05d1\u05d5\u05e8\u05d0 \u05e2\u05d5\u05dc\u05dd.\n\u05e2\u05e0\u05d5\u05d5\u05d4 \u05de\u05d5\u05dc \u05d4\u05e7\u05d1"\u05d4 \u2013 \u05dc\u05d0 \u05de\u05db\u05d5\u05d7 \u05d6\u05db\u05d5\u05d9\u05d5\u05ea\u05d9\u05e0\u05d5:\n\u05d4\u05d1\u05d9\u05d8\u05d5\u05d9 \u05d4\u05de\u05e8\u05db\u05d6\u05d9 \u05db\u05d0\u05df \u05d4\u05d5\u05d0 \u05e9\u05d0\u05e0\u05d7\u05e0\u05d5 \u05dc\u05d0 \u05d1\u05d0\u05d9\u05dd \u05dc\u05d1\u05e7\u05e9 \u05d1\u05d6\u05db\u05d5\u05ea \u05e2\u05e6\u05de\u05e0\u05d5 \u2013 \u05dc\u05d0 \u05d1\u05d6\u05db\u05d5\u05ea \u05d4\u05de\u05e2\u05e9\u05d9\u05dd \u05e9\u05dc\u05e0\u05d5, \u05dc\u05d0 \u05d1\u05d6\u05db\u05d5\u05ea \u05d4\u05d2\u05d3\u05d5\u05dc\u05d4 \u05d4\u05d0\u05d9\u05e9\u05d9\u05ea \u05e9\u05dc\u05e0\u05d5 \u2013 \u05d0\u05dc\u05d0 \u05d1\u05d6\u05db\u05d5\u05ea \u05d4\u05d0\u05d1\u05d5\u05ea, "\u05d0\u05d4\u05d1\u05ea \u05d4\u05e7\u05d3\u05de\u05d5\u05e0\u05d9\u05dd". \u05db\u05dc\u05d5\u05de\u05e8, \u05d0\u05e0\u05d7\u05e0\u05d5 \u05de\u05d1\u05e7\u05e9\u05d9\u05dd \u05de\u05d4\u05e7\u05d1"\u05d4 \u05e9\u05d9\u05d6\u05db\u05d5\u05e8 \u05d0\u05ea \u05d4\u05e7\u05e9\u05e8 \u05e9\u05dc\u05d5 \u05e2\u05dd \u05d0\u05d1\u05d5\u05ea\u05d9\u05e0\u05d5 \u2013 \u05d0\u05d1\u05e8\u05d4\u05dd, \u05d9\u05e6\u05d7\u05e7 \u05d5\u05d9\u05e2\u05e7\u05d1 \u2013 \u05e9\u05e2\u05d1\u05d3\u05d5 \u05d0\u05ea \u05d4\' \u05d1\u05d0\u05de\u05ea, \u05d1\u05e2\u05e0\u05d5\u05d5\u05d4, \u05d1\u05de\u05e1\u05d9\u05e8\u05d5\u05ea, \u05d5\u05d1\u05e0\u05d0\u05de\u05e0\u05d5\u05ea \u05de\u05d5\u05d7\u05dc\u05d8\u05ea.\n\u05d6\u05d5\u05d4\u05d9 \u05e2\u05e0\u05d5\u05d5\u05d4 \u05de\u05d4\u05d5\u05ea\u05d9\u05ea: \u05dc\u05d4\u05db\u05d9\u05e8 \u05d1\u05db\u05da \u05e9\u05d0\u05e0\u05d7\u05e0\u05d5 \u05dc\u05d0 \u05ea\u05de\u05d9\u05d3 \u05d1\u05de\u05e7\u05d5\u05dd \u05d2\u05d1\u05d5\u05d4, \u05e9\u05dc\u05d0 \u05ea\u05de\u05d9\u05d3 \u05de\u05d2\u05d9\u05e2 \u05dc\u05e0\u05d5, \u05d5\u05e9\u05d0\u05e0\u05d5 \u05e0\u05e9\u05e2\u05e0\u05d9\u05dd \u05e2\u05dc \u05d7\u05d9\u05d1\u05d5\u05e8 \u05e2\u05de\u05d5\u05e7 \u05d9\u05d5\u05ea\u05e8 \u2013 \u05e9\u05dc \u05d3\u05d5\u05e8\u05d5\u05ea \u05e9\u05d4\u05e7\u05d3\u05d9\u05e9\u05d5 \u05d0\u05ea \u05e2\u05e6\u05de\u05dd \u05dc\u05e9\u05dd \u05e9\u05de\u05d9\u05d9\u05dd.\n\u05e2\u05e0\u05d5\u05d5\u05d4 \u05db\u05d9\u05e1\u05d5\u05d3 \u05d4\u05ea\u05e7\u05e9\u05d5\u05e8\u05ea \u05e2\u05dd \u05d4\u05e7\u05d1"\u05d4:\n\u05d0\u05d9 \u05d0\u05e4\u05e9\u05e8 \u05dc\u05d1\u05d5\u05d0 \u05dc\u05e4\u05e0\u05d9 \u05d4\u05e7\u05d1"\u05d4 \u05d1\u05d2\u05d0\u05d5\u05d5\u05d4. \u05ea\u05d7\u05d5\u05e9\u05ea "\u05de\u05d2\u05d9\u05e2 \u05dc\u05d9" \u2013 \u05de\u05e0\u05ea\u05e7\u05ea. \u05d0\u05d1\u05dc \u05db\u05e9\u05d0\u05d3\u05dd \u05e2\u05d5\u05de\u05d3 \u05de\u05d5\u05dc \u05d4\u05e7\u05d1"\u05d4 \u05d1\u05ea\u05d7\u05d5\u05e9\u05ea \u05e7\u05d8\u05e0\u05d5\u05ea, \u05d1\u05d9\u05d3\u05d9\u05e2\u05d4 \u05e9\u05d4\u05d7\u05d9\u05d9\u05dd \u05e2\u05e6\u05de\u05dd \u05d4\u05dd \u05d7\u05e1\u05d3, \u05e9\u05d4\u05db\u05dc \u05ea\u05dc\u05d5\u05d9 \u05d1\u05e8\u05d7\u05de\u05d9\u05dd, \u05d4\u05d5\u05d0 \u05de\u05ea\u05d7\u05d9\u05dc \u05dc\u05ea\u05e7\u05e9\u05e8 \u05d1\u05d0\u05de\u05ea.\n\u05d6\u05d5\u05d4\u05d9 \u05e9\u05e4\u05d4 \u05e9\u05dc \u05e2\u05e0\u05d5\u05d5\u05d4, \u05e9\u05dc \u05d1\u05e7\u05e9\u05d4, \u05e9\u05dc \u05e7\u05e8\u05d1\u05d4 \u05e9\u05de\u05d1\u05d5\u05e1\u05e1\u05ea \u05dc\u05d0 \u05e2\u05dc \u05d3\u05e8\u05d9\u05e9\u05d5\u05ea \u05d0\u05dc\u05d0 \u05e2\u05dc \u05d0\u05de\u05d5\u05df, \u05d6\u05d9\u05db\u05e8\u05d5\u05df, \u05d5\u05d4\u05db\u05e8\u05d4 \u05d1\u05d8\u05d5\u05d1 \u2013 \u05e9\u05dc \u05d4\u05d3\u05d5\u05e8\u05d5\u05ea \u05d4\u05e7\u05d5\u05d3\u05de\u05d9\u05dd \u05d5\u05e9\u05dc \u05d4\u05e7\u05d1"\u05d4.\n\u05e2\u05e0\u05d5\u05d5\u05d4 \u05d2\u05dd \u05de\u05d5\u05dc \u05db\u05dc \u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea:\n\u05d4\u05d4\u05d1\u05e0\u05d4 \u05d4\u05d6\u05d5 \u05de\u05e7\u05e8\u05d9\u05e0\u05d4 \u05e2\u05dc \u05db\u05dc \u05d4\u05d7\u05d9\u05d9\u05dd. \u05d0\u05dd \u05d0\u05d3\u05dd \u05d7\u05d9 \u05de\u05ea\u05d5\u05da "\u05d6\u05db\u05d5\u05ea", \u05de\u05ea\u05d5\u05da "\u05de\u05d2\u05d9\u05e2 \u05dc\u05d9", \u05d4\u05d5\u05d0 \u05de\u05ea\u05de\u05dc\u05d0 \u05d0\u05db\u05d6\u05d1\u05d4, \u05ea\u05e1\u05db\u05d5\u05dc, \u05d5\u05dc\u05e2\u05d9\u05ea\u05d9\u05dd \u05ea\u05d5\u05e7\u05e4\u05e0\u05d5\u05ea.\n\u05d0\u05d1\u05dc \u05d0\u05dd \u05d0\u05d3\u05dd \u05de\u05d1\u05d9\u05df \u05e9\u05db\u05dc \u05de\u05d4 \u05e9\u05d9\u05e9 \u05dc\u05d5 \u05d1\u05d7\u05d9\u05d9\u05dd, \u05d1\u05e8\u05d9\u05d0\u05d5\u05ea, \u05e7\u05e9\u05e8\u05d9\u05dd, \u05d4\u05d6\u05d3\u05de\u05e0\u05d5\u05d9\u05d5\u05ea - \u05d0\u05d9\u05e0\u05d5 \u05de\u05d5\u05d1\u05df \u05de\u05d0\u05dc\u05d9\u05d5 \u05d0\u05dc\u05d0 \u05de\u05ea\u05e0\u05d4, \u05d4\u05d5\u05d0 \u05d7\u05d9 \u05d1\u05e2\u05e0\u05d5\u05d5\u05d4, \u05d1\u05d4\u05db\u05e8\u05ea \u05ea\u05d5\u05d3\u05d4, \u05d1\u05e4\u05e9\u05d8\u05d5\u05ea \u05e9\u05de\u05d1\u05d9\u05d0\u05d4 \u05e9\u05de\u05d7\u05d4.\n\u05d4\u05d7\u05d5\u05e1\u05e8 \u05e9\u05dc\u05d5 \u05dc\u05d0 \u05d2\u05d5\u05e8\u05dd \u05dc\u05d5 \u05d6\u05e2\u05dd \u05d0\u05dc\u05d0 \u05d1\u05e7\u05e9\u05d4. \u05d4\u05d5\u05d0 \u05dc\u05d0 \u05e8\u05d5\u05d3\u05e3 \u05e6\u05d3\u05e7 \u05dc\u05e2\u05e6\u05de\u05d5 \u05d0\u05dc\u05d0 \u05e9\u05d5\u05d0\u05e3 \u05d7\u05e1\u05d3 \u05de\u05d4\u05e9\u05de\u05d9\u05dd.\n\u05d4\u05e4\u05e1\u05d5\u05e7 \u05d4\u05d6\u05d4 \u05dc\u05d0 \u05e8\u05e7 \u05de\u05dc\u05de\u05d3 \u05d0\u05d5\u05ea\u05e0\u05d5 \u05d0\u05d9\u05da \u05dc\u05d1\u05e7\u05e9 \u05d0\u05dc\u05d0 \u05d2\u05dd \u05de\u05d0\u05d9\u05e4\u05d4 \u05dc\u05d1\u05e7\u05e9. \u05de\u05ea\u05d5\u05da \u05e2\u05e0\u05d5\u05d5\u05d4, \u05de\u05ea\u05d5\u05da \u05d6\u05d9\u05db\u05e8\u05d5\u05df \u05e9\u05dc \u05d4\u05d3\u05d5\u05e8\u05d5\u05ea \u05d4\u05e7\u05d5\u05d3\u05de\u05d9\u05dd \u05e9\u05e2\u05d1\u05d3\u05d5 \u05d0\u05ea \u05d4\' \u05d1\u05d0\u05de\u05ea, \u05d5\u05de\u05ea\u05d5\u05da \u05d9\u05d3\u05d9\u05e2\u05d4 \u05e9\u05d0\u05e0\u05d7\u05e0\u05d5 \u05dc\u05d0 \u05d4\u05de\u05e8\u05db\u05d6 \u05d0\u05dc\u05d0 \u05d7\u05dc\u05e7 \u05de\u05e9\u05e8\u05e9\u05e8\u05ea \u05d2\u05d3\u05d5\u05dc\u05d4.\n\u05d4\u05e2\u05e0\u05d5\u05d5\u05d4 \u05d4\u05d6\u05d5 \u05de\u05d5\u05dc \u05d1\u05d5\u05e8\u05d0 \u05e2\u05d5\u05dc\u05dd, \u05de\u05d5\u05dc \u05d4\u05d7\u05d9\u05d9\u05dd, \u05de\u05d5\u05dc \u05e2\u05e6\u05de\u05e0\u05d5 - \u05d4\u05d9\u05d0 \u05de\u05d4 \u05e9\u05de\u05d1\u05e0\u05d4 \u05d0\u05ea \u05d4\u05d0\u05d3\u05dd \u05d5\u05de\u05e2\u05de\u05d9\u05e7 \u05d0\u05ea \u05d4\u05e7\u05e9\u05e8 \u05d4\u05d0\u05de\u05d9\u05ea\u05d9 \u05d1\u05d9\u05df \u05d0\u05d3\u05dd \u05dc\u05d0\u05dc\u05d5\u05e7\u05d9\u05d5.\n"\u05d0\u05e0\u05d9 \u05de\u05d5\u05e6\u05d0 \u05d0\u05ea \u05d4\u05e9\u05dd \u05d1\u05d1\u05e8\u05d5\u05da \u05e9\u05d0\u05de\u05e8\u2019"\n\u05d4\u05d1\u05e2\u05dc \u05e9\u05dd \u05d8\u05d5\u05d1 \u05d4\u05d9\u05d4 \u05e0\u05d5\u05d4\u05d2 \u05dc\u05d4\u05ea\u05e2\u05db\u05d1 \u05de\u05d0\u05d5\u05d3 \u05e2\u05dc \u05e4\u05e1\u05d5\u05e7\u05d9 \u05d3\u05d6\u05de\u05e8\u05d4. \u05e9\u05d0\u05dc\u05d5 \u05d0\u05d5\u05ea\u05d5 \u05de\u05d3\u05d5\u05e2 \u05d0\u05d9\u05e0\u05d5 \u05de\u05de\u05d4\u05e8 \u05dc\u05e9\u05de\u05d5\u05e0\u05d4 \u05e2\u05e9\u05e8\u05d4, \u05e9\u05d4\u05d9\u05d0 \u05e2\u05d9\u05e7\u05e8 \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4. \u05e2\u05e0\u05d4:\n"\u05d0\u05e0\u05d9 \u05dc\u05d0 \u05de\u05d7\u05e4\u05e9 \u05d0\u05ea \u05d4\u05e9\u05dd \u05d1\u05e1\u05d5\u05e3. \u05d0\u05e0\u05d9 \u05e4\u05d5\u05d2\u05e9 \u05d0\u05d5\u05ea\u05d5 \u05db\u05d1\u05e8 \u05d1\u05d1\u05e8\u05d5\u05da \u05e9\u05d0\u05de\u05e8. \u05dc\u05de\u05d4 \u05e9\u05d0\u05e2\u05d6\u05d5\u05d1 \u05de\u05e7\u05d5\u05dd \u05e9\u05d9\u05e9 \u05d1\u05d5 \u05d3\u05d1\u05e7\u05d5\u05ea \u05d0\u05de\u05d9\u05ea\u05d9\u05ea, \u05e8\u05e7 \u05db\u05d3\u05d9 \u05dc\u05de\u05d4\u05e8 \u05dc\u05de\u05e7\u05d5\u05dd \u05d0\u05d7\u05e8?"\n\u05d4\u05d7\u05d5\u05d6\u05d4 \u05de\u05dc\u05d5\u05d1\u05dc\u05d9\u05df - \u05d0\u05d9\u05da \u05d1\u05d5\u05e0\u05d9\u05dd \u05e7\u05d5\u05de\u05d4 \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea\n\u05e4\u05e2\u05dd \u05d1\u05d0 \u05d0\u05dc\u05d9\u05d5 \u05d7\u05e1\u05d9\u05d3 \u05e6\u05e2\u05d9\u05e8 \u05d5\u05d0\u05de\u05e8:\n"\u05e8\u05d1\u05d9, \u05d0\u05e0\u05d9 \u05dc\u05d0 \u05de\u05e6\u05dc\u05d9\u05d7 \u05dc\u05d4\u05ea\u05e8\u05db\u05d6 \u05d1\u05e9\u05de\u05d5\u05e0\u05d4 \u05e2\u05e9\u05e8\u05d4. \u05e8\u05e7 \u05db\u05e9\u05d0\u05e0\u05d9 \u05de\u05d2\u05d9\u05e2 \u05dc\u05e9\u05dd \u05d0\u05e0\u05d9 \u05de\u05ea\u05e2\u05d5\u05e8\u05e8 \u05dc\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d0\u05de\u05d9\u05ea\u05d9\u05ea."\n\u05e2\u05e0\u05d4 \u05dc\u05d5 \u05d4\u05d7\u05d5\u05d6\u05d4:\n"\u05d0\u05dd \u05d4\u05d9\u05d9\u05ea \u05d1\u05d5\u05e0\u05d4 \u05d1\u05d9\u05ea, \u05d4\u05d9\u05d9\u05ea \u05de\u05ea\u05d7\u05d9\u05dc \u05de\u05d4\u05d2\u05d2? \u05db\u05dc \u05de\u05d9\u05dc\u05d4 \u05dc\u05e4\u05e0\u05d9 \u05ea\u05e4\u05d9\u05dc\u05ea \u05e9\u05de\u05d5\u05e0\u05d4 \u05e2\u05e9\u05e8\u05d4 \u05d4\u05d9\u05d0 \u05e2\u05d5\u05d3 \u05dc\u05d1\u05e0\u05d4 \u05d1\u05d9\u05e1\u05d5\u05d3\u05d5\u05ea \u05d1\u05e0\u05d9\u05d9\u05df \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4. \u05db\u05db\u05dc \u05e9\u05ea\u05e9\u05d9\u05dd \u05d9\u05d5\u05ea\u05e8 \u05dc\u05d1\u05e0\u05d9\u05dd \u05db\u05da \u05d4\u05e2\u05de\u05d9\u05d3\u05d4 \u05e9\u05dc\u05da \u05ea\u05d4\u05d9\u05d4 \u05d9\u05e6\u05d9\u05d1\u05d4 \u05d9\u05d5\u05ea\u05e8."\n\u05d4\u05d7\u05d9\u05d3\u05d5\u05e9 - \u05d2\u05dd \u05d4\u05d4\u05ea\u05d7\u05dc\u05d4 \u05d4\u05d9\u05d0 \u05d2\u05d9\u05dc\u05d5\u05d9 \u05e9\u05db\u05d9\u05e0\u05d4\n\u05d9\u05e9 \u05e0\u05d8\u05d9\u05d9\u05d4 \u05dc\u05d4\u05d7\u05e9\u05d9\u05d1 \u05d0\u05ea \u05ea\u05e4\u05d9\u05dc\u05ea \u05e9\u05de\u05d5\u05e0\u05d4 \u05e2\u05e9\u05e8\u05d4 \u05db"\u05e9\u05d9\u05d0", \u05d5\u05d0\u05ea \u05db\u05dc \u05d4\u05e9\u05d0\u05e8 \u05db"\u05d4\u05db\u05e0\u05d4". \u05d0\u05da \u05d1\u05e2\u05d5\u05de\u05e7, \u05db\u05dc \u05e9\u05dc\u05d1 \u05de\u05d2\u05dc\u05d4 \u05e4\u05e0\u05d9\u05dd \u05e9\u05d5\u05e0\u05d5\u05ea \u05e9\u05dc \u05d4\u05d1\u05d5\u05e8\u05d0:\n\u05e4\u05e1\u05d5\u05e7\u05d9 \u05d3\u05d6\u05de\u05e8\u05d4 - \u05d7\u05d9\u05d1\u05d5\u05e8 \u05dc\u05ea\u05d7\u05d5\u05e9\u05ea \u05d4\u05d4\u05d5\u05d3\u05d9\u05d4. \u05e2\u05d6\u05d9\u05d1\u05ea \u05d7\u05e8\u05d3\u05ea \u05d4\u05d1\u05d5\u05e7\u05e8 \u05d3\u05e8\u05da \u05d2\u05d9\u05dc\u05d5\u05d9 \u05d4\u05d4\u05d5\u05d3 \u05d5\u05d4\u05d9\u05d5\u05e4\u05d9 \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9 \u05e9\u05d1\u05d1\u05e8\u05d9\u05d0\u05d4\n\u05d1\u05e8\u05db\u05d5\u05ea \u05e9\u05de\u05e2 - \u05d4\u05d5\u05d3\u05d0\u05d4 \u05d1\u05de\u05dc\u05db\u05d5\u05ea\u05d5 \u05d9\u05ea\u05d1\u05e8\u05da \u05e2\u05dc \u05d4\u05e2\u05d5\u05dc\u05dd\n\u05e9\u05de\u05d5\u05e0\u05d4 \u05e2\u05e9\u05e8\u05d4 \u2013 \u05d4\u05db\u05e0\u05e2\u05d4, \u05d4\u05ea\u05d0\u05d7\u05d3\u05d5\u05ea \u05d5\u05d1\u05e0\u05d9\u05d9\u05ea \u05d4\u05e8\u05e6\u05d5\u05df \u05dc\u05d7\u05d9\u05d9\u05dd\n\u05d4\u05d4\u05db\u05e0\u05d4 \u05d4\u05d9\u05d0 \u05dc\u05d0 \u05e8\u05e7 \u05d0\u05de\u05e6\u05e2\u05d9 \u05d0\u05dc\u05d0 \u05d4\u05d9\u05d0 \u05d7\u05dc\u05e7 \u05de\u05d4\u05de\u05e4\u05d2\u05e9 \u05e2\u05dd \u05d4\u05d0\u05dc\u05d5\u05e7\u05d5\u05ea, \u05e8\u05e7 \u05d1\u05e6\u05d1\u05e2\u05d9\u05dd \u05d0\u05d7\u05e8\u05d9\u05dd. \u05db\u05de\u05d5 \u05d6\u05d5\u05d2 \u05e9\u05de\u05ea\u05db\u05ea\u05d1 \u05dc\u05e4\u05e0\u05d9 \u05d4\u05d3\u05d9\u05d9\u05d8 - \u05d4\u05d4\u05ea\u05db\u05ea\u05d1\u05d5\u05ea \u05d0\u05d9\u05e0\u05e0\u05d4 \u05d1\u05d6\u05d1\u05d5\u05d6 \u05d6\u05de\u05df. \u05d4\u05d9\u05d0 \u05d7\u05dc\u05e7 \u05de\u05d4\u05e7\u05e9\u05e8.\n\u05e2\u05e6\u05d4 \u05de\u05e2\u05e9\u05d9\u05ea \u05dc\u05ea\u05d7\u05d5\u05e9\u05d4 \u05e8\u05d2\u05e9\u05d9\u05ea \u05d7\u05d9\u05d5\u05d1\u05d9\u05ea\n\u05d0\u05dd \u05d0\u05ea/\u05d4 \u05e8\u05d5\u05e6\u05d4 \u05e9\u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05e9\u05dc\u05da \u05ea\u05d9\u05d2\u05e2 \u05dc\u05da \u05d1\u05dc\u05d1, \u05ea\u05e2\u05dc\u05d4 \u05d0\u05d5\u05ea\u05da \u05dc\u05de\u05e2\u05dc\u05d4, \u05d5\u05ea\u05d0\u05d9\u05e8 \u05d0\u05d5\u05ea\u05da \u05de\u05d1\u05e4\u05e0\u05d9\u05dd \u05d0\u05dc \u05ea\u05de\u05d4\u05e8/\u05d9.\n\u05d6\u05d4 \u05d8\u05d1\u05e2\u05d9 \u05e9\u05e7\u05e9\u05d4 \u05dc\u05da \u05dc\u05d4\u05ea\u05e8\u05db\u05d6 \u05d1\u05db\u05dc \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4. \u05d2\u05dd \u05dc\u05e6\u05d3\u05d9\u05e7\u05d9\u05dd \u05d4\u05db\u05d9 \u05d2\u05d3\u05d5\u05dc\u05d9\u05dd \u05d4\u05d9\u05d5 \u05d4\u05e1\u05d7\u05d5\u05ea \u05d3\u05e2\u05ea \u05d5\u05d4\u05dd \u05e0\u05dc\u05d7\u05de\u05d5 \u05e2\u05dc \u05d4\u05e8\u05d9\u05db\u05d5\u05d6 \u05d1\u05db\u05dc \u05de\u05d9\u05dc\u05d4. \u05d5\u05d2\u05dd \u05d0\u05dd \u05ea\u05d3\u05d1\u05e8 \u05e2\u05dd \u05db\u05dc \u05d0\u05d3\u05dd \u05e9\u05e0\u05e8\u05d0\u05d4 \u05dc\u05da \u05e0\u05e2\u05dc\u05d4 \u05e8\u05d5\u05d7\u05e0\u05d9 \u05d4\u05d5\u05d0 \u05d9\u05e1\u05e4\u05e8 \u05dc\u05da \u05db\u05d9 \u05d4\u05d5\u05d0 \u05e0\u05dc\u05d7\u05dd \u05e2\u05dc \u05d4\u05e8\u05d9\u05db\u05d5\u05d6 \u05d1\u05db\u05dc \u05e8\u05d2\u05e2. \u05d0\u05d1\u05dc \u05d4\u05d7\u05d3\u05e9\u05d5\u05ea \u05d4\u05d8\u05d5\u05d1\u05d5\u05ea \u05d4\u05df \u05e9\u05db\u05db\u05dc \u05e9\u05de\u05ea\u05e8\u05d2\u05dc\u05d9\u05dd \u05e8\u05d9\u05db\u05d5\u05d6 \u05db\u05da \u05d6\u05d4 \u05e0\u05e2\u05e9\u05d4 \u05e7\u05dc \u05d9\u05d5\u05ea\u05e8. \u05d4\u05e9\u05d0\u05dc\u05d4 \u05d4\u05d9\u05d0 \u05dc\u05d0 \u05d4\u05d0\u05dd \u05d0\u05ea\u05d4 \u05de\u05ea\u05e8\u05db\u05d6 \u05d0\u05dc\u05d0 \u05d1\u05de\u05d4 \u05d0\u05ea\u05d4 \u05de\u05ea\u05e8\u05db\u05d6. \u05de\u05d4 \u05d2\u05d5\u05e0\u05d1 \u05dc\u05da \u05d0\u05ea \u05d4\u05e8\u05d9\u05db\u05d5\u05d6 \u05de\u05d4\u05de\u05e7\u05d5\u05dd \u05d1\u05d5 \u05d0\u05ea\u05d4 \u05de\u05ea\u05db\u05e0\u05df \u05dc\u05d4\u05ea\u05e8\u05db\u05d6 \u05db\u05e8\u05d2\u05e2. \u05e7\u05d5\u05e8\u05d0\u05d9\u05dd \u05dc\u05d6\u05d4 \u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05d6\u05e8\u05d5\u05ea. \u05d0\u05da \u05db\u05de\u05d5 \u05e9\u05d0\u05de\u05e8 \u05d4\u05e8\u05d1\u05d9 \u05de\u05e7\u05d5\u05e6\u05e7, \u05d4\u05df \u05dc\u05d0 \u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05d6\u05e8\u05d5\u05ea \u05d0\u05dc\u05d0 \u05d4\u05df \u05d4\u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05e9\u05dc\u05da. \u05d4\u05e9\u05d0\u05dc\u05d4 \u05d0\u05dd \u05d1\u05d0\u05d4 \u05de\u05d7\u05e9\u05d1\u05d4 \u05e9\u05d3\u05d5\u05e8\u05e9\u05ea \u05d4\u05ea\u05e2\u05de\u05e7\u05d5\u05ea \u05d0\u05d5 \u05de\u05d7\u05e9\u05d1\u05d4 \u05e9\u05d3\u05d5\u05e8\u05e9\u05ea \u05d4\u05d3\u05d7\u05d4.    \u05e0\u05e1\u05d4 \u05dc\u05e4\u05d7\u05d5\u05ea \u05dc\u05d1\u05d7\u05d5\u05e8 \u05e4\u05e1\u05d5\u05e7 \u05d0\u05d7\u05d3 \u05de\u05e4\u05e1\u05d5\u05e7\u05d9 \u05d3\u05d6\u05de\u05e8\u05d4, \u05d5\u05dc\u05e9\u05d4\u05d5\u05ea \u05d1\u05d5 \u05e8\u05d2\u05e2.\n\u05d4\u05e4\u05d5\u05da \u05d0\u05d5\u05ea\u05d5 \u05dc\u05e9\u05d9\u05e8 \u05e4\u05e0\u05d9\u05de\u05d9.\n\u05e0\u05e1\u05d4 \u05dc\u05e9\u05de\u05d5\u05e2 \u05d0\u05ea \u05d4\u05e0\u05e9\u05de\u05d4 \u05e9\u05dc\u05da \u05e9\u05e8\u05d4 \u05d0\u05d5\u05ea\u05d5. \u05d4\u05d0\u05dd \u05d6\u05d5 \u05de\u05e0\u05d2\u05d9\u05e0\u05d4 \u05e9\u05de\u05d7\u05d4 \u05d0\u05d5 \u05e2\u05e6\u05d5\u05d1\u05d4? \u05d4\u05d0\u05dd \u05e0\u05e9\u05d9\u05de\u05ea\u05da \u05e7\u05dc\u05d4 \u05d0\u05d5 \u05db\u05d1\u05d3\u05d4? \u05d4\u05d0\u05dd \u05d4\u05de\u05d9\u05dc\u05d9\u05dd \u05d9\u05d5\u05e6\u05e8\u05d5\u05ea \u05d7\u05d9\u05d1\u05d5\u05e8 \u05d0\u05d5 \u05de\u05e8\u05d2\u05d9\u05e9\u05d5\u05ea \u05dc\u05da \u05d0\u05d7\u05d3 \u05d1\u05e4\u05d4 \u05d5\u05d0\u05d7\u05d3 \u05d1\u05dc\u05d1. \u05d4\u05d0\u05dd \u05d4\u05de\u05d9\u05dc\u05d9\u05dd \u05d2\u05d5\u05e8\u05de\u05d5\u05ea \u05dc\u05ea\u05d7\u05d5\u05e9\u05ea \u05db\u05d9\u05d5\u05d5\u05e5 \u05d0\u05d5 \u05d4\u05e8\u05d2\u05e2\u05d4 \u05d1\u05d7\u05d6\u05d4 \u05d0\u05d5 \u05d1\u05d1\u05d8\u05df?\n\u05db\u05de\u05d5 \u05e9\u05d0\u05de\u05e8 \u05e8\u2019 \u05e0\u05d7\u05de\u05df:\n"\u05de\u05d9 \u05e9\u05de\u05ea\u05e8\u05d2\u05dc \u05dc\u05d5\u05de\u05e8 \u05d0\u05ea \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d1\u05e0\u05d7\u05ea - \u05d9\u05de\u05e6\u05d0 \u05e9\u05d4\u05dc\u05d1 \u05d9\u05ea\u05d7\u05d9\u05dc \u05dc\u05d4\u05ea\u05e4\u05dc\u05dc \u05dc\u05d1\u05d3."\n(\u05e9\u05d9\u05d7\u05d5\u05ea \u05d4\u05e8"\u05df \u05e7\u05e0"\u05d3)\n\u05d0\u05ea \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9\u05dd \u05d4\u05ea\u05d4\u05dc\u05da \u05d1\u05e8\u05d2\u05e9.\n\u05d0\u05dc\u05d5\u05e7\u05d9\u05dd \u05d4\u05d5\u05d0 \u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea. \u05d0\u05e0\u05d5 \u05e8\u05d5\u05e6\u05d9\u05dd \u05dc\u05d4\u05ea\u05d4\u05dc\u05da \u05d1\u05ea\u05d5\u05da \u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea \u05e2\u05dd \u05dc\u05d1 \u05e4\u05ea\u05d5\u05d7. \u05d1\u05e8\u05d2\u05e9. \u05dc\u05d0 \u05dc\u05d4\u05ea\u05e0\u05db\u05e8 \u05dc\u05e8\u05d2\u05e9\u05d5\u05ea \u05d1\u05d2\u05dc\u05dc \u05db\u05d0\u05d1 \u05de\u05e0\u05d9\u05e1\u05d9\u05d5\u05df \u05d4\u05e2\u05d1\u05e8.\n\u05d0\u05e4\u05e9\u05e8 \u05dc\u05db\u05e2\u05d5\u05e1 \u05e2\u05dc \u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea \u05d5\u05de\u05ea\u05d5\u05da \u05db\u05da \u05e2\u05dc \u05d0\u05dc\u05d5\u05e7\u05d9\u05dd \u05d0\u05d5 \u05e9\u05d0\u05e4\u05e9\u05e8 \u05dc\u05dc\u05db\u05ea \u05e2\u05dd \u05d4\' \u05d1\u05dc\u05d1 \u05e4\u05ea\u05d5\u05d7 \u05dc\u05d0\u05d5\u05e8 \u05d7\u05d3\u05e9 \u05e9\u05de\u05d7\u05db\u05d4 \u05dc\u05d4\u05d0\u05d9\u05e8 \u05d1\u05d7\u05d9\u05d9\u05e0\u05d5. (\u05d4\u05e8\u05d7\u05d1\u05d4 \u05e2\u05dc \u05db\u05da \u05d1\u05d4\u05de\u05e9\u05da \u05d4\u05e1\u05e4\u05e8 \u05e2\u05dc \u05d4\u05e4\u05e1\u05d5\u05e7 \u05d0\u05d5\u05e8 \u05d7\u05d3\u05e9 \u05e2\u05dc \u05e6\u05d9\u05d5\u05df \u05ea\u05d0\u05d9\u05e8)\n\u05d4\u05d1\u05d9\u05d8\u05d5\u05d9 "\u05d0\u05ea \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9\u05dd \u05d4\u05ea\u05d4\u05dc\u05da \u05e0\u05d7" (\u05d1\u05e8\u05d0\u05e9\u05d9\u05ea \u05d5\', \u05d8\') \u05de\u05d5\u05e4\u05d9\u05e2 \u05dc\u05d2\u05d1\u05d9 \u05e0\u05d7, \u05d5\u05de\u05d1\u05d9\u05e2 \u05d4\u05dc\u05d9\u05db\u05d4 \u05e9\u05dc \u05d4\u05d0\u05d3\u05dd \u05e2\u05dd \u05d4\u05e7\u05d1"\u05d4. \u05de\u05d3\u05e8\u05e9 \u05d1\u05e8\u05d0\u05e9\u05d9\u05ea \u05e8\u05d1\u05d4 \u05de\u05e1\u05d1\u05d9\u05e8:\n"\u05e0\u05d7 \u2013 \u05d4\u05d9\u05d4 \u05e6\u05e8\u05d9\u05da \u05e1\u05e2\u05d3, \u05d0\u05d1\u05e8\u05d4\u05dd \u2013 \u05d4\u05d9\u05d4 \u05de\u05ea\u05d7\u05d6\u05e7 \u05d5\u05d4\u05d5\u05dc\u05da \u05d1\u05e6\u05d3\u05e7\u05d5"\n\u05db\u05dc\u05d5\u05de\u05e8, \u05e0\u05d7 \u05d4\u05d5\u05dc\u05da \u05d0\u05ea \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9\u05dd \u2013 \u05db\u05de\u05d5 \u05d9\u05dc\u05d3 \u05d4\u05d4\u05d5\u05dc\u05da \u05dc\u05e6\u05d3 \u05d0\u05d1\u05d9\u05d5 \u05d5\u05de\u05d1\u05e7\u05e9 \u05ea\u05de\u05d9\u05db\u05d4. \u05dc\u05e2\u05d5\u05de\u05ea\u05d5, \u05d0\u05d1\u05e8\u05d4\u05dd \u05d4\u05d5\u05dc\u05da \u05dc\u05e4\u05e0\u05d9 \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9\u05dd \u2013 \u05de\u05d5\u05d1\u05d9\u05dc \u05d7\u05d6\u05d5\u05df, \u05de\u05ea\u05de\u05d5\u05d3\u05d3 \u05d1\u05d0\u05d5\u05de\u05e5 \u05e2\u05dd \u05d4\u05e2\u05d5\u05dc\u05dd.\n"\u05d0\u05ea \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9\u05dd \u05d4\u05ea\u05d4\u05dc\u05da \u05d1\u05e8\u05d2\u05e9" \u05d6\u05d5 \u05d4\u05d6\u05de\u05e0\u05d4 \u05dc\u05d7\u05d9\u05d5\u05ea \u05d0\u05ea \u05d4\u05d7\u05d9\u05d9\u05dd \u05de\u05ea\u05d5\u05da \u05dc\u05d9\u05d5\u05d5\u05d9 \u05e4\u05e0\u05d9\u05de\u05d9 \u05de\u05ea\u05de\u05d9\u05d3 \u05e9\u05dc \u05ea\u05d7\u05d5\u05e9\u05ea \u05e0\u05d5\u05db\u05d7\u05d5\u05ea \u05d0\u05dc\u05d5\u05e7\u05d9\u05ea, \u05d0\u05da \u05d1\u05e8\u05d2\u05e9 \u05dc\u05d0 \u05e8\u05e7 \u05d1\u05d0\u05de\u05d5\u05e0\u05d4 \u05e9\u05db\u05dc\u05d9\u05ea, \u05d0\u05dc\u05d0 \u05d3\u05e8\u05da \u05dc\u05d4\u05e2\u05d1\u05d9\u05e8 \u05d0\u05ea \u05e8\u05d2\u05e9\u05d5\u05ea\u05d4\u05dc\u05d1, \u05d4\u05ea\u05d7\u05d5\u05e9\u05d5\u05ea, \u05d4\u05ea\u05e0\u05d5\u05e2\u05d5\u05ea \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05d5\u05ea \u05e9\u05dc \u05d4\u05e0\u05e4\u05e9 \u05d3\u05e8\u05da \u05d4\u05e4\u05e8\u05e1\u05e4\u05e7\u05d8\u05d9\u05d1\u05d4 \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9\u05ea. \u05dc\u05e9\u05d0\u05d5\u05dc \u05d0\u05ea \u05d4\u05e9\u05dd \u05e2\u05dc \u05db\u05dc \u05e8\u05d2\u05e9 \u05de\u05d4 \u05d4\u05d5\u05d0 \u05d1\u05d0 \u05dc\u05dc\u05de\u05d3 \u05d0\u05d5\u05ea\u05d9 \u05e2\u05dc \u05d4\u05d7\u05d9\u05d9\u05dd, \u05e2\u05dc \u05d4\u05ea\u05e7\u05e9\u05d5\u05e8\u05ea \u05e9\u05dc\u05d9 \u05e2\u05dd \u05d0\u05e0\u05e9\u05d9\u05dd \u05d0\u05d7\u05e8\u05d9\u05dd. \u05d1\u05de\u05d9\u05d5\u05d7\u05d3 \u05d0\u05dc\u05d5 \u05e9\u05d3\u05d5\u05e8\u05db\u05d9\u05dd \u05dc\u05d9 \u05e2\u05dc \u05d9\u05d1\u05dc\u05d5\u05ea.\n\u05d6\u05d4 \u05dc\u05d0 \u05dc\u05d4\u05d9\u05d5\u05ea \u05e6\u05d3\u05d9\u05e7 \u05de\u05d5\u05e9\u05dc\u05dd \u05e9\'\u05db\u05d5\u05d1\u05e9 \u05e8\u05d2\u05e9\u05d5\u05ea\' \u05d0\u05dc\u05d0 \u05dc\u05d4\u05e4\u05da \u2013 \u05dc\u05ea\u05ea \u05dc\u05e8\u05d2\u05e9 \u05dc\u05d4\u05d9\u05d5\u05ea \u05de\u05e7\u05d5\u05dd \u05d4\u05de\u05e4\u05d2\u05e9 \u05e2\u05dd \u05d0\u05dc\u05d5\u05e7\u05d9\u05dd.\n\u05d6\u05d5 \u05d3\u05e8\u05da \u05e9\u05dc \u05d4\u05ea\u05de\u05e1\u05e8\u05d5\u05ea \u05e8\u05d2\u05e9\u05d9\u05ea, \u05e9\u05dc \u05d7\u05d9\u05e4\u05d5\u05e9 \u05d5\u05d7\u05d9\u05d1\u05d5\u05e8 \u05de\u05ea\u05d5\u05da \u05d4\u05dc\u05d1 \u05d4\u05e4\u05d5\u05e2\u05dd, \u05de\u05ea\u05d5\u05da \u05d4\u05e4\u05d2\u05d9\u05e2\u05d5\u05ea, \u05d4\u05d0\u05d4\u05d1\u05d4, \u05d4\u05d2\u05e2\u05d2\u05d5\u05e2, \u05d4\u05e9\u05d1\u05e8 \u05d5\u05d4\u05ea\u05e7\u05d5\u05d5\u05d4.\n\u05d4\u05de\u05e9\u05e4\u05d8 \u05d1\u05ea\u05e4\u05d9\u05dc\u05d4 \u05de\u05ea\u05d0\u05e8 \u05d4\u05dc\u05d9\u05db\u05d4 \u05d6\u05d5\u05d2\u05d9\u05ea \u2013 \u05d9\u05d3 \u05d1\u05d9\u05d3 \u05e2\u05dd \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9\u05dd. \u05dc\u05d0 \u05dc\u05d1\u05d3. \u05dc\u05d0 \u05de\u05e0\u05e1\u05d4 \u05dc\u05e9\u05dc\u05d5\u05d8 \u05d1\u05de\u05e6\u05d9\u05d0\u05d5\u05ea. \u05dc\u05d0 \u05e8\u05e6\u05d4 \u05d1\u05dc\u05e2\u05d3\u05d9\u05d5. \u05d5\u05dc\u05d0 \u05e0\u05e1\u05d5\u05d2\u05d4 \u05de\u05d0\u05d7\u05d5\u05e8 \u05de\u05e8\u05d5\u05d1 \u05e4\u05d7\u05d3.\n\u05d0\u05dc\u05d0 \u05d1\u05d4\u05e7\u05e9\u05d1\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05e9\u05de\u05d0\u05e4\u05e9\u05e8\u05ea \u05e0\u05d5\u05db\u05d7\u05d5\u05ea \u05d0\u05dc\u05d5\u05e7\u05d9\u05ea \u05de\u05dc\u05d5\u05d5\u05d4.\n\u05db\u05e9\u05de\u05d5\u05e1\u05d9\u05e4\u05d9\u05dd \u05d0\u05ea \u05d4\u05de\u05d9\u05dc\u05d9\u05dd "\u05d1\u05e8\u05d2\u05e9" \u2013 \u05d0\u05e0\u05d7\u05e0\u05d5 \u05de\u05e7\u05d1\u05dc\u05d9\u05dd \u05d3\u05e8\u05da \u05d7\u05d9\u05d9\u05dd \u05e9\u05d1\u05d4 \u05db\u05dc \u05e8\u05d2\u05e9 \u05d4\u05d5\u05d0 \u05d4\u05d6\u05de\u05e0\u05d4 \u05dc\u05dc\u05db\u05ea \u05d9\u05d3 \u05d1\u05d9\u05d3 \u05e2\u05dd \u05d0\u05dc\u05d5\u05e7\u05d9\u05dd:\n\u05db\u05e9\u05d0\u05e0\u05d9 \u05e4\u05d5\u05d7\u05d3 \u2013 \u05d0\u05e0\u05d9 \u05dc\u05d0 \u05dc\u05d1\u05d3 \u05d1\u05e4\u05d7\u05d3. \u05e9\u05de\u05d9\u05dd \u05d9\u05d3 \u05d1\u05d9\u05d3 \u05e2\u05dd \u05d4\u05d1\u05d5\u05e8\u05d0 \u05e9\u05de\u05db\u05d9\u05dc \u05d0\u05ea \u05d4\u05e4\u05d7\u05d3 \u05d4\u05d6\u05d4.\n\u05db\u05e9\u05d0\u05e0\u05d9 \u05de\u05ea\u05e8\u05d2\u05e9\u05ea - \u05d4\u05d5\u05d0 \u05e9\u05d5\u05ea\u05e3 \u05d1\u05d4\u05ea\u05e4\u05e2\u05de\u05d5\u05ea.\n\u05db\u05e9\u05e9\u05d1\u05d5\u05e8\u05d9\u05dd \u05d0\u05d5 \u05e2\u05d9\u05d9\u05e4\u05d9\u05dd - \u05d4\u05d5\u05d0 \u05dc\u05d0 \u05e2\u05d5\u05d6\u05d1 \u05dc\u05d9 \u05d0\u05ea \u05d4\u05d9\u05d3.\n\u05db\u05e9\u05e2\u05e6\u05d5\u05d1\u05d9\u05dd \u05d4\u05d5\u05dc\u05db\u05d9\u05dd \u05e2\u05dd \u05d0\u05dc\u05d5\u05e7\u05d9\u05dd \u05d1\u05ea\u05d5\u05da \u05d4\u05e2\u05e6\u05d1.\n\u05db\u05e9\u05e9\u05de\u05d7\u05d9\u05dd \u05dc\u05d4\u05e8\u05d2\u05d9\u05e9 \u05d0\u05ea \u05d4\u05e9\u05de\u05d7\u05d4 \u05db\u05de\u05ea\u05e0\u05d4 \u05d0\u05dc\u05d5\u05e7\u05d9\u05ea.\n\u05db\u05e9\u05de\u05e8\u05d2\u05d9\u05e9\u05d9\u05dd \u05d1\u05d3\u05d9\u05d3\u05d5\u05ea \u05dc\u05d4\u05e8\u05d2\u05d9\u05e9 \u05e9\u05e9\u05dd, \u05d1\u05dc\u05d1 \u05d4\u05d1\u05d3\u05d9\u05d3\u05d5\u05ea, \u05d9\u05e9 \u05e7\u05d5\u05dc \u05d0\u05dc\u05d5\u05e7\u05d9 \u05e9\u05de\u05d1\u05e7\u05e9 \u05e7\u05e9\u05e8\n\u05d6\u05d4 \u05de\u05e6\u05e8\u05d9\u05da \u05ea\u05d6\u05db\u05d5\u05e8\u05ea \u05de\u05ea\u05de\u05d3\u05ea: \u05d4\u05e8\u05d2\u05e9\u05d5\u05ea \u05e9\u05dc\u05d9 \u05dc\u05d0 \u05de\u05e4\u05e8\u05d9\u05d3\u05d9\u05dd \u05d0\u05d5\u05ea\u05d9 \u05de\u05d4\u05d0\u05dc\u05d5\u05e7\u05d9\u05dd \u2013 \u05d4\u05dd \u05d1\u05d3\u05d9\u05d5\u05e7 \u05d4\u05de\u05e7\u05d5\u05dd \u05dc\u05e4\u05d2\u05d5\u05e9 \u05d0\u05d5\u05ea\u05d5.\n\u2728 \u05ea\u05e8\u05d2\u05d9\u05dc \u05d4\u05d8\u05de\u05e2\u05d4: "\u05d9\u05d3 \u05d1\u05d9\u05d3 \u05e2\u05dd \u05d0\u05dc\u05d5\u05e7\u05d9\u05dd \u2013 \u05d1\u05d9\u05d5\u05de\u05df \u05d4\u05e8\u05d2\u05e9"\n\u05e7\u05d7\u05d9 \u05de\u05d7\u05d1\u05e8\u05ea \u05e7\u05d8\u05e0\u05d4 \u05d0\u05d5 \u05d0\u05e4\u05dc\u05d9\u05e7\u05e6\u05d9\u05d9\u05ea \u05d4\u05e2\u05e8\u05d5\u05ea, \u05d5\u05db\u05ea\u05d1\u05d9 \u05db\u05d5\u05ea\u05e8\u05ea:\n\u05d1\u05d7\u05e8\u05d9 \u05e8\u05d2\u05e2 \u05d0\u05d7\u05d3 \u05de\u05d4\u05d9\u05d5\u05dd \u05e9\u05d4\u05d9\u05d4 \u05d1\u05d5 \u05e8\u05d2\u05e9 \u05d7\u05d6\u05e7 \u2013 \u05e2\u05e6\u05d1, \u05db\u05e2\u05e1, \u05d4\u05ea\u05e8\u05d2\u05e9\u05d5\u05ea, \u05e2\u05dc\u05d1\u05d5\u05df, \u05e9\u05de\u05d7\u05d4."\u05d4\u05d9\u05d5\u05dd \u05d4\u05dc\u05db\u05ea\u05d9 \u05d9\u05d3 \u05d1\u05d9\u05d3 \u05e2\u05dd \u05d0\u05dc\u05d5\u05e7\u05d9\u05dd \u05db\u05e9..."\n\u05e1\u05de\u05e0\u05d9 \u05dc\u05e2\u05e6\u05de\u05da \u05d1\u05d0\u05d9\u05d6\u05d4 \u05e8\u05d2\u05e9 \u05e7\u05e9\u05d4 \u05dc\u05da \u05dc\u05d4\u05ea\u05d7\u05d1\u05e8 \u05dc\u05d0\u05dc\u05d5\u05e7\u05d9\u05dd \u05d5\u05e2\u05e9\u05d9 \u05dc\u05da \u05ea\u05d6\u05db\u05d5\u05e8\u05ea \u05d4\u05e4\u05dc\u05d0\u05e4\u05d5\u05df \u05e9\u05e4\u05e2\u05dd \u05d4\u05d1\u05d0\u05d4 \u05e9\u05d4\u05e8\u05d2\u05e9 \u05d4\u05d6\u05d4 \u05d9\u05e2\u05dc\u05d4 \u05d0\u05ea \u05e8\u05d5\u05e6\u05d4 \u05dc\u05d7\u05d1\u05e8 \u05d0\u05d5\u05ea\u05d5 \u05dc\u05d0\u05dc\u05d5\u05e7\u05d9\u05dd\n\u05e4\u05e2\u05dd \u05d1\u05d9\u05d5\u05dd, \u05e2\u05e6\u05e8\u05d9 \u05dc\u05e8\u05d2\u05e2 \u05d5\u05e2\u05e0\u05d9 \u05e2\u05dc \u05d6\u05d4:\n\u05d1\u05d0\u05d9\u05dc\u05d5 \u05de\u05e6\u05d1\u05d9\u05dd \u05d0\u05e0\u05d9 \u05de\u05e8\u05d2\u05d9\u05e9\u05d4 \u05e8\u05d2\u05e9 \u05d7\u05d6\u05e7 \u2013 \u05e4\u05d7\u05d3, \u05e7\u05e0\u05d0\u05d4, \u05e9\u05de\u05d7\u05d4, \u05d0\u05d4\u05d1\u05d4, \u05e2\u05dc\u05d1\u05d5\u05df?\n\u05d4\u05d0\u05dd \u05e0\u05d6\u05db\u05e8\u05ea\u05d9 \u05dc\u05d4\u05d7\u05d6\u05d9\u05e7 \u05d0\u05ea \u05d9\u05d3\u05d5 \u05e9\u05dc \u05d0\u05dc\u05d5\u05e7\u05d9\u05dd \u05d1\u05d0\u05d5\u05ea\u05d5 \u05e8\u05d2\u05e2?\n\u05d0\u05dd \u05db\u05df \u05ea\u05ea\u05d0\u05e8\u05d9 \u05d0\u05d9\u05da \u05d6\u05d4 \u05d4\u05e8\u05d2\u05d9\u05e9 \u05dc\u05e2\u05d5\u05de\u05ea \u05de\u05ea\u05d9 \u05e9\u05dc\u05d0 \u05d4\u05ea\u05d7\u05d1\u05e8\u05ea \u05dc\u05d0\u05dc\u05d5\u05e7\u05d9\u05dd\n\u05dc\u05d3\u05d5\u05d2\u05de\u05d0:\n\u05d0\u05ea \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9\u05dd \u05d4\u05ea\u05d4\u05dc\u05db\u05ea\u05d9 \u05d1\u05e8\u05d2\u05e9 \u05db\u05e9\u05d4\u05e8\u05d2\u05e9\u05ea\u05d9 \u05e7\u05d8\u05e0\u05d4 \u05de\u05d5\u05dc \u05d4\u05e2\u05d5\u05dc\u05dd \u05d5\u05d4\u05d5\u05d0 \u05dc\u05d7\u05e9 \u05dc\u05d9 \u05e9\u05d0\u05e0\u05d9 \u05d0\u05d4\u05d5\u05d1\u05d4."\n"\u05d0\u05ea \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9\u05dd \u05d4\u05ea\u05d4\u05dc\u05db\u05ea\u05d9 \u05d1\u05e8\u05d2\u05e9 \u05db\u05e9\u05db\u05e2\u05e1\u05ea\u05d9 \u2013 \u05d5\u05d4\u05d5\u05d0 \u05dc\u05d0 \u05d4\u05ea\u05e8\u05d7\u05e7, \u05d4\u05d5\u05d0 \u05d4\u05d9\u05d4 \u05e9\u05dd \u05d1\u05ea\u05d5\u05da \u05d4\u05dc\u05d1 \u05d4\u05e1\u05d5\u05e2\u05e8 \u05e9\u05dc\u05d9."\n\u05d0\u05dd \u05dc\u05d0 \u05d6\u05db\u05e8\u05ea \u05dc\u05d4\u05ea\u05d7\u05d1\u05e8 \u05ea\u05db\u05ea\u05d1\u05d9 \u05d0\u05d9\u05da \u05d4\u05d9\u05d9\u05ea \u05e8\u05d5\u05e6\u05d4 \u05dc\u05d6\u05db\u05d5\u05e8 \u05d1\u05e4\u05e2\u05dd \u05d4\u05d1\u05d0\u05d4.\u05e2\u05e6\u05de\u05d9 \u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05d5\u05d3\u05de\u05d9\u05d9\u05e0\u05d9: \u05d0\u05ea \u05d0\u05dc\u05d5\u05e7\u05d9\u05dd \u05e2\u05d5\u05de\u05d3 \u05dc\u05d9\u05d3\u05da \u05d1\u05e8\u05d2\u05e2 \u05d4\u05d4\u05d5\u05d0 \u2013 \u05dc\u05d0 \u05e9\u05d5\u05e4\u05d8, \u05dc\u05d0 \u05de\u05d3\u05e8\u05d9\u05da, \u05e8\u05e7 \u05e0\u05d5\u05db\u05d7 \u05d1\u05d0\u05d4\u05d1\u05d4.\n\u05e9\u05d0\u05dc\u05d9: \u05de\u05d4 \u05d4\u05d9\u05d9\u05ea\u05d9 \u05e8\u05d5\u05e6\u05d4 \u05dc\u05d5\u05de\u05e8 \u05dc\u05d5 \u05e2\u05db\u05e9\u05d9\u05d5?\n\u05de\u05d4 \u05d4\u05d5\u05d0 \u05d4\u05d9\u05d4 \u05e2\u05d5\u05e0\u05d4 \u05dc\u05d9 \u05d1\u05dc\u05d1?\n\u05e2\u05e9\u05d9 \u05dc\u05da \u05ea\u05d6\u05db\u05d5\u05e8\u05d5\u05ea \u05d1\u05de\u05e7\u05d5\u05de\u05d5\u05ea \u05e0\u05e8\u05d0\u05d9\u05dd \u05dc\u05e2\u05d9\u05df. \u05e2\u05dc \u05d4\u05de\u05e8\u05d0\u05d4, \u05e2\u05dc \u05de\u05e7\u05e8\u05e8, \u05e2\u05dc \u05d4\u05d4\u05d2\u05d4. \u05d1\u05de\u05e9\u05e8\u05d3. \u05d5\u05d4\u05db\u05d9 \u05d7\u05e9\u05d5\u05d1 \u05d1\u05de\u05e7\u05d5\u05de\u05d5\u05ea \u05e9\u05d0\u05ea \u05d9\u05d5\u05d3\u05e2\u05ea \u05e9\u05e7\u05e9\u05d4 \u05dc\u05da \u05dc\u05d4\u05ea\u05d7\u05d1\u05e8\n\u05d4\u05d5\u05e1\u05d9\u05e4\u05d9 \u05de\u05e9\u05e4\u05d8 \u05d7\u05d9\u05d6\u05d5\u05e7 \u05d5\u05d4\u05d8\u05de\u05e2\u05d4:\n"\u05d2\u05dd \u05d1\u05e8\u05d2\u05e9 \u05d4\u05d6\u05d4 \u05d0\u05e0\u05d9 \u05dc\u05d0 \u05dc\u05d1\u05d3. \u05d0\u05e0\u05d9 \u05de\u05d7\u05d6\u05d9\u05e7\u05d4 \u05d0\u05ea \u05d9\u05d3\u05da, \u05d0\u05dc\u05d5\u05e7\u05d9."\n\u05ea\u05d5\u05db\u05dc\u05d9 \u05dc\u05ea\u05dc\u05d5\u05ea \u05d1\u05d1\u05d9\u05ea \u05e4\u05ea\u05e7 \u05e7\u05d8\u05df:\n"\u05d6\u05db\u05e8\u05d9: \u05d0\u05ea \u05dc\u05d0 \u05dc\u05d1\u05d3. \u05d1\u05db\u05dc \u05e8\u05d2\u05e9 \u2013 \u05d4\u05d7\u05d6\u05d9\u05e7\u05d9 \u05d0\u05ea \u05d9\u05d3\u05d5."\n\u05db\u05d3\u05d0\u05d9 \u05d2\u05dd \u05dc\u05e7\u05d1\u05d5\u05e2 \u05ea\u05d6\u05db\u05d5\u05e8\u05ea \u05d1\u05d8\u05dc\u05e4\u05d5\u05df \u05e9\u05ea\u05d5\u05e4\u05d9\u05e2 \u05db\u05dc \u05e2\u05e8\u05d1:\n"\u05d4\u05d0\u05dd \u05d4\u05d7\u05d6\u05e7\u05ea \u05d4\u05d9\u05d5\u05dd \u05d9\u05d3 \u05d1\u05d9\u05d3 \u05e2\u05dd \u05d0\u05dc\u05d5\u05e7\u05d9\u05dd\n\u05d4\u05d7\u05d9\u05d9\u05dd \u05d4\u05dd \u05de\u05e1\u05e2 \u05e8\u05d2\u05e9\u05d9.\n\u05d0\u05dd \u05de\u05ea\u05d4\u05dc\u05db\u05d9\u05dd \u05e2\u05dd \u05d0\u05dc\u05d5\u05e7\u05d9\u05dd \u05d1\u05e8\u05d2\u05e9 \u05de\u05e7\u05d3\u05e9\u05d9\u05dd \u05d0\u05ea \u05d4\u05e8\u05d2\u05e9. \u05de\u05e2\u05dc\u05d9\u05dd \u05d0\u05d5\u05ea\u05d5 \u05de\u05de\u05e7\u05d5\u05dd \u05d0\u05d9\u05e0\u05e1\u05d8\u05d9\u05e0\u05e7\u05d8\u05d9\u05d1\u05d9 \u05e9\u05e9\u05d5\u05dc\u05d8 \u05d1\u05e0\u05d5 \u05dc\u05ea\u05d5\u05d3\u05e2\u05d4 \u05d7\u05d9\u05d5\u05d1\u05d9\u05ea \u05e9\u05de\u05d0\u05e4\u05e9\u05e8\u05ea \u05dc\u05e0\u05d5 \u05dc\u05e0\u05e9\u05d5\u05dd \u05d5\u05dc\u05d7\u05d9\u05d5\u05ea \u05d8\u05d5\u05d1 \u05d9\u05d5\u05ea\u05e8.\n\u05dc\u05d0 \u05ea\u05e6\u05d8\u05e8\u05db\u05d5 \u05dc\u05d1\u05d8\u05dc \u05e8\u05d2\u05e9\u05d5\u05ea \u05d0\u05dc\u05d0 \u05dc\u05e7\u05d3\u05e9 \u05d0\u05d5\u05ea\u05dd.\n\u05d5\u05e9\u05dd, \u05d1\u05de\u05e7\u05d5\u05dd \u05d4\u05db\u05d9 \u05d0\u05d9\u05e9\u05d9, \u05d4\u05db\u05d9 \u05d0\u05e0\u05d5\u05e9\u05d9 \u05de\u05ea\u05d2\u05dc\u05d4 \u05d4\u05e9\u05db\u05d9\u05e0\u05d4.\n_--------------------------------\n\u05de\u05d4 \u05e7\u05d5\u05e8\u05d4 \u05d1\u05de\u05d5\u05d7  \u05d5\u05d1\u05d2\u05d5\u05e3 \u05d1\u05d6\u05de\u05df \u05ea\u05e4\u05d9\u05dc\u05d4? \u05d4\u05e1\u05d5\u05d3 \u05d4\u05e2\u05ea\u05d9\u05e7 \u05e9\u05d4\u05de\u05d3\u05e2 \u05e8\u05e7 \u05de\u05ea\u05d7\u05d9\u05dc \u05dc\u05d4\u05d1\u05d9\u05df\n\u05d0\u05e4\u05e9\u05e8 \u05dc\u05e8\u05d0\u05d5\u05ea \u05d0\u05ea \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d1\u05de\u05e1\u05d5\u05e8\u05ea \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9\u05ea \u05db\u05ea\u05d4\u05dc\u05d9\u05da \u05e2\u05de\u05d5\u05e7 \u05e9\u05dc \u05e2\u05d1\u05d5\u05d3\u05d4 \u05e2\u05dd \u05d4\u05e8\u05e9\u05de\u05d9\u05dd \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05d9\u05dd \u05e9\u05dc \u05d4\u05d0\u05d3\u05dd -\u05de\u05d4 \u05e9\u05d4\u05de\u05d3\u05e2 \u05d4\u05d9\u05d5\u05dd \u05d4\u05d9\u05d4 \u05e7\u05d5\u05e8\u05d0 \u05dc\u05d5 \u05e2\u05e7\u05d1\u05d5\u05ea \u05d6\u05d9\u05db\u05e8\u05d5\u05df \u05d1\u05de\u05d5\u05d7  \u05d5\u05d1\u05d2\u05d5\u05e3. (Engram)\n\u05d1\u05de\u05d3\u05e2\u05d9 \u05d4\u05de\u05d5\u05d7 \u05de\u05d3\u05d1\u05e8\u05d9\u05dd \u05e2\u05dc \u05db\u05da \u05e9\u05d7\u05d5\u05d5\u05d9\u05d5\u05ea \u05d9\u05d5\u05e6\u05e8\u05d5\u05ea \u05d0\u05e0\u05d2\u05e8\u05de\u05d9\u05dd - \u05e2\u05e7\u05d1\u05d5\u05ea \u05d1\u05d6\u05d9\u05db\u05e8\u05d5\u05df \u05d1\u05de\u05e2\u05e8\u05db\u05ea \u05d4\u05e2\u05e6\u05d1\u05d9\u05dd. \u05d4\u05e8\u05e9\u05de\u05d9\u05dd \u05d4\u05d0\u05dc\u05d5 \u05de\u05e9\u05e4\u05d9\u05e2\u05d9\u05dd \u05e2\u05dc \u05d4\u05e8\u05d2\u05e9\u05d5\u05ea, \u05e2\u05dc \u05d4\u05ea\u05d2\u05d5\u05d1\u05d5\u05ea \u05d5\u05e2\u05dc \u05d4\u05d0\u05d5\u05e4\u05df \u05e9\u05d1\u05d5 \u05d4\u05d0\u05d3\u05dd \u05de\u05e4\u05e8\u05e9 \u05d5\u05d7\u05d5\u05d5\u05d4 \u05d0\u05ea \u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea. \u05d0\u05d1\u05dc \u05d4\u05de\u05d7\u05e7\u05e8 \u05d2\u05dd \u05de\u05e8\u05d0\u05d4 \u05e9\u05db\u05d0\u05e9\u05e8 \u05d6\u05d9\u05db\u05e8\u05d5\u05df \u05de\u05ea\u05e2\u05d5\u05e8\u05e8 \u05de\u05d7\u05d3\u05e9 \u05d1\u05ea\u05d5\u05da \u05d7\u05d5\u05d5\u05d9\u05d4 \u05e8\u05d2\u05e9\u05d9\u05ea \u05d0\u05d7\u05e8\u05ea, \u05d4\u05d5\u05d0 \u05d9\u05db\u05d5\u05dc \u05dc\u05d4\u05e9\u05ea\u05e0\u05d5\u05ea \u05d5\u05dc\u05d4\u05ea\u05e8\u05e4\u05d0.\n\u05d5\u05db\u05d0\u05df \u05e0\u05db\u05e0\u05e1 \u05d4\u05e7\u05e9\u05e8 \u05dc\u05ea\u05e4\u05d9\u05dc\u05d4. \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05de\u05d0\u05e4\u05e9\u05e8\u05ea \u05e4\u05e8\u05e9\u05e0\u05d5\u05ea \u05d7\u05d9\u05d5\u05d1\u05d9\u05ea \u05dc\u05d7\u05d5\u05d5\u05d9\u05d5\u05ea \u05d4\u05d7\u05d9\u05d9\u05dd.\n\u05d1\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d4\u05d0\u05d3\u05dd \u05dc\u05d0 \u05e4\u05d5\u05e0\u05d4 \u05e8\u05e7 \u05d1\u05e9\u05db\u05dc. \u05d4\u05d5\u05d0 \u05e4\u05d5\u05e0\u05d4 \u05e2\u05dd \u05db\u05dc \u05d7\u05dc\u05e7\u05d9 \u05d4\u05d5\u05d5\u05d9\u05d9\u05ea\u05d5. \u05de\u05d7\u05d1\u05e8 \u05d0\u05ea \u05d4\u05e9\u05db\u05dc \u05d0\u05dc \u05d4\u05e8\u05d2\u05e9. \u05db\u05d0\u05e9\u05e8 \u05d0\u05e0\u05d5 \u05e9\u05e8\u05d9\u05dd \u05d4\u05e0\u05e9\u05d9\u05de\u05d4 \u05e9\u05dc\u05e0\u05d5 \u05e0\u05e8\u05d2\u05e2\u05ea \u05d5\u05db\u05d0\u05e9\u05e8 \u05d0\u05e0\u05d5 \u05de\u05ea\u05d1\u05d5\u05e0\u05e0\u05d9\u05dd \u05d1\u05ea\u05d1\u05d5\u05e0\u05d4 \u05e2\u05dc \u05d4\u05de\u05d9\u05dc\u05d9\u05dd \u05d4\u05de\u05d7\u05d3\u05e9\u05d5\u05ea \u05d0\u05de\u05d5\u05df \u05e9\u05dc\u05db\u05dc \u05d9\u05e9 \u05de\u05d8\u05e8\u05d4 \u05d5\u05d9\u05e9 \u05de\u05d4\u05d5\u05ea \u05e9\u05d0\u05d5\u05d4\u05d1\u05ea \u05d0\u05d5\u05ea\u05e0\u05d5 \u05d5\u05d3\u05d5\u05d0\u05d2\u05ea \u05dc\u05e0\u05d5 \u05d4\u05d7\u05d5\u05d5\u05d9\u05d4 \u05de\u05e9\u05ea\u05e0\u05d4. \u05e0\u05e2\u05e9\u05d4 \u05ea\u05e8\u05e9\u05d9\u05dd \u05d7\u05d3\u05e9. \u05e0\u05d5\u05e6\u05e8\u05d9\u05dd \u05e7\u05e9\u05e8\u05d9\u05dd \u05d7\u05d3\u05e9\u05d9\u05dd \u05d1\u05de\u05d5\u05d7 \u05e9\u05de\u05d6\u05e8\u05d9\u05de\u05d9\u05dd \u05d3\u05dd \u05e0\u05e7\u05d9 \u05de\u05e7\u05d5\u05e8\u05d8\u05d9\u05d6\u05d5\u05dc (\u05d4\u05d5\u05e8\u05de\u05d5\u05df \u05d4\u05dc\u05d7\u05e5) \u05d5\u05db\u05dc \u05d4\u05d2\u05d5\u05e3 \u05e0\u05e8\u05d2\u05e2.\n\u05dc\u05db\u05df \u05d0\u05e0\u05d5 \u05de\u05ea\u05d7\u05d9\u05dc\u05d9\u05dd \u05d0\u05ea \u05d1\u05e8\u05db\u05d5\u05ea \u05d4\u05e9\u05d7\u05e8 \u05d1\u05d1\u05e8\u05db\u05d4:\n"\u05d0\u05dc\u05d5\u05e7\u05d9, \u05e0\u05e9\u05de\u05d4 \u05e9\u05e0\u05ea\u05ea \u05d1\u05d9 \u05d8\u05d4\u05d5\u05e8\u05d4 \u05d4\u05d9\u05d0\u2026 \u05d5\u05d0\u05ea\u05d4 \u05e0\u05e4\u05d7\u05ea\u05d4 \u05d1\u05d9". \u05d0\u05e0\u05d5 \u05de\u05d0\u05e4\u05e9\u05e8\u05d9\u05dd \u05dc\u05e2\u05e6\u05de\u05e0\u05d5 \u05dc\u05d4\u05ea\u05d7\u05d1\u05e8 \u05dc\u05ea\u05d5\u05d3\u05e2\u05d4 \u05e9\u05d4\u05db\u05d0\u05d1 \u05e9\u05dc \u05d4\u05e2\u05d1\u05e8 \u05dc\u05d0 \u05d7\u05d9\u05d9\u05d1 \u05dc\u05d4\u05de\u05e9\u05d9\u05da \u05dc\u05d4\u05ea\u05dc\u05d5\u05d5\u05ea \u05dc\u05d7\u05d5\u05d5\u05d9\u05d9\u05ea \u05d4\u05d7\u05d9\u05d9\u05dd \u05e9\u05dc\u05e0\u05d5. \u05d0\u05e4\u05e9\u05e8 \u05dc\u05d4\u05e9\u05d0\u05d9\u05e8 \u05d0\u05d5\u05ea\u05d5 \u05de\u05d0\u05d7\u05d5\u05e8.\n\u05d4\u05e8\u05d5\u05d7 \u05d5\u05d4\u05e0\u05e9\u05de\u05d4 \u05d0\u05d9\u05e0\u05df \u05e8\u05e7 \u05e8\u05e2\u05d9\u05d5\u05df \u05de\u05d5\u05e4\u05e9\u05d8. \u05d4\u05df \u05d4\u05e0\u05e9\u05d9\u05de\u05d4 \u05e2\u05e6\u05de\u05d4, \u05d7\u05d5\u05d5\u05d9\u05ea \u05d4\u05d7\u05d9\u05d9\u05dd \u05d0\u05d5\u05ea\u05d4 \u05d0\u05d3\u05dd \u05d4\u05e8\u05d0\u05e9\u05d5\u05df \u05e8\u05e6\u05d4 \u05dc\u05d7\u05d5\u05d5\u05ea \u05de\u05e2\u05e5 \u05d4\u05d3\u05e2\u05ea \u05e7\u05e6\u05ea \u05dc\u05e4\u05e0\u05d9 \u05d4\u05d6\u05de\u05df \u05d4\u05e0\u05db\u05d5\u05df \u05d1\u05d2\u05df \u05e2\u05d3\u05df. \u05d0\u05da \u05d4\u05d5\u05d0 \u05dc\u05d0 \u05d4\u05d1\u05d9\u05df \u05e9\u05d7\u05d5\u05d5\u05d9\u05ea \u05d4\u05d7\u05d9\u05d9\u05dd \u05d0\u05d9\u05e0\u05d4 \u05e0\u05de\u05e6\u05d0\u05ea \u05e8\u05e7 \u05d1\u05d4\u05d1\u05d3\u05dc\u05d4 \u05d0\u05d5 \u05d1\u05d7\u05d5\u05d5\u05d9\u05d4 \u05d4\u05e9\u05db\u05dc\u05d9\u05ea \u05d4\u05d9\u05d0 \u05e0\u05de\u05e6\u05d0\u05ea \u05d1\u05d0\u05d9\u05d6\u05d5\u05df \u05d5\u05d1\u05d7\u05d9\u05d1\u05d5\u05e8 \u05d1\u05d9\u05df \u05d4\u05e9\u05db\u05dc \u05dc\u05e8\u05d2\u05e9. \u05d0\u05ea \u05d4\u05d7\u05d9\u05d1\u05d5\u05e8 \u05d4\u05d6\u05d4 \u05d0\u05e0\u05d5 \u05d9\u05d5\u05e6\u05e8\u05d9\u05dd \u05d1\u05ea\u05e4\u05d9\u05dc\u05d4.\n\u05d6\u05d4\u05d5 \u05e7\u05e6\u05d1 \u05d0\u05d5 \u05e0\u05e9\u05de\u05ea \u05d4\u05d7\u05d9\u05d9\u05dd \u05d4\u05d6\u05d5\u05e8\u05de\u05ea \u05d1\u05d2\u05d5\u05e3. \u05db\u05e9\u05d0\u05d3\u05dd \u05de\u05ea\u05e4\u05dc\u05dc, \u05e0\u05d5\u05e9\u05dd, \u05d0\u05d5\u05de\u05e8 \u05de\u05d9\u05dc\u05d9\u05dd \u05d5\u05d7\u05d5\u05e9\u05d1 \u05e2\u05dc \u05de\u05e9\u05de\u05e2\u05d5\u05ea\u05df \u05d1\u05d7\u05d9\u05d9\u05d5 \u05e9\u05dc\u05d5, \u05e9\u05e8 - \u05d4\u05d5\u05d0 \u05de\u05e4\u05e2\u05d9\u05dc \u05d0\u05ea \u05de\u05e2\u05e8\u05db\u05ea \u05d4\u05e2\u05e6\u05d1\u05d9\u05dd, \u05d0\u05ea \u05d4\u05e8\u05d2\u05e9 \u05d5\u05d0\u05ea \u05d4\u05d6\u05d9\u05db\u05e8\u05d5\u05df. \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05e0\u05e2\u05e9\u05d9\u05ea \u05de\u05e2\u05d9\u05df \u05e2\u05d9\u05e6\u05d5\u05d1 \u05de\u05d7\u05d3\u05e9 \u05e9\u05dc \u05d4\u05e8\u05e9\u05de\u05d9\u05dd \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05d9\u05dd.\n\u05dc\u05db\u05df \u05d3\u05d5\u05d3 \u05d4\u05de\u05dc\u05da \u05de\u05ea\u05d0\u05e8 \u05d0\u05ea \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05db\u05da:\n"\u05d5\u05db\u05dc \u05e7\u05e8\u05d1 \u05d5\u05db\u05dc\u05d9\u05d5\u05ea \u05d9\u05d6\u05de\u05e8\u05d5 \u05dc\u05e9\u05de\u05da".\n\u05d4\u05db\u05dc\u05d9\u05d5\u05ea \u05d1\u05dc\u05e9\u05d5\u05df \u05d4\u05de\u05e7\u05e8\u05d0 \u05d4\u05df \u05de\u05e7\u05d5\u05dd \u05d4\u05de\u05d5\u05e1\u05e8 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9. \u05db\u05dc\u05d5\u05de\u05e8, \u05d2\u05dd \u05d4\u05de\u05e7\u05d5\u05de\u05d5\u05ea \u05d4\u05e2\u05de\u05d5\u05e7\u05d9\u05dd \u05d5\u05d4\u05e0\u05e1\u05ea\u05e8\u05d9\u05dd \u05e9\u05dc \u05d4\u05d0\u05d3\u05dd \u05de\u05e6\u05d8\u05e8\u05e4\u05d9\u05dd \u05dc\u05e9\u05d9\u05e8\u05d4.\n\u05d5\u05d1\u05de\u05e7\u05d5\u05dd \u05d0\u05d7\u05e8 \u05d4\u05d5\u05d0 \u05d0\u05d5\u05de\u05e8:\n"\u05db\u05dc \u05e2\u05e6\u05de\u05d5\u05ea\u05d9 \u05ea\u05d0\u05de\u05e8\u05e0\u05d4 \u05d4\' \u05de\u05d9 \u05db\u05de\u05d5\u05da".\n\u05dc\u05d0 \u05e8\u05e7 \u05d4\u05e4\u05d4 \u05de\u05ea\u05e4\u05dc\u05dc. \u05d4\u05d2\u05d5\u05e3 \u05db\u05d5\u05dc\u05d5 \u05de\u05ea\u05e4\u05dc\u05dc. \u05d4\u05e2\u05e6\u05de\u05d5\u05ea, \u05d4\u05e0\u05e9\u05d9\u05de\u05d4, \u05d4\u05dc\u05d1 \u05d5\u05d4\u05e7\u05e8\u05d1\u05d9\u05d9\u05dd - \u05db\u05dc \u05d4\u05d2\u05d5\u05e3 \u05e0\u05e2\u05e9\u05d4 \u05db\u05dc\u05d9 \u05dc\u05e9\u05d9\u05e8\u05d4.\n\u05dc\u05e9\u05e4\u05d4 \u05de\u05d5\u05d3\u05e8\u05e0\u05d9\u05ea, \u05d0\u05e4\u05e9\u05e8 \u05dc\u05ea\u05e8\u05d2\u05dd \u05db\u05da:\n\u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d4\u05d9\u05d0 \u05e8\u05d2\u05e2 \u05e9\u05d1\u05d5 \u05d4\u05d0\u05d3\u05dd \u05de\u05db\u05e0\u05d9\u05e1 \u05dc\u05ea\u05d5\u05da \u05d4\u05d6\u05d9\u05db\u05e8\u05d5\u05df \u05d5\u05d4\u05d2\u05d5\u05e3 \u05e9\u05dc\u05d5 \u05d7\u05d5\u05d5\u05d9\u05d4 \u05d7\u05d3\u05e9\u05d4 \u05e9\u05dc \u05de\u05e9\u05de\u05e2\u05d5\u05ea, \u05d0\u05de\u05d5\u05df \u05d5\u05d7\u05d9\u05d1\u05d5\u05e8. \u05d4\u05d7\u05d5\u05d5\u05d9\u05d4 \u05d4\u05d6\u05d5 \u05d9\u05db\u05d5\u05dc\u05d4 \u05dc\u05d4\u05d7\u05dc\u05d9\u05e9 \u05e4\u05d7\u05d3\u05d9\u05dd \u05d5\u05e8\u05e9\u05de\u05d9\u05dd \u05e7\u05d5\u05d3\u05de\u05d9\u05dd \u05d5\u05dc\u05d4\u05d8\u05d1\u05d9\u05e2 \u05d1\u05de\u05e7\u05d5\u05de\u05dd \u05e8\u05d5\u05e9\u05dd \u05d0\u05d7\u05e8.\n\u05dc\u05db\u05df \u05d1\u05ea\u05d5\u05e8\u05ea \u05d4\u05d7\u05e1\u05d9\u05d3\u05d5\u05ea \u05de\u05d3\u05d1\u05e8\u05d9\u05dd \u05e2\u05dc \u05db\u05da \u05e9\u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d4\u05d9\u05d0 \u05e2\u05d1\u05d5\u05d3\u05d4 \u05e9\u05d1\u05dc\u05d1 - \u05dc\u05d0 \u05e8\u05e7 \u05d1\u05e7\u05e9\u05d4, \u05d0\u05dc\u05d0 \u05ea\u05d4\u05dc\u05d9\u05da \u05e9\u05d1\u05d5 \u05d4\u05d0\u05d3\u05dd \u05de\u05e9\u05e0\u05d4 \u05d0\u05ea \u05de\u05e6\u05d1 \u05d4\u05ea\u05d5\u05d3\u05e2\u05d4 \u05e9\u05dc\u05d5, \u05d5\u05de\u05d8\u05d1\u05d9\u05e2 \u05d1\u05e0\u05e4\u05e9\u05d5 \u05d5\u05d1\u05d2\u05d5\u05e4\u05d5 \u05e8\u05d5\u05e9\u05dd \u05d7\u05d3\u05e9 \u05e9\u05dc \u05e7\u05e8\u05d1\u05d4 \u05dc\u05e2\u05e6\u05de\u05d5 \u05d5\u05dc\u05d1\u05d5\u05e8\u05d0\u05d5, \u05e9\u05de\u05d7\u05d4 \u05d5\u05d7\u05d9\u05d9\u05dd.\n_----------------------------------\n"\u05d5\u05ea\u05e6\u05d9\u05dc\u05e0\u05d9 \u05d4\u05d9\u05d5\u05dd \u05d5\u05d1\u05db\u05dc \u05d9\u05d5\u05dd \u05de\u05e9\u05d8\u05df \u05d4\u05de\u05e9\u05d7\u05d9\u05ea, \u05d5\u05de\u05d3\u05d9\u05df \u05e7\u05e9\u05d4, \u05d5\u05de\u05d1\u05e2\u05dc \u05d3\u05d9\u05df \u05e7\u05e9\u05d4, \u05d1\u05d9\u05df \u05e9\u05d4\u05d5\u05d0 \u05d1\u05df \u05d1\u05e8\u05d9\u05ea \u05d5\u05d1\u05d9\u05df \u05e9\u05d0\u05d9\u05e0\u05d5 \u05d1\u05df \u05d1\u05e8\u05d9\u05ea"\n\u05e0\u05d5\u05e9\u05d0 \u05de\u05e9\u05de\u05e2\u05d5\u05ea \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea \u05e2\u05de\u05d5\u05e7\u05d4, \u05d5\u05e0\u05d9\u05ea\u05df \u05dc\u05e2\u05e1\u05d5\u05e7 \u05d1\u05d5 \u05d3\u05e8\u05da \u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d5\u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea \u05e4\u05e0\u05d9\u05de\u05d9\u05ea.\n\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d6\u05d5 \u05d0\u05d9\u05e0\u05d4 \u05e8\u05e7 \u05d1\u05e7\u05e9\u05d4 \u05dc\u05d4\u05d9\u05e0\u05e6\u05dc \u05de\u05d2\u05d5\u05e8\u05de\u05d9\u05dd \u05d7\u05d9\u05e6\u05d5\u05e0\u05d9\u05d9\u05dd \u05e9\u05dc\u05d9\u05dc\u05d9\u05d9\u05dd, \u05d0\u05dc\u05d0 \u05d2\u05dd \u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea \u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05d1\u05db\u05d5\u05d7\u05d5\u05ea \u05e9\u05d1\u05ea\u05d5\u05db\u05e0\u05d5:\n"\u05de\u05e9\u05d8\u05df \u05d4\u05de\u05e9\u05d7\u05d9\u05ea" - \u05de\u05d9\u05d9\u05e6\u05d2 \u05d0\u05ea \u05d4\u05e7\u05d5\u05dc \u05d4\u05e4\u05e0\u05d9\u05de\u05d9 \u05e9\u05de\u05e4\u05ea\u05d4 \u05d0\u05d5\u05ea\u05e0\u05d5 \u05dc\u05d1\u05d7\u05d5\u05e8 \u05d1\u05d3\u05e8\u05da \u05e9\u05dc \u05d4\u05e8\u05e1 \u05e2\u05e6\u05de\u05d9, \u05e4\u05d7\u05d3, \u05d0\u05d5 \u05e9\u05e0\u05d0\u05d4. \u05d6\u05d4\u05d5 "\u05d4\u05d9\u05e6\u05e8" \u05e9\u05de\u05e8\u05d7\u05d9\u05e7 \u05d0\u05d5\u05ea\u05e0\u05d5 \u05de\u05d4\u05de\u05d4\u05d5\u05ea \u05d4\u05d0\u05de\u05d9\u05ea\u05d9\u05ea \u05e9\u05dc\u05e0\u05d5.\n"\u05de\u05d3\u05d9\u05df \u05e7\u05e9\u05d4" - \u05de\u05e1\u05de\u05dc \u05e9\u05d9\u05e4\u05d5\u05d8 \u05e2\u05e6\u05de\u05d9 \u05e7\u05e9\u05d4, \u05d0\u05d5 \u05de\u05e6\u05d1\u05d9\u05dd \u05e9\u05d1\u05d4\u05dd \u05d0\u05e0\u05d5 \u05d7\u05d5\u05d5\u05d9\u05dd \u05d1\u05d9\u05e7\u05d5\u05e8\u05ea \u05d7\u05d9\u05e6\u05d5\u05e0\u05d9\u05ea \u05d0\u05d5 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05d7\u05e8\u05d9\u05e4\u05d4, \u05e9\u05dc\u05e2\u05ea\u05d9\u05dd \u05e4\u05d5\u05d2\u05e2\u05ea \u05d1\u05e0\u05e4\u05e9\u05e0\u05d5 \u05d5\u05d1\u05d9\u05db\u05d5\u05dc\u05ea\u05e0\u05d5 \u05dc\u05d2\u05d3\u05d5\u05dc.\n"\u05de\u05d1\u05e2\u05dc \u05d3\u05d9\u05df \u05e7\u05e9\u05d4" - \u05de\u05d9\u05d9\u05e6\u05d2 \u05d0\u05ea \u05d4\u05d4\u05ea\u05de\u05d5\u05d3\u05d3\u05d5\u05ea \u05e2\u05dd \u05e1\u05db\u05e1\u05d5\u05db\u05d9\u05dd \u05d0\u05d5 \u05d0\u05e0\u05e9\u05d9\u05dd \u05e7\u05e9\u05d9\u05dd, \u05d0\u05da \u05d2\u05dd \u05d0\u05ea \u05d4"\u05de\u05d1\u05e7\u05e8 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9" \u05d1\u05ea\u05d5\u05db\u05e0\u05d5, \u05d0\u05d5\u05ea\u05d5 \u05e7\u05d5\u05dc \u05e9\u05de\u05e2\u05e8\u05e2\u05e8 \u05e2\u05dc \u05d4\u05dc\u05d2\u05d9\u05d8\u05d9\u05de\u05d9\u05d5\u05ea \u05e9\u05dc\u05e0\u05d5.\n"\u05d1\u05d9\u05df \u05e9\u05d4\u05d5\u05d0 \u05d1\u05df \u05d1\u05e8\u05d9\u05ea \u05d5\u05d1\u05d9\u05df \u05e9\u05d0\u05d9\u05e0\u05d5 \u05d1\u05df \u05d1\u05e8\u05d9\u05ea" - \u05de\u05d3\u05d2\u05d9\u05e9 \u05e9\u05d4\u05d0\u05ea\u05d2\u05e8\u05d9\u05dd \u05d9\u05db\u05d5\u05dc\u05d9\u05dd \u05dc\u05d4\u05d2\u05d9\u05e2 \u05de\u05de\u05e7\u05d5\u05de\u05d5\u05ea \u05e6\u05e4\u05d5\u05d9\u05d9\u05dd \u05db\u05de\u05d5 \u05d4\u05d0\u05d5\u05d9\u05d1\u05d9\u05dd \u05e9\u05dc\u05e0\u05d5 \u05de\u05d7\u05d5\u05e5 \u05d0\u05d5 \u05de\u05d1\u05dc\u05ea\u05d9 \u05e6\u05e4\u05d5\u05d9\u05d9\u05dd \u05db\u05de\u05d5 \u05d4\u05e7\u05e8\u05d5\u05d1\u05d9\u05dd \u05dc\u05e0\u05d5 \u05d1\u05d9\u05d5\u05ea\u05e8. \u05d4\u05d0\u05e0\u05e9\u05d9\u05dd \u05d4\u05d0\u05d4\u05d5\u05d1\u05d9\u05dd \u05e2\u05dc\u05d9\u05e0\u05d5 \u05d0\u05d1\u05dc \u05e9\u05d9\u05e9 \u05dc\u05e0\u05d5 \u05d9\u05d7\u05e1\u05d9\u05dd \u05e8\u05e2\u05d9\u05dc\u05d9\u05dd \u05d0\u05d9\u05ea\u05dd. \u05e9\u05dc \u05d0\u05d5\u05dc\u05d9 \u05e7\u05e0\u05d0\u05d4 \u05e1\u05de\u05d5\u05d9\u05d4, \u05e9\u05ea\u05dc\u05d8\u05e0\u05d5\u05ea \u05d5\u05e2\u05d5\u05d3.. \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d4\u05d9\u05d0 \u05d2\u05dd \u05e9\u05e0\u05d4\u05d9\u05d4 \u05de\u05d5\u05db\u05e0\u05d9\u05dd \u05de\u05d6\u05d4 \u05d0\u05d1\u05dc \u05d2\u05dd \u05e9\u05dc\u05d0 \u05e0\u05e9\u05d7\u05e7 \u05ea\u05e4\u05e7\u05d9\u05d3 \u05e8\u05e2\u05d9\u05dc \u05d1\u05d7\u05d9\u05d9\u05dd \u05e9\u05dc \u05d0\u05d7\u05e8\u05d9\u05dd. \u05e9\u05e0\u05d9\u05ea\u05df \u05db\u05d5\u05d7\u05d5\u05ea \u05d0\u05d7\u05d3 \u05dc\u05e9\u05e0\u05d9 \u05dc\u05e6\u05de\u05d5\u05d7 \u05d5\u05dc\u05d4\u05ea\u05e4\u05ea\u05d7\n\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05ea \u05d4\u05d8\u05de\u05e2\u05d4 "\u05d4\u05ea\u05d7\u05d1\u05e8\u05d5\u05ea \u05dc\u05de\u05d2\u05df \u05d4\u05e4\u05e0\u05d9\u05de\u05d9"\n\u05de\u05d5\u05de\u05dc\u05e5 \u05dc\u05e9\u05d1\u05ea \u05d1\u05e9\u05e7\u05d8, \u05d1\u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05e2\u05e6\u05d5\u05de\u05d5\u05ea. \u05d0\u05e4\u05d9\u05dc\u05d5 \u05dc\u05d2\u05dc\u05d2\u05dc \u05d0\u05ea \u05d4\u05d0\u05d9\u05e9\u05d5\u05e0\u05d9\u05dd \u05db\u05dc\u05e4\u05d9 \u05de\u05e2\u05dc\u05d4. \u05e4\u05e2\u05d5\u05dc\u05d4 \u05d6\u05d5 \u05de\u05d0\u05e4\u05e9\u05e8\u05ea \u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea \u05ea\u05ea \u05de\u05d5\u05d3\u05e2\u05ea \u05e2\u05de\u05d5\u05e7\u05d4 \u05d9\u05d5\u05ea\u05e8\n\u05e9\u05dc\u05d1 \u05e8\u05d0\u05e9\u05d5\u05df \u2013 \u05e0\u05e9\u05d9\u05de\u05d4 \u05de\u05d5\u05d3\u05e2\u05ea:\n\u05d4\u05ea\u05d7\u05dc/\u05d9 \u05d1\u05e9\u05d0\u05d9\u05e4\u05d5\u05ea \u05d5\u05e0\u05e9\u05d9\u05e4\u05d5\u05ea \u05e2\u05de\u05d5\u05e7\u05d5\u05ea \u05d5\u05d0\u05d9\u05d8\u05d9\u05d5\u05ea. \u05d1\u05db\u05dc \u05e0\u05e9\u05d9\u05e4\u05d4 \u05e9\u05d7\u05e8\u05e8/\u05d9 \u05de\u05ea\u05d7\u05d9\u05dd, \u05e4\u05d7\u05d3\u05d9\u05dd \u05d5\u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05e9\u05d9\u05e4\u05d5\u05d8\u05d9\u05d5\u05ea.\n\u05e9\u05dc\u05d1 \u05e9\u05e0\u05d9 \u2013 \u05d4\u05d3\u05de\u05d9\u05d4:\n\u05d3\u05de\u05d9\u05d9\u05df/\u05d9 \u05d0\u05d5\u05e8 \u05e8\u05da \u05d5\u05d6\u05d5\u05d4\u05e8 \u05d4\u05de\u05e7\u05d9\u05e3 \u05d0\u05d5\u05ea\u05da \u2013 \u05db\u05de\u05d5 \u05de\u05d2\u05df \u05d0\u05e0\u05e8\u05d2\u05d8\u05d9. \u05d6\u05d4\u05d5 "\u05d4\u05de\u05d2\u05df \u05d4\u05d0\u05dc\u05d5\u05d4\u05d9" \u05e9\u05e9\u05d5\u05de\u05e8 \u05e2\u05dc\u05d9\u05da \u05de\u05e9\u05d8\u05df \u05d4\u05de\u05e9\u05d7\u05d9\u05ea, \u05de\u05d3\u05d9\u05df \u05e7\u05e9\u05d4 \u05d5\u05de\u05d1\u05e2\u05dc \u05d3\u05d9\u05df \u05e7\u05e9\u05d4.\n\u05e9\u05dc\u05d1 \u05e9\u05dc\u05d9\u05e9\u05d9 \u2013 \u05d7\u05d9\u05d6\u05d5\u05e7 \u05e4\u05e0\u05d9\u05de\u05d9:\n\u05d7\u05d6\u05d5\u05e8/\u05d9 \u05d1\u05dc\u05d1\u05da:\n"\u05d0\u05e0\u05d9 \u05de\u05d5\u05d2\u05df/\u05ea. \u05d0\u05e0\u05d9 \u05e4\u05d5\u05e2\u05dc/\u05ea \u05de\u05ea\u05d5\u05da \u05d7\u05de\u05dc\u05d4. \u05d0\u05d9\u05e0\u05d9 \u05e9\u05d5\u05e4\u05d8/\u05ea \u05d0\u05ea \u05e2\u05e6\u05de\u05d9 \u05d0\u05d5 \u05d0\u05ea \u05d6\u05d5\u05dc\u05ea\u05d9. \u05d0\u05e0\u05d9 \u05de\u05ea\u05e0\u05d4\u05dc/\u05ea \u05d1\u05d9\u05d5\u05e9\u05e8, \u05d1\u05d0\u05d5\u05e8 \u05d5\u05d1\u05e9\u05dc\u05d5\u05dd."\n\u05e9\u05dc\u05d1 \u05e8\u05d1\u05d9\u05e2\u05d9 \u2013 \u05d1\u05e7\u05e9\u05ea \u05d7\u05e1\u05d3:\n\u05d1\u05e7\u05e9/\u05d9:\n"\u05d0\u05e0\u05d0 \u05d4\', \u05ea\u05e6\u05d9\u05dc\u05e0\u05d9 \u05d4\u05d9\u05d5\u05dd \u05d5\u05d1\u05db\u05dc \u05d9\u05d5\u05dd \u05de\u05d4\u05db\u05d5\u05d7\u05d5\u05ea \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05d9\u05dd \u05d5\u05d4\u05d7\u05d9\u05e6\u05d5\u05e0\u05d9\u05d9\u05dd \u05e9\u05de\u05e8\u05d7\u05d9\u05e7\u05d9\u05dd \u05d0\u05d5\u05ea\u05d9 \u05de\u05de\u05da. \u05e2\u05d6\u05d5\u05e8 \u05dc\u05d9 \u05dc\u05e4\u05e2\u05d5\u05dc \u05de\u05ea\u05d5\u05da \u05d0\u05d4\u05d1\u05d4, \u05d0\u05de\u05d5\u05e0\u05d4 \u05d5\u05d0\u05d9\u05d6\u05d5\u05df."\n\u05e1\u05d9\u05d5\u05dd:\n\u05d7\u05d6\u05d5\u05e8/\u05d9 \u05dc\u05e0\u05e9\u05d9\u05de\u05d4 \u05e8\u05d2\u05d9\u05dc\u05d4, \u05e4\u05ea\u05d7/\u05d9 \u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05dc\u05d0\u05d8, \u05d5\u05d4\u05e8\u05d2\u05e9/\u05d9 \u05d0\u05ea \u05d4\u05d4\u05d2\u05e0\u05d4 \u05de\u05de\u05e9\u05d9\u05db\u05d4 \u05dc\u05dc\u05d5\u05d5\u05ea \u05d0\u05d5\u05ea\u05da \u05d1\u05d9\u05d5\u05dd.\n\u05d7\u05e1\u05d3 \u05e9\u05d0\u05d9\u05e0\u05d5 \u05d8\u05d5\u05d1 \u2013 \u05d2\u05dd \u05de\u05d4\u05d1\u05d5\u05e8\u05d0?\n\u05db\u05df. \u05dc\u05d0 \u05de\u05e4\u05e0\u05d9 \u05e9\u05d4\u05d1\u05d5\u05e8\u05d0 \u05e0\u05d5\u05ea\u05df \u05e8\u05e2 \u05d7\u05dc\u05d9\u05dc\u05d4 \u2013 \u05d0\u05dc\u05d0 \u05de\u05e4\u05e0\u05d9 \u05e9\u05d4\u05d8\u05d5\u05d1 \u05e9\u05d4\u05d5\u05d0 \u05e0\u05d5\u05ea\u05df \u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05e2\u05d5\u05d1\u05e8 \u05d3\u05e8\u05db\u05e0\u05d5 \u05d0\u05d5 \u05de\u05d2\u05d9\u05e2 \u05d0\u05dc\u05d9\u05e0\u05d5 \u05d1\u05e6\u05d5\u05e8\u05d4 \u05e9\u05dc\u05d0 \u05de\u05ea\u05d0\u05d9\u05de\u05d4 \u05dc\u05e0\u05d5 \u05d1\u05d0\u05d5\u05ea\u05d5 \u05e8\u05d2\u05e2.\n\u05dc\u05d3\u05d5\u05d2\u05de\u05d4:\n\u05d0\u05d3\u05dd \u05de\u05d1\u05e7\u05e9 \u05e9\u05e4\u05e2 \u05db\u05dc\u05db\u05dc\u05d9, \u05d5\u05d4\u05d1\u05d5\u05e8\u05d0 \u05e9\u05d5\u05dc\u05d7 \u05dc\u05d5 \u05d4\u05d6\u05d3\u05de\u05e0\u05d5\u05ea. \u05d0\u05d1\u05dc \u05d0\u05dd \u05d4\u05e0\u05e4\u05e9 \u05e9\u05dc\u05d5 \u05e2\u05d3\u05d9\u05d9\u05df \u05de\u05d7\u05d5\u05d1\u05e8\u05ea \u05dc\u05e4\u05d7\u05d3\u05d9\u05dd, \u05dc\u05db\u05e2\u05e1\u05d9\u05dd, \u05dc\u05d7\u05d5\u05e1\u05e8 \u05d2\u05d1\u05d5\u05dc\u05d5\u05ea \u2013 \u05d4\u05d4\u05d6\u05d3\u05de\u05e0\u05d5\u05ea \u05d4\u05d6\u05d0\u05ea \u05ea\u05db\u05d1\u05d9\u05d3 \u05e2\u05dc\u05d9\u05d5, \u05ea\u05d1\u05dc\u05d1\u05dc \u05d0\u05d5\u05ea\u05d5, \u05d0\u05d5 \u05ea\u05d2\u05e8\u05d5\u05dd \u05dc\u05d5 \u05dc\u05d0\u05d1\u05d3 \u05d0\u05ea \u05e2\u05e6\u05de\u05d5.\n\u05d0\u05d3\u05dd \u05de\u05d1\u05e7\u05e9 \u05d0\u05d4\u05d1\u05d4, \u05d5\u05d1\u05d5\u05e8\u05d0 \u05e2\u05d5\u05dc\u05dd \u05de\u05d6\u05de\u05df \u05dc\u05d5 \u05e7\u05e9\u05e8. \u05d0\u05d1\u05dc \u05d0\u05dd \u05d4\u05d5\u05d0 \u05dc\u05d0 \u05d1\u05e9\u05dc, \u05d0\u05d5 \u05e9\u05d4\u05e7\u05e9\u05e8 \u05de\u05d2\u05d9\u05e2 \u05d1\u05dc\u05d9 \u05d4\u05db\u05e0\u05d4 \u05e8\u05d2\u05e9\u05d9\u05ea \u05d0\u05d5 \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea \u2013 \u05d6\u05d4 \u05e2\u05dc\u05d5\u05dc \u05dc\u05d4\u05e4\u05d5\u05da \u05dc\u05e1\u05e2\u05e8\u05ea \u05e0\u05e4\u05e9 \u05d5\u05dc\u05d0 \u05dc\u05d1\u05e8\u05db\u05d4.\n\u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05d0\u05e4\u05d9\u05dc\u05d5 \u05d4\u05d0\u05e8\u05d4 \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea \u05e4\u05ea\u05d0\u05d5\u05de\u05d9\u05ea \u05e2\u05dc\u05d5\u05dc\u05d4 \u05dc\u05d4\u05d6\u05d9\u05e7 \u2013 \u05db\u05de\u05d5 \u05d0\u05d5\u05e8 \u05d7\u05d6\u05e7 \u05de\u05d3\u05d9 \u05dc\u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05e9\u05dc\u05d0 \u05d4\u05ea\u05e8\u05d2\u05dc\u05d5.\n\u05de\u05d4\u05d5 "\u05d2\u05d5\u05de\u05dc \u05d7\u05e1\u05d3\u05d9\u05dd \u05d8\u05d5\u05d1\u05d9\u05dd"?\n\u05db\u05d9\u05e6\u05d3 \u05d7\u05e1\u05d3\u05d9\u05dd \u05d9\u05db\u05d5\u05dc\u05d9\u05dd \u05dc\u05d4\u05d9\u05d5\u05ea \u05dc\u05d0 \u05d8\u05d5\u05d1\u05d9\u05dd?\n\u05d4\u05d1\u05d9\u05d8\u05d5\u05d9 "\u05d2\u05d5\u05de\u05dc \u05d7\u05e1\u05d3\u05d9\u05dd \u05d8\u05d5\u05d1\u05d9\u05dd" \u05de\u05ea\u05d5\u05da \u05ea\u05e4\u05d9\u05dc\u05ea \u05d4\u05e2\u05de\u05d9\u05d3\u05d4 \u05de\u05dc\u05de\u05d3 \u05e9\u05d9\u05e9 \u05d4\u05d1\u05d3\u05dc \u05d1\u05d9\u05df "\u05d7\u05e1\u05d3" \u05e1\u05ea\u05dd \u05dc\u05d1\u05d9\u05df "\u05d7\u05e1\u05d3 \u05d8\u05d5\u05d1". \u05d0\u05dd \u05d9\u05e9 \u05d7\u05e1\u05d3 \u05d8\u05d5\u05d1 \u2013 \u05de\u05e9\u05de\u05e2 \u05e9\u05d9\u05e9 \u05d2\u05dd \u05d7\u05e1\u05d3 \u05e9\u05d0\u05d9\u05e0\u05d5 \u05d8\u05d5\u05d1. \u05e0\u05e9\u05de\u05e2 \u05de\u05d5\u05d6\u05e8 \u2013 \u05d7\u05e1\u05d3 \u05d4\u05e8\u05d9 \u05d4\u05d5\u05d0 \u05d3\u05d1\u05e8 \u05d7\u05d9\u05d5\u05d1\u05d9, \u05dc\u05d0? \u05d0\u05d9\u05da \u05d9\u05db\u05d5\u05dc \u05dc\u05d4\u05d9\u05d5\u05ea \u05e9\u05d7\u05e1\u05d3 \u05d0\u05d9\u05e0\u05d5 \u05d8\u05d5\u05d1?\n\u05d7\u05e1\u05d3 \u05e9\u05d0\u05d9\u05e0\u05d5 \u05d8\u05d5\u05d1 - \u05d2\u05dd \u05de\u05d4\u05d1\u05d5\u05e8\u05d0?\n\u05db\u05df. \u05dc\u05d0 \u05de\u05e4\u05e0\u05d9 \u05e9\u05d4\u05d1\u05d5\u05e8\u05d0 \u05e0\u05d5\u05ea\u05df \u05e8\u05e2 \u05d7\u05dc\u05d9\u05dc\u05d4 \u2013 \u05d0\u05dc\u05d0 \u05de\u05e4\u05e0\u05d9 \u05e9\u05d4\u05d8\u05d5\u05d1 \u05e9\u05d4\u05d5\u05d0 \u05e0\u05d5\u05ea\u05df \u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05e2\u05d5\u05d1\u05e8 \u05d3\u05e8\u05db\u05e0\u05d5 \u05d0\u05d5 \u05de\u05d2\u05d9\u05e2 \u05d0\u05dc\u05d9\u05e0\u05d5 \u05d1\u05e6\u05d5\u05e8\u05d4 \u05e9\u05dc\u05d0 \u05de\u05ea\u05d0\u05d9\u05de\u05d4 \u05dc\u05e0\u05d5 \u05d1\u05d0\u05d5\u05ea\u05d5 \u05e8\u05d2\u05e2.\n\u05dc\u05d3\u05d5\u05d2\u05de\u05d4:\n\u05d0\u05d3\u05dd \u05de\u05d1\u05e7\u05e9 \u05e9\u05e4\u05e2 \u05db\u05dc\u05db\u05dc\u05d9, \u05d5\u05d4\u05d1\u05d5\u05e8\u05d0 \u05e9\u05d5\u05dc\u05d7 \u05dc\u05d5 \u05d4\u05d6\u05d3\u05de\u05e0\u05d5\u05ea. \u05d0\u05d1\u05dc \u05d0\u05dd \u05d4\u05e0\u05e4\u05e9 \u05e9\u05dc\u05d5 \u05e2\u05d3\u05d9\u05d9\u05df \u05de\u05d7\u05d5\u05d1\u05e8\u05ea \u05dc\u05e4\u05d7\u05d3\u05d9\u05dd, \u05dc\u05db\u05e2\u05e1\u05d9\u05dd, \u05dc\u05d7\u05d5\u05e1\u05e8 \u05d2\u05d1\u05d5\u05dc\u05d5\u05ea \u2013 \u05d4\u05d4\u05d6\u05d3\u05de\u05e0\u05d5\u05ea \u05d4\u05d6\u05d0\u05ea \u05ea\u05db\u05d1\u05d9\u05d3 \u05e2\u05dc\u05d9\u05d5, \u05ea\u05d1\u05dc\u05d1\u05dc \u05d0\u05d5\u05ea\u05d5, \u05d0\u05d5 \u05ea\u05d2\u05e8\u05d5\u05dd \u05dc\u05d5 \u05dc\u05d0\u05d1\u05d3 \u05d0\u05ea \u05e2\u05e6\u05de\u05d5.\n\u05d0\u05d3\u05dd \u05de\u05d1\u05e7\u05e9 \u05d0\u05d4\u05d1\u05d4, \u05d5\u05d1\u05d5\u05e8\u05d0 \u05e2\u05d5\u05dc\u05dd \u05de\u05d6\u05de\u05df \u05dc\u05d5 \u05e7\u05e9\u05e8. \u05d0\u05d1\u05dc \u05d0\u05dd \u05d4\u05d5\u05d0 \u05dc\u05d0 \u05d1\u05e9\u05dc, \u05d0\u05d5 \u05e9\u05d4\u05e7\u05e9\u05e8 \u05de\u05d2\u05d9\u05e2 \u05d1\u05dc\u05d9 \u05d4\u05db\u05e0\u05d4 \u05e8\u05d2\u05e9\u05d9\u05ea \u05d0\u05d5 \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea \u2013 \u05d6\u05d4 \u05e2\u05dc\u05d5\u05dc \u05dc\u05d4\u05e4\u05d5\u05da \u05dc\u05e1\u05e2\u05e8\u05ea \u05e0\u05e4\u05e9 \u05d5\u05dc\u05d0 \u05dc\u05d1\u05e8\u05db\u05d4.\n\u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05d0\u05e4\u05d9\u05dc\u05d5 \u05d4\u05d0\u05e8\u05d4 \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea \u05e4\u05ea\u05d0\u05d5\u05de\u05d9\u05ea \u05e2\u05dc\u05d5\u05dc\u05d4 \u05dc\u05d4\u05d6\u05d9\u05e7 \u2013 \u05db\u05de\u05d5 \u05d0\u05d5\u05e8 \u05d7\u05d6\u05e7 \u05de\u05d3\u05d9 \u05dc\u05e2\u05d9\u05e0\u05d9\u05d9\u05dd .\n\u05d0\u05e0\u05d5 \u05e0\u05d5\u05d8\u05d9\u05dd \u05dc\u05d1\u05e7\u05e9 \u05e0\u05e1\u05d9\u05dd. \u05d5\u05d2\u05dd \u05dc\u05d4\u05d5\u05d3\u05d5\u05ea \u05e2\u05dc \u05d4\u05db\u05dc. \u05d0\u05d1\u05dc \u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05e0\u05e1 \u05e9\u05d1\u05d9\u05e7\u05e9\u05e0\u05d5 \u05e9\u05e7\u05d9\u05d1\u05dc\u05e0\u05d5 \u05d9\u05db\u05d5\u05dc \u05dc\u05e9\u05d7\u05e7 \u05ea\u05e4\u05e7\u05d9\u05d3 \u05e9\u05dc\u05d9\u05dc\u05d9 \u05d1\u05d7\u05d9\u05d9\u05e0\u05d5 \u05db\u05d9 \u05e9\u05db\u05d7\u05e0\u05d5 \u05dc\u05d1\u05e7\u05e9 \u05d7\u05e1\u05d3\u05d9\u05dd \u05d8\u05d5\u05d1\u05d9\u05dd.\n\u05dc\u05db\u05df \u05d1\u05e2\u05d5\u05de\u05e7 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9 \u05e9\u05dc \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4, \u05d0\u05e0\u05d7\u05e0\u05d5 \u05de\u05d1\u05e7\u05e9\u05d9\u05dd:\n\u05dc\u05d0 \u05e8\u05e7 \u05d7\u05e1\u05d3. \u05d7\u05e1\u05d3 \u05d8\u05d5\u05d1.\n\u05d7\u05e1\u05d3 \u05e9\u05de\u05d2\u05d9\u05e2 \u05d1\u05e2\u05d9\u05ea\u05d5\u05d9 \u05d4\u05de\u05d3\u05d5\u05d9\u05e7.\n\u05d7\u05e1\u05d3 \u05e9\u05de\u05ea\u05d7\u05e9\u05d1 \u05d1\u05de\u05d1\u05e0\u05d4 \u05d4\u05e0\u05e4\u05e9\u05d9 \u05e9\u05dc\u05e0\u05d5.\n\u05d7\u05e1\u05d3 \u05e9\u05dc\u05d0 \u05e9\u05d5\u05e4\u05da \u05e2\u05dc\u05d9\u05e0\u05d5 \u05d0\u05d5\u05e8 \u05de\u05e1\u05e0\u05d5\u05d5\u05e8, \u05d0\u05dc\u05d0 \u05de\u05d3\u05dc\u05d9\u05e7 \u05d1\u05ea\u05d5\u05db\u05e0\u05d5 \u05e0\u05d9\u05e6\u05d5\u05e5 \u05e2\u05d3\u05d9\u05df, \u05e9\u05e0\u05d5\u05db\u05dc \u05dc\u05e9\u05d0\u05ea.\n\u05db\u05d9 \u05d0\u05d5\u05e8 \u05e9\u05dc\u05d0 \u05de\u05d5\u05ea\u05d0\u05dd \u2013 \u05e2\u05dc\u05d5\u05dc \u05dc\u05e1\u05e0\u05d5\u05d5\u05e8.\n\u05e9\u05e4\u05e2 \u05dc\u05d0 \u05de\u05d3\u05d5\u05d3 \u2013 \u05e2\u05dc\u05d5\u05dc \u05dc\u05d4\u05e6\u05d9\u05e3.\n\u05d0\u05d4\u05d1\u05d4 \u05e9\u05de\u05d2\u05d9\u05e2\u05d4 \u05de\u05d5\u05e7\u05d3\u05dd \u05de\u05d3\u05d9 \u2013 \u05e2\u05dc\u05d5\u05dc\u05d4 \u05dc\u05e9\u05d1\u05d5\u05e8.\n\u05d5\u05dc\u05db\u05df \u05d0\u05e0\u05d7\u05e0\u05d5 \u05de\u05ea\u05e4\u05dc\u05dc\u05d9\u05dd \u2013 \u05de\u05ea\u05d5\u05da \u05e1\u05e4\u05d9\u05e8\u05ea \u05d4\u05d4\u05d5\u05d3:\n"\u05ea\u05df \u05dc\u05d9 \u05d7\u05e1\u05d3\u05d9\u05dd \u05d8\u05d5\u05d1\u05d9\u05dd. \u05dc\u05d0 \u05dc\u05e4\u05d9 \u05d2\u05d5\u05d3\u05dc\u05da \u2013 \u05d0\u05dc\u05d0 \u05dc\u05e4\u05d9 \u05d9\u05db\u05d5\u05dc\u05ea\u05d9 \u05dc\u05d4\u05db\u05d9\u05dc."\n\u05d4\u05d5\u05d3 \u05d4\u05d9\u05d0 \u05d4\u05de\u05d9\u05d3\u05d4 \u05e9\u05de\u05db\u05d9\u05e8\u05d4 \u05d1\u05de\u05d5\u05d2\u05d1\u05dc\u05d5\u05ea, \u05d5\u05d3\u05d5\u05d5\u05e7\u05d0 \u05de\u05ea\u05d5\u05db\u05d4 \u2013 \u05de\u05d1\u05e7\u05e9\u05ea \u05d1\u05e2\u05d3\u05d9\u05e0\u05d5\u05ea:\n\u05e8\u05e7 \u05de\u05d4 \u05e9\u05d0\u05e0\u05d9 \u05d9\u05db\u05d5\u05dc \u05dc\u05e9\u05d0\u05ea, \u05e8\u05e7 \u05de\u05d4 \u05e9\u05d9\u05e8\u05e4\u05d0, \u05d5\u05dc\u05d0 \u05d9\u05db\u05d1\u05d9\u05d3 \u05d0\u05d5 \u05d1\u05e2\u05dc \u05d4\u05e9\u05dc\u05db\u05d5\u05ea \u05e9\u05dc\u05d9\u05dc\u05d9\u05d5\u05ea \u05d1\u05e2\u05ea\u05d9\u05d3\n\u05d6\u05d5\u05d4\u05d9 \u05d1\u05e7\u05e9\u05d4 \u05e2\u05d3\u05d9\u05e0\u05d4:\n\u05d0\u05dc \u05ea\u05d9\u05ea\u05df \u05dc\u05d9 \u05e1\u05ea\u05dd \u05d7\u05e1\u05d3\u05d9\u05dd \u2013 \u05ea\u05df \u05dc\u05d9 \u05d7\u05e1\u05d3 \u05d8\u05d5\u05d1.\n\u05d7\u05e1\u05d3 \u05e9\u05de\u05ea\u05d0\u05d9\u05dd \u05dc\u05e0\u05e9\u05de\u05d4 \u05e9\u05dc\u05d9. \u05dc\u05e2\u05d9\u05db\u05d5\u05dc \u05e9\u05dc\u05d9. \u05dc\u05e2\u05d9\u05ea\u05d5\u05d9 \u05e9\u05dc\u05d9.\n\u05d7\u05e1\u05d3 \u05e9\u05d0\u05e0\u05d9 \u05d0\u05d5\u05db\u05dc \u05dc\u05d4\u05db\u05d9\u05dc \u05d0\u05d5\u05ea\u05d5, \u05dc\u05d4\u05db\u05d9\u05e8 \u05d1\u05d5, \u05dc\u05d4\u05d5\u05d3\u05d5\u05ea \u05e2\u05dc\u05d9\u05d5, \u05d5\u05dc\u05e6\u05de\u05d5\u05d7 \u05de\u05de\u05e0\u05d5.\n\u05d6\u05d5 \u05d1\u05e7\u05e9\u05d4 \u05e9\u05de\u05dc\u05d0\u05d4 \u05d1\u05d4\u05d5\u05d3.\n\u05d1\u05d4\u05db\u05e8\u05ea \u05de\u05e7\u05d5\u05de\u05d9. \u05db\u05d9\u05d5\u05d5\u05df \u05e9\u05d4\u05d5\u05d3 \u05d4\u05d5\u05d0 \u05d2\u05dd \u05d4\u05d5\u05d3\u05d0\u05d4 \u05e2\u05dc \u05de\u05e7\u05d5\u05de\u05d9.\n\u05d1\u05d4\u05d1\u05e0\u05d4 \u05e9\u05d0\u05e0\u05d9 \u05dc\u05d0 \u05de\u05d1\u05e7\u05e9 \u05dc\u05e7\u05d1\u05dc \u05e8\u05e7 \u05db\u05d9 \u05de\u05d2\u05d9\u05e2 \u05dc\u05d9, \u05d0\u05dc\u05d0 \u05de\u05ea\u05d5\u05da \u05e2\u05e0\u05d5\u05d5\u05d4 \u05e9\u05dc \u05ea\u05dc\u05de\u05d9\u05d3 \u05e9\u05de\u05d1\u05e7\u05e9 \u05dc\u05dc\u05de\u05d5\u05d3 \u05d0\u05ea \u05d4\u05d7\u05e1\u05d3 \u2013 \u05dc\u05d0 \u05e8\u05e7 \u05dc\u05e7\u05d1\u05dc\u05d5.\n\u05d4\u05e7\u05e9\u05e8 \u05dc\u05e1\u05e4\u05d9\u05e8\u05ea \u05d4\u05d5\u05d3\n\u05d4\u05d5\u05d3 \u05d4\u05d9\u05d0 \u05d4\u05d9\u05db\u05d5\u05dc\u05ea \u05dc\u05e8\u05d0\u05d5\u05ea \u05d0\u05ea \u05d4\u05d0\u05d5\u05e8 \u2013 \u05d2\u05dd \u05db\u05e9\u05d4\u05d5\u05d0 \u05e7\u05d8\u05df, \u05e9\u05d1\u05e8\u05d9\u05e8\u05d9, \u05d0\u05d5 \u05d7\u05d1\u05d5\u05d9.\n\u05d4\u05d5\u05d3 \u05d4\u05d9\u05d0 \u05dc\u05d4\u05d5\u05d3\u05d5\u05ea \u05d2\u05dd \u05e2\u05dc \u05de\u05d4 \u05e9\u05e2\u05d5\u05d3 \u05dc\u05d0 \u05d1\u05e8\u05d5\u05e8.\n\u05dc\u05d4\u05d9\u05d5\u05ea \u05d1\u05e0\u05d5\u05db\u05d7\u05d5\u05ea \u05e9\u05dc \u05e7\u05d1\u05dc\u05d4, \u05d5\u05dc\u05d4\u05ea\u05e4\u05dc\u05dc:\n\u05e8\u05d9\u05d1\u05d5\u05e0\u05d5 \u05e9\u05dc \u05e2\u05d5\u05dc\u05dd, \u05d2\u05de\u05d5\u05dc \u05dc\u05d9 \u05d7\u05e1\u05d3\u05d9\u05dd \u2013 \u05d0\u05d1\u05dc \u05d2\u05de\u05d5\u05dc \u05dc\u05d9 \u05d7\u05e1\u05d3\u05d9\u05dd \u05d8\u05d5\u05d1\u05d9\u05dd.\n\u05d8\u05d5\u05d1\u05d9\u05dd \u05d1\u05d0\u05de\u05ea.\n\u05db\u05d0\u05dc\u05d4 \u05e9\u05d0\u05d5\u05db\u05dc \u05dc\u05e2\u05de\u05d5\u05d3 \u05d1\u05d4\u05dd, \u05dc\u05d2\u05d3\u05d5\u05dc \u05de\u05d4\u05dd, \u05d5\u05dc\u05d7\u05d9\u05d5\u05ea \u05d1\u05ea\u05d5\u05db\u05dd \u05d1\u05d0\u05de\u05ea.\n\u05d7\u05e1\u05d3 \u05e9\u05d0\u05d9\u05e0\u05d5 \u05d8\u05d5\u05d1 \u2013 \u05de\u05d4\u05d5?\n\u05d7\u05e1\u05d3 \u05e9\u05d0\u05d9\u05e0\u05d5 \u05d8\u05d5\u05d1 \u05d4\u05d5\u05d0 \u05d7\u05e1\u05d3 \u05e9\u05d0\u05d9\u05e0\u05d5 \u05e8\u05d2\u05d9\u05e9. \u05d6\u05d4\u05d5 \u05d7\u05e1\u05d3 \u05e9\u05e0\u05d5\u05ea\u05df \u05de\u05de\u05e7\u05d5\u05dd \u05e9\u05dc \u05db\u05d5\u05d7, \u05dc\u05d0 \u05de\u05de\u05e7\u05d5\u05dd \u05e9\u05dc \u05d4\u05e7\u05e9\u05d1\u05d4.\n\u05d7\u05e1\u05d3 \u05e9\u05de\u05e8\u05d7\u05dd \u05d9\u05ea\u05e8 \u05e2\u05dc \u05d4\u05de\u05d9\u05d3\u05d4 \u05d5\u05de\u05d5\u05e0\u05e2 \u05de\u05d4\u05de\u05e7\u05d1\u05dc \u05dc\u05d4\u05ea\u05e4\u05ea\u05d7 \u05d1\u05e2\u05e6\u05de\u05d5.\n\u05d7\u05e1\u05d3 \u05e9\u05d1\u05d0 \u05de\u05de\u05e7\u05d5\u05dd \u05e9\u05dc \u05e6\u05d5\u05e8\u05da \u05dc\u05d4\u05d9\u05d5\u05ea "\u05d4\u05de\u05d5\u05e9\u05d9\u05e2", \u05d5\u05dc\u05d0 \u05de\u05de\u05e7\u05d5\u05dd \u05e9\u05dc \u05d0\u05d4\u05d1\u05d4 \u05e0\u05d8\u05d5\u05dc\u05ea \u05d0\u05d2\u05d5.\n\u05d7\u05e1\u05d3 \u05e9\u05dc\u05d0 \u05de\u05d1\u05d3\u05d9\u05dc \u05d1\u05d9\u05df \u05de\u05d4 \u05e9\u05e0\u05db\u05d5\u05df \u05dc\u05ea\u05ea \u05dc\u05d1\u05d9\u05df \u05de\u05d4 \u05e9\u05e2\u05dc\u05d5\u05dc \u05dc\u05d4\u05d6\u05d9\u05e7 \u2013 \u05db\u05de\u05d5 \u05dc\u05ea\u05ea \u05db\u05e1\u05e3 \u05dc\u05d0\u05d3\u05dd \u05e9\u05de\u05ea\u05de\u05d5\u05d3\u05d3 \u05e2\u05dd \u05d4\u05ea\u05de\u05db\u05e8\u05d5\u05ea, \u05d0\u05d5 \u05dc\u05d4\u05e6\u05d9\u05dc \u05de\u05d9\u05e9\u05d4\u05d5 \u05de\u05ea\u05d5\u05e6\u05d0\u05d4 \u05e9\u05dc \u05de\u05e2\u05e9\u05d9\u05d5 \u05d1\u05de\u05e7\u05d5\u05dd \u05dc\u05d0\u05e4\u05e9\u05e8 \u05dc\u05d5 \u05dc\u05e9\u05d0\u05ea \u05d1\u05d0\u05d7\u05e8\u05d9\u05d5\u05ea \u05d5\u05dc\u05e6\u05de\u05d5\u05d7.\n\u05d6\u05d4\u05d5 \u05d7\u05e1\u05d3 \u05e9\u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05e9\u05d5\u05db\u05d7 \u05d0\u05ea \u05d4\u05d2\u05d1\u05d5\u05dc\u05d5\u05ea, \u05d0\u05ea \u05d4\u05d4\u05e7\u05e9\u05e8, \u05d0\u05ea \u05d4\u05d0\u05d3\u05dd \u05e9\u05de\u05d5\u05dc\u05d5 \u2013 \u05d5\u05e0\u05d5\u05ea\u05df \u05e8\u05e7 \u05db\u05d9 "\u05db\u05da \u05e6\u05e8\u05d9\u05da", \u05d1\u05dc\u05d9 \u05d1\u05d0\u05de\u05ea \u05dc\u05e4\u05d2\u05d5\u05e9 \u05d0\u05ea \u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea.\n\u05d5\u05de\u05d4\u05d5 "\u05d7\u05e1\u05d3 \u05d8\u05d5\u05d1"?\n\u05d6\u05d4\u05d5 \u05d7\u05e1\u05d3 \u05e9\u05d9\u05e9 \u05d1\u05d5 \u05e8\u05d2\u05d9\u05e9\u05d5\u05ea. \u05e9\u05d4\u05d5\u05d0 \u05de\u05d3\u05d5\u05d3. \u05e9\u05d4\u05d5\u05d0 \u05de\u05d1\u05d5\u05e1\u05e1 \u05e2\u05dc \u05d4\u05e7\u05e9\u05d1\u05d4, \u05e2\u05dc \u05e2\u05e0\u05d5\u05d5\u05d4, \u05e2\u05dc \u05e8\u05d0\u05d9\u05d9\u05ea \u05d4\u05d0\u05d3\u05dd \u05d5\u05dc\u05d0 \u05e8\u05e7 \u05d0\u05ea \u05d4\u05e0\u05ea\u05d9\u05e0\u05d4.\n\u05d6\u05d4 \u05d7\u05e1\u05d3 \u05e9\u05de\u05e9\u05d9\u05d1 \u05d4\u05d5\u05d3, \u05e9\u05de\u05db\u05d1\u05d3. \u05e9\u05de\u05e8\u05e4\u05d0.\n\u05d6\u05d4 \u05d7\u05e1\u05d3 \u05e9\u05e0\u05d9\u05ea\u05df \u05de\u05de\u05e7\u05d5\u05dd \u05e9\u05dc \u05d7\u05d9\u05d1\u05d5\u05e8 \u2013 \u05dc\u05d0 \u05e8\u05e7 \u05de\u05ea\u05d5\u05da \u05d7\u05d5\u05d1\u05d4, \u05d0\u05dc\u05d0 \u05de\u05ea\u05d5\u05da \u05e0\u05d5\u05db\u05d7\u05d5\u05ea \u05d5\u05d0\u05db\u05e4\u05ea\u05d9\u05d5\u05ea.\n\u05e1\u05e4\u05d9\u05e8\u05ea \u05d4\u05d4\u05d5\u05d3 \u05d4\u05d9\u05d0 \u05de\u05d9\u05d3\u05d4 \u05e9\u05dc \u05d4\u05db\u05e0\u05e2\u05d4, \u05e9\u05dc \u05e2\u05e0\u05d5\u05d5\u05d4, \u05e9\u05dc \u05e0\u05d5\u05db\u05d7\u05d5\u05ea \u05e9\u05e7\u05d8\u05d4.\n\u05d7\u05e1\u05d3 \u05e9\u05e0\u05d9\u05ea\u05df \u05de\u05ea\u05d5\u05da \u05d4\u05d5\u05d3 \u2013 \u05d4\u05d5\u05d0 \u05d7\u05e1\u05d3 \u05e9\u05d0\u05d9\u05e0\u05d5 "\u05e9\u05d5\u05e4\u05da \u05d0\u05d5\u05e8" \u05d0\u05dc\u05d0 \u05de\u05d0\u05d9\u05e8 \u05d1\u05e8\u05d5\u05da. \u05d4\u05d5\u05d0 \u05d0\u05d9\u05e0\u05d5 \u05db\u05d5\u05e4\u05d4 \u05d0\u05ea \u05e2\u05e6\u05de\u05d5 \u05d0\u05dc\u05d0 \u05de\u05d0\u05e4\u05e9\u05e8.\n\u05d4\u05d5\u05d3 \u05de\u05d6\u05db\u05d9\u05e8 \u05dc\u05e0\u05d5 \u05e9\u05d4\u05db\u05d5\u05d7 \u05d4\u05d0\u05de\u05d9\u05ea\u05d9 \u05d1\u05e0\u05ea\u05d9\u05e0\u05d4 \u05d4\u05d5\u05d0 \u05d3\u05d5\u05d5\u05e7\u05d0 \u05d1\u05e4\u05e9\u05d8\u05d5\u05ea, \u05d1\u05d0\u05d9-\u05d4\u05e9\u05dc\u05d9\u05d8\u05d4, \u05d1\u05d4\u05d5\u05d3\u05d9\u05d4 \u05e2\u05dc \u05d4\u05d6\u05db\u05d5\u05ea \u05dc\u05ea\u05ea \u2013 \u05d5\u05dc\u05d0 \u05d1\u05ea\u05d7\u05d5\u05e9\u05ea \u05d4"\u05d0\u05e0\u05d9 \u05d4\u05de\u05d5\u05e9\u05d9\u05e2".\n"\u05d2\u05d5\u05de\u05dc \u05d7\u05e1\u05d3\u05d9\u05dd \u05d8\u05d5\u05d1\u05d9\u05dd" \u05d4\u05d5\u05d0 \u05d6\u05d4 \u05e9\u05dc\u05d0 \u05e8\u05e7 \u05e0\u05d5\u05ea\u05df \u05d0\u05dc\u05d0 \u05e0\u05d5\u05ea\u05df \u05d1\u05de\u05e7\u05d5\u05dd \u05d5\u05d1\u05e6\u05d5\u05e8\u05d4 \u05d4\u05e0\u05db\u05d5\u05e0\u05d4\n\u05e9\u05d9\u05e9 \u05d1\u05d5 \u05d2\u05dd \u05d7\u05e1\u05d3, \u05d5\u05d2\u05dd \u05d4\u05d5\u05d3.\n\u05d4\u05d5\u05d0 \u05dc\u05d0 \u05e8\u05e7 \u05de\u05e2\u05e0\u05d9\u05e7 \u2013 \u05d4\u05d5\u05d0 \u05de\u05db\u05d1\u05d3 \u05d0\u05ea \u05e0\u05e9\u05de\u05ea\u05d5 \u05e9\u05dc \u05d4\u05de\u05e7\u05d1\u05dc.\n\u05d4\u05d5\u05d0 \u05dc\u05d0 \u05e8\u05e7 \u05de\u05d5\u05e9\u05d9\u05d8 \u05d9\u05d3 \u2013 \u05d4\u05d5\u05d0 \u05e8\u05d5\u05d0\u05d4 \u05d0\u05ea \u05d4\u05d0\u05d3\u05dd \u05e9\u05de\u05d5\u05dc\u05d5.\n\u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05d0\u05e0\u05d7\u05e0\u05d5 \u05de\u05d1\u05e7\u05e9\u05d9\u05dd \u05de\u05d4\u05d1\u05d5\u05e8\u05d0 \u05d8\u05d5\u05d1 \u2013 \u05d5\u05e8\u05d5\u05e6\u05d9\u05dd \u05dc\u05d4\u05d0\u05de\u05d9\u05df \u05e9\u05db\u05dc \u05d8\u05d5\u05d1 \u05e9\u05d9\u05d1\u05d5\u05d0 \u05de\u05de\u05e0\u05d5 \u05d9\u05d4\u05d9\u05d4 \u05d2\u05dd \u05e0\u05db\u05d5\u05df \u05d5\u05e0\u05e2\u05d9\u05dd \u05d5\u05de\u05e8\u05e4\u05d0.\n\u05d0\u05d1\u05dc \u05d4\u05d0\u05de\u05ea \u05d4\u05de\u05d5\u05e8\u05db\u05d1\u05ea \u05d9\u05d5\u05ea\u05e8 \u05d4\u05d9\u05d0 \u05e9\u05d2\u05dd \u05d8\u05d5\u05d1 \u05e9\u05de\u05d2\u05d9\u05e2 \u05de\u05dc\u05de\u05e2\u05dc\u05d4, \u05d0\u05dd \u05dc\u05d0 \u05de\u05ea\u05e7\u05d1\u05dc \u05d1\u05e0\u05e4\u05e9 \u05de\u05d5\u05db\u05e0\u05d4, \u05d0\u05d5 \u05d0\u05dd \u05dc\u05d0 \u05de\u05ea\u05d0\u05d9\u05dd \u05dc\u05e2\u05d9\u05ea\u05d5\u05d9, \u05e2\u05dc\u05d5\u05dc \u05dc\u05d4\u05e4\u05d5\u05da \u05dc\u05d7\u05e1\u05d3 \u05e9\u05d0\u05d9\u05e0\u05d5 \u05d8\u05d5\u05d1.\n\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05ea \u05d4\u05d8\u05de\u05e2\u05d4: \u05d7\u05e1\u05d3 \u05de\u05ea\u05d5\u05da \u05d4\u05d5\u05d3\n\u05de\u05e6\u05d0/\u05d9 \u05de\u05e7\u05d5\u05dd \u05e9\u05e7\u05d8, \u05e9\u05d1/\u05d9 \u05d1\u05e0\u05d5\u05d7\u05d5\u05ea. \u05e2\u05e6\u05de/\u05d9 \u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05d5\u05e0\u05e9\u05d5\u05dd/\u05d9 \u05e2\u05de\u05d5\u05e7 \u05e9\u05dc\u05d5\u05e9 \u05e0\u05e9\u05d9\u05de\u05d5\u05ea \u05de\u05dc\u05d0\u05d5\u05ea.\n1. \u05d4\u05ea\u05d7\u05d1\u05e8\u05d5\u05ea \u05dc\u05e0\u05e9\u05d9\u05de\u05d4:\n\u05e0\u05e9\u05d9\u05e4\u05d4 \u05d0\u05d9\u05d8\u05d9\u05ea\u2026 \u05e7\u05d1\u05dc\u05d4 \u05d0\u05d9\u05d8\u05d9\u05ea\u2026\n\u05d4\u05e0\u05e9\u05d9\u05de\u05d4 \u05e0\u05d5\u05e9\u05d0\u05ea \u05d0\u05d5\u05ea\u05da, \u05db\u05d0\u05d9\u05dc\u05d5 \u05d0\u05d5\u05de\u05e8\u05ea: "\u05d0\u05d9\u05df \u05e6\u05d5\u05e8\u05da \u05dc\u05d4\u05d7\u05d6\u05d9\u05e7. \u05e8\u05e7 \u05dc\u05d4\u05d9\u05d5\u05ea."\n2. \u05d4\u05db\u05e8\u05ea \u05de\u05e7\u05d5\u05dd \u05e4\u05e0\u05d9\u05de\u05d9:\n\u05d4\u05ea\u05d7\u05d1\u05e8/\u05d9 \u05e2\u05db\u05e9\u05d9\u05d5 \u05dc\u05e0\u05e7\u05d5\u05d3\u05d4 \u05d1\u05dc\u05d1, \u05d3\u05de\u05d9\u05d9\u05df/\u05d9 \u05e0\u05d9\u05e6\u05d5\u05e5 \u05e7\u05d8\u05df.\n\u05e9\u05d0\u05dc/\u05d9 \u05d0\u05ea \u05e2\u05e6\u05de\u05da:\n\u05de\u05d4 \u05d4\u05d7\u05e1\u05d3 \u05e9\u05d0\u05e0\u05d9 \u05de\u05d1\u05e7\u05e9/\u05ea \u05de\u05d4\u05d1\u05d5\u05e8\u05d0 \u05e2\u05db\u05e9\u05d9\u05d5?\n\u05de\u05d4 \u05d0\u05e0\u05d9 \u05de\u05e8\u05d2\u05d9\u05e9/\u05d4 \u05e9\u05d7\u05e1\u05e8 \u05dc\u05d9?\n3. \u05e9\u05d0\u05dc\u05ea \u05d4\u05d4\u05ea\u05d0\u05de\u05d4:\n\u05db\u05e2\u05ea \u05e9\u05d0\u05dc/\u05d9 \u05d1\u05e2\u05d3\u05d9\u05e0\u05d5\u05ea:\n\u05d4\u05d0\u05dd \u05d0\u05e0\u05d9 \u05de\u05d5\u05db\u05df/\u05d4 \u05d1\u05d0\u05de\u05ea \u05dc\u05e7\u05d1\u05dc \u05d0\u05ea \u05d6\u05d4?\n\u05de\u05d4 \u05d1\u05ea\u05d5\u05db\u05d9 \u05e6\u05e8\u05d9\u05da \u05dc\u05d4\u05ea\u05d0\u05e8\u05d2\u05df, \u05db\u05d3\u05d9 \u05dc\u05e7\u05d1\u05dc \u05d0\u05ea \u05d4\u05d7\u05e1\u05d3 \u05d4\u05d6\u05d4 \u05db\u05da \u05e9\u05d9\u05d4\u05d9\u05d4 \u05d8\u05d5\u05d1 \u05e2\u05d1\u05d5\u05e8\u05d9?\n4. \u05ea\u05e4\u05d9\u05dc\u05d4 \u05e9\u05e7\u05d8\u05d4 \u05de\u05ea\u05d5\u05da \u05d4\u05d5\u05d3:\n\u05dc\u05d7\u05d5\u05e9 \u05d1\u05d2\u05d5\u05e3 \u05e2\u05e0\u05d5\u05d5\u05d4, \u05d4\u05db\u05e8\u05d4 \u05d1\u05de\u05d5\u05d2\u05d1\u05dc\u05d5\u05ea, \u05d5\u05d2\u05dd \u05e0\u05db\u05d5\u05e0\u05d5\u05ea \u05dc\u05d4\u05ea\u05de\u05e1\u05e8.\n\u05d0\u05de\u05d5\u05e8/\u05d9 \u05d1\u05dc\u05d1:\n\u05e8\u05d9\u05d1\u05d5\u05e0\u05d5 \u05e9\u05dc \u05e2\u05d5\u05dc\u05dd, \u05d0\u05e0\u05d9 \u05de\u05d1\u05e7\u05e9/\u05ea \u05d7\u05e1\u05d3\n\u05d0\u05d1\u05dc \u05dc\u05d0 \u05db\u05dc \u05d7\u05e1\u05d3 \u2013 \u05d7\u05e1\u05d3 \u05d8\u05d5\u05d1.\n\u05db\u05d6\u05d4 \u05e9\u05d9\u05d0\u05d9\u05e8 \u05d5\u05dc\u05d0 \u05d9\u05e1\u05e0\u05d5\u05d5\u05e8\n\u05e9\u05d9\u05d1\u05d9\u05d0 \u05e6\u05de\u05d9\u05d7\u05d4, \u05d5\u05dc\u05d0 \u05d4\u05e6\u05e4\u05d4\n\u05e9\u05d9\u05e4\u05ea\u05d7 \u05d1\u05d9 \u05db\u05d5\u05d7\u05d5\u05ea, \u05d5\u05dc\u05d0 \u05d9\u05d3\u05e8\u05d5\u05e9 \u05de\u05d4 \u05e9\u05e2\u05d5\u05d3 \u05d0\u05d9\u05e0\u05d9 \u05de\u05e1\u05d5\u05d2\u05dc/\u05ea \u05dc\u05ea\u05ea.\n\u05ea\u05df \u05dc\u05d9 \u05d0\u05ea \u05d4\u05de\u05e0\u05d4 \u05d4\u05de\u05d3\u05d5\u05d9\u05e7\u05ea \u2013 \u05d1\u05d0\u05d4\u05d1\u05d4, \u05d1\u05d7\u05de\u05dc\u05d4, \u05d5\u05d1\u05ea\u05d6\u05de\u05d5\u05df \u05d4\u05e0\u05db\u05d5\u05df.\n\u05e2\u05d6\u05d5\u05e8 \u05dc\u05d9 \u05dc\u05d4\u05d9\u05d5\u05ea \u05e8\u05d0\u05d5\u05d9/\u05d4, \u05de\u05d5\u05db\u05df/\u05d4, \u05e4\u05ea\u05d5\u05d7/\u05d4.\n\u05d2\u05d5\u05de\u05dc \u05d7\u05e1\u05d3\u05d9\u05dd \u05d8\u05d5\u05d1\u05d9\u05dd \u2013 \u05d2\u05dd \u05dc\u05d9.\n5. \u05e1\u05d9\u05d5\u05dd:\n\u05d3\u05de\u05d9\u05d9\u05df/\u05d9 \u05d0\u05ea \u05d4\u05e0\u05d9\u05e6\u05d5\u05e5 \u05e9\u05d1\u05dc\u05d1 \u05d2\u05d3\u05dc \u05de\u05e2\u05d8. \u05dc\u05d0 \u05dc\u05d4\u05d1\u05d4, \u05e8\u05e7 \u05d0\u05d5\u05e8 \u05e7\u05d8\u05df.\n\u05db\u05d6\u05d4 \u05e9\u05d0\u05ea/\u05d4 \u05de\u05e1\u05d5\u05d2\u05dc/\u05ea \u05dc\u05d4\u05db\u05d9\u05dc.\n\u05e7\u05d7/\u05d9 \u05d0\u05d9\u05ea\u05da \u05d0\u05ea \u05d4\u05d0\u05d5\u05e8 \u05d4\u05d6\u05d4 \u05d0\u05dc \u05d4\u05d9\u05d5\u05dd \u05e9\u05dc\u05da.\n\u05d5\u05d4\u05d5\u05d3\u05d4/\u05d9. \u05e2\u05dc \u05de\u05d4 \u05e9\u05d9\u05e9, \u05d5\u05e2\u05dc \u05de\u05d4 \u05e9\u05d9\u05d1\u05d5\u05d0 \u2013 \u05d1\u05d8\u05d5\u05d1\n"\u05d0\u05d5\u05e8 \u05d7\u05d3\u05e9 \u05e2\u05dc \u05e6\u05d9\u05d5\u05df" \u05d4\u05d5\u05d0 \u05d1\u05d9\u05d8\u05d5\u05d9 \u05e9\u05de\u05d5\u05e4\u05d9\u05e2 \u05d1\u05de\u05e7\u05d5\u05e8\u05d5\u05ea \u05d9\u05d4\u05d5\u05d3\u05d9\u05d9\u05dd, \u05db\u05d5\u05dc\u05dc \u05d1\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d5\u05d1\u05e4\u05d9\u05d5\u05d8\u05d9\u05dd, \u05d5\u05d1\u05d0\u05d5\u05e4\u05df \u05de\u05e1\u05d5\u05e8\u05ea\u05d9 \u05de\u05d5\u05d1\u05df \u05db\u05d4\u05ea\u05d2\u05dc\u05d5\u05ea \u05de\u05d7\u05d5\u05d3\u05e9\u05ea \u05e9\u05dc \u05d0\u05d5\u05e8 \u05d0\u05dc\u05d5\u05e7\u05d9 \u05d0\u05d5 \u05ea\u05d5\u05d3\u05e2\u05d4 \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea \u05e2\u05dc \u05e2\u05dd \u05d9\u05e9\u05e8\u05d0\u05dc \u05d5\u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc, \u05d1\u05de\u05d9\u05d5\u05d7\u05d3 \u05d1\u05e6\u05d9\u05d5\u05df \u2013 \u05db\u05dc\u05d5\u05de\u05e8 \u05d1\u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd.\n\u05db\u05d0\u05e9\u05e8 \u05e0\u05d1\u05d7\u05df \u05d0\u05ea \u05d4\u05de\u05d5\u05e9\u05d2 \u05de\u05e0\u05e7\u05d5\u05d3\u05ea \u05de\u05d1\u05d8 \u05e9\u05dc \u05d4\u05ea\u05e4\u05ea\u05d7\u05d5\u05ea \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea, \u05e0\u05d9\u05ea\u05df \u05dc\u05e4\u05e8\u05e9 \u05d0\u05d5\u05ea\u05d5 \u05db\u05e9\u05dc\u05d1 \u05d7\u05d3\u05e9 \u05d0\u05d5 \u05ea\u05d5\u05d3\u05e2\u05d4 \u05d7\u05d3\u05e9\u05d4 \u05d1\u05ea\u05d4\u05dc\u05d9\u05da \u05d4\u05d4\u05ea\u05e7\u05d3\u05de\u05d5\u05ea \u05e9\u05dc \u05d4\u05d9\u05d7\u05d9\u05d3 \u05d0\u05d5 \u05d4\u05e7\u05d5\u05dc\u05e7\u05d8\u05d9\u05d1 \u05dc\u05e7\u05e8\u05d0\u05ea \u05de\u05d9\u05de\u05d5\u05e9 \u05e8\u05d5\u05d7\u05e0\u05d9.\n\u05e4\u05e8\u05e9\u05e0\u05d5\u05ea \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea \u2013 "\u05d0\u05d5\u05e8 \u05d7\u05d3\u05e9 \u05e2\u05dc \u05e6\u05d9\u05d5\u05df \u05ea\u05d0\u05d9\u05e8":\n1. \u05d0\u05d5\u05e8 \u05d7\u05d3\u05e9 \u2013 \u05ea\u05d5\u05d3\u05e2\u05d4 \u05d7\u05d3\u05e9\u05d4\n\u05d4"\u05d0\u05d5\u05e8 \u05d4\u05d7\u05d3\u05e9" \u05de\u05e1\u05de\u05dc \u05e9\u05dc\u05d1 \u05d7\u05d3\u05e9 \u05d1\u05ea\u05d5\u05d3\u05e2\u05d4, \u05d4\u05d0\u05e8\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05e9\u05dc\u05d0 \u05d4\u05d9\u05d9\u05ea\u05d4 \u05e7\u05d5\u05d3\u05dd. \u05de\u05d3\u05d5\u05d1\u05e8 \u05dc\u05d0 \u05d1\u05d0\u05d5\u05e8 \u05de\u05d5\u05db\u05e8 \u05d0\u05d5 \u05e9\u05d7\u05d5\u05d6\u05e8 \u05e2\u05dc \u05e2\u05e6\u05de\u05d5, \u05d0\u05dc\u05d0 \u05d1\u05d2\u05d9\u05dc\u05d5\u05d9 \u05e2\u05de\u05d5\u05e7 \u05d5\u05de\u05e8\u05d5\u05de\u05dd \u05d9\u05d5\u05ea\u05e8, \u05d0\u05d5\u05dc\u05d9 \u05d7\u05d9\u05d1\u05d5\u05e8 \u05dc\u05e8\u05d5\u05d1\u05d3 \u05d2\u05d1\u05d5\u05d4 \u05d9\u05d5\u05ea\u05e8 \u05e9\u05dc \u05d4\u05e0\u05e9\u05de\u05d4 \u05d0\u05d5 \u05e9\u05dc \u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea.\n\u05d6\u05d4\u05d5 \u05de\u05e2\u05d1\u05e8 \u05de\u05e8\u05d5\u05d1\u05d3 \u05d7\u05d9\u05e6\u05d5\u05e0\u05d9 \u05dc\u05e8\u05d5\u05d1\u05d3 \u05e4\u05e0\u05d9\u05de\u05d9, \u05de\u05de\u05d5\u05d3\u05e2\u05d5\u05ea \u05e9\u05dc \u05e4\u05d9\u05e8\u05d5\u05d3 \u05dc\u05de\u05d5\u05d3\u05e2\u05d5\u05ea \u05e9\u05dc \u05d0\u05d7\u05d3\u05d5\u05ea.\n2. \u05e6\u05d9\u05d5\u05df \u2013 \u05d4\u05dc\u05d1 \u05d0\u05d5 \u05de\u05e8\u05db\u05d6 \u05d4\u05ea\u05d5\u05d3\u05e2\u05d4\n"\u05e6\u05d9\u05d5\u05df" \u05d9\u05db\u05d5\u05dc\u05d4 \u05dc\u05d4\u05ea\u05e4\u05e8\u05e9 \u05dc\u05d0 \u05e8\u05e7 \u05db\u05de\u05e7\u05d5\u05dd \u05d2\u05d9\u05d0\u05d5\u05d2\u05e8\u05e4\u05d9 (\u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd), \u05d0\u05dc\u05d0 \u05d2\u05dd \u05db\u05e1\u05de\u05dc \u05e4\u05e0\u05d9\u05de\u05d9 \u05dc"\u05de\u05e8\u05db\u05d6 \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9" \u05e9\u05dc \u05d4\u05d0\u05d3\u05dd \u2013 \u05d4\u05dc\u05d1, \u05d4\u05e0\u05e7\u05d5\u05d3\u05d4 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05e9\u05d1\u05d4 \u05e9\u05d5\u05db\u05df \u05d4\u05e7\u05e9\u05e8 \u05d4\u05d9\u05e9\u05d9\u05e8 \u05e2\u05dd \u05d4\u05d0\u05dc\u05d5\u05d4\u05d5\u05ea.\n\u05d1\u05de\u05d5\u05d1\u05df \u05d6\u05d4, "\u05e6\u05d9\u05d5\u05df" \u05d4\u05d9\u05d0 \u05e0\u05e7\u05d5\u05d3\u05ea \u05d4\u05e6\u05d9\u05d5\u05df \u05e9\u05dc \u05d4\u05d0\u05d3\u05dd \u05d1\u05ea\u05d5\u05da \u05de\u05e1\u05e2 \u05d4\u05d4\u05ea\u05e4\u05ea\u05d7\u05d5\u05ea \u05e9\u05dc\u05d5 \u2013 \u05d4\u05de\u05e7\u05d5\u05dd \u05d1\u05d5 \u05d4\u05d5\u05d0 \u05e9\u05d5\u05d0\u05e3 \u05dc\u05d4\u05ea\u05d0\u05d7\u05d3 \u05e2\u05dd \u05d4\u05de\u05e7\u05d5\u05e8, \u05dc\u05d7\u05d5\u05d5\u05ea \u05d4\u05e9\u05e8\u05d0\u05d4 \u05d5\u05d4\u05db\u05d5\u05d5\u05e0\u05d4.\n3. \u05ea\u05d0\u05d9\u05e8 \u2013 \u05e4\u05e2\u05d5\u05dc\u05ea \u05d4\u05d4\u05e9\u05e4\u05e2\u05d4\n\u05d4\u05d0\u05d5\u05e8 \u05d0\u05d9\u05e0\u05d5 \u05e8\u05e7 \u05de\u05ea\u05d2\u05dc\u05d4 \u2013 \u05d4\u05d5\u05d0 "\u05de\u05d0\u05d9\u05e8", \u05db\u05dc\u05d5\u05de\u05e8 \u05e4\u05d5\u05e2\u05dc, \u05de\u05e9\u05e0\u05d4, \u05de\u05e9\u05e4\u05d9\u05e2 \u05e2\u05dc \u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea.\n\u05db\u05d0\u05e9\u05e8 \u05d0\u05d3\u05dd \u05d7\u05d5\u05d5\u05d4 "\u05d0\u05d5\u05e8 \u05d7\u05d3\u05e9", \u05d6\u05d4 \u05dc\u05d0 \u05e8\u05e7 \u05e9\u05d9\u05e0\u05d5\u05d9 \u05e4\u05e0\u05d9\u05de\u05d9 \u05d0\u05dc\u05d0 \u05d2\u05dd \u05d4\u05ea\u05d7\u05dc\u05d4 \u05e9\u05dc \u05e9\u05d9\u05e0\u05d5\u05d9 \u05d7\u05d9\u05e6\u05d5\u05e0\u05d9 \u2013 \u05e4\u05e2\u05d5\u05dc\u05ea \u05d4\u05d0\u05e8\u05d4 \u05e9\u05de\u05e7\u05e8\u05d9\u05e0\u05d4 \u05d4\u05d7\u05d5\u05e6\u05d4, \u05dc\u05d7\u05d1\u05e8\u05d4, \u05dc\u05e2\u05d5\u05dc\u05dd.\n\u05de\u05d2\u05dc\u05d5\u05ea \u05ea\u05d5\u05d3\u05e2\u05ea\u05d9\u05ea \u05d0\u05dc \u05d4\u05d2\u05d0\u05d5\u05dc\u05d4 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05ea\n\u05d1\u05e4\u05e1\u05d9\u05db\u05d5\u05dc\u05d5\u05d2\u05d9\u05d4 \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea, \u05d4\u05ea\u05e4\u05ea\u05d7\u05d5\u05ea \u05de\u05ea\u05d7\u05d9\u05dc\u05d4 \u05dc\u05e2\u05d9\u05ea\u05d9\u05dd \u05de\u05ea\u05d5\u05da \u05d7\u05d5\u05e9\u05da \u2013 \u05db\u05d0\u05d1, \u05d1\u05dc\u05d1\u05d5\u05dc, \u05d2\u05dc\u05d5\u05ea \u05e4\u05e0\u05d9\u05de\u05d9\u05ea.\n"\u05d0\u05d5\u05e8 \u05d7\u05d3\u05e9 \u05e2\u05dc \u05e6\u05d9\u05d5\u05df \u05ea\u05d0\u05d9\u05e8" \u05de\u05e6\u05d9\u05d9\u05df \u05d0\u05ea \u05d4\u05e8\u05d2\u05e2 \u05e9\u05d1\u05d5 \u05d0\u05d3\u05dd \u05d9\u05d5\u05e6\u05d0 \u05de\u05df \u05d4\u05d4\u05e1\u05ea\u05e8\u05d4 \u05d0\u05dc \u05d4\u05d2\u05d9\u05dc\u05d5\u05d9 \u2013 \u05d7\u05d5\u05d5\u05d4 \u05d4\u05d0\u05e8\u05d4, \u05d0\u05d5 \u05d4\u05d1\u05e0\u05d4 \u05d7\u05d3\u05e9\u05d4 \u05e9\u05de\u05e0\u05d9\u05e2\u05d4 \u05d0\u05d5\u05ea\u05d5 \u05dc\u05e7\u05e8\u05d0\u05ea \u05d9\u05d9\u05e2\u05d5\u05d3\u05d5.\n\u05de\u05d3\u05d5\u05d1\u05e8 \u05d1\u05d2\u05d0\u05d5\u05dc\u05d4 \u05dc\u05d0\u05d5\u05de\u05d9\u05ea \u05d0\u05da \u05d2\u05dd \u05d2\u05d0\u05d5\u05dc\u05d4 \u05d0\u05d9\u05e9\u05d9\u05ea - \u05d7\u05d9\u05d1\u05d5\u05e8 \u05de\u05d7\u05d5\u05d3\u05e9 \u05dc\u05d0\u05de\u05ea \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05ea, \u05dc\u05de\u05e1\u05dc\u05d5\u05dc \u05d4\u05e0\u05e9\u05de\u05ea\u05d9.\n\u05d4\u05e7\u05d1\u05dc\u05d4 \u05e8\u05d5\u05d0\u05d4 \u05d1\u05d0\u05d5\u05e8 \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9 \u05d0\u05ea \u05de\u05e7\u05d5\u05e8 \u05db\u05dc \u05d4\u05d4\u05d5\u05d5\u05d9\u05d4. \u05db\u05e9\u05d4\u05d0\u05d5\u05e8 \u05d4\u05d7\u05d3\u05e9 \u05de\u05d0\u05d9\u05e8 \u05d1\u05e6\u05d9\u05d5\u05df, \u05d4\u05db\u05d5\u05d5\u05e0\u05d4 \u05d4\u05d9\u05d0 \u05e9\u05d4\u05e9\u05e4\u05e2 \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9 \u05de\u05ea\u05d7\u05d9\u05dc \u05dc\u05d6\u05e8\u05d5\u05dd \u05d1\u05e6\u05d5\u05e8\u05d4 \u05d7\u05d3\u05e9\u05d4, \u05de\u05ea\u05d5\u05e7\u05e0\u05ea, \u05e9\u05dc\u05de\u05d4 \u05d9\u05d5\u05ea\u05e8.\n\u05d1\u05d7\u05e1\u05d9\u05d3\u05d5\u05ea \u05e0\u05d0\u05de\u05e8 \u05db\u05d9 "\u05e6\u05d9\u05d5\u05df" \u05d4\u05d9\u05d0 \u05e0\u05e7\u05d5\u05d3\u05ea \u05d4\u05e6\u05d3\u05d9\u05e7 \u05e9\u05d1\u05db\u05dc \u05d0\u05d3\u05dd \u2013 \u05d4\u05de\u05e7\u05d5\u05dd \u05e9\u05d1\u05d5 \u05e0\u05d5\u05db\u05d7\u05ea \u05d4\u05e0\u05e9\u05de\u05d4 \u05d4\u05d2\u05d1\u05d5\u05d4\u05d4, \u05d5\u05e9\u05dd \u05de\u05ea\u05e8\u05d7\u05e9\u05ea \u05d4\u05e2\u05d1\u05d5\u05d3\u05d4 \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9\u05ea \u05d4\u05d0\u05de\u05d9\u05ea\u05d9\u05ea.\n\u05d4\u05d0\u05d5\u05e8 \u05d4\u05d7\u05d3\u05e9 \u05d4\u05d5\u05d0 \u05d4\u05ea\u05d7\u05d3\u05e9\u05d5\u05ea \u05ea\u05de\u05d9\u05d3\u05d9\u05ea \u2013 \u05d0\u05d9\u05df \u05dc\u05e2\u05d5\u05dc\u05dd \u05d3\u05e8\u05da \u05dc\u05d4\u05ea\u05e7\u05d9\u05d9\u05dd \u05d1\u05dc\u05d9 \u05e9\u05d4\u05d0\u05d5\u05e8 \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9 \u05d9\u05ea\u05d7\u05d3\u05e9 \u05d1\u05d5. \u05db\u05e9\u05de\u05ea\u05d7\u05d1\u05e8\u05d9\u05dd \u05dc\u05db\u05da, \u05de\u05e8\u05d2\u05d9\u05e9\u05d9\u05dd \u05d7\u05d9\u05d5\u05ea, \u05d4\u05e9\u05e8\u05d0\u05d4, \u05d5\u05e9\u05de\u05d7\u05d4.\n\u05de\u05e1\u05e8 \u05de\u05e2\u05e9\u05d9:\n\u05d7\u05e4\u05e9 \u05d0\u05ea \u05d4"\u05e6\u05d9\u05d5\u05df" \u05d4\u05e4\u05e0\u05d9\u05de\u05d9 \u05e9\u05dc\u05da \u2013 \u05d0\u05ea \u05d4\u05de\u05e7\u05d5\u05dd \u05e9\u05d1\u05d5 \u05d0\u05ea\u05d4 \u05e9\u05d5\u05d0\u05e3 \u05dc\u05d0\u05de\u05ea, \u05dc\u05d8\u05d5\u05d1, \u05dc\u05e9\u05dc\u05de\u05d5\u05ea.\n\u05d4\u05d6\u05de\u05df \u05d0\u05ea \u05d4"\u05d0\u05d5\u05e8 \u05d4\u05d7\u05d3\u05e9" \u2013 \u05d3\u05e8\u05da \u05dc\u05d9\u05de\u05d5\u05d3, \u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4, \u05ea\u05e4\u05d9\u05dc\u05d4, \u05d0\u05d5 \u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea \u2013 \u05db\u05d3\u05d9 \u05e9\u05ea\u05d5\u05db\u05dc \u05dc\u05e8\u05d0\u05d5\u05ea \u05d0\u05ea \u05e2\u05e6\u05de\u05da \u05d5\u05d0\u05ea \u05d4\u05e2\u05d5\u05dc\u05dd \u05d0\u05d7\u05e8\u05ea.\n\u05d0\u05dc \u05ea\u05e1\u05ea\u05e4\u05e7 \u05d1\u05d0\u05d5\u05e8 \u05d9\u05e9\u05df \u2013 \u05db\u05dc \u05e9\u05dc\u05d1 \u05e8\u05d5\u05d7\u05e0\u05d9 \u05d3\u05d5\u05e8\u05e9 \u05d4\u05d0\u05e8\u05d4 \u05d7\u05d3\u05e9\u05d4, \u05ea\u05d5\u05d3\u05e2\u05d4 \u05de\u05ea\u05e4\u05ea\u05d7\u05ea, \u05d9\u05e6\u05d9\u05d0\u05d4 \u05de\u05d7\u05d5\u05e5 \u05dc\u05d0\u05d6\u05d5\u05e8\u05d9 \u05d4\u05e0\u05d5\u05d7\u05d5\u05ea.\n\u05ea\u05e9\u05d5\u05d1\u05d4 \u05e2\u05dc \u05d4\u05ea\u05e9\u05d5\u05d1\u05d4-\n\u05e7\u05d1\u05dc \u05d0\u05d5\u05e8 \u05d7\u05d3\u05e9 \u05de\u05dc\u05e2\u05e9\u05d5\u05ea \u05ea\u05e9\u05d5\u05d1\u05d4 \u05e2\u05dc \u05d4\u05ea\u05e9\u05d5\u05d1\u05d4. \u05de\u05d4 \u05d6\u05d4 \u05d0\u05d5\u05de\u05e8?\n\u05d4\u05ea\u05d5\u05e8\u05d4 \u05d4\u05d9\u05d0 \u05d0\u05d5\u05e8. \u05d0\u05d1\u05dc \u05d4\u05d9\u05d0 \u05d2\u05dd \u05d9\u05db\u05d5\u05dc\u05d4 \u05dc\u05d4\u05d9\u05d5\u05ea \u05d0\u05d5\u05e8 \u05de\u05e1\u05e0\u05d5\u05d5\u05e8. \u05d4\u05e7\u05d3\u05d5\u05e9\u05d4 \u05de\u05e9\u05d5\u05dc\u05d4 \u05dc\u05d0\u05e9. \u05d0\u05d1\u05dc \u05d0\u05e9 \u05d9\u05db\u05d5\u05dc\u05d4 \u05dc\u05d7\u05de\u05dd \u05d5\u05d9\u05db\u05d5\u05dc\u05d4 \u05dc\u05e9\u05e8\u05d5\u05e3. \u05d1\u05d3\u05d9\u05d5\u05e7 \u05db\u05de\u05d5 \u05d4\u05e9\u05de\u05e9. \u05dc\u05db\u05df \u05d7\u05d6\u05dc \u05d0\u05de\u05e8\u05d5 \u05e2\u05dc \u05d4\u05ea\u05d5\u05e8\u05d4 \u05d6\u05db\u05d4 \u05e0\u05e2\u05e9\u05ea\u05d4 \u05dc\u05d5 \u05e1\u05dd \u05d7\u05d9\u05d9\u05dd \u05dc\u05d0 \u05d6\u05db\u05d4 \u05e0\u05e2\u05e9\u05ea\u05d4 \u05dc\u05d5 \u05e1\u05dd \u05de\u05d5\u05d5\u05ea. \u05d0\u05d5\u05ea\u05d4 \u05ea\u05d5\u05e8\u05d4 \u05d9\u05db\u05d5\u05dc\u05d4 \u05dc\u05d4\u05d9\u05d5\u05ea \u05d0\u05d5 \u05d7\u05dc\u05d9\u05dc\u05d4 \u05dc\u05d4\u05d5\u05e8\u05d9\u05d3 \u05de\u05d4\u05d7\u05d9\u05d5\u05ea \u05e9\u05dc\u05e0\u05d5.\n\u05dc\u05db\u05df \u05e6\u05e8\u05d9\u05da \u05dc\u05d4\u05d9\u05d5\u05ea \u05d1\u05d1\u05d9\u05e8\u05d5\u05e8 \u05ea\u05de\u05d9\u05d3\u05d9 \u05de\u05d5\u05dc \u05e2\u05e6\u05de\u05e0\u05d5 \u05de\u05d4 \u05de\u05d7\u05d9\u05d4 \u05de\u05d5\u05e1\u05d9\u05e3 \u05d0\u05d5\u05e8 \u05dc\u05d7\u05d9\u05d9 \u05d5\u05de\u05d4 \u05dc\u05d0 .',"","")
B.KT=new A.cv(15,"\u05ea\u05e9\u05d5\u05d1\u05d4: \u05ea\u05d4\u05dc\u05d9\u05da \u05de\u05ea\u05de\u05e9\u05da",'\u05e8\u05d1\u05d9 \u05e0\u05d7\u05de\u05df \u05de\u05dc\u05de\u05d3 \u05d0\u05d5\u05ea\u05e0\u05d5 \u05e9\u05d4\u05ea\u05e9\u05d5\u05d1\u05d4 \u05d4\u05d9\u05d0 \u05ea\u05d4\u05dc\u05d9\u05da \u05de\u05ea\u05de\u05e9\u05da \u05d5\u05dc\u05d0 \u05e0\u05e7\u05d5\u05d3\u05d4 \u05e1\u05d5\u05e4\u05d9\u05ea. \u05dc\u05e2\u05d9\u05ea\u05d9\u05dd \u05d0\u05e0\u05d7\u05e0\u05d5 \u05d7\u05d5\u05e9\u05d1\u05d9\u05dd \u05e9\u05e2\u05e9\u05d9\u05e0\u05d5 "\u05ea\u05e9\u05d5\u05d1\u05d4" \u05d0\u05d5 \u05dc\u05e7\u05d7\u05e0\u05d5 \u05e2\u05dc \u05e2\u05e6\u05de\u05e0\u05d5 \u05e9\u05d9\u05e0\u05d5\u05d9 \u05e8\u05d5\u05d7\u05e0\u05d9, \u05d0\u05d1\u05dc \u05d1\u05e4\u05d5\u05e2\u05dc \u05d9\u05d9\u05ea\u05db\u05df \u05e9\u05d4\u05e6\u05e2\u05d3 \u05d4\u05d6\u05d4 \u05dc\u05d0 \u05d1\u05d0\u05de\u05ea \u05de\u05ea\u05d0\u05d9\u05dd \u05dc\u05de\u05e6\u05d1 \u05d4\u05e0\u05e4\u05e9\u05d9 \u05d0\u05d5 \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9 \u05e9\u05dc\u05e0\u05d5 \u05d1\u05d0\u05d5\u05ea\u05d5 \u05e8\u05d2\u05e2, \u05d0\u05d5 \u05e9\u05d4\u05d5\u05d0 \u05e2\u05d5\u05d3 \u05dc\u05d0 \u05d4\u05d2\u05d9\u05e2 \u05de\u05d1\u05e4\u05e0\u05d9\u05dd.\n\u05d4\u05de\u05e9\u05de\u05e2\u05d5\u05ea \u05d1\u05e4\u05d9\u05e8\u05d5\u05d8:\n\u05ea\u05e9\u05d5\u05d1\u05d4 \u05e8\u05d0\u05e9\u05d5\u05e0\u05d9\u05ea: \u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05d0\u05d3\u05dd \u05e2\u05d5\u05e9\u05d4 \u05ea\u05e9\u05d5\u05d1\u05d4 \u05d1\u05d2\u05dc\u05dc \u05dc\u05d7\u05e5 \u05d7\u05d9\u05e6\u05d5\u05e0\u05d9, \u05e4\u05d7\u05d3, \u05d0\u05d5 \u05de\u05e1\u05d9\u05d1\u05d4 \u05dc\u05d0 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05d1\u05d0\u05de\u05ea. \u05d6\u05d4 \u05e0\u05e7\u05e8\u05d0 "\u05ea\u05e9\u05d5\u05d1\u05d4 \u05de\u05d1\u05d7\u05d5\u05e5". \u05d4\u05de\u05d8\u05e8\u05d4 \u05d4\u05e1\u05d5\u05e4\u05d9\u05ea \u05d4\u05d9\u05d0 \u05dc\u05e2\u05d1\u05d5\u05d3 \u05d0\u05ea \u05d4\u05e9\u05dd \u05d5\u05dc\u05d7\u05d9\u05d5\u05ea \u05de\u05ea\u05d5\u05da \u05d0\u05d4\u05d1\u05d4 \u05d5\u05dc\u05d0 \u05de\u05ea\u05d5\u05da \u05e4\u05d7\u05d3 \u05e9\u05d4\u05e9\u05dd \u05d9\u05e2\u05e0\u05d9\u05e9 \u05d0\u05d5\u05ea\u05d9 \u05d0\u05d5 \u05de\u05ea\u05d5\u05da \u05e8\u05e6\u05d5\u05df \u05dc\u05ea\u05d2\u05de\u05d5\u05dc.\n\u05d6\u05d4\u05d5 \u05d4\u05dc\u05d1 \u05d4\u05e4\u05d5\u05e2\u05dd \u05e9\u05dc \u05d4\u05d9\u05d4\u05d3\u05d5\u05ea \u05d4\u05d7\u05dc \u05de\u05d4\u05d2\u05de\u05e8\u05d0 \u05e9\u05d0\u05d5\u05de\u05e8\u05ea \u05ea\u05e4\u05d9\u05dc\u05d4 \u05d1\u05dc\u05d0 \u05db\u05d5\u05d5\u05e0\u05d4 \u05db\u05d2\u05d5\u05e3 \u05d1\u05dc\u05d0 \u05e0\u05e9\u05de\u05d4\n\u05dc\u05e2\u05d1\u05d5\u05d3 \u05d0\u05ea \u05d4\u05e9\u05dd \u05de\u05ea\u05d5\u05da \u05d0\u05d4\u05d1\u05d4 - \u05d4\u05de\u05e9\u05de\u05e2\u05d5\u05ea \u05d4\u05e2\u05de\u05d5\u05e7\u05d4\n\u05d4\u05d1\u05e2\u05dc \u05e9\u05dd \u05d8\u05d5\u05d1 \u05dc\u05d9\u05de\u05d3 \u05e9\u05d4\u05de\u05e4\u05ea\u05d7 \u05dc\u05e2\u05d1\u05d5\u05d3\u05ea \u05d4\u2019 \u05d0\u05de\u05d9\u05ea\u05d9\u05ea \u05d4\u05d5\u05d0 \u05d0\u05d4\u05d1\u05d4 \u05d5\u05dc\u05d0 \u05e4\u05d7\u05d3 \u05d0\u05d5 \u05e8\u05e7 \u05e7\u05d9\u05d5\u05dd \u05de\u05e6\u05d5\u05d5\u05ea \u05de\u05db\u05d5\u05e8\u05d7. \u05d4\u05d5\u05d0 \u05d4\u05d3\u05d2\u05d9\u05e9 \u05e9\u05db\u05e9\u05e2\u05d5\u05e9\u05d9\u05dd \u05de\u05e6\u05d5\u05d5\u05ea \u05d0\u05d5 \u05ea\u05e4\u05d9\u05dc\u05d4 \u05de\u05ea\u05d5\u05da \u05d0\u05d4\u05d1\u05d4, \u05de\u05ea\u05d5\u05da \u05e8\u05e6\u05d5\u05df \u05db\u05e0\u05d4 \u05dc\u05d4\u05ea\u05d7\u05d1\u05e8 \u05dc\u05d0\u05dc, \u05d4\u05d4\u05ea\u05e7\u05e8\u05d1\u05d5\u05ea \u05d4\u05d9\u05d0 \u05d0\u05de\u05d9\u05ea\u05d9\u05ea \u05d5\u05e2\u05de\u05d5\u05e7\u05d4 \u05d9\u05d5\u05ea\u05e8.\n\u05dc\u05de\u05d4 \u05d3\u05d5\u05d5\u05e7\u05d0 \u05d0\u05d4\u05d1\u05d4?\n\u05d0\u05d4\u05d1\u05d4 \u05d4\u05d9\u05d0 \u05db\u05d5\u05d7 \u05e9\u05de\u05e2\u05dc\u05d4 \u05d0\u05ea \u05d4\u05e0\u05e9\u05de\u05d4 \u2013 \u05db\u05e9\u05d0\u05d3\u05dd \u05e4\u05d5\u05e2\u05dc \u05de\u05ea\u05d5\u05da \u05d0\u05d4\u05d1\u05d4, \u05d4\u05d5\u05d0 \u05de\u05ea\u05e2\u05dc\u05d4 \u05de\u05e2\u05dc \u05d4\u05d3\u05d0\u05d2\u05d5\u05ea, \u05d4\u05e4\u05d7\u05d3\u05d9\u05dd, \u05d5\u05d4\u05d7\u05d5\u05e7\u05d9\u05dd \u05d4\u05d9\u05d1\u05e9\u05d9\u05dd, \u05d5\u05d9\u05d5\u05e6\u05e8 \u05e7\u05e9\u05e8 \u05d0\u05d9\u05e9\u05d9 \u05d5\u05d7\u05d9 \u05e2\u05dd \u05d4\u05d1\u05d5\u05e8\u05d0.\n\u05d0\u05d4\u05d1\u05d4 \u05de\u05e0\u05d9\u05e2\u05d4 \u05e9\u05d9\u05e0\u05d5\u05d9 \u05e4\u05e0\u05d9\u05de\u05d9 \u05d0\u05de\u05d9\u05ea\u05d9, \u05e9\u05de\u05d5\u05d1\u05d9\u05dc \u05dc\u05d2\u05d3\u05d9\u05dc\u05d4 \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea \u05d8\u05d1\u05e2\u05d9\u05ea.\n\u05de\u05ea\u05d5\u05da \u05d0\u05d4\u05d1\u05d4, \u05d2\u05dd \u05d4\u05de\u05e6\u05d5\u05d5\u05ea \u05d4\u05db\u05d9 \u05e4\u05e9\u05d5\u05d8\u05d5\u05ea \u05de\u05e7\u05d1\u05dc\u05d5\u05ea \u05de\u05e9\u05de\u05e2\u05d5\u05ea \u05de\u05d9\u05d5\u05d7\u05d3\u05ea, \u05d5\u05d4\u05df \u05dc\u05d0 \u05d4\u05d5\u05e4\u05db\u05d5\u05ea \u05dc\u05e0\u05d8\u05dc \u05d0\u05dc\u05d0 \u05dc\u05e9\u05de\u05d7\u05d4.\n\u05e8\u05d1\u05d9 \u05e0\u05d7\u05de\u05df \u05de\u05d3\u05d2\u05d9\u05e9 \u05d0\u05ea \u05d4\u05d7\u05e9\u05d9\u05d1\u05d5\u05ea \u05e9\u05dc \u05d7\u05d6\u05e8\u05d4 \u05d5\u05e9\u05d9\u05e4\u05d5\u05e8 \u05d1\u05ea\u05d4\u05dc\u05d9\u05da \u05d4\u05ea\u05e9\u05d5\u05d1\u05d4, \u05d5\u05db\u05e9\u05d4\u05e2\u05d1\u05d5\u05d3\u05d4 \u05d4\u05d9\u05d0 \u05de\u05ea\u05d5\u05da \u05d0\u05d4\u05d1\u05d4, \u05d2\u05dd \u05d4\u05d8\u05e2\u05d5\u05d9\u05d5\u05ea, \u05d4\u05d7\u05d6\u05e8\u05d4 \u05d0\u05d7\u05d5\u05e8\u05d4 \u05d5\u05d4\u05d1\u05d3\u05d9\u05e7\u05d5\u05ea \u2013 \u05d4\u05dd \u05d7\u05dc\u05e7 \u05de\u05ea\u05d4\u05dc\u05d9\u05da \u05de\u05dc\u05d0 \u05d5\u05d7\u05d9, \u05dc\u05d0 \u05e2\u05d9\u05d3\u05d5\u05ea \u05e2\u05dc \u05db\u05d9\u05e9\u05dc\u05d5\u05df. \u05db\u05de\u05d5 \u05e9\u05d7\u05d6\u05dc \u05d0\u05de\u05e8\u05d5 \u05d0\u05d9\u05df \u05d0\u05d3\u05dd \u05e2\u05d5\u05de\u05d3 \u05e2\u05dc \u05d3\u05d1\u05e8\u05d9 \u05ea\u05d5\u05e8\u05d4 \u05d0\u05dc\u05d0 \u05d0\u05dd \u05e0\u05db\u05e9\u05dc \u05d1\u05d4\u05dd. \u05d6\u05d4 \u05dc\u05d0 \u05e8\u05e7 \u05d4\u05d4\u05d1\u05e0\u05d4 \u05e9\u05dc \u05d4\u05d4\u05dc\u05db\u05d4 \u05d0\u05dc\u05d0 \u05d4\u05d4\u05d1\u05e0\u05d4 \u05e9\u05dc \u05d4\u05d7\u05d9\u05d1\u05d5\u05e8 \u05d4\u05d0\u05d9\u05e9\u05d9 \u05e9\u05dc\u05d9 \u05d0\u05dc \u05d4\u05d4\u05dc\u05db\u05d4.\n\u05dc\u05e2\u05d1\u05d5\u05d3 \u05d0\u05ea \u05d4\u05e9\u05dd \u05de\u05ea\u05d5\u05da \u05d0\u05d4\u05d1\u05d4 \u05d6\u05d4 \u05dc\u05d1\u05e7\u05e9 \u05de\u05d4\u05dc\u05d1 \u05dc\u05d4\u05ea\u05d7\u05d1\u05e8, \u05dc\u05d4\u05d0\u05d9\u05e8 \u05d0\u05ea \u05d4\u05de\u05e2\u05e9\u05d4, \u05dc\u05d4\u05db\u05e0\u05d9\u05e1 \u05e9\u05de\u05d7\u05d4 \u05d5\u05e2\u05d5\u05de\u05e7 \u05dc\u05db\u05dc \u05e8\u05d2\u05e2.\n\u05d4\u05d3\u05d1\u05e8 \u05de\u05d0\u05e4\u05e9\u05e8 \u05dc\u05e0\u05d5 \u05dc\u05d4\u05de\u05e9\u05d9\u05da \u05dc\u05e2\u05dc\u05d5\u05ea \u05d5\u05dc\u05d4\u05ea\u05e4\u05ea\u05d7 \u05d1\u05dc\u05d9 \u05e4\u05d7\u05d3 \u05de\u05d4\u05d8\u05e2\u05d5\u05d9\u05d5\u05ea, \u05d1\u05dc\u05d9 \u05d3\u05d0\u05d2\u05d5\u05ea \u05e9\u05dc "\u05d4\u05d0\u05dd \u05e2\u05e9\u05d9\u05ea\u05d9 \u05de\u05e1\u05e4\u05d9\u05e7", \u05d0\u05dc\u05d0 \u05de\u05ea\u05d5\u05da \u05e9\u05de\u05d7\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea. \u05d5\u05dc\u05d0 \u05de\u05ea\u05d5\u05da \u05e8\u05e6\u05d5\u05df \u05dc\u05ea\u05d2\u05de\u05d5\u05dc.\n\u05ea\u05e9\u05d5\u05d1\u05d4 \u05e2\u05dc \u05d4\u05ea\u05e9\u05d5\u05d1\u05d4: \u05d4\u05ea\u05d4\u05dc\u05d9\u05da \u05e9\u05d1\u05d5 \u05d4\u05d0\u05d3\u05dd \u05d7\u05d5\u05d6\u05e8 \u05e9\u05d5\u05d1 \u05d5\u05e9\u05d5\u05d1 \u05dc\u05ea\u05d4\u05dc\u05d9\u05da \u05d4\u05ea\u05e9\u05d5\u05d1\u05d4, \u05de\u05d7\u05d3\u05d3, \u05d1\u05d5\u05d3\u05e7 \u05d0\u05ea \u05d4\u05db\u05d5\u05d5\u05e0\u05d5\u05ea \u05e9\u05dc\u05d5, \u05de\u05d1\u05d9\u05df \u05dc\u05e2\u05d5\u05de\u05e7 \u05d0\u05ea \u05d4\u05e6\u05d5\u05e8\u05da \u05d4\u05d0\u05de\u05d9\u05ea\u05d9, \u05d5\u05de\u05d6\u05db\u05da \u05d0\u05ea \u05d4\u05e0\u05e4\u05e9.\n\u05d1\u05de\u05d9\u05dc\u05d9\u05dd \u05d0\u05d7\u05e8\u05d5\u05ea, \u05d6\u05d5 \u05ea\u05e9\u05d5\u05d1\u05d4 \u05e2\u05de\u05d5\u05e7\u05d4 \u05d9\u05d5\u05ea\u05e8, \u05d0\u05d5\u05ea\u05e0\u05d8\u05d9\u05ea \u05d9\u05d5\u05ea\u05e8, \u05e9\u05de\u05d2\u05d9\u05e2\u05d4 \u05de\u05de\u05e7\u05d5\u05dd \u05e4\u05e0\u05d9\u05de\u05d9, \u05dc\u05d0 \u05db\u05ea\u05d5\u05e6\u05d0\u05d4 \u05de\u05dc\u05d7\u05e6\u05d9\u05dd \u05d7\u05d9\u05e6\u05d5\u05e0\u05d9\u05d9\u05dd \u05d0\u05d5 \u05d4\u05d7\u05dc\u05d8\u05d5\u05ea \u05e8\u05d2\u05e2\u05d9\u05d5\u05ea.\n\u05dc\u05de\u05d4 \u05d6\u05d4 \u05d7\u05e9\u05d5\u05d1 \u05d1\u05d4\u05ea\u05e4\u05ea\u05d7\u05d5\u05ea \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea?\n\u05d4\u05d4\u05ea\u05e4\u05ea\u05d7\u05d5\u05ea \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9\u05ea \u05dc\u05d0 \u05e4\u05e9\u05d5\u05d8\u05d4 \u05d5\u05e7\u05d1\u05d5\u05e2\u05d4, \u05d4\u05d9\u05d0 \u05d3\u05d9\u05e0\u05de\u05d9\u05ea \u05d5\u05db\u05d5\u05dc\u05dc\u05ea \u05e2\u05dc\u05d9\u05d5\u05ea \u05d5\u05de\u05d5\u05e8\u05d3\u05d5\u05ea.\n\u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05d4\u05e6\u05e2\u05d3 \u05d4\u05e8\u05d0\u05e9\u05d5\u05df \u05d9\u05db\u05d5\u05dc \u05dc\u05d4\u05d9\u05d5\u05ea \u05dc\u05d0 \u05de\u05d3\u05d5\u05d9\u05e7 \u05d0\u05d5 \u05dc\u05d0 \u05d1\u05e9\u05dc\u05d1 \u05d4\u05de\u05ea\u05d0\u05d9\u05dd \u05dc\u05e0\u05d5, \u05d5\u05d0\u05d6 \u05d9\u05e9 \u05e6\u05d5\u05e8\u05da \u05dc\u05d7\u05d6\u05d5\u05e8, \u05dc\u05e9\u05e0\u05d5\u05ea, \u05dc\u05d7\u05d3\u05d3 \u05d0\u05ea \u05d4\u05db\u05d5\u05d5\u05e0\u05d4.\n\u05d6\u05d4 \u05d7\u05dc\u05e7 \u05de\u05d4\u05e6\u05de\u05d9\u05d7\u05d4 \u2013 \u05dc\u05d0 \u05dc\u05d4\u05d9\u05e8\u05ea\u05e2 \u05de\u05d8\u05e2\u05d5\u05d9\u05d5\u05ea \u05d0\u05d5 \u05de\u05d7\u05d5\u05e1\u05e8 \u05e9\u05dc\u05d9\u05de\u05d5\u05ea, \u05d0\u05dc\u05d0 \u05dc\u05e8\u05d0\u05d5\u05ea \u05d0\u05d5\u05ea\u05df \u05db\u05d7\u05dc\u05e7 \u05de\u05d4\u05d3\u05e8\u05da.\n\u05dc\u05e7\u05d9\u05d7\u05ea \u05de\u05e6\u05d5\u05d5\u05d4 \u05e9\u05dc\u05d0 \u05de\u05ea\u05d0\u05d9\u05de\u05d4\n\u05dc\u05de\u05e9\u05dc, \u05d0\u05d3\u05dd \u05d9\u05db\u05d5\u05dc \u05dc\u05e7\u05d7\u05ea \u05e2\u05dc \u05e2\u05e6\u05de\u05d5 \u05de\u05e6\u05d5\u05d5\u05d4 \u05d0\u05d5 \u05d4\u05e8\u05d2\u05dc \u05e8\u05d5\u05d7\u05e0\u05d9 \u05e9\u05d4\u05d5\u05d0 \u05dc\u05d0 \u05d1\u05d0\u05de\u05ea \u05de\u05d5\u05db\u05df \u05dc\u05d5 \u2013 \u05de\u05d4 \u05e9\u05e2\u05dc\u05d5\u05dc \u05dc\u05d2\u05e8\u05d5\u05dd \u05dc\u05ea\u05e1\u05db\u05d5\u05dc \u05d0\u05d5 \u05dc\u05d5\u05d5\u05d9\u05ea\u05d5\u05e8 \u05de\u05d4\u05ea\u05d4\u05dc\u05d9\u05da.\n\u05e8\u05d1\u05d9 \u05e0\u05d7\u05de\u05df \u05de\u05e2\u05d5\u05d3\u05d3 \u05d0\u05d5\u05ea\u05e0\u05d5 \u05dc\u05d4\u05d1\u05d9\u05df \u05e9\u05d4\u05ea\u05d4\u05dc\u05d9\u05da \u05d4\u05d5\u05d0 \u05e9\u05dc\u05dd \u05d5\u05de\u05db\u05d9\u05dc, \u05d5\u05e9\u05d0\u05e4\u05e9\u05e8 \u05dc\u05d7\u05d6\u05d5\u05e8 \u05d0\u05d7\u05d5\u05e8\u05d4, "\u05dc\u05ea\u05e7\u05df \u05d0\u05ea \u05d4\u05ea\u05e9\u05d5\u05d1\u05d4", \u05db\u05d3\u05d9 \u05dc\u05d4\u05d2\u05d9\u05e2 \u05dc\u05d1\u05d7\u05d9\u05e8\u05d4 \u05d0\u05d5\u05ea\u05e0\u05d8\u05d9\u05ea \u05d5\u05de\u05ea\u05d0\u05d9\u05de\u05d4.\n\u05dc\u05d0 \u05de\u05d3\u05d5\u05d1\u05e8 \u05d1\u05d5\u05d5\u05d9\u05ea\u05d5\u05e8 \u05d0\u05d5 \u05db\u05d9\u05e9\u05dc\u05d5\u05df, \u05d0\u05dc\u05d0 \u05d1\u05e6\u05e2\u05d3 \u05d4\u05db\u05e8\u05d7\u05d9 \u05e9\u05dc \u05dc\u05de\u05d9\u05d3\u05d4 \u05e2\u05e6\u05de\u05d9\u05ea \u05d5\u05d4\u05e2\u05de\u05e7\u05d4.\n\u05de\u05e1\u05e8 \u05de\u05e2\u05e9\u05d9:\n\u05db\u05e9\u05d0\u05ea\u05d4 \u05de\u05e8\u05d2\u05d9\u05e9 \u05e9\u05d4\u05de\u05e6\u05d5\u05d5\u05d4 \u05d0\u05d5 \u05d4\u05d3\u05e8\u05da \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9\u05ea \u05e9\u05d4\u05ea\u05d7\u05dc\u05ea \u05d0\u05d9\u05e0\u05dd \u05de\u05ea\u05d0\u05d9\u05de\u05d9\u05dd, \u05d0\u05dc \u05ea\u05ea\u05d9\u05d9\u05d0\u05e9.\n\u05d7\u05d6\u05d5\u05e8 \u05dc\u05d1\u05d7\u05d5\u05df \u05d0\u05ea \u05e2\u05e6\u05de\u05da, \u05d0\u05ea \u05d4\u05db\u05d5\u05d5\u05e0\u05d5\u05ea, \u05d0\u05ea \u05d4\u05e6\u05e8\u05db\u05d9\u05dd \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05d9\u05dd \u05e9\u05dc\u05da.\n\u05e2\u05d1\u05d5\u05d3 \u05e2\u05dc "\u05ea\u05e9\u05d5\u05d1\u05d4 \u05e2\u05dc \u05d4\u05ea\u05e9\u05d5\u05d1\u05d4" \u2013 \u05ea\u05d4\u05dc\u05d9\u05da \u05e9\u05dc \u05d1\u05d9\u05e8\u05d5\u05e8 \u05e2\u05e6\u05de\u05d9 \u05de\u05ea\u05de\u05d9\u05d3.\n\u05db\u05da \u05ea\u05d1\u05e0\u05d4 \u05ea\u05d4\u05dc\u05d9\u05da \u05e8\u05d5\u05d7\u05e0\u05d9 \u05e9\u05de\u05d5\u05ea\u05d0\u05dd \u05d1\u05d0\u05de\u05ea \u05dc\u05de\u05d9 \u05e9\u05d0\u05ea\u05d4 \u05d5\u05dc\u05e9\u05dc\u05d1 \u05e9\u05d1\u05d5 \u05d0\u05ea\u05d4 \u05e0\u05de\u05e6\u05d0.\n\u05d1\u05e9\u05de\u05d7\u05d4! \u05d4\u05e0\u05d4 \u05ea\u05e8\u05d2\u05d9\u05dc \u05d4\u05d8\u05de\u05e2\u05d4 \u05e4\u05e9\u05d5\u05d8 \u05d5\u05de\u05e2\u05de\u05d9\u05e7 \u05e9\u05d9\u05e2\u05d6\u05d5\u05e8 \u05dc\u05da \u05dc\u05d4\u05ea\u05d7\u05d1\u05e8 \u05dc\u05e2\u05d1\u05d5\u05d3\u05d4 \u05e2\u05dd \u05d4\u05e9\u05dd \u05de\u05ea\u05d5\u05da \u05d0\u05d4\u05d1\u05d4, \u05dc\u05e4\u05d9 \u05de\u05e1\u05d5\u05e8\u05ea \u05d4\u05d1\u05e2\u05dc \u05e9\u05dd \u05d8\u05d5\u05d1:',"\u05ea\u05e8\u05d2\u05d9\u05dc \u05d4\u05d8\u05de\u05e2\u05d4: \u05d4\u05e1\u05ea\u05db\u05dc\u05d5\u05ea \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05d5\u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea \u05e4\u05e0\u05d9\u05de\u05d9\u05ea",'\u05d6\u05de\u05df \u05de\u05d5\u05de\u05dc\u05e5: 10-15 \u05d3\u05e7\u05d5\u05ea \u05d1\u05d9\u05d5\u05dd\n\u05de\u05e7\u05d5\u05dd: \u05e9\u05e7\u05d8, \u05de\u05e7\u05d5\u05dd \u05e9\u05d1\u05d5 \u05ea\u05d5\u05db\u05dc \u05dc\u05d4\u05e8\u05d2\u05d9\u05e9 \u05e0\u05d9\u05e0\u05d5\u05d7 \u05d5\u05e0\u05d8\u05d5\u05dc \u05d4\u05e4\u05e8\u05e2\u05d5\u05ea\n\u05e9\u05dc\u05d1 1\n\u05e9\u05d1 \u05d1\u05e0\u05d5\u05d7\u05d5\u05ea, \u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05e2\u05e6\u05d5\u05de\u05d5\u05ea \u05d0\u05d5 \u05d1\u05de\u05d1\u05d8 \u05e8\u05da \u05e7\u05d3\u05d9\u05de\u05d4.\n\u05e0\u05e9\u05d5\u05dd \u05e2\u05de\u05d5\u05e7 \u05dc\u05d0\u05d8, \u05d3\u05e8\u05da \u05d4\u05d0\u05e3, \u05d5\u05e9\u05d7\u05e8\u05e8 \u05d0\u05ea \u05d4\u05d0\u05d5\u05d5\u05d9\u05e8 \u05dc\u05d0\u05d8 \u05d3\u05e8\u05da \u05d4\u05e4\u05d4. \u05d7\u05d6\u05d5\u05e8 \u05e2\u05dc \u05e0\u05e9\u05d9\u05de\u05d5\u05ea \u05d0\u05dc\u05d5 \u05db\u05de\u05d4 \u05e4\u05e2\u05de\u05d9\u05dd \u05e2\u05d3 \u05e9\u05ea\u05e8\u05d2\u05d9\u05e9 \u05de\u05e2\u05d8 \u05e8\u05d2\u05d5\u05e2.\n\u05e9\u05dc\u05d1 2\n\u05d0\u05de\u05d5\u05e8 \u05d0\u05d5 \u05d7\u05e9\u05d1 \u05d1\u05dc\u05d1\u05da:\n"\u05d0\u05e0\u05d9 \u05e8\u05d5\u05e6\u05d4 \u05dc\u05e2\u05d1\u05d5\u05d3 \u05d0\u05ea \u05d4\u05e9\u05dd \u05de\u05ea\u05d5\u05da \u05d0\u05d4\u05d1\u05d4, \u05de\u05ea\u05d5\u05da \u05e8\u05e6\u05d5\u05df \u05dc\u05d1, \u05de\u05ea\u05d5\u05da \u05e9\u05de\u05d7\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea."\n\u05d4\u05e8\u05d2\u05e9 \u05d0\u05ea \u05d4\u05de\u05d9\u05dc\u05d9\u05dd \u05d4\u05d0\u05dc\u05d4 \u05e2\u05d5\u05dc\u05d5\u05ea \u05de\u05d4\u05dc\u05d1 \u05d0\u05dc \u05db\u05dc \u05d4\u05d2\u05d5\u05e3. \u05ea\u05df \u05dc\u05db\u05d5\u05d5\u05e0\u05d4 \u05d4\u05d6\u05d0\u05ea \u05dc\u05d4\u05ea\u05de\u05e7\u05dd \u05d1\u05ea\u05d5\u05db\u05da.\n\u05e9\u05dc\u05d1 3\n\u05d3\u05de\u05d9\u05d9\u05df \u05e8\u05d2\u05e2 \u05e9\u05d1\u05d5 \u05d4\u05e8\u05d2\u05e9\u05ea \u05d0\u05d4\u05d1\u05d4 \u05d0\u05de\u05d9\u05ea\u05d9\u05ea (\u05d6\u05d4 \u05d9\u05db\u05d5\u05dc \u05dc\u05d4\u05d9\u05d5\u05ea \u05d0\u05d4\u05d1\u05d4 \u05dc\u05d0\u05d3\u05dd \u05e7\u05e8\u05d5\u05d1, \u05dc\u05ea\u05d9\u05e0\u05d5\u05e7, \u05dc\u05d8\u05d1\u05e2, \u05d0\u05d5 \u05e4\u05e9\u05d5\u05d8 \u05ea\u05d7\u05d5\u05e9\u05ea \u05d7\u05d5\u05dd \u05d1\u05dc\u05d1).\n\u05db\u05e2\u05ea, \u05ea\u05e0\u05e1\u05d4 \u05dc\u05d4\u05e2\u05d1\u05d9\u05e8 \u05d0\u05ea \u05d4\u05ea\u05d7\u05d5\u05e9\u05d4 \u05d4\u05d6\u05d0\u05ea \u05d0\u05dc \u05d4\u05e2\u05d1\u05d5\u05d3\u05d4 \u05e2\u05dd \u05d4\u05e9\u05dd, \u05d0\u05dc \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d0\u05d5 \u05d4\u05de\u05e6\u05d5\u05d5\u05d4 \u05e9\u05d0\u05ea\u05d4 \u05dc\u05d5\u05e7\u05d7 \u05e2\u05dc \u05e2\u05e6\u05de\u05da.\n\u05d0\u05de\u05d5\u05e8 \u05d0\u05d5 \u05d7\u05d6\u05d5\u05e8 \u05d1\u05dc\u05d1\u05da \u05de\u05e9\u05e4\u05d8 \u05e4\u05e9\u05d5\u05d8 \u05db\u05de\u05d5:\n"\u05d0\u05e0\u05d9 \u05e2\u05d5\u05d1\u05d3 \u05d0\u05ea \u05d4\u05e9\u05dd \u05de\u05ea\u05d5\u05da \u05d0\u05d4\u05d1\u05d4 \u05d2\u05d3\u05d5\u05dc\u05d4, \u05de\u05ea\u05d5\u05da \u05e9\u05de\u05d7\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea."\n\u05d0\u05dd \u05d4\u05de\u05d9\u05dc\u05d9\u05dd \u05e0\u05ea\u05e7\u05e2\u05d5\u05ea, \u05ea\u05d5\u05db\u05dc \u05e4\u05e9\u05d5\u05d8 \u05dc\u05e9\u05d4\u05d5\u05ea \u05d1\u05ea\u05d7\u05d5\u05e9\u05d4 \u05e9\u05dc \u05d7\u05d5\u05dd \u05d5\u05d0\u05d5\u05e8 \u05d1\u05dc\u05d1.\n\u05e9\u05dc\u05d1 4\n\u05e7\u05d7 \u05db\u05de\u05d4 \u05e0\u05e9\u05d9\u05de\u05d5\u05ea \u05e2\u05de\u05d5\u05e7\u05d5\u05ea \u05e9\u05d5\u05d1.\n\u05d0\u05de\u05d5\u05e8 \u05dc\u05e2\u05e6\u05de\u05da:\n"\u05d0\u05e0\u05d9 \u05de\u05de\u05e9\u05d9\u05da \u05dc\u05e2\u05d1\u05d5\u05d3 \u05d0\u05ea \u05d4\u05e9\u05dd \u05de\u05ea\u05d5\u05da \u05d0\u05d4\u05d1\u05d4 \u05d1\u05db\u05dc \u05d9\u05d5\u05dd, \u05dc\u05d0\u05d8 \u05dc\u05d0\u05d8, \u05d1\u05e6\u05e2\u05d3\u05d9\u05d9 \u05d4\u05e7\u05d8\u05e0\u05d9\u05dd \u05d5\u05d4\u05d0\u05de\u05d9\u05ea\u05d9\u05d9\u05dd."\n\u05e4\u05ea\u05d7 \u05d0\u05ea \u05d4\u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05dc\u05d0\u05d8 \u05d5\u05d7\u05d6\u05d5\u05e8 \u05d1\u05d4\u05d3\u05e8\u05d2\u05d4 \u05dc\u05e1\u05d1\u05d9\u05d1\u05d4.\n\u05d8\u05d9\u05e4 \u05d7\u05e9\u05d5\u05d1\n\u05db\u05e9\u05d0\u05ea\u05d4 \u05d4\u05d5\u05dc\u05da \u05dc\u05d9\u05d5\u05dd \u05e9\u05dc\u05da, \u05ea\u05d6\u05db\u05d9\u05e8 \u05dc\u05e2\u05e6\u05de\u05da \u05de\u05d3\u05d9 \u05e4\u05e2\u05dd:\n\u201c\u05d0\u05e0\u05d9 \u05e9\u05d5\u05de\u05e8 \u05de\u05e6\u05d5\u05d5\u05ea \u05d5\u05de\u05ea\u05e4\u05dc\u05dc \u05de\u05ea\u05d5\u05da \u05d0\u05d4\u05d1\u05d4, \u05dc\u05d0 \u05de\u05ea\u05d5\u05da \u05dc\u05d7\u05e5 \u05d0\u05d5 \u05e4\u05d7\u05d3.\u201d\n\u05d2\u05dd \u05d1\u05de\u05e6\u05d1\u05d9\u05dd \u05de\u05d0\u05ea\u05d2\u05e8\u05d9\u05dd, \u05ea\u05d7\u05d6\u05d5\u05e8 \u05dc\u05de\u05d9\u05dc\u05d9\u05dd \u05d4\u05d0\u05dc\u05d4 \u05d5\u05dc\u05ea\u05d7\u05d5\u05e9\u05d4 \u05e9\u05d9\u05e6\u05e8\u05ea \u05d1\u05ea\u05e8\u05d2\u05d9\u05dc.\n\u05dc\u05dc\u05de\u05d5\u05d3 \u05dc\u05d0\u05d4\u05d5\u05d1 \u2013 \u05d2\u05dd \u05db\u05e9\u05e7\u05e9\u05d4\n"\u05d4\u05d0\u05d4\u05d1\u05d4 \u05de\u05ea\u05d7\u05d9\u05dc\u05d4 \u05db\u05d0\u05df"\n"\u05d5\u05d0\u05d4\u05d1\u05ea \u05d0\u05ea \u05d4\' \u05d0\u05dc\u05d5\u05e7\u05d9\u05da" \u05d1\u05db\u05dc \u05d1\u05d5\u05e7\u05e8, \u05d5\u05d1\u05e1\u05d5\u05e3 \u05db\u05dc \u05d9\u05d5\u05dd \u05dc\u05e4\u05e0\u05d9 \u05d4\u05e9\u05d9\u05e0\u05d4, \u05e0\u05d9\u05ea\u05e0\u05ea \u05dc\u05e0\u05d5 \u05d4\u05d4\u05d6\u05d3\u05de\u05e0\u05d5\u05ea \u05dc\u05d0\u05d6\u05df \u05d5\u05dc\u05d1\u05d7\u05d5\u05df \u05d0\u05ea \u05d9\u05d7\u05e1\u05d9\u05e0\u05d5 \u05e2\u05dd \u05d4\u05d0\u05d4\u05d1\u05d4: \u05db\u05dc\u05e4\u05d9 \u05d4\u05e2\u05d5\u05dc\u05dd, \u05db\u05dc\u05e4\u05d9 \u05e2\u05e6\u05de\u05e0\u05d5, \u05d5\u05db\u05dc\u05e4\u05d9 \u05d4\u05d1\u05d5\u05e8\u05d0.\n\u05d0\u05d4\u05d1\u05ea \u05d4\' \u05d0\u05d9\u05e0\u05e0\u05d4 \u05e8\u05e7 \u05d4\u05e6\u05d4\u05e8\u05d4 \u05e9\u05d1\u05dc\u05d1 \u05d0\u05d5 \u05d1\u05e4\u05d4. \u05d4\u05d9\u05d0 \u05e0\u05d1\u05d7\u05e0\u05ea \u05d5\u05e0\u05de\u05d3\u05d3\u05ea \u05d1\u05d0\u05d4\u05d1\u05ea \u05d4\u05d0\u05d3\u05dd. \u05db\u05de\u05d4 \u05d0\u05d4\u05d1\u05d4 \u05d9\u05e9 \u05d1\u05d9 \u05db\u05dc\u05e4\u05d9 \u05d0\u05d7\u05e8\u05d9\u05dd? \u05d5\u05e2\u05d3 \u05db\u05de\u05d4 \u05d4\u05d0\u05d4\u05d1\u05d4 \u05d4\u05d6\u05d5 \u05de\u05ea\u05e7\u05d9\u05d9\u05de\u05ea \u05d2\u05dd \u05db\u05e9\u05d0\u05d7\u05e8\u05d9\u05dd \u05d8\u05d5\u05e2\u05d9\u05dd, \u05e4\u05d5\u05d2\u05e2\u05d9\u05dd \u05d0\u05d5 \u05de\u05ea\u05e0\u05d4\u05d2\u05d9\u05dd \u05d0\u05d7\u05e8\u05ea \u05de\u05de\u05d4 \u05e9\u05e6\u05d9\u05e4\u05d9\u05ea\u05d9?\n\u05d0\u05d4\u05d1\u05d4 \u05d0\u05de\u05d9\u05ea\u05d9\u05ea \u05d0\u05d9\u05e0\u05e0\u05d4 \u05e8\u05d2\u05e9 \u05d1\u05dc\u05d1\u05d3 \u05d4\u05d9\u05d0 \u05ea\u05d5\u05d3\u05e2\u05d4 \u05e4\u05e2\u05d9\u05dc\u05d4 \u05d5\u05de\u05e2\u05e9\u05d4 \u05de\u05ea\u05de\u05e9\u05da \u05d4\u05d3\u05d5\u05e8\u05e9 \u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea \u05d5\u05e2\u05d1\u05d5\u05d3\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea. \u05d4\u05d0\u05dd \u05d0\u05e0\u05d9 \u05de\u05e1\u05d5\u05d2\u05dc \u05dc\u05dc\u05de\u05d3 \u05d6\u05db\u05d5\u05ea \u05e2\u05dc \u05de\u05d9 \u05e9\u05d0\u05d4\u05d5\u05d1 \u05e2\u05dc\u05d9\u05d9 \u05db\u05e9\u05e7\u05e9\u05d4 \u05dc\u05d9 \u05dc\u05d4\u05d1\u05d9\u05df \u05d0\u05ea \u05d3\u05e8\u05db\u05d9\u05d5? \u05d4\u05d0\u05dd \u05d0\u05e0\u05d9 \u05e0\u05d5\u05ea\u05df \u05de\u05e7\u05d5\u05dd \u05dc\u05de\u05d7\u05e9\u05d1\u05d4 \u05e9\u05d0\u05d5\u05dc\u05d9 \u05d0\u05e0\u05d9 \u05d4\u05d5\u05d0 \u05d6\u05d4 \u05e9\u05dc\u05d0 \u05d4\u05d1\u05d9\u05df? \u05d5\u05d4\u05d0\u05dd \u05de\u05ea\u05d5\u05da \u05d4\u05d4\u05d1\u05e0\u05d4 \u05d4\u05d6\u05d5, \u05d0\u05e0\u05d9 \u05de\u05e6\u05dc\u05d9\u05d7 \u05dc\u05e9\u05d3\u05e8 \u05d0\u05dc\u05d9\u05d5 \u05ea\u05d7\u05d5\u05e9\u05d5\u05ea \u05d8\u05d5\u05d1\u05d5\u05ea, \u05d5\u05dc\u05d0 \u05e9\u05d9\u05e4\u05d5\u05d8?\n\u05d0\u05d4\u05d1\u05d4 \u05db\u05d6\u05d5 \u2014 \u05de\u05d7\u05d5\u05d1\u05e8\u05ea \u05dc\u05de\u05e2\u05e9\u05d9\u05dd, \u05dc\u05de\u05d7\u05e9\u05d1\u05d4, \u05d5\u05dc\u05d1\u05d7\u05d9\u05e8\u05d4 \u05d9\u05d5\u05de\u05d9\u05d5\u05de\u05d9\u05ea \u2014 \u05d4\u05d9\u05d0 \u05d4\u05d3\u05e8\u05da \u05dc\u05d0\u05d4\u05d1\u05ea \u05d4\', \u05d3\u05e8\u05da \u05d4\u05dc\u05d1 \u05e9\u05dc \u05d4\u05d1\u05e8\u05d9\u05d0\u05d4.\n\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05de\u05d5\u05d3\u05e8\u05db\u05ea \u2013 \u05d0\u05d4\u05d1\u05d4 \u05d5\u05ea\u05d9\u05e7\u05d5\u05df \u05d4\u05d9\u05d7\u05e1\u05d9\u05dd:\n\u05e2\u05e6\u05d5\u05dd \u05e2\u05d9\u05e0\u05d9\u05d9\u05dd. \u05e7\u05d7 \u05e0\u05e9\u05d9\u05de\u05d4 \u05e2\u05de\u05d5\u05e7\u05d4 \u05d3\u05e8\u05da \u05d4\u05d0\u05e3\u2026 \u05d5\u05d4\u05d5\u05e6\u05d0 \u05dc\u05d0\u05d8 \u05d3\u05e8\u05da \u05d4\u05e4\u05d4.\n\u05d4\u05e8\u05d2\u05e9 \u05d0\u05ea \u05d4\u05d2\u05d5\u05e3 \u05de\u05ea\u05e8\u05e4\u05d4, \u05d0\u05ea \u05d4\u05dc\u05d1 \u05e0\u05e8\u05d2\u05e2.\n\u05d3\u05de\u05d9\u05d9\u05df \u05d0\u05d3\u05dd \u05e7\u05e8\u05d5\u05d1 \u05d0\u05dc\u05d9\u05da \u05d0\u05d5\u05dc\u05d9 \u05de\u05d9\u05e9\u05d4\u05d5 \u05e9\u05d0\u05ea\u05d4 \u05d0\u05d5\u05d4\u05d1, \u05d0\u05d1\u05dc \u05d9\u05e9 \u05d0\u05d9\u05ea\u05d5 \u05d2\u05dd \u05e7\u05d5\u05e9\u05d9.\n\u05e8\u05d0\u05d4 \u05d0\u05d5\u05ea\u05d5 \u05e2\u05d5\u05de\u05d3 \u05de\u05d5\u05dc\u05da, \u05e9\u05d5\u05ea\u05e7.\n\u05d4\u05e1\u05ea\u05db\u05dc \u05dc\u05d5 \u05d1\u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05d1\u05d3\u05de\u05d9\u05d5\u05df\u2026\n\u05e9\u05d9\u05dd \u05dc\u05d1: \u05de\u05d4 \u05d0\u05ea\u05d4 \u05de\u05e8\u05d2\u05d9\u05e9 \u05de\u05d5\u05dc\u05d5? \u05d4\u05d0\u05dd \u05d9\u05e9 \u05db\u05d0\u05d1, \u05ea\u05e1\u05db\u05d5\u05dc, \u05e6\u05d9\u05e4\u05d9\u05d9\u05d4, \u05d0\u05d5 \u05d0\u05d4\u05d1\u05d4?\n\u05db\u05e2\u05ea \u05d0\u05de\u05d5\u05e8 \u05d1\u05dc\u05d1\u05da:\n"\u05d2\u05dd \u05d0\u05dd \u05d0\u05d9\u05e0\u05e0\u05d9 \u05de\u05d1\u05d9\u05df, \u05d0\u05e0\u05d9 \u05d1\u05d5\u05d7\u05e8 \u05dc\u05d0\u05d4\u05d5\u05d1. \u05d2\u05dd \u05d0\u05dd \u05e0\u05e4\u05d2\u05e2\u05ea\u05d9, \u05d0\u05e0\u05d9 \u05d1\u05d5\u05d7\u05e8 \u05dc\u05e8\u05d0\u05d5\u05ea \u05d0\u05ea \u05d4\u05d0\u05e0\u05d5\u05e9\u05d9 \u05e9\u05d1\u05d5. \u05d2\u05dd \u05d0\u05dd \u05d0\u05d9\u05e0\u05e0\u05d5 \u05de\u05e1\u05db\u05d9\u05de\u05d9\u05dd \u05d0\u05e0\u05d9 \u05de\u05e9\u05d3\u05e8 \u05d0\u05dc\u05d9\u05d5 \u05d0\u05d5\u05e8, \u05d5\u05dc\u05d0 \u05d7\u05e9\u05db\u05d4."\n\u05e0\u05e9\u05d5\u05dd \u05e2\u05d5\u05d3 \u05e0\u05e9\u05d9\u05de\u05d4 \u05e2\u05de\u05d5\u05e7\u05d4\u2026\n\u05d5\u05ea\u05df \u05dc\u05e2\u05e6\u05de\u05da \u05dc\u05d7\u05d5\u05e9 \u05db\u05d9\u05e6\u05d3 \u05d4\u05dc\u05d1 \u05de\u05ea\u05e8\u05d7\u05d1 \u05de\u05e2\u05d8\u2026\n\u05db\u05d9\u05e6\u05d3 \u05d0\u05ea\u05d4 \u05d4\u05d5\u05e4\u05da \u05dc\u05e9\u05d5\u05ea\u05e3 \u05e4\u05e2\u05d9\u05dc \u05d1\u05d0\u05d4\u05d1\u05ea \u05d4\' \u05d3\u05e8\u05da \u05d4\u05d0\u05d4\u05d1\u05d4 \u05e9\u05d0\u05ea\u05d4 \u05d1\u05d5\u05e8\u05d0 \u05e2\u05db\u05e9\u05d9\u05d5 \u05d1\u05e2\u05d5\u05dc\u05dd.\n\u05db\u05e9\u05ea\u05d4\u05d9\u05d4 \u05de\u05d5\u05db\u05df, \u05e4\u05e7\u05d7 \u05d0\u05ea \u05e2\u05d9\u05e0\u05d9\u05da \u05d1\u05d0\u05d9\u05d8\u05d9\u05d5\u05ea.\n\u05e9\u05de\u05d5\u05e8 \u05d0\u05d9\u05ea\u05da \u05d0\u05ea \u05ea\u05d7\u05d5\u05e9\u05ea \u05d4\u05d4\u05ea\u05e8\u05d7\u05d1\u05d5\u05ea \u05d4\u05d6\u05d5 \u05dc\u05d9\u05d5\u05dd \u05d4\u05d1\u05d0.\n\u05d1\u05db\u05dc \u05dc\u05d1\u05d1\u05da: \u05db\u05e9\u05d4\u05d0\u05d5\u05e8 \u05d5\u05d4\u05d7\u05d5\u05e9\u05da \u05de\u05ea\u05e4\u05dc\u05dc\u05d9\u05dd \u05d9\u05d7\u05d3\n\u05db\u05d9\u05e6\u05d3 \u05e0\u05d0\u05d4\u05d1? - \u05d1\u05db\u05dc \u05dc\u05d1\u05d1\u05da, \u05d5\u05d1\u05db\u05dc \u05e0\u05e4\u05e9\u05da, \u05d5\u05d1\u05db\u05dc \u05de\u05d0\u05d5\u05d3\u05da.\n\u05e9\u05dc\u05d5\u05e9\u05d4 \u05e9\u05e2\u05e8\u05d9\u05dd \u05dc\u05d0\u05d4\u05d1\u05d4. \u05e9\u05dc\u05d5\u05e9 \u05e7\u05d5\u05de\u05d5\u05ea \u05d1\u05e0\u05e4\u05e9.\n\u05d1\u05db\u05dc \u05dc\u05d1\u05d1\u05da - \u05e2\u05dd \u05e9\u05e0\u05d9 \u05d9\u05e6\u05e8\u05d9\u05da. \u05dc\u05d0 \u05e8\u05e7 \u05d4\u05d7\u05dc\u05e7 \u05d4\u05e0\u05e2\u05d9\u05dd, \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9, \u05d4\u05e6\u05d5\u05d3\u05e7 \u05e9\u05d1\u05da, \u05d0\u05dc\u05d0 \u05d2\u05dd \u05d4\u05d7\u05dc\u05e7\u05d9\u05dd \u05d4\u05e4\u05d7\u05d5\u05ea \u05e0\u05d5\u05d7\u05d9\u05dd: \u05d4\u05e4\u05d7\u05d3, \u05d4\u05e7\u05e0\u05d0\u05d4, \u05d4\u05db\u05e2\u05e1. \u05d0\u05d4\u05d1\u05ea \u05d4\' "\u05d1\u05db\u05dc \u05dc\u05d1\u05d1\u05da" \u05de\u05ea\u05d7\u05d9\u05dc\u05d4 \u05d1\u05db\u05da \u05e9\u05d0\u05ea\u05d4 \u05de\u05e4\u05e1\u05d9\u05e7 \u05dc\u05d4\u05d9\u05dc\u05d7\u05dd \u05d1\u05e2\u05e6\u05de\u05da. \u05d0\u05ea\u05d4 \u05e4\u05d5\u05d2\u05e9 \u05d2\u05dd \u05d0\u05ea \u05d4\u05de\u05e7\u05d5\u05de\u05d5\u05ea \u05d4\u05d7\u05e9\u05d5\u05db\u05d9\u05dd \u05e9\u05dc\u05da \u05d5\u05de\u05d1\u05d9\u05d0 \u05d0\u05d5\u05ea\u05dd \u05d0\u05dc \u05ea\u05d5\u05da \u05d4\u05e7\u05e9\u05e8 \u05e2\u05dd \u05d4\u05d1\u05d5\u05e8\u05d0. \u05d2\u05dd \u05d4\u05dd \u05d7\u05dc\u05e7 \u05de\u05d4\u05ea\u05de\u05d5\u05e0\u05d4 \u05d4\u05e9\u05dc\u05de\u05d4.\n\u05d1\u05db\u05dc \u05e0\u05e4\u05e9\u05da - \u05d2\u05dd \u05d0\u05dd \u05d9\u05d9\u05e7\u05d7 \u05d0\u05ea \u05e0\u05e4\u05e9\u05da. \u05d6\u05d5 \u05db\u05d1\u05e8 \u05de\u05d3\u05e8\u05d2\u05d4 \u05e9\u05dc \u05de\u05e1\u05d9\u05e8\u05d5\u05ea. \u05d4\u05d9\u05db\u05d5\u05dc\u05ea \u05dc\u05d5\u05de\u05e8: \u05d0\u05e0\u05d9 \u05dc\u05d0 \u05e2\u05d5\u05d1\u05d3 \u05d0\u05d5\u05ea\u05da \u05e8\u05e7 \u05db\u05e9\u05e0\u05e2\u05d9\u05dd \u05dc\u05d9. \u05d2\u05dd \u05db\u05e9\u05db\u05d5\u05d0\u05d1, \u05d2\u05dd \u05db\u05e9\u05d9\u05e9 \u05e1\u05d1\u05dc, \u05d2\u05dd \u05db\u05e9\u05d0\u05e0\u05d9 \u05dc\u05d0 \u05de\u05d1\u05d9\u05df \u05d0\u05e0\u05d9 \u05e0\u05e9\u05d0\u05e8. \u05d0\u05e0\u05d9 \u05dc\u05d0 \u05de\u05e0\u05ea\u05e7 \u05de\u05d2\u05e2. \u05d6\u05d5 \u05d0\u05d4\u05d1\u05d4 \u05e9\u05de\u05d7\u05d6\u05d9\u05e7\u05d4 \u05d2\u05dd \u05db\u05e9\u05d0\u05d9\u05df "\u05ea\u05de\u05d5\u05e8\u05d4 \u05de\u05d9\u05d9\u05d3\u05d9\u05ea".\n\u05d5\u05d1\u05db\u05dc \u05de\u05d0\u05d5\u05d3\u05da - "\u05de\u05d0\u05d5\u05d3" \u05d4\u05d5\u05d0 \u05d4\u05db\u05d5\u05d7 \u05e9\u05dc\u05da, \u05d4\u05e8\u05e6\u05d5\u05df \u05e9\u05dc\u05da, \u05d4\u05db\u05e1\u05e3 \u05e9\u05dc\u05da, \u05d4\u05d4\u05e9\u05ea\u05d5\u05e7\u05e7\u05d5\u05ea \u05e9\u05dc\u05da. \u05db\u05dc \u05de\u05d4 \u05e9\u05d0\u05ea\u05d4 "\u05de\u05d0\u05d5\u05d3 \u05e8\u05d5\u05e6\u05d4" \u2013 \u05ea\u05d1\u05d9\u05d0 \u05d0\u05ea \u05d6\u05d4 \u05d0\u05dc \u05ea\u05d5\u05da \u05d4\u05d0\u05d4\u05d1\u05d4. \u05dc\u05d0 \u05ea\u05d5\u05d5\u05ea\u05e8 \u05e2\u05dc \u05d4\u05e8\u05e6\u05d5\u05e0\u05d5\u05ea \u05e9\u05dc\u05da, \u05d0\u05dc\u05d0 \u05ea\u05d4\u05e4\u05d5\u05da \u05d0\u05d5\u05ea\u05dd \u05dc\u05e9\u05e2\u05e8. \u05d2\u05dd \u05d4\u05e2\u05d5\u05e6\u05de\u05d4, \u05d2\u05dd \u05d4\u05d3\u05d7\u05e3, \u05d2\u05dd \u05d4\u05ea\u05e9\u05d5\u05e7\u05d4 \u2013 \u05d4\u05dd \u05e0\u05ea\u05d9\u05d1\u05d9\u05dd \u05dc\u05e2\u05d1\u05d5\u05d3\u05ea \u05d4\'.\n\u05e9\u05d1/\u05d9 \u05d1\u05e0\u05d7\u05ea. \u05e7\u05d7 \u05e9\u05dc\u05d5\u05e9 \u05e0\u05e9\u05d9\u05de\u05d5\u05ea \u05e2\u05de\u05d5\u05e7\u05d5\u05ea, \u05d5\u05db\u05dc \u05d0\u05d7\u05ea \u05de\u05d4\u05df \u05ea\u05d4\u05d9\u05d4 \u05db\u05e0\u05d9\u05e1\u05d4 \u05dc\u05d0\u05d7\u05ea \u05de\u05d4\u05de\u05d3\u05e8\u05d2\u05d5\u05ea:\n\u05e0\u05e9\u05d9\u05de\u05d4 \u05e8\u05d0\u05e9\u05d5\u05e0\u05d4: "\u05d1\u05db\u05dc \u05dc\u05d1\u05d1\u05d9" - \u05d0\u05e0\u05d9 \u05de\u05e7\u05d1\u05dc \u05d0\u05ea \u05db\u05dc \u05de\u05d4 \u05e9\u05d9\u05e9 \u05d1\u05d9. \u05d0\u05e0\u05d9 \u05de\u05d1\u05d9\u05d0 \u05dc\u05d1\u05d5\u05e8\u05d0 \u05d0\u05ea \u05db\u05dc \u05d4\u05dc\u05d1.\n\u05e0\u05e9\u05d9\u05de\u05d4 \u05e9\u05e0\u05d9\u05d9\u05d4: "\u05d1\u05db\u05dc \u05e0\u05e4\u05e9\u05d9" - \u05d2\u05dd \u05d0\u05dd \u05e7\u05e9\u05d4, \u05d2\u05dd \u05d0\u05dd \u05db\u05d5\u05d0\u05d1 \u2013 \u05d0\u05e0\u05d9 \u05d1\u05d5\u05d7\u05e8 \u05dc\u05d0\u05d4\u05d5\u05d1. \u05d0\u05e0\u05d9 \u05dc\u05d0 \u05d1\u05d5\u05e8\u05d7.\n\u05e0\u05e9\u05d9\u05de\u05d4 \u05e9\u05dc\u05d9\u05e9\u05d9\u05ea: "\u05d1\u05db\u05dc \u05de\u05d0\u05d5\u05d3\u05d9" - \u05d0\u05e0\u05d9 \u05e0\u05d5\u05ea\u05df \u05d0\u05ea \u05d4\u05d0\u05e0\u05e8\u05d2\u05d9\u05d4, \u05d4\u05e8\u05e6\u05d5\u05df \u05d5\u05d4\u05db\u05d5\u05d7 \u05e9\u05dc\u05d9 \u2013 \u05dc\u05d3\u05d1\u05e8 \u05d4\u05d2\u05d3\u05d5\u05dc \u05de\u05de\u05e0\u05d9. \u05dc\u05de\u05e9\u05d4\u05d5 \u05e9\u05d9\u05e9 \u05d1\u05d5 \u05d0\u05de\u05ea \u05e2\u05de\u05d5\u05e7\u05d4.\n\u05d4\u05e9\u05d0\u05e8/\u05d9 \u05e2\u05d5\u05d3 \u05e8\u05d2\u05e2 \u05d0\u05d7\u05d3 \u05d1\u05e9\u05e7\u05d8\u2026 \u05d5\u05ea\u05df \u05dc\u05d0\u05d4\u05d1\u05d4 \u05e9\u05d1\u05ea\u05d5\u05db\u05da \u05dc\u05d4\u05ea\u05e4\u05e9\u05d8 \u05dc\u05db\u05dc \u05e4\u05d9\u05e0\u05d5\u05ea \u05d4\u05dc\u05d1.\n"\u05d5\u05e9\u05d9\u05e0\u05e0\u05ea\u05dd \u05dc\u05d1\u05e0\u05d9\u05da" - \u05d1\u05e4\u05e8\u05e9\u05ea \u05ea\u05d5\u05dc\u05d3\u05d5\u05ea \u05d0\u05e0\u05d5 \u05dc\u05d5\u05de\u05d3\u05d9\u05dd \u05e9\u05db\u05d0\u05e9\u05e8 \u05d0\u05e0\u05d5 \u05e2\u05d5\u05e1\u05e7\u05d9\u05dd \u05d1\u05ea\u05d5\u05dc\u05d3\u05d5\u05ea \u05d4\u05d0\u05d1\u05d5\u05ea, \u05d4\u05de\u05d9\u05d9\u05e6\u05d2\u05d9\u05dd \u05ea\u05db\u05d5\u05e0\u05d5\u05ea \u05db\u05de\u05d5 \u05d7\u05e1\u05d3 \u05d5\u05d2\u05d1\u05d5\u05e8\u05d4, \u05d0\u05d9\u05e0\u05e0\u05d5 \u05e2\u05d5\u05e1\u05e7\u05d9\u05dd \u05e8\u05e7 \u05d1\u05e1\u05d9\u05e4\u05d5\u05e8 \u05d4\u05d9\u05e1\u05d8\u05d5\u05e8\u05d9, \u05d0\u05dc\u05d0 \u05d1\u05ea\u05d4\u05dc\u05d9\u05da \u05e4\u05e0\u05d9\u05de\u05d9 \u05e9\u05dc \u05d9\u05e6\u05d9\u05e8\u05d4 \u05d5\u05d1\u05e0\u05d9\u05d9\u05ea \u05ea\u05d5\u05d3\u05e2\u05d4. \u05db\u05dc \u05d0\u05d7\u05ea \u05de\u05d4\u05ea\u05db\u05d5\u05e0\u05d5\u05ea \u05d4\u05dc\u05dc\u05d5, \u05d7\u05e1\u05d3, \u05d2\u05d1\u05d5\u05e8\u05d4 \u05d0\u05d5 \u05ea\u05e4\u05d0\u05e8\u05ea \u05d4\u05d9\u05d0 \u05de\u05e6\u05d1 \u05ea\u05d5\u05d3\u05e2\u05ea\u05d9 \u05e9\u05e0\u05d9\u05ea\u05df \u05dc\u05e0\u05d5 \u05dc\u05d0\u05de\u05e5, \u05dc\u05d8\u05e4\u05d7 \u05d5\u05dc\u05d4\u05e2\u05e6\u05d9\u05dd.\n\u05db\u05d0\u05e9\u05e8 \u05d0\u05e0\u05d5 \u05de\u05e4\u05ea\u05d7\u05d9\u05dd \u05ea\u05d5\u05d3\u05e2\u05d4 \u05d7\u05d3\u05e9\u05d4 \u05d0\u05d5 \u05de\u05d5\u05e1\u05d9\u05e4\u05d9\u05dd \u05e8\u05d5\u05d1\u05d3 \u05ea\u05d5\u05d3\u05e2\u05ea\u05d9 \u05dc\u05d7\u05d9\u05d9\u05e0\u05d5, \u05d6\u05d5\u05d4\u05d9 \u05de\u05e2\u05d9\u05df \u05dc\u05d9\u05d3\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea - \u05d4\u05d9\u05dc\u05d3 \u05e9\u05dc\u05e0\u05d5. \u05db\u05dc "\u05d9\u05dc\u05d3" \u05db\u05d6\u05d4 \u05d6\u05e7\u05d5\u05e7 \u05dc\u05d8\u05d9\u05e4\u05d5\u05d7, \u05d0\u05d4\u05d1\u05d4 \u05d5\u05d4\u05db\u05d5\u05d5\u05e0\u05d4. \u05e2\u05dd \u05d6\u05d0\u05ea, \u05dc\u05e6\u05d3 \u05d4\u05d9\u05dc\u05d3\u05d9\u05dd \u05d4\u05de\u05ea\u05e4\u05ea\u05d7\u05d9\u05dd, \u05db\u05d5\u05dc\u05e0\u05d5 \u05e0\u05d5\u05e9\u05d0\u05d9\u05dd \u05d1\u05ea\u05d5\u05db\u05e0\u05d5 \u05d2\u05dd \u05d9\u05dc\u05d3\u05d9\u05dd \u05e4\u05e0\u05d9\u05de\u05d9\u05d9\u05dd \u05db\u05d0\u05d5\u05d1\u05d9\u05dd - \u05ea\u05d5\u05d3\u05e2\u05d5\u05ea \u05e9\u05e0\u05e2\u05e6\u05e8\u05d5 \u05d1\u05e9\u05dc\u05d1\u05d9\u05dd \u05e9\u05d5\u05e0\u05d9\u05dd \u05e9\u05dc \u05d4\u05ea\u05d1\u05d2\u05e8\u05d5\u05ea, \u05e9\u05dc\u05d0 \u05e7\u05d9\u05d1\u05dc\u05d5 \u05d0\u05ea \u05d4\u05de\u05e2\u05e0\u05d4 \u05e9\u05e0\u05d3\u05e8\u05e9 \u05dc\u05d4\u05df \u05d1\u05d6\u05de\u05e0\u05df.\n\u05e2\u05dc\u05d9\u05e0\u05d5 \u05dc\u05e9\u05d9\u05dd \u05dc\u05d1 \u05dc\u05de\u05e6\u05d1 \u05d4\u05d4\u05ea\u05e4\u05ea\u05d7\u05d5\u05ea\u05d9 \u05e9\u05dc \u05db\u05dc \u05ea\u05d5\u05d3\u05e2\u05d4 \u05d1\u05ea\u05d5\u05db\u05e0\u05d5: \u05dc\u05d6\u05d4\u05d5\u05ea \u05d4\u05d0\u05dd \u05d4\u05d9\u05d0 \u05e2\u05d3\u05d9\u05d9\u05df \u05d1\u05e9\u05dc\u05d1 \u05d4\u05d9\u05e0\u05e7\u05d5\u05ea, \u05d4\u05d9\u05dc\u05d3\u05d5\u05ea \u05d0\u05d5 \u05d4\u05d4\u05ea\u05d1\u05d2\u05e8\u05d5\u05ea, \u05d5\u05dc\u05e1\u05d9\u05d9\u05e2 \u05dc\u05d4 \u05dc\u05d4\u05ea\u05e7\u05d3\u05dd \u05dc\u05e2\u05d1\u05e8 \u05d1\u05d2\u05e8\u05d5\u05ea \u05de\u05dc\u05d0\u05d4. \u05d6\u05d5\u05d4\u05d9 \u05d3\u05e8\u05da \u05e9\u05dc \u05e8\u05d9\u05e4\u05d5\u05d9 \u05e4\u05e0\u05d9\u05de\u05d9, \u05e9\u05dc \u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea \u05d5\u05e9\u05dc \u05d2\u05d9\u05d3\u05d5\u05dc \u05e8\u05d5\u05d7\u05e0\u05d9 \u05de\u05ea\u05de\u05d9\u05d3.\n\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4: "\u05de\u05e4\u05d2\u05e9 \u05e2\u05dd \u05d4\u05d9\u05dc\u05d3 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9"\n\u05e9\u05d1\u05d9 \u05d0\u05d5 \u05e9\u05db\u05d1\u05d9 \u05d1\u05e0\u05d5\u05d7\u05d5\u05ea, \u05e2\u05e6\u05de/\u05d9 \u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05d5\u05e7\u05d7/\u05d9 \u05e0\u05e9\u05d9\u05de\u05d4 \u05e2\u05de\u05d5\u05e7\u05d4.\n\u05d0\u05e4\u05e9\u05e8/\u05d9 \u05dc\u05d2\u05d5\u05e3 \u05dc\u05d4\u05e9\u05ea\u05d7\u05e8\u05e8 \u05d0\u05d8 \u05d0\u05d8... \u05e9\u05d9\u05dd/\u05d9 \u05dc\u05d1 \u05dc\u05e7\u05d5\u05dc \u05d4\u05e0\u05e9\u05d9\u05de\u05d4.\n\u05d3\u05de\u05d9\u05d9\u05df/\u05d9 \u05e9\u05d0\u05ea/\u05d4 \u05e0\u05db\u05e0\u05e1/\u05ea \u05dc\u05d2\u05df \u05e9\u05e7\u05d8 \u05d5\u05de\u05d5\u05d0\u05e8. \u05d1\u05d0\u05de\u05e6\u05e2 \u05d4\u05d2\u05df \u05de\u05d7\u05db\u05d4 \u05dc\u05da \u05d9\u05dc\u05d3 - \u05d4\u05d5\u05d0 \u05d4\u05d9\u05dc\u05d3 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9 \u05e9\u05dc\u05da. \u05d4\u05d1\u05d9\u05d8/\u05d9 \u05d1\u05d5: \u05d1\u05df \u05db\u05de\u05d4 \u05d4\u05d5\u05d0? \u05de\u05d4 \u05d4\u05d5\u05d0 \u05de\u05e8\u05d2\u05d9\u05e9?\n\u05d2\u05e9/\u05d9 \u05d0\u05dc\u05d9\u05d5 \u05d1\u05e2\u05d3\u05d9\u05e0\u05d5\u05ea. \u05e9\u05d0\u05dc/\u05d9 \u05d0\u05d5\u05ea\u05d5:\n\u05de\u05d4 \u05d0\u05ea\u05d4 \u05e6\u05e8\u05d9\u05da \u05e2\u05db\u05e9\u05d9\u05d5?\n\u05de\u05de\u05d4 \u05d0\u05ea\u05d4 \u05d7\u05d5\u05e9\u05e9?\n\u05de\u05d4 \u05d9\u05e9\u05de\u05d7 \u05d0\u05d5\u05ea\u05da?\n\u05d4\u05e7\u05e9\u05d1/\u05d9 \u05dc\u05ea\u05e9\u05d5\u05d1\u05d5\u05ea \u05e9\u05e2\u05d5\u05dc\u05d5\u05ea - \u05d2\u05dd \u05d0\u05dd \u05d4\u05df \u05e9\u05e7\u05d8\u05d5\u05ea, \u05e2\u05de\u05d5\u05de\u05d5\u05ea \u05d0\u05d5 \u05de\u05e4\u05ea\u05d9\u05e2\u05d5\u05ea.\n\u05db\u05e2\u05ea, \u05d7\u05d1\u05e7/\u05d9 \u05d0\u05ea \u05d4\u05d9\u05dc\u05d3 \u05d4\u05d6\u05d4 \u05d1\u05d0\u05d4\u05d1\u05d4. \u05d4\u05d1\u05d8\u05d7/\u05d9 \u05dc\u05d5 \u05e9\u05ea\u05d4\u05d9\u05d9 \u05e9\u05dd \u05e2\u05d1\u05d5\u05e8\u05d5, \u05e9\u05ea\u05dc\u05d5\u05d5\u05d9 \u05d0\u05d5\u05ea\u05d5 \u05dc\u05d2\u05d3\u05d5\u05dc.\n\u05e0\u05e9\u05d5\u05dd/\u05d9 \u05e2\u05de\u05d5\u05e7. \u05db\u05d0\u05e9\u05e8 \u05d0\u05ea/\u05d4 \u05de\u05d5\u05db\u05e0/\u05d4, \u05d7\u05d6\u05e8/\u05d9 \u05d0\u05d8 \u05d0\u05d8 \u05dc\u05de\u05d5\u05d3\u05e2\u05d5\u05ea \u05de\u05dc\u05d0\u05d4, \u05e4\u05e7\u05d7/\u05d9 \u05e2\u05d9\u05e0\u05d9\u05d9\u05dd, \u05d5\u05d0\u05dc \u05ea\u05e9\u05db\u05d7/\u05d9 \u05d0\u05ea \u05d4\u05d4\u05d1\u05d8\u05d7\u05d4 \u05e9\u05d4\u05e2\u05e0\u05e7\u05ea \u05d1\u05dc\u05d1\u05da.\n\u05d4\u05de\u05ea\u05d7 \u05d4\u05e7\u05d9\u05d5\u05de\u05d9 \u05d1\u05d9\u05df \u05e7\u05d3\u05d5\u05e9 \u05e7\u05d3\u05d5\u05e9 \u05e7\u05d3\u05d5\u05e9 \u05dc\u05d0\u05d9\u05e9\u05d4 \u05de\u05e7\u05d5\u05dd \u05db\u05d1\u05d5\u05d3\u05d5\n\u05d4\u05d0\u05dd \u05d7\u05d5\u05e1\u05e8 \u05e1\u05d9\u05e4\u05d5\u05e7 \u05d9\u05d4\u05e8\u05d5\u05e1 \u05d0\u05d5\u05ea\u05da \u2013 \u05d0\u05d5 \u05d9\u05d1\u05e0\u05d4 \u05d0\u05d5\u05ea\u05da?\n\u05d4\u05e4\u05e1\u05d5\u05e7 "\u05d4\u05b7\u05e9\u05b8\u05bc\u05c1\u05de\u05b7\u05d9\u05b4\u05dd \u05db\u05b4\u05bc\u05e1\u05b0\u05d0\u05b4\u05d9 \u05d5\u05b0\u05d4\u05b8\u05d0\u05b8\u05e8\u05b6\u05e5 \u05d4\u05b2\u05d3\u05b9\u05dd \u05e8\u05b7\u05d2\u05b0\u05dc\u05b8\u05d9" (\u05d9\u05e9\u05e2\u05d9\u05d4\u05d5 \u05e1\u05d5, \u05d0) \u05de\u05d3\u05d1\u05e8 \u05e2\u05dc \u05d2\u05d3\u05dc\u05d5\u05ea\u05d5 \u05d4\u05d1\u05dc\u05ea\u05d9 \u05e0\u05ea\u05e4\u05e1\u05ea \u05e9\u05dc \u05d4\'. \u05d4\u05e9\u05de\u05d9\u05d9\u05dd \u05d4\u05d1\u05dc\u05ea\u05d9 \u05de\u05d5\u05d2\u05d1\u05dc\u05d9\u05dd \u05d4\u05dd \u05db\u05e1\u05d0\u05d5, \u05d5\u05d0\u05d9\u05dc\u05d5 \u05d4\u05d0\u05e8\u05e5, \u05e2\u05dd \u05db\u05dc \u05de\u05d4 \u05e9\u05d9\u05e9 \u05d1\u05d4, \u05d4\u05d9\u05d0 \u05e8\u05e7 \u05d4\u05b2\u05d3\u05b9\u05dd \u05e8\u05d2\u05dc\u05d9\u05d5. \u05d6\u05d4 \u05de\u05e1\u05de\u05dc \u05e4\u05e2\u05e8 \u05e2\u05e6\u05d5\u05dd \u05d1\u05d9\u05df \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9 \u05dc\u05d0\u05e0\u05d5\u05e9\u05d9.\n\u05d4\u05de\u05ea\u05d7 \u05d1\u05d9\u05df "\u05dc\u05d4\u05d9\u05d5\u05ea \u05e9\u05de\u05d7 \u05d1\u05d7\u05dc\u05e7\u05da" \u05dc"\u05dc\u05e9\u05d0\u05d5\u05e3 \u05dc\u05d9\u05d5\u05ea\u05e8" \u05de\u05e9\u05ea\u05e7\u05e3 \u05db\u05d0\u05df: \u05de\u05e6\u05d3 \u05d0\u05d7\u05d3, \u05d0\u05e0\u05d7\u05e0\u05d5 "\u05d4\u05d0\u05e8\u05e5", \u05de\u05e8\u05d2\u05d9\u05e9\u05d9\u05dd \u05de\u05d5\u05d2\u05d1\u05dc\u05d9\u05dd, \u05d7\u05dc\u05e7 \u05de\u05ea\u05d5\u05db\u05e0\u05d9\u05ea \u05d2\u05d3\u05d5\u05dc\u05d4, \u05d5\u05dc\u05db\u05df \u05d9\u05e9 \u05e2\u05e8\u05da \u05d1\u05d4\u05e9\u05dc\u05de\u05d4 \u05d5\u05e7\u05d1\u05dc\u05d4. \u05de\u05e6\u05d3 \u05e9\u05e0\u05d9, \u05d4\u05e0\u05e9\u05de\u05d4 \u05e9\u05dc\u05e0\u05d5 \u05de\u05d7\u05d5\u05d1\u05e8\u05ea \u05dc\u05e9\u05de\u05d9\u05d9\u05dd, \u05dc\u05de\u05e9\u05d4\u05d5 \u05d0\u05d9\u05e0\u05e1\u05d5\u05e4\u05d9, \u05d5\u05dc\u05db\u05df \u05ea\u05de\u05d9\u05d3 \u05d9\u05e9 \u05ea\u05e9\u05d5\u05e7\u05d4 \u05dc\u05e9\u05d0\u05d5\u05e3 \u05dc\u05de\u05e2\u05dc\u05d4, \u05dc\u05d2\u05d3\u05d5\u05dc \u05d5\u05dc\u05d4\u05ea\u05e4\u05ea\u05d7.\n\u05d5\u05d6\u05d5 \u05d1\u05d3\u05d9\u05d5\u05e7 \u05d4\u05d4\u05d6\u05d3\u05de\u05e0\u05d5\u05ea \u05dc\u05d4\u05ea\u05d1\u05d5\u05e0\u05df \u05e2\u05dc \u05db\u05da \u05d1\u05ea\u05e4\u05d9\u05dc\u05d4: \u05e7\u05d3\u05d5\u05e9 \u05e7\u05d3\u05d5\u05e9 \u05e7\u05d3\u05d5\u05e9 \u05de\u05d5\u05dc \u05d0\u05d9\u05d4 \u05de\u05e7\u05d5\u05dd \u05db\u05d1\u05d5\u05d3\u05d5\n\u05d4\u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea \u05e2\u05dc \u05d2\u05d3\u05dc\u05d5\u05ea \u05d4\' \u05d5\u05e9\u05d0\u05dc\u05ea \u05d4\u05e9\u05d0\u05d9\u05e4\u05d4 \u05dc\u05d4\u05d1\u05d9\u05df \u05d0\u05ea \u05d3\u05e8\u05db\u05d9 \u05d4\u05d1\u05d5\u05e8\u05d0 \u05d5\u05d2\u05dd \u05dc\u05d4\u05ea\u05d7\u05d1\u05e8 \u05d9\u05d5\u05ea\u05e8 \u05d0\u05dc \u05db\u05dc \u05de\u05d4 \u05e9\u05e7\u05d3\u05d5\u05e9:\n1. "\u05e7\u05b8\u05d3\u05d5\u05b9\u05e9\u05c1 \u05e7\u05b8\u05d3\u05d5\u05b9\u05e9\u05c1 \u05e7\u05b8\u05d3\u05d5\u05b9\u05e9\u05c1 \u05d4\' \u05e6\u05b0\u05d1\u05b8\u05d0\u05d5\u05b9\u05ea \u05de\u05b0\u05dc\u05b9\u05d0 \u05db\u05b8\u05dc \u05d4\u05b8\u05d0\u05b8\u05e8\u05b6\u05e5 \u05db\u05b0\u05bc\u05d1\u05d5\u05b9\u05d3\u05d5\u05b9" (\u05d9\u05e9\u05e2\u05d9\u05d4\u05d5 \u05d5, \u05d2) \u2013 \u05d6\u05d5 \u05d4\u05db\u05e8\u05d6\u05d4 \u05d1\u05e8\u05d5\u05e8\u05d4 \u05e2\u05dc \u05d2\u05d3\u05dc\u05d5\u05ea\u05d5 \u05e9\u05dc \u05d4\', \u05e9\u05de\u05dc\u05d0 \u05db\u05dc \u05d4\u05d0\u05e8\u05e5 \u05db\u05d1\u05d5\u05d3\u05d5, \u05db\u05dc\u05d5\u05de\u05e8, \u05d4\u05d5\u05d0 \u05e0\u05d5\u05db\u05d7 \u05d5\u05e9\u05d5\u05dc\u05d8 \u05d1\u05db\u05dc, \u05d0\u05e4\u05d9\u05dc\u05d5 \u05d1\u05e2\u05d5\u05dc\u05dd \u05d4\u05d7\u05d5\u05de\u05e8\u05d9 \u05e9\u05dc\u05e0\u05d5. \u05d6\u05d4 \u05de\u05d3\u05d2\u05d9\u05e9 \u05d0\u05ea \u05d4\u05e9\u05dc\u05de\u05d5\u05ea \u05d4\u05e7\u05d9\u05d9\u05de\u05ea \u05db\u05d1\u05e8.\n2. "\u05d0\u05b5\u05d9\u05b8\u05d4 \u05de\u05b0\u05e7\u05d5\u05b9\u05dd \u05db\u05b0\u05bc\u05d1\u05d5\u05b9\u05d3\u05d5\u05b9 \u05dc\u05b0\u05d4\u05b7\u05e2\u05e8\u05d9\u05e6\u05d5\u05b9" \u2013 \u05db\u05d0\u05df, \u05d1\u05de\u05e7\u05d5\u05dd \u05d4\u05db\u05e8\u05d6\u05d4 \u05e0\u05d7\u05e8\u05e6\u05ea \u05e2\u05dc \u05d2\u05d3\u05d5\u05dc\u05ea \u05d4\u05d7\u05d9\u05d9\u05dd \u05d5\u05d9\u05db\u05d5\u05dc\u05d5\u05ea \u05d4\u05d1\u05d5\u05e8\u05d0 \u05d4\u05d0\u05d9\u05e0\u05e1\u05d5\u05e4\u05d9\u05d5\u05ea, \u05d9\u05e9 \u05e9\u05d0\u05dc\u05d4: \u05d4\u05d9\u05db\u05df \u05d0\u05ea\u05d4 \u05d1\u05d0\u05de\u05ea? \u05d4\u05d0\u05dd \u05d0\u05ea\u05d4 \u05e7\u05d9\u05d9\u05dd? \u05e9\u05d0\u05dc\u05d4 \u05d0\u05e0\u05d5\u05e9\u05d9\u05ea \u05e9\u05d9\u05e9 \u05dc\u05d4 \u05de\u05e7\u05d5\u05dd \u05d3\u05d5\u05d5\u05e7\u05d0 \u05d1\u05ea\u05e4\u05d9\u05dc\u05d4.  \u05d4\u05d9\u05db\u05df \u05d9\u05e9 \u05d9\u05d5\u05ea\u05e8 \u05e2\u05e8\u05da \u05dc\u05d7\u05d9\u05d9\u05dd? \u05d0\u05d5 \u05d4\u05d9\u05db\u05df \u05d4\u05e9\u05dc\u05de\u05d5\u05ea? \u05d4\u05d9\u05db\u05df \u05d4\u05dd \u05db\u05d0\u05e9\u05e8 \u05d9\u05e9 \u05d7\u05d5\u05e1\u05e8 \u05e9\u05dc\u05de\u05d5\u05ea \u05d0\u05d5 \u05d8\u05e8\u05d2\u05d3\u05d9\u05d5\u05ea \u05e0\u05d5\u05e8\u05d0\u05d9\u05d5\u05ea?\n\u05d6\u05d5 \u05e7\u05e8\u05d9\u05d0\u05d4 \u05dc\u05d7\u05d9\u05e4\u05d5\u05e9 \u05de\u05ea\u05de\u05d9\u05d3, \u05d4\u05db\u05e8\u05d4 \u05d1\u05db\u05da \u05e9\u05d4\u05d1\u05d5\u05e8\u05d0 \u05d0\u05d9\u05e0\u05e1\u05d5\u05e4\u05d9, \u05d5\u05e9\u05d0\u05e0\u05d7\u05e0\u05d5 \u05d0\u05e3 \u05e4\u05e2\u05dd \u05dc\u05d0 \u05d1\u05d0\u05de\u05ea \u05de\u05e9\u05d9\u05d2\u05d9\u05dd \u05d0\u05ea \u05de\u05dc\u05d5\u05d0 \u05de\u05e9\u05de\u05e2\u05d5\u05ea \u05d4\u05d7\u05d9\u05d9\u05dd \u05d5\u05d4\u05d1\u05e8\u05d9\u05d0\u05d4. \u05d6\u05d5 \u05d4\u05e9\u05d0\u05d9\u05e4\u05d4 \u05dc\u05d9\u05d5\u05ea\u05e8, \u05dc\u05d4\u05d1\u05e0\u05d4 \u05e2\u05de\u05d5\u05e7\u05d4 \u05d9\u05d5\u05ea\u05e8, \u05dc\u05e2\u05dc\u05d9\u05d9\u05d4 \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea \u05e9\u05d0\u05d9\u05df \u05dc\u05d4 \u05e1\u05d5\u05e3.\n\u05db\u05de\u05d5 \u05e9\u05d1\u05e7\u05d3\u05d5\u05e9\u05d4 \u05d9\u05e9 \u05e9\u05d9\u05dc\u05d5\u05d1 \u05e9\u05dc \u05d5\u05d3\u05d0\u05d5\u05ea \u05d5\u05d7\u05d9\u05e4\u05d5\u05e9, \u05db\u05da \u05d2\u05dd \u05d1\u05d7\u05d9\u05d9\u05dd \u05d4\u05d2\u05e9\u05de\u05d9\u05d9\u05dd \u05d5\u05d4\u05e8\u05d2\u05e9\u05d9\u05d9\u05dd:\n\u05dc\u05d4\u05d9\u05d5\u05ea \u05e9\u05de\u05d7 \u05d1\u05d7\u05dc\u05e7\u05da \u05d6\u05d4 \u05dc\u05d4\u05db\u05d9\u05e8 \u05d1\u05db\u05da \u05e9"\u05de\u05dc\u05d5\u05d0 \u05db\u05dc \u05d4\u05d0\u05e8\u05e5 \u05db\u05d1\u05d5\u05d3\u05d5" \u05d4\u05e9\u05dd (\u05d4\u05d0\u05d5\u05e8, \u05d4\u05e7\u05d3\u05d5\u05e9\u05d4 \u05d5\u05d4\u05e9\u05de\u05d7\u05d4) \u05db\u05d1\u05e8 \u05e0\u05de\u05e6\u05d0\u05d9\u05dd \u05db\u05d0\u05df, \u05d1\u05de\u05d4 \u05e9\u05d9\u05e9 \u05dc\u05e0\u05d5.\n\u05d9\u05d7\u05d3 \u05e2\u05dd \u05d6\u05d0\u05ea \u05dc\u05e9\u05d0\u05d5\u05e3 \u05dc\u05d9\u05d5\u05ea\u05e8. \u05db\u05dc\u05d5\u05de\u05e8 \u05dc\u05d7\u05d9\u05d5\u05ea \u05de\u05ea\u05d5\u05da \u05d4\u05e9\u05d0\u05dc\u05d4 "\u05d0\u05d9\u05d4 \u05de\u05e7\u05d5\u05dd \u05db\u05d1\u05d5\u05d3\u05d5" \u05db\u05dc\u05d5\u05de\u05e8 \u05dc\u05d7\u05e4\u05e9 \u05e9\u05d9\u05d4\u05d9\u05d4 \u05e2\u05d5\u05d3 \u05d9\u05d5\u05ea\u05e8 \u05d8\u05d5\u05d1 \u05d5\u05e2\u05d5\u05d3 \u05d9\u05d5\u05ea\u05e8 \u05d8\u05d5\u05d1. \u05d9\u05d5\u05ea\u05e8 \u05e2\u05d5\u05de\u05e7, \u05de\u05e9\u05de\u05e2\u05d5\u05ea \u05d5\u05e6\u05de\u05d9\u05d7\u05d4.\n\u05d4\u05d0\u05d9\u05d6\u05d5\u05df \u05d4\u05e0\u05db\u05d5\u05df \u05d4\u05d5\u05d0 \u05dc\u05d4\u05d7\u05d6\u05d9\u05e7 \u05d1\u05e9\u05e0\u05d9\u05d4\u05dd \u05d9\u05d7\u05d3: \u05dc\u05d4\u05d9\u05d5\u05ea \u05d0\u05e1\u05d9\u05e8 \u05ea\u05d5\u05d3\u05d4 \u05e2\u05dc \u05d4\u05de\u05e7\u05d5\u05dd \u05e9\u05d1\u05d5 \u05d0\u05e0\u05d5 \u05e0\u05de\u05e6\u05d0\u05d9\u05dd, \u05d0\u05da \u05dc\u05d4\u05de\u05e9\u05d9\u05da \u05dc\u05e9\u05d0\u05d5\u05dc, \u05dc\u05d7\u05e4\u05e9 \u05d5\u05dc\u05e9\u05d0\u05d5\u05e3 \u05d2\u05d1\u05d5\u05d4 \u05d9\u05d5\u05ea\u05e8, \u05d1\u05d3\u05d9\u05d5\u05e7 \u05db\u05de\u05d5 \u05d4\u05d7\u05d9\u05d1\u05d5\u05e8 \u05d1\u05d9\u05df \u05d4\u05e9\u05de\u05d9\u05d9\u05dd \u05d5\u05d4\u05d0\u05e8\u05e5 \u05d1\u05e4\u05e1\u05d5\u05e7.\n\u05d6\u05d5 \u05d2\u05dd \u05d4\u05d4\u05d1\u05e0\u05d4 \u05e9\u05db\u05dc \u05d0\u05d7\u05d3 \u05e2\u05d5\u05d1\u05e8 \u05e8\u05d2\u05e2\u05d9\u05dd \u05e9\u05dc \u05d0\u05d9\u05d4 \u05de\u05e7\u05d5\u05dd \u05db\u05d1\u05d5\u05d3\u05d5. \u05e9\u05dc \u05d7\u05d5\u05e1\u05e8 \u05d4\u05d1\u05e0\u05d4 \u05d0\u05d5 \u05d0\u05de\u05d5\u05e0\u05d4 \u05d1\u05db\u05d5\u05d7 \u05e2\u05dc\u05d9\u05d5\u05df. \u05d0\u05d5 \u05d1\u05db\u05da \u05e9\u05d4\u05db\u05d5\u05d7 \u05d4\u05e2\u05dc\u05d9\u05d5\u05df \u05d0\u05d5\u05d4\u05d1 \u05d0\u05d5\u05ea\u05e0\u05d5 \u05d5\u05ea\u05d5\u05de\u05da \u05d1\u05e0\u05d5.   \u05d5\u05e6\u05e8\u05d9\u05da \u05dc\u05d4\u05d9\u05d5\u05ea \u05de\u05d0\u05d3 \u05e2\u05d3\u05d9\u05e0\u05d9\u05dd \u05e2\u05dd \u05d0\u05d3\u05dd \u05d1\u05e8\u05d2\u05e2 \u05e9\u05d4\u05d5\u05d0 \u05d1\u05d0\u05d9\u05d4 \u05de\u05e7\u05d5\u05dd \u05db\u05d1\u05d5\u05d3\u05d5. \u05d6\u05d4 \u05dc\u05d0\u05d5 \u05d3\u05d5\u05d5\u05e7\u05d0 \u05d4\u05d6\u05de\u05df \u05dc\u05d4\u05d2\u05d9\u05d3 \u05dc\u05d5 \u05e9\u05d4\u05e2\u05d5\u05dc\u05dd \u05e7\u05d3\u05d5\u05e9 \u05e7\u05d3\u05d5\u05e9 \u05e7\u05d3\u05d5\u05e9. \u05d0\u05d5\u05dc\u05d9 \u05d0\u05d9\u05df \u05dc\u05d5 \u05db\u05dc\u05d9\u05dd \u05dc\u05e9\u05de\u05d5\u05e2 \u05e2\u05db\u05e9\u05d9\u05d5 \u05d4\u05d8\u05e4\u05ea \u05d0\u05de\u05d5\u05e0\u05d4. \u05d6\u05d5 \u05d4\u05d6\u05d3\u05de\u05e0\u05d5\u05ea \u05dc\u05d1\u05d3\u05d5\u05e7 \u05d0\u05d9\u05da \u05d0\u05e0\u05d7\u05e0\u05d5 \u05e2\u05d5\u05de\u05d3\u05d9\u05dd \u05e0\u05d5\u05db\u05d7\u05d9\u05dd \u05de\u05d5\u05dc \u05d7\u05d5\u05e1\u05e8 \u05e9\u05dc\u05de\u05d5\u05ea \u05d1\u05e2\u05d5\u05dc\u05dd \u05d5\u05d2\u05dd \u05de\u05d5\u05dc \u05d0\u05e0\u05e9\u05d9\u05dd \u05d0\u05d7\u05e8\u05d9\u05dd \u05e9\u05d7\u05d5\u05d5\u05d9\u05dd \u05d7\u05d5\u05e1\u05e8 \u05e9\u05dc\u05de\u05d5\u05ea. \u05de\u05e2\u05d1\u05e8 \u05dc\u05db\u05da \u05e9\u05d4\u05e2\u05d5\u05dc\u05dd \u05d1\u05d0\u05de\u05ea \u05d3\u05d5\u05e8\u05e9 \u05e2\u05d3\u05d9\u05d9\u05df \u05e9\u05d9\u05e4\u05d5\u05e8. \u05d5\u05dc\u05d7\u05d9\u05d5\u05ea \u05d7\u05d9\u05d9\u05dd \u05e9\u05e8\u05d5\u05d0\u05d9\u05dd \u05e8\u05e7 \u05d8\u05d5\u05d1 \u05db\u05d9 \u05dc\u05d9 \u05d8\u05d5\u05d1 \u05d0\u05d5 \u05d8\u05d5\u05d1 \u05d9\u05d7\u05e1\u05d9\u05ea \u05d6\u05d5 \u05d4\u05ea\u05e2\u05dc\u05de\u05d5\u05ea \u05de\u05db\u05d0\u05d1 \u05e9\u05dc \u05d0\u05d7\u05e8\u05d9\u05dd. \u05d5\u05d4\u05e8\u05d9 \u05e0\u05e6\u05d8\u05d5\u05d5\u05d9\u05e0\u05d5 \u05dc\u05ea\u05e7\u05df \u05d0\u05ea \u05d4\u05e2\u05d5\u05dc\u05dd. \u05db\u05dc\u05d5\u05de\u05e8 \u05dc\u05e8\u05d0\u05d5\u05ea \u05d0\u05ea \u05d4\u05de\u05d7\u05d3\u05dc\u05d9\u05dd, \u05dc\u05d3\u05e2\u05ea \u05e9\u05d4\u05db\u05dc \u05d1\u05d9\u05d3\u05d9 \u05e9\u05de\u05d9\u05d9\u05dd \u05d5\u05e2\u05d3\u05d9\u05d9\u05df \u05dc\u05d4\u05e9\u05ea\u05d3\u05dc \u05dc\u05ea\u05e7\u05df \u05d1\u05e2\u05e6\u05de\u05e0\u05d5.\n\u05d1\u05e0\u05d9\u05d9\u05ea \u05de\u05e2\u05e8\u05db\u05ea \u05d4\u05d9\u05d7\u05e1\u05d9\u05dd \u05e9\u05dc\u05e0\u05d5 \u05e2\u05dd \u05d4\u05e2\u05d5\u05dc\u05dd\n\u05de\u05e2\u05d1\u05e8 \u05dc\u05d7\u05d9\u05d6\u05d5\u05e7 \u05d4\u05ea\u05d7\u05d5\u05e9\u05d5\u05ea \u05d4\u05d0\u05d9\u05e9\u05d9\u05d5\u05ea, \u05d4\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9\u05ea \u05de\u05e1\u05d9\u05d9\u05e2\u05ea \u05dc\u05e0\u05d5 \u05dc\u05e2\u05e6\u05d1 \u05d0\u05ea \u05d9\u05d7\u05e1\u05d9\u05e0\u05d5 \u05e2\u05dd \u05d4\u05d6\u05d5\u05dc\u05ea \u05de\u05ea\u05d5\u05da \u05e2\u05e8\u05db\u05d9\u05dd \u05e9\u05dc:\n\u05d0\u05e1\u05e8\u05d8\u05d9\u05d1\u05d9\u05d5\u05ea.\n\u05e0\u05ea\u05d9\u05e0\u05d4.\n\u05d4\u05db\u05dc\u05d4.\n\u05d0\u05d4\u05d1\u05d4.\n\u05dc\u05e1\u05d9\u05db\u05d5\u05dd, \u05d4\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9\u05ea \u05d0\u05d9\u05e0\u05d4 \u05e8\u05e7 \u05db\u05dc\u05d9 \u05dc\u05d4\u05e8\u05d2\u05e2\u05ea \u05d4\u05e0\u05e4\u05e9, \u05d0\u05dc\u05d0 \u05d3\u05e8\u05da \u05de\u05e2\u05de\u05d9\u05e7\u05d4 \u05dc\u05e9\u05d9\u05e0\u05d5\u05d9 \u05ea\u05d5\u05d3\u05e2\u05ea\u05d9, \u05d8\u05d9\u05e4\u05d5\u05d7 \u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05d7\u05d9\u05d5\u05d1\u05d9\u05d5\u05ea \u05d5\u05d7\u05d9\u05d6\u05d5\u05e7 \u05d4\u05e7\u05e9\u05e8 \u05e9\u05dc\u05e0\u05d5 \u05e2\u05dd \u05e2\u05e6\u05de\u05e0\u05d5, \u05e2\u05dd \u05d4\u05e2\u05d5\u05dc\u05dd \u05d5\u05e2\u05dd \u05d4\u05d1\u05d5\u05e8\u05d0.\n\u05e9\u05d5\u05d4\u05d9\u05dd \u05d0\u05d7\u05e8\u05d9 \u05dc\u05e8\u05d3\u05ea \u05dc\u05e2\u05d5\u05dc\u05dd \u05dc\u05e4\u05e8\u05e7\u05d8\u05d9\u05e7\u05d4.\n\u05d4\u05d4\u05db\u05e0\u05d4 \u05dc\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4\n\u05d1\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9\u05ea \u05d0\u05e0\u05d5 \u05e9\u05de\u05d9\u05dd \u05dc\u05d1 \u05dc\u05e6\u05d5\u05e8\u05d4 \u05e9\u05d1\u05d4 \u05d0\u05e0\u05d5 \u05d9\u05d5\u05e9\u05d1\u05d9\u05dd, \u05dc\u05d0\u05df \u05e4\u05e0\u05d9\u05e0\u05d5 \u05de\u05d5\u05e4\u05e0\u05d5\u05ea, \u05d5\u05db\u05d9\u05e6\u05d3 \u05d0\u05e0\u05d5 \u05e0\u05d5\u05e9\u05de\u05d9\u05dd. \u05d1\u05e0\u05d9\u05d2\u05d5\u05d3 \u05dc\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d4\u05e2\u05d5\u05dc\u05de\u05d9\u05ea, \u05e9\u05d1\u05d4 \u05d4\u05de\u05d8\u05e8\u05d4 \u05d4\u05d9\u05d0 \u05dc\u05e4\u05e0\u05d5\u05ea \u05d0\u05ea \u05d4\u05de\u05d7\u05e9\u05d1\u05d5\u05ea, \u05d1\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9\u05ea \u05d4\u05de\u05d8\u05e8\u05d4 \u05d4\u05d9\u05d0 \u05dc\u05db\u05d5\u05d5\u05df \u05d0\u05ea \u05d4\u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05dc\u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05d4\u05e8\u05e6\u05d5\u05d9\u05d5\u05ea.\n\u05db\u05d9\u05e6\u05d3 \u05e0\u05e2\u05e9\u05d4 \u05d6\u05d0\u05ea?\n\u05d4\u05db\u05d9\u05d5\u05d5\u05df \u05d4\u05d5\u05d0 \u05dc\u05d0 \u05d1\u05d4\u05db\u05e8\u05d7 \u05dc\u05d4\u05e4\u05e1\u05d9\u05e7 \u05d0\u05ea \u05d4\u05de\u05d7\u05e9\u05d1\u05d5\u05ea, \u05d0\u05dc\u05d0 \u05dc\u05e2\u05e6\u05d1 \u05d0\u05d5\u05ea\u05df \u05db\u05da \u05e9\u05d9\u05ea\u05de\u05e7\u05d3\u05d5 \u05d1\u05e0\u05d5\u05e9\u05d0\u05d9\u05dd \u05d5\u05d1\u05db\u05d9\u05d5\u05d5\u05e0\u05d9\u05dd \u05e9\u05de\u05d5\u05d1\u05d9\u05dc\u05d9\u05dd \u05d0\u05d5\u05ea\u05e0\u05d5 \u05dc\u05d4\u05ea\u05d7\u05d1\u05e8\u05d5\u05ea \u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05e2\u05de\u05d5\u05e7\u05d4 \u05d9\u05d5\u05ea\u05e8 \u05e2\u05dd \u05e2\u05e6\u05de\u05e0\u05d5 \u05d5\u05e2\u05dd \u05d4\u05d1\u05e8\u05d9\u05d0\u05d4.\n\u05db\u05d9\u05e6\u05d3 \u05d9\u05d5\u05e9\u05d1\u05d9\u05dd \u05d1\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9\u05ea\n\u05db\u05de\u05d5 \u05e9\u05db\u05d1\u05e8 \u05d0\u05de\u05e8\u05e0\u05d5 \u05d1\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9\u05ea, \u05d1\u05e0\u05d9\u05d2\u05d5\u05d3 \u05dc\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d4\u05e2\u05d5\u05dc\u05de\u05d9\u05ea, \u05d9\u05d5\u05e9\u05d1\u05d9\u05dd \u05e2\u05dd \u05d4\u05e8\u05d2\u05dc\u05d9\u05d9\u05dd \u05e2\u05dc \u05d4\u05e7\u05e8\u05e7\u05e2 \u05d5\u05d9\u05d3\u05d9\u05d9\u05dd \u05e4\u05ea\u05d5\u05d7\u05d5\u05ea \u05db\u05dc\u05e4\u05d9 \u05d4\u05e9\u05de\u05d9\u05d9\u05dd. \u05d9\u05e9 \u05dc\u05db\u05da \u05db\u05de\u05d4 \u05de\u05e9\u05de\u05e2\u05d5\u05d9\u05d5\u05ea.\n\u05e8\u05d0\u05e9\u05d9\u05ea, \u05d0\u05e0\u05d5 \u05e8\u05d5\u05e6\u05d9\u05dd \u05dc\u05d4\u05d7\u05d9\u05dc \u05e2\u05dc \u05d4\u05de\u05d5\u05d3\u05e2\u05d5\u05ea \u05e9\u05dc\u05e0\u05d5 \u05d0\u05ea \u05d4\u05d7\u05d9\u05d1\u05d5\u05e8 \u05d1\u05d9\u05df \u05e9\u05de\u05d9\u05d9\u05dd \u05d5\u05d0\u05e8\u05e5. \u05d4\u05e8\u05d2\u05dc\u05d9\u05d9\u05dd \u05e4\u05e8\u05d5\u05e1\u05d5\u05ea \u05e2\u05dc \u05d4\u05e7\u05e8\u05e7\u05e2, \u05de\u05d9\u05d9\u05e6\u05d2\u05d5\u05ea \u05d0\u05ea \u05d4\u05d7\u05d9\u05d1\u05d5\u05e8 \u05e9\u05dc\u05e0\u05d5 \u05dc\u05d0\u05d3\u05de\u05d4, \u05d5\u05d9\u05d3\u05d9\u05e0\u05d5 \u05de\u05d5\u05e4\u05e0\u05d5\u05ea \u05db\u05dc\u05e4\u05d9 \u05d4\u05e9\u05de\u05d9\u05d9\u05dd, \u05de\u05d9\u05d9\u05e6\u05d2\u05d5\u05ea \u05d0\u05ea \u05d4\u05e7\u05e9\u05e8 \u05e2\u05dd \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9\u05d5\u05ea \u05d5\u05d4\u05d1\u05e8\u05db\u05d4 \u05d4\u05e2\u05dc\u05d9\u05d5\u05e0\u05d4.\n\u05e9\u05e0\u05d9\u05ea, \u05d0\u05e0\u05d5 \u05e9\u05d5\u05d0\u05d1\u05d9\u05dd \u05d0\u05e0\u05e8\u05d2\u05d9\u05d4 \u05de\u05d4\u05e9\u05de\u05d9\u05d9\u05dd \u05d5\u05de\u05e2\u05d1\u05d9\u05e8\u05d9\u05dd \u05d0\u05d5\u05ea\u05d4 \u05dc\u05d9\u05d3\u05d9 \u05d1\u05d9\u05e6\u05d5\u05e2 \u05d1\u05e2\u05d5\u05dc\u05dd \u05d4\u05d6\u05d4. \u05d1\u05db\u05da \u05d0\u05e0\u05d5 \u05de\u05d6\u05db\u05d9\u05e8\u05d9\u05dd \u05dc\u05e2\u05e6\u05de\u05e0\u05d5 \u05e9\u05d4\u05d7\u05d9\u05d9\u05dd \u05de\u05e7\u05d5\u05e8\u05dd \u05d1\u05d1\u05e8\u05db\u05d4 (\u05de\u05d6\u05dc) \u05de\u05d4\u05e9\u05de\u05d9\u05d9\u05dd, \u05d0\u05da \u05d4\u05d4\u05e9\u05ea\u05d3\u05dc\u05d5\u05ea \u05d1\u05e2\u05d5\u05dc\u05dd \u05d4\u05d6\u05d4 \u05d4\u05d9\u05d0 \u05e2\u05dc\u05d9\u05e0\u05d5. \u05db\u05e9\u05e0\u05e6\u05dc\u05d9\u05d7, \u05e0\u05d6\u05db\u05d5\u05e8 \u05e9\u05dc\u05d0 \u05d1\u05d6\u05db\u05d5\u05ea \u05e2\u05e6\u05de\u05e0\u05d5 \u05d4\u05e6\u05dc\u05d7\u05ea\u05d9, \u05d0\u05dc\u05d0 \u05d1\u05d6\u05db\u05d5\u05ea \u05d4\u05db\u05d5\u05d7\u05d5\u05ea, \u05d4\u05d1\u05e8\u05db\u05d4 \u05d5\u05d4\u05de\u05d6\u05dc \u05e9\u05e7\u05d9\u05d1\u05dc\u05e0\u05d5 \u05de\u05d4\u05e9\u05de\u05d9\u05d9\u05dd, \u05db\u05de\u05d5 \u05e9\u05e0\u05d0\u05de\u05e8: "\u05dc\u05d0 \u05db\u05d5\u05d7\u05d9 \u05d5\u05e2\u05d5\u05e6\u05dd \u05d9\u05d3\u05d9 \u05e2\u05e9\u05d4 \u05dc\u05d9 \u05d0\u05ea \u05d4\u05d7\u05d9\u05dc \u05d4\u05d6\u05d4".\n\u05d1\u05e0\u05d5\u05e1\u05e3, \u05d1\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d4\u05e2\u05d5\u05dc\u05de\u05d9\u05ea \u05e0\u05d4\u05d5\u05d2 \u05dc\u05e1\u05d2\u05d5\u05e8 \u05d0\u05ea \u05d4\u05d9\u05d3\u05d9\u05d9\u05dd, \u05d0\u05da \u05d0\u05e6\u05dc\u05e0\u05d5 \u05d0\u05e0\u05d5 \u05e4\u05d5\u05ea\u05d7\u05d9\u05dd \u05d0\u05ea \u05d4\u05d9\u05d3\u05d9\u05d9\u05dd. \u05d0\u05e0\u05d5 \u05de\u05ea\u05d7\u05d1\u05e8\u05d9\u05dd \u05dc\u05e8\u05d5\u05d7\u05d1 \u05d4\u05d9\u05d3, \u05dc\u05e9\u05e4\u05e2 \u05e9\u05d9\u05d5\u05e8\u05d3 \u05d0\u05dc\u05d9\u05e0\u05d5 \u05de\u05d4\u05e9\u05de\u05d9\u05d9\u05dd, \u05d5\u05dc\u05d0 \u05e1\u05d5\u05d2\u05e8\u05d9\u05dd \u05d0\u05ea \u05e2\u05e6\u05de\u05e0\u05d5 \u05d1\u05e4\u05e0\u05d9 \u05d4\u05d0\u05e0\u05e8\u05d2\u05d9\u05d4 \u05d4\u05d6\u05d5.\n\u05e4\u05e0\u05d9\u05e0\u05d5 \u05dc\u05de\u05d6\u05e8\u05d7\n\u05d4\u05e4\u05e0\u05d9\u05d9\u05d4 \u05dc\u05de\u05d6\u05e8\u05d7 \u05d1\u05e2\u05ea \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d4\u05d9\u05d0 \u05de\u05e0\u05d4\u05d2 \u05e9\u05e0\u05d5\u05d1\u05e2 \u05de\u05d4\u05e9\u05d0\u05d9\u05e4\u05d4 \u05dc\u05db\u05d5\u05d5\u05df \u05d0\u05ea \u05d4\u05dc\u05d1 \u05d5\u05d4\u05de\u05d7\u05e9\u05d1\u05d4 \u05db\u05dc\u05e4\u05d9 \u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd, \u05d5\u05d1\u05e4\u05e8\u05d8 \u05db\u05dc\u05e4\u05d9 \u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9. \u05dc\u05d4\u05dc\u05df \u05d4\u05d4\u05e1\u05d1\u05e8\u05d9\u05dd \u05d4\u05de\u05e8\u05db\u05d6\u05d9\u05d9\u05dd \u05dc\u05de\u05e0\u05d4\u05d2 \u05d6\u05d4.\n\u05d4\u05de\u05d6\u05e8\u05d7 \u05de\u05e1\u05de\u05dc \u05d0\u05ea \u05d4\u05d0\u05d5\u05e8 \u05d4\u05d7\u05d3\u05e9. \u05db\u05dc \u05d9\u05d5\u05dd \u05de\u05d0\u05d9\u05e8 \u05d9\u05d5\u05dd \u05d7\u05d3\u05e9 \u05e2\u05dd \u05d1\u05e8\u05db\u05d4 \u05d7\u05d3\u05e9\u05d4 \u05dc\u05e2\u05d5\u05dc\u05dd. \u05db\u05da \u05d2\u05dd \u05d0\u05e0\u05d5 \u05d6\u05d5\u05db\u05e8\u05d9\u05dd \u05dc\u05e4\u05e0\u05d5\u05ea \u05de\u05e7\u05d5\u05dd \u05dc\u05d0\u05d5\u05e4\u05d8\u05d9\u05de\u05d9\u05d5\u05ea \u05d7\u05d3\u05e9\u05d4 \u05d1\u05db\u05dc \u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4. \u05db\u05dc \u05de\u05d4 \u05e9\u05e8\u05e6\u05d9\u05e0\u05d5 \u05e9\u05d9\u05e7\u05e8\u05d4 \u05e2\u05d3 \u05e2\u05db\u05e9\u05d9\u05d5 \u05d5\u05e2\u05d3\u05d9\u05d9\u05df \u05dc\u05d0 \u05e7\u05e8\u05d4, \u05e0\u05d6\u05db\u05d5\u05e8 \u05db\u05d9 \u05d2\u05dd \u05d0\u05dd \u05dc\u05d0 \u05e7\u05e8\u05d4 \u05e2\u05d3 \u05db\u05d4, \u05d6\u05d4 \u05dc\u05d0 \u05d1\u05d2\u05dc\u05dc \u05e9\u05dc\u05d0 \u05d9\u05e7\u05e8\u05d4, \u05d0\u05dc\u05d0 \u05db\u05d9 \u05d6\u05d4 \u05e2\u05d3\u05d9\u05d9\u05df \u05dc\u05d0 \u05d4\u05d2\u05d9\u05e2. \u05db\u05de\u05d5 \u05e9\u05d4\u05e9\u05de\u05e9 \u05d6\u05d5\u05e8\u05d7\u05ea \u05db\u05dc \u05d9\u05d5\u05dd \u05de\u05d7\u05d3\u05e9, \u05db\u05da \u05d2\u05dd \u05d9\u05d2\u05d9\u05e2 \u05d0\u05dc\u05d9\u05e0\u05d5 \u05d0\u05d5\u05e8 \u05d5\u05e9\u05e4\u05e2 \u05d7\u05d3\u05e9\u05d9\u05dd \u05d4\u05d9\u05d5\u05dd.\n\u05e0\u05d9\u05e4\u05ea\u05d7 \u05d2\u05dd \u05dc\u05d4\u05e4\u05e0\u05de\u05d4 \u05e9\u05d3\u05d1\u05e8\u05d9\u05dd \u05d8\u05d5\u05d1\u05d9\u05dd \u05e9\u05e2\u05d5\u05d3 \u05dc\u05d0 \u05e7\u05e8\u05d5 \u05dc\u05e0\u05d5, \u05e2\u05d3\u05d9\u05d9\u05df \u05dc\u05d0 \u05e7\u05e8\u05d5 \u05db\u05d9 \u05dc\u05d0 \u05d4\u05d2\u05e2\u05e0\u05d5 \u05dc\u05ea\u05d5\u05d1\u05e0\u05d4 \u05de\u05e1\u05d5\u05d9\u05de\u05ea \u05e9\u05de\u05d7\u05db\u05d4 \u05dc\u05d4\u05ea\u05d2\u05dc\u05d5\u05ea \u05dc\u05e0\u05d5. \u05d5\u05d0\u05d5\u05dc\u05d9 \u05d4\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d4\u05d6\u05d5 \u05ea\u05d4\u05d9\u05d4 \u05d6\u05d5 \u05e9\u05ea\u05e4\u05ea\u05d7 \u05dc\u05e0\u05d5 \u05d0\u05ea \u05d4\u05ea\u05d5\u05d1\u05e0\u05d4 \u05e9\u05ea\u05d0\u05e4\u05e9\u05e8 \u05d2\u05dd \u05d0\u05ea \u05d4\u05e9\u05e4\u05e2 \u05d4\u05d2\u05e9\u05de\u05d9.\n\u05d1\u05de\u05d9\u05dc\u05d9\u05dd \u05d0\u05d7\u05e8\u05d5\u05ea, \u05d1\u05db\u05dc \u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d0\u05e0\u05d5 \u05e4\u05d5\u05ea\u05d7\u05d9\u05dd \u05d0\u05ea \u05e2\u05e6\u05de\u05e0\u05d5 \u05dc\u05d0 \u05e8\u05e7 \u05dc\u05d1\u05e7\u05e9 \u05d0\u05ea \u05d4\u05e9\u05e4\u05e2 \u05d4\u05d2\u05e9\u05de\u05d9 \u05d4\u05d7\u05e1\u05e8 \u05dc\u05e0\u05d5, \u05d0\u05dc\u05d0 \u05d1\u05e2\u05d9\u05e7\u05e8 \u05d0\u05e0\u05d5 \u05de\u05d7\u05e4\u05e9\u05d9\u05dd \u05d0\u05ea \u05d4\u05ea\u05d5\u05d1\u05e0\u05d5\u05ea \u05e9\u05de\u05e4\u05e8\u05d9\u05e2\u05d5\u05ea \u05dc\u05e0\u05d5 \u05dc\u05d4\u05ea\u05e7\u05d3\u05dd \u05d1\u05d7\u05d9\u05d9\u05dd.\n\u05d0\u05dd \u05ea\u05d7\u05e9\u05d1\u05d5 \u05e2\u05dc \u05db\u05da, \u05d9\u05d9\u05ea\u05db\u05df \u05e9\u05de\u05d4 \u05e9\u05de\u05e4\u05e8\u05d9\u05e2 \u05dc\u05db\u05dd \u05dc\u05d4\u05ea\u05e7\u05d3\u05dd \u05d1\u05d7\u05d9\u05d9\u05dd \u05d4\u05d5\u05d0 \u05db\u05d0\u05d1 \u05d1\u05d2\u05d1 \u05d0\u05d5 \u05d7\u05d5\u05e1\u05e8 \u05d1\u05db\u05e1\u05e3 \u05dc\u05de\u05d9\u05de\u05d5\u05e9 \u05d4\u05d7\u05dc\u05d5\u05de\u05d5\u05ea. \u05d5\u05d0\u05db\u05df, \u05d6\u05d4 \u05e0\u05db\u05d5\u05df \u05d7\u05dc\u05e7\u05d9\u05ea. \u05d0\u05da \u05d3\u05e8\u05da \u05d4\u05d4\u05e1\u05ea\u05db\u05dc\u05d5\u05ea \u05d4\u05d4\u05e4\u05d5\u05db\u05d4 \u05ea\u05e4\u05ea\u05d7 \u05dc\u05db\u05dd \u05d0\u05ea \u05d4\u05e9\u05e4\u05e2 \u05d4\u05d2\u05e9\u05de\u05d9. \u05d0\u05dd \u05e0\u05d1\u05d9\u05df \u05e9\u05d4\u05ea\u05e7\u05d9\u05e2\u05d5\u05ea \u05e9\u05dc\u05e0\u05d5 \u05d1\u05d7\u05d9\u05d9\u05dd \u05e7\u05d9\u05d9\u05de\u05ea \u05db\u05d3\u05d9 \u05dc\u05e9\u05e8\u05ea \u05d0\u05ea \u05d4\u05e6\u05de\u05d9\u05d7\u05d4 \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9\u05ea \u05e9\u05dc\u05e0\u05d5, \u05e0\u05ea\u05de\u05e7\u05d3 \u05d1\u05e6\u05de\u05d9\u05d7\u05d4 \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9\u05ea. \u05d0\u05d6, \u05db\u05d0\u05e9\u05e8 \u05e0\u05e4\u05ea\u05d7 \u05d0\u05ea \u05d4\u05e4\u05ea\u05d7 \u05dc\u05ea\u05d5\u05d1\u05e0\u05d5\u05ea \u05e9\u05de\u05d7\u05db\u05d5\u05ea \u05dc\u05e0\u05d5, \u05d4\u05e9\u05e4\u05e2 \u05d4\u05d2\u05e9\u05de\u05d9 \u05d9\u05d1\u05d5\u05d0 \u05d1\u05e2\u05e7\u05d1\u05d5\u05ea\u05d9\u05d4\u05df.\n\u05e4\u05e0\u05d9\u05e0\u05d5 \u05dc\u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd\n\u05db\u05de\u05d5 \u05db\u05df, \u05d0\u05e0\u05d5 \u05de\u05de\u05e7\u05de\u05d9\u05dd \u05d0\u05ea \u05e2\u05e6\u05de\u05e0\u05d5 \u05e2\u05dd \u05d4\u05e4\u05e0\u05d9\u05dd \u05dc\u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd. \u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd \u05d4\u05d9\u05d0 \u05e6\u05e8\u05d5\u05e3 \u05d4\u05de\u05d9\u05dc\u05d9\u05dd "\u05d9\u05e8\u05d0\u05d4 \u05e9\u05dc\u05de\u05d4". \u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd \u05de\u05e1\u05de\u05dc\u05ea \u05d0\u05ea \u05de\u05e7\u05d5\u05e8 \u05d4\u05e7\u05d3\u05d5\u05e9\u05d4 \u05e9\u05dc \u05d4\u05e2\u05d5\u05dc\u05dd. \u05e9\u05dd \u05e0\u05de\u05e6\u05d0 \u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9, \u05d5\u05e9\u05dd \u05de\u05e1\u05e8\u05d5 \u05d0\u05d1\u05e8\u05d4\u05dd \u05d5\u05d9\u05e6\u05d7\u05e7 \u05d0\u05d1\u05d9\u05e0\u05d5 \u05d0\u05ea \u05e0\u05e4\u05e9\u05dd \u05dc\u05d1\u05d5\u05e8\u05d0 \u05d1\u05e2\u05e7\u05d9\u05d3\u05ea \u05d9\u05e6\u05d7\u05e7. \u05de\u05e1\u05d9\u05e8\u05d5\u05ea \u05d4\u05e0\u05e4\u05e9 \u05e9\u05dc\u05d4\u05dd \u05d4\u05d1\u05d9\u05d0\u05d4 \u05e9\u05e0\u05d9 \u05d3\u05d1\u05e8\u05d9\u05dd \u05d7\u05e9\u05d5\u05d1\u05d9\u05dd \u05dc\u05e2\u05d5\u05dc\u05dd.\n\u05e7\u05d5\u05d3\u05dd \u05db\u05dc, \u05d4\u05d9\u05d0 \u05e4\u05ea\u05d7\u05d4 \u05dc\u05d4\u05dd \u05e4\u05ea\u05d7 \u05dc\u05e8\u05d0\u05d5\u05ea \u05d0\u05ea \u05d0\u05dc\u05d5\u05e7\u05d9\u05dd, \u05db\u05de\u05d5 \u05e9\u05db\u05ea\u05d5\u05d1:\n"\u05d5\u05b7\u05d9\u05b4\u05bc\u05e7\u05b0\u05e8\u05b8\u05d0 \u05d0\u05b7\u05d1\u05b0\u05e8\u05b8\u05d4\u05b8\u05dd \u05e9\u05b5\u05c1\u05dd \u05d4\u05b7\u05de\u05b8\u05bc\u05e7\u05d5\u05b9\u05dd \u05d4\u05b7\u05d4\u05d5\u05bc\u05d0 \u05d9\u05b0\u05d4\u05d5\u05b8\u05d4 \u05d9\u05b4\u05e8\u05b0\u05d0\u05b6\u05d4, \u05d0\u05b2\u05e9\u05b6\u05c1\u05e8 \u05d9\u05b5\u05d0\u05b8\u05de\u05b5\u05e8 \u05d4\u05b7\u05d9\u05bc\u05d5\u05b9\u05dd \u05d1\u05b0\u05bc\u05d4\u05b7\u05e8 \u05d9\u05b0\u05d4\u05d5\u05b8\u05d4 \u05d9\u05b5\u05e8\u05b8\u05d0\u05b6\u05d4."\n\u05db\u05dc\u05d5\u05de\u05e8, \u05d0\u05d1\u05e8\u05d4\u05dd \u05d0\u05d1\u05d9\u05e0\u05d5 \u05e8\u05d0\u05d4 \u05e9\u05dd \u05de\u05e9\u05d4\u05d5 \u05d1\u05d3\u05e8\u05d2\u05d5\u05ea \u05e8\u05d5\u05d7\u05e0\u05d9\u05d5\u05ea \u05d0\u05d7\u05e8\u05d5\u05ea \u05de\u05de\u05d4 \u05e9\u05d4\u05d5\u05d0 \u05e8\u05d0\u05d4 \u05e7\u05d5\u05d3\u05dd.\n\u05d1\u05e0\u05d5\u05e1\u05e3, \u05d4\u05de\u05d9\u05dc\u05d4 "\u05d9\u05b4\u05e8\u05b0\u05d0\u05b6\u05d4" \u05d4\u05d9\u05d0 \u05de\u05d0\u05d5\u05ea\u05d5 \u05e9\u05d5\u05e8\u05e9 \u05e9\u05dc "\u05d9\u05b4\u05e8\u05b0\u05d0\u05b8\u05d4", \u05d5\u05d4\u05de\u05e9\u05de\u05e2\u05d5\u05ea \u05d4\u05db\u05e4\u05d5\u05dc\u05d4 \u05e9\u05dc \u05d4\u05de\u05d9\u05dc\u05d4 \u05d1\u05e0\u05d9\u05e7\u05d5\u05d3 \u05d4\u05e9\u05d5\u05e0\u05d4 \u05de\u05d1\u05d9\u05d0\u05d4 \u05d0\u05d5\u05ea\u05e0\u05d5 \u05dc\u05d4\u05d1\u05e0\u05d4 \u05e9\u05db\u05d0\u05e9\u05e8 \u05d0\u05e0\u05d5 \u05d7\u05d9\u05d9\u05dd \u05d1\u05de\u05e1\u05d9\u05e8\u05d5\u05ea \u05e0\u05e4\u05e9 \u05e2\u05dc \u05e2\u05e7\u05e8\u05d5\u05e0\u05d5\u05ea \u05d4\u05d7\u05d9\u05d9\u05dd \u05d4\u05d7\u05e9\u05d5\u05d1\u05d9\u05dd, \u05d0\u05e0\u05d5 \u05d6\u05d5\u05db\u05d9\u05dd \u05dc\u05e8\u05d0\u05d5\u05ea \u05d0\u05d5\u05e8 \u05e8\u05d5\u05d7\u05e0\u05d9 \u05d2\u05d3\u05d5\u05dc.\n\u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9 \u05db\u05de\u05d5\u05e7\u05d3 \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 - \u05de\u05d0\u05d6 \u05d7\u05d5\u05e8\u05d1\u05df \u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9, \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d4\u05e4\u05db\u05d4 \u05dc\u05ea\u05d7\u05dc\u05d9\u05e3 \u05dc\u05d4\u05e7\u05e8\u05d1\u05ea \u05d4\u05e7\u05d5\u05e8\u05d1\u05e0\u05d5\u05ea, \u05d5\u05dc\u05db\u05df \u05d9\u05e9\u05e0\u05d4 \u05de\u05e1\u05d5\u05e8\u05ea \u05dc\u05db\u05d5\u05d5\u05df \u05d0\u05ea \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05db\u05dc\u05e4\u05d9 \u05d4\u05de\u05e7\u05d5\u05dd \u05e9\u05d1\u05d5 \u05e9\u05db\u05df \u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9. \u05d4\u05d3\u05d1\u05e8 \u05de\u05d1\u05d5\u05e1\u05e1 \u05e2\u05dc \u05d3\u05d1\u05e8\u05d9 \u05e9\u05dc\u05de\u05d4 \u05d4\u05de\u05dc\u05da \u05d1\u05e2\u05ea \u05d7\u05e0\u05d5\u05db\u05ea \u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9:\n"\u05d5\u05b0\u05d4\u05b4\u05ea\u05b0\u05e4\u05b7\u05bc\u05dc\u05b0\u05dc\u05d5\u05bc \u05d0\u05b5\u05dc\u05b6\u05d9\u05da\u05b8 \u05d3\u05b6\u05bc\u05e8\u05b6\u05da\u05b0 \u05d0\u05b7\u05e8\u05b0\u05e6\u05b8\u05dd \u05d0\u05b2\u05e9\u05b6\u05c1\u05e8 \u05e0\u05b8\u05ea\u05b7\u05ea\u05b8\u05bc \u05dc\u05b7\u05d0\u05b2\u05d1\u05d5\u05b9\u05ea\u05b8\u05dd \u05d4\u05b8\u05e2\u05b4\u05d9\u05e8 \u05d0\u05b2\u05e9\u05b6\u05c1\u05e8 \u05d1\u05b8\u05bc\u05d7\u05b7\u05e8\u05b0\u05ea\u05b8\u05bc \u05d5\u05b0\u05d4\u05b7\u05d1\u05b7\u05bc\u05d9\u05b4\u05ea \u05d0\u05b2\u05e9\u05b6\u05c1\u05e8 \u05d1\u05b8\u05bc\u05e0\u05b4\u05d9\u05ea\u05b4\u05d9 \u05dc\u05b4\u05e9\u05b0\u05c1\u05de\u05b6\u05da\u05b8" (\u05de\u05dc\u05db\u05d9\u05dd \u05d0\', \u05d7\', \u05de\u05d7).\n\u05db\u05d9\u05d5\u05d5\u05df \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d1\u05ea\u05e4\u05d5\u05e6\u05d5\u05ea - \u05dc\u05e4\u05d9 \u05d4\u05d4\u05dc\u05db\u05d4, \u05d9\u05d4\u05d5\u05d3\u05d9\u05dd \u05de\u05d7\u05d5\u05e5 \u05dc\u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05de\u05ea\u05e4\u05dc\u05dc\u05d9\u05dd \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc, \u05d9\u05d4\u05d5\u05d3\u05d9\u05dd \u05d1\u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05de\u05ea\u05e4\u05dc\u05dc\u05d9\u05dd \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd, \u05d5\u05d9\u05d4\u05d5\u05d3\u05d9\u05dd \u05d1\u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd \u05de\u05ea\u05e4\u05dc\u05dc\u05d9\u05dd \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d4\u05e8 \u05d4\u05d1\u05d9\u05ea. \u05db\u05da \u05dc\u05de\u05e9\u05dc \u05e0\u05d0\u05de\u05e8 \u05d1\u05d2\u05de\u05e8\u05d0:\n"\u05d4\u05d9\u05d4 \u05e2\u05d5\u05de\u05d3 \u05d1\u05d7\u05d5\u05e6\u05d4 \u05dc\u05d0\u05e8\u05e5 \u05d9\u05d7\u05d6\u05d9\u05e8 \u05e4\u05e0\u05d9\u05d5 \u05dc\u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc... \u05d4\u05d9\u05d4 \u05e2\u05d5\u05de\u05d3 \u05d1\u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05d9\u05d7\u05d6\u05d9\u05e8 \u05e4\u05e0\u05d9\u05d5 \u05dc\u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd..." (\u05d1\u05e8\u05db\u05d5\u05ea \u05dc\', \u05d0\').\n\u05d4\u05de\u05e9\u05de\u05e2\u05d5\u05ea \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9\u05ea \u05e9\u05dc \u05d4\u05de\u05d6\u05e8\u05d7. \u05d1\u05de\u05e7\u05d5\u05de\u05d5\u05ea \u05e8\u05d1\u05d9\u05dd \u05d1\u05e2\u05d5\u05dc\u05dd, \u05d4\u05de\u05d6\u05e8\u05d7 (\u05e7\u05d3\u05d9\u05de\u05d4) \u05e0\u05d7\u05e9\u05d1 \u05dc\u05de\u05e7\u05d5\u05e8 \u05d4\u05d0\u05d5\u05e8 \u05d5\u05d4\u05e9\u05de\u05e9, \u05d5\u05dc\u05db\u05df \u05d9\u05e9 \u05dc\u05d5 \u05d2\u05dd \u05de\u05e9\u05de\u05e2\u05d5\u05ea \u05e1\u05de\u05dc\u05d9\u05ea \u05e9\u05dc \u05d0\u05d5\u05e8 \u05e8\u05d5\u05d7\u05e0\u05d9 \u05d5\u05d4\u05ea\u05d7\u05d3\u05e9\u05d5\u05ea.\n\u05d4\u05e9\u05e4\u05e2\u05ea \u05d1\u05d9\u05ea \u05d4\u05db\u05e0\u05e1\u05ea \u05d5\u05d4\u05de\u05d9\u05e7\u05d5\u05dd \u05d4\u05d4\u05d9\u05e1\u05d8\u05d5\u05e8\u05d9 \u05d1\u05e8\u05d5\u05d1 \u05d4\u05e7\u05d4\u05d9\u05dc\u05d5\u05ea, \u05d0\u05e8\u05d5\u05df \u05d4\u05e7\u05d5\u05d3\u05e9 \u05e9\u05d1\u05d5 \u05e0\u05de\u05e6\u05d0\u05d9\u05dd \u05e1\u05e4\u05e8\u05d9 \u05d4\u05ea\u05d5\u05e8\u05d4 \u05de\u05de\u05d5\u05e7\u05dd \u05db\u05da \u05e9\u05d4\u05de\u05ea\u05e4\u05dc\u05dc\u05d9\u05dd \u05e4\u05d5\u05e0\u05d9\u05dd \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd. \u05de\u05db\u05d0\u05df \u05e0\u05d5\u05e6\u05e8 \u05d4\u05d1\u05d9\u05d8\u05d5\u05d9 "\u05dc\u05d4\u05ea\u05e4\u05dc\u05dc \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05de\u05d6\u05e8\u05d7" \u05d0\u05e3 \u05db\u05d9 \u05d1\u05e4\u05d5\u05e2\u05dc \u05d1\u05db\u05dc \u05de\u05e7\u05d5\u05dd \u05e4\u05d5\u05e0\u05d9\u05dd \u05d9\u05e9\u05d9\u05e8\u05d5\u05ea \u05dc\u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd \u05d5\u05dc\u05d0\u05d5 \u05d3\u05d5\u05d5\u05e7\u05d0 \u05de\u05d6\u05e8\u05d7\u05d4.\n\u05e1\u05d9\u05db\u05d5\u05dd:\n\u05de\u05e0\u05d4\u05d2 \u05d4\u05e4\u05e0\u05d9\u05d9\u05d4 \u05dc\u05de\u05d6\u05e8\u05d7 \u05de\u05d1\u05d5\u05e1\u05e1 \u05e2\u05dc \u05d4\u05de\u05e1\u05d5\u05e8\u05ea \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9\u05ea \u05d4\u05e8\u05d5\u05d0\u05d4 \u05d1\u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd \u05d5\u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9 \u05d0\u05ea \u05de\u05e8\u05db\u05d6 \u05d4\u05e7\u05d5\u05d3\u05e9 \u05d5\u05d4\u05e7\u05d3\u05d5\u05e9\u05d4. \u05ea\u05e4\u05d9\u05dc\u05d4 \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d6\u05d4 \u05de\u05d1\u05d8\u05d0\u05ea \u05d0\u05ea \u05d4\u05db\u05de\u05d9\u05d4\u05d4 \u05dc\u05d7\u05d9\u05d3\u05d5\u05e9 \u05d4\u05e7\u05e9\u05e8 \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9 \u05d5\u05d4\u05dc\u05d0\u05d5\u05de\u05d9 \u05e2\u05dd \u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd \u05d5\u05d0\u05ea \u05d4\u05ea\u05e7\u05d5\u05d5\u05d4 \u05dc\u05d1\u05e0\u05d9\u05d9\u05df \u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9 \u05de\u05d7\u05d3\u05e9.\n\u05d4\u05de\u05e9\u05de\u05e2\u05d5\u05ea \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9\u05ea \u05e9\u05dc \u05d4\u05d4\u05e1\u05ea\u05db\u05dc\u05d5\u05ea \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc - \u05d7\u05d9\u05d1\u05d5\u05e8 \u05e4\u05e0\u05d9\u05de\u05d9 \u05dc\u05e9\u05d5\u05e8\u05e9 \u05d4\u05d0\u05dc\u05d5\u05d4\u05d9\n\u05d4\u05d4\u05e1\u05ea\u05db\u05dc\u05d5\u05ea \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05d0\u05d9\u05e0\u05e0\u05d4 \u05e8\u05e7 \u05e4\u05e2\u05d5\u05dc\u05d4 \u05d7\u05d9\u05e6\u05d5\u05e0\u05d9\u05ea, \u05d0\u05dc\u05d0 \u05de\u05d4\u05d5\u05d5\u05d4 \u05de\u05e1\u05e2 \u05e4\u05e0\u05d9\u05de\u05d9 \u05e9\u05dc \u05d7\u05d9\u05d1\u05d5\u05e8 \u05dc\u05e2\u05e6\u05de\u05e0\u05d5, \u05dc\u05e2\u05dd \u05d9\u05e9\u05e8\u05d0\u05dc \u05d5\u05dc\u05d1\u05d5\u05e8\u05d0. \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05e0\u05d7\u05e9\u05d1\u05ea \u05d1\u05de\u05d9\u05e1\u05d8\u05d9\u05e7\u05d4 \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9\u05ea \u05dc\u05dc\u05d1 \u05d4\u05e2\u05d5\u05dc\u05dd, \u05d4\u05de\u05e7\u05d5\u05dd \u05e9\u05de\u05d7\u05d1\u05e8 \u05d1\u05d9\u05df \u05d4\u05d7\u05d5\u05de\u05e8 \u05dc\u05e8\u05d5\u05d7, \u05d1\u05d9\u05df \u05d4\u05d0\u05e0\u05d5\u05e9\u05d9 \u05dc\u05d0\u05dc\u05d5\u05d4\u05d9. \u05dc\u05db\u05df, \u05db\u05d0\u05e9\u05e8 \u05d0\u05d3\u05dd \u05de\u05ea\u05d1\u05d5\u05e0\u05df \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc, \u05d4\u05d5\u05d0 \u05de\u05db\u05d5\u05d5\u05df \u05d0\u05ea \u05e0\u05e9\u05de\u05ea\u05d5 \u05dc\u05ea\u05d3\u05e8 \u05e8\u05d5\u05d7\u05e0\u05d9 \u05d2\u05d1\u05d5\u05d4 \u05d9\u05d5\u05ea\u05e8, \u05d4\u05de\u05ea\u05d0\u05d9\u05dd \u05dc\u05e9\u05d5\u05e8\u05e9 \u05e0\u05e9\u05de\u05ea\u05d5.\n\u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05db\u05de\u05e7\u05d5\u05dd \u05e9\u05dc \u05d0\u05d5\u05e8 \u05d5\u05d4\u05ea\u05d2\u05dc\u05d5\u05ea \u05d0\u05dc\u05d5\u05d4\u05d9\u05ea\n\u05d7\u05d6"\u05dc \u05de\u05dc\u05de\u05d3\u05d9\u05dd \u05db\u05d9 "\u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05e7\u05d3\u05d5\u05e9\u05d4 \u05de\u05db\u05dc \u05d4\u05d0\u05e8\u05e6\u05d5\u05ea" (\u05de\u05e9\u05e0\u05d4 \u05db\u05dc\u05d9\u05dd \u05d0\', \u05d5\'), \u05de\u05e9\u05d5\u05dd \u05e9\u05d1\u05d4 \u05e9\u05d5\u05e8\u05d4 \u05d4\u05e9\u05db\u05d9\u05e0\u05d4 \u05d1\u05e6\u05d5\u05e8\u05d4 \u05d2\u05dc\u05d5\u05d9\u05d4 \u05d9\u05d5\u05ea\u05e8 \u05de\u05d0\u05e9\u05e8 \u05d1\u05db\u05dc \u05de\u05e7\u05d5\u05dd \u05d0\u05d7\u05e8 \u05d1\u05e2\u05d5\u05dc\u05dd.\n\u05e2\u05dc \u05e4\u05d9 \u05d4\u05e7\u05d1\u05dc\u05d4, \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05d4\u05d9\u05d0 \u05d4\u05de\u05e7\u05d5\u05dd \u05e9\u05d1\u05d5 \u05e7\u05d9\u05d9\u05de\u05ea "\u05d4\u05d0\u05e8\u05d4 \u05d9\u05e9\u05d9\u05e8\u05d4" \u05e9\u05dc \u05d4\u05d0\u05d5\u05e8 \u05d4\u05d0\u05dc\u05d5\u05d4\u05d9, \u05dc\u05dc\u05d0 \u05d4\u05e1\u05ea\u05e8\u05d5\u05ea \u05d5\u05dc\u05dc\u05d0 \u05de\u05e1\u05db\u05d9\u05dd. \u05db\u05d0\u05e9\u05e8 \u05d0\u05d3\u05dd \u05e4\u05d5\u05e0\u05d4 \u05dc\u05db\u05d9\u05d5\u05d5\u05e0\u05d4, \u05d4\u05d5\u05d0 \u05de\u05ea\u05d7\u05d1\u05e8 \u05dc\u05d0\u05e0\u05e8\u05d2\u05d9\u05d4 \u05d6\u05d5 \u05d5\u05de\u05d0\u05e4\u05e9\u05e8 \u05dc\u05d4 \u05dc\u05d4\u05d9\u05db\u05e0\u05e1 \u05d0\u05dc \u05d7\u05d9\u05d9\u05d5.\n\u05d4\u05d0\u05e8"\u05d9 \u05d4\u05e7\u05d3\u05d5\u05e9 \u05de\u05e1\u05d1\u05d9\u05e8 \u05db\u05d9 \u05db\u05dc \u05de\u05d9 \u05e9\u05de\u05d7\u05d5\u05d1\u05e8 \u05dc\u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc, \u05d0\u05e4\u05d9\u05dc\u05d5 \u05de\u05e8\u05d7\u05d5\u05e7, \u05d9\u05db\u05d5\u05dc \u05dc\u05e7\u05d1\u05dc \u05e9\u05e4\u05e2 \u05e8\u05d5\u05d7\u05e0\u05d9 \u05d9\u05d9\u05d7\u05d5\u05d3\u05d9 \u05de\u05de\u05e0\u05d4. \u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea \u05dc\u05db\u05d9\u05d5\u05d5\u05e0\u05d4 \u05d4\u05d9\u05d0 \u05de\u05e2\u05e9\u05d4 \u05e9\u05dc \u05e4\u05ea\u05d9\u05d7\u05ea \u05d4\u05dc\u05d1 \u05dc\u05e7\u05d1\u05dc\u05ea \u05d4\u05d0\u05d5\u05e8 \u05d4\u05d0\u05dc\u05d5\u05d4\u05d9.\n\u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05db\u05de\u05e7\u05d5\u05dd \u05d4\u05e9\u05d5\u05e8\u05e9 \u05e9\u05dc \u05d4\u05e0\u05e9\u05de\u05d4\n\u05d4\u05e8\u05de\u05d7"\u05dc \u05de\u05e1\u05d1\u05d9\u05e8 \u05db\u05d9 \u05e0\u05e9\u05de\u05d5\u05ea \u05d9\u05e9\u05e8\u05d0\u05dc \u05e7\u05e9\u05d5\u05e8\u05d5\u05ea \u05d1\u05e7\u05e9\u05e8 \u05e2\u05de\u05d5\u05e7 \u05dc\u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc, \u05e9\u05db\u05df \u05de\u05e9\u05dd \u05e0\u05d5\u05d1\u05e2\u05d9\u05dd \u05e9\u05d5\u05e8\u05e9\u05d9\u05d4\u05dd \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9\u05d9\u05dd.\n\u05db\u05d0\u05e9\u05e8 \u05d9\u05d4\u05d5\u05d3\u05d9 \u05de\u05ea\u05e4\u05dc\u05dc \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc, \u05d4\u05d5\u05d0 \u05de\u05d7\u05d1\u05e8 \u05d0\u05ea \u05e0\u05e9\u05de\u05ea\u05d5 \u05d7\u05d6\u05e8\u05d4 \u05dc\u05de\u05e7\u05d5\u05e8 \u05d4\u05d0\u05de\u05d9\u05ea\u05d9 \u05e9\u05dc\u05d4, \u05d1\u05d3\u05d9\u05d5\u05e7 \u05db\u05e4\u05d9 \u05e9\u05d4\u05e2\u05e5 \u05de\u05d7\u05d5\u05d1\u05e8 \u05dc\u05e9\u05d5\u05e8\u05e9\u05d9\u05d5.\n\u05d1\u05de\u05d5\u05d1\u05df \u05d6\u05d4, \u05d4\u05d4\u05e1\u05ea\u05db\u05dc\u05d5\u05ea \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05d4\u05d9\u05d0 \u05ea\u05d4\u05dc\u05d9\u05da \u05e9\u05dc \u05d7\u05d6\u05e8\u05d4 \u05d4\u05d1\u05d9\u05ea\u05d4 \u05dc\u05d0 \u05d1\u05de\u05d5\u05d1\u05df \u05d4\u05e4\u05d9\u05d6\u05d9 \u05d1\u05dc\u05d1\u05d3, \u05d0\u05dc\u05d0 \u05d2\u05dd \u05d1\u05de\u05d5\u05d1\u05df \u05d4\u05e4\u05e0\u05d9\u05de\u05d9 \u05d5\u05d4\u05e8\u05d5\u05d7\u05e0\u05d9.\n\u05db\u05d0\u05e9\u05e8 \u05d0\u05d3\u05dd \u05de\u05db\u05d5\u05d5\u05df \u05d0\u05ea \u05de\u05d1\u05d8\u05d5 \u05d5\u05dc\u05d9\u05d1\u05d5 \u05dc\u05e9\u05dd, \u05d4\u05d5\u05d0 \u05d1\u05e2\u05e6\u05dd \u05de\u05ea\u05d9\u05d9\u05e9\u05e8 \u05de\u05d7\u05d3\u05e9 \u05e2\u05dd \u05d9\u05d9\u05e2\u05d5\u05d3\u05d5 \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9, \u05e2\u05dd \u05d6\u05d4\u05d5\u05ea\u05d5 \u05d4\u05d0\u05de\u05d9\u05ea\u05d9\u05ea \u05d5\u05e2\u05dd \u05d4\u05d7\u05d6\u05d5\u05df \u05d4\u05d0\u05dc\u05d5\u05d4\u05d9 \u05e2\u05d1\u05d5\u05e8\u05d5 \u05d5\u05e2\u05d1\u05d5\u05e8 \u05d4\u05e2\u05d5\u05dc\u05dd.\n\u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05db\u05de\u05e7\u05d5\u05dd \u05d4\u05d1\u05e8\u05d9\u05d0\u05d4 \u05d5\u05d4\u05e9\u05e4\u05e2\n\u05e2\u05dc \u05e4\u05d9 \u05d4\u05de\u05d3\u05e8\u05e9 (\u05d1\u05e8\u05d0\u05e9\u05d9\u05ea \u05e8\u05d1\u05d4 \u05d8"\u05d6, \u05d3\'), \u05d4\u05d1\u05e8\u05d9\u05d0\u05d4 \u05d4\u05ea\u05d7\u05d9\u05dc\u05d4 \u05de\u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc, \u05d5\u05d4\u05d0\u05d5\u05e8 \u05d4\u05d0\u05dc\u05d5\u05d4\u05d9 \u05de\u05ea\u05e4\u05e9\u05d8 \u05de\u05de\u05e0\u05d4 \u05dc\u05db\u05dc \u05d4\u05e2\u05d5\u05dc\u05dd.\n\u05dc\u05db\u05df, \u05db\u05e9\u05d4\u05d0\u05d3\u05dd \u05de\u05ea\u05d1\u05d5\u05e0\u05df \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc, \u05d4\u05d5\u05d0 \u05de\u05d7\u05d1\u05e8 \u05d0\u05ea \u05e2\u05e6\u05de\u05d5 \u05dc\u05ea\u05d3\u05e8 \u05e9\u05dc \u05d1\u05e8\u05d9\u05d0\u05d4 \u05de\u05d7\u05d5\u05d3\u05e9\u05ea, \u05dc\u05e6\u05de\u05d9\u05d7\u05d4, \u05dc\u05d4\u05ea\u05d7\u05d3\u05e9\u05d5\u05ea \u05d5\u05dc\u05d4\u05e9\u05e4\u05e2\u05d4 \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea.\n\u05d7\u05d6"\u05dc \u05de\u05ea\u05d0\u05e8\u05d9\u05dd \u05d0\u05ea \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05db\u05d0\u05e8\u05e5 \u05e9\u05dc \u05d4\u05e9\u05d2\u05d7\u05d4 \u05e4\u05e8\u05d8\u05d9\u05ea, \u05e9\u05d1\u05d4 \u05db\u05dc \u05d8\u05d9\u05e4\u05d4 \u05e9\u05dc \u05d2\u05e9\u05dd \u05d5\u05db\u05dc \u05e6\u05de\u05d7 \u05de\u05d5\u05e9\u05d2\u05d7\u05d9\u05dd \u05d9\u05e9\u05d9\u05e8\u05d5\u05ea \u05e2\u05dc \u05d9\u05d3\u05d9 \u05d4\u05d1\u05d5\u05e8\u05d0.\n\u05d4\u05e4\u05e0\u05d9\u05d9\u05ea \u05d4\u05de\u05d1\u05d8 \u05dc\u05e9\u05dd \u05d4\u05d9\u05d0 \u05e4\u05e2\u05d5\u05dc\u05d4 \u05e9\u05dc \u05d4\u05ea\u05d7\u05d1\u05e8\u05d5\u05ea \u05dc\u05de\u05e7\u05d5\u05e8 \u05d4\u05d1\u05e8\u05db\u05d4, \u05dc\u05d7\u05d9\u05d9\u05dd \u05de\u05ea\u05d5\u05da \u05d0\u05de\u05d5\u05e0\u05d4 \u05d5\u05e9\u05e4\u05e2, \u05dc\u05e2\u05d5\u05de\u05ea \u05d4\u05ea\u05e4\u05d9\u05e1\u05d4 \u05d4\u05d7\u05d5\u05de\u05e8\u05d9\u05ea \u05e9\u05dc \u05d4\u05e2\u05d5\u05dc\u05dd.\n\u05d4\u05d4\u05e1\u05ea\u05db\u05dc\u05d5\u05ea \u05db\u05e4\u05e2\u05d5\u05dc\u05d4 \u05e9\u05dc \u05db\u05de\u05d9\u05d4\u05d4 \u05d5\u05d4\u05d2\u05e9\u05de\u05d4\n\u05d4\u05e8\u05de\u05d1"\u05df \u05de\u05dc\u05de\u05d3 \u05db\u05d9 \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05d4\u05d9\u05d0 \u05d4\u05de\u05e7\u05d5\u05dd \u05d4\u05d9\u05d7\u05d9\u05d3 \u05e9\u05d1\u05d5 \u05e2\u05dd \u05d9\u05e9\u05e8\u05d0\u05dc \u05d9\u05db\u05d5\u05dc \u05dc\u05de\u05de\u05e9 \u05d0\u05ea \u05e9\u05dc\u05d9\u05d7\u05d5\u05ea\u05d5 \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9\u05ea \u05d1\u05de\u05dc\u05d5\u05d0\u05d4.\n\u05db\u05d0\u05e9\u05e8 \u05d0\u05e0\u05d5 \u05de\u05db\u05d5\u05d5\u05e0\u05d9\u05dd \u05d0\u05ea \u05de\u05d1\u05d8\u05e0\u05d5 \u05dc\u05db\u05d9\u05d5\u05d5\u05e0\u05d4, \u05d0\u05e0\u05d5 \u05de\u05d1\u05d8\u05d0\u05d9\u05dd \u05db\u05de\u05d9\u05d4\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05dc\u05d4\u05ea\u05d7\u05d1\u05e8 \u05dc\u05e9\u05dc\u05de\u05d5\u05ea \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9\u05ea, \u05dc\u05e9\u05d5\u05e8\u05e9 \u05d4\u05d6\u05d4\u05d5\u05ea \u05e9\u05dc\u05e0\u05d5, \u05d5\u05dc\u05de\u05e7\u05d5\u05dd \u05e9\u05d1\u05d5 \u05d4\u05e0\u05e9\u05de\u05d4 \u05d9\u05db\u05d5\u05dc\u05d4 \u05dc\u05de\u05de\u05e9 \u05d0\u05ea \u05de\u05dc\u05d5\u05d0 \u05d4\u05e4\u05d5\u05d8\u05e0\u05e6\u05d9\u05d0\u05dc \u05e9\u05dc\u05d4.\n\u05d6\u05d4\u05d5 \u05de\u05e2\u05e9\u05d4 \u05e9\u05dc \u05d4\u05d2\u05e9\u05de\u05d4 \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea \u05db\u05d0\u05e9\u05e8 \u05d4\u05d0\u05d3\u05dd \u05de\u05e1\u05ea\u05db\u05dc \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc, \u05d4\u05d5\u05d0 \u05de\u05db\u05e8\u05d9\u05d6 \u05e9\u05d4\u05d5\u05d0 \u05d7\u05dc\u05e7 \u05de\u05d4\u05d7\u05d6\u05d5\u05df \u05d4\u05d0\u05dc\u05d5\u05d4\u05d9 \u05dc\u05e2\u05d5\u05dc\u05dd, \u05d5\u05e9\u05d4\u05d5\u05d0 \u05e8\u05d5\u05e6\u05d4 \u05dc\u05d4\u05d9\u05d5\u05ea \u05e9\u05d5\u05ea\u05e3 \u05dc\u05ea\u05d4\u05dc\u05d9\u05da \u05d4\u05d2\u05d0\u05d5\u05dc\u05d4.\n\u05d4\u05e1\u05ea\u05db\u05dc\u05d5\u05ea \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05db\u05e4\u05e2\u05d5\u05dc\u05d4 \u05e9\u05dc \u05d0\u05d7\u05d3\u05d5\u05ea\n\u05d7\u05d6"\u05dc \u05de\u05dc\u05de\u05d3\u05d9\u05dd \u05db\u05d9 \u05db\u05dc \u05d9\u05d4\u05d5\u05d3\u05d9 \u05d1\u05db\u05dc \u05de\u05e7\u05d5\u05dd \u05d1\u05e2\u05d5\u05dc\u05dd \u05de\u05db\u05d5\u05d5\u05df \u05d0\u05ea \u05dc\u05d9\u05d1\u05d5 \u05dc\u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05d1\u05ea\u05e4\u05d9\u05dc\u05ea\u05d5, \u05d5\u05db\u05da \u05e0\u05d5\u05e6\u05e8 \u05d7\u05d9\u05d1\u05d5\u05e8 \u05e8\u05d5\u05d7\u05e0\u05d9 \u05e2\u05de\u05d5\u05e7 \u05d1\u05d9\u05df \u05db\u05dc \u05d7\u05dc\u05e7\u05d9 \u05d4\u05e2\u05dd.\n\u05db\u05d0\u05e9\u05e8 \u05d0\u05e0\u05d5 \u05e4\u05d5\u05e0\u05d9\u05dd \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc, \u05d0\u05e0\u05d5 \u05de\u05d1\u05d8\u05d0\u05d9\u05dd \u05d0\u05d7\u05d3\u05d5\u05ea \u05e4\u05e0\u05d9\u05de\u05d9\u05ea. \u05d0\u05e0\u05d5 \u05de\u05d7\u05d1\u05e8\u05d9\u05dd \u05d0\u05ea \u05db\u05dc \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9\u05dd \u05de\u05db\u05dc \u05e7\u05e6\u05d5\u05d5\u05ea \u05ea\u05d1\u05dc \u05dc\u05de\u05e7\u05d5\u05dd \u05d0\u05d7\u05d3, \u05e9\u05d1\u05d5 \u05db\u05dc \u05d4\u05e0\u05e9\u05de\u05d5\u05ea \u05de\u05ea\u05d0\u05d7\u05d3\u05d5\u05ea \u05dc\u05d0\u05d5\u05e8 \u05d0\u05d7\u05d3 \u05e9\u05dc\u05dd.\n\u05d1\u05de\u05d5\u05d1\u05df \u05d6\u05d4, \u05d4\u05d4\u05e1\u05ea\u05db\u05dc\u05d5\u05ea \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05d4\u05d9\u05d0 \u05de\u05e2\u05e9\u05d4 \u05e9\u05dc \u05d0\u05d4\u05d1\u05ea \u05d9\u05e9\u05e8\u05d0\u05dc, \u05de\u05e9\u05d5\u05dd \u05e9\u05d4\u05d9\u05d0 \u05de\u05d7\u05d1\u05e8\u05ea \u05d0\u05d5\u05ea\u05e0\u05d5 \u05dc\u05de\u05e9\u05d4\u05d5 \u05d2\u05d3\u05d5\u05dc \u05de\u05d0\u05d9\u05ea\u05e0\u05d5 - \u05dc\u05e9\u05d5\u05e8\u05e9 \u05d4\u05dc\u05d0\u05d5\u05de\u05d9 \u05d5\u05d4\u05e8\u05d5\u05d7\u05e0\u05d9 \u05d4\u05de\u05e9\u05d5\u05ea\u05e3 \u05e9\u05dc\u05e0\u05d5.\n\u05db\u05d5\u05d5\u05e0\u05d5\u05df \u05d4\u05ea\u05d5\u05d3\u05e2\u05d4 \u05d3\u05e8\u05da \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc\n\u05d7\u05d6"\u05dc \u05de\u05dc\u05de\u05d3\u05d9\u05dd \u05db\u05d9 "\u05d0\u05d5\u05d5\u05d9\u05e8 \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05de\u05d7\u05db\u05d9\u05dd" (\u05d1\u05d1\u05d0 \u05d1\u05ea\u05e8\u05d0 \u05e7\u05e0"\u05d7, \u05d1\') \u05db\u05dc\u05d5\u05de\u05e8, \u05dc\u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05d9\u05e9 \u05d4\u05e9\u05e4\u05e2\u05d4 \u05e2\u05dc \u05d4\u05d0\u05d3\u05dd \u05d1\u05e8\u05de\u05d4 \u05d4\u05de\u05d7\u05e9\u05d1\u05ea\u05d9\u05ea \u05d5\u05d4\u05e8\u05d5\u05d7\u05e0\u05d9\u05ea.\n\u05db\u05d0\u05e9\u05e8 \u05d0\u05d3\u05dd \u05de\u05ea\u05d1\u05d5\u05e0\u05df \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc, \u05d4\u05d5\u05d0 \u05de\u05ea\u05d7\u05d1\u05e8 \u05dc\u05d0\u05e0\u05e8\u05d2\u05d9\u05d4 \u05e9\u05dc \u05d7\u05db\u05de\u05d4 \u05d5\u05e9\u05dc \u05d1\u05d4\u05d9\u05e8\u05d5\u05ea \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea.\n\u05d1\u05de\u05d5\u05d1\u05df \u05d6\u05d4, \u05d4\u05d4\u05e1\u05ea\u05db\u05dc\u05d5\u05ea \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05d4\u05d9\u05d0 \u05ea\u05e8\u05d2\u05d5\u05dc \u05e9\u05dc \u05db\u05d5\u05d5\u05e0\u05d5\u05df \u05d4\u05ea\u05d5\u05d3\u05e2\u05d4. \u05d4\u05d9\u05d0 \u05de\u05d7\u05d1\u05e8\u05ea \u05d0\u05d5\u05ea\u05e0\u05d5 \u05dc\u05ea\u05d3\u05e8 \u05e9\u05dc \u05d0\u05de\u05ea, \u05e9\u05dc \u05e7\u05d3\u05d5\u05e9\u05d4, \u05e9\u05dc \u05d1\u05d4\u05d9\u05e8\u05d5\u05ea \u05d5\u05e9\u05dc \u05d7\u05d9\u05d9\u05dd \u05de\u05ea\u05d5\u05da \u05d7\u05d9\u05d1\u05d5\u05e8 \u05dc\u05d0\u05dc\u05d5\u05d4\u05d5\u05ea.\n\u05d4\u05d7\u05d6\u05d5\u05df \u05e9\u05dc \u05d4\u05d2\u05d0\u05d5\u05dc\u05d4 \u05d4\u05d0\u05d9\u05e9\u05d9\u05ea \u05d5\u05d4\u05e2\u05d5\u05dc\u05de\u05d9\u05ea\n\u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05d0\u05d9\u05e0\u05d4 \u05e8\u05e7 \u05de\u05e7\u05d5\u05dd \u05e4\u05d9\u05d6\u05d9, \u05d4\u05d9\u05d0 \u05d7\u05d6\u05d5\u05df, \u05d7\u05dc\u05d5\u05dd \u05d5\u05ea\u05db\u05dc\u05d9\u05ea \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea.\n\u05d7\u05d6"\u05dc \u05de\u05dc\u05de\u05d3\u05d9\u05dd \u05db\u05d9 \u05db\u05dc \u05de\u05d9 \u05e9\u05de\u05d7\u05d5\u05d1\u05e8 \u05dc\u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc, \u05d0\u05e4\u05d9\u05dc\u05d5 \u05d1\u05dc\u05d9\u05d1\u05d5, \u05d4\u05d5\u05e4\u05da \u05dc\u05d7\u05dc\u05e7 \u05de\u05d4\u05ea\u05d4\u05dc\u05d9\u05da \u05d4\u05d0\u05dc\u05d5\u05d4\u05d9 \u05e9\u05dc \u05ea\u05d9\u05e7\u05d5\u05df \u05d4\u05e2\u05d5\u05dc\u05dd.\n"\u05d5\u05b0\u05e9\u05b8\u05c1\u05d1\u05d5\u05bc \u05d1\u05b8\u05e0\u05b4\u05d9\u05dd \u05dc\u05b4\u05d2\u05b0\u05d1\u05d5\u05bc\u05dc\u05b8\u05dd" (\u05d9\u05e8\u05de\u05d9\u05d4\u05d5 \u05dc"\u05d0, \u05d8"\u05d6)\n\u05db\u05d0\u05e9\u05e8 \u05d0\u05e0\u05d5 \u05de\u05e1\u05ea\u05db\u05dc\u05d9\u05dd \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc, \u05d0\u05e0\u05d5 \u05d1\u05e2\u05e6\u05dd \u05de\u05db\u05e8\u05d9\u05d6\u05d9\u05dd \u05e9\u05d0\u05e0\u05d5 \u05de\u05d0\u05de\u05d9\u05e0\u05d9\u05dd \u05d1\u05ea\u05d4\u05dc\u05d9\u05da \u05d4\u05d6\u05d4. \u05e9\u05d0\u05e0\u05d5 \u05e8\u05d5\u05e6\u05d9\u05dd \u05dc\u05d4\u05d9\u05d5\u05ea \u05d7\u05dc\u05e7 \u05de\u05d4\u05ea\u05d9\u05e7\u05d5\u05df, \u05de\u05d4\u05d2\u05d0\u05d5\u05dc\u05d4 \u05d5\u05d4\u05d7\u05d6\u05e8\u05ea \u05d4\u05d0\u05d5\u05e8 \u05d4\u05d0\u05dc\u05d5\u05d4\u05d9 \u05dc\u05e2\u05d5\u05dc\u05dd.\n\u05d4\u05d4\u05e1\u05ea\u05db\u05dc\u05d5\u05ea \u05db\u05de\u05e2\u05e9\u05d4 \u05e9\u05dc \u05d7\u05d9\u05d1\u05d5\u05e8, \u05e7\u05d3\u05d5\u05e9\u05d4 \u05d5\u05d4\u05ea\u05e2\u05dc\u05d5\u05ea\n\u05d4\u05d4\u05e1\u05ea\u05db\u05dc\u05d5\u05ea \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05d4\u05d9\u05d0 \u05d4\u05e8\u05d1\u05d4 \u05de\u05e2\u05d1\u05e8 \u05dc\u05e4\u05e2\u05d5\u05dc\u05d4 \u05d7\u05d9\u05e6\u05d5\u05e0\u05d9\u05ea.\n\u05d6\u05d4\u05d5 \u05de\u05e2\u05e9\u05d4 \u05e9\u05dc \u05d4\u05ea\u05d7\u05d1\u05e8\u05d5\u05ea \u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05dc\u05e9\u05d5\u05e8\u05e9 \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9 \u05e9\u05dc\u05e0\u05d5, \u05e9\u05dc \u05e4\u05ea\u05d9\u05d7\u05ea \u05d4\u05dc\u05d1 \u05dc\u05d0\u05d5\u05e8 \u05d4\u05d0\u05dc\u05d5\u05d4\u05d9, \u05d5\u05e9\u05dc \u05d4\u05e9\u05ea\u05ea\u05e4\u05d5\u05ea \u05d0\u05e7\u05d8\u05d9\u05d1\u05d9\u05ea \u05d1\u05ea\u05d4\u05dc\u05d9\u05da \u05d4\u05d2\u05d0\u05d5\u05dc\u05d4 \u05d4\u05d0\u05d9\u05e9\u05d9\u05ea \u05d5\u05d4\u05e2\u05d5\u05dc\u05de\u05d9\u05ea.\n\u05db\u05d0\u05e9\u05e8 \u05d0\u05e0\u05d5 \u05de\u05ea\u05d1\u05d5\u05e0\u05e0\u05d9\u05dd \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc, \u05d0\u05e0\u05d5 \u05de\u05d6\u05db\u05d9\u05e8\u05d9\u05dd \u05dc\u05e2\u05e6\u05de\u05e0\u05d5:\n\u05e9\u05d9\u05e9 \u05dc\u05e0\u05d5 \u05e9\u05d5\u05e8\u05e9, \u05de\u05e7\u05d5\u05dd \u05dc\u05d4\u05e9\u05ea\u05d9\u05d9\u05da \u05d0\u05dc\u05d9\u05d5 \u05d5\u05de\u05e9\u05de\u05e2\u05d5\u05ea \u05e2\u05de\u05d5\u05e7\u05d4 \u05dc\u05d7\u05d9\u05d9\u05e0\u05d5.\n\u05e9\u05d0\u05e0\u05d7\u05e0\u05d5 \u05de\u05d7\u05d5\u05d1\u05e8\u05d9\u05dd \u05dc\u05d0\u05d5\u05e8 \u05d4\u05e9\u05db\u05d9\u05e0\u05d4, \u05d2\u05dd \u05d0\u05dd \u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05d4\u05d5\u05d0 \u05e0\u05e1\u05ea\u05e8.\n\u05e9\u05d0\u05e0\u05d7\u05e0\u05d5 \u05d7\u05dc\u05e7 \u05de\u05de\u05e9\u05d4\u05d5 \u05d2\u05d3\u05d5\u05dc \u05d9\u05d5\u05ea\u05e8, \u05de\u05d7\u05d6\u05d5\u05df \u05d0\u05dc\u05d5\u05d4\u05d9 \u05e9\u05dc \u05d2\u05d0\u05d5\u05dc\u05d4, \u05d0\u05d7\u05d3\u05d5\u05ea \u05d5\u05d0\u05d4\u05d1\u05d4.\n\u05d4\u05d4\u05e1\u05ea\u05db\u05dc\u05d5\u05ea \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05e4\u05d5\u05ea\u05d7\u05ea \u05d1\u05ea\u05d5\u05db\u05e0\u05d5 \u05e9\u05e2\u05e8\u05d9\u05dd \u05e4\u05e0\u05d9\u05de\u05d9\u05d9\u05dd. \u05e9\u05e2\u05e8\u05d9\u05dd \u05e9\u05dc \u05d0\u05de\u05d5\u05e0\u05d4, \u05e9\u05dc \u05d7\u05db\u05de\u05d4, \u05d5\u05e9\u05dc \u05d7\u05d9\u05d1\u05d5\u05e8 \u05e2\u05de\u05d5\u05e7 \u05dc\u05d0\u05d5\u05e8 \u05d4\u05d0\u05dc\u05d5\u05d4\u05d9 \u05e9\u05e0\u05de\u05e6\u05d0 \u05d1\u05ea\u05d5\u05db\u05e0\u05d5.\n\u05de\u05d8\u05e8\u05d4:\n\u05d4\u05ea\u05e8\u05d2\u05d9\u05dc \u05d9\u05e2\u05d6\u05d5\u05e8 \u05dc\u05da \u05dc\u05d7\u05d5\u05d5\u05ea \u05d1\u05d0\u05d5\u05e4\u05df \u05d0\u05d9\u05e9\u05d9 \u05d5\u05e2\u05de\u05d5\u05e7 \u05d0\u05ea \u05d4\u05de\u05e9\u05de\u05e2\u05d5\u05ea \u05e9\u05dc \u05d4\u05d4\u05e1\u05ea\u05db\u05dc\u05d5\u05ea \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05d5\u05dc\u05d7\u05d1\u05e8 \u05d6\u05d0\u05ea \u05dc\u05d7\u05d9\u05d9\u05dd \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05d9\u05dd \u05e9\u05dc\u05da.\n\u05e9\u05dc\u05d1 1: \u05d9\u05e6\u05d9\u05e8\u05ea \u05de\u05e8\u05d7\u05d1 \u05e9\u05dc \u05e9\u05e7\u05d8 \u05d5\u05d4\u05ea\u05db\u05d5\u05d5\u05e0\u05e0\u05d5\u05ea\n\u05de\u05e6\u05d0 \u05de\u05e7\u05d5\u05dd \u05e9\u05e7\u05d8 \u2013 \u05d6\u05d4 \u05d9\u05db\u05d5\u05dc \u05dc\u05d4\u05d9\u05d5\u05ea \u05d1\u05d7\u05d3\u05e8 \u05e9\u05dc\u05da, \u05d1\u05d8\u05d1\u05e2, \u05d1\u05d1\u05d9\u05ea \u05d4\u05db\u05e0\u05e1\u05ea, \u05d0\u05d5 \u05db\u05dc \u05de\u05e7\u05d5\u05dd \u05e9\u05d1\u05d5 \u05ea\u05d5\u05db\u05dc \u05dc\u05d4\u05e7\u05d3\u05d9\u05e9 \u05de\u05e1\u05e4\u05e8 \u05d3\u05e7\u05d5\u05ea \u05dc\u05dc\u05d0 \u05d4\u05e4\u05e8\u05e2\u05d5\u05ea.\n\u05e9\u05d1 \u05d1\u05e0\u05d5\u05d7\u05d5\u05ea \u2013 \u05e2\u05e6\u05d5\u05dd \u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05dc\u05db\u05de\u05d4 \u05e8\u05d2\u05e2\u05d9\u05dd \u05d5\u05e0\u05e9\u05d5\u05dd \u05e2\u05de\u05d5\u05e7.\n\u05d3\u05de\u05d9\u05d9\u05df \u05e9\u05d0\u05ea\u05d4 \u05de\u05d5\u05e7\u05e3 \u05d1\u05d0\u05d5\u05e8 \u2013 \u05d0\u05d5\u05e8 \u05e8\u05da \u05d5\u05de\u05e8\u05d2\u05d9\u05e2 \u05e9\u05e2\u05d5\u05d8\u05e3 \u05d0\u05d5\u05ea\u05da \u05d5\u05de\u05d7\u05d1\u05e8 \u05d0\u05d5\u05ea\u05da \u05dc\u05ea\u05d7\u05d5\u05e9\u05ea \u05e9\u05dc\u05d5\u05d5\u05d4.\n\u05e9\u05dc\u05d1 2: \u05d4\u05d4\u05e1\u05ea\u05db\u05dc\u05d5\u05ea \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc\n\u05d0\u05dd \u05d0\u05ea\u05d4 \u05d9\u05d5\u05d3\u05e2 \u05d0\u05ea \u05d4\u05db\u05d9\u05d5\u05d5\u05df \u05e9\u05dc \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05de\u05d4\u05de\u05e7\u05d5\u05dd \u05e9\u05d1\u05d5 \u05d0\u05ea\u05d4 \u05e0\u05de\u05e6\u05d0, \u05e4\u05e0\u05d4 \u05dc\u05e9\u05dd \u05e4\u05d9\u05d6\u05d9\u05ea.\n\u05d0\u05dd \u05d0\u05d9\u05e0\u05da \u05d1\u05d8\u05d5\u05d7 \u2013 \u05e4\u05e9\u05d5\u05d8 \u05d4\u05ea\u05db\u05d5\u05d5\u05e0\u05df \u05d1\u05dc\u05d9\u05d1\u05da \u05dc\u05db\u05d9\u05d5\u05d5\u05e0\u05d4.\n\u05d4\u05e8\u05dd \u05d0\u05ea \u05de\u05d1\u05d8\u05da \u05d1\u05e2\u05d3\u05d9\u05e0\u05d5\u05ea \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d6\u05d4 \u2013 \u05db\u05de\u05d5 \u05d0\u05d3\u05dd \u05e9\u05de\u05d1\u05d9\u05d8 \u05dc\u05e2\u05d1\u05e8 \u05d9\u05e2\u05d3 \u05e0\u05db\u05e1\u05e3 \u05d1\u05de\u05e1\u05e2 \u05d7\u05d9\u05d9\u05d5.\n\u05d4\u05e8\u05d2\u05e9 \u05d0\u05ea \u05d4\u05d7\u05d9\u05d1\u05d5\u05e8 \u05dc\u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u2013 \u05d3\u05de\u05d9\u05d9\u05df \u05e9\u05d0\u05ea\u05d4 \u05e2\u05d5\u05de\u05d3 \u05e2\u05dc \u05d0\u05d3\u05de\u05ea\u05d4, \u05e0\u05d5\u05d2\u05e2 \u05d1\u05d4 \u05d1\u05d9\u05d3\u05d9\u05da, \u05de\u05e8\u05d2\u05d9\u05e9 \u05d0\u05ea \u05d4\u05d0\u05d5\u05d5\u05d9\u05e8 \u05e9\u05dc\u05d4 \u05de\u05de\u05dc\u05d0 \u05d0\u05ea \u05e8\u05d9\u05d0\u05d5\u05ea\u05d9\u05da.\n\u05e9\u05d0\u05dc \u05d0\u05ea \u05e2\u05e6\u05de\u05da:\n\u05de\u05d4 \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05de\u05e1\u05de\u05dc\u05ea \u05e2\u05d1\u05d5\u05e8\u05d9?\n\u05d0\u05d9\u05d6\u05d4 \u05e9\u05d5\u05e8\u05e9 \u05e8\u05d5\u05d7\u05e0\u05d9 \u05d9\u05e9 \u05dc\u05d9 \u05d1\u05de\u05e7\u05d5\u05dd \u05d4\u05d6\u05d4?\n\u05db\u05d9\u05e6\u05d3 \u05d0\u05e0\u05d9 \u05d9\u05db\u05d5\u05dc \u05dc\u05d4\u05d1\u05d9\u05d0 \u05d0\u05ea \u05d4\u05e7\u05d3\u05d5\u05e9\u05d4 \u05e9\u05dc \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05d0\u05dc \u05ea\u05d5\u05da \u05d7\u05d9\u05d9?\n\u05e9\u05dc\u05d1 3: \u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05e2\u05dc \u05d4\u05e7\u05e9\u05e8 \u05d1\u05d9\u05df \u05d4\u05d2\u05d5\u05e3 \u05dc\u05e0\u05e9\u05de\u05d4\n\u05d4\u05e0\u05d7 \u05d0\u05ea \u05d9\u05d3\u05da \u05e2\u05dc \u05d4\u05dc\u05d1 \u2013 \u05d4\u05e8\u05d2\u05e9 \u05d0\u05ea \u05e4\u05e2\u05d9\u05de\u05d5\u05ea \u05d4\u05dc\u05d1 \u05e9\u05dc\u05da.\n\u05d3\u05de\u05d9\u05d9\u05df \u05e9\u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05d4\u05d9\u05d0 \u05d4\u05dc\u05d1 \u05e9\u05dc \u05d4\u05e2\u05d5\u05dc\u05dd, \u05d1\u05d3\u05d9\u05d5\u05e7 \u05db\u05e4\u05d9 \u05e9\u05d4\u05dc\u05d1 \u05e9\u05dc\u05da \u05d4\u05d5\u05d0 \u05de\u05e8\u05db\u05d6 \u05d7\u05d9\u05d9\u05da.\n\u05d7\u05e9\u05d5\u05d1 \u05e2\u05dc \u05d7\u05d9\u05d1\u05d5\u05e8 \u05d1\u05d9\u05df \u05e9\u05e0\u05d9\u05d4\u05dd:\n\u05db\u05de\u05d5 \u05e9\u05dc\u05d1 \u05e4\u05d5\u05e2\u05dd \u05d5\u05de\u05d6\u05e8\u05d9\u05dd \u05d7\u05d9\u05d9\u05dd \u05dc\u05db\u05dc \u05d4\u05d2\u05d5\u05e3, \u05db\u05da \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05de\u05d6\u05d9\u05e0\u05d4 \u05d0\u05ea \u05db\u05dc \u05d4\u05e2\u05dd \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9 \u05d1\u05d0\u05e0\u05e8\u05d2\u05d9\u05d4 \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea.\n\u05d3\u05de\u05d9\u05d9\u05df \u05d0\u05d9\u05da \u05d4\u05d0\u05d5\u05e8 \u05e9\u05dc \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05de\u05de\u05dc\u05d0 \u05d0\u05ea \u05dc\u05d9\u05d1\u05da, \u05d5\u05de\u05d7\u05d1\u05e8 \u05d0\u05d5\u05ea\u05da \u05dc\u05e9\u05d5\u05e8\u05e9\u05d9\u05dd \u05e9\u05dc\u05da.\n\u05d0\u05de\u05d5\u05e8 \u05d1\u05dc\u05d1\u05da \u05d0\u05d5 \u05d1\u05e7\u05d5\u05dc \u05e8\u05dd:\n"\u05d0\u05e0\u05d9 \u05de\u05d7\u05d5\u05d1\u05e8 \u05dc\u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc, \u05dc\u05e9\u05d5\u05e8\u05e9 \u05e9\u05dc\u05d9, \u05dc\u05e0\u05e9\u05de\u05d4 \u05e9\u05dc\u05d9."\n"\u05db\u05de\u05d5 \u05e9\u05d0\u05e0\u05d9 \u05de\u05e1\u05ea\u05db\u05dc \u05dc\u05e2\u05d1\u05e8\u05d4, \u05db\u05da \u05d0\u05e0\u05d9 \u05de\u05d1\u05e7\u05e9 \u05dc\u05d4\u05ea\u05e7\u05e8\u05d1 \u05dc\u05de\u05d4\u05d5\u05ea \u05e9\u05dc\u05d9."\n"\u05d0\u05e0\u05d9 \u05de\u05d0\u05e4\u05e9\u05e8 \u05dc\u05d0\u05d5\u05e8 \u05e9\u05dc \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05dc\u05d4\u05d9\u05db\u05e0\u05e1 \u05dc\u05d7\u05d9\u05d9, \u05dc\u05d4\u05d3\u05e8\u05d9\u05da \u05d0\u05d5\u05ea\u05d9, \u05d5\u05dc\u05d4\u05d0\u05d9\u05e8 \u05d0\u05ea \u05d3\u05e8\u05db\u05d9."\n\u05e9\u05dc\u05d1 4: \u05db\u05ea\u05d9\u05d1\u05d4 \u05d5\u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea\n\u05dc\u05d0\u05d7\u05e8 \u05e9\u05e1\u05d9\u05d9\u05de\u05ea \u05d0\u05ea \u05d4\u05ea\u05e8\u05d2\u05d9\u05dc, \u05e7\u05d7 \u05de\u05d7\u05d1\u05e8\u05ea \u05d0\u05d5 \u05d3\u05e3 \u05d5\u05e2\u05e0\u05d4 \u05e2\u05dc \u05d4\u05e9\u05d0\u05dc\u05d5\u05ea \u05d4\u05d1\u05d0\u05d5\u05ea:\n\u05d0\u05d9\u05da \u05d4\u05e8\u05d2\u05e9\u05ea\u05d9 \u05d1\u05de\u05d4\u05dc\u05da \u05d4\u05ea\u05e8\u05d2\u05d9\u05dc?\n\u05d0\u05d9\u05d6\u05d5 \u05de\u05d7\u05e9\u05d1\u05d4 \u05d0\u05d5 \u05ea\u05d5\u05d1\u05e0\u05d4 \u05e2\u05dc\u05d5 \u05d1\u05d9 \u05db\u05e9\u05e4\u05e0\u05d9\u05ea\u05d9 \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc?\n\u05de\u05d4 \u05d0\u05e0\u05d9 \u05dc\u05d5\u05e7\u05d7 \u05de\u05d4\u05ea\u05e8\u05d2\u05d9\u05dc \u05d4\u05d6\u05d4 \u05dc\u05d4\u05de\u05e9\u05da \u05d4\u05d9\u05d5\u05dd \u05e9\u05dc\u05d9?\n\u05d0\u05dd \u05ea\u05e8\u05e6\u05d4, \u05db\u05ea\u05d5\u05d1 \u05ea\u05e4\u05d9\u05dc\u05d4 \u05d0\u05d9\u05e9\u05d9\u05ea \u2013 \u05d1\u05e7\u05e9\u05d4, \u05d4\u05d5\u05d3\u05d9\u05d4, \u05d0\u05d5 \u05e4\u05e9\u05d5\u05d8 \u05de\u05d9\u05dc\u05d9\u05dd \u05e9\u05de\u05d1\u05d8\u05d0\u05d5\u05ea \u05d0\u05ea \u05de\u05d4 \u05e9\u05d7\u05e9\u05d1\u05ea \u05d5\u05d4\u05e8\u05d2\u05e9\u05ea.\n\u05e9\u05dc\u05d1 5: \u05d4\u05d8\u05de\u05e2\u05d4 \u05d1\u05d7\u05d9\u05d9 \u05d4\u05d9\u05d5\u05de\u05d9\u05d5\u05dd\n\u05e0\u05e1\u05d4 \u05e4\u05e2\u05dd \u05d1\u05d9\u05d5\u05dd \u05dc\u05db\u05d5\u05d5\u05df \u05d0\u05ea \u05dc\u05d9\u05d1\u05da \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc, \u05d0\u05e4\u05d9\u05dc\u05d5 \u05d0\u05dd \u05d6\u05d4 \u05e8\u05e7 \u05dc\u05db\u05de\u05d4 \u05e8\u05d2\u05e2\u05d9\u05dd.\n\u05db\u05e9\u05d0\u05ea\u05d4 \u05de\u05ea\u05e4\u05dc\u05dc, \u05d3\u05de\u05d9\u05d9\u05df \u05e9\u05d0\u05ea\u05d4 \u05e2\u05d5\u05de\u05d3 \u05de\u05de\u05e9 \u05d1\u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc, \u05d5\u05e8\u05d0\u05d4 \u05db\u05d9\u05e6\u05d3 \u05d6\u05d4 \u05de\u05e9\u05e4\u05d9\u05e2 \u05e2\u05dc \u05db\u05d5\u05d5\u05e0\u05ea\u05da.\n\u05d1\u05d7\u05d9\u05d9 \u05d4\u05d9\u05d5\u05de\u05d9\u05d5\u05dd, \u05e9\u05d0\u05dc \u05d0\u05ea \u05e2\u05e6\u05de\u05da:\n"\u05d4\u05d0\u05dd \u05d0\u05e0\u05d9 \u05d7\u05d9 \u05d0\u05ea \u05d7\u05d9\u05d9 \u05de\u05ea\u05d5\u05da \u05e7\u05d3\u05d5\u05e9\u05d4 \u05db\u05de\u05d5 \u05e9\u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05de\u05e1\u05de\u05dc\u05ea?"\n"\u05d0\u05d9\u05da \u05d0\u05e0\u05d9 \u05d9\u05db\u05d5\u05dc \u05dc\u05d4\u05d9\u05d5\u05ea \u05e2\u05e8\u05d5\u05e5 \u05e9\u05dc \u05d0\u05d5\u05e8 \u05d5\u05e9\u05e4\u05e2, \u05db\u05de\u05d5 \u05e9\u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05d4\u05d9\u05d0 \u05de\u05e7\u05d5\u05e8 \u05d4\u05d1\u05e8\u05db\u05d4 \u05dc\u05e2\u05d5\u05dc\u05dd?"\n\u05e1\u05d9\u05db\u05d5\u05dd\n\u05d4\u05ea\u05e8\u05d2\u05d9\u05dc \u05d4\u05d6\u05d4 \u05d9\u05e2\u05d6\u05d5\u05e8 \u05dc\u05da \u05dc\u05d4\u05e4\u05d5\u05da \u05d0\u05ea \u05d4\u05d4\u05e1\u05ea\u05db\u05dc\u05d5\u05ea \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05dc\u05d7\u05d5\u05d5\u05d9\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05d5\u05de\u05e9\u05de\u05e2\u05d5\u05ea\u05d9\u05ea, \u05e9\u05de\u05d7\u05d1\u05e8\u05ea \u05d0\u05d5\u05ea\u05da \u05dc\u05e2\u05e6\u05de\u05da, \u05dc\u05d0\u05dc\u05d5\u05d4\u05d5\u05ea, \u05d5\u05dc\u05e2\u05dd \u05d9\u05e9\u05e8\u05d0\u05dc.\n\u05db\u05db\u05dc \u05e9\u05ea\u05ea\u05e8\u05d2\u05dc \u05d9\u05d5\u05ea\u05e8, \u05ea\u05d5\u05db\u05dc \u05dc\u05d4\u05e8\u05d2\u05d9\u05e9 \u05d0\u05d9\u05da \u05d4\u05d4\u05e1\u05ea\u05db\u05dc\u05d5\u05ea \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc \u05de\u05e9\u05e0\u05d4 \u05dc\u05d0 \u05e8\u05e7 \u05d0\u05ea \u05db\u05d9\u05d5\u05d5\u05df \u05d2\u05d5\u05e4\u05da, \u05d0\u05dc\u05d0 \u05d2\u05dd \u05d0\u05ea \u05db\u05d9\u05d5\u05d5\u05df \u05d4\u05e0\u05e9\u05de\u05d4 \u05e9\u05dc\u05da.\n\u05d4\u05e1\u05ea\u05db\u05dc\u05d5\u05ea \u05dc\u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd\n\u05d4\u05de\u05e9\u05de\u05e2\u05d5\u05ea \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9\u05ea \u05e9\u05dc \u05d4\u05e4\u05e0\u05d9\u05d9\u05d4 \u05dc\u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd \u05d1\u05ea\u05e4\u05d9\u05dc\u05d4 \u2013 \u05de\u05d1\u05d8 \u05d4\u05d5\u05dc\u05d9\u05e1\u05d8\u05d9\n1. \u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd \u2013 \u05e0\u05e7\u05d5\u05d3\u05ea \u05d4\u05de\u05e4\u05d2\u05e9 \u05d1\u05d9\u05df \u05e9\u05de\u05d9\u05dd \u05dc\u05d0\u05e8\u05e5\n\u05d4\u05e4\u05e0\u05d9\u05d9\u05d4 \u05dc\u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd \u05d1\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d0\u05d9\u05e0\u05e0\u05d4 \u05e8\u05e7 \u05e2\u05e0\u05d9\u05d9\u05df \u05d4\u05dc\u05db\u05ea\u05d9 \u05d0\u05d5 \u05d8\u05db\u05e0\u05d9, \u05d0\u05dc\u05d0 \u05d4\u05d9\u05d0 \u05de\u05e1\u05e2 \u05e4\u05e0\u05d9\u05de\u05d9 \u05e2\u05de\u05d5\u05e7. \u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd \u05de\u05e1\u05de\u05dc\u05ea \u05d0\u05ea \u05d4\u05de\u05e7\u05d5\u05dd \u05e9\u05d1\u05d5 \u05d4\u05d0\u05e8\u05e6\u05d9 \u05d5\u05d4\u05d0\u05dc\u05d5\u05d4\u05d9 \u05e0\u05e4\u05d2\u05e9\u05d9\u05dd, \u05e9\u05d1\u05d5 \u05d4\u05e9\u05db\u05d9\u05e0\u05d4 \u05d9\u05d5\u05e8\u05d3\u05ea \u05dc\u05e2\u05d5\u05dc\u05dd \u05d5\u05de\u05e9\u05dd \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05e2\u05d5\u05dc\u05d4 \u05dc\u05de\u05e8\u05d5\u05de\u05d9\u05dd.\n\u05d1\u05de\u05d9\u05e1\u05d8\u05d9\u05e7\u05d4 \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9\u05ea, \u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd \u05d4\u05d9\u05d0 \u05d4"\u05de\u05e8\u05db\u05d6 \u05d4\u05d0\u05e0\u05e8\u05d2\u05d8\u05d9" \u05e9\u05dc \u05d4\u05d1\u05e8\u05d9\u05d0\u05d4 \u2013 \u05e6\u05d9\u05e8 \u05d4\u05de\u05d7\u05d1\u05e8 \u05d1\u05d9\u05df \u05e2\u05d5\u05dc\u05de\u05d5\u05ea \u05d4\u05e8\u05d5\u05d7 \u05d5\u05d4\u05d7\u05d5\u05de\u05e8. \u05db\u05d0\u05e9\u05e8 \u05d0\u05e0\u05d5 \u05de\u05ea\u05e4\u05dc\u05dc\u05d9\u05dd \u05dc\u05db\u05d9\u05d5\u05d5\u05e0\u05d4, \u05d0\u05e0\u05d5 \u05de\u05db\u05d5\u05d5\u05e0\u05d9\u05dd \u05d0\u05ea \u05d4\u05ea\u05d5\u05d3\u05e2\u05d4 \u05e9\u05dc\u05e0\u05d5 \u05d0\u05dc \u05e0\u05e7\u05d5\u05d3\u05ea \u05d4\u05e9\u05d5\u05e8\u05e9, \u05e9\u05d1\u05d4 \u05de\u05ea\u05de\u05d6\u05d2\u05d9\u05dd \u05d4\u05e7\u05d5\u05d3\u05e9 \u05d5\u05d4\u05d7\u05d9\u05d9\u05dd \u05d4\u05d2\u05e9\u05de\u05d9\u05d9\u05dd.\n2. \u05d7\u05d9\u05d1\u05d5\u05e8 \u05dc\u05e7\u05d5 \u05d4\u05d0\u05d5\u05e8 \u05d4\u05d0\u05dc\u05d5\u05d4\u05d9\n\u05e2\u05dc \u05e4\u05d9 \u05d4\u05e7\u05d1\u05dc\u05d4, \u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd \u05d4\u05d9\u05d0 \u05e6\u05d9\u05e0\u05d5\u05e8 \u05e9\u05dc \u05d0\u05d5\u05e8 \u05d0\u05dc\u05d5\u05d4\u05d9 \u05d4\u05e9\u05d5\u05e4\u05e2 \u05dc\u05e2\u05d5\u05dc\u05dd. \u05d1\u05de\u05d5\u05d1\u05df \u05d6\u05d4, \u05e4\u05e0\u05d9\u05d9\u05d4 \u05dc\u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd \u05d4\u05d9\u05d0 \u05d4\u05ea\u05db\u05d5\u05d5\u05e0\u05e0\u05d5\u05ea \u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05d0\u05dc \u05d4\u05e9\u05e4\u05e2 \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9 \u05e9\u05d9\u05d5\u05e8\u05d3 \u05de\u05d4\u05de\u05de\u05d3 \u05d4\u05e2\u05dc\u05d9\u05d5\u05df.\n\u05db\u05e4\u05d9 \u05e9\u05d0\u05e0\u05d8\u05e0\u05d4 \u05de\u05db\u05d5\u05d5\u05e0\u05ea \u05d0\u05ea \u05e2\u05e6\u05de\u05d4 \u05dc\u05e7\u05dc\u05d5\u05d8 \u05ea\u05d3\u05e8\u05d9\u05dd \u05de\u05e1\u05d5\u05d9\u05de\u05d9\u05dd, \u05db\u05da \u05d4\u05e4\u05e0\u05d9\u05d9\u05ea \u05d4\u05d2\u05d5\u05e3 \u05d5\u05d4\u05dc\u05d1 \u05dc\u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd \u05e4\u05d5\u05ea\u05d7\u05ea \u05e2\u05e8\u05d5\u05e5 \u05e9\u05d1\u05d5 \u05d4\u05e0\u05e9\u05de\u05d4 \u05e9\u05dc\u05e0\u05d5 \u05de\u05ea\u05de\u05dc\u05d0\u05ea \u05d1\u05d0\u05d5\u05e8 \u05d5\u05d1\u05d7\u05d9\u05d5\u05ea \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea.\n3. \u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd \u2013 \u05dc\u05d1 \u05d4\u05d9\u05e7\u05d5\u05dd\n\u05d4\u05d6\u05d5\u05d4\u05e8 \u05de\u05db\u05e0\u05d4 \u05d0\u05ea \u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd "\u05dc\u05d1 \u05d4\u05e2\u05d5\u05dc\u05dd", \u05d5\u05d4\u05dc\u05d1 \u05d4\u05d5\u05d0 \u05d4\u05de\u05e7\u05d5\u05dd \u05e9\u05de\u05de\u05e0\u05d5 \u05d6\u05d5\u05e8\u05de\u05d9\u05dd \u05d4\u05d7\u05d9\u05d9\u05dd \u05dc\u05db\u05dc \u05d0\u05d9\u05d1\u05e8\u05d9 \u05d4\u05d2\u05d5\u05e3.\n\u05db\u05d0\u05e9\u05e8 \u05d0\u05d3\u05dd \u05de\u05ea\u05e4\u05dc\u05dc \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd, \u05d4\u05d5\u05d0 \u05de\u05de\u05e7\u05dd \u05d0\u05ea \u05e2\u05e6\u05de\u05d5 \u05de\u05d7\u05d3\u05e9 \u05d1\u05ea\u05d5\u05da \u05d4\u05de\u05e2\u05e8\u05db\u05ea \u05d4\u05d0\u05e0\u05e8\u05d2\u05d8\u05d9\u05ea \u05e9\u05dc \u05d4\u05d1\u05e8\u05d9\u05d0\u05d4, \u05d5\u05de\u05d7\u05d1\u05e8 \u05d0\u05ea \u05e0\u05e9\u05de\u05ea\u05d5 \u05dc\u05e9\u05d5\u05e8\u05e9\u05d9\u05d4 \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9\u05d9\u05dd.\n\u05ea\u05d4\u05dc\u05d9\u05da \u05d6\u05d4 \u05d3\u05d5\u05de\u05d4 \u05dc\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05e2\u05de\u05d5\u05e7\u05d4: \u05d4\u05db\u05d9\u05d5\u05d5\u05df \u05d4\u05e4\u05d9\u05d6\u05d9 \u05e9\u05dc \u05d4\u05d2\u05d5\u05e3 \u05de\u05e9\u05de\u05e9 \u05db\u05db\u05dc\u05d9 \u05dc\u05d4\u05d2\u05d1\u05e8\u05ea \u05d4\u05e4\u05d5\u05e7\u05d5\u05e1 \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9, \u05d5\u05de\u05d0\u05e4\u05e9\u05e8 \u05dc\u05e0\u05d5 "\u05dc\u05e0\u05d8\u05e8\u05dc \u05e8\u05e2\u05e9\u05d9\u05dd" \u05d5\u05dc\u05d4\u05ea\u05d7\u05d1\u05e8 \u05dc\u05de\u05d4\u05d5\u05ea \u05d4\u05d2\u05d1\u05d5\u05d4\u05d4 \u05e9\u05dc\u05e0\u05d5.\n4. \u05d4\u05e4\u05e0\u05d9\u05d9\u05d4 \u05db\u05d3\u05e8\u05da \u05dc\u05d4\u05d6\u05db\u05e8\u05d5\u05ea \u05d1\u05de\u05d4\u05d5\u05ea \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05ea\n\u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd \u05de\u05d9\u05d9\u05e6\u05d2\u05ea \u05dc\u05d0 \u05e8\u05e7 \u05de\u05e7\u05d5\u05dd \u05d2\u05d9\u05d0\u05d5\u05d2\u05e8\u05e4\u05d9, \u05d0\u05dc\u05d0 \u05de\u05e6\u05d1 \u05ea\u05d5\u05d3\u05e2\u05ea\u05d9 \u2013 \u05de\u05e6\u05d1 \u05e9\u05d1\u05d5 \u05d4\u05d0\u05d3\u05dd \u05e9\u05dc\u05dd \u05e2\u05dd \u05e2\u05e6\u05de\u05d5, \u05d1\u05de\u05d5\u05d3\u05e2\u05d5\u05ea \u05d2\u05d1\u05d5\u05d4\u05d4 \u05d5\u05e0\u05de\u05e6\u05d0 \u05d1\u05d4\u05e8\u05de\u05d5\u05e0\u05d9\u05d4 \u05e2\u05dd \u05d4\u05d1\u05e8\u05d9\u05d0\u05d4.\n\u05d4\u05de\u05d9\u05dc\u05d4 "\u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd" \u05de\u05d5\u05e8\u05db\u05d1\u05ea \u05de\u05d4\u05de\u05d9\u05dc\u05d9\u05dd "\u05d9\u05e8\u05d0\u05d4" \u05d5**"\u05e9\u05dc\u05dd"**, \u05d5\u05d4\u05d9\u05d0 \u05de\u05e1\u05de\u05dc\u05ea \u05d0\u05ea \u05d4\u05d9\u05db\u05d5\u05dc\u05ea \u05dc\u05e8\u05d0\u05d5\u05ea \u05d0\u05ea \u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea \u05d1\u05e9\u05dc\u05de\u05d5\u05ea\u05d4, \u05de\u05ea\u05d5\u05da \u05e7\u05d3\u05d5\u05e9\u05d4, \u05d0\u05d4\u05d1\u05d4 \u05d5\u05d9\u05e8\u05d0\u05ea \u05db\u05d1\u05d5\u05d3.\n\u05db\u05d0\u05e9\u05e8 \u05d0\u05e0\u05d5 \u05de\u05ea\u05e4\u05dc\u05dc\u05d9\u05dd \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd, \u05d0\u05e0\u05d5 \u05d1\u05e2\u05e6\u05dd \u05e9\u05d5\u05d0\u05dc\u05d9\u05dd \u05d0\u05ea \u05e2\u05e6\u05de\u05e0\u05d5:\n"\u05d4\u05d0\u05dd \u05d0\u05e0\u05d9 \u05de\u05db\u05d5\u05d5\u05df \u05d0\u05ea \u05d7\u05d9\u05d9 \u05dc\u05e2\u05d1\u05e8 \u05d4\u05e9\u05dc\u05de\u05d5\u05ea?"\n"\u05d4\u05d0\u05dd \u05d0\u05e0\u05d9 \u05de\u05d7\u05d5\u05d1\u05e8 \u05dc\u05de\u05d4\u05d5\u05ea \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9\u05ea \u05e9\u05dc\u05d9?"\n\u05d4\u05e4\u05e0\u05d9\u05d9\u05d4 \u05d4\u05e4\u05d9\u05d6\u05d9\u05ea \u05d4\u05d9\u05d0 \u05dc\u05de\u05e2\u05e9\u05d4 \u05ea\u05d6\u05db\u05d5\u05e8\u05ea \u05dc\u05db\u05da \u05e9\u05d4\u05de\u05e1\u05e2 \u05d4\u05d0\u05de\u05d9\u05ea\u05d9 \u05d4\u05d5\u05d0 \u05e4\u05e0\u05d9\u05de\u05d9 \u2013 \u05dc\u05e9\u05d5\u05d1 \u05dc\u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd \u05e9\u05d1\u05ea\u05d5\u05db\u05e0\u05d5.\n5. \u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd \u05db\u05de\u05e9\u05dc \u05dc\u05de\u05e1\u05e2 \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9 \u05e9\u05dc \u05d4\u05d0\u05d3\u05dd\n\u05db\u05dc \u05d0\u05d3\u05dd \u05e0\u05de\u05e6\u05d0 \u05d1\u05de\u05e1\u05e2 \u05d0\u05d9\u05e9\u05d9 \u05e9\u05dc \u05d7\u05d9\u05e4\u05d5\u05e9 \u05d0\u05d7\u05e8 \u05d7\u05d9\u05d1\u05d5\u05e8, \u05de\u05e9\u05de\u05e2\u05d5\u05ea \u05d5\u05d4\u05d0\u05e8\u05d4.\n\u05d1\u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd \u05d4\u05d9\u05d4 \u05d1\u05e0\u05d5\u05d9 \u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9, \u05d0\u05e9\u05e8 \u05e9\u05d9\u05de\u05e9 \u05db\u05de\u05e8\u05db\u05d6 \u05e9\u05d1\u05d5 \u05d4\u05d0\u05d3\u05dd \u05e0\u05e4\u05d2\u05e9 \u05e2\u05dd \u05d4\u05d0\u05dc\u05d5\u05d4\u05d9 \u05d1\u05d0\u05d5\u05e4\u05df \u05d9\u05e9\u05d9\u05e8. \u05db\u05d9\u05d5\u05dd, \u05db\u05d0\u05e9\u05e8 \u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9 \u05d7\u05e8\u05d1, \u05d4\u05d7\u05d6"\u05dc \u05de\u05dc\u05de\u05d3\u05d9\u05dd \u05db\u05d9 \u05d4\u05dc\u05d1 \u05e9\u05dc \u05d4\u05d0\u05d3\u05dd \u05d4\u05d5\u05d0 \u05d4\u05de\u05e7\u05d3\u05e9 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9.\n\u05db\u05d0\u05e9\u05e8 \u05d0\u05e0\u05d5 \u05e4\u05d5\u05e0\u05d9\u05dd \u05dc\u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd, \u05d0\u05e0\u05d5 \u05dc\u05de\u05e2\u05e9\u05d4 \u05de\u05ea\u05db\u05d5\u05d5\u05e0\u05e0\u05d9\u05dd \u05dc\u05d1\u05e0\u05d5\u05ea \u05de\u05d7\u05d3\u05e9 \u05d0\u05ea \u05d4\u05de\u05e7\u05d3\u05e9 \u05d1\u05ea\u05d5\u05db\u05e0\u05d5 \u2013 \u05de\u05e7\u05d5\u05dd \u05e9\u05dc \u05e7\u05d3\u05d5\u05e9\u05d4, \u05d8\u05d5\u05d4\u05e8 \u05d5\u05ea\u05e9\u05d5\u05e7\u05d4 \u05d0\u05de\u05d9\u05ea\u05d9\u05ea \u05dc\u05d4\u05d9\u05d5\u05ea \u05de\u05d7\u05d5\u05d1\u05e8\u05d9\u05dd \u05dc\u05d0\u05d5\u05e8 \u05d4\u05e2\u05dc\u05d9\u05d5\u05df.\n6. \u05e1\u05d9\u05db\u05d5\u05dd \u2013 \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05db\u05de\u05e2\u05e9\u05d4 \u05e9\u05dc \u05d7\u05d9\u05d1\u05d5\u05e8 \u05d5\u05ea\u05d9\u05e7\u05d5\u05df\n\u05e4\u05e0\u05d9\u05d9\u05d4 \u05dc\u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd \u05d4\u05d9\u05d0 \u05d4\u05e8\u05d1\u05d4 \u05de\u05e2\u05d1\u05e8 \u05dc\u05ea\u05e0\u05d5\u05e2\u05d4 \u05e4\u05d9\u05d6\u05d9\u05ea. \u05d4\u05d9\u05d0 \u05d0\u05e7\u05d8 \u05e9\u05dc \u05d7\u05d9\u05d1\u05d5\u05e8 \u05de\u05d7\u05d5\u05d3\u05e9 \u05dc\u05e9\u05d5\u05e8\u05e9 \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9, \u05e9\u05dc \u05ea\u05d9\u05e7\u05d5\u05df \u05e2\u05e6\u05de\u05d9 \u05d5\u05e9\u05dc \u05d4\u05e6\u05d1\u05ea \u05d4\u05dc\u05d1 \u05d1\u05de\u05e7\u05d5\u05dd \u05d4\u05e0\u05db\u05d5\u05df.\n\u05d4\u05d9\u05d0 \u05ea\u05d4\u05dc\u05d9\u05da \u05e9\u05d1\u05d5 \u05d0\u05e0\u05d5 \u05de\u05e1\u05e0\u05db\u05e8\u05e0\u05d9\u05dd \u05d0\u05ea \u05e2\u05e6\u05de\u05e0\u05d5 \u05e2\u05dd \u05d4\u05d9\u05e7\u05d5\u05dd, \u05e2\u05dd \u05d4\u05e0\u05e9\u05de\u05d4 \u05e9\u05dc\u05e0\u05d5 \u05d5\u05e2\u05dd \u05d4\u05d0\u05d5\u05e8 \u05d4\u05d0\u05dc\u05d5\u05d4\u05d9, \u05d5\u05de\u05d6\u05db\u05d9\u05e8\u05d9\u05dd \u05dc\u05e2\u05e6\u05de\u05e0\u05d5 \u05e9\u05ea\u05db\u05dc\u05d9\u05ea \u05d4\u05d7\u05d9\u05d9\u05dd \u05d4\u05d9\u05d0 \u05dc\u05d4\u05e4\u05d5\u05da \u05d0\u05ea \u05e2\u05e6\u05de\u05e0\u05d5 \u05d5\u05d0\u05ea \u05d4\u05e2\u05d5\u05dc\u05dd \u05dc\u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd \u2013 \u05dc\u05de\u05e7\u05d5\u05dd \u05e9\u05dc \u05e9\u05dc\u05de\u05d5\u05ea, \u05e9\u05dc\u05d5\u05dd \u05d5\u05e0\u05d5\u05db\u05d7\u05d5\u05ea \u05d0\u05dc\u05d5\u05d4\u05d9\u05ea.\n\u05d4\u05e1\u05ea\u05db\u05dc\u05d5\u05ea \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9\n\u05d4\u05de\u05e9\u05de\u05e2\u05d5\u05ea \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9\u05ea \u05e9\u05dc \u05d4\u05d4\u05e1\u05ea\u05db\u05dc\u05d5\u05ea \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9 \u2013 \u05de\u05e1\u05e2 \u05e4\u05e0\u05d9\u05de\u05d9 \u05d0\u05dc \u05d4\u05de\u05e8\u05db\u05d6 \u05d4\u05d0\u05dc\u05d5\u05d4\u05d9\n1. \u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9 \u2013 \u05e9\u05e2\u05e8 \u05d1\u05d9\u05df \u05d4\u05e2\u05d5\u05dc\u05de\u05d5\u05ea\n\u05d4\u05e1\u05ea\u05db\u05dc\u05d5\u05ea \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9 \u05d0\u05d9\u05e0\u05e0\u05d4 \u05e8\u05e7 \u05e4\u05e2\u05d5\u05dc\u05d4 \u05d7\u05d9\u05e6\u05d5\u05e0\u05d9\u05ea, \u05d0\u05dc\u05d0 \u05db\u05d5\u05d5\u05e0\u05d5\u05df \u05e9\u05dc \u05d4\u05ea\u05d5\u05d3\u05e2\u05d4 \u05d0\u05dc \u05e0\u05e7\u05d5\u05d3\u05ea \u05d4\u05d7\u05d9\u05d1\u05d5\u05e8 \u05d1\u05d9\u05df \u05d4\u05d0\u05d3\u05dd \u05dc\u05d1\u05d5\u05e8\u05d0. \u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9 \u05d4\u05d9\u05d4 \u05d4\u05e9\u05e2\u05e8 \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9 \u05e9\u05dc \u05d4\u05d1\u05e8\u05d9\u05d0\u05d4, \u05d4\u05de\u05e7\u05d5\u05dd \u05e9\u05d1\u05d5 \u05d4\u05e9\u05db\u05d9\u05e0\u05d4 \u05d9\u05e8\u05d3\u05d4 \u05dc\u05e2\u05d5\u05dc\u05dd. \u05d4\u05e7\u05d1\u05dc\u05d4 \u05de\u05dc\u05de\u05d3\u05ea \u05db\u05d9 \u05d4\u05e8 \u05d4\u05d1\u05d9\u05ea \u05d4\u05d5\u05d0 \u05d4"\u05e6\u05d9\u05e0\u05d5\u05e8" \u05d3\u05e8\u05db\u05d5 \u05d4\u05e9\u05e4\u05e2 \u05d4\u05d0\u05dc\u05d5\u05d4\u05d9 \u05e0\u05db\u05e0\u05e1 \u05dc\u05de\u05e6\u05d9\u05d0\u05d5\u05ea \u05d4\u05e4\u05d9\u05d6\u05d9\u05ea, \u05d5\u05dc\u05db\u05df \u05db\u05e9\u05d0\u05d3\u05dd \u05de\u05db\u05d5\u05d5\u05df \u05d0\u05ea \u05de\u05d1\u05d8\u05d5 \u05dc\u05e9\u05dd, \u05d4\u05d5\u05d0 \u05de\u05ea\u05d9\u05d9\u05e9\u05e8 \u05e2\u05dd \u05d0\u05e0\u05e8\u05d2\u05d9\u05d4 \u05e9\u05dc \u05e7\u05d3\u05d5\u05e9\u05d4 \u05d5\u05d7\u05d9\u05d9\u05dd.\n\u05d4\u05e4\u05e1\u05d5\u05e7 "\u05d5\u05d4\u05d9\u05d5 \u05e2\u05d9\u05e0\u05d9 \u05d5\u05dc\u05d9\u05d1\u05d9 \u05e9\u05dd \u05db\u05dc \u05d4\u05d9\u05de\u05d9\u05dd" (\u05de\u05dc\u05db\u05d9\u05dd \u05d0\' \u05d8\', \u05d2) \u05de\u05dc\u05de\u05d3 \u05e9\u05d4\u05e0\u05d5\u05db\u05d7\u05d5\u05ea \u05d4\u05d0\u05dc\u05d5\u05d4\u05d9\u05ea \u05e7\u05e9\u05d5\u05e8\u05d4 \u05dc\u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9 \u05dc\u05e0\u05e6\u05d7. \u05db\u05d0\u05e9\u05e8 \u05d0\u05e0\u05d5 \u05de\u05e1\u05ea\u05db\u05dc\u05d9\u05dd \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9 \u05d1\u05ea\u05e4\u05d9\u05dc\u05d4, \u05d0\u05e0\u05d5 \u05de\u05ea\u05d7\u05d1\u05e8\u05d9\u05dd \u05dc\u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05d5\u05dc\u05dc\u05d1 \u05e9\u05dc \u05d4\u05d0\u05dc\u05d5\u05d4\u05d5\u05ea, \u05d5\u05db\u05da \u05d0\u05e0\u05d5 \u05d9\u05db\u05d5\u05dc\u05d9\u05dd \u05dc\u05e8\u05d0\u05d5\u05ea \u05d0\u05ea \u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea \u05d1\u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05d7\u05d3\u05e9\u05d5\u05ea \u2013 \u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05e9\u05dc \u05d0\u05de\u05ea \u05d5\u05d0\u05d4\u05d1\u05d4.\n2. \u05d4\u05d4\u05e1\u05ea\u05db\u05dc\u05d5\u05ea \u05db\u05de\u05e1\u05e2 \u05e9\u05dc \u05ea\u05d9\u05e7\u05d5\u05df\n\u05d1\u05de\u05d9\u05e1\u05d8\u05d9\u05e7\u05d4 \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9\u05ea, \u05d4\u05e2\u05d5\u05dc\u05dd \u05e0\u05de\u05e6\u05d0 \u05d1\u05de\u05e6\u05d1 \u05e9\u05dc \u05d4\u05e1\u05ea\u05e8 \u05e4\u05e0\u05d9\u05dd \u2013 \u05d0\u05d5\u05e8 \u05d4\u05e9\u05db\u05d9\u05e0\u05d4 \u05e0\u05e1\u05ea\u05e8 \u05d1\u05ea\u05d5\u05da \u05d4\u05d7\u05d5\u05de\u05e8, \u05d5\u05d4\u05d0\u05d3\u05dd \u05de\u05d7\u05e4\u05e9 \u05d0\u05ea \u05d3\u05e8\u05db\u05d5 \u05d0\u05dc \u05d4\u05e7\u05d3\u05d5\u05e9\u05d4.\n\u05d4\u05e1\u05ea\u05db\u05dc\u05d5\u05ea \u05dc\u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9 \u05d4\u05d9\u05d0 \u05ea\u05d4\u05dc\u05d9\u05da \u05e9\u05d1\u05d5 \u05d0\u05e0\u05d5 \u05de\u05d7\u05d6\u05d9\u05e8\u05d9\u05dd \u05d0\u05ea \u05d0\u05d5\u05e8 \u05d4\u05e9\u05db\u05d9\u05e0\u05d4 \u05dc\u05d7\u05d9\u05d9\u05e0\u05d5.\n\u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9, \u05e9\u05d4\u05d9\u05d4 \u05de\u05e7\u05d5\u05dd \u05d4\u05d4\u05ea\u05d2\u05dc\u05d5\u05ea \u05d4\u05d0\u05dc\u05d5\u05d4\u05d9\u05ea, \u05de\u05e1\u05de\u05dc \u05d0\u05ea \u05d4\u05de\u05e8\u05db\u05d6 \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9 \u05e9\u05dc \u05d4\u05d0\u05d3\u05dd. \u05db\u05dc \u05d0\u05d3\u05dd \u05d4\u05d5\u05d0 \u05de\u05e7\u05d3\u05e9 \u05e7\u05d8\u05df \u2013 \u05d1\u05ea\u05d5\u05db\u05d5 \u05e9\u05d5\u05db\u05e0\u05ea \u05d4\u05e0\u05e9\u05de\u05d4 \u05d4\u05d0\u05dc\u05d5\u05d4\u05d9\u05ea, \u05d5\u05ea\u05e4\u05e7\u05d9\u05d3\u05d5 \u05d4\u05d5\u05d0 \u05dc\u05d8\u05d4\u05e8 \u05d0\u05ea \u05e2\u05e6\u05de\u05d5 \u05d5\u05dc\u05d4\u05d9\u05d5\u05ea \u05db\u05dc\u05d9 \u05dc\u05d4\u05e9\u05e8\u05d0\u05ea \u05d4\u05e9\u05db\u05d9\u05e0\u05d4. \u05db\u05d0\u05e9\u05e8 \u05d0\u05e0\u05d5 \u05de\u05e1\u05ea\u05db\u05dc\u05d9\u05dd \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9, \u05d0\u05e0\u05d5 \u05d1\u05e2\u05e6\u05dd \u05e9\u05d5\u05d0\u05dc\u05d9\u05dd \u05d0\u05ea \u05e2\u05e6\u05de\u05e0\u05d5: \u05d4\u05d0\u05dd \u05d0\u05e0\u05d9 \u05de\u05d0\u05e4\u05e9\u05e8 \u05dc\u05e9\u05db\u05d9\u05e0\u05d4 \u05dc\u05e9\u05db\u05d5\u05df \u05d1\u05d9? \u05d4\u05d0\u05dd \u05d0\u05e0\u05d9 \u05d9\u05d5\u05e6\u05e8 \u05d1\u05ea\u05d5\u05db\u05d9 \u05de\u05e7\u05d5\u05dd \u05dc\u05d4\u05e9\u05e8\u05d0\u05ea \u05d4\u05e7\u05d3\u05d5\u05e9\u05d4?\n3. \u05d4\u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea \u05db\u05e4\u05e2\u05d5\u05dc\u05d4 \u05e9\u05dc \u05d9\u05d9\u05d7\u05d5\u05d3 \u05d5\u05d0\u05d7\u05d3\u05d5\u05ea\n\u05d4\u05e8\u05de\u05d1"\u05dd \u05de\u05e1\u05d1\u05d9\u05e8 \u05db\u05d9 \u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9 \u05d4\u05d9\u05d4 \u05d4\u05de\u05e7\u05d5\u05dd \u05e9\u05d1\u05d5 \u05e0\u05d5\u05e6\u05e8 \u05d4\u05d7\u05d9\u05d1\u05d5\u05e8 \u05d1\u05d9\u05df \u05db\u05dc \u05d4\u05de\u05de\u05d3\u05d9\u05dd \u2013 \u05d1\u05d9\u05df \u05d4\u05d0\u05d3\u05dd, \u05d4\u05e2\u05dd \u05d5\u05d4\u05d0\u05dc\u05d5\u05d4\u05d5\u05ea.\n"\u05e0\u05de\u05e6\u05d0 \u05db\u05dc \u05d9\u05e9\u05e8\u05d0\u05dc \u05de\u05db\u05d5\u05d5\u05e0\u05d9\u05df \u05d0\u05ea \u05dc\u05d9\u05d1\u05dd \u05dc\u05de\u05e7\u05d5\u05dd \u05d0\u05d7\u05d3." (\u05d1\u05e8\u05db\u05d5\u05ea \u05dc\', \u05d0\')\n\u05db\u05d0\u05e9\u05e8 \u05d0\u05e0\u05d5 \u05de\u05e1\u05ea\u05db\u05dc\u05d9\u05dd \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9, \u05d0\u05e0\u05d5 \u05de\u05ea\u05e2\u05dc\u05d9\u05dd \u05de\u05e2\u05dc \u05dc\u05d4\u05d1\u05d3\u05dc\u05d9\u05dd \u05d5\u05dc\u05e4\u05d9\u05e6\u05d5\u05dc\u05d9\u05dd \u05d5\u05de\u05db\u05d5\u05d5\u05e0\u05d9\u05dd \u05d0\u05ea \u05dc\u05d9\u05d1\u05e0\u05d5 \u05dc\u05d0\u05d7\u05d3\u05d5\u05ea.\n\u05d4\u05d7\u05d9\u05d9\u05dd \u05de\u05dc\u05d0\u05d9\u05dd \u05d1\u05d4\u05e1\u05d7\u05d5\u05ea \u05d3\u05e2\u05ea, \u05d1\u05dc\u05d1\u05d5\u05dc \u05d5\u05e4\u05d9\u05d6\u05d5\u05e8 \u05e0\u05e4\u05e9 \u2013 \u05d0\u05da \u05d1\u05e8\u05d2\u05e2 \u05e9\u05d0\u05d3\u05dd \u05de\u05ea\u05e8\u05db\u05d6 \u05d1\u05e0\u05e7\u05d5\u05d3\u05ea \u05d4\u05d0\u05d7\u05d3\u05d5\u05ea \u05e9\u05dc \u05d4\u05d1\u05e8\u05d9\u05d0\u05d4, \u05d4\u05d5\u05d0 \u05d7\u05d5\u05d6\u05e8 \u05d0\u05dc \u05d4\u05de\u05d4\u05d5\u05ea \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05e9\u05dc\u05d5. \u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9 \u05de\u05e1\u05de\u05dc \u05d0\u05ea \u05e0\u05e7\u05d5\u05d3\u05ea \u05d4\u05d9\u05d9\u05d7\u05d5\u05d3 \u05e9\u05dc \u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea, \u05d5\u05dc\u05db\u05df \u05d4\u05d4\u05e1\u05ea\u05db\u05dc\u05d5\u05ea \u05dc\u05e9\u05dd \u05d4\u05d9\u05d0 \u05ea\u05e8\u05d2\u05d5\u05dc \u05e8\u05d5\u05d7\u05e0\u05d9 \u05e9\u05de\u05d6\u05db\u05d9\u05e8 \u05dc\u05e0\u05d5 \u05e9\u05d0\u05e0\u05d5 \u05d7\u05dc\u05e7 \u05de\u05d4\u05e9\u05dc\u05dd, \u05e9\u05d4\u05d0\u05dc\u05d5\u05d4\u05d5\u05ea \u05e0\u05d5\u05db\u05d7\u05ea \u05d1\u05db\u05dc, \u05d5\u05e9\u05db\u05dc \u05d4\u05e4\u05d9\u05e6\u05d5\u05dc\u05d9\u05dd \u05d4\u05dd \u05d0\u05e9\u05dc\u05d9\u05d4.\n4. \u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9 \u05db\u05ea\u05d3\u05e8 \u05e9\u05dc \u05d0\u05d5\u05e8\n\u05d4\u05e7\u05d1\u05dc\u05d4 \u05de\u05dc\u05de\u05d3\u05ea \u05db\u05d9 \u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9 \u05e9\u05d9\u05de\u05e9 \u05db"\u05ea\u05d7\u05e0\u05ea \u05db\u05d5\u05d7" \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea. \u05d4\u05d0\u05d5\u05e8 \u05d4\u05d0\u05dc\u05d5\u05d4\u05d9 \u05d9\u05e8\u05d3 \u05d3\u05e8\u05da \u05d4**"\u05d0\u05d1\u05df \u05d4\u05e9\u05ea\u05d9\u05d9\u05d4"**, \u05e9\u05de\u05de\u05e0\u05d4 \u05e0\u05d1\u05e8\u05d0 \u05d4\u05e2\u05d5\u05dc\u05dd, \u05d5\u05de\u05e9\u05dd \u05d4\u05ea\u05e4\u05e9\u05d8 \u05dc\u05db\u05dc \u05d4\u05d1\u05e8\u05d9\u05d0\u05d4.\n\u05db\u05d0\u05e9\u05e8 \u05d0\u05e0\u05d5 \u05de\u05db\u05d5\u05d5\u05e0\u05d9\u05dd \u05d0\u05ea \u05d4\u05de\u05d1\u05d8 \u05dc\u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9, \u05d0\u05e0\u05d5 \u05de\u05ea\u05d9\u05d9\u05e9\u05e8\u05d9\u05dd \u05e2\u05dd \u05d4\u05ea\u05d3\u05e8 \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9 \u05d4\u05d2\u05d1\u05d5\u05d4 \u05d1\u05d9\u05d5\u05ea\u05e8, \u05de\u05e2\u05d9\u05df \u05db\u05d5\u05d5\u05e0\u05d5\u05df \u05e0\u05e9\u05de\u05ea\u05d9 \u05e9\u05de\u05d0\u05e4\u05e9\u05e8 \u05dc\u05d0\u05d5\u05e8 \u05d4\u05e2\u05dc\u05d9\u05d5\u05df \u05dc\u05d6\u05e8\u05d5\u05dd \u05d3\u05e8\u05db\u05e0\u05d5.\n\u05d1\u05d3\u05d5\u05de\u05d4 \u05dc\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05e9\u05d1\u05d4 \u05d0\u05d3\u05dd \u05de\u05ea\u05de\u05e7\u05d3 \u05d1\u05e0\u05e7\u05d5\u05d3\u05ea \u05d0\u05d5\u05e8 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea, \u05db\u05da \u05d2\u05dd \u05d4\u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea \u05dc\u05e2\u05d1\u05e8 \u05d4\u05de\u05e7\u05d3\u05e9 \u05de\u05d0\u05e4\u05e9\u05e8\u05ea \u05dc\u05e0\u05d5 \u05dc\u05e9\u05d0\u05d5\u05d1 \u05e2\u05d5\u05e6\u05de\u05d4 \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea, \u05dc\u05d4\u05ea\u05d7\u05d3\u05e9 \u05d5\u05dc\u05d4\u05ea\u05de\u05dc\u05d0 \u05d1\u05d0\u05e0\u05e8\u05d2\u05d9\u05d4 \u05d0\u05dc\u05d5\u05d4\u05d9\u05ea.\n5. \u05d4\u05d4\u05e1\u05ea\u05db\u05dc\u05d5\u05ea \u05db\u05d4\u05d6\u05de\u05e0\u05d4 \u05dc\u05d2\u05d0\u05d5\u05dc\u05d4\n\u05e2\u05dc \u05e4\u05d9 \u05d4\u05d7\u05e1\u05d9\u05d3\u05d5\u05ea, \u05d4\u05de\u05d7\u05e9\u05d1\u05d4 \u05d9\u05d5\u05e6\u05e8\u05ea \u05de\u05e6\u05d9\u05d0\u05d5\u05ea. \u05db\u05d0\u05e9\u05e8 \u05d0\u05e0\u05d5 \u05de\u05e1\u05ea\u05db\u05dc\u05d9\u05dd \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9, \u05d0\u05e0\u05d5 \u05dc\u05d0 \u05e8\u05e7 \u05de\u05ea\u05d7\u05d1\u05e8\u05d9\u05dd \u05dc\u05d0\u05d5\u05e8\u05d5, \u05d0\u05dc\u05d0 \u05d2\u05dd \u05de\u05e9\u05ea\u05ea\u05e4\u05d9\u05dd \u05d1\u05d0\u05e7\u05d8 \u05e9\u05dc \u05d9\u05e6\u05d9\u05e8\u05ea \u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9\u05ea \u05e9\u05dc \u05d4\u05d2\u05d0\u05d5\u05dc\u05d4.\n\u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9 \u05d4\u05e9\u05dc\u05d9\u05e9\u05d9, \u05e2\u05dc \u05e4\u05d9 \u05d4\u05de\u05e1\u05d5\u05e8\u05ea, \u05db\u05d1\u05e8 \u05e7\u05d9\u05d9\u05dd \u05d1\u05de\u05de\u05d3 \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9 \u2013 \u05d4\u05d5\u05d0 \u05de\u05d7\u05db\u05d4 \u05e9\u05e0\u05d6\u05de\u05d9\u05df \u05d0\u05d5\u05ea\u05d5 \u05d0\u05dc \u05ea\u05d5\u05da \u05d4\u05e2\u05d5\u05dc\u05dd \u05d4\u05d6\u05d4.\n\u05db\u05d0\u05e9\u05e8 \u05d0\u05e0\u05d5 \u05de\u05db\u05d5\u05d5\u05e0\u05d9\u05dd \u05d0\u05ea \u05d4\u05de\u05d1\u05d8, \u05d4\u05dc\u05d1 \u05d5\u05d4\u05de\u05d7\u05e9\u05d1\u05d4 \u05dc\u05e9\u05dd, \u05d0\u05e0\u05d5 \u05de\u05d5\u05e9\u05db\u05d9\u05dd \u05d0\u05ea \u05d4\u05d0\u05e0\u05e8\u05d2\u05d9\u05d4 \u05d4\u05d6\u05d5 \u05dc\u05ea\u05d5\u05da \u05d7\u05d9\u05d9\u05e0\u05d5 \u05d5\u05de\u05d6\u05e8\u05d6\u05d9\u05dd \u05d0\u05ea \u05d4\u05ea\u05d4\u05dc\u05d9\u05da \u05e9\u05dc \u05d1\u05e0\u05d9\u05d9\u05df \u05d4\u05de\u05e7\u05d3\u05e9 \u05d1\u05d2\u05e9\u05de\u05d9\u05d5\u05ea.\n\u05d4\u05d4\u05e1\u05ea\u05db\u05dc\u05d5\u05ea \u05dc\u05de\u05e7\u05d3\u05e9 \u05d4\u05d9\u05d0 \u05de\u05e2\u05d9\u05df \u05e0\u05d1\u05d5\u05d0\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u2013 \u05d0\u05e0\u05d5 \u05e8\u05d5\u05d0\u05d9\u05dd \u05d1\u05e2\u05d9\u05e0\u05d9 \u05e8\u05d5\u05d7\u05e0\u05d5 \u05d0\u05ea \u05d4\u05e9\u05dc\u05de\u05d5\u05ea, \u05d0\u05ea \u05d4\u05d0\u05d5\u05e8 \u05d4\u05d2\u05e0\u05d5\u05d6, \u05d5\u05de\u05d0\u05e4\u05e9\u05e8\u05d9\u05dd \u05dc\u05de\u05e6\u05d9\u05d0\u05d5\u05ea \u05dc\u05d4\u05ea\u05e2\u05e6\u05d1 \u05d1\u05d4\u05ea\u05d0\u05dd.\n6. \u05d4\u05e4\u05e0\u05d9\u05dd \u05db\u05d1\u05d1\u05d5\u05d0\u05d4 \u05e9\u05dc \u05d4\u05de\u05e7\u05d3\u05e9\n\u05e2\u05dc \u05e4\u05d9 \u05d4\u05e7\u05d1\u05dc\u05d4, \u05d4\u05de\u05d1\u05e0\u05d4 \u05e9\u05dc \u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9 \u05de\u05e9\u05ea\u05e7\u05e3 \u05d1\u05d2\u05d5\u05e3 \u05d4\u05d0\u05d3\u05dd:\n\u05d4\u05e7\u05d5\u05d3\u05e9 \u2013 \u05d4\u05dc\u05d1\n\u05e7\u05d5\u05d3\u05e9 \u05d4\u05e7\u05d5\u05d3\u05e9\u05d9\u05dd \u2013 \u05d4\u05e0\u05e9\u05de\u05d4\n\u05d4\u05de\u05d6\u05d1\u05d7 \u2013 \u05d4\u05e4\u05d4 \u05d5\u05d4\u05ea\u05e4\u05d9\u05dc\u05d4\n\u05db\u05d0\u05e9\u05e8 \u05d0\u05e0\u05d5 \u05de\u05e1\u05ea\u05db\u05dc\u05d9\u05dd \u05dc\u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9, \u05d0\u05e0\u05d5 \u05dc\u05de\u05e2\u05e9\u05d4 \u05de\u05db\u05d5\u05d5\u05e0\u05d9\u05dd \u05d0\u05ea \u05e2\u05e6\u05de\u05e0\u05d5 \u05e4\u05e0\u05d9\u05de\u05d4 \u2013 \u05d0\u05dc \u05d4\u05dc\u05d1, \u05d0\u05dc \u05d4\u05e0\u05e9\u05de\u05d4, \u05d0\u05dc \u05d4\u05de\u05e7\u05d5\u05dd \u05d4\u05e7\u05d3\u05d5\u05e9 \u05d1\u05d9\u05d5\u05ea\u05e8 \u05e9\u05d1\u05ea\u05d5\u05db\u05e0\u05d5.\n\u05db\u05e4\u05d9 \u05e9\u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9 \u05d4\u05d9\u05d4 \u05d4\u05de\u05e7\u05d5\u05dd \u05e9\u05de\u05de\u05e0\u05d5 \u05d4\u05d5\u05e7\u05e8\u05d1\u05d5 \u05d4\u05e7\u05d5\u05e8\u05d1\u05e0\u05d5\u05ea \u05dc\u05d8\u05d4\u05e8\u05ea \u05d4\u05e2\u05dd, \u05db\u05da \u05d2\u05dd \u05d4\u05d4\u05e1\u05ea\u05db\u05dc\u05d5\u05ea \u05e9\u05dc\u05e0\u05d5 \u05dc\u05e9\u05dd \u05d4\u05d9\u05d0 \u05e7\u05e8\u05d1\u05df \u05e8\u05d5\u05d7\u05e0\u05d9 \u2013 \u05e7\u05e8\u05d1\u05df \u05e9\u05dc \u05d4\u05d0\u05d2\u05d5, \u05e9\u05dc \u05d4\u05e4\u05d7\u05d3\u05d9\u05dd, \u05e9\u05dc \u05d4\u05de\u05d7\u05d9\u05e6\u05d5\u05ea \u05e9\u05de\u05e4\u05e8\u05d9\u05d3\u05d5\u05ea \u05d1\u05d9\u05e0\u05d9\u05e0\u05d5 \u05dc\u05d1\u05d9\u05df \u05d4\u05d0\u05d5\u05e8 \u05d4\u05d0\u05dc\u05d5\u05d4\u05d9.\n\u05e1\u05d9\u05db\u05d5\u05dd: \u05d4\u05d4\u05e1\u05ea\u05db\u05dc\u05d5\u05ea \u05dc\u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9 \u05db\u05de\u05e2\u05e9\u05d4 \u05e9\u05dc \u05d7\u05d9\u05d1\u05d5\u05e8, \u05d4\u05ea\u05e2\u05dc\u05d5\u05ea \u05d5\u05ea\u05d9\u05e7\u05d5\u05df\n\u05d4\u05e1\u05ea\u05db\u05dc\u05d5\u05ea \u05dc\u05db\u05d9\u05d5\u05d5\u05df \u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9 \u05d4\u05d9\u05d0 \u05de\u05e2\u05e9\u05d4 \u05e9\u05dc \u05d4\u05ea\u05d7\u05d1\u05e8\u05d5\u05ea \u05dc\u05de\u05e8\u05db\u05d6 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9 \u05e9\u05dc\u05e0\u05d5.\n\u05d6\u05d5 \u05d0\u05d9\u05e0\u05d4 \u05e8\u05e7 \u05e4\u05e2\u05d5\u05dc\u05d4 \u05d7\u05d9\u05e6\u05d5\u05e0\u05d9\u05ea, \u05d0\u05dc\u05d0 \u05de\u05e1\u05e2 \u05e4\u05e0\u05d9\u05de\u05d9 \u05e9\u05dc \u05d2\u05d9\u05dc\u05d5\u05d9 \u05d4\u05e9\u05db\u05d9\u05e0\u05d4 \u2013 \u05d1\u05e0\u05d5 \u05d5\u05d1\u05e2\u05d5\u05dc\u05dd.\n\u05db\u05d0\u05e9\u05e8 \u05d0\u05e0\u05d5 \u05e4\u05d5\u05e0\u05d9\u05dd \u05dc\u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9, \u05d0\u05e0\u05d5 \u05de\u05d6\u05db\u05d9\u05e8\u05d9\u05dd \u05dc\u05e2\u05e6\u05de\u05e0\u05d5:\n\u05e9\u05d0\u05e0\u05d5 \u05d7\u05dc\u05e7 \u05de\u05e1\u05d9\u05e4\u05d5\u05e8 \u05d2\u05d3\u05d5\u05dc \u05d9\u05d5\u05ea\u05e8 \u2013 \u05e1\u05d9\u05e4\u05d5\u05e8 \u05e9\u05dc \u05e7\u05d3\u05d5\u05e9\u05d4, \u05d0\u05d7\u05d3\u05d5\u05ea \u05d5\u05d2\u05d0\u05d5\u05dc\u05d4.\n\u05e9\u05d4\u05d0\u05d5\u05e8 \u05d4\u05d0\u05dc\u05d5\u05d4\u05d9 \u05e0\u05d5\u05db\u05d7, \u05d2\u05dd \u05d0\u05dd \u05d4\u05d5\u05d0 \u05e0\u05e1\u05ea\u05e8.\n\u05e9\u05db\u05dc \u05d0\u05d7\u05d3 \u05de\u05d0\u05d9\u05ea\u05e0\u05d5 \u05d4\u05d5\u05d0 \u05de\u05e7\u05d3\u05e9 \u05d7\u05d9, \u05d5\u05d4\u05d1\u05d7\u05d9\u05e8\u05d4 \u05d1\u05d9\u05d3\u05d9\u05e0\u05d5 \u05dc\u05d4\u05e4\u05d5\u05da \u05d0\u05ea \u05d7\u05d9\u05d9\u05e0\u05d5 \u05dc\u05db\u05dc\u05d9 \u05dc\u05d0\u05d5\u05e8 \u05d4\u05d0\u05dc\u05d5\u05d4\u05d9.\n\u05db\u05da, \u05d4\u05d4\u05e1\u05ea\u05db\u05dc\u05d5\u05ea \u05d4\u05e4\u05d9\u05d6\u05d9\u05ea \u05d4\u05d5\u05e4\u05db\u05ea \u05dc\u05e9\u05e2\u05e8 \u05dc\u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea \u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05e2\u05de\u05d5\u05e7\u05d4 \u2013 \u05e9\u05e2\u05e8 \u05e9\u05de\u05d5\u05d1\u05d9\u05dc \u05d0\u05d5\u05ea\u05e0\u05d5 \u05dc\u05de\u05e7\u05d5\u05dd \u05e9\u05dc \u05e9\u05dc\u05d5\u05d5\u05d4, \u05d4\u05e9\u05e8\u05d0\u05d4 \u05d5\u05d4\u05ea\u05d7\u05d1\u05e8\u05d5\u05ea \u05de\u05d7\u05d5\u05d3\u05e9\u05ea \u05dc\u05de\u05e7\u05d5\u05e8 \u05d4\u05d7\u05d9\u05d9\u05dd.\n.\n\u05d0\u05de\u05d5\u05e0\u05d4 \u05d4\u05d9\u05d0 \u05d1\u05d7\u05d9\u05e8\u05d4\n\u05d0\u05de\u05d5\u05e0\u05d4 \u05d0\u05d9\u05e0\u05d4 \u05ea\u05db\u05d5\u05e0\u05d4 \u05de\u05d5\u05dc\u05d3\u05ea \u2013 \u05d4\u05d9\u05d0 \u05d1\u05d7\u05d9\u05e8\u05d4 \u05de\u05d5\u05d3\u05e2\u05ea.\n\u05d0\u05e0\u05d7\u05e0\u05d5 \u05d1\u05d5\u05d7\u05e8\u05d9\u05dd \u05dc\u05d4\u05d0\u05de\u05d9\u05df. \u05d1\u05d5\u05d7\u05e8\u05d9\u05dd \u05dc\u05d4\u05d0\u05de\u05d9\u05df \u05d1\u05d9\u05db\u05d5\u05dc\u05ea \u05e9\u05dc \u05d4\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05dc\u05e8\u05e4\u05d0 \u05d5\u05dc\u05e9\u05e4\u05e8 \u05d0\u05ea \u05d7\u05d9\u05d9\u05e0\u05d5. \u05d1\u05d5\u05d7\u05e8\u05d9\u05dd \u05dc\u05d4\u05d0\u05de\u05d9\u05df \u05d1\u05db\u05d5\u05d7\u05dd \u05e9\u05dc \u05db\u05dc\u05d9\u05dd \u05e9\u05d5\u05e0\u05d9\u05dd \u05d4\u05de\u05d0\u05e4\u05e9\u05e8\u05d9\u05dd \u05dc\u05e0\u05d5 \u05dc\u05d4\u05ea\u05d1\u05d5\u05e0\u05df \u05e4\u05e0\u05d9\u05de\u05d4, \u05dc\u05d4\u05ea\u05d7\u05d1\u05e8 \u05d5\u05dc\u05e6\u05de\u05d5\u05d7.\n\u05d1\u05e2\u05d5\u05dc\u05dd \u05e7\u05d9\u05d9\u05de\u05d9\u05dd \u05e1\u05d2\u05e0\u05d5\u05e0\u05d5\u05ea \u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05de\u05d2\u05d5\u05d5\u05e0\u05d9\u05dd, \u05d5\u05db\u05dc \u05d0\u05d3\u05dd \u05de\u05ea\u05d7\u05d1\u05e8 \u05dc\u05e9\u05d9\u05d8\u05d4 \u05e9\u05de\u05ea\u05d0\u05d9\u05de\u05d4 \u05dc\u05d5. \u05d0\u05e0\u05d7\u05e0\u05d5 \u05d1\u05d5\u05d7\u05e8\u05d9\u05dd \u05dc\u05d4\u05d0\u05de\u05d9\u05df \u05d1\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05e9\u05dc \u05d4\u05d0\u05d5\u05e8 \u05d4\u05d0\u05d9\u05e0\u05e1\u05d5\u05e4\u05d9, \u05d4\u05de\u05d9\u05d5\u05e6\u05d2 \u05d1\u05e9\u05dd \u05d4\u05e7\u05d3\u05d5\u05e9 \u05d9-\u05d4-\u05d5-\u05d4. \u05d3\u05e8\u05da \u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d6\u05d5 \u05d0\u05e0\u05d5 \u05de\u05d1\u05e7\u05e9\u05d9\u05dd \u05dc\u05d4\u05ea\u05d7\u05d1\u05e8 \u05dc\u05e9\u05d5\u05e8\u05e9 \u05d4\u05d1\u05e8\u05d9\u05d0\u05d4, \u05d0\u05dc \u05d4\u05de\u05e7\u05d5\u05e8 \u05d4\u05e2\u05dc\u05d9\u05d5\u05df \u05e9\u05dc \u05d4\u05d8\u05d5\u05d1, \u05d4\u05e9\u05dc\u05d5\u05d5\u05d4 \u05d5\u05d4\u05e8\u05d9\u05e4\u05d5\u05d9.\n\u05d6\u05d5\u05d4\u05d9 \u05d1\u05d7\u05d9\u05e8\u05d4 \u05d4\u05de\u05e2\u05e6\u05d1\u05ea \u05d0\u05d5\u05ea\u05e0\u05d5, \u05de\u05e8\u05e4\u05d0\u05d4 \u05d0\u05d5\u05ea\u05e0\u05d5 \u05d5\u05de\u05d5\u05d1\u05d9\u05dc\u05d4 \u05d0\u05d5\u05ea\u05e0\u05d5 \u05dc\u05d3\u05e8\u05da \u05d7\u05d3\u05e9\u05d4 \u05e9\u05dc \u05e6\u05de\u05d9\u05d7\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea.')
B.L4=new A.cv(16,"\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d9\u05d4\u05d5\u05d3\u05d9\u05ea \u05d3\u05e8\u05da \u05d4\u05e1\u05d9\u05d3\u05d5\u05e8 \u05d5\u05d4\u05de\u05d9\u05dc\u05d4 \u05d0\u05d5\u05d5\u05d9\u05e8",'\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d9\u05d4\u05d5\u05d3\u05d9\u05ea: \u05d7\u05d9\u05d1\u05d5\u05e8 \u05dc\u05e2\u05d5\u05de\u05e7 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9 \u05d3\u05e8\u05da \u05d4\u05e1\u05d9\u05d3\u05d5\u05e8\n\u05d4\u05d1\u05e1\u05d9\u05e1 \u05dc\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d9\u05d4\u05d5\u05d3\u05d9\u05ea \u05d8\u05de\u05d5\u05df \u05d1\u05e1\u05d9\u05d3\u05d5\u05e8 \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4.\n\u05d4\u05e1\u05d9\u05d3\u05d5\u05e8, \u05de\u05e2\u05d1\u05e8 \u05dc\u05d4\u05d9\u05d5\u05ea\u05d5 \u05d0\u05d5\u05e1\u05e3 \u05ea\u05e4\u05d9\u05dc\u05d5\u05ea, \u05d4\u05d5\u05d0 \u05d2\u05dd \u05e1\u05d5\u05d2 \u05e9\u05dc \u05de\u05d5\u05e8\u05d4 \u05d3\u05e8\u05da \u2013 \u05de\u05e2\u05d9\u05df \u05d3\u05de\u05d9\u05d5\u05df \u05de\u05d5\u05d3\u05e8\u05da. \u05d4\u05d5\u05d0 \u05de\u05e9\u05de\u05e9 \u05db\u05dc\u05d9 \u05dc\u05e2\u05d9\u05e6\u05d5\u05d1 \u05d4\u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05d5\u05d4\u05db\u05d5\u05d5\u05e0\u05ea\u05df.\n\u05db\u05d3\u05d9 \u05dc\u05d4\u05d3\u05e8\u05d9\u05da \u05d0\u05ea \u05de\u05d7\u05e9\u05d1\u05d5\u05ea\u05d9\u05e0\u05d5 \u05d1\u05e6\u05d5\u05e8\u05d4 \u05d9\u05e2\u05d9\u05dc\u05d4, \u05e2\u05dc\u05d9\u05e0\u05d5 \u05dc\u05d3\u05de\u05d9\u05d9\u05df \u05d1\u05e2\u05d5\u05e6\u05de\u05d4 \u05d0\u05ea \u05d4\u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05e9\u05d0\u05e0\u05d5 \u05e9\u05d5\u05d0\u05e4\u05d9\u05dd \u05dc\u05d4\u05d8\u05de\u05d9\u05e2 \u05d1\u05ea\u05d5\u05db\u05e0\u05d5: \u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05d7\u05d9\u05d5\u05d1\u05d9\u05d5\u05ea \u05e9\u05de\u05d7\u05d6\u05e7\u05d5\u05ea \u05d0\u05ea \u05e2\u05d5\u05dc\u05dd \u05d4\u05e2\u05e8\u05db\u05d9\u05dd \u05d5\u05d4\u05e2\u05e9\u05d9\u05d9\u05d4 \u05e9\u05dc\u05e0\u05d5. \u05d0\u05d7\u05e8\u05ea, \u05d4\u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05e0\u05d5\u05d8\u05d5\u05ea \u05dc\u05e0\u05d3\u05d5\u05d3 \u05dc\u05db\u05d9\u05d5\u05d5\u05e0\u05d9\u05dd \u05dc\u05d0 \u05e8\u05e6\u05d5\u05d9\u05d9\u05dd.\n\u05dc\u05de\u05e8\u05d5\u05ea \u05d6\u05d0\u05ea, \u05d9\u05e9\u05e0\u05dd \u05d0\u05e0\u05e9\u05d9\u05dd \u05d0\u05e9\u05e8 \u05d1\u05d0\u05d5\u05e4\u05df \u05d8\u05d1\u05e2\u05d9, \u05d0\u05d5 \u05d1\u05d6\u05db\u05d5\u05ea \u05e9\u05e2\u05d5\u05ea \u05e8\u05d1\u05d5\u05ea \u05e9\u05dc \u05ea\u05e8\u05d2\u05d5\u05dc \u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4, \u05de\u05e6\u05dc\u05d9\u05d7\u05d9\u05dd \u05dc\u05e9\u05dc\u05d5\u05d8 \u05d1\u05de\u05d7\u05e9\u05d1\u05d5\u05ea\u05d9\u05d4\u05dd. \u05de\u05ea\u05d5\u05da \u05e0\u05d9\u05e1\u05d9\u05d5\u05e0\u05d9 \u05d4\u05d0\u05d9\u05e9\u05d9, \u05d4\u05d9\u05d5 \u05ea\u05e7\u05d5\u05e4\u05d5\u05ea \u05d1\u05d7\u05d9\u05d9 \u05e9\u05d1\u05d4\u05df \u05e9\u05dc\u05d9\u05d8\u05d4 \u05d1\u05de\u05d7\u05e9\u05d1\u05d5\u05ea\u05d9\u05d9 \u05d1\u05d0\u05d4 \u05d1\u05d0\u05d5\u05e4\u05df \u05d8\u05d1\u05e2\u05d9 \u05d9\u05d5\u05ea\u05e8 \u2013 \u05d0\u05da \u05d0\u05d9\u05e0\u05d9 \u05d9\u05db\u05d5\u05dc\u05d4 \u05dc\u05d4\u05ea\u05e2\u05dc\u05dd \u05de\u05d4\u05d4\u05e9\u05e4\u05e2\u05d4 \u05d4\u05de\u05e9\u05de\u05e2\u05d5\u05ea\u05d9\u05ea \u05e9\u05dc \u05e9\u05e2\u05d5\u05ea \u05d4\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05e9\u05d4\u05e7\u05d3\u05e9\u05ea\u05d9 \u05dc\u05e2\u05e6\u05de\u05d9.\n\u05db\u05e9\u05d4\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d0\u05d9\u05e0\u05d4 \u05e0\u05d5\u05db\u05d7\u05ea \u05d1\u05d7\u05d9\u05d9\u05e0\u05d5, \u05d4\u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05e2\u05dc\u05d5\u05dc\u05d5\u05ea \u05dc\u05d4\u05e4\u05d5\u05da \u05dc\u05de\u05d1\u05d5\u05dc\u05d1\u05dc\u05d5\u05ea, \u05de\u05e4\u05d5\u05d6\u05e8\u05d5\u05ea \u05d5\u05dc\u05e2\u05d9\u05ea\u05d9\u05dd \u05dc\u05d0 \u05d9\u05e2\u05d9\u05dc\u05d5\u05ea. \u05d6\u05d4\u05d5 \u05de\u05e2\u05d2\u05dc \u05e7\u05e1\u05de\u05d9\u05dd: \u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05de\u05e4\u05d5\u05d6\u05e8\u05d5\u05ea \u05de\u05e7\u05e9\u05d5\u05ea \u05e2\u05dc \u05d4\u05d7\u05d6\u05e8\u05d4 \u05dc\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d0\u05d9\u05db\u05d5\u05ea\u05d9\u05ea, \u05e9\u05de\u05e1\u05d5\u05d2\u05dc\u05ea \u05dc\u05e2\u05e6\u05d1 \u05de\u05d7\u05d3\u05e9 \u05d0\u05ea \u05d4\u05ea\u05d5\u05d3\u05e2\u05d4 \u05d5\u05d0\u05ea \u05ea\u05d7\u05d5\u05e9\u05ea \u05d4\u05d9\u05e6\u05d9\u05d1\u05d5\u05ea \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05ea.\n\u05d1\u05e1\u05e4\u05e8 \u05d6\u05d4 \u05d0\u05e1\u05e7\u05e8 \u05d8\u05db\u05e0\u05d9\u05e7\u05d5\u05ea \u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05e9\u05d0\u05e1\u05e4\u05ea\u05d9 \u05de\u05e8\u05d1\u05d5\u05ea\u05d9\u05d9 \u05d5\u05de\u05ea\u05d5\u05da \u05d0\u05e8\u05d5\u05df \u05d4\u05e1\u05e4\u05e8\u05d9\u05dd \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9, \u05d5\u05d0\u05e9\u05ea\u05e3 \u05d2\u05dd \u05d1\u05e0\u05d9\u05e1\u05d9\u05d5\u05e0\u05d9 \u05d4\u05d0\u05d9\u05e9\u05d9 \u05d5\u05ea\u05d5\u05d1\u05e0\u05d5\u05ea\u05d9\u05d9. \u05dc\u05d4\u05e4\u05ea\u05e2\u05ea\u05d9, \u05d2\u05d9\u05dc\u05d9\u05ea\u05d9 \u05e2\u05dd \u05d4\u05e9\u05e0\u05d9\u05dd \u05e9\u05e8\u05d1\u05d5\u05ea \u05de\u05d4\u05ea\u05d5\u05d1\u05e0\u05d5\u05ea \u05e9\u05d4\u05d2\u05e2\u05ea\u05d9 \u05d0\u05dc\u05d9\u05d4\u05df \u05d1\u05e6\u05d5\u05e8\u05d4 \u05d0\u05d9\u05e0\u05d8\u05d5\u05d0\u05d9\u05d8\u05d9\u05d1\u05d9\u05ea \u05d4\u05d9\u05d5 \u05dc\u05de\u05e2\u05e9\u05d4 \u05db\u05ea\u05d5\u05d1\u05d5\u05ea \u05d1\u05e1\u05e4\u05e8\u05d9 \u05d4\u05e7\u05d5\u05d3\u05e9 \u05e9\u05dc\u05e0\u05d5.\n\u05d4\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9\u05ea \u05d4\u05d9\u05d0 \u05ea\u05d4\u05dc\u05d9\u05da \u05e2\u05de\u05d5\u05e7 \u05e9\u05dc \u05d4\u05ea\u05d7\u05d1\u05e8\u05d5\u05ea \u05dc\u05ea\u05d5\u05d3\u05e2\u05d4 \u05d7\u05d9\u05d5\u05d1\u05d9\u05ea \u05d5\u05dc\u05e2\u05e8\u05db\u05d9\u05dd \u05d9\u05d4\u05d5\u05d3\u05d9\u05d9\u05dd, \u05d5\u05d4\u05d9\u05d0 \u05de\u05d6\u05de\u05d9\u05e0\u05d4 \u05d0\u05d5\u05ea\u05e0\u05d5 \u05dc\u05d2\u05dc\u05d5\u05ea \u05de\u05d7\u05d3\u05e9 \u05d0\u05ea \u05db\u05d5\u05d7\u05dd \u05d4\u05de\u05e8\u05e4\u05d0 \u05e9\u05dc \u05d4\u05de\u05d9\u05dc\u05d9\u05dd \u05d5\u05e9\u05dc \u05d4\u05d3\u05de\u05d9\u05d5\u05df \u05d4\u05de\u05d5\u05d3\u05e8\u05da \u05d4\u05d8\u05de\u05d5\u05df \u05d1\u05ea\u05e4\u05d9\u05dc\u05d4.\n\u05dc\u05e9\u05e0\u05d5\u05ea \u05d0\u05ea \u05d4\u05de\u05d7\u05e9\u05d1\u05d4, \u05dc\u05d0 \u05dc\u05d4\u05e9\u05ea\u05d9\u05e7 \u05d0\u05d5\u05ea\u05d4\n\u05d4\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9\u05ea \u05e9\u05d5\u05e0\u05d4 \u05d1\u05de\u05d4\u05d5\u05ea\u05d4 \u05de\u05d2\u05d9\u05e9\u05d5\u05ea \u05e8\u05d1\u05d5\u05ea \u05dc\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4.\n\u05d1\u05e2\u05d5\u05d3 \u05e9\u05d2\u05d9\u05e9\u05d5\u05ea \u05d0\u05d7\u05e8\u05d5\u05ea \u05de\u05ea\u05de\u05e7\u05d3\u05d5\u05ea \u05d1\u05d4\u05e8\u05d2\u05e2\u05ea \u05d4\u05e8\u05d2\u05e9\u05d5\u05ea \u05e2\u05dc \u05d9\u05d3\u05d9 \u05d4\u05e9\u05ea\u05e7\u05ea \u05d4\u05de\u05d7\u05e9\u05d1\u05d5\u05ea, \u05de\u05d8\u05e8\u05ea\u05d4 \u05e9\u05dc \u05d4\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9\u05ea \u05d4\u05d9\u05d0 \u05dc\u05e9\u05e0\u05d5\u05ea \u05d0\u05ea \u05d4\u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05d5\u05dc\u05d0 \u05dc\u05d4\u05e9\u05ea\u05d9\u05e7\u05df.\n\u05d1\u05d9\u05d4\u05d3\u05d5\u05ea, \u05e7\u05d9\u05d9\u05dd \u05de\u05d5\u05e9\u05d2 \u05e2\u05ea\u05d9\u05e7 \u05d5\u05e2\u05de\u05d5\u05e7 \u2013 "\u05de\u05d5\u05d7 \u05e9\u05dc\u05d9\u05d8 \u05e2\u05dc \u05d4\u05dc\u05d1". \u05e8\u05e2\u05d9\u05d5\u05df \u05d6\u05d4 \u05e7\u05d9\u05d1\u05dc \u05d7\u05d9\u05d6\u05d5\u05e7 \u05d2\u05dd \u05d1\u05d2\u05d9\u05e9\u05d5\u05ea \u05de\u05d5\u05d3\u05e8\u05e0\u05d9\u05d5\u05ea \u05d1\u05e4\u05e1\u05d9\u05db\u05d5\u05dc\u05d5\u05d2\u05d9\u05d4, \u05d4\u05de\u05d3\u05d2\u05d9\u05e9\u05d5\u05ea \u05db\u05d9 \u05d4\u05e8\u05d2\u05e9 \u05e6\u05e8\u05d9\u05da \u05dc\u05d4\u05d9\u05d5\u05ea \u05de\u05d5\u05e0\u05d7\u05d4 \u05e2\u05dc \u05d9\u05d3\u05d9 \u05d4\u05e9\u05db\u05dc \u05d5\u05dc\u05d0 \u05dc\u05d4\u05e4\u05da. \u05db\u05dc\u05d5\u05de\u05e8, \u05d0\u05d9\u05df \u05dc\u05ea\u05ea \u05dc\u05e8\u05d2\u05e9\u05d5\u05ea \u05dc\u05e0\u05d4\u05dc \u05d0\u05ea \u05d7\u05d9\u05d9\u05e0\u05d5. \u05d1\u05de\u05e7\u05d5\u05dd \u05d6\u05d0\u05ea, \u05e2\u05dc\u05d9\u05e0\u05d5 \u05dc\u05d4\u05e0\u05d7\u05d5\u05ea \u05d0\u05ea \u05e8\u05d2\u05e9\u05d5\u05ea\u05d9\u05e0\u05d5 \u05dc\u05e2\u05d1\u05e8 \u05ea\u05d7\u05d5\u05e9\u05d5\u05ea \u05d7\u05d9\u05d5\u05d1\u05d9\u05d5\u05ea, \u05d3\u05e8\u05da \u05d4\u05e4\u05e2\u05dc\u05ea \u05db\u05d5\u05d7\u05d5\u05ea \u05d4\u05d7\u05e9\u05d9\u05d1\u05d4.\n\u05d1\u05d0\u05de\u05e6\u05e2\u05d5\u05ea \u05d7\u05e9\u05d9\u05d1\u05d4 \u05d7\u05d9\u05d5\u05d1\u05d9\u05ea \u05d0\u05e4\u05e9\u05e8:\n\u05dc\u05e6\u05d0\u05ea \u05de\u05ea\u05d7\u05d5\u05e9\u05ea \u05e7\u05d5\u05e8\u05d1\u05e0\u05d5\u05ea \u05d0\u05dc \u05d2\u05d0\u05d5\u05dc\u05d4 \u05e8\u05d2\u05e9\u05d9\u05ea.\n\u05dc\u05d4\u05de\u05d9\u05e8 \u05db\u05e2\u05e1 \u05dc\u05e9\u05dc\u05d9\u05d8\u05d4 \u05d1\u05db\u05e2\u05e1.\n\u05dc\u05d4\u05ea\u05de\u05d5\u05d3\u05d3 \u05e2\u05dd \u05d7\u05e8\u05d3\u05d4 \u05e2\u05dc \u05d9\u05d3\u05d9 \u05d4\u05d1\u05e0\u05d4 \u05e9\u05d4\u05d0\u05d9\u05d5\u05dd \u05dc\u05d0 \u05e7\u05d9\u05d9\u05dd, \u05d4\u05e1\u05ea\u05d9\u05d9\u05dd, \u05d0\u05d5 \u05e7\u05d8\u05df \u05de\u05db\u05e4\u05d9 \u05e9\u05d3\u05de\u05d9\u05d9\u05e0\u05d5.\n\u05d0\u05d9\u05dc\u05d5 \u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05d0\u05e0\u05d5 \u05e8\u05d5\u05e6\u05d9\u05dd \u05dc\u05d4\u05d8\u05de\u05d9\u05e2?\n\u05d4\u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05e9\u05d0\u05e0\u05d5 \u05de\u05d1\u05e7\u05e9\u05d9\u05dd \u05dc\u05d4\u05d8\u05de\u05d9\u05e2 \u05d1\u05ea\u05d5\u05db\u05e0\u05d5 \u05d4\u05df \u05d0\u05de\u05d5\u05e0\u05d5\u05ea \u05d7\u05d9\u05d5\u05d1\u05d9\u05d5\u05ea. \u05d1\u05d0\u05d5\u05e4\u05df \u05d8\u05d1\u05e2\u05d9, \u05d0\u05e0\u05d7\u05e0\u05d5 \u05e0\u05d5\u05d8\u05d9\u05dd \u05dc\u05d1\u05e8\u05d5\u05d7 \u05dc\u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05e9\u05dc\u05d9\u05dc\u05d9\u05d5\u05ea \u2013 \u05ea\u05d7\u05d5\u05e9\u05ea \u05e7\u05d5\u05e8\u05d1\u05df, \u05d7\u05d5\u05e1\u05e8 \u05e9\u05dc\u05d9\u05d8\u05d4, \u05d0\u05d5 \u05e9\u05dc\u05d9\u05d8\u05ea \u05d9\u05ea\u05e8. \u05dc\u05e2\u05d9\u05ea\u05d9\u05dd \u05d0\u05e0\u05d5 \u05e0\u05e1\u05d7\u05e4\u05d9\u05dd \u05dc\u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05d3\u05d9\u05db\u05d0\u05d5\u05e0\u05d9\u05d5\u05ea \u05d0\u05d5 \u05de\u05d0\u05e0\u05d9\u05d5\u05ea. \u05d4\u05e1\u05d9\u05d3\u05d5\u05e8 \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9 \u05de\u05e9\u05de\u05e9 \u05db\u05dc\u05d9 \u05e8\u05d1-\u05e2\u05d5\u05e6\u05de\u05d4 \u05e9\u05de\u05d0\u05e4\u05e9\u05e8 \u05dc\u05e0\u05d5 \u05dc\u05d1\u05d7\u05d5\u05df \u05d0\u05ea \u05d4\u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05d4\u05dc\u05dc\u05d5 \u05d5\u05dc\u05d0\u05e8\u05d2\u05df \u05d0\u05ea \u05de\u05e2\u05e8\u05db\u05ea \u05d4\u05e2\u05e8\u05db\u05d9\u05dd \u05e9\u05dc\u05e0\u05d5.\n\u05d3\u05e8\u05da \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d5\u05d4\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4, \u05d0\u05e0\u05d5 \u05e9\u05d5\u05d0\u05e4\u05d9\u05dd \u05dc\u05d4\u05d2\u05d9\u05e2 \u05dc\u05e2\u05de\u05d3\u05d4 \u05de\u05d0\u05d5\u05d6\u05e0\u05ea:\n\u05e2\u05e0\u05d5\u05d5\u05d4 \u05dc\u05e6\u05d3 \u05d0\u05e1\u05e8\u05d8\u05d9\u05d1\u05d9\u05d5\u05ea.\n\u05d4\u05d1\u05e0\u05d4 \u05e9\u05d0\u05e0\u05d5 \u05d2\u05d3\u05d5\u05dc\u05d9\u05dd, \u05d1\u05db\u05da \u05e9\u05d9\u05e9 \u05dc\u05e0\u05d5 \u05d9\u05db\u05d5\u05dc\u05ea \u05dc\u05e9\u05dc\u05d5\u05d8 \u05d1\u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05d5\u05d1\u05e8\u05d2\u05e9\u05d5\u05ea \u05e9\u05dc\u05e0\u05d5.\n\u05d4\u05db\u05e8\u05d4 \u05e9\u05d0\u05e0\u05d5 \u05e7\u05d8\u05e0\u05d9\u05dd \u05de\u05e1\u05e4\u05d9\u05e7 \u05db\u05d3\u05d9 \u05dc\u05d4\u05d9\u05e9\u05d0\u05e8 \u05e6\u05e0\u05d5\u05e2\u05d9\u05dd, \u05e4\u05ea\u05d5\u05d7\u05d9\u05dd \u05dc\u05dc\u05de\u05d9\u05d3\u05d4 \u05d5\u05d4\u05ea\u05e4\u05ea\u05d7\u05d5\u05ea \u05e8\u05d2\u05e9\u05d9\u05ea.\n\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d6\u05d5 \u05de\u05dc\u05de\u05d3\u05ea \u05d0\u05d5\u05ea\u05e0\u05d5 \u05dc\u05d4\u05e4\u05e0\u05d9\u05dd \u05e9\u05d2\u05dd \u05d1\u05de\u05e6\u05d9\u05d0\u05d5\u05ea \u05d4\u05e7\u05e9\u05d4 \u05d1\u05d9\u05d5\u05ea\u05e8 \u05d8\u05de\u05d5\u05df \u05d2\u05e8\u05e2\u05d9\u05df \u05d7\u05d9\u05d5\u05d1\u05d9, \u05d2\u05dd \u05d0\u05dd \u05d0\u05d9\u05e0\u05e0\u05d5 \u05e8\u05d5\u05d0\u05d9\u05dd \u05d0\u05d5\u05ea\u05d5 \u05de\u05d9\u05d3.\n\u05db\u05dc\u05d9\u05dd \u05de\u05e2\u05e9\u05d9\u05d9\u05dd \u05dc\u05e9\u05d9\u05e0\u05d5\u05d9 \u05de\u05d7\u05e9\u05d1\u05ea\u05d9\n\u05d4\u05d8\u05e7\u05e1\u05d8\u05d9\u05dd \u05e9\u05dc \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05de\u05e9\u05de\u05e9\u05d9\u05dd \u05dc\u05e0\u05d5 \u05db\u05d3\u05de\u05d9\u05d5\u05df \u05de\u05d5\u05d3\u05e8\u05da \u2013 \u05de\u05e0\u05d8\u05e8\u05d5\u05ea \u05e9\u05d9\u05db\u05d5\u05dc\u05d5\u05ea \u05dc\u05e1\u05d9\u05d9\u05e2 \u05d1\u05d4\u05ea\u05de\u05d5\u05d3\u05d3\u05d5\u05ea \u05e2\u05dd \u05e8\u05d2\u05e2\u05d9\u05dd \u05e7\u05e9\u05d9\u05dd.\n\u05d1\u05e1\u05e4\u05e8 \u05d6\u05d4, \u05e0\u05e6\u05dc\u05d5\u05dc \u05d0\u05dc \u05de\u05d9\u05dc\u05d5\u05ea \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d5\u05e4\u05e1\u05d5\u05e7\u05d9 \u05ea\u05d4\u05d9\u05dc\u05d9\u05dd, \u05db\u05d3\u05d9:\n\u05dc\u05d1\u05d7\u05d5\u05df \u05d0\u05ea \u05de\u05e6\u05d1\u05e0\u05d5 \u05d4\u05e0\u05e4\u05e9\u05d9.\n\u05dc\u05d2\u05d1\u05e9 \u05ea\u05d5\u05d1\u05e0\u05d5\u05ea \u05d1\u05e8\u05d9\u05d0\u05d5\u05ea \u05d5\u05de\u05e2\u05e6\u05d9\u05de\u05d5\u05ea \u05e2\u05dc \u05d4\u05d7\u05d9\u05d9\u05dd.\n\u05e9\u05dd \u05d4\u05e9\u05dd: \u05e9\u05e2\u05e8 \u05dc\u05ea\u05d5\u05d1\u05e0\u05d4 \u05e2\u05de\u05d5\u05e7\u05d4\n\u05d4\u05e1\u05e4\u05e8 \u05de\u05ea\u05d7\u05d9\u05dc \u05d1\u05e0\u05d9\u05ea\u05d5\u05d7 \u05e9\u05dc \u05e9\u05dd \u05d4\u05e9\u05dd \u2013 \u05d9-\u05d4-\u05d5-\u05d4.\n\u05d2\u05dd \u05d0\u05dd \u05d0\u05ea\u05dd \u05de\u05d0\u05de\u05d9\u05e0\u05d9\u05dd \u05d1\u05d0\u05dc\u05d5\u05e7\u05d9\u05dd \u05d5\u05d2\u05dd \u05d0\u05dd \u05dc\u05d0, \u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea \u05d1\u05e9\u05dd \u05d6\u05d4 \u05e2\u05e9\u05d5\u05d9\u05d4 \u05dc\u05e4\u05ea\u05d5\u05d7 \u05d1\u05e4\u05e0\u05d9\u05db\u05dd \u05d3\u05e8\u05da \u05d7\u05d3\u05e9\u05d4 \u05dc\u05d4\u05ea\u05de\u05d5\u05d3\u05d3 \u05e2\u05dd \u05e7\u05e9\u05d9\u05d9\u05dd. \u05d4\u05e9\u05dd \u05de\u05e1\u05de\u05dc \u05d0\u05d9\u05e0\u05e1\u05d5\u05e4\u05d9\u05d5\u05ea \u05d5\u05d7\u05d9\u05d1\u05d5\u05e8 \u05dc\u05e2\u05d5\u05e6\u05de\u05d4 \u05e9\u05de\u05e2\u05d1\u05e8 \u05dc\u05e0\u05d5, \u05e9\u05de\u05de\u05e0\u05d4 \u05e0\u05d9\u05ea\u05df \u05dc\u05e9\u05d0\u05d5\u05d1 \u05db\u05d5\u05d7, \u05d1\u05d4\u05d9\u05e8\u05d5\u05ea \u05d5\u05e9\u05dc\u05d5\u05d5\u05d4.\n\u05d6\u05d4\u05d5 \u05de\u05e1\u05e2 \u05e9\u05dc \u05e9\u05d9\u05e0\u05d5\u05d9, \u05e9\u05d1\u05d5 \u05e0\u05dc\u05de\u05d3 \u05dc\u05d0 \u05e8\u05e7 \u05dc\u05d4\u05e1\u05ea\u05db\u05dc \u05e4\u05e0\u05d9\u05de\u05d4, \u05d0\u05dc\u05d0 \u05d2\u05dd \u05dc\u05d0\u05e8\u05d2\u05df \u05de\u05d7\u05d3\u05e9 \u05d0\u05ea \u05de\u05d7\u05e9\u05d1\u05d5\u05ea\u05d9\u05e0\u05d5, \u05e8\u05d2\u05e9\u05d5\u05ea\u05d9\u05e0\u05d5 \u05d5\u05e2\u05de\u05d3\u05d5\u05ea\u05d9\u05e0\u05d5 \u05db\u05dc\u05e4\u05d9 \u05d4\u05e2\u05d5\u05dc\u05dd.\n\u05d9-\u05d4-\u05d5-\u05d4: \u05d7\u05d9\u05d1\u05d5\u05e8 \u05dc\u05d7\u05d9\u05d9\u05dd, \u05ea\u05d5\u05d3\u05e2\u05d4 \u05d5\u05e7\u05d3\u05d5\u05e9\u05d4\n\u05db\u05d9\u05e6\u05d3 \u05de\u05d5\u05e1\u05d9\u05e4\u05d9\u05dd \u05d7\u05d9\u05d5\u05ea \u05d5\u05d4\u05d1\u05e0\u05d4 \u05dc\u05de\u05e6\u05d9\u05d0\u05d5\u05ea \u05d7\u05d9\u05d9\u05e0\u05d5 \u05d5\u05de\u05d0\u05e8\u05d2\u05e0\u05d9\u05dd \u05d0\u05ea \u05d4\u05de\u05d7\u05e9\u05d1\u05d5\u05ea?\n\u05d3\u05e8\u05da \u05d7\u05d9\u05d1\u05d5\u05e8 \u05dc\u05d4\u05d5\u05d5\u05d9\u05d4 \u05d1\u05d0\u05de\u05e6\u05e2\u05d5\u05ea \u05d4\u05e0\u05e9\u05d9\u05de\u05d4. \u05d1\u05de\u05d5\u05d1\u05df \u05d4\u05e2\u05de\u05d5\u05e7, \u05d4\u05de\u05d9\u05dc\u05d4 "\u05d4\u05d5\u05d5\u05d9\u05d4" \u05d1\u05d9\u05d4\u05d3\u05d5\u05ea \u05e7\u05e9\u05d5\u05e8\u05d4 \u05d2\u05dd \u05dc\u05d7\u05d5\u05d5\u05d9\u05d4. \u05e9\u05dd \u05d4\u05e9\u05dd, \u05d4\u05e0\u05db\u05ea\u05d1 \u05d1\u05d3\u05e8\u05da \u05db\u05dc\u05dc \u05db"\u05d9-\u05d4-\u05d5-\u05d4", \u05de\u05d2\u05dc\u05dd \u05d0\u05ea \u05d4\u05de\u05d9\u05dc\u05d9\u05dd \u05d4\u05d5\u05d5\u05d9\u05d4, \u05d4\u05d9\u05d4, \u05d4\u05d5\u05d5\u05d4 \u05d5\u05d9\u05d4\u05d9\u05d4. \u05d4\u05de\u05d9\u05dc\u05d4 "\u05d4\u05d5\u05d5\u05d4" \u05de\u05ea\u05d7\u05d1\u05e8\u05ea \u05d1\u05de\u05d9\u05d5\u05d7\u05d3 \u05dc\u05de\u05d9\u05dc\u05d4 "\u05d4\u05d5\u05d5\u05d9\u05d4" \u2013 \u05d4\u05d9\u05d0 \u05de\u05e1\u05de\u05dc\u05ea \u05d0\u05ea \u05d4\u05ea\u05d4\u05d5\u05d5\u05ea \u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea, \u05d0\u05ea \u05d4\u05e7\u05d9\u05d5\u05dd \u05d5\u05d4\u05d7\u05d9\u05d5\u05ea, \u05d0\u05ea \u05d4\u05d4\u05d5\u05d5\u05d4 \u05d0\u05da \u05d2\u05dd \u05d0\u05ea \u05de\u05d4\u05d5\u05ea \u05d4\u05d7\u05d9\u05d9\u05dd \u05e2\u05e6\u05de\u05dd.\n\u05db\u05d0\u05e9\u05e8 \u05d0\u05e0\u05d5 \u05d7\u05d5\u05e9\u05d1\u05d9\u05dd \u05e2\u05dc \u05e7\u05d9\u05d5\u05de\u05e0\u05d5, \u05d0\u05e0\u05d5 \u05de\u05db\u05d9\u05e8\u05d9\u05dd \u05d1\u05db\u05da \u05e9\u05d0\u05e0\u05d5 \u05dc\u05d0 \u05e8\u05e7 \u05d2\u05d5\u05e3 \u05d0\u05dc\u05d0 \u05d2\u05dd \u05e0\u05e9\u05de\u05d4. \u05d0\u05e0\u05d5 \u05de\u05ea\u05d7\u05d1\u05e8\u05d9\u05dd \u05dc\u05e0\u05e9\u05de\u05ea\u05e0\u05d5, \u05dc\u05e9\u05d5\u05e8\u05e9 \u05e7\u05d9\u05d5\u05de\u05e0\u05d5. \u05d1\u05db\u05da, \u05d0\u05e0\u05d5 \u05de\u05d7\u05d1\u05e8\u05d9\u05dd \u05d0\u05ea \u05d4\u05e2\u05d1\u05e8, \u05d4\u05d4\u05d5\u05d5\u05d4 \u05d5\u05d4\u05e2\u05ea\u05d9\u05d3 \u05e9\u05dc\u05e0\u05d5, \u05db\u05e4\u05d9 \u05e9\u05de\u05e8\u05de\u05d6\u05ea \u05d4\u05de\u05d9\u05dc\u05d4 \u05d9-\u05d4-\u05d5-\u05d4 \u2013 \u05d4\u05db\u05dc\u05dc\u05d4 \u05e9\u05dc \u05d4\u05d9\u05d4, \u05d4\u05d5\u05d5\u05d4 \u05d5\u05d9\u05d4\u05d9\u05d4.\n\u05d4\u05d0\u05d5\u05e8 \u05e9\u05d1\u05e0\u05e9\u05d9\u05de\u05d4\n\u05de\u05e2\u05e0\u05d9\u05d9\u05df \u05dc\u05e6\u05d9\u05d9\u05df \u05db\u05d9 \u05d4\u05d0\u05d5\u05ea\u05d9\u05d5\u05ea \u05d9-\u05d4-\u05d5-\u05d4 \u05d4\u05df \u05d4\u05d1\u05e1\u05d9\u05e1 \u05dc\u05d0 \u05e8\u05e7 \u05d1\u05d4\u05d1\u05e8\u05d5\u05ea \u05d5\u05d1\u05e0\u05e9\u05d9\u05de\u05d4, \u05d0\u05dc\u05d0 \u05d2\u05dd \u05d1\u05de\u05e0\u05d8\u05e8\u05d5\u05ea \u05d5\u05d1\u05ea\u05e4\u05d9\u05dc\u05d4 \u05e9\u05dc \u05de\u05e1\u05d5\u05e8\u05d5\u05ea \u05e2\u05ea\u05d9\u05e7\u05d5\u05ea \u05e8\u05d1\u05d5\u05ea, \u05dc\u05d0 \u05e8\u05e7 \u05d1\u05d9\u05d4\u05d3\u05d5\u05ea. \u05d4\u05e0\u05e9\u05d9\u05de\u05d4, \u05db\u05d0\u05de\u05e6\u05e2\u05d9 \u05dc\u05d7\u05d9\u05d1\u05d5\u05e8 \u05e4\u05e0\u05d9\u05de\u05d9, \u05de\u05ea\u05d0\u05d7\u05d3\u05ea \u05e2\u05dd \u05d4\u05d0\u05d5\u05ea\u05d9\u05d5\u05ea \u05d4\u05d0\u05dc\u05d5, \u05db\u05da \u05e9\u05d0\u05e0\u05d5 \u05e0\u05d5\u05e9\u05de\u05d9\u05dd \u05d0\u05d5\u05ea\u05dd \u05dc\u05ea\u05d5\u05da \u05d4\u05de\u05d5\u05d3\u05e2\u05d5\u05ea \u05e9\u05dc\u05e0\u05d5.\n\u05d7\u05d9\u05d1\u05d5\u05e8 \u05dc\u05de\u05e6\u05d9\u05d0\u05d5\u05ea \u05de\u05ea\u05d5\u05da \u05d4\u05db\u05e8\u05d4 \u05d0\u05dc\u05d5\u05e7\u05d9\u05ea\n\u05db\u05d0\u05e9\u05e8 \u05d0\u05e0\u05d5 \u05d0\u05d5\u05de\u05e8\u05d9\u05dd \u05d0\u05ea \u05d4\u05de\u05d9\u05dc\u05d4 \u05d9-\u05d4-\u05d5-\u05d4, \u05d0\u05e0\u05d5 \u05d9\u05db\u05d5\u05dc\u05d9\u05dd \u05dc\u05d4\u05ea\u05d7\u05d1\u05e8 \u05d0\u05dc \u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea \u05de\u05ea\u05d5\u05da \u05d4\u05db\u05e8\u05d4 \u05d1\u05db\u05da \u05e9\u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea \u05db\u05d5\u05dc\u05d4 \u05de\u05d1\u05e8\u05db\u05ea \u05d5\u05d8\u05d5\u05d1\u05d4. \u05d2\u05dd \u05d0\u05dd \u05d1\u05e8\u05d2\u05e2 \u05d6\u05d4 \u05d0\u05d9\u05e0\u05e0\u05d5 \u05e8\u05d5\u05d0\u05d9\u05dd \u05d0\u05ea \u05d4\u05d8\u05d5\u05d1, \u05e2\u05dc\u05d9\u05e0\u05d5 \u05dc\u05d6\u05db\u05d5\u05e8 \u05db\u05d9 \u05d4\u05d7\u05db\u05de\u05d4 \u05d4\u05e2\u05dc\u05d9\u05d5\u05e0\u05d4 \u05e8\u05d5\u05d0\u05d4 \u05d0\u05ea \u05db\u05dc \u05d4\u05d6\u05de\u05df \u2013 \u05d4\u05e2\u05d1\u05e8, \u05d4\u05d4\u05d5\u05d5\u05d4 \u05d5\u05d4\u05e2\u05ea\u05d9\u05d3 \u2013 \u05db\u05d9\u05d7\u05d9\u05d3\u05d4 \u05d0\u05d7\u05ea. \u05d9\u05d5\u05dd \u05d0\u05d7\u05d3, \u05d2\u05dd \u05d0\u05e0\u05d5 \u05e0\u05d5\u05db\u05dc \u05dc\u05e8\u05d0\u05d5\u05ea \u05d0\u05ea \u05d4\u05d8\u05d5\u05d1 \u05e9\u05e6\u05d5\u05de\u05d7 \u05de\u05ea\u05d5\u05da \u05d4\u05db\u05d0\u05d1 \u05d1\u05d4\u05d5\u05d5\u05d4, \u05db\u05e4\u05d9 \u05e9\u05dc\u05e2\u05ea\u05d9\u05dd \u05e7\u05e8\u05d5\u05d1\u05d5\u05ea \u05d0\u05e0\u05d5 \u05de\u05d1\u05d9\u05e0\u05d9\u05dd \u05d0\u05ea \u05d4\u05ea\u05d5\u05d1\u05e0\u05d4 \u05e9\u05d4\u05d2\u05d9\u05e2\u05d4 \u05dc\u05d7\u05d9\u05d9\u05e0\u05d5 \u05de\u05db\u05d0\u05d1 \u05d4\u05e2\u05d1\u05e8.\n\u05d4\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9\u05ea\n\u05dc\u05e2\u05d5\u05de\u05ea \u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d5\u05ea \u05d0\u05d7\u05e8\u05d5\u05ea \u05d4\u05e0\u05d5\u05ea\u05e0\u05d5\u05ea \u05de\u05e7\u05d5\u05dd \u05dc\u05d7\u05e9\u05d9\u05d1\u05d4 \u05d7\u05e4\u05e9\u05d9\u05ea \u05d0\u05d5 \u05e0\u05d9\u05e7\u05d5\u05d9 \u05d5\u05e8\u05d9\u05e7\u05d5\u05df \u05d4\u05d7\u05e9\u05d9\u05d1\u05d4 \u05db\u05de\u05ea\u05db\u05d5\u05df \u05dc\u05e9\u05dc\u05d5\u05d5\u05d4, \u05d4\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9\u05ea \u05d3\u05e8\u05da \u05d4\u05e1\u05d9\u05d3\u05d5\u05e8 \u05d5\u05db\u05dc \u05de\u05d9\u05dc\u05d4 \u05d1\u05ea\u05e4\u05d9\u05dc\u05d4, \u05d0\u05d5 \u05d1\u05ea\u05d4\u05d9\u05dc\u05d9\u05dd \u05d0\u05d5 \u05d1\u05ea\u05d5\u05e8\u05d4 \u05de\u05db\u05d5\u05d5\u05e0\u05ea \u05d0\u05d5\u05ea\u05e0\u05d5 \u05dc\u05d1\u05d3\u05d5\u05e7 \u05d0\u05ea \u05d4\u05de\u05e7\u05d5\u05dd \u05d4\u05ea\u05d5\u05d3\u05e2\u05ea\u05d9 \u05d1\u05d5 \u05d0\u05e0\u05d5 \u05e0\u05de\u05e6\u05d0\u05d9\u05dd \u05d5\u05dc\u05db\u05d5\u05d5\u05df \u05d0\u05ea \u05d4\u05de\u05d5\u05d3\u05e2\u05d5\u05ea \u05dc\u05ea\u05d5\u05d3\u05e2\u05d4 \u05d7\u05d9\u05d5\u05d1\u05d9.  \u05dc\u05e9\u05ea\u05d5\u05dc \u05d1\u05e0\u05d5 \u05ea\u05d5\u05d3\u05e2\u05d4 \u05d7\u05d3\u05e9\u05d4, \u05d7\u05d9\u05d5\u05d1\u05d9\u05ea \u05d5\u05de\u05d7\u05d1\u05e8\u05ea. \u05db\u05dc \u05de\u05d9\u05dc\u05d4 \u05d4\u05d5\u05e4\u05db\u05ea \u05dc\u05d4\u05d9\u05d5\u05ea \u05db\u05dc\u05d9 \u05dc\u05e2\u05d1\u05d5\u05d3\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea, \u05d5\u05d4\u05e0\u05e9\u05d9\u05de\u05d4 \u05de\u05e9\u05de\u05e9\u05ea \u05db\u05d2\u05e9\u05e8 \u05e9\u05de\u05d7\u05d1\u05e8 \u05d0\u05ea \u05d4\u05d2\u05d5\u05e3 \u05dc\u05e0\u05e4\u05e9, \u05d0\u05d5\u05ea\u05e0\u05d5 \u05dc\u05e2\u05d5\u05de\u05e7 \u05d4\u05d7\u05d9\u05d9\u05dd \u05d5\u05dc\u05e7\u05d9\u05d5\u05de\u05e0\u05d5 \u05d4\u05de\u05e9\u05d5\u05dc\u05d1 \u05e2\u05dd \u05d0\u05dc\u05d5\u05d4\u05d5\u05ea, \u05d7\u05db\u05de\u05d4 \u05d5\u05d4\u05d5\u05d5\u05d9\u05d4 \u05d0\u05d9\u05e0\u05e1\u05d5\u05e4\u05d9\u05ea. \u05db\u05d0\u05e9\u05e8 \u05d0\u05e0\u05d5 \u05e0\u05d5\u05e9\u05de\u05d9\u05dd \u05d1\u05db\u05dc \u05de\u05d9\u05dc\u05d4 \u05d5\u05e8\u05d5\u05d0\u05d9\u05dd \u05db\u05d9\u05e6\u05d3 \u05d4\u05e9\u05e0\u05d9\u05de\u05d4 \u05e9\u05dc\u05e0\u05d5 \u05de\u05e9\u05ea\u05e0\u05d4 \u05de\u05de\u05d9\u05dc\u05d4 \u05dc\u05de\u05d9\u05dc\u05d4 \u05de\u05de\u05e9\u05e4\u05d8  \u05dc\u05de\u05e9\u05e4\u05d8 \u05d6\u05d4 \u05d2\u05d5\u05e8\u05dd \u05dc\u05e0\u05d5 \u05dc\u05d4\u05e8\u05d2\u05d9\u05e9 \u05d3\u05e8\u05da \u05d4\u05d2\u05d5\u05e3 \u05d4\u05d9\u05db\u05df \u05d0\u05e0\u05d5 \u05d0\u05d5\u05d7\u05d6\u05d9\u05dd \u05e8\u05d2\u05e9\u05d9\u05ea. \u05d0\u05dd \u05d4\u05e9\u05e0\u05d9\u05de\u05d4 \u05e9\u05dc\u05d9 \u05d0\u05d5\u05e0\u05e2\u05e9\u05d9\u05ea \u05db\u05d1\u05d3\u05d4 \u05d9\u05d5\u05ea\u05e8 \u05d0\u05d5\u05dc\u05d9 \u05d0\u05e0\u05d9 \u05dc\u05d0 \u05de\u05ea\u05d7\u05d1\u05e8\u05ea \u05d0\u05dc \u05d4\u05de\u05d9\u05d9\u05dc\u05dd \u05d4\u05d0\u05dc\u05d5 \u05db\u05e8\u05d2\u05e2, \u05d6\u05d4 \u05d9\u05d2\u05e8\u05d5\u05dd \u05dc\u05d9 \u05dc\u05e2\u05e6\u05d5\u05e8 \u05dc\u05e0\u05e9\u05d5\u05dd \u05e2\u05dd \u05d4\u05de\u05d9\u05dc\u05d9\u05dd \u05d4\u05d0\u05dc\u05d5 \u05e2\u05d5\u05df\u05d3, \u05dc\u05d7\u05e9\u05d5\u05d1 \u05e2\u05dc\u05d9\u05d4\u05df. \u05de\u05d4 \u05d4\u05dd\u05df \u05e2\u05d5\u05e9\u05d5\u05ea \u05dc\u05d9, \u05d4\u05d9\u05db\u05df \u05d4\u05df \u05e0\u05d5\u05d2\u05e2\u05d5\u05ea \u05d1\u05d9. \u05d0\u05d9\u05d6\u05d4 \u05e8\u05d2\u05e9 \u05d4\u05df \u05de\u05e6\u05d9\u05e4\u05d5\u05ea \u05d1\u05d9 \u05d5\u05de\u05d4 \u05d0\u05e0\u05d9 \u05e8\u05d5\u05e6\u05d4 \u05dc\u05e9\u05e0\u05d5\u05ea \u05db\u05d3\u05d9 \u05dc\u05d4\u05e8\u05d2\u05d9\u05e9 \u05d0\u05d7\u05e8\u05ea. \u05d4\u05d0\u05dd \u05d0\u05e0\u05d9 \u05e8\u05d5\u05e6\u05d4 \u05dc\u05d9\u05e6\u05d5\u05e8 \u05e7\u05e9\u05e8 \u05e2\u05dd \u05de\u05d9\u05e9\u05d4\u05d5 \u05db\u05d3\u05d9 \u05dc\u05d1\u05e7\u05e9 \u05e1\u05dc\u05d9\u05d7\u05d4. \u05d0\u05d5 \u05d4\u05d4\u05e4\u05da \u05d0\u05e0\u05d9 \u05de\u05e8\u05d2\u05d9\u05e9\u05d4 \u05e9\u05e0\u05e2\u05e9\u05d4 \u05dc\u05d9 \u05d7\u05d5\u05e1\u05e8 \u05e6\u05d3\u05e7. \u05d5\u05db\u05df \u05d4\u05dc\u05d0\u05d4. \u05d0\u05dd \u05d0\u05e0\u05d9 \u05d0\u05d5\u05de\u05e8\u05ea \u05d4\u05e9\u05dc\u05da \u05d9\u05d4\u05d1\u05da \u05d0\u05dc \u05d4\u05e9\u05dd \u05d5\u05d4\u05d5\u05d0 \u05d9\u05db\u05dc\u05db\u05dc\u05da \u05d0\u05e0\u05d9 \u05d1\u05d5\u05d3\u05e7\u05ea \u05e2\u05dd \u05e2\u05e6\u05de\u05d9 \u05d4\u05d0\u05dd\u05e4 \u05d0\u05e0\u05d9 \u05d1\u05e8\u05de\u05ea \u05d7\u05d9\u05d4 \u05d0\u05ea \u05d4\u05d7\u05d9\u05d9\u05dd \u05d4\u05db\u05dc\u05db\u05dc\u05d9\u05d9\u05dd \u05e9\u05dc\u05d9 \u05d1\u05ea\u05d7\u05d5\u05e9\u05d4 \u05d4\u05d2\u05e0\u05d4 \u05d1\u05e6\u05dc \u05d4\u05e9\u05dd. \u05d0\u05d5 \u05e9\u05d0\u05e0\u05d9 \u05e8\u05d5\u05e6\u05d4 / \u05e6\u05e8\u05d9\u05db\u05d4 \u05dc\u05d7\u05d6\u05e7 \u05d0\u05ea \u05ea\u05d7\u05d5\u05e9\u05ea \u05d4\u05d1\u05d9\u05d8\u05d7\u05d5\u05df \u05d1\u05e6\u05d3 \u05d4\u05db\u05dc\u05db\u05dc\u05d9. \u05d0\u05d5 \u05d4\u05d1\u05e8\u05d9\u05d0\u05d5\u05ea\u05d9, \u05d4\u05de\u05e9\u05e4\u05d7\u05ea\u05d9 \u05d5\u05db\u05df \u05d4\u05dc\u05d0\u05d4. \u05d0\u05d9\u05d6\u05d5 \u05e2\u05d1\u05d5\u05d3\u05d4 \u05ea\u05d5\u05d3\u05e2\u05ea\u05d9\u05ea \u05d7\u05e1\u05e8\u05d4 \u05dc\u05d9 \u05d5\u05db\u05de\u05d4 \u05e2\u05d1\u05d5\u05d3\u05d3\u05d4 \u05e4\u05e8\u05e7\u05d8\u05d9\u05ea \u05d7\u05e1\u05e8\u05d4 \u05dc\u05d9. \u05e9\u05dc \u05dc\u05d4\u05e8\u05d9\u05dd \u05d8\u05dc\u05e4\u05d5\u05df \u05dc\u05de\u05d9\u05e9\u05d4\u05d5 \u05d0\u05d5 \u05dc\u05d4\u05e9\u05ea\u05d3\u05dc \u05d9\u05d5\u05ea\u05e8.\n\u05db\u05de\u05d5 \u05e9\u05e1\u05d9\u05e4\u05e8 \u05d4\u05e2\u05dc \u05e9\u05dd \u05d8\u05d5\u05d1 \u05e4\u05e2\u05dd \u05d0\u05d7\u05ea \u05d4\u05d5\u05d0\n\u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea \u05d1\u05de\u05d9\u05dc\u05d4 "\u05d0\u05d5\u05d5\u05d9\u05e8"\n\u05d4\u05de\u05d9\u05dc\u05d4 \u05d0\u05d5\u05d5\u05d9\u05e8 \u05de\u05d5\u05e8\u05db\u05d1\u05ea \u05de\u05d4\u05de\u05d9\u05dc\u05d4 \u05d0\u05d5\u05e8 \u05d5\u05d4\u05d0\u05d5\u05ea \u05d9, \u05e9\u05d4\u05d9\u05d0 \u05e1\u05de\u05dc \u05dc\u05d8\u05d5\u05d1 \u05d4\u05e0\u05e6\u05d7\u05d9 \u05d5\u05dc\u05d7\u05db\u05de\u05d4 \u05d4\u05e2\u05dc\u05d9\u05d5\u05e0\u05d4 \u2013 \u05d1\u05e7\u05d9\u05e6\u05d5\u05e8, \u05d4\u05d0\u05dc\u05d5\u05e7\u05d5\u05ea. \u05db\u05d0\u05e9\u05e8 \u05d0\u05e0\u05d5 \u05e0\u05d5\u05e9\u05de\u05d9\u05dd \u05d0\u05d5\u05d5\u05d9\u05e8 \u05d1\u05e0\u05e9\u05d9\u05de\u05d4 \u05de\u05d5\u05d3\u05e2\u05ea, \u05de\u05d1\u05dc\u05d9 \u05dc\u05d4\u05d9\u05d5\u05ea \u05de\u05d5\u05d3\u05e2\u05d9\u05dd \u05dc\u05de\u05e9\u05de\u05e2\u05d5\u05ea \u05d4\u05e2\u05de\u05d5\u05e7\u05d4 \u05e9\u05dc \u05d4\u05de\u05d9\u05dc\u05d4, \u05d0\u05e0\u05d5 \u05e2\u05d3\u05d9\u05d9\u05df \u05de\u05d1\u05e6\u05e2\u05d9\u05dd \u05e4\u05e2\u05d5\u05dc\u05d4 \u05d7\u05e9\u05d5\u05d1\u05d4 \u05e9\u05de\u05e1\u05d9\u05d9\u05e2\u05ea \u05dc\u05d0\u05d9\u05d6\u05d5\u05df \u05d4\u05d4\u05d5\u05e8\u05de\u05d5\u05e0\u05dc\u05d9 \u05e9\u05dc\u05e0\u05d5. \u05d0\u05da \u05db\u05d0\u05e9\u05e8 \u05d0\u05e0\u05d5 \u05e0\u05d5\u05e9\u05de\u05d9\u05dd \u05e0\u05e9\u05d9\u05de\u05d4 \u05de\u05d5\u05d3\u05e2\u05ea, \u05ea\u05d5\u05da \u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea \u05d1\u05de\u05d9\u05dc\u05d4 "\u05d0\u05d5\u05d5\u05d9\u05e8", \u05d0\u05e0\u05d5 \u05de\u05e7\u05d9\u05e4\u05d9\u05dd \u05d0\u05ea \u05e2\u05e6\u05de\u05e0\u05d5 \u05d1\u05d0\u05d5\u05e8 \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9 \u05d5\u05de\u05d6\u05de\u05d9\u05e0\u05d9\u05dd \u05d0\u05ea \u05d4\u05d0\u05d5\u05e8 \u05d4\u05d6\u05d4 \u05dc\u05d4\u05d9\u05db\u05e0\u05e1 \u05dc\u05ea\u05d5\u05da \u05db\u05dc \u05ea\u05d0 \u05d1\u05d2\u05d5\u05e4\u05e0\u05d5 \u2013 \u05d1\u05de\u05d9\u05d5\u05d7\u05d3 \u05dc\u05d0\u05d6\u05d5\u05e8\u05d9\u05dd \u05d4\u05db\u05d5\u05d0\u05d1\u05d9\u05dd, \u05d2\u05d5\u05e4\u05e0\u05d9\u05d9\u05dd \u05d0\u05d5 \u05e0\u05e4\u05e9\u05d9\u05d9\u05dd.\n\u05d4\u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea \u05d1\u05d0\u05d5\u05e8 \u05de\u05e1\u05d1\u05d9\u05d1\u05e0\u05d5 \u05d5\u05d1\u05d0\u05d5\u05e8 \u05d4\u05e0\u05db\u05e0\u05e1 \u05dc\u05ea\u05d5\u05db\u05e0\u05d5 \u05e0\u05d5\u05d1\u05e2\u05ea \u05de\u05d4\u05d4\u05d1\u05e0\u05d4 \u05d4\u05e7\u05d1\u05dc\u05d9\u05ea \u05e9\u05dc \u05d0\u05d5\u05e8 \u05de\u05e7\u05d9\u05e3 \u05d5\u05d0\u05d5\u05e8 \u05e4\u05e0\u05d9\u05de\u05d9 \u2013 \u05d4\u05d0\u05d5\u05e8 \u05d4\u05de\u05e7\u05d9\u05e3 \u05d4\u05d5\u05d0 \u05de\u05d4 \u05e9\u05e0\u05de\u05e6\u05d0 \u05de\u05d7\u05d5\u05e5 \u05dc\u05e0\u05d5, \u05d5\u05d0\u05d9\u05dc\u05d5 \u05d4\u05d0\u05d5\u05e8 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9 \u05d4\u05d5\u05d0 \u05de\u05d4 \u05e9\u05d7\u05d5\u05d3\u05e8 \u05e4\u05e0\u05d9\u05de\u05d4 \u05d5\u05de\u05e9\u05e4\u05d9\u05e2 \u05e2\u05dc\u05d9\u05e0\u05d5 \u05d1\u05d0\u05d5\u05e4\u05df \u05e2\u05de\u05d5\u05e7.',"\u05ea\u05e8\u05d2\u05d5\u05dc \u05d6\u05d4 \u05de\u05d7\u05d1\u05e8 \u05d0\u05d5\u05ea\u05e0\u05d5 \u05dc\u05d0\u05d5\u05e8 \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9 \u05d5\u05de\u05d6\u05de\u05d9\u05df \u05d0\u05ea \u05d4\u05e9\u05e4\u05e2 \u05d5\u05d4\u05d0\u05d9\u05d6\u05d5\u05df \u05dc\u05d4\u05d9\u05db\u05e0\u05e1 \u05dc\u05ea\u05d5\u05da \u05d2\u05d5\u05e4\u05e0\u05d5, \u05ea\u05d5\u05da \u05e9\u05de\u05d9\u05e8\u05d4 \u05e2\u05dc \u05ea\u05d5\u05d3\u05e2\u05d4 \u05d2\u05d1\u05d5\u05d4\u05d4 \u05e9\u05de\u05d6\u05d9\u05e0\u05d4 \u05d0\u05ea \u05d4\u05e0\u05e9\u05de\u05d4 \u05d5\u05d4\u05d2\u05d5\u05e3 \u05db\u05d0\u05d7\u05d3.",'\u05e9\u05d0\u05e4\u05d5 \u05d3\u05e8\u05da \u05d4\u05d0\u05e3 \u05e2\u05dd \u05e4\u05d4 \u05e1\u05d2\u05d5\u05e8, \u05e2\u05d3 \u05dc\u05de\u05dc\u05d0\u05ea \u05d4\u05e8\u05d9\u05d0\u05d5\u05ea \u05d5\u05d4\u05d1\u05d8\u05df, \u05e2\u05d3 \u05e9\u05d4\u05d1\u05d8\u05df \u05de\u05e8\u05d2\u05d9\u05e9\u05d4 \u05db\u05de\u05d5 \u05d1\u05dc\u05d5\u05df \u05e2\u05e0\u05e7.\n\u05d3\u05de\u05d9\u05d9\u05e0\u05d5 \u05d0\u05d5\u05e8 \u05d2\u05d3\u05d5\u05dc \u05d4\u05de\u05e7\u05d9\u05e3 \u05d0\u05ea\u05db\u05dd \u05d5\u05ea\u05d7\u05d9\u05dc\u05d5 \u05dc\u05d4\u05e8\u05d2\u05d9\u05e9 \u05db\u05d9\u05e6\u05d3 \u05d4\u05d5\u05d0 \u05de\u05ea\u05d7\u05d9\u05dc \u05dc\u05d7\u05d3\u05d5\u05e8 \u05dc\u05ea\u05d5\u05da \u05d2\u05d5\u05e4\u05db\u05dd \u05d3\u05e8\u05da \u05d4\u05de\u05e7\u05d5\u05dd \u05e9\u05dc \u05d4\u05e2\u05d9\u05df \u05d4\u05e9\u05dc\u05d9\u05e9\u05d9\u05ea, \u05de\u05e2\u05dc \u05d4\u05d2\u05d1\u05d5\u05ea, \u05d1\u05de\u05e8\u05db\u05d6 \u05d4\u05de\u05e6\u05d7.\n\u05d7\u05e9\u05d1\u05d5 \u05e2\u05dc \u05d4\u05de\u05d9\u05dc\u05d9\u05dd "\u05d0\u05d5\u05e8 \u05d0\u05dc\u05d5\u05e7\u05d9" \u05d5\u05d1\u05e7\u05e9\u05d5 \u05de\u05d4\u05d0\u05d5\u05e8 \u05d4\u05e0\u05e6\u05d7\u05d9 \u05d5\u05d4\u05d8\u05d5\u05d1 \u05d4\u05e0\u05e6\u05d7\u05d9 \u05dc\u05d1\u05d5\u05d0 \u05d0\u05dc\u05d9\u05db\u05dd.\n\u05d4\u05d7\u05d6\u05d9\u05e7\u05d5 \u05d0\u05ea \u05d4\u05d0\u05d5\u05d5\u05d9\u05e8 \u05db\u05db\u05dc \u05d4\u05d0\u05e4\u05e9\u05e8, \u05de\u05d1\u05dc\u05d9 \u05dc\u05e0\u05e9\u05d5\u05e3 \u05d7\u05d6\u05e7 \u05d4\u05d7\u05d5\u05e6\u05d4.\n\u05db\u05d0\u05e9\u05e8 \u05d0\u05ea\u05dd \u05de\u05e8\u05d2\u05d9\u05e9\u05d9\u05dd \u05d0\u05ea \u05d2\u05d1\u05d5\u05dc \u05d4\u05d9\u05db\u05d5\u05dc\u05ea \u05de\u05ea\u05e7\u05e8\u05d1, \u05d4\u05ea\u05d7\u05d9\u05dc\u05d5 \u05dc\u05e0\u05e9\u05d5\u05e3 \u05d3\u05e8\u05da \u05d7\u05e8\u05d9\u05e5 \u05e7\u05d8\u05df \u05d1\u05e9\u05e4\u05ea\u05d9\u05d9\u05dd, \u05d1\u05d0\u05d5\u05e4\u05df \u05d0\u05d9\u05d8\u05d9 \u05d5\u05de\u05d1\u05d5\u05e7\u05e8.\n\u05db\u05dc \u05d4\u05e0\u05e9\u05de\u05d4 \u05ea\u05d4\u05dc\u05dc \u05d9-\u05d4\n\u05d0\u05e4\u05e9\u05e8 \u05dc\u05d7\u05e9\u05d5\u05d1 \u05e2\u05dc \u05db\u05dc \u05d4\u05e0\u05e9\u05de\u05d4 \u05e9\u05dc\u05d9, \u05dc\u05d4\u05e8\u05d2\u05d9\u05e9 \u05d0\u05ea \u05d4\u05dc\u05d1 \u05de\u05ea\u05de\u05dc\u05d0 \u05d1\u05d4\u05db\u05e8\u05ea \u05d4\u05d8\u05d5\u05d1 \u05d1\u05d7\u05d9\u05d9\u05dd. \u05d0\u05d5 \u05dc\u05d7\u05e9\u05d5\u05d1 \u05e2\u05dc \u05db\u05dc \u05d4\u05e0\u05e9\u05de\u05d5\u05ea \u05e9\u05dc \u05d4\u05e2\u05d5\u05dc\u05dd. \u05db\u05dc\u05d5\u05de\u05e8 \u05d1\u05e6\u05d5\u05e8\u05d4 \u05de\u05e1\u05d5\u05d9\u05d9\u05de\u05ea \u05d0\u05e0\u05d5 \u05de\u05d1\u05e8\u05db\u05d9\u05dd \u05d0\u05ea \u05d4\u05e7\u05d1"\u05d4 \u05d5\u05d4\u05d1\u05e8\u05d9\u05d0\u05d4 \u05e9\u05db\u05d5\u05dc\u05dd \u05d9\u05d4\u05d9\u05d5 \u05d1\u05e2\u05dc\u05d9 \u05d4\u05db\u05e8\u05ea \u05d4\u05d8\u05d5\u05d1 \u05d5\u05d9\u05d5\u05d3\u05d5 \u05e2\u05dc \u05d4\u05d8\u05d5\u05d1.\n\u05d1\u05e4\u05e1\u05d5\u05e7 "\u05db\u05dc \u05d4\u05e0\u05e9\u05de\u05d4 \u05ea\u05d4\u05dc\u05dc \u05d9\u05d4" (\u05ea\u05d4\u05d9\u05dc\u05d9\u05dd, \u05e7\u05d9"\u05d5) \u05d0\u05e0\u05d5 \u05d9\u05db\u05d5\u05dc\u05d9\u05dd \u05dc\u05d4\u05d1\u05d9\u05df \u05db\u05d9\u05e6\u05d3 \u05db\u05dc \u05d4\u05e0\u05e9\u05de\u05d4 - \u05d4\u05de\u05d4\u05d5\u05ea \u05e9\u05dc\u05d9, \u05db\u05dc \u05db\u05d5\u05d7\u05d5\u05ea \u05d4\u05ea\u05d5\u05d3\u05e2\u05d4 \u05de\u05d4\u05dc\u05dc\u05d9\u05dd \u05d0\u05ea \u05e7\u05d9\u05d5\u05dd \u05d4\u05d7\u05d9\u05d9\u05dd \u05e2\u05e6\u05de\u05dd \u05d5\u05d0\u05ea \u05db\u05dc \u05d4\u05d1\u05e8\u05d9\u05d0\u05d4.\n\u05d3\u05e8\u05da \u05d4\u05ea\u05db\u05dc\u05dc\u05d5\u05ea \u05d4\u05e0\u05e9\u05d9\u05de\u05d4. \u05db\u05dc\u05d5\u05de\u05e8, \u05d4\u05e8\u05d7\u05d1\u05ea \u05d4\u05e0\u05e9\u05d9\u05de\u05d4 \u05de\u05d0\u05e4\u05e9\u05e8\u05ea \u05dc\u05d4\u05dc\u05dc \u05d0\u05ea \u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea, \u05d0\u05ea \u05e9\u05dd \u05d4\', \u05d0\u05ea \u05d4\u05d1\u05d5\u05e8\u05d0, \u05d5\u05dc\u05d7\u05d1\u05e8 \u05d0\u05ea \u05e2\u05e6\u05de\u05e0\u05d5 \u05dc\u05d0\u05d5\u05e8 \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9 \u05e9\u05d1\u05e0\u05d5 \u05d5\u05d1\u05d9\u05e7\u05d5\u05dd. \u05e0\u05e9\u05d9\u05de\u05d4 \u05d4\u05d9\u05d0 \u05d2\u05dd \u05d0\u05d5\u05ea\u05d9\u05d5\u05ea \u05e0\u05e9\u05de\u05d4 \u05e2\u05dd \u05d4\u05d0\u05d5\u05ea \u05d9, \u05e9\u05d4\u05d9\u05d0 \u05e1\u05de\u05dc \u05dc\u05e9\u05d5\u05e8\u05e9 \u05e7\u05d9\u05d5\u05dd \u05d4\u05e2\u05d5\u05dc\u05dd, \u05dc\u05d0\u05dc\u05d5\u05d4\u05d9\u05dd \u05d0\u05d5 \u05dc\u05e9\u05db\u05d9\u05e0\u05d4.\n\u05d4\u05e8\u05d1\u05d4 \u05d0\u05e0\u05e9\u05d9\u05dd \u05d7\u05d5\u05d5\u05d9\u05dd \u05e7\u05d5\u05e9\u05d9 \u05dc\u05d4\u05ea\u05d7\u05d1\u05e8 \u05dc\u05d0\u05dc\u05d5\u05e7\u05d5\u05ea, \u05d1\u05de\u05d9\u05d5\u05d7\u05d3 \u05db\u05d0\u05e9\u05e8 \u05de\u05d3\u05d5\u05d1\u05e8 \u05d1\u05d4\u05d1\u05e0\u05d4 \u05e9\u05dc \u05d4\u05d1\u05d5\u05e8\u05d0 \u05db\u05d6\u05db\u05e8 \u05d0\u05d5 \u05e0\u05e7\u05d1\u05d4. \u05e7\u05d5\u05e9\u05d9 \u05d6\u05d4 \u05e2\u05e9\u05d5\u05d9 \u05dc\u05e0\u05d1\u05d5\u05e2 \u05de\u05de\u05e1\u05e4\u05e8 \u05d2\u05d5\u05e8\u05de\u05d9\u05dd, \u05d5\u05dc\u05e2\u05d9\u05ea\u05d9\u05dd \u05de\u05d5\u05e0\u05e2 \u05de\u05d4\u05dd \u05dc\u05e0\u05e1\u05d5\u05ea \u05dc\u05d4\u05ea\u05d7\u05d1\u05e8 \u05d0\u05dc \u05d4\u05d1\u05d5\u05e8\u05d0 \u05d1\u05e6\u05d5\u05e8\u05d4 \u05e1\u05de\u05e0\u05d8\u05d9\u05ea \u05d0\u05d5 \u05ea\u05e4\u05d9\u05e1\u05ea\u05d9\u05ea. \u05e2\u05dc\u05d9\u05e0\u05d5 \u05dc\u05d4\u05d1\u05d9\u05df \u05db\u05d9 \u05d1\u05ea\u05d5\u05db\u05e0\u05d5 \u05e7\u05d9\u05d9\u05de\u05ea \u05de\u05d4\u05d5\u05ea \u05d2\u05d1\u05e8\u05d9\u05ea \u05d5\u05e0\u05e9\u05d9\u05ea, \u05e9\u05d0\u05d9\u05e0\u05d4 \u05ea\u05dc\u05d5\u05d9\u05d4 \u05d1\u05de\u05e8\u05d0\u05d4 \u05d4\u05e4\u05d9\u05d6\u05d9 \u05e9\u05dc\u05e0\u05d5. \u05d2\u05d1\u05e8\u05d9\u05dd \u05d9\u05db\u05d5\u05dc\u05d9\u05dd \u05dc\u05d4\u05e8\u05d2\u05d9\u05e9 \u05e0\u05e9\u05d9\u05d9\u05dd \u05d9\u05d5\u05ea\u05e8, \u05d5\u05e0\u05e9\u05d9\u05dd \u05d9\u05db\u05d5\u05dc\u05d5\u05ea \u05dc\u05d4\u05ea\u05d7\u05d1\u05e8 \u05dc\u05de\u05d0\u05e4\u05d9\u05d9\u05e0\u05d9\u05dd \u05d2\u05d1\u05e8\u05d9\u05d9\u05dd. \u05d1\u05e0\u05d5\u05e1\u05e3, \u05d4\u05ea\u05e9\u05d5\u05de\u05d5\u05ea \u05d4\u05e8\u05d2\u05e9\u05d9\u05d5\u05ea \u05d5\u05d4\u05e0\u05e4\u05e9\u05d9\u05d5\u05ea \u05e9\u05dc \u05d4\u05d0\u05d3\u05dd \u05e7\u05e9\u05d5\u05e8\u05d5\u05ea \u05dc\u05d0\u05e8\u05d1\u05e2\u05ea \u05de\u05de\u05d3\u05d9 \u05d4\u05e0\u05e4\u05e9, \u05db\u05e4\u05d9 \u05e9\u05de\u05d5\u05e4\u05d9\u05e2 \u05d1\u05d9\u05d4\u05d3\u05d5\u05ea \u2013 \u05e0\u05e4\u05e9, \u05e8\u05d5\u05d7, \u05e0\u05e9\u05de\u05d4, \u05d7\u05d9\u05d4 \u05d5\u05d9\u05d7\u05d9\u05d3\u05d4. \u05e8\u05d5\u05d1\u05e0\u05d5 \u05e0\u05d5\u05d8\u05d9\u05dd \u05dc\u05d4\u05e1\u05ea\u05e4\u05e7 \u05d1\u05e0\u05d9\u05ea\u05d5\u05d7 \u05d4\u05d7\u05d9\u05d9\u05dd \u05dc\u05e4\u05d9 \u05d3\u05e8\u05d2\u05ea \u05d4\u05e0\u05e4\u05e9, \u05e9\u05d4\u05d9\u05d0 \u05d4\u05e9\u05dc\u05d1 \u05d4\u05e9\u05d8\u05d7\u05d9 \u05d1\u05d9\u05d5\u05ea\u05e8, \u05d4\u05e7\u05e9\u05d5\u05e8 \u05dc\u05d7\u05d5\u05d5\u05d9\u05d5\u05ea \u05d2\u05d5\u05e4\u05e0\u05d9\u05d5\u05ea. \u05d0\u05da \u05d0\u05e0\u05d7\u05e0\u05d5 \u05d9\u05db\u05d5\u05dc\u05d9\u05dd \u05dc\u05d4\u05d2\u05d9\u05e2 \u05dc\u05d3\u05e8\u05d2\u05ea \u05d4\u05d9\u05d7\u05d9\u05d3\u05d4, \u05d1\u05d4 \u05de\u05e6\u05d5\u05d9\u05d9\u05dd \u05d4\u05ea\u05e9\u05d5\u05d1\u05d5\u05ea \u05d4\u05e2\u05de\u05d5\u05e7\u05d5\u05ea \u05d1\u05d9\u05d5\u05ea\u05e8 \u05dc\u05e9\u05d0\u05dc\u05d5\u05ea \u05d4\u05e0\u05e4\u05e9 \u05d5\u05d4\u05d7\u05d9\u05d9\u05dd.\n\u05d4\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05de\u05d0\u05e4\u05e9\u05e8\u05ea \u05dc\u05e0\u05d5 \u05dc\u05d4\u05d2\u05d9\u05e2 \u05d0\u05dc \u05d4\u05de\u05e7\u05d5\u05de\u05d5\u05ea \u05d4\u05d7\u05d1\u05d5\u05d9\u05d9\u05dd \u05d4\u05dc\u05dc\u05d5 \u05d1\u05ea\u05d5\u05db\u05e0\u05d5, \u05dc\u05dc\u05d0 \u05d4\u05e6\u05d5\u05e8\u05da \u05d1\u05d4\u05db\u05d5\u05d5\u05e0\u05d4 \u05de\u05e7\u05e6\u05d5\u05e2\u05d9\u05ea, \u05d5\u05dc\u05e2\u05d9\u05ea\u05d9\u05dd \u05d4\u05d9\u05d0 \u05d4\u05d3\u05e8\u05da \u05dc\u05d4\u05ea\u05de\u05d5\u05d3\u05d3 \u05e2\u05dd \u05d4\u05ea\u05d7\u05d1\u05d8\u05d5\u05d9\u05d5\u05ea \u05e4\u05e0\u05d9\u05de\u05d9\u05d5\u05ea. \u05db\u05d3\u05d9 \u05dc\u05d4\u05ea\u05d7\u05d1\u05e8 \u05dc\u05ea\u05d5\u05d3\u05e2\u05d4 \u05d4\u05d2\u05d1\u05d5\u05d4\u05d4 \u05e9\u05dc\u05e0\u05d5, \u05e0\u05ea\u05d7\u05d9\u05dc \u05d1\u05e0\u05e9\u05d9\u05de\u05d4 \u05de\u05d5\u05d3\u05e2\u05ea \u05e2\u05dd \u05e9\u05dd \u05d9-\u05d4-\u05d5-\u05d4, \u05d5\u05dc\u05d0\u05d7\u05e8 \u05de\u05db\u05df \u05e0\u05d5\u05db\u05dc \u05dc\u05d4\u05ea\u05d7\u05d1\u05e8 \u05dc\u05d1\u05e8\u05db\u05d5\u05ea \u05db\u05d0\u05dc \u05d3\u05d9\u05de\u05d5\u05d9 \u05de\u05d5\u05d3\u05e8\u05da \u05e9\u05de\u05d4\u05df \u05e0\u05e8\u05e6\u05d4 \u05dc\u05d4\u05d8\u05de\u05d9\u05e2 \u05d0\u05ea \u05d4\u05de\u05d4\u05d5\u05ea \u05dc\u05d7\u05d9\u05d9\u05e0\u05d5.\n"\u05de\u05d4 \u05e2\u05d5\u05e9\u05d9\u05dd \u05db\u05e9\u05d4\u05d7\u05d9\u05d9\u05dd \u05dc\u05d0 \u05d6\u05d5\u05d4\u05e8\u05d9\u05dd? \u05d4\u05ea\u05e9\u05d5\u05d1\u05d4 \u05de\u05e1\u05ea\u05ea\u05e8\u05ea \u05d1\u05e4\u05e1\u05d5\u05e7 \u05d0\u05d7\u05d3 \u05de\u05ea\u05d4\u05d9\u05dc\u05d9\u05dd"\n"\u05d4\u05b7\u05dc\u05b0\u05dc\u05d5\u05bc\u05d4\u05d5\u05bc \u05e9\u05c1\u05b6\u05de\u05b6\u05e9\u05c1 \u05d5\u05b0\u05d9\u05b8\u05e8\u05b5\u05d7\u05b7, \u05d4\u05b7\u05dc\u05b0\u05dc\u05d5\u05bc\u05d4\u05d5\u05bc \u05db\u05bc\u05b8\u05dc \u05db\u05bc\u05d5\u05b9\u05db\u05b0\u05d1\u05b5\u05d9 \u05d0\u05d5\u05b9\u05e8" (\u05ea\u05d4\u05dc\u05d9\u05dd \u05e7\u05de"\u05d7, \u05d2),\n\u05d0\u05e4\u05e9\u05e8 \u05dc\u05e8\u05d0\u05d5\u05ea \u05d0\u05ea \u05d4\u05e7\u05e8\u05d9\u05d0\u05d4 \u05dc\u05d4\u05dc\u05dc \u05d0\u05ea \u05d4\' \u05db\u05e7\u05e8\u05d9\u05d0\u05d4 \u05e7\u05d9\u05d5\u05de\u05d9\u05ea \u2014 \u05dc\u05d4\u05d6\u05d3\u05d4\u05d5\u05ea \u05e2\u05dd \u05e4\u05e2\u05d9\u05de\u05ea \u05d4\u05d4\u05d5\u05d3 \u05e9\u05d1\u05d1\u05e8\u05d9\u05d0\u05d4, \u05d1\u05db\u05dc \u05de\u05e6\u05d1 \u05d5\u05d1\u05db\u05dc \u05e2\u05d5\u05e0\u05d4 \u05e9\u05dc \u05d7\u05d9\u05d9\u05dd.\n\u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05d4\u05d7\u05d9\u05d9\u05dd \u05de\u05d0\u05d9\u05e8\u05d9\u05dd \u05db\u05e9\u05de\u05e9 \u2014 \u05d4\u05db\u05dc \u05d1\u05e8\u05d5\u05e8, \u05d7\u05de\u05d9\u05dd, \u05de\u05dc\u05d0 \u05d7\u05d9\u05d5\u05e0\u05d9\u05d5\u05ea.\n\u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05d4\u05dd \u05db\u05de\u05d5 \u05d9\u05e8\u05d7 \u2014 \u05e4\u05d7\u05d5\u05ea \u05e2\u05d5\u05e6\u05de\u05d4, \u05d9\u05d5\u05ea\u05e8 \u05e8\u05d5\u05da, \u05d4\u05e9\u05ea\u05e7\u05e4\u05d5\u05ea \u05e9\u05dc \u05d0\u05d5\u05e8 \u05de\u05de\u05e7\u05d5\u05e8 \u05d0\u05d7\u05e8.\n\u05d5\u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u2014 \u05e8\u05e7 \u05db\u05de\u05d5 \u05db\u05d5\u05db\u05d1\u05d9\u05dd: \u05e0\u05e7\u05d5\u05d3\u05d5\u05ea \u05e7\u05d8\u05e0\u05d5\u05ea \u05e9\u05dc \u05d0\u05d5\u05e8 \u05d1\u05ea\u05d5\u05da \u05e9\u05de\u05d9\u05d9\u05dd \u05d7\u05e9\u05d5\u05db\u05d9\u05dd, \u05e9\u05e6\u05e8\u05d9\u05da \u05dc\u05d4\u05ea\u05d0\u05de\u05e5 \u05db\u05d3\u05d9 \u05dc\u05e8\u05d0\u05d5\u05ea.\n\u05d0\u05d1\u05dc \u05d1\u05db\u05dc \u05d4\u05de\u05e6\u05d1\u05d9\u05dd \u05d4\u05dc\u05dc\u05d5 \u2014 \u05e7\u05e8\u05d9\u05d0\u05d4 \u05d0\u05d7\u05ea \u05de\u05d4\u05d3\u05d4\u05d3\u05ea: \'\u05d4\u05dc\u05dc\u05d5\u05d4\u05d5\'.\n\u05d2\u05dd \u05db\u05e9\u05d4\u05d0\u05d5\u05e8 \u05d2\u05d3\u05d5\u05dc \u05d5\u05d1\u05e8\u05d5\u05e8, \u05d5\u05d2\u05dd \u05db\u05e9\u05d4\u05d5\u05d0 \u05de\u05e8\u05d5\u05de\u05d6, \u05e9\u05d1\u05d5\u05e8 \u05d0\u05d5 \u05d7\u05d1\u05d5\u05d9.\n\u05d4\u05db\u05d5\u05db\u05d1\u05d9\u05dd, \u05db\u05de\u05d5 \u05d4\u05e9\u05de\u05e9 \u05d5\u05d4\u05d9\u05e8\u05d7, \u05de\u05d4\u05dc\u05dc\u05d9\u05dd \u2013 \u05dc\u05d0 \u05db\u05d9 \u05d4\u05dd \u05d2\u05d3\u05d5\u05dc\u05d9\u05dd \u05d0\u05d5 \u05e7\u05d8\u05e0\u05d9\u05dd, \u05d0\u05dc\u05d0 \u05db\u05d9 \u05d4\u05dd \u05de\u05d0\u05d9\u05e8\u05d9\u05dd \u05db\u05e4\u05d9 \u05e9\u05d4\u05dd.\n\u05db\u05da \u05d2\u05dd \u05d0\u05e0\u05d7\u05e0\u05d5 \u2014 \u05d4\u05d4\u05dc\u05dc \u05d0\u05d9\u05e0\u05d5 \u05ea\u05dc\u05d5\u05d9 \u05d1\u05e2\u05d5\u05e6\u05de\u05ea \u05d4\u05d0\u05d5\u05e8 \u05e9\u05de\u05d0\u05d9\u05e8 \u05e2\u05dc\u05d9\u05e0\u05d5 \u05d0\u05d5 \u05de\u05ea\u05d5\u05db\u05e0\u05d5, \u05d0\u05dc\u05d0 \u05d1\u05e0\u05db\u05d5\u05e0\u05d5\u05ea \u05dc\u05d4\u05d1\u05d7\u05d9\u05df \u05d1\u05d0\u05d5\u05e8, \u05d2\u05dd \u05db\u05e9\u05d4\u05d5\u05d0 \u05e2\u05d3\u05d9\u05df \u05d5\u05e8\u05d7\u05d5\u05e7, \u05d5\u05dc\u05d4\u05d5\u05d3\u05d5\u05ea \u05e2\u05dc\u05d9\u05d5.\n\u05d3\u05d5\u05d5\u05e7\u05d0 \u05db\u05e9\u05d0\u05e0\u05d7\u05e0\u05d5 \u05e9\u05d5\u05de\u05e8\u05d9\u05dd \u05e2\u05dc \u05dc\u05d1 \u05de\u05dc\u05d0 \u05d4\u05d5\u05d3\u05d9\u05d4 \u2014 \u05dc\u05d0 \u05e8\u05e7 \u05d1\u05d0\u05d5\u05e8 \u05d4\u05d2\u05d3\u05d5\u05dc, \u05d0\u05dc\u05d0 \u05d2\u05dd \u05d1\u05e0\u05d9\u05e6\u05d5\u05e6\u05d5\u05ea \u05d4\u05e7\u05d8\u05e0\u05d9\u05dd \u2014 \u05d0\u05e0\u05d7\u05e0\u05d5 \u05e0\u05e2\u05e9\u05d9\u05dd \u05d1\u05e2\u05e6\u05de\u05e0\u05d5 \u05d7\u05dc\u05e7 \u05de\u05ea\u05d6\u05de\u05d5\u05e8\u05ea \u05d4\u05d4\u05dc\u05dc \u05e9\u05dc \u05d4\u05d1\u05e8\u05d9\u05d0\u05d4.\n\u05d4\u05e0\u05d4 \u05d4\u05e6\u05e2\u05d4 \u05dc\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05e9\u05e7\u05d8\u05d4 \u05d5\u05d0\u05d9\u05d8\u05d9\u05ea, \u05d1\u05d4\u05e9\u05e8\u05d0\u05ea \u05d4\u05e8\u05e2\u05d9\u05d5\u05df \u05de\u05d4\u05e4\u05e1\u05d5\u05e7:\n\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d9\u05ea "\u05d4\u05dc\u05dc\u05d5\u05d4\u05d5 \u2014 \u05d1\u05d0\u05d5\u05e8 \u05d4\u05d2\u05d3\u05d5\u05dc \u05d5\u05d4\u05e7\u05d8\u05df"\n1. \u05d4\u05d9\u05db\u05e8\u05d5\u05ea \u05e2\u05dd \u05d4\u05de\u05e8\u05d7\u05d1 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\n\u05e2\u05e6\u05d5\u05dd \u05e2\u05d9\u05e0\u05d9\u05d9\u05dd. \u05e9\u05d9\u05dd \u05dc\u05d1 \u05dc\u05d2\u05d5\u05e3 \u05e9\u05dc\u05da. \u05d0\u05dc \u05d4\u05e0\u05e9\u05d9\u05de\u05d4.\n\u05d4\u05d0\u05dd \u05d9\u05e9 \u05d1\u05ea\u05d5\u05db\u05da \u05e9\u05de\u05e9? \u05d0\u05d5\u05e8 \u05d1\u05e8\u05d5\u05e8? \u05e9\u05de\u05d7\u05d4 \u05e4\u05e9\u05d5\u05d8\u05d4?\n\u05d0\u05dd \u05db\u05df \u2014 \u05d4\u05e0\u05d7 \u05dc\u05d6\u05d4 \u05dc\u05d4\u05d0\u05d9\u05e8. \u05d0\u05de\u05d5\u05e8 \u05d1\u05dc\u05d1\u05da: *"\u05d4\u05dc\u05dc\u05d5\u05d4\u05d5 \u05e9\u05de\u05e9."*\n\u05ea\u05df \u05dc\u05d4\u05d5\u05d3\u05d9\u05d4 \u05dc\u05e2\u05dc\u05d5\u05ea \u05de\u05ea\u05d5\u05db\u05da \u05db\u05de\u05d5 \u05e7\u05e8\u05df \u05d0\u05d5\u05e8 \u05d9\u05e9\u05e8\u05d4 \u05d5\u05d7\u05de\u05d4.\n2. \u05e4\u05d2\u05d9\u05e9\u05d4 \u05e2\u05dd \u05d0\u05d5\u05e8 \u05d4\u05d9\u05e8\u05d7\n\u05d0\u05dd \u05d0\u05ea\u05d4 \u05de\u05e8\u05d2\u05d9\u05e9 \u05d3\u05d5\u05d5\u05e7\u05d0 \u05e9\u05e7\u05d8, \u05e8\u05d5\u05da, \u05d0\u05d5\u05dc\u05d9 \u05d0\u05e4\u05d9\u05dc\u05d5 \u05e2\u05e6\u05d1 \u05e7\u05dc\n\u05d4\u05d9\u05e8\u05d7 \u05d0\u05d9\u05ea\u05da. \u05d4\u05d0\u05d5\u05e8 \u05e7\u05d9\u05d9\u05dd, \u05d0\u05d1\u05dc \u05d4\u05d5\u05d0 \u05dc\u05d0 \u05e9\u05dc\u05da. \u05d4\u05d5\u05d0 \u05de\u05d5\u05d7\u05d6\u05e8, \u05de\u05e8\u05d5\u05d7\u05e7.\n\u05d6\u05d4 \u05d1\u05e1\u05d3\u05e8.\n\u05d0\u05d5\u05dc\u05d9 \u05d0\u05ea\u05dd \u05dc\u05d0 \u05de\u05e6\u05dc\u05d9\u05d7\u05d9\u05dd \u05db\u05e8\u05d2\u05e2 \u05d5\u05dc\u05d0 \u05de\u05e8\u05d2\u05d9\u05e9\u05d9\u05dd \u05db\u05de\u05d5 \u05e9\u05de\u05e9 \u05de\u05d0\u05d9\u05e8\u05d4 \u05d0\u05d1\u05dc \u05d0\u05e4\u05e9\u05e8 \u05dc\u05d4\u05e9\u05ea\u05ea\u05e3 \u05d1\u05e9\u05de\u05d7\u05ea \u05d4\u05e6\u05dc\u05d7\u05ea \u05d4\u05d6\u05d5\u05dc\u05ea. \u05d4\u05e9\u05ea\u05e7\u05e4\u05d5\u05ea \u05d0\u05d5\u05e8 \u05d4\u05d7\u05d9\u05d9\u05dd \u05d1\u05d0\u05d7\u05e8\u05d9\u05dd. \u05d1\u05d9\u05dc\u05d3\u05d9\u05dd \u05e9\u05dc\u05db\u05dd, \u05d1\u05d1\u05e0\u05d9 \u05d4\u05d6\u05d5\u05d2 \u05d0\u05d5 \u05e9\u05d0\u05e8 \u05d4\u05e2\u05d5\u05dc\u05dd.\n\u05d0\u05de\u05d5\u05e8 \u05d1\u05dc\u05d1\u05da: "\u05d4\u05dc\u05dc\u05d5\u05d4\u05d5 \u05d9\u05e8\u05d7."\n\u05d2\u05dd \u05db\u05d0\u05df \u2014 \u05d9\u05e9 \u05d0\u05d5\u05e8. \u05d2\u05dd \u05d6\u05d4 \u05e8\u05d2\u05e2 \u05e9\u05dc \u05d4\u05dc\u05dc.\n3. \u05d4\u05db\u05e8\u05ea \u05d0\u05d5\u05e8 \u05d4\u05db\u05d5\u05db\u05d1\u05d9\u05dd\n\u05d0\u05d5\u05dc\u05d9 \u05e2\u05db\u05e9\u05d9\u05d5 \u05d7\u05e9\u05d5\u05da. \u05d0\u05d5\u05dc\u05d9 \u05d0\u05ea\u05d4 \u05de\u05ea\u05de\u05d5\u05d3\u05d3, \u05de\u05d1\u05d5\u05dc\u05d1\u05dc, \u05e2\u05d9\u05d9\u05e3.\n\u05d7\u05e4\u05e9 \u05d0\u05ea \u05e0\u05e7\u05d5\u05d3\u05d5\u05ea \u05d4\u05d0\u05d5\u05e8 \u05d4\u05e7\u05d8\u05e0\u05d5\u05ea \u2014 \u05e0\u05e9\u05d9\u05de\u05d4, \u05d6\u05d9\u05db\u05e8\u05d5\u05df \u05d8\u05d5\u05d1, \u05de\u05d1\u05d8 \u05d0\u05d5\u05d4\u05d1, \u05ea\u05e7\u05d5\u05d5\u05d4.\n\u05db\u05de\u05d5 \u05db\u05d5\u05db\u05d1\u05d9\u05dd \u05de\u05e0\u05e6\u05e0\u05e6\u05d9\u05dd.\n\u05d0\u05de\u05d5\u05e8 \u05d1\u05dc\u05d1\u05da: "\u05d4\u05dc\u05dc\u05d5\u05d4\u05d5 \u05db\u05dc \u05db\u05d5\u05db\u05d1\u05d9 \u05d0\u05d5\u05e8."\n\u05d4\u05db\u05d5\u05db\u05d1\u05d9\u05dd \u05e9\u05e8\u05d9\u05dd \u2014 \u05d2\u05dd \u05db\u05e9\u05d0\u05e3 \u05d0\u05d7\u05d3 \u05dc\u05d0 \u05e9\u05d5\u05de\u05e2.\n4. \u05e9\u05d4\u05d9\u05d9\u05d4 \u05d1\u05d4\u05d5\u05d3\u05d9\u05d4\n\u05d1\u05db\u05dc \u05de\u05e6\u05d1 \u2014 \u05e9\u05de\u05e9, \u05d9\u05e8\u05d7 \u05d0\u05d5 \u05db\u05d5\u05db\u05d1\u05d9\u05dd \u2014 \u05d0\u05ea\u05d4 \u05d7\u05dc\u05e7 \u05de\u05ea\u05d6\u05de\u05d5\u05e8\u05ea \u05d0\u05d7\u05ea \u05d2\u05d3\u05d5\u05dc\u05d4.\n\u05ea\u05df \u05dc\u05dc\u05d1 \u05dc\u05d5\u05de\u05e8: *"\u05de\u05d5\u05d3\u05d4 \u05d0\u05e0\u05d9."*\n\u05e2\u05dc \u05de\u05d4 \u05e9\u05d9\u05e9. \u05e2\u05dc \u05de\u05d4 \u05e9\u05d0\u05d9\u05e0\u05e0\u05d5. \u05e2\u05dc \u05e2\u05e6\u05dd \u05e7\u05d9\u05d5\u05de\u05da.\n5. \u05e1\u05d9\u05d5\u05dd\n\u05d7\u05d6\u05d5\u05e8 \u05d0\u05dc \u05d4\u05e0\u05e9\u05d9\u05de\u05d4. \u05e4\u05e7\u05d7 \u05d0\u05ea \u05d4\u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05d1\u05d0\u05d9\u05d8\u05d9\u05d5\u05ea.\n\u05e7\u05d7 \u05d0\u05d9\u05ea\u05da \u05d0\u05ea \u05d4\u05ea\u05d7\u05d5\u05e9\u05d4 \u05d4\u05d6\u05d5 \u2014\n\u05e9\u05d2\u05dd \u05d0\u05dd \u05d0\u05ea\u05d4 \u05db\u05d5\u05db\u05d1 \u05e7\u05d8\u05df \u05d1\u05e9\u05de\u05d9 \u05dc\u05d9\u05dc\u05d4 \u2014 \u05d0\u05ea\u05d4 \u05d0\u05d5\u05e8. \u05d5\u05d0\u05ea\u05d4 \u05de\u05d4\u05dc\u05dc.\n\u05d7\u05d9\u05d1\u05d5\u05e8 \u05dc\u05de\u05e6\u05d9\u05d0\u05d5\u05ea \u05d7\u05d9\u05d9 \u05d3\u05e8\u05da \u05d4\u05ea\u05de\u05e7\u05d3\u05d5\u05ea \u05d1\u05d0\u05d5\u05ea\u05d9\u05d5\u05ea \u05d4\u05e7\u05d3\u05d5\u05e9\u05d5\u05ea \u05d9-\u05d4-\u05d5-\u05d4\n\u05d9\u05e9\u05e0\u05df \u05e7\u05d5\u05de\u05d1\u05d9\u05e0\u05e6\u05d9\u05d5\u05ea \u05e8\u05d1\u05d5\u05ea \u05e9\u05dc \u05d4\u05d0\u05d5\u05ea\u05d9\u05d5\u05ea \u05d4\u05e7\u05d3\u05d5\u05e9\u05d5\u05ea \u05d9-\u05d4-\u05d5-\u05d4. \u05db\u05dc \u05e9\u05d9\u05dc\u05d5\u05d1 \u05de\u05ea\u05de\u05e7\u05d3 \u05d1\u05d0\u05e1\u05e4\u05e7\u05d8 \u05d0\u05d7\u05e8 \u05e9\u05dc \u05e0\u05d5\u05db\u05d7\u05d5\u05ea \u05d4\u05e2\u05e6\u05de\u05d9\u05d5\u05ea \u05e9\u05dc\u05e0\u05d5. \u05d4\u05e9\u05dc\u05d1 \u05d4\u05e8\u05d0\u05e9\u05d5\u05df \u05d4\u05d5\u05d0 \u05dc\u05d4\u05ea\u05d7\u05d9\u05dc \u05dc\u05e0\u05e9\u05d5\u05dd \u05dc\u05ea\u05d5\u05da \u05e2\u05e6\u05de\u05e0\u05d5 \u05d0\u05ea \u05d0\u05d5\u05e8 \u05d4\u05d0\u05d9\u05e0\u05e1\u05d5\u05e3, \u05d5\u05dc\u05dc\u05de\u05d5\u05d3 \u05dc\u05d4\u05ea\u05de\u05e7\u05d3 \u05d5\u05dc\u05d4\u05ea\u05e8\u05db\u05d6. \u05d0\u05e0\u05d5 \u05d7\u05d9\u05d9\u05dd \u05d1\u05e2\u05d5\u05dc\u05dd \u05e9\u05d1\u05d5 \u05d4\u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05e8\u05e6\u05d5\u05ea \u05dc\u05dc\u05d0 \u05d4\u05e4\u05e1\u05e7\u05d4, \u05de\u05d4 \u05e9\u05d4\u05d5\u05e4\u05da \u05d0\u05ea \u05d4\u05e8\u05d9\u05db\u05d5\u05d6 \u05dc\u05de\u05d0\u05ea\u05d2\u05e8. \u05e2\u05dc \u05db\u05df, \u05e0\u05ea\u05d7\u05d9\u05dc \u05dc\u05dc\u05de\u05d5\u05d3 \u05dc\u05e9\u05dc\u05d5\u05d8 \u05d1\u05de\u05d7\u05e9\u05d1\u05d5\u05ea\u05d9\u05e0\u05d5 \u05d3\u05e8\u05da \u05e8\u05d9\u05db\u05d5\u05d6 \u05e2\u05dc \u05d4\u05d0\u05d5\u05ea \u05d9.\n\u05e0\u05e0\u05d9\u05d7 \u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05e1\u05d2\u05d5\u05e8\u05d5\u05ea, \u05d5\u05e0\u05e9\u05d0\u05e3 \u05e0\u05e9\u05d9\u05de\u05d4 \u05e2\u05de\u05d5\u05e7\u05d4 \u05db\u05db\u05dc \u05d4\u05d0\u05e4\u05e9\u05e8, \u05e2\u05d3 \u05e9\u05d4\u05d0\u05d5\u05d5\u05d9\u05e8 \u05d9\u05de\u05dc\u05d0 \u05d0\u05ea \u05db\u05dc \u05d4\u05e8\u05d9\u05d0\u05d5\u05ea \u05d5\u05d4\u05d1\u05d8\u05df, \u05d4\u05e8\u05d0\u05e9, \u05d4\u05e4\u05e0\u05d9\u05dd, \u05d4\u05d0\u05e3, \u05d0\u05e8\u05d5\u05d1\u05d5\u05ea \u05d4\u05e2\u05d9\u05e0\u05d9\u05d9\u05dd, \u05d4\u05d2\u05d1\u05d5\u05ea, \u05d4\u05de\u05e6\u05d7, \u05d4\u05e8\u05d2\u05dc\u05d9\u05d9\u05dd, \u05d4\u05d9\u05d3\u05d9\u05d9\u05dd \u05d5\u05db\u05dc \u05d0\u05e6\u05d1\u05e2. \u05d0\u05d7\u05e8\u05d9 \u05db\u05de\u05d4 \u05e0\u05e9\u05d9\u05de\u05d5\u05ea \u05e2\u05de\u05d5\u05e7\u05d5\u05ea \u05d5\u05e0\u05e9\u05d9\u05e4\u05d5\u05ea \u05e9\u05d7\u05e8\u05d5\u05e8\u05d9\u05d5\u05ea, \u05e0\u05ea\u05d7\u05d9\u05dc \u05dc\u05d4\u05ea\u05de\u05e7\u05d3 \u05d1\u05e9\u05d0\u05d9\u05e4\u05d4 \u05d7\u05d3\u05e9\u05d4, \u05ea\u05d5\u05da \u05d3\u05de\u05d9\u05d5\u05df \u05e9\u05dc \u05d4\u05d0\u05d5\u05ea \u05d9. \u05d4\u05d0\u05d5\u05ea \u05d9 \u05de\u05d9\u05d9\u05e6\u05d2\u05ea \u05d0\u05ea \u05d4\u05d0\u05d5\u05e8 \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9, \u05d0\u05ea \u05d0\u05d5\u05e8 \u05d4\u05d0\u05d9\u05e0\u05e1\u05d5\u05e3 \u05d4\u05e0\u05de\u05e6\u05d0 \u05d1\u05ea\u05d5\u05db\u05e0\u05d5.\n\u05e0\u05d3\u05de\u05d9\u05d9\u05df \u05e1\u05d1\u05d9\u05d1 \u05d4\u05d0\u05d5\u05ea \u05d9 \u05d4\u05d9\u05dc\u05d4 \u05e9\u05dc \u05d0\u05d5\u05e8, \u05d5\u05e0\u05d9\u05ea\u05df \u05dc\u05d0\u05d5\u05e8 \u05d4\u05d6\u05d4 \u05dc\u05d7\u05d3\u05d5\u05e8 \u05dc\u05ea\u05d5\u05da \u05d4\u05ea\u05d5\u05d3\u05e2\u05d4 \u05e9\u05dc\u05e0\u05d5, \u05dc\u05e8\u05e4\u05d0 \u05d0\u05ea \u05d4\u05de\u05e7\u05d5\u05de\u05d5\u05ea \u05d4\u05e4\u05e6\u05d5\u05e2\u05d9\u05dd \u05d5\u05d4\u05db\u05d5\u05d0\u05d1\u05d9\u05dd \u05d1\u05ea\u05d5\u05d3\u05e2\u05d4 \u05d5\u05d1\u05d2\u05d5\u05e3. \u05db\u05dc \u05e9\u05d0\u05d9\u05e4\u05d4 \u05ea\u05d4\u05d9\u05d4 \u05d4\u05d6\u05d3\u05de\u05e0\u05d5\u05ea \u05dc\u05d4\u05ea\u05d7\u05d1\u05e8 \u05dc\u05d0\u05d5\u05e8 \u05d4\u05d6\u05d4, \u05dc\u05e9\u05d7\u05e8\u05e8 \u05d0\u05e0\u05e8\u05d2\u05d9\u05d4 \u05e9\u05dc\u05d9\u05dc\u05d9\u05ea, \u05d5\u05dc\u05de\u05dc\u05d0 \u05d0\u05ea \u05e2\u05e6\u05de\u05e0\u05d5 \u05d1\u05d0\u05d5\u05e8 \u05d0\u05dc\u05d5\u05e7\u05d9 \u05e9\u05de\u05d6\u05d9\u05df \u05d0\u05d5\u05ea\u05e0\u05d5 \u05d1\u05e0\u05e4\u05e9 \u05d5\u05d1\u05d2\u05d5\u05e3.\n\u05e0\u05e4\u05ea\u05d7 \u05d1\u05d4\u05d5\u05d3\u05d9\u05d4 \u05dc\u05d0\u05d5\u05e8 \u05e9\u05de\u05d0\u05d9\u05e8 \u05d0\u05d5\u05ea\u05e0\u05d5 \u05d5\u05de\u05d1\u05e4\u05e0\u05d9\u05dd. \u05ea\u05d5\u05d3\u05d4 \u05e2\u05dc\u2026 \u05ea\u05d5\u05d3\u05d4 \u05e9\u05d9\u05e9 \u05dc\u05d9 \u05de\u05d4 \u05dc\u05d0\u05db\u05d5\u05dc, \u05ea\u05d5\u05d3\u05d4 \u05e9\u05d9\u05e9 \u05dc\u05d9 \u05e7\u05d5\u05e8\u05ea \u05d2\u05d2, \u05ea\u05d5\u05d3\u05d4 \u05e9\u05d0\u05e0\u05d9 \u05e2\u05e9\u05d9\u05e8. \u05db\u05d9 \u05d4\u05de\u05d9\u05dc\u05d4 "\u05e2\u05e9\u05d9\u05e8" \u05de\u05d5\u05e8\u05db\u05d1\u05ea \u05de\u05d4\u05d0\u05d5\u05ea\u05d9\u05d5\u05ea \u05e2\u05d9\u05e0\u05d9\u05d9\u05dd, \u05e9\u05d9\u05e0\u05d9\u05d9\u05dd, \u05d9\u05d3\u05d9\u05d9\u05dd \u05d5\u05e8\u05d2\u05dc\u05d9\u05d9\u05dd. \u05ea\u05d5\u05d3\u05d4 \u05e2\u05dc \u05db\u05dc \u05d3\u05d1\u05e8 \u05e9\u05d9\u05e9 \u05dc\u05d4\u05d5\u05d3\u05d5\u05ea \u05e2\u05dc\u05d9\u05d5. \u05ea\u05d5\u05d3\u05d4 \u05e2\u05dc \u05d4\u05de\u05d9\u05dd \u05d4\u05d6\u05d5\u05e8\u05de\u05d9\u05dd, \u05ea\u05d5\u05d3\u05d4 \u05e2\u05dc \u05d4\u05d7\u05e9\u05de\u05dc, \u05ea\u05d5\u05d3\u05d4 \u05e2\u05dc \u05de\u05db\u05d5\u05e0\u05ea \u05d4\u05db\u05d1\u05d9\u05e1\u05d4, \u05ea\u05d5\u05d3\u05d4 \u05e2\u05dc \u05d4\u05e8\u05d2\u05e2 \u05d4\u05d6\u05d4 \u05e9\u05de\u05de\u05dc\u05d0 \u05d0\u05d5\u05ea\u05d9 \u05d1\u05e9\u05dc\u05d5\u05d5\u05d4. \u05ea\u05d5\u05d3\u05d4 \u05e2\u05dc \u05d4\u05e9\u05de\u05e9, \u05ea\u05d5\u05d3\u05d4 \u05e2\u05dc \u05d4\u05d2\u05e9\u05dd.\n\u05e0\u05d9\u05d9\u05d7\u05dc \u05d1\u05dc\u05d9\u05d1\u05e0\u05d5, \u05d5\u05e8\u05e6\u05d5\u05d9 \u05d2\u05dd \u05dc\u05d5\u05de\u05e8 \u05d0\u05ea \u05d4\u05de\u05d9\u05dc\u05d9\u05dd: "\u05d4\u05d9\u05d0 \u05e8\u05e6\u05d5\u05df \u05e9\u05d4\u05d0\u05d5\u05e8 \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9 \u05d9\u05e8\u05e4\u05d0 \u05d0\u05ea \u05d4\u05de\u05e7\u05d5\u05de\u05d5\u05ea \u05d4\u05db\u05d5\u05d0\u05d1\u05d9\u05dd \u05d1\u05ea\u05d5\u05db\u05e0\u05d5, \u05d4\u05df \u05d4\u05e0\u05e4\u05e9\u05d9\u05d9\u05dd \u05d5\u05d4\u05df \u05d4\u05d2\u05d5\u05e4\u05e0\u05d9\u05d9\u05dd". \u05e0\u05d0\u05de\u05e8 \u05d1\u05de\u05d9\u05dc\u05d9\u05dd: "\u05d0\u05e0\u05d9 \u05e8\u05d5\u05e6\u05d4" \u05d0\u05d5 "\u05d9\u05d4\u05d9 \u05e8\u05e6\u05d5\u05df \u05e9\u2026"\n\u05d0\u05dc\u05d5\u05d4\u05d9 \u05e0\u05e9\u05de\u05d4 - \u05ea\u05d5\u05d3\u05d4 \u05e9\u05d4\u05e0\u05e9\u05de\u05d4 \u05e9\u05dc\u05d9 \u05de\u05d0\u05d9\u05e8\u05d4 \u05d1\u05d9 \u05d0\u05ea \u05d4\u05ea\u05d5\u05d1\u05e0\u05d5\u05ea. \u05d0\u05e0\u05d9 \u05d1\u05d5\u05d7\u05e8\u05ea \u05dc\u05d4\u05d9\u05d6\u05db\u05e8 \u05d1\u05ea\u05d5\u05d1\u05e0\u05d5\u05ea \u05e9\u05de\u05d0\u05d9\u05e8\u05d5\u05ea \u05d0\u05ea \u05d7\u05d9\u05d9 \u05d1\u05db\u05dc \u05e8\u05d2\u05e2, \u05d1\u05de\u05d9\u05d5\u05d7\u05d3 \u05d1\u05e8\u05d2\u05e2\u05d9\u05dd \u05de\u05d0\u05ea\u05d2\u05e8\u05d9\u05dd.\n\u05d4\u05ea\u05de\u05e7\u05d3\u05d5\u05ea \u05d1\u05e0\u05d5\u05db\u05d7\u05d5\u05ea \u05d0\u05d5\u05e8 \u05d4\u05d0\u05d9\u05e0\u05e1\u05d5\u05e3 \u05d1\u05ea\u05d5\u05da \u05d4\u05e8\u05d2\u05e2: \u05d0\u05d4\u05d9\u05d4 \u2013 \u05d4\u05d5\u05d5\u05d9\u05d4 \u2013 \u05d4\u05d4\u05ea\u05d4\u05d5\u05d5\u05ea \u05e9\u05dc \u05db\u05d7 \u05d4\u05e9\u05db\u05d9\u05e0\u05d4 \u05d1\u05ea\u05d5\u05db\u05d9 \u2013 \u05d4\u05e0\u05d5\u05db\u05d7\u05d5\u05ea \u05e9\u05dc \u05e2\u05e6\u05de\u05d9 \u2013 \u05d4\u05e0\u05d5\u05db\u05d7\u05d5\u05ea \u05e9\u05dc \u05d0\u05d5\u05e8 \u05d4\u05d0\u05d9\u05e0\u05e1\u05d5\u05e3 \u2013 \u05d0\u05d5\u05e8 \u05d0\u05dc\u05d5\u05e7\u05d9 \u05d1\u05ea\u05d5\u05db\u05d9.\n"\u05d5\u05b0\u05d4\u05b8\u05d9\u05d5\u05bc \u05dc\u05b0\u05d8\u05bb\u05d8\u05b8\u05bc\u05e4\u05d5\u05b9\u05ea \u05d1\u05b5\u05bc\u05d9\u05df \u05e2\u05b5\u05d9\u05e0\u05b6\u05d9\u05da\u05b8" \u2013 \u05d0\u05e0\u05d9 \u05e8\u05d5\u05e6\u05d4 \u05dc\u05d4\u05d7\u05d6\u05d9\u05e7 \u05d0\u05ea \u05db\u05dc \u05de\u05d4 \u05e9\u05dc\u05de\u05d3\u05ea\u05d9 \u05d1\u05de\u05d5\u05d3\u05e2\u05d5\u05ea \u05e9\u05dc\u05d9, \u05d5\u05dc\u05d0 \u05dc\u05e9\u05db\u05d5\u05d7.\n"\u05d5\u05e7\u05e9\u05e8\u05ea\u05dd \u05dc\u05d0\u05d5\u05ea \u05e2\u05dc \u05d9\u05d3\u05da" \u2013\u05e0\u05ea\u05d1\u05d5\u05e0\u05df \u05d1\u05db\u05da \u05e9\u05d0\u05e0\u05d9 \u05e8\u05d5\u05e6\u05d4 \u05dc\u05d4\u05e2\u05d1\u05d9\u05e8 \u05dc\u05d9\u05d9\u05e9\u05d5\u05dd \u05d0\u05ea \u05db\u05dc \u05de\u05d4 \u05e9\u05dc\u05de\u05d3\u05ea\u05d9.\n"\u05d1\u05e8\u05d5\u05da \u05e9\u05d0\u05de\u05e8" \u2013 \u05e9\u05d1\u05d7 \u05d6\u05d4 \u05e8\u05dd \u05d5\u05e0\u05d9\u05e9\u05d0. \u05d1\u05d1\u05e8\u05db\u05d4 \u05d6\u05d5 \u05d9\u05e9 \u05e2\u05e9\u05e8 \u05de\u05d0\u05de\u05e8\u05d5\u05ea \u05e9\u05d1\u05d4\u05df \u05e0\u05d1\u05e8\u05d0 \u05d4\u05e2\u05d5\u05dc\u05dd, \u05db\u05e4\u05d9 \u05e9\u05e0\u05d3\u05e8\u05e9 \u05dc\u05e1\u05e4\u05e8 \u05d1\u05e9\u05d1\u05d7\u05d5 \u05e9\u05dc \u05d4\u05e7\u05d1"\u05d4, \u05db\u05de\u05d5 \u05e9\u05e0\u05d0\u05de\u05e8: "\u05dc\u05e2\u05d5\u05dc\u05dd \u05d9\u05e1\u05d3\u05e8 \u05e9\u05d1\u05d7\u05d5 \u05e9\u05dc \u05d4\u05e7\u05d1"\u05d4, \u05d5\u05d0\u05d7\u05e8 \u05db\u05da \u05d9\u05ea\u05e4\u05dc\u05dc" (\u05de\u05e1\u05db\u05ea \u05d1\u05e8\u05db\u05d5\u05ea). \u05dc\u05e4\u05d9\u05db\u05da, \u05d4\u05d1\u05e8\u05db\u05d4 \u05de\u05ea\u05d7\u05d9\u05dc\u05d4 \u05d1\u05d1\u05e8\u05d9\u05d0\u05ea \u05d4\u05e2\u05d5\u05dc\u05dd (\u05e9\u05d1\u05d4"\u05dc, \u05e1\u05d9\u05de\u05df \u05d5).')
B.KQ=new A.cv(17,"\u05ea\u05e8\u05d2\u05d9\u05dc\u05e0\u05d5 \u05d1\u05ea\u05d5\u05e8\u05ea\u05da: \u05d4\u05e8\u05d2\u05dc \u05d5\u05d3\u05d1\u05e7\u05d5\u05ea",'"\u05ea\u05e8\u05d2\u05d9\u05dc\u05e0\u05d5 \u05d1\u05ea\u05d5\u05e8\u05ea\u05da \u05d5\u05d3\u05d1\u05e7\u05e0\u05d5 \u05d1\u05de\u05e6\u05d5\u05d5\u05ea\u05da" \u2013 \u05d0\u05e0\u05d5 \u05de\u05d1\u05e7\u05e9\u05d9\u05dd \u05e9\u05d4\u05d4\u05d7\u05dc\u05d8\u05d5\u05ea \u05d4\u05d8\u05d5\u05d1\u05d5\u05ea \u05e9\u05e7\u05d9\u05d1\u05dc\u05e0\u05d5 \u05e2\u05dc \u05e2\u05e6\u05de\u05e0\u05d5 \u05d9\u05d4\u05e4\u05db\u05d5 \u05dc\u05d4\u05e8\u05d2\u05dc, \u05e9\u05e0\u05d4\u05d9\u05d4 \u05e8\u05d2\u05d9\u05dc\u05d9\u05dd \u05d1\u05d4\u05dd. \u05d0\u05da \u05d2\u05dd \u05e9\u05e0\u05d3\u05d1\u05e7 \u05d1\u05d4\u05dd \u05de\u05ea\u05d5\u05da \u05de\u05d5\u05d3\u05e2\u05d5\u05ea \u05e2\u05de\u05d5\u05e7\u05d4, \u05e9\u05dc\u05d0 \u05e8\u05e7 \u05e0\u05e2\u05e1\u05d5\u05e7 \u05d1\u05d4\u05dd \u05de\u05ea\u05d5\u05da \u05d4\u05e8\u05d2\u05dc, \u05d0\u05dc\u05d0 \u05de\u05ea\u05d5\u05da \u05e9\u05db\u05e0\u05d5\u05e2 \u05e4\u05e0\u05d9\u05de\u05d9 \u05e2\u05de\u05d5\u05e7 \u05e9\u05d6\u05d4 \u05de\u05d4 \u05e9\u05e0\u05db\u05d5\u05df \u05dc\u05e0\u05d5. \u05db\u05da \u05e9\u05d4\u05d4\u05e8\u05d2\u05dc \u05dc\u05d0 \u05d9\u05d4\u05e4\u05d5\u05da \u05dc\u05de\u05e9\u05e2\u05de\u05dd, \u05d5\u05e9\u05dd \u05d4\u05d3\u05d1\u05e7 \u05d1\u05d9\u05e0\u05e0\u05d5 \u05dc\u05d1\u05d9\u05df \u05d4\u05d4\u05e8\u05d2\u05dc\u05d9\u05dd \u05d4\u05d7\u05d9\u05d5\u05d1\u05d9\u05d9\u05dd \u05d9\u05d4\u05d9\u05d4 \u05d7\u05d6\u05e7 \u05e2\u05d3 \u05db\u05d3\u05d9 \u05d7\u05d5\u05e1\u05e8 \u05d9\u05db\u05d5\u05dc\u05ea \u05dc\u05d4\u05d9\u05e4\u05e8\u05d3\u05d5\u05ea. \u05e0\u05d9\u05d3\u05d1\u05e7 \u05d1\u05d3\u05d9\u05d1\u05d5\u05e8 \u05d7\u05d9\u05d5\u05d1\u05d9, \u05e9\u05e0\u05d4\u05d9\u05d4 \u05e8\u05d2\u05d9\u05dc\u05d9\u05dd \u05dc\u05d3\u05d9\u05d1\u05d5\u05e8 \u05d7\u05d9\u05d5\u05d1\u05d9, \u05d5\u05e9\u05e0\u05d4\u05d9\u05d4 \u05e8\u05d2\u05d9\u05dc\u05d9\u05dd \u05dc\u05d4\u05d9\u05de\u05e0\u05e2 \u05de\u05d3\u05d9\u05d1\u05d5\u05e8 \u05e9\u05e4\u05d5\u05d2\u05e2 \u05d1\u05e0\u05e9\u05de\u05ea\u05e0\u05d5 \u05d5\u05d1\u05e1\u05d1\u05d9\u05d1\u05ea\u05e0\u05d5.\n\u05d0\u05d9\u05da \u05d1\u05d5\u05e0\u05d9\u05dd \u05d4\u05e8\u05d2\u05dc\u05d9\u05dd \u05e9\u05dc\u05d0 \u05e0\u05e8\u05e6\u05d4 \u05dc\u05d4\u05e4\u05e1\u05d9\u05e7?\n\u05ea\u05d7\u05e9\u05d1\u05d5 \u05e8\u05d2\u05e2 \u05e2\u05dc \u05d6\u05d4: \u05db\u05de\u05d4 \u05e4\u05e2\u05de\u05d9\u05dd \u05e0\u05d9\u05e1\u05d9\u05e0\u05d5 \u05dc\u05d4\u05ea\u05d7\u05d9\u05dc \u05d4\u05e8\u05d2\u05dc \u05d7\u05d3\u05e9 \u2013 \u05ea\u05d6\u05d5\u05e0\u05d4 \u05d1\u05e8\u05d9\u05d0\u05d4, \u05e1\u05e4\u05d5\u05e8\u05d8, \u05e4\u05d7\u05d5\u05ea \u05e9\u05e2\u05d5\u05ea \u05de\u05e1\u05db\u05d9\u05dd \u2013 \u05d5\u05d4\u05d4\u05ea\u05dc\u05d4\u05d1\u05d5\u05ea \u05d4\u05e8\u05d0\u05e9\u05d5\u05e0\u05d9\u05ea \u05d4\u05ea\u05e4\u05d5\u05d2\u05d2\u05d4 \u05ea\u05d5\u05da \u05d9\u05de\u05d9\u05dd?\n\u05d5\u05de\u05d4 \u05d2\u05d5\u05e8\u05dd \u05dc\u05d4\u05e8\u05d2\u05dc\u05d9\u05dd \u05d0\u05d7\u05e8\u05d9\u05dd \u2013 \u05db\u05de\u05d5 \u05e7\u05e4\u05d4 \u05d1\u05d1\u05d5\u05e7\u05e8 \u05d0\u05d5 \u05de\u05d5\u05d6\u05d9\u05e7\u05d4 \u05d1\u05d3\u05e8\u05da \u05dc\u05e2\u05d1\u05d5\u05d3\u05d4 \u2013 \u05dc\u05d4\u05d9\u05e9\u05d0\u05e8 \u05d0\u05d9\u05ea\u05e0\u05d5 \u05dc\u05d0\u05d5\u05e8\u05da \u05e9\u05e0\u05d9\u05dd?\n\u05d6\u05d4 \u05dc\u05d0 \u05e8\u05e7 \u05e2\u05e0\u05d9\u05d9\u05df \u05e9\u05dc \u05d4\u05d7\u05dc\u05d8\u05d4, \u05d0\u05dc\u05d0 \u05e9\u05dc \u05ea\u05e8\u05d2\u05d5\u05dc \u05d5\u05d3\u05d1\u05e7\u05d5\u05ea.',"\u05ea\u05e8\u05d2\u05d9\u05dc \u05d4\u05d8\u05de\u05e2\u05d4:",'\u05db\u05dc \u05e9\u05d9\u05e0\u05d5\u05d9 \u05d2\u05d3\u05d5\u05dc \u05de\u05ea\u05d7\u05d9\u05dc \u05d1\u05e6\u05e2\u05d3 \u05e7\u05d8\u05df \u05e9\u05d7\u05d5\u05d6\u05e8 \u05e2\u05dc \u05e2\u05e6\u05de\u05d5. \u05db\u05db\u05dc \u05e9\u05d0\u05e0\u05d7\u05e0\u05d5 \u05de\u05ea\u05e8\u05d2\u05dc\u05d9\u05dd \u05de\u05e9\u05d4\u05d5 \u2013 \u05d4\u05d5\u05d0 \u05d4\u05d5\u05e4\u05da \u05d0\u05d5\u05d8\u05d5\u05de\u05d8\u05d9. \u05db\u05d1\u05e8 \u05dc\u05d0 \u05e6\u05e8\u05d9\u05da \u05dc\u05e9\u05db\u05e0\u05e2 \u05d0\u05ea \u05e2\u05e6\u05de\u05e0\u05d5 \u05db\u05dc \u05e4\u05e2\u05dd \u05de\u05d7\u05d3\u05e9, \u05db\u05d9 \u05d4\u05de\u05d5\u05d7 \u05db\u05d1\u05e8 \u05d1\u05e0\u05d4 \u05e9\u05d1\u05d9\u05dc. \u05d6\u05d4 \u05db\u05d1\u05e8 \u05d4\u05e8\u05d2\u05dc.\n\u05d5\u05d3\u05d1\u05e7\u05d5\u05ea \u2013 \u05dc\u05d4\u05e4\u05d5\u05da \u05d0\u05ea \u05d6\u05d4 \u05dc\u05d7\u05dc\u05e7 \u05de\u05de\u05e0\u05d9\n\u05e8\u05e7 \u05ea\u05e8\u05d2\u05d5\u05dc \u05dc\u05d0 \u05de\u05e1\u05e4\u05d9\u05e7. \u05e6\u05e8\u05d9\u05da \u05d2\u05dd \u05d7\u05d9\u05d1\u05d5\u05e8 \u05e4\u05e0\u05d9\u05de\u05d9, \u05de\u05e9\u05d4\u05d5 \u05e9\u05e0\u05e8\u05e6\u05d4 \u05d1\u05d5, \u05e9\u05e0\u05e8\u05d2\u05d9\u05e9 \u05e9\u05d4\u05d5\u05d0 \u05d7\u05dc\u05e7 \u05de\u05de\u05d9 \u05e9\u05d0\u05e0\u05d7\u05e0\u05d5.\n\u05d4\u05d4\u05e8\u05d2\u05dc\u05d9\u05dd \u05e9\u05e0\u05e9\u05d0\u05e8\u05d9\u05dd \u05d0\u05d9\u05ea\u05e0\u05d5 \u05d4\u05dd \u05d0\u05dc\u05d4 \u05e9\u05d0\u05e0\u05d7\u05e0\u05d5 \u05de\u05ea\u05d7\u05d1\u05e8\u05d9\u05dd \u05d0\u05dc\u05d9\u05d4\u05dd \u05e8\u05d2\u05e9\u05d9\u05ea \u2013 \u05e9\u05de\u05e8\u05d2\u05d9\u05e9\u05d9\u05dd \u05e9\u05d4\u05dd \u05ea\u05d5\u05e8\u05de\u05d9\u05dd \u05dc\u05e0\u05d5, \u05e9\u05de\u05de\u05dc\u05d0\u05d9\u05dd \u05d0\u05d5\u05ea\u05e0\u05d5.\n\u05e8\u05e2\u05d9\u05d5\u05df \u05e2\u05ea\u05d9\u05e7 \u05e2\u05dc \u05d4\u05e8\u05d2\u05dc\u05d9\u05dd \u05d7\u05d3\u05e9\u05d9\u05dd\n\u05d1\u05ea\u05e4\u05d9\u05dc\u05ea \u05d4\u05d1\u05d5\u05e7\u05e8 , \u05de\u05d5\u05e4\u05d9\u05e2 \u05de\u05e9\u05e4\u05d8 \u05d4\u05de\u05d6\u05db\u05d9\u05e8 \u05dc\u05d4\u05ea\u05d1\u05d5\u05e0\u05df \u05d1\u05d4\u05d8\u05de\u05e2\u05ea \u05d4\u05d4\u05e8\u05d2\u05dc\u05d9\u05dd \u05d4\u05e8\u05e6\u05d5\u05d9\u05d9\u05dd \u05dc\u05e0\u05d5:\n"\u05d5\u05ea\u05e8\u05d2\u05d9\u05dc\u05e0\u05d5... \u05d5\u05d3\u05d1\u05e7\u05e0\u05d5..."\n\u05d4\u05de\u05e9\u05de\u05e2\u05d5\u05ea \u05e4\u05e9\u05d5\u05d8\u05d4: \u05ea\u05d4\u05e4\u05d5\u05da \u05d0\u05ea \u05d4\u05d3\u05d1\u05e8\u05d9\u05dd \u05d4\u05d7\u05e9\u05d5\u05d1\u05d9\u05dd \u05dc\u05d4\u05e8\u05d2\u05dc \u2013 \u05d5\u05d0\u05d6 \u05ea\u05d1\u05e7\u05e9 \u05d2\u05dd \u05dc\u05d4\u05e8\u05d2\u05d9\u05e9 \u05d7\u05d9\u05d1\u05d5\u05e8 \u05d0\u05dc\u05d9\u05d4\u05dd.\n\u05d6\u05d5 \u05e2\u05e6\u05d4 \u05e9\u05de\u05d0\u05e4\u05e9\u05e8\u05ea \u05de\u05e2\u05d1\u05e8 \u05dc\u05d4\u05d8\u05de\u05e2\u05ea \u05d4\u05e8\u05d2\u05dc\u05d9\u05dd \u05d3\u05ea\u05d9\u05d9\u05dd \u05ea\u05db\u05e0\u05d5\u05df \u05d4\u05e8\u05d2\u05dc\u05d9\u05dd \u05d1\u05db\u05dc \u05ea\u05d7\u05d5\u05de\u05d9 \u05d4\u05d7\u05d9\u05d9\u05dd \u2013  \u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea \u05dc\u05e4\u05d9\u05ea\u05d5\u05d7 \u05db\u05dc \u05d4\u05e8\u05d2\u05dc \u05d8\u05d5\u05d1, \u05d1\u05d9\u05df \u05d0\u05dd \u05d6\u05d4 \u05dc\u05d9\u05de\u05d5\u05d3 \u05d9\u05d5\u05de\u05d9, \u05e0\u05d5\u05db\u05d7\u05d5\u05ea \u05e8\u05d2\u05e9\u05d9\u05ea \u05e2\u05dd \u05d4\u05e7\u05e8\u05d5\u05d1\u05d9\u05dd \u05dc\u05e0\u05d5 \u05d0\u05d5 \u05ea\u05db\u05e0\u05d9\u05ea \u05d4\u05d1\u05e8\u05d0\u05d4 \u05d2\u05d5\u05e4\u05e0\u05d9\u05ea.\n\u05d0\u05d6 \u05de\u05d4\u05d5 \u05d4\u05d4\u05e8\u05d2\u05dc \u05d4\u05d1\u05d0 \u05e9\u05d0\u05ea\u05d4 \u05e8\u05d5\u05e6\u05d4 \u05dc\u05d4\u05d8\u05de\u05d9\u05e2?\n\u05d1\u05e4\u05e2\u05dd \u05d4\u05d1\u05d0\u05d4 \u05e9\u05ea\u05e0\u05e1\u05d4 \u05dc\u05d0\u05de\u05e5 \u05d4\u05e8\u05d2\u05dc \u05d7\u05d3\u05e9 \u05d0\u05dc \u05ea\u05e1\u05ea\u05e4\u05e7 \u05d1\u05d4\u05d7\u05dc\u05d8\u05d4 \u05e9\u05dc \u05e8\u05d2\u05e2. \u05e9\u05d0\u05dc \u05d0\u05ea \u05e2\u05e6\u05de\u05da \u05e9\u05ea\u05d9 \u05e9\u05d0\u05dc\u05d5\u05ea:\n1. \u05d4\u05d0\u05dd \u05d0\u05e0\u05d9 \u05de\u05ea\u05e8\u05d2\u05dc \u05d0\u05ea \u05d6\u05d4 \u05de\u05e1\u05e4\u05d9\u05e7 \u05db\u05d3\u05d9 \u05e9\u05d6\u05d4 \u05d9\u05d4\u05e4\u05d5\u05da \u05dc\u05d8\u05d1\u05e2\u05d9?\n2. \u05d4\u05d0\u05dd \u05d0\u05e0\u05d9 \u05de\u05e6\u05dc\u05d9\u05d7 \u05dc\u05d4\u05e8\u05d2\u05d9\u05e9 \u05d1\u05d6\u05d4 \u05d7\u05d9\u05d1\u05d5\u05e8, \u05de\u05e9\u05de\u05e2\u05d5\u05ea, \u05e1\u05d9\u05e4\u05d5\u05e7?\n\u05e9\u05d9\u05dc\u05d5\u05d1 \u05e9\u05dc \u05ea\u05e8\u05d2\u05d5\u05dc \u05d5\u05d3\u05d1\u05e7\u05d5\u05ea - \u05d6\u05d5 \u05e0\u05d5\u05e1\u05d7\u05d4 \u05e9\u05e2\u05d5\u05d1\u05d3\u05ea \u05db\u05d1\u05e8 \u05d0\u05dc\u05e4\u05d9 \u05e9\u05e0\u05d9\u05dd.\n15 \u05d4\u05e6\u05d4\u05e8\u05d5\u05ea \u05d9\u05d5\u05de\u05d9\u05d5\u05ea \u05d1\u05d4\u05e9\u05e8\u05d0\u05ea \u05d1\u05e8\u05db\u05d5\u05ea \u05d4\u05e9\u05d7\u05e8\n\u05d0\u05e9\u05e8 \u05e0\u05ea\u05df \u05dc\u05e9\u05db\u05d5\u05d9 \u05d1\u05d9\u05e0\u05d4 \u05dc\u05d4\u05d1\u05d7\u05d9\u05df \u05d1\u05d9\u05df \u05d9\u05d5\u05dd \u05d5\u05d1\u05d9\u05df \u05dc\u05d9\u05dc\u05d4 -  \u05ea\u05d5\u05d3\u05d4 \u05e9\u05d9\u05e9 \u05dc\u05d9 \u05d0\u05ea \u05d4\u05db\u05d5\u05d7 \u05dc\u05d4\u05d1\u05d3\u05d9\u05dc \u05d1\u05d9\u05df \u05d0\u05d5\u05e8 \u05dc\u05d7\u05d5\u05e9\u05da, \u05d1\u05d9\u05df \u05de\u05d4 \u05e9\u05e0\u05db\u05d5\u05df \u05d5\u05d1\u05e8\u05d9\u05d0 \u05dc\u05d7\u05d9\u05d9 \u05dc\u05de\u05d4 \u05e9\u05de\u05d6\u05d9\u05e7 \u05d0\u05d5 \u05de\u05d9\u05d5\u05ea\u05e8 \u05d1\u05d7\u05d9\u05d9. \u05d0\u05e0\u05d9 \u05de\u05ea\u05d7\u05d1\u05e8\u05ea \u05dc\u05d4\u05d1\u05d7\u05e0\u05d4 \u05d1\u05d9\u05df \u05d4\u05d7\u05d9\u05d5\u05d1\u05d9 \u05dc\u05e4\u05d7\u05d5\u05ea \u05d7\u05d9\u05d5\u05d1\u05d9 \u05d1\u05db\u05dc \u05e8\u05d2\u05e2 \u05d5\u05dc\u05d1\u05d7\u05d9\u05e8\u05ea \u05d4\u05d7\u05dc\u05d8\u05d5\u05ea \u05de\u05d5\u05e9\u05db\u05dc\u05d5\u05ea\n\u05e9\u05dc\u05d0 \u05e2\u05e9\u05e0\u05d9  \u05e9\u05e4\u05d7\u05d4 - \u05ea\u05d5\u05d3\u05d4 \u05e9\u05d9\u05e9 \u05dc\u05d9 \u05d7\u05d5\u05e4\u05e9 \u05dc\u05d7\u05d9\u05d5\u05ea \u05d0\u05ea \u05d7\u05d9\u05d9 \u05db\u05e8\u05e6\u05d5\u05e0\u05d9. \u05d0\u05e0\u05d9 \u05d1\u05d5\u05d7\u05e8\u05ea \u05dc\u05d4\u05de\u05e9\u05d9\u05da \u05dc\u05d4\u05e9\u05ea\u05de\u05e9 \u05d1\u05d7\u05d5\u05e4\u05e9 \u05d4\u05d6\u05d4 \u05dc\u05de\u05e2\u05df \u05d1\u05d7\u05d9\u05e8\u05d5\u05ea \u05d7\u05d9\u05d5\u05d1\u05d9\u05d5\u05ea.\n\u05e9\u05e2\u05e9\u05e0\u05d9 \u05db\u05e8\u05e6\u05d5\u05e0\u05d5 - \u05ea\u05d5\u05d3\u05d4 \u05e2\u05dc \u05db\u05dc \u05d4\u05d2\u05d5\u05e8\u05de\u05d9\u05dd \u05d1\u05d7\u05d9\u05d9, \u05d4\u05d7\u05d9\u05d5\u05d1\u05d9\u05d9\u05dd \u05d9\u05d5\u05ea\u05e8 \u05d5\u05d4\u05d7\u05d9\u05d5\u05d1\u05d9\u05d9\u05dd \u05e4\u05d7\u05d5\u05ea. \u05d0\u05e0\u05d9 \u05d1\u05d5\u05d7\u05e8\u05ea \u05dc\u05dc\u05de\u05d5\u05d3 \u05de\u05db\u05dc \u05d4\u05d2\u05d5\u05e8\u05de\u05d9\u05dd \u05e9\u05e0\u05d1\u05e8\u05d0\u05d5 \u05dc\u05d1\u05e0\u05d5\u05ea \u05e1\u05d9\u05e4\u05d5\u05e8 \u05d7\u05d9\u05d9.\n\u05e4\u05d5\u05e7\u05d7 \u05e2\u05d9\u05d5\u05d5\u05e8\u05d9\u05dd - \u05ea\u05d5\u05d3\u05d4 \u05e9\u05e4\u05e7\u05d7\u05ea\u05d9 \u05d0\u05ea \u05e2\u05d9\u05e0\u05d9 \u05d4\u05d1\u05d5\u05e7\u05e8. \u05d0\u05e0\u05d0, \u05ea\u05df \u05dc\u05d9 \u05e8\u05e2\u05e0\u05e0\u05d5\u05ea \u05dc\u05e4\u05e2\u05d5\u05dc \u05d1\u05e2\u05d5\u05dc\u05dd \u05de\u05ea\u05d5\u05da \u05ea\u05d7\u05d5\u05e9\u05ea \u05e9\u05de\u05d7\u05d4, \u05e9\u05dc\u05d9\u05d7\u05d5\u05ea \u05d5\u05db\u05d5\u05d7\u05d5\u05ea \u05dc\u05d4\u05d2\u05e9\u05d9\u05dd \u05d0\u05ea \u05d4\u05e9\u05dc\u05d9\u05d7\u05d5\u05ea \u05e9\u05dc\u05e9\u05de\u05d4 \u05d9\u05e9 \u05dc\u05d9 \u05d0\u05ea \u05e0\u05e9\u05de\u05ea\u05d9.\n\u05ea\u05d5\u05d3\u05d4 \u05e9\u05e4\u05e7\u05d7\u05ea\u05d9 \u05d0\u05ea \u05e2\u05d9\u05e0\u05d9 \u05d4\u05d2\u05e9\u05de\u05d9\u05d5\u05ea. \u05ea\u05df \u05dc\u05d9 \u05e9\u05dc\u05e2\u05d5\u05dc\u05dd \u05db\u05d5\u05dc\u05d5 \u05dc\u05e4\u05e7\u05d5\u05d7 \u05d2\u05dd \u05d0\u05ea \u05e2\u05d9\u05e0\u05d9\u05e0\u05d5 \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9\u05d5\u05ea. \u05dc\u05d4\u05ea\u05d1\u05d5\u05e0\u05df \u05d1\u05e2\u05d5\u05dc\u05dd \u05d1\u05e4\u05e8\u05e1\u05e4\u05e7\u05d8\u05d9\u05d1\u05d4 \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea.  \u05d0\u05e0\u05d9 \u05de\u05ea\u05e4\u05dc\u05dc\u05ea \u05d5\u05de\u05d0\u05d7\u05dc\u05ea \u05dc\u05e2\u05e6\u05de\u05d9 \u05d5\u05db\u05dc \u05d4\u05e2\u05d5\u05dc\u05dd \u05e9\u05e0\u05d6\u05db\u05d4 \u05dc\u05e8\u05d0\u05d5\u05ea \u05d0\u05ea \u05e2\u05d5\u05de\u05e7 \u05e1\u05d9\u05e4\u05d5\u05e8 \u05d7\u05d9\u05d9\u05e0\u05d5 \u05d5\u05e1\u05d9\u05e4\u05d5\u05e8 \u05d4\u05e2\u05d5\u05dc\u05dd \u05d4\u05de\u05ea\u05de\u05e9\u05da \u05d1\u05db\u05dc \u05e8\u05d2\u05e2. \u05db\u05d9\u05e6\u05d3 \u05e8\u05d2\u05e2\u05d9\u05dd \u05e7\u05e9\u05d9\u05dd \u05d4\u05d1\u05d9\u05d0\u05d5 \u05d2\u05dd \u05d4\u05e8\u05d1\u05d4 \u05d7\u05d9\u05d5\u05d1\u05d9 \u05dc\u05e2\u05d5\u05dc\u05dd.  \u05e9\u05e0\u05d6\u05db\u05d4 \u05dc\u05e8\u05d0\u05d5\u05ea \u05d0\u05ea \u05d2\u05d3\u05d5\u05dc\u05ea \u05d9\u05d3\u05da \u05d4\u05e7\u05d3\u05d5\u05e9\u05d4 \u05d5\u05d4\u05e0\u05d8\u05d5\u05d9\u05d4. \u05dc\u05e8\u05d0\u05d5\u05ea \u05db\u05d9\u05e6\u05d3 \u05d3\u05e8\u05da \u05d4\u05d7\u05d5\u05e9\u05da \u05d4\u05db\u05d1\u05d3 \u05de\u05d1\u05dc\u05d9\u05d7\u05d9\u05dd \u05e0\u05d9\u05e6\u05d5\u05e6\u05d5\u05ea \u05e9\u05dc \u05d0\u05d5\u05e8 \u05d4\u05de\u05d6\u05db\u05d9\u05e8\u05d9\u05dd \u05dc\u05e0\u05d5 \u05d0\u05ea \u05e0\u05d5\u05db\u05d7\u05d5\u05ea\u05da \u05d4\u05e9\u05dd \u05d9\u05ea\u05d1\u05e8\u05da. \u05d5\u05db\u05da \u05e0\u05d5\u05ea\u05e0\u05d9\u05dd \u05dc\u05d9 \u05db\u05d7 \u05dc\u05e9\u05e8\u05d5\u05d3 \u05e2\u05d3 \u05d4\u05d0\u05d5\u05e8 \u05d4\u05d2\u05d3\u05d5\u05dc\n\u05de\u05dc\u05d1\u05d9\u05e9 \u05e2\u05e8\u05d5\u05de\u05d9\u05dd - \u05ea\u05d5\u05d3\u05d4 \u05e2\u05dc \u05db\u05dc \u05d4\u05dc\u05d1\u05d5\u05e9\u05d9\u05dd \u05d4\u05d2\u05e9\u05de\u05d9\u05d9\u05dd \u05d1\u05d7\u05d9\u05d9. \u05d0\u05e0\u05d9 \u05de\u05d9\u05d9\u05d7\u05dc\u05ea \u05dc\u05e2\u05d8\u05d5\u05e3 \u05d0\u05ea \u05e2\u05e6\u05de\u05d9 \u05d1\u05dc\u05d1\u05d5\u05e9\u05d9\u05dd \u05e8\u05d5\u05d7\u05e0\u05d9\u05d9\u05dd \u05e9\u05d9\u05d2\u05e0\u05d5 \u05e2\u05dc \u05e8\u05d5\u05d7\u05d9 \u05d5\u05e0\u05e9\u05de\u05ea\u05d9 \u05d1\u05d3\u05d9\u05d5\u05e7 \u05db\u05de\u05d5 \u05e9\u05d4\u05dc\u05d1\u05d5\u05e9 \u05d4\u05d2\u05e9\u05de\u05d9 \u05de\u05d2\u05df \u05e2\u05dc \u05d2\u05d5\u05e4\u05d9.\n\u05de\u05ea\u05d9\u05e8 \u05d0\u05e1\u05d5\u05e8\u05d9\u05dd-  \u05ea\u05d5\u05d3\u05d4 \u05e9\u05d0\u05e0\u05d9 \u05de\u05e6\u05dc\u05d9\u05d7\u05d4 \u05dc\u05d4\u05e9\u05ea\u05d7\u05e8\u05e8 \u05de\u05db\u05d1\u05dc\u05d9\u05dd \u05e9\u05de\u05e4\u05e8\u05d9\u05e2\u05d9\u05dd \u05dc\u05d9 \u05dc\u05d4\u05d5\u05e6\u05d9\u05d0 \u05d0\u05dc \u05d4\u05e4\u05d5\u05e2\u05dc \u05d0\u05ea \u05d4\u05d0\u05d5\u05e8 \u05e9\u05d1\u05ea\u05d5\u05db\u05d9. \u05d0\u05e0\u05d9 \u05de\u05ea\u05e4\u05dc\u05dc\u05ea \u05d5\u05de\u05d9\u05d9\u05d7\u05dc\u05ea \u05dc\u05d4\u05e9\u05ea\u05d7\u05e8\u05e8 \u05de\u05db\u05dc \u05db\u05d1\u05dc \u05e9\u05d0\u05d5\u05e1\u05e8 \u05d0\u05d5\u05ea\u05d9 \u05de\u05d4\u05ea\u05e7\u05d3\u05de\u05d5\u05ea \u05d1\u05d7\u05d9\u05d9.\n\u05d6\u05d5\u05e7\u05e3 \u05db\u05e4\u05d5\u05e4\u05d9\u05dd-  \u05ea\u05d5\u05d3\u05d4 \u05e2\u05dc \u05d4\u05d1\u05d9\u05d8\u05d7\u05d5\u05df \u05d4\u05e2\u05e6\u05de\u05d9 \u05e9\u05d9\u05e9 \u05dc\u05d9. \u05d0\u05e0\u05d9 \u05de\u05ea\u05e4\u05dc\u05dc\u05ea \u05d5\u05de\u05d9\u05d9\u05d7\u05dc\u05ea \u05dc\u05d4\u05d6\u05d3\u05e7\u05e3 \u05dc\u05de\u05dc\u05d5\u05d0 \u05e4\u05d5\u05d8\u05e0\u05e6\u05d9\u05d0\u05dc \u05e7\u05d5\u05de\u05ea\u05d9 \u05d5\u05dc\u05d3\u05e2\u05ea \u05e9\u05d9\u05e9 \u05d1\u05d9 \u05d0\u05d5\u05e8 \u05e9\u05e8\u05e7 \u05de\u05d7\u05db\u05d4 \u05dc\u05e4\u05e8\u05d5\u05e5.\n\u05e8\u05d5\u05e7\u05e2 \u05d4\u05d0\u05e8\u05e5 \u05e2\u05dc \u05d4\u05de\u05d9\u05dd - \u05ea\u05d5\u05d3\u05d4 \u05e9\u05d4\u05e2\u05d5\u05dc\u05dd \u05d4\u05db\u05dc\u05dc\u05d9 \u05d5\u05d4\u05e2\u05d5\u05dc\u05dd \u05e9\u05dc\u05d9 \u05e2\u05de\u05d3 \u05e2\u05dc \u05db\u05e0\u05d5. \u05d0\u05e0\u05d9 \u05de\u05ea\u05e4\u05dc\u05dc\u05ea \u05d5\u05de\u05d9\u05d9\u05d7\u05dc\u05ea \u05e9\u05d4\u05e2\u05d5\u05dc\u05dd \u05d9\u05e9\u05de\u05d5\u05e8 \u05e2\u05dc \u05e2\u05e6\u05de\u05d5 \u05d5\u05e9\u05d0\u05e0\u05d5 \u05e0\u05e9\u05de\u05d5\u05e8 \u05e2\u05dc \u05d4\u05e2\u05d5\u05dc\u05dd \u05de\u05d1\u05d7\u05d9\u05e0\u05d4 \u05d2\u05e9\u05de\u05d9\u05ea \u05d0\u05da \u05d1\u05e2\u05d9\u05e7\u05e8 \u05e2\u05e8\u05db\u05d9\u05ea, \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea \u05d5\u05de\u05d5\u05e1\u05e8\u05d9\u05ea.\n\u05e2\u05d5\u05d8\u05e8 \u05d9\u05e9\u05e8\u05d0\u05dc \u05d1\u05ea\u05e4\u05d0\u05e8\u05d4 - \u05ea\u05d5\u05d3\u05d4 \u05e2\u05dc \u05d4\u05d9\u05d5\u05e4\u05d9 \u05e9\u05dc \u05d1\u05e0\u05d9 \u05d4\u05d0\u05d3\u05dd. \u05ea\u05d5\u05d3\u05d4 \u05e2\u05dc \u05d4\u05d6\u05db\u05d5\u05ea \u05dc\u05e8\u05d0\u05d5\u05ea \u05d0\u05ea \u05d4\u05d9\u05d5\u05e4\u05d9 \u05e9\u05dc \u05d1\u05e0\u05d9 \u05d0\u05d3\u05dd. \u05ea\u05df \u05dc\u05d9 \u05d0\u05ea \u05d4\u05db\u05d5\u05d7 \u05dc\u05d4\u05de\u05e9\u05d9\u05da \u05dc\u05d4\u05e9\u05ea\u05e4\u05e8, \u05dc\u05d4\u05d9\u05d5\u05ea \u05d9\u05d5\u05ea\u05e8 \u05d9\u05e4\u05d4 \u05d1\u05d0\u05d9\u05e9\u05d9\u05d5\u05ea\u05d9 \u05d5\u05dc\u05e8\u05d0\u05d5\u05ea \u05d0\u05ea \u05d4\u05d9\u05d5\u05e4\u05d9 \u05e9\u05d1\u05db\u05dc \u05d0\u05d3\u05dd.\n\u05ea\u05d5\u05d3\u05d4 \u05e2\u05dc \u05db\u05d5\u05d7 \u05d4\u05d0\u05d9\u05d6\u05d5\u05df \u05d1\u05d9\u05df \u05d4\u05e0\u05ea\u05d9\u05e0\u05d4 \u05d5\u05d4\u05d0\u05e1\u05e8\u05d8\u05d9\u05d1\u05d9\u05d5\u05ea \u05d1\u05d7\u05d9\u05d9. \u05d0\u05e0\u05d9 \u05de\u05d9\u05d9\u05d7\u05dc\u05ea \u05dc\u05d3\u05e2\u05ea \u05d0\u05ea \u05d4\u05d0\u05d9\u05d6\u05d5\u05df \u05d1\u05db\u05dc \u05e8\u05d2\u05e2.\n\u05e9\u05e2\u05e9\u05d4 \u05dc\u05d9 \u05db\u05dc \u05e6\u05e8\u05db\u05d9 - \u05ea\u05d5\u05d3\u05d4 \u05e2\u05dc \u05db\u05dc \u05de\u05d4 \u05e9\u05d9\u05e9 \u05dc\u05d9: \u05e7\u05d5\u05e8\u05ea \u05d4\u05d2\u05d2, \u05d4\u05d7\u05e9\u05de\u05dc, \u05d4\u05d0\u05d5\u05db\u05dc, \u05d4\u05d0\u05e0\u05e9\u05d9\u05dd \u05e9\u05d0\u05e0\u05d9 \u05d0\u05d5\u05d4\u05d1\u05ea \u05d5\u05e2\u05d5\u05d3 \u05d5\u05e2\u05d5\u05d3. \u05d9\u05d4\u05d9 \u05e8\u05e6\u05d5\u05df \u05e9\u05d0\u05de\u05e9\u05d9\u05da \u05dc\u05d4\u05d5\u05d3\u05d5\u05ea \u05ea\u05de\u05d9\u05d3. \u05d0\u05e0\u05d9 \u05d1\u05d5\u05d7\u05e8\u05ea \u05dc\u05d4\u05de\u05e9\u05d9\u05da \u05e9\u05e4\u05e2 \u05dc\u05d7\u05d9\u05d9 \u05d5\u05dc\u05d7\u05d9\u05d5\u05ea \u05d1\u05ea\u05d5\u05d3\u05e2\u05d4 \u05e9\u05dc \u05d4\u05d5\u05d3\u05d9\u05d4 \u05ea\u05de\u05d9\u05d3.\n\u05d0\u05d5\u05d6\u05e8 \u05d9\u05e9\u05e8\u05d0\u05dc \u05d1\u05d2\u05d1\u05d5\u05e8\u05d4 - \u05ea\u05d5\u05d3\u05d4 \u05e2\u05dc \u05db\u05d5\u05d7 \u05d4\u05d0\u05e1\u05e8\u05d8\u05d9\u05d1\u05d9\u05d5\u05ea \u05d1\u05d7\u05d9\u05d9. \u05d0\u05e0\u05d9 \u05d1\u05d5\u05d7\u05e8\u05ea \u05dc\u05d4\u05e9\u05ea\u05de\u05e9 \u05d1\u05d0\u05e1\u05e8\u05d8\u05d9\u05d1\u05d9\u05d5\u05ea \u05dc\u05d0 \u05e8\u05e7 \u05db\u05d3\u05d9 \u05dc\u05d4\u05d2\u05df \u05e2\u05dc \u05e2\u05e6\u05de\u05d9, \u05d0\u05dc\u05d0 \u05d2\u05dd \u05db\u05d3\u05d9 \u05dc\u05d4\u05d2\u05df \u05e2\u05dc \u05d4\u05e2\u05d5\u05dc\u05dd \u05de\u05e4\u05e0\u05d9 \u05d5\u05de\u05e4\u05e0\u05d9 \u05d0\u05d7\u05e8\u05d9\u05dd.\n\u05ea\u05d5\u05d3\u05d4 \u05e9\u05d9\u05e9 \u05dc\u05d9 \u05db\u05d5\u05d7 \u05e4\u05d9\u05d6\u05d9 \u05d5\u05e0\u05e4\u05e9\u05d9 \u05dc\u05e4\u05e2\u05d5\u05dc \u05d1\u05e2\u05d5\u05dc\u05dd. \u05d0\u05e0\u05d9 \u05de\u05ea\u05e4\u05dc\u05dc\u05ea \u05e9\u05d4\u05db\u05d5\u05d7 \u05d4\u05d6\u05d4 \u05d9\u05de\u05e9\u05d9\u05da.\n---------------------------------------------------------------\n\u05e2\u05d5\u05d3 \u05d3\u05e8\u05da \u05dc\u05d4\u05ea\u05d1\u05d5\u05e0\u05df \u05e2\u05dc \u05d1\u05e8\u05db\u05d5\u05ea \u05d4\u05e9\u05d7\u05e8 \u05db\u05d4\u05e9\u05e8\u05d0\u05d4 \u05dc\u05de\u05e6\u05d9\u05d0\u05ea \u05d4\u05d9\u05d9\u05e2\u05d5\u05d3 \u05d5\u05de\u05d9\u05de\u05d5\u05e9\u05d5\n\u05d1\u05e8\u05db\u05d5\u05ea \u05e2\u05ea\u05d9\u05e7\u05d5\u05ea \u05d0\u05dc\u05d5 \u05d4\u05df \u05dc\u05d0 \u05e8\u05e7 \u05de\u05d9\u05dc\u05d9\u05dd, \u05d0\u05dc\u05d0 \u05e9\u05e2\u05e8\u05d9\u05dd \u05dc\u05e4\u05ea\u05d9\u05d7\u05ea \u05d4\u05ea\u05d5\u05d3\u05e2\u05d4. \u05db\u05dc \u05d0\u05d7\u05ea \u05de\u05d4\u05d1\u05e8\u05db\u05d5\u05ea \u05d4\u05d9\u05d0 \u05e7\u05e8\u05d9\u05d0\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05dc\u05d4\u05ea\u05e2\u05d5\u05e8\u05e8\u05d5\u05ea \u05e2\u05de\u05d5\u05e7\u05d4 \u05d9\u05d5\u05ea\u05e8 \u05d5\u05d2\u05d9\u05dc\u05d5\u05d9 \u05d4\u05d9\u05d9\u05e2\u05d5\u05d3, \u05dc\u05de\u05d9\u05de\u05d5\u05e9 \u05d4\u05e4\u05d5\u05d8\u05e0\u05e6\u05d9\u05d0\u05dc \u05d4\u05d8\u05de\u05d5\u05df \u05d1\u05e0\u05d5, \u05dc\u05d4\u05dc\u05d9\u05db\u05d4 \u05d1\u05ea\u05e9\u05d5\u05de\u05ea \u05dc\u05d1 \u05dc\u05e0\u05e4\u05e9 \u05d5\u05dc\u05e0\u05e9\u05de\u05d4.\n\ud83d\udd39 "\u05d6\u05d5\u05e7\u05e3 \u05db\u05e4\u05d5\u05e4\u05d9\u05dd" \u2013 \u05e7\u05d1\u05dc\u05ea \u05d1\u05d9\u05d8\u05d7\u05d5\u05df \u05e2\u05e6\u05de\u05d9\n\u05db\u05de\u05d4 \u05e4\u05e2\u05de\u05d9\u05dd \u05d4\u05d9\u05d9\u05e0\u05d5 \u05e9\u05e4\u05d5\u05e4\u05d9\u05dd - \u05e0\u05d1\u05d5\u05db\u05d9\u05dd \u05de\u05db\u05d9\u05e9\u05dc\u05d5\u05e0\u05d5\u05ea, \u05e7\u05d5\u05dc\u05d5\u05ea \u05de\u05d4\u05e2\u05d1\u05e8 \u05e9\u05d0\u05de\u05e8\u05d5 \u05dc\u05e0\u05d5 \u05e9\u05d0\u05e0\u05d7\u05e0\u05d5 \u05dc\u05d0 \u05de\u05e1\u05e4\u05d9\u05e7... \u05d6\u05d4 \u05dc\u05d0 \u05d9\u05d9\u05dc\u05da... \u05e0\u05d5\u05dc\u05d3\u05ea \u05e2\u05dd \u05de\u05d8\u05e2\u05df \u05d2\u05e0\u05d8\u05d9 \u05e9\u05dc\u05d9\u05dc\u05d9. \u05d5\u05d4\u05e0\u05d4, \u05e2\u05dd \u05db\u05dc \u05d1\u05d5\u05e7\u05e8 \u05d7\u05d3\u05e9, \u05d4\u05e7\u05d1"\u05d4 \u05d6\u05d5\u05e7\u05e3 \u05d0\u05d5\u05ea\u05e0\u05d5 \u05de\u05d7\u05d3\u05e9. \u05dc\u05d0 \u05e8\u05e7 \u05d0\u05ea \u05d2\u05d5\u05e4\u05e0\u05d5 \u05d0\u05dc\u05d0 \u05d0\u05ea \u05d4\u05e8\u05d5\u05d7! \u05e0\u05d5\u05ea\u05df \u05dc\u05e0\u05d5 \u05d0\u05ea \u05d4\u05d6\u05db\u05d5\u05ea \u05d5\u05d4\u05d9\u05db\u05d5\u05dc\u05ea \u05dc\u05d4\u05d6\u05d3\u05e7\u05e3, \u05dc\u05d4\u05d1\u05d9\u05d8 \u05d0\u05dc \u05d4\u05e2\u05d5\u05dc\u05dd \u05d1\u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05e4\u05e7\u05d5\u05d7\u05d5\u05ea \u05d5\u05d2\u05d1 \u05d6\u05e7\u05d5\u05e3, \u05dc\u05d5\u05de\u05e8: \u05d0\u05e0\u05d9 \u05db\u05d0\u05df. \u05d9\u05e9 \u05dc\u05d9 \u05e9\u05dc\u05d9\u05d7\u05d5\u05ea. \u05d9\u05e9 \u05dc\u05d9 \u05e2\u05e8\u05da.\n\u05dc\u05d4\u05d0\u05de\u05d9\u05df \u05d1\u05d9\u05d5\u05e4\u05d9 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9 \u05d5\u05d1\u05db\u05d5\u05d7\u05d5\u05ea \u05e9\u05dc\u05e0\u05d5 \u05d6\u05d4\u05d5 \u05d4\u05e6\u05e2\u05d3 \u05d4\u05e8\u05d0\u05e9\u05d5\u05df \u05d1\u05d3\u05e8\u05da \u05d4\u05d9\u05d9\u05e2\u05d5\u05d3.\n\ud83d\udd39 "\u05de\u05ea\u05d9\u05e8 \u05d0\u05e1\u05d5\u05e8\u05d9\u05dd" \u05d6\u05d5 \u05d4\u05ea\u05db\u05d5\u05d5\u05e0\u05e0\u05d5\u05ea \u05dc\u05d4\u05ea\u05e8\u05ea \u05db\u05d1\u05dc\u05d9\u05dd \u05ea\u05d5\u05d3\u05e2\u05ea\u05d9\u05d9\u05dd\n\u05dc\u05e4\u05e0\u05d9 \u05e9\u05de\u05ea\u05e7\u05d3\u05de\u05d9\u05dd, \u05e6\u05e8\u05d9\u05da \u05dc\u05e9\u05d7\u05e8\u05e8. \u05d0\u05ea \u05d4\u05e4\u05d7\u05d3\u05d9\u05dd. \u05d0\u05ea \u05d4\u05d0\u05de\u05d5\u05e0\u05d5\u05ea \u05d4\u05de\u05d2\u05d1\u05d9\u05dc\u05d5\u05ea. \u05d0\u05ea \u05de\u05d4 \u05e9"\u05d0\u05de\u05d5\u05e8\u05d9\u05dd" \u05dc\u05d4\u05d9\u05d5\u05ea. \u05db\u05dc \u05d0\u05d5\u05ea\u05dd \u05db\u05d1\u05dc\u05d9\u05dd \u05e9\u05e7\u05e9\u05e8\u05d5 \u05d0\u05d5\u05ea\u05e0\u05d5 \u05e9\u05e0\u05d9\u05dd \u05d1\u05ea\u05d5\u05d3\u05e2\u05d4. \u05d4\u05d1\u05e8\u05db\u05d4 \u05d4\u05d6\u05d5 \u05de\u05d6\u05db\u05d9\u05e8\u05d4 \u05dc\u05e0\u05d5 \u05e9\u05d0\u05e4\u05e9\u05e8 \u05dc\u05e9\u05d7\u05e8\u05e8! \u05d0\u05e4\u05e9\u05e8 \u05dc\u05d1\u05d7\u05d5\u05e8 \u05de\u05d7\u05d3\u05e9!\n\u05db\u05d3\u05d9 \u05dc\u05dc\u05db\u05ea \u05d1\u05d3\u05e8\u05db\u05da, \u05e2\u05dc\u05d9\u05da \u05dc\u05d4\u05e1\u05db\u05d9\u05dd \u05dc\u05d4\u05e8\u05e4\u05d5\u05ea \u05de\u05db\u05dc \u05de\u05d4 \u05e9\u05dc\u05d0 \u05e9\u05dc\u05da \u05d1\u05d0\u05de\u05ea.\n\ud83d\udd39 "\u05d0\u05d5\u05d6\u05e8 \u05d9\u05e9\u05e8\u05d0\u05dc \u05d1\u05d2\u05d1\u05d5\u05e8\u05d4" \u05d0\u05dc\u05d5 \u05ea\u05e2\u05e6\u05d5\u05de\u05d5\u05ea \u05e0\u05e4\u05e9 \u05dc\u05d3\u05d7\u05d5\u05e3 \u05e7\u05d3\u05d9\u05de\u05d4\n\u05dc\u05e6\u05e2\u05d5\u05d3 \u05d1\u05d3\u05e8\u05da \u05d4\u05d7\u05d9\u05d9\u05dd \u05d4\u05d0\u05d5\u05ea\u05e0\u05d8\u05d9\u05ea \u05d3\u05d5\u05e8\u05e9 \u05d0\u05d5\u05de\u05e5. \u05d2\u05d1\u05d5\u05e8\u05d4 \u05d4\u05d9\u05d0 \u05dc\u05d0\u05d5 \u05d3\u05d5\u05d5\u05e7\u05d0 \u05e6\u05e2\u05e7\u05d4 \u05d4\u05d9\u05d0 \u05d4\u05d4\u05ea\u05de\u05d3\u05d4 \u05d4\u05e9\u05e7\u05d8\u05d4, \u05d4\u05d9\u05db\u05d5\u05dc\u05ea \u05dc\u05d4\u05de\u05e9\u05d9\u05da \u05d2\u05dd \u05db\u05e9\u05d0\u05d9\u05df \u05d5\u05d3\u05d0\u05d5\u05ea. \u05dc\u05d0\u05d6\u05d5\u05e8 \u05db\u05d5\u05d7, \u05dc\u05d4\u05d0\u05de\u05d9\u05df \u05e9\u05d5\u05d1, \u05dc\u05e0\u05e1\u05d5\u05ea \u05e9\u05d5\u05d1.\n\u05db\u05e9\u05d0\u05d3\u05dd \u05de\u05d7\u05d5\u05d1\u05e8 \u05dc\u05d9\u05d9\u05e2\u05d5\u05d3\u05d5, \u05de\u05ea\u05e2\u05d5\u05e8\u05e8\u05ea \u05d1\u05d5 \u05d2\u05d1\u05d5\u05e8\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05d6\u05d4 \u05dc\u05d0 \u05e9\u05d4\u05d5\u05d0 \u05dc\u05d0 \u05de\u05e4\u05d7\u05d3, \u05d4\u05d5\u05d0 \u05e4\u05e9\u05d5\u05d8 \u05de\u05d5\u05e0\u05e2 \u05de\u05de\u05e9\u05d4\u05d5 \u05e2\u05de\u05d5\u05e7 \u05d9\u05d5\u05ea\u05e8.\n\ud83d\udd39 "\u05e2\u05d5\u05d8\u05e8 \u05d9\u05e9\u05e8\u05d0\u05dc \u05d1\u05ea\u05e4\u05d0\u05e8\u05d4" \u05d6\u05d4 \u05dc\u05d3\u05d7\u05d5\u05e3 \u05d1\u05e6\u05d5\u05e8\u05d4 \u05e2\u05d3\u05d9\u05e0\u05d4, \u05de\u05ea\u05d5\u05da \u05d4\u05e7\u05e9\u05d1\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea\n\u05d4\u05de\u05d9\u05de\u05d5\u05e9 \u05dc\u05d0 \u05e6\u05e8\u05d9\u05da \u05dc\u05d4\u05d9\u05d5\u05ea \u05db\u05d5\u05d7\u05e0\u05d9. \u05d4\u05d9\u05d5\u05e4\u05d9 \u05d4\u05d5\u05d0 \u05d1\u05d0\u05d9\u05d6\u05d5\u05df. \u05d1\u05d9\u05df \u05d4\u05d0\u05e9 \u05e9\u05dc \u05d4\u05e2\u05e9\u05d9\u05d9\u05d4 \u05dc\u05d1\u05d9\u05df \u05de\u05d9 \u05d4\u05e0\u05e4\u05e9. \u05d1\u05d9\u05df \u05d4\u05e8\u05e6\u05d5\u05df \u05dc\u05e4\u05e8\u05d5\u05e5 \u05dc\u05d1\u05d9\u05df \u05d4\u05d4\u05e7\u05e9\u05d1\u05d4 \u05dc\u05e7\u05e6\u05d1. \u05d6\u05d5 \u05d4"\u05ea\u05e4\u05d0\u05e8\u05ea" \u05d4\u05dc\u05d9\u05db\u05d4 \u05d1\u05e2\u05d3\u05d9\u05e0\u05d5\u05ea \u05e4\u05e0\u05d9\u05de\u05d4 \u05d5\u05d4\u05d7\u05d5\u05e6\u05d4, \u05d4\u05e7\u05e9\u05d1\u05d4 \u05dc\u05e2\u05e6\u05de\u05d9 \u05d5\u05dc\u05e1\u05d5\u05d1\u05d1\u05d9\u05dd.\n\u05de\u05d9\u05de\u05d5\u05e9 \u05d0\u05de\u05d9\u05ea\u05d9 \u05e9\u05dc \u05d9\u05d9\u05e2\u05d5\u05d3 \u05d0\u05d9\u05e0\u05d5 \u05e8\u05e7 \u05d4\u05e9\u05d2\u05ea \u05de\u05d8\u05e8\u05d5\u05ea, \u05d0\u05dc\u05d0 \u05d7\u05d9\u05d9\u05dd \u05e9\u05dc\u05de\u05d9\u05dd \u05e9\u05dc \u05d4\u05e8\u05de\u05d5\u05e0\u05d9\u05d4 \u05d1\u05d9\u05df \u05d4\u05e0\u05e9\u05de\u05d4 \u05dc\u05e4\u05e2\u05d5\u05dc\u05d4.\n\u2728\u05d0\u05d6 \u05d1\u05db\u05dc \u05d1\u05d5\u05e7\u05e8, \u05db\u05e9\u05d0\u05ea\u05d4 \u05d0\u05d5 \u05d0\u05ea \u05de\u05d1\u05e8\u05db\u05d9\u05dd \u05e2\u05e6\u05e8\u05d5 \u05e8\u05d2\u05e2 \u05dc\u05d4\u05e7\u05e9\u05d9\u05d1:\n\u05d4\u05d9\u05db\u05df \u05d0\u05e0\u05d9 \u05d6\u05e7\u05d5\u05e7 \u05dc\u05d4\u05d6\u05d3\u05e7\u05e4\u05d5\u05ea?\n\u05de\u05d4 \u05d0\u05e0\u05d9 \u05de\u05d5\u05db\u05df \u05dc\u05e9\u05d7\u05e8\u05e8?\n\u05d0\u05d9\u05e4\u05d4 \u05e0\u05d3\u05e8\u05e9\u05ea \u05de\u05de\u05e0\u05d9 \u05e2\u05d5\u05d3 \u05d2\u05d1\u05d5\u05e8\u05d4?\n\u05d5\u05d0\u05d9\u05da \u05d0\u05dc\u05da \u05d4\u05d9\u05d5\u05dd \u05d1\u05d3\u05e8\u05db\u05d9, \u05d1\u05ea\u05e4\u05d0\u05e8\u05d4?\n\u05db\u05d9 \u05d4\u05d9\u05d9\u05e2\u05d5\u05d3 \u05e9\u05dc\u05e0\u05d5 \u05d4\u05d5\u05d0 \u05dc\u05d0 \u05e8\u05e7 \u05d4\u05d9\u05e2\u05d3. \u05d4\u05d5\u05d0 \u05d1\u05e2\u05d9\u05e7\u05e8 \u05d4\u05d3\u05e8\u05da. \u05d4\u05d2\u05d9\u05e9\u05d4 \u05e9\u05dc\u05e0\u05d5 \u05dc\u05d7\u05d9\u05d9\u05dd\n\ud83c\udf00 \u05ea\u05e8\u05d2\u05d9\u05dc \u05d4\u05d8\u05de\u05e2\u05d4 \u05dc\u05d9\u05d5\u05dd \u05d7\u05d3\u05e9: "4 \u05e0\u05e9\u05d9\u05de\u05d5\u05ea \u05e9\u05dc \u05d9\u05d9\u05e2\u05d5\u05d3"\n\u05e7\u05d7/\u05d9 \u05db\u05de\u05d4 \u05d3\u05e7\u05d5\u05ea \u05e9\u05e7\u05d8\u05d5\u05ea, \u05d5\u05e9\u05d1/\u05d9 \u05d1\u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05e2\u05e6\u05d5\u05de\u05d5\u05ea. \u05e2\u05dd \u05db\u05dc \u05e0\u05e9\u05d9\u05de\u05d4, \u05d0\u05de\u05d5\u05e8/\u05d9 \u05d1\u05dc\u05d1:\n1.  \u05d0\u05e0\u05d9 \u05de\u05d6\u05d3\u05e7\u05e3/\u05ea. \u05d9\u05e9 \u05dc\u05d9 \u05e2\u05e8\u05da \u05d5\u05e0\u05d5\u05db\u05d7\u05d5\u05ea \u05d1\u05e2\u05d5\u05dc\u05dd\n2.  \u05d0\u05e0\u05d9 \u05de\u05e9\u05d7\u05e8\u05e8/\u05ea \u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05e9\u05db\u05d5\u05d1\u05dc\u05d5\u05ea \u05d0\u05d5\u05ea\u05d9.\n3. \u05d0\u05e0\u05d9 \u05d0\u05d5\u05d6\u05e8/\u05ea \u05d0\u05d5\u05de\u05e5 \u05dc\u05e4\u05e2\u05d5\u05dc \u05d1\u05d0\u05de\u05ea.\n4. \u05d0\u05e0\u05d9 \u05de\u05d0\u05d6\u05d9\u05df/\u05d4 \u05dc\u05e7\u05d5\u05dc \u05d4\u05e0\u05e9\u05de\u05d4 \u05e9\u05dc\u05d9 \u05d5\u05e4\u05d5\u05e2\u05dc/\u05ea \u05d1\u05d4\u05e8\u05de\u05d5\u05e0\u05d9\u05d4.\u05de\u05e9\u05d7\u05e8\u05e8/\u05ea \u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05e9\u05db\u05d5\u05d1\u05dc\u05d5\u05ea \u05d0\u05d5\u05ea\u05d9.\n\u05ea\u05e6\u05d9\u05dc\u05e0\u05d9 \u05de\u05d7\u05d1\u05e8 \u05e8\u05e2\n\ud83c\udf3f \u05e2\u05dc \u05d7\u05d1\u05e8\u05d5\u05ea \u05d0\u05de\u05d9\u05ea\u05d9\u05ea, \u05d5\u05e2\u05dc \u05de\u05d4 \u05e9\u05d0\u05e0\u05d7\u05e0\u05d5 \u05d1\u05d0\u05de\u05ea \u05de\u05d1\u05e7\u05e9\u05d9\u05dd \u05db\u05e9\u05d0\u05e0\u05d7\u05e0\u05d5 \u05d0\u05d5\u05de\u05e8\u05d9\u05dd "\u05d5\u05ea\u05e6\u05d9\u05dc\u05e0\u05d5 \u05de\u05d7\u05d1\u05e8 \u05e8\u05e2" \ud83c\udf3f\n\u05d0\u05d1\u05dc \u05de\u05d4 \u05d6\u05d4 \u05d1\u05e2\u05e6\u05dd \u05d7\u05d1\u05e8 \u05e8\u05e2?\n\u05d6\u05d4 \u05dc\u05d0\u05d5 \u05d3\u05d5\u05d5\u05e7\u05d0 \u05e8\u05e7 \u05de\u05d9\u05e9\u05d4\u05d5 \u05e8\u05e2 \u05dc\u05d1, \u05d0\u05d5 \u05d0\u05dc\u05d9\u05dd.\n\u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05d7\u05d1\u05e8 \u05e8\u05e2 \u05d4\u05d5\u05d0 \u05e4\u05e9\u05d5\u05d8 \u05e7\u05e9\u05e8 \u05e9\u05dc\u05d0 \u05de\u05d9\u05d8\u05d9\u05d1 \u05d0\u05d9\u05ea\u05e0\u05d5. \u05d0\u05d5 \u05e7\u05e9\u05e8 \u05e9\u05e1\u05d9\u05d9\u05dd \u05d0\u05ea \u05ea\u05e4\u05e7\u05d9\u05d3\u05d5. \u05e7\u05e9\u05e8 \u05e9\u05de\u05db\u05e0\u05d9\u05e1 \u05d0\u05d5\u05ea\u05e0\u05d5 \u05dc\u05d1\u05d9\u05e7\u05d5\u05e8\u05ea \u05e2\u05e6\u05de\u05d9\u05ea, \u05dc\u05ea\u05d7\u05d5\u05e9\u05ea \u05d7\u05d5\u05e1\u05e8 \u05e2\u05e8\u05da, \u05dc\u05ea\u05d7\u05e8\u05d5\u05ea \u05d0\u05d5 \u05dc\u05d4\u05e9\u05d5\u05d5\u05d0\u05d4. \u05d7\u05d1\u05e8 \u05e9"\u05de\u05d5\u05e8\u05d9\u05d3" \u05d0\u05d5\u05ea\u05e0\u05d5 \u05d1\u05de\u05e7\u05d5\u05dd \u05dc\u05d4\u05e8\u05d9\u05dd. \u05e7\u05e9\u05e8 \u05e9\u05dc\u05d0 \u05de\u05d0\u05e4\u05e9\u05e8 \u05dc\u05e0\u05d5 \u05dc\u05e6\u05de\u05d5\u05d7 \u05d1\u05d0\u05de\u05ea, \u05dc\u05d4\u05d9\u05d5\u05ea \u05de\u05d9 \u05e9\u05d0\u05e0\u05d7\u05e0\u05d5.\n\u05d5\u05dc\u05e4\u05e2\u05de\u05d9\u05dd, \u05d1\u05dc\u05d9 \u05dc\u05e9\u05d9\u05dd \u05dc\u05d1 - \u05d2\u05dd \u05d0\u05e0\u05d7\u05e0\u05d5 \u05d9\u05db\u05d5\u05dc\u05d9\u05dd \u05dc\u05d4\u05d9\u05d5\u05ea \u05d4\u05d7\u05d1\u05e8 \u05d4\u05d6\u05d4 \u05e2\u05d1\u05d5\u05e8 \u05de\u05d9\u05e9\u05d4\u05d5 \u05d0\u05d7\u05e8. \u05dc\u05db\u05df \u05d6\u05d5 \u05d2\u05dd \u05ea\u05e4\u05d9\u05dc\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea: \u05ea\u05e6\u05d9\u05dc \u05d0\u05d5\u05ea\u05e0\u05d5 \u05de\u05dc\u05d4\u05d9\u05d5\u05ea \u05d1\u05d7\u05d1\u05e8\u05d5\u05bc\u05ea \u05e9\u05d0\u05d9\u05e0\u05d4 \u05de\u05d3\u05d5\u05d9\u05e7\u05ea, \u05e9\u05d0\u05d9\u05e0\u05d4 \u05de\u05d8\u05d9\u05d1\u05d4, \u05e9\u05d0\u05d9\u05e0\u05d4 \u05d1\u05d5\u05e0\u05d4 \u05d0\u05ea \u05d4\u05e0\u05e9\u05de\u05d4 \u05e9\u05dc \u05d0\u05e3 \u05d0\u05d7\u05d3 \u05de\u05d4\u05e6\u05d3\u05d3\u05d9\u05dd.\n\ud83e\udd1d \u05d0\u05d6 \u05de\u05d4 \u05db\u05df? \u05de\u05d4\u05d9 \u05d7\u05d1\u05e8\u05d5\u05ea \u05d8\u05d5\u05d1\u05d4?\n* \u05d7\u05d1\u05e8\u05d5\u05ea \u05d8\u05d5\u05d1\u05d4 \u05d4\u05d9\u05d0 \u05e7\u05e9\u05e8 \u05e9\u05d9\u05e9 \u05d1\u05d5 \u05d4\u05e7\u05e9\u05d1\u05d4 \u05d5\u05dc\u05d0 \u05e8\u05e7 \u05ea\u05d2\u05d5\u05d1\u05d4.\n* \u05d7\u05d1\u05e8\u05d5\u05ea \u05d8\u05d5\u05d1\u05d4 \u05d9\u05d5\u05d3\u05e2\u05ea \u05dc\u05d4\u05db\u05d9\u05dc \u05e9\u05d9\u05e0\u05d5\u05d9 \u05db\u05d9 \u05d0\u05e0\u05d7\u05e0\u05d5 \u05dc\u05d0 \u05d0\u05d5\u05ea\u05df \u05e0\u05e9\u05d9\u05dd \u05d0\u05d5 \u05d0\u05d5\u05ea\u05dd \u05d0\u05e0\u05e9\u05d9\u05dd \u05e9\u05d4\u05d9\u05d9\u05e0\u05d5 \u05dc\u05e4\u05e0\u05d9 \u05e9\u05e0\u05d4.\n* \u05d7\u05d1\u05e8\u05d5\u05ea \u05d8\u05d5\u05d1\u05d4 \u05dc\u05d0 \u05e6\u05e8\u05d9\u05db\u05d4 \u05d4\u05e8\u05d1\u05d4 \u05de\u05d9\u05dc\u05d9\u05dd. \u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05d6\u05d4 \u05de\u05d1\u05d8, \u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05d6\u05d5 \u05e9\u05ea\u05d9\u05e7\u05d4 \u05e9\u05de\u05d1\u05d9\u05e0\u05d4.\n* \u05d7\u05d1\u05e8\u05d5\u05ea \u05d8\u05d5\u05d1\u05d4 \u05de\u05e9\u05d0\u05d9\u05e8\u05d4 \u05de\u05e7\u05d5\u05dd \u05dc\u05d1\u05d7\u05d9\u05e8\u05d4 \u05d5\u05dc\u05d7\u05d5\u05e4\u05e9.\n\ud83c\udf00 \u05d0\u05d9\u05da \u05de\u05d8\u05e4\u05d7\u05d9\u05dd \u05e7\u05e9\u05e8\u05d9\u05dd \u05e9\u05d9\u05d9\u05e9\u05d0\u05e8\u05d5 \u05d7\u05d9\u05d9\u05dd?\n* \u05dc\u05d0 \u05dc\u05e7\u05d7\u05ea \u05db\u05de\u05d5\u05d1\u05df \u05de\u05d0\u05dc\u05d9\u05d5. \u05dc\u05e9\u05dc\u05d5\u05d7 \u05d4\u05d5\u05d3\u05e2\u05d4 \u05d1\u05dc\u05d9 \u05e1\u05d9\u05d1\u05d4, \u05dc\u05d4\u05d6\u05de\u05d9\u05df \u05dc\u05e7\u05e4\u05d4 \u05d1\u05dc\u05d9 \u05ea\u05d9\u05e8\u05d5\u05e5.\n* \u05dc\u05d4\u05d9\u05d5\u05ea \u05d0\u05de\u05d9\u05e6\u05d9\u05dd \u05dc\u05d3\u05d1\u05e8 \u05d2\u05dd \u05e2\u05dc \u05e8\u05d2\u05e2\u05d9\u05dd \u05e9\u05dc \u05e8\u05d9\u05d7\u05d5\u05e7 \u05d0\u05d5 \u05e4\u05d2\u05d9\u05e2\u05d4, \u05d1\u05dc\u05d9 \u05dc\u05d4\u05d9\u05d1\u05d4\u05dc.\n* \u05dc\u05d2\u05dc\u05d5\u05ea \u05e1\u05e7\u05e8\u05e0\u05d5\u05ea \u05de\u05d7\u05d5\u05d3\u05e9\u05ea \u05e2\u05dc \u05de\u05d4 \u05e2\u05d5\u05d1\u05e8 \u05e2\u05dc \u05d4\u05d7\u05d1\u05e8\u05d9\u05dd \u05e9\u05dc\u05d9, \u05de\u05d4 \u05d4\u05e9\u05ea\u05e0\u05d4 \u05d0\u05e6\u05dc\u05dd, \u05de\u05d4 \u05de\u05e9\u05de\u05d7 \u05d0\u05d5\u05ea\u05dd \u05d5\u05de\u05d4 \u05de\u05e6\u05d9\u05e7 \u05dc\u05d4\u05dd.\n\ud83c\udf42 \u05d5\u05d9\u05e9 \u05e2\u05d5\u05d3 \u05de\u05e9\u05d4\u05d5 \u05e9\u05e6\u05e8\u05d9\u05da \u05dc\u05d3\u05e2\u05ea, \u05d2\u05dd \u05d0\u05dd \u05d4\u05d5\u05d0 \u05db\u05d5\u05d0\u05d1 \u05dc\u05e4\u05e2\u05de\u05d9\u05dd:\n\u05dc\u05d0 \u05db\u05dc \u05e7\u05e9\u05e8 \u05e0\u05d5\u05e2\u05d3 \u05dc\u05d4\u05d9\u05e9\u05d0\u05e8 \u05dc\u05e0\u05e6\u05d7.\n\u05d9\u05e9 \u05d7\u05d1\u05e8\u05d5\u05ea \u05e9\u05e0\u05db\u05e0\u05e1\u05d5\u05ea \u05dc\u05d7\u05d9\u05d9\u05e0\u05d5 \u05dc\u05ea\u05e7\u05d5\u05e4\u05d4 \u05db\u05d3\u05d9 \u05dc\u05dc\u05de\u05d3, \u05dc\u05e8\u05e4\u05d0, \u05dc\u05e2\u05d1\u05d5\u05e8 \u05d3\u05e8\u05da \u05d1\u05d9\u05d7\u05d3.\n\u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05d4\u05ea\u05e4\u05e7\u05d9\u05d3 \u05e9\u05dc \u05d4\u05d9\u05d3\u05d9\u05d3\u05d5\u05ea \u05de\u05e1\u05ea\u05d9\u05d9\u05dd.\n\u05d5\u05d6\u05d4 \u05dc\u05d0 \u05db\u05d9\u05e9\u05dc\u05d5\u05df - \u05d6\u05d5 \u05ea\u05e0\u05d5\u05e2\u05d4 \u05d8\u05d1\u05e2\u05d9\u05ea \u05e9\u05dc \u05d4\u05d7\u05d9\u05d9\u05dd.\n\u05dc\u05d3\u05e2\u05ea \u05dc\u05d4\u05d9\u05e4\u05e8\u05d3 \u05d1\u05d0\u05d4\u05d1\u05d4, \u05d0\u05d5 \u05dc\u05e9\u05d9\u05dd \u05e7\u05e9\u05e8 \u05e2\u05dc "\u05d4\u05d5\u05dc\u05d3" \u05db\u05e9\u05e6\u05e8\u05d9\u05da \u05d6\u05d5 \u05d1\u05d2\u05e8\u05d5\u05ea.\n\u05d5\u05d0\u05d5\u05dc\u05d9, \u05d9\u05d5\u05dd \u05d0\u05d7\u05d3, \u05d3\u05e8\u05db\u05e0\u05d5 \u05d9\u05e4\u05d2\u05e9\u05d5 \u05e9\u05d5\u05d1. \u05d5\u05d0\u05d5\u05dc\u05d9 \u05dc\u05d0.\n\u05d0\u05d1\u05dc \u05dc\u05d0 \u05dc\u05ea\u05ea \u05dc\u05dc\u05d1 \u05dc\u05d4\u05d9\u05e9\u05d0\u05e8 \u05db\u05d5\u05e2\u05e1 \u05d0\u05dc\u05d0 \u05dc\u05d4\u05d5\u05d3\u05d5\u05ea \u05e2\u05dc \u05de\u05d4 \u05e9\u05d4\u05d9\u05d4 \u05d5\u05e2\u05dc \u05de\u05d4 \u05e9\u05d9\u05e9 \u05d0\u05d5 \u05d0\u05d9\u05df.\n\u05d0\u05d6 \u05d1\u05d5\u05d0\u05d5 \u05e0\u05d1\u05e7\u05e9 \u05d4\u05d9\u05d5\u05dd \u05e9\u05e0\u05d6\u05db\u05d4 \u05dc\u05e7\u05e9\u05e8\u05d9\u05dd \u05de\u05d9\u05d8\u05d9\u05d1\u05d9\u05dd.\n\u05dc\u05d7\u05d1\u05e8\u05d5\u05bc\u05ea \u05e9\u05de\u05e8\u05d5\u05de\u05de\u05ea \u05d5\u05dc\u05d0 \u05de\u05db\u05d1\u05d9\u05d3\u05d4.\n\u05e9\u05e0\u05b5\u05d3\u05e2 \u05dc\u05d1\u05d7\u05d5\u05e8 \u05d5\u05d2\u05dd \u05dc\u05e9\u05d7\u05e8\u05e8 \u05d1\u05d0\u05d4\u05d1\u05d4.\n\u05d5\u05e9\u05e0\u05d6\u05db\u05d5\u05e8 \u05dc\u05d4\u05d9\u05d5\u05ea \u05e7\u05d5\u05d3\u05dd \u05db\u05dc \u05d7\u05d1\u05e8\u05d9\u05dd \u05d8\u05d5\u05d1\u05d9\u05dd \u05e9\u05dc \u05e2\u05e6\u05de\u05e0\u05d5.\n---------------------------------------------\n\u05e2\u05e7\u05d3\u05ea \u05d9\u05e6\u05d7\u05e7 -  \u05db\u05d9\u05d1\u05d5\u05e9 \u05d4\u05d8\u05d1\u05e2 \u05d5\u05ea\u05e4\u05d9\u05dc\u05d4 \u05e9\u05dc \u05d9\u05d5\u05e9\u05e8\u05d4\n\u05d7\u05d6"\u05dc \u05ea\u05d9\u05e7\u05e0\u05d5 \u05dc\u05d5\u05de\u05e8 \u05d1\u05db\u05dc \u05d1\u05d5\u05e7\u05e8 \u05d5\u05d1\u05e8\u05d0\u05e9 \u05d4\u05e9\u05e0\u05d4 "\u05db\u05de\u05d5 \u05e9\u05db\u05d1\u05e9 \u05d0\u05d1\u05e8\u05d4\u05dd \u05d0\u05d1\u05d9\u05e0\u05d5 \u05d0\u05ea \u05e8\u05d7\u05de\u05d9\u05d5... \u05db\u05df \u05ea\u05db\u05d1\u05d5\u05e9 \u05db\u05e2\u05e1\u05da \u05de\u05e2\u05dc\u05d9\u05e0\u05d5".\n\u05d4\u05de\u05d9\u05dc\u05d9\u05dd \u05d4\u05dc\u05dc\u05d5 \u05de\u05e6\u05d9\u05d1\u05d5\u05ea \u05de\u05e8\u05d0\u05d4 \u05e7\u05e9\u05d4 \u05de\u05d5\u05dc \u05d4\u05dc\u05d1: \u05d0\u05d1\u05e8\u05d4\u05dd \u05e0\u05d3\u05e8\u05e9 \u05dc\u05db\u05d1\u05d5\u05e9 \u05d0\u05ea \u05d4\u05d0\u05d9\u05e0\u05e1\u05d8\u05d9\u05e0\u05e7\u05d8 \u05d4\u05e2\u05de\u05d5\u05e7 \u05d1\u05d9\u05d5\u05ea\u05e8 - \u05e8\u05d7\u05de\u05d9 \u05d0\u05d1 \u05e2\u05dc \u05d1\u05e0\u05d5 \u05d4\u05d9\u05d7\u05d9\u05d3. \u05d3\u05d5\u05d5\u05e7\u05d0 \u05d4\u05d0\u05d4\u05d1\u05d4 \u05d4\u05db\u05d9 \u05de\u05e9\u05de\u05e2\u05d5\u05ea\u05d9\u05ea \u05e0\u05d3\u05e8\u05e9\u05d4 \u05dc\u05e7\u05e8\u05d1\u05df. \u05db\u05de\u05d5 \u05d2\u05dd \u05d0\u05d9 \u05db\u05e0\u05d9\u05e1\u05ea\u05d5 \u05e9\u05dc \u05de\u05e9\u05d4 \u05e8\u05d1\u05e0\u05d5 \u05dc\u05d0\u05e8\u05e5 \u05d9\u05e9\u05e8\u05d0\u05dc.\n\u05db\u05d0\u05e9\u05e8 \u05d0\u05e0\u05d9 \u05e0\u05e2\u05de\u05d3\u05ea \u05d1\u05ea\u05e4\u05d9\u05dc\u05d4, \u05d0\u05e0\u05d9 \u05e9\u05d5\u05de\u05e2\u05ea \u05d0\u05ea \u05d4\u05de\u05d9\u05dc\u05d9\u05dd \u05d4\u05dc\u05dc\u05d5 \u05d5\u05de\u05d4\u05d3\u05d4\u05d3\u05ea \u05d1\u05ea\u05d5\u05db\u05d9 \u05d1\u05e7\u05e9\u05d4: \u05d4\u05dc\u05d5\u05d5\u05d0\u05d9 \u05d5\u05d9\u05d9\u05e0\u05ea\u05df \u05dc\u05d9 \u05d4\u05db\u05d5\u05d7 \u05dc\u05db\u05d1\u05d5\u05e9 \u05d0\u05ea \u05d4\u05d3\u05d7\u05e4\u05d9\u05dd \u05d4\u05e7\u05d8\u05e0\u05d9\u05dd \u05e9\u05de\u05e1\u05d9\u05d8\u05d9\u05dd \u05d0\u05d5\u05ea\u05d9. \u05dc\u05d0 \u05e8\u05d7\u05de\u05d9\u05dd \u05d2\u05d3\u05d5\u05dc\u05d9\u05dd \u05db\u05de\u05d5 \u05e9\u05dc \u05d0\u05d1\u05e8\u05d4\u05dd, \u05d0\u05dc\u05d0 \u05db\u05e2\u05e1 \u05e8\u05d2\u05e2\u05d9, \u05d0\u05d2\u05d5 \u05de\u05ea\u05e4\u05e8\u05e5, \u05ea\u05d0\u05d5\u05d5\u05ea \u05e7\u05d8\u05e0\u05d5\u05ea \u05e9\u05de\u05d5\u05e9\u05db\u05d5\u05ea \u05d0\u05d5\u05ea\u05d9 \u05de\u05df \u05d4\u05d3\u05e8\u05da. \u05d0\u05dd \u05d4\u05d5\u05d0 \u05d4\u05e6\u05dc\u05d9\u05d7 \u05dc\u05d4\u05ea\u05d2\u05d1\u05e8 \u05e2\u05dc \u05dc\u05d1 \u05d0\u05d1, \u05d0\u05d5\u05dc\u05d9 \u05d2\u05dd \u05d0\u05e0\u05d9 \u05d0\u05e6\u05dc\u05d9\u05d7 \u05dc\u05d4\u05ea\u05d2\u05d1\u05e8 \u05e2\u05dc \u05d4\u05e4\u05d9\u05ea\u05d5\u05d9 \u05d4\u05e4\u05e9\u05d5\u05d8 \u05e9\u05dc \u05d9\u05d5\u05dd\u05be\u05d9\u05d5\u05dd.\n\u05d0\u05d1\u05dc \u05d9\u05e9 \u05db\u05d0\u05df \u05e2\u05d5\u05d3 \u05e7\u05d5\u05dc, \u05e7\u05d5\u05dc \u05d4\u05d3\u05d5\u05e8 \u05d4\u05d6\u05d4. \u05d9\u05e6\u05d7\u05e7 \u05d0\u05de\u05e0\u05dd \u05dc\u05d0 \u05e0\u05e2\u05e7\u05d3 \u05d1\u05e4\u05d5\u05e2\u05dc \u05d0\u05dc\u05d0 \u05e8\u05e7 \u05d4\u05d9\u05d4 \u05de\u05d5\u05db\u05df, \u05d5\u05d0\u05d9\u05dc\u05d5 \u05d1\u05e2\u05e9\u05d5\u05e8\u05d9\u05dd \u05d4\u05d0\u05d7\u05e8\u05d5\u05e0\u05d9\u05dd \u05d5\u05d1\u05e2\u05d9\u05e7\u05e8 \u05d1\u05e9\u05e0\u05d9\u05dd \u05d4\u05d0\u05d7\u05e8\u05d5\u05e0\u05d5\u05ea \u05e0\u05e2\u05e7\u05d3\u05d5 \u05d0\u05dc\u05e4\u05d9 \u05d9\u05e6\u05d7\u05e7\u05d9\u05dd \u05de\u05de\u05e9. \u05de\u05e9\u05e4\u05d7\u05d5\u05ea \u05e9\u05dc\u05de\u05d5\u05ea \u05e9\u05d9\u05dc\u05de\u05d5 \u05de\u05d7\u05d9\u05e8 \u05d7\u05d9\u05d9\u05dd. \u05d5\u05d1\u05db\u05dc \u05d6\u05d0\u05ea, \u05d0\u05d5\u05ea\u05df \u05de\u05e9\u05e4\u05d7\u05d5\u05ea \u05dc\u05d0 \u05d6\u05e0\u05d7\u05d5 \u05d0\u05ea \u05d0\u05de\u05d5\u05e0\u05ea\u05df. \u05d4\u05df \u05de\u05de\u05e9\u05d9\u05db\u05d5\u05ea \u05dc\u05d4\u05ea\u05e4\u05dc\u05dc, \u05dc\u05e7\u05d9\u05d9\u05dd \u05de\u05e6\u05d5\u05d5\u05ea, \u05dc\u05d3\u05d1\u05d5\u05e7 \u05d1\u05d7\u05d9\u05d9\u05dd. \u05d4\u05d0\u05de\u05d5\u05e0\u05d4 \u05e9\u05dc\u05d4\u05df \u05d0\u05d9\u05e0\u05d4 \u05d0\u05de\u05d5\u05e0\u05d4 \u05dc\u05de\u05e8\u05d5\u05ea \u05d7\u05d5\u05e1\u05e8 \u05e0\u05d5\u05d7\u05d5\u05ea \u05d0\u05dc\u05d0 \u05d0\u05de\u05d5\u05e0\u05d4 \u05e9\u05de\u05dc\u05de\u05d3\u05ea \u05e9\u05d2\u05dd \u05d1\u05db\u05d0\u05d1 \u05d4\u05db\u05d9 \u05d2\u05d3\u05d5\u05dc \u05d0\u05e4\u05e9\u05e8 \u05dc\u05d3\u05d1\u05d5\u05e7 \u05d1\u05db\u05d5\u05d7\u05d5\u05ea \u05d4\u05e8\u05d5\u05d7. \u05d0\u05e4\u05e9\u05e8 \u05dc\u05e9\u05d0\u05d5\u05e3 \u05db\u05dc\u05e4\u05d9 \u05de\u05e2\u05dc\u05d4 \u05d2\u05dd \u05d1\u05db\u05d0\u05d1 \u05d4\u05db\u05d9 \u05d2\u05d3\u05d5\u05dc. \u05db\u05e9\u05d0\u05e0\u05d5 \u05de\u05d1\u05e7\u05e9\u05d9\u05dd \u05e8\u05d7\u05de\u05d9\u05dd, \u05d0\u05e0\u05d5 \u05de\u05d1\u05e7\u05e9\u05d9\u05dd \u05d1\u05d6\u05db\u05d5\u05ea\u05dd.\n\u05d0\u05dc\u05d0 \u05e9\u05d4\u05d9\u05d5\u05e9\u05e8\u05d4 \u05e9\u05dc\u05d9 \u05d0\u05d9\u05e0\u05d4 \u05e0\u05d5\u05ea\u05e0\u05ea \u05dc\u05d9 \u05dc\u05d4\u05e1\u05ea\u05e4\u05e7 \u05d1\u05db\u05da. \u05d0\u05d9\u05e0\u05d9 \u05e8\u05d5\u05e6\u05d4 \u05dc\u05d4\u05d9\u05e9\u05e2\u05df \u05e8\u05e7 \u05e2\u05dc \u05d0\u05d1\u05d5\u05ea\u05d9\u05d9 \u05d0\u05d5 \u05e2\u05dc \u05de\u05e9\u05e4\u05d7\u05d5\u05ea \u05d0\u05d7\u05e8\u05d5\u05ea \u05e9\u05e0\u05e9\u05d0\u05d5 \u05d1\u05d3\u05dd \u05d0\u05ea \u05e2\u05d5\u05dc \u05d4\u05d0\u05de\u05d5\u05e0\u05d4. \u05ea\u05e4\u05d9\u05dc\u05ea\u05d9 \u05de\u05d7\u05d9\u05d9\u05d1\u05ea \u05d0\u05d5\u05ea\u05d9 \u05dc\u05e9\u05d0\u05d5\u05dc: \u05de\u05d4\u05d5 \u05d4\u05e7\u05e8\u05d1\u05df \u05e9\u05dc\u05d9? \u05de\u05d4\u05d9 \u05d7\u05d5\u05e1\u05e8 \u05d4\u05e0\u05d5\u05d7\u05d5\u05ea \u05e9\u05d0\u05e0\u05d9 \u05de\u05d5\u05db\u05e0\u05d4 \u05dc\u05d4\u05e0\u05d9\u05d7 \u05e2\u05dc \u05d4\u05de\u05d6\u05d1\u05d7?\n\u05dc\u05d0 \u05d7\u05d9\u05d9 \u05e0\u05d3\u05e8\u05e9\u05d9\u05dd \u05de\u05de\u05e0\u05d9, \u05d0\u05dc\u05d0 \u05de\u05e9\u05d4\u05d5 \u05e7\u05d8\u05df \u05d1\u05d4\u05e8\u05d1\u05d4. \u05dc\u05d5\u05d5\u05ea\u05e8 \u05e2\u05dc \u05d7\u05d5\u05e1\u05e8 \u05e0\u05d5\u05d7\u05d5\u05ea, \u05e2\u05dc \u05ea\u05e1\u05db\u05d5\u05dc, \u05dc\u05d7\u05e4\u05e9 \u05d9\u05ea\u05e8 \u05e1\u05d1\u05dc\u05e0\u05d5\u05ea, \u05d5\u05dc\u05d5\u05d5\u05ea\u05e8 \u05e2\u05dc \u05e2\u05d9\u05e7\u05e9\u05d5\u05ea \u05e9\u05d0\u05d9\u05df \u05d1\u05d4 \u05e6\u05d5\u05e8\u05da. \u05db\u05dc \u05d5\u05d9\u05ea\u05d5\u05e8 \u05db\u05d6\u05d4, \u05d0\u05dd \u05d4\u05d5\u05d0 \u05e0\u05e2\u05e9\u05d4 \u05dc\u05e9\u05dd \u05e9\u05de\u05d9\u05d9\u05dd, \u05d4\u05d5\u05d0 \u05e2\u05e7\u05d3\u05d4. \u05d4\u05d5\u05d0 \u05de\u05d1\u05d8\u05d0 \u05d0\u05ea \u05e0\u05db\u05d5\u05e0\u05d5\u05ea\u05d9 \u05dc\u05d7\u05d9\u05d5\u05ea \u05d1\u05d9\u05d5\u05e9\u05e8 \u05de\u05d5\u05dc \u05d4\u05e7\u05d1"\u05d4 \u05d5\u05de\u05d5\u05dc \u05d1\u05e0\u05d9 \u05d0\u05d3\u05dd, \u05dc\u05d0 \u05e8\u05e7 \u05dc\u05d1\u05e7\u05e9 \u05d0\u05dc\u05d0 \u05d2\u05dd \u05dc\u05ea\u05ea.\n\u05d5\u05d9\u05e9 \u05e4\u05d4 \u05e8\u05d5\u05d1\u05d3 \u05e0\u05d5\u05e1\u05e3. \u05db\u05de\u05d5 \u05de\u05e9\u05d4 \u05e8\u05d1\u05e0\u05d5 \u05d1\u05d6\u05de\u05e0\u05d5 \u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05d4\u05e2\u05e7\u05d3\u05d4 \u05e9\u05dc\u05e0\u05d5 \u05d0\u05d9\u05e0\u05e0\u05d4 \u05d5\u05d9\u05ea\u05d5\u05e8 \u05e2\u05dc \u05e0\u05d5\u05d7\u05d5\u05ea \u05d0\u05dc\u05d0 \u05d3\u05d5\u05d5\u05e7\u05d0 \u05d4\u05d9\u05db\u05d5\u05dc\u05ea \u05dc\u05e7\u05d1\u05dc \u05d0\u05ea \u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea \u05d1\u05e0\u05d7\u05ea. \u05dc\u05e9\u05e0\u05d5\u05ea \u05d0\u05ea \u05de\u05d1\u05d8\u05e0\u05d5 \u05e2\u05dc \u05db\u05d0\u05d1 \u05e9\u05db\u05d1\u05e8 \u05e7\u05d9\u05d9\u05dd. \u05dc\u05d0 \u05dc\u05d1\u05e8\u05d5\u05d7 \u05de\u05de\u05e0\u05d5, \u05dc\u05d0 \u05dc\u05d8\u05e9\u05d8\u05e9 \u05d0\u05d5\u05ea\u05d5, \u05d0\u05dc\u05d0 \u05dc\u05d2\u05e9\u05ea \u05d0\u05dc\u05d9\u05d5 \u05d1\u05d2\u05d9\u05e9\u05d4 \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea \u05d0\u05e4\u05d9\u05dc\u05d5 \u05d7\u05d9\u05d5\u05d1\u05d9\u05ea. \u05dc\u05d4\u05e4\u05d5\u05da \u05d0\u05ea \u05d4\u05e4\u05e6\u05e2 \u05dc\u05de\u05e7\u05d5\u05e8 \u05e9\u05dc \u05d0\u05de\u05d5\u05e0\u05d4, \u05d0\u05ea \u05d4\u05d7\u05e1\u05e8\u05d5\u05df \u05dc\u05de\u05e7\u05d5\u05dd \u05e9\u05dc \u05d7\u05d9\u05d1\u05d5\u05e8, \u05d0\u05ea \u05d4\u05d3\u05de\u05e2\u05d4 \u05dc\u05de\u05e2\u05d9\u05d9\u05df \u05e9\u05dc \u05ea\u05e4\u05d9\u05dc\u05d4. \u05d6\u05d5 \u05e2\u05e7\u05d3\u05d4 \u05e9\u05e7\u05d8\u05d4, \u05e4\u05e0\u05d9\u05de\u05d9\u05ea - \u05e7\u05d1\u05dc\u05ea \u05d4\u05db\u05d0\u05d1 \u05db\u05d7\u05dc\u05e7 \u05de\u05de\u05e1\u05e2 \u05d4\u05e0\u05e9\u05de\u05d4, \u05d5\u05d4\u05e4\u05d9\u05db\u05ea\u05d5 \u05dc\u05e7\u05e8\u05d1\u05df \u05e8\u05e6\u05d5\u05df \u05dc\u05e4\u05e0\u05d9 \u05d4\u05d1\u05d5\u05e8\u05d0.\n\u05db\u05da \u05d4\u05d5\u05e4\u05db\u05ea \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05de\u05de\u05d9\u05dc\u05d9\u05dd \u05dc\u05de\u05e2\u05e9\u05d4. \u05d4\u05d9\u05d0 \u05d0\u05d9\u05e0\u05d4 \u05de\u05d1\u05e7\u05e9\u05ea \u05de\u05de\u05e0\u05d9 \u05e8\u05e7 \u05dc\u05e9\u05d0\u05ea \u05ea\u05d7\u05d9\u05e0\u05d4, \u05d0\u05dc\u05d0 \u05dc\u05d4\u05e9\u05ea\u05e0\u05d5\u05ea. \u05dc\u05d4\u05e4\u05d5\u05da \u05db\u05dc \u05d7\u05d5\u05e1\u05e8 \u05e0\u05d5\u05d7\u05d5\u05ea \u05dc\u05e7\u05e8\u05d1\u05df \u05e7\u05d8\u05df, \u05db\u05dc \u05d5\u05d9\u05ea\u05d5\u05e8 \u05dc\u05d7\u05d5\u05dc\u05d9\u05d4 \u05e0\u05d5\u05e1\u05e4\u05ea \u05d1\u05e9\u05e8\u05e9\u05e8\u05ea \u05d7\u05d9\u05d6\u05d5\u05e7 \u05d4\u05d0\u05de\u05d5\u05e0\u05d4 \u05e9\u05de\u05de\u05e9\u05d9\u05db\u05d4 \u05de\u05d3\u05d5\u05e8 \u05dc\u05d3\u05d5\u05e8. \u05d4\u05db\u05d0\u05d1 \u05e2\u05e6\u05de\u05d5, \u05db\u05e9\u05d0\u05e0\u05d9 \u05e0\u05d5\u05e9\u05d0\u05ea \u05d0\u05d5\u05ea\u05d5 \u05d1\u05d0\u05de\u05d5\u05e0\u05d4 \u05d5\u05d1\u05d8\u05d5\u05d1, \u05e0\u05e2\u05e9\u05d4 \u05e2\u05e7\u05d3\u05ea \u05d9\u05e6\u05d7\u05e7 \u05e9\u05dc\u05d9 \u05d1\u05e4\u05d5\u05e2\u05dc.\n\u05e4\u05e1\u05d5\u05e7\u05d9 \u05d3\u05d6\u05d9\u05de\u05e8\u05d4\n\u05d5\u05d9\u05e9\u05d1\u05e8 \u05d4\' \u05d0\u05ea \u05d0\u05e8\u05d6\u05d9 \u05d4\u05dc\u05d1\u05e0\u05d5\u05df \u2014 \u05d5\u05d9\u05e8\u05e7\u05d9\u05d3\u05dd \u05db\u05de\u05d5 \u05e2\u05d2\u05dc.\n\u05d4\u05de\u05d7\u05e1\u05d5\u05dd \u05d4\u05db\u05d9 \u05d2\u05d3\u05d5\u05dc \u05dc\u05e9\u05de\u05d7\u05d4 \u05d4\u05d5\u05d0 \u05d4\u05d2\u05d0\u05d5\u05d5\u05d4.\n\u05d4\u05d0\u05e8\u05d6 \u2014 \u05d4\u05e2\u05e5 \u05d4\u05d2\u05d1\u05d5\u05d4 \u05d5\u05d4\u05d7\u05d6\u05e7 \u2014 \u05de\u05e1\u05de\u05dc \u05d0\u05ea \u05d4\u05d0\u05d3\u05dd \u05d4\u05de\u05ea\u05e0\u05e9\u05d0, \u05d4\u05d1\u05d8\u05d5\u05d7 \u05d1\u05e2\u05e6\u05de\u05d5, \u05d4\u05d1\u05dc\u05ea\u05d9 \u05e0\u05d9\u05ea\u05df \u05dc\u05d4\u05d6\u05d6\u05d4. \u05d0\u05d1\u05dc \u05d3\u05d5\u05d5\u05e7\u05d0 \u05ea\u05d7\u05d5\u05e9\u05ea \u05d4\u05e2\u05dc\u05d9\u05d5\u05e0\u05d5\u05ea \u05d4\u05d6\u05d5 \u05e1\u05d5\u05d2\u05e8\u05ea \u05d0\u05ea \u05d4\u05dc\u05d1, \u05de\u05e7\u05e4\u05d9\u05d0\u05d4 \u05d0\u05ea \u05d4\u05e8\u05d2\u05e9, \u05d5\u05de\u05d5\u05e0\u05e2\u05ea \u05ea\u05e0\u05d5\u05e2\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea.\n\u05db\u05d3\u05d9 \u05dc\u05e8\u05e7\u05d5\u05d3, \u05e6\u05e8\u05d9\u05da \u05e8\u05d5\u05da, \u05d2\u05de\u05d9\u05e9\u05d5\u05ea, \u05e4\u05ea\u05d9\u05d7\u05d5\u05ea. \u05dc\u05db\u05df \u05d4\' \u05e9\u05d5\u05d1\u05e8 \u05d0\u05ea \u05d4\u05d0\u05e8\u05d6  \u05e9\u05d5\u05d1\u05e8\u05ea \u05d4\u05d2\u05d0\u05d5\u05d5\u05d4 \u05d5\u05d0\u05d6 \u05d0\u05e4\u05e9\u05e8 "\u05d5\u05d9\u05e8\u05e7\u05d9\u05d3\u05dd \u05db\u05de\u05d5 \u05e2\u05d2\u05dc": \u05db\u05de\u05d5 \u05e2\u05d2\u05dc \u05e8\u05da, \u05e6\u05e2\u05d9\u05e8, \u05e9\u05de\u05d7 \u05d5\u05de\u05e9\u05d5\u05d7\u05e8\u05e8.\n\u05e8\u05e7 \u05db\u05d0\u05e9\u05e8 \u05d4\u05d0\u05d3\u05dd \u05de\u05e9\u05d9\u05dc \u05de\u05e2\u05dc\u05d9\u05d5 \u05d0\u05ea \u05ea\u05d7\u05d5\u05e9\u05ea \u05d4\u05d4\u05ea\u05e0\u05e9\u05d0\u05d5\u05ea, \u05d4\u05d5\u05d0 \u05e0\u05e2\u05e9\u05d4 \u05e7\u05dc \u05d9\u05d5\u05ea\u05e8, \u05e4\u05ea\u05d5\u05d7 \u05d9\u05d5\u05ea\u05e8 \u05d5\u05d0\u05d6 \u05d2\u05dd \u05d4\u05e9\u05de\u05d7\u05d4 \u05d9\u05db\u05d5\u05dc\u05d4 \u05dc\u05e4\u05e8\u05d5\u05e5.\n\u05db\u05da \u05e0\u05d4\u05d2 \u05d3\u05d5\u05d3 \u05d4\u05de\u05dc\u05da, \u05e9"\u05d5\u05bc\u05d3\u05b8\u05d5\u05b4\u05d3 \u05de\u05b0\u05db\u05b7\u05e8\u05b0\u05db\u05b5\u05bc\u05e8 \u05d1\u05b0\u05bc\u05db\u05b8\u05dc \u05e2\u05b9\u05d6 \u05dc\u05b4\u05e4\u05b0\u05e0\u05b5\u05d9 \u05d4\'" \u05dc\u05de\u05e8\u05d5\u05ea \u05d4\u05d9\u05d5\u05ea\u05d5 \u05de\u05dc\u05da, \u05dc\u05d1\u05d5\u05e9 \u05d1\u05d0\u05e4\u05d5\u05d3 \u05d1\u05d3 \u05e4\u05e9\u05d5\u05d8, \u05d4\u05d5\u05d0 \u05dc\u05d0 \u05d4\u05ea\u05d1\u05d9\u05d9\u05e9 \u05dc\u05d4\u05e9\u05e4\u05d9\u05dc \u05d0\u05ea \u05e2\u05e6\u05de\u05d5 \u05d5\u05dc\u05e8\u05e7\u05d5\u05d3 \u05d1\u05db\u05dc \u05db\u05d5\u05d7\u05d5 \u05dc\u05e4\u05e0\u05d9 \u05d4\'. \u05db\u05e9\u05de\u05d9\u05db\u05dc \u05d1\u05ea \u05e9\u05d0\u05d5\u05dc \u05dc\u05e2\u05d2\u05d4 \u05dc\u05d5 \u05e2\u05dc \u05db\u05da, \u05d4\u05d5\u05d0 \u05e2\u05e0\u05d4 \u05dc\u05d4: "\u05d5\u05e0\u05e7\u05dc\u05d5\u05ea\u05d9 \u05e2\u05d5\u05d3 \u05de\u05d6\u05d0\u05ea" \u05d3\u05d5\u05d5\u05e7\u05d0 \u05d1\u05e2\u05e0\u05d5\u05d5\u05d4, \u05d1\u05d1\u05d9\u05d8\u05d5\u05dc \u05d4\u05d0\u05d2\u05d5, \u05d4\u05d5\u05d0 \u05d6\u05db\u05d4 \u05dc\u05e9\u05de\u05d7\u05d4 \u05d4\u05d0\u05de\u05d9\u05ea\u05d9\u05ea, \u05dc\u05e9\u05db\u05d9\u05e0\u05d4, \u05dc\u05e0\u05d1\u05d5\u05d0\u05d4, \u05d5\u05dc\u05e0\u05e6\u05d7\u05d9\u05d5\u05ea.\n\u05d0\u05d3\u05dd \u05de\u05ea\u05dc\u05d5\u05e0\u05df \u05e9\u05d0\u05d9\u05df \u05dc\u05d5 \u05e9\u05de\u05d7\u05d4 \u05d0\u05d1\u05dc \u05d7\u05e1\u05e8\u05d4 \u05dc\u05e0\u05d5 \u05e9\u05de\u05d7\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05db\u05d9 \u05d0\u05e0\u05d7\u05e0\u05d5 \u05dc\u05d0 \u05de\u05ea\u05e0\u05d9\u05e2\u05d9\u05dd \u05d0\u05d5\u05ea\u05d4 \u05d1\u05ea\u05e4\u05d9\u05dc\u05d4. \u05d4\u05e9\u05d9\u05e8\u05d4 \u05d5\u05d4\u05e8\u05d9\u05e7\u05d5\u05d3 \u05d1\u05ea\u05e4\u05d9\u05dc\u05d4 \u05de\u05d5\u05e1\u05d9\u05e4\u05d9\u05dd \u05ea\u05d7\u05d5\u05e9\u05ea \u05d4\u05e7\u05dc\u05d4 \u05d5\u05d4\u05e2\u05e8\u05db\u05d4 \u05dc\u05d7\u05d9\u05d9\u05dd. \u05ea\u05d7\u05d5\u05e9\u05ea \u05e7\u05dc\u05d9\u05dc\u05d5\u05ea \u05d5\u05de\u05e1\u05d5\u05d2\u05dc\u05d5\u05ea \u05dc\u05d4\u05ea\u05de\u05d5\u05d3\u05d3 \u05e2\u05dd \u05db\u05dc \u05d0\u05ea\u05d2\u05e8. \u05d5\u05d0\u05d6 \u05e0\u05d5\u05e1\u05e4\u05ea \u05ea\u05d7\u05d5\u05e9\u05ea \u05d4\u05d4\u05e6\u05dc\u05d7\u05d4 \u05d5\u05d4\u05e1\u05d9\u05e4\u05d5\u05e7. \u05d0\u05d1\u05dc \u05d4\u05db\u05dc \u05d4\u05ea\u05d7\u05d9\u05dc \u05de\u05ea\u05d7\u05d5\u05e9\u05ea \u05d4\u05d4\u05d5\u05d3\u05d9\u05d4 \u05e9\u05d4\u05ea\u05e0\u05e2\u05e0\u05d5 \u05d1\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d1\u05e9\u05d9\u05e8\u05d4 \u05d5\u05e8\u05d9\u05e7\u05d5\u05d3\n"\u05e2\u05b2\u05e9\u05b5\u05c2\u05d4 \u05e2\u05b4\u05de\u05b8\u05bc\u05e0\u05d5\u05bc \u05e6\u05b0\u05d3\u05b8\u05e7\u05b8\u05d4 \u05d5\u05b8\u05d7\u05b6\u05e1\u05b6\u05d3 \u05d1\u05b7\u05bc\u05e2\u05b2\u05d1\u05d5\u05bc\u05e8 \u05e9\u05b4\u05c1\u05de\u05b0\u05da\u05b8 \u05d4\u05b7\u05d2\u05b8\u05bc\u05d3\u05d5\u05b9\u05dc"\n\u05d1\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d6\u05d5 \u05d9\u05e9 \u05e2\u05d5\u05de\u05e7 \u05de\u05d9\u05d5\u05d7\u05d3: \u05d4\u05d9\u05d0 \u05e0\u05e8\u05d0\u05d9\u05ea \u05dc\u05db\u05d0\u05d5\u05e8\u05d4 \u05db\u05d1\u05e7\u05e9\u05d4 \u05d0\u05d9\u05e9\u05d9\u05ea \u05e9\u05e0\u05e7\u05d1\u05dc \u05d7\u05e1\u05d3, \u05e8\u05d7\u05de\u05d9\u05dd, \u05d9\u05e9\u05d5\u05e2\u05d4. \u05d0\u05da \u05de\u05ea\u05d7\u05ea \u05dc\u05de\u05d9\u05dc\u05d9\u05dd \u05de\u05e1\u05ea\u05ea\u05e8\u05ea \u05e2\u05de\u05d3\u05d4 \u05d4\u05e4\u05d5\u05db\u05d4 \u05db\u05de\u05e2\u05d8: \u05dc\u05d0 \u05d0\u05e0\u05d7\u05e0\u05d5 \u05d1\u05de\u05e8\u05db\u05d6 \u05d0\u05dc\u05d0 \u05d4\' \u05d5\u05e9\u05de\u05d5 \u05d1\u05e2\u05d5\u05dc\u05dd.\n\u05d1\u05d3\u05e8\u05da \u05db\u05dc\u05dc \u05d0\u05e0\u05d5 \u05e8\u05d2\u05d9\u05dc\u05d9\u05dd \u05dc\u05d4\u05ea\u05e4\u05dc\u05dc \u05d1\u05dc\u05e9\u05d5\u05df \u05ea\u05d7\u05e0\u05d5\u05e0\u05d9\u05dd: "\u05ea\u05df \u05dc\u05e0\u05d5", "\u05d4\u05d5\u05e9\u05d9\u05e2 \u05d0\u05d5\u05ea\u05e0\u05d5", "\u05e8\u05e4\u05d0 \u05d0\u05d5\u05ea\u05e0\u05d5". \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d4\u05d6\u05d5 \u05de\u05d6\u05db\u05d9\u05e8\u05d4 \u05dc\u05e0\u05d5 \u05de\u05de\u05d3 \u05d0\u05d7\u05e8.\n\u05dc\u05d0 \u05e8\u05e7 \u05d1\u05e7\u05e9\u05d4 \u05d0\u05dc\u05d0 \u05d4\u05e6\u05d4\u05e8\u05d4.\n\u05d0\u05e0\u05d7\u05e0\u05d5 \u05d0\u05d5\u05de\u05e8\u05d9\u05dd \u05dc\u05d4\u2019: \u05d0\u05ea\u05d4 \u05d4\u05e8\u05d9 \u05e8\u05d5\u05e6\u05d4 \u05e9\u05d9\u05d4\u05d9\u05d4 \u05dc\u05e0\u05d5 \u05d8\u05d5\u05d1, \u05db\u05d9 \u05d0\u05e0\u05d5 \u05d9\u05dc\u05d3\u05d9\u05da, \u05d5\u05db\u05dc \u05d8\u05d5\u05d1 \u05e9\u05de\u05d2\u05d9\u05e2 \u05dc\u05e0\u05d5 \u05de\u05d0\u05d9\u05e8 \u05d0\u05ea \u05e9\u05de\u05da \u05d1\u05e2\u05d5\u05dc\u05dd. \u05dc\u05d0 \u05de\u05d3\u05d5\u05d1\u05e8 \u05e8\u05e7 \u05d1\u05d1\u05e7\u05e9\u05d4 \u05d0\u05e0\u05d5\u05db\u05d9\u05ea, \u05d0\u05dc\u05d0 \u05d1\u05d3\u05d0\u05d2\u05d4 \u05dc"\u05db\u05d1\u05d5\u05d3 \u05e9\u05de\u05d9\u05d9\u05dd".\n\u05db\u05da \u05d4\u05d5\u05e4\u05db\u05ea \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05dc\u05e9\u05d9\u05d7\u05d4 \u05d1\u05e2\u05dc\u05ea \u05e8\u05d5\u05d1\u05d3 \u05e0\u05d5\u05e1\u05e3 \u05e2\u05dd \u05d4\u2019:\n\u05d0\u05e0\u05d7\u05e0\u05d5 \u05de\u05d1\u05e7\u05e9\u05d9\u05dd \u05dc\u05d0 \u05e8\u05e7 \u05de\u05e4\u05e0\u05d9 \u05e9\u05d0\u05e0\u05d5 \u05d6\u05e7\u05d5\u05e7\u05d9\u05dd, \u05d0\u05dc\u05d0 \u05de\u05e4\u05e0\u05d9 \u05e9\u05d0\u05ea\u05d4, \u05e8\u05d9\u05d1\u05d5\u05e0\u05d5 \u05e9\u05dc \u05e2\u05d5\u05dc\u05dd, \u05e8\u05d5\u05e6\u05d4 \u05d1\u05d8\u05d5\u05d1\u05ea\u05d9. \u05db\u05d9 \u05db\u05e9\u05d0\u05e0\u05d7\u05e0\u05d5 \u05d7\u05d9\u05d9\u05dd \u05d1\u05d0\u05d5\u05e8, \u05e9\u05de\u05da \u05d9\u05ea\u05e7\u05d3\u05e9 \u05d1\u05e2\u05d5\u05dc\u05dd.\n\u05d5\u05db\u05d0\u05df \u05e0\u05db\u05e0\u05e1\u05ea \u05d2\u05dd \u05d4\u05d0\u05de\u05d9\u05e8\u05d4 \u05d4\u05e0\u05d5\u05e7\u05d1\u05ea \u05e9\u05dc \u05e2\u05d5\u05de\u05e8 \u05e9\u05dd\u05be\u05d8\u05d5\u05d1, \u05de\u05d4\u05d7\u05d8\u05d5\u05e4\u05d9\u05dd \u05e9\u05e9\u05d1\u05d5 \u05de\u05e2\u05d6\u05d4: "\u05db\u05d5\u05dc\u05dd \u05de\u05d1\u05e7\u05e9\u05d9\u05dd \u05de\u05d0\u05dc\u05d5\u05d4\u05d9\u05dd, \u05d0\u05d1\u05dc \u05de\u05d9 \u05e9\u05d5\u05d0\u05dc \u05d0\u05d5\u05ea\u05d5 \u05de\u05d4 \u05e9\u05dc\u05d5\u05de\u05d5?"\n\u05d4\u05de\u05e9\u05e4\u05d8 \u05d4\u05d6\u05d4 \u05e4\u05d5\u05ea\u05d7 \u05e4\u05ea\u05d7 \u05d7\u05d3\u05e9 \u05dc\u05d4\u05d1\u05e0\u05ea \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4.\n\u05d1\u05de\u05e7\u05d5\u05dd \u05dc\u05e8\u05d0\u05d5\u05ea \u05d0\u05ea \u05d4\u05e7\u05e9\u05e8 \u05e2\u05dd \u05d4\u2019 \u05db\u05e2\u05e8\u05d5\u05e5 \u05d7\u05d3\u05be\u05db\u05d9\u05d5\u05d5\u05e0\u05d9 \u05e9\u05dc \u05d1\u05e7\u05e9\u05d5\u05ea, \u05d0\u05e4\u05e9\u05e8 \u05dc\u05e8\u05d0\u05d5\u05ea \u05d0\u05ea \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d2\u05dd \u05db\u05e9\u05d5\u05ea\u05e4\u05d5\u05ea. \u05d0\u05e0\u05d7\u05e0\u05d5 \u05d3\u05d5\u05d0\u05d2\u05d9\u05dd \u05dc\u05d5, \u05dc\u05e9\u05de\u05d5, \u05dc\u05de\u05e2\u05de\u05d3\u05d5 \u05d1\u05e2\u05d5\u05dc\u05dd.\n"\u05e2\u05e9\u05d4 \u05e2\u05de\u05e0\u05d5 \u05e6\u05d3\u05e7\u05d4 \u05d5\u05d7\u05e1\u05d3 \u05d1\u05e2\u05d1\u05d5\u05e8 \u05e9\u05de\u05da \u05d4\u05d2\u05d3\u05d5\u05dc" \u05d6\u05d5 \u05d0\u05d9\u05e0\u05d4 \u05e8\u05e7 \u05d1\u05e7\u05e9\u05d4 \u05dc\u05e8\u05d7\u05de\u05d9\u05dd, \u05d0\u05dc\u05d0 \u05de\u05d7\u05d5\u05d5\u05d4 \u05e9\u05dc \u05d0\u05d4\u05d1\u05d4. \u05d4\u05e6\u05d4\u05e8\u05d4 \u05e9\u05de\u05d5\u05db\u05e0\u05d4 \u05dc\u05d4\u05e0\u05d9\u05d7 \u05d1\u05e6\u05d3 \u05d0\u05ea \u05d4\u05d0\u05e0\u05d5\u05db\u05d9\u05d5\u05ea \u05d5\u05dc\u05d5\u05de\u05e8: \u05e8\u05d1\u05d5\u05e0\u05d5 \u05e9\u05dc \u05e2\u05d5\u05dc\u05dd, \u05d2\u05dd \u05dc\u05da \u05de\u05d2\u05d9\u05e2 \u05e9\u05d9\u05d4\u05d9\u05d4 \u05dc\u05da \u05d8\u05d5\u05d1. \u05e9\u05de\u05da \u05d9\u05ea\u05d2\u05d3\u05dc, \u05d5\u05e9\u05de\u05da \u05d9\u05d0\u05d4\u05d1 \u05d1\u05e2\u05d5\u05dc\u05dd.\n\u05d6\u05d5 \u05ea\u05e4\u05d9\u05dc\u05d4 \u05d4\u05e4\u05d5\u05ea\u05d7\u05ea \u05d0\u05ea \u05d4\u05dc\u05d1 \u05dc\u05e8\u05d0\u05d5\u05ea \u05d0\u05ea \u05d4\u05d6\u05d5\u05dc\u05ea \u05de\u05ea\u05d5\u05da \u05ea\u05e8\u05d2\u05d5\u05dc \u05dc\u05e8\u05d0\u05d5\u05ea \u05d0\u05ea \u05d4\u05e6\u05d5\u05e8\u05da \u05e9\u05dc \u05d0\u05dc\u05d5\u05d4\u05d9\u05dd, \u05db\u05d1\u05e1\u05d9\u05e1 \u05dc\u05db\u05dc \u05d4\u05d9\u05d7\u05e1\u05d9\u05dd \u05e9\u05dc\u05e0\u05d5 \u05e2\u05dd \u05d1\u05e0\u05d9 \u05d0\u05d3\u05dd. \u05ea\u05e4\u05d9\u05dc\u05d4 \u05d6\u05d5 \u05de\u05dc\u05de\u05d3\u05ea \u05d0\u05d5\u05ea\u05e0\u05d5 \u05e9\u05d9\u05d7\u05e1\u05d9\u05dd \u05d0\u05de\u05d9\u05ea\u05d9\u05d9\u05dd - \u05d0\u05e4\u05d9\u05dc\u05d5 \u05e2\u05dd \u05d0\u05dc\u05d5\u05e7\u05d9\u05dd - \u05d0\u05d9\u05e0\u05dd \u05e8\u05e7 \u05dc\u05e7\u05d7\u05ea, \u05d0\u05dc\u05d0 \u05d2\u05dd \u05dc\u05ea\u05ea.\n_____________\n"\u05d9\u05d4\u05d5\u05d4 \u05d1\u05e8\u05e6\u05d5\u05e0\u05da \u05d4\u05e2\u05de\u05d3\u05ea \u05dc\u05d4\u05e8\u05e8\u05d9 \u05e2\u05d6, \u05d4\u05e1\u05ea\u05e8\u05ea \u05e4\u05e0\u05d9\u05da \u05d4\u05d9\u05d9\u05ea\u05d9 \u05e0\u05d1\u05d4\u05dc.."\n\u05d3\u05de\u05d9\u05d9\u05e0\u05d5 \u05e9\u05db\u05dc \u05d0\u05ea\u05d2\u05e8 \u05d0\u05d5 \u05e6\u05e8\u05d4 \u05d1\u05d7\u05d9\u05d9\u05dd \u05e9\u05dc\u05e0\u05d5 \u05d4\u05d5\u05d0 \u05d4\u05e8, \u05e7\u05e9\u05d4 \u05dc\u05e2\u05d1\u05d5\u05e8 \u05d0\u05d5\u05ea\u05d5, \u05d0\u05da \u05d9\u05e9 \u05dc\u05e0\u05d5 \u05e2\u05d6, \u05db\u05d5\u05d7\u05d5\u05ea \u05e0\u05e4\u05e9\u05d9\u05d9\u05dd \u05dc\u05e2\u05d1\u05d5\u05e8 \u05d0\u05d5\u05ea\u05d5.\n\u05d4\u05e2\u05d5\u05d6 \u05de\u05d2\u05d9\u05e2 \u05de\u05d9\u05d4\u05d5\u05d4.\n\u05d3\u05de\u05d9\u05d9\u05e0\u05d5 \u05d0\u05d5\u05e8 \u05d2\u05d3\u05d5\u05dc \u05d3\u05d5\u05d7\u05e3 \u05d0\u05d5\u05ea\u05e0\u05d5 \u05dc\u05d4\u05ea\u05d2\u05d1\u05e8 \u05e2\u05dc \u05d4\u05d0\u05ea\u05d2\u05e8 \u05d1\u05d7\u05d9\u05d9\u05dd, \u05d5\u05d2\u05dd \u05d0\u05d5\u05e8 \u05d2\u05d3\u05d5\u05dc, \u05d7\u05dd \u05d5\u05e0\u05e2\u05d9\u05dd, \u05de\u05d5\u05e9\u05da \u05d0\u05d5\u05ea\u05e0\u05d5 \u05dc\u05d8\u05e4\u05e1 \u05e2\u05dc \u05d4\u05d4\u05e8. \u05d0\u05dd \u05d6\u05d4 \u05d0\u05d3\u05dd \u05e9\u05e7\u05e9\u05d4 \u05dc\u05e0\u05d5 \u05dc\u05ea\u05e7\u05e9\u05e8 \u05d0\u05ea\u05d5, \u05d3\u05de\u05d9\u05d9\u05e0\u05d5 \u05d0\u05ea \u05d4\u05d0\u05d3\u05dd \u05de\u05d5\u05e7\u05e3 \u05d1\u05d4\u05d9\u05dc\u05d4 \u05e9\u05dc \u05d0\u05d5\u05e8. \u05e2\u05db\u05e9\u05d9\u05d5 \u05d3\u05de\u05d9\u05d9\u05e0\u05d5 \u05e9\u05d0\u05e0\u05d5 \u05e0\u05d9\u05d2\u05e9\u05d9\u05dd \u05d0\u05dc\u05d9\u05d5 \u05d1\u05de\u05d9\u05dc\u05d9\u05dd \u05d8\u05d5\u05d1\u05d5\u05ea, \u05d1\u05d8\u05d5\u05df \u05e2\u05d3\u05d9\u05df \u05d5\u05de\u05e4\u05d9\u05d9\u05e1, \u05d1\u05d0\u05d4\u05d1\u05d4. \u05e2\u05db\u05e9\u05d9\u05d5 \u05d3\u05de\u05d9\u05d9\u05e0\u05d5 \u05e9\u05d4\u05d5\u05d0 \u05de\u05e7\u05d1\u05dc \u05d0\u05d5\u05ea\u05e0\u05d5 \u05d0\u05dc \u05ea\u05d5\u05da \u05d4\u05d9\u05dc\u05ea \u05d4\u05d0\u05d5\u05e8 \u05e9\u05dc\u05d5, \u05d5\u05d0\u05e0\u05d5 \u05de\u05d5\u05e7\u05e4\u05d9\u05dd \u05e9\u05e0\u05d9\u05e0\u05d5 \u05d1\u05d4\u05d9\u05dc\u05ea \u05d4\u05d0\u05d5\u05e8 \u05e9\u05dc\u05d5. \u05d0\u05e0\u05d5 \u05e4\u05d5\u05e0\u05d9\u05dd \u05d0\u05dc\u05d9\u05d5 \u05d1\u05de\u05d9\u05dc\u05d9\u05dd \u05e0\u05e2\u05d9\u05de\u05d5\u05ea \u05d5\u05d4\u05d5\u05d0 \u05de\u05d7\u05d6\u05d9\u05e8 \u05dc\u05e0\u05d5 \u05d1\u05de\u05d9\u05dc\u05d9\u05dd \u05d8\u05d5\u05d1\u05d5\u05ea \u05d5\u05e0\u05e2\u05d9\u05de\u05d5\u05ea.\n-----------------------------------------------------\n\u05d3\u05de\u05d9\u05d9\u05e0\u05d5 \u05d0\u05ea \u05d4\u05de\u05e8\u05d0\u05d9\u05d9\u05df \u05de\u05d5\u05e7\u05e3 \u05d1\u05d0\u05d5\u05e8 \u05d7\u05de\u05d9\u05dd \u05d5\u05e0\u05e2\u05d9\u05dd. \u05d3\u05de\u05d9\u05d9\u05e0\u05d5 \u05d0\u05d5\u05ea\u05d5 \u05de\u05e7\u05d1\u05dc \u05d0\u05d5\u05ea\u05e0\u05d5 \u05d1\u05d7\u05d9\u05d5\u05da, \u05de\u05e1\u05ea\u05db\u05dc \u05e2\u05dc \u05e7\u05d5\u05e8\u05d5\u05ea \u05d4\u05d7\u05d9\u05d9\u05dd \u05e9\u05dc\u05e0\u05d5 \u05d1\u05d4\u05e2\u05e8\u05db\u05d4. \u05d5\u05d0\u05d6 \u05d4\u05d5\u05d0 \u05de\u05d1\u05d9\u05d8 \u05d0\u05dc\u05d9\u05db\u05dd \u05d1\u05d4\u05e2\u05e8\u05db\u05d4, \u05de\u05d1\u05e7\u05e9 \u05dc\u05d3\u05e2\u05ea \u05e2\u05d5\u05d3 \u05e4\u05e8\u05d8\u05d9\u05dd \u05e2\u05dc \u05de\u05d4 \u05e9\u05d0\u05ea\u05dd \u05d9\u05d5\u05d3\u05e2\u05d9\u05dd, \u05d5\u05de\u05e7\u05d1\u05dc \u05d0\u05ea\u05db\u05dd \u05d1\u05d4\u05e2\u05e8\u05db\u05d4 \u05dc\u05e2\u05d1\u05d5\u05d3\u05d4. \u05d1\u05e1\u05d5\u05e4\u05d5 \u05e9\u05dc \u05d3\u05d1\u05e8, \u05d4\u05d5\u05d0 \u05de\u05e6\u05d9\u05e2 \u05dc\u05db\u05dd \u05d0\u05ea \u05d4\u05de\u05e9\u05db\u05d5\u05e8\u05ea \u05e9\u05e8\u05e6\u05d9\u05ea\u05dd.\n-------------------------------------------------------------------------------------------------\n\u05e8\u05d5\u05d7 \u05d4\u05e7\u05d5\u05d3\u05e9 \u05d0\u05d5 \u05e0\u05d1\u05d5\u05d0\u05d4\n\u05d0\u05e0\u05d5 \u05e0\u05d5\u05d8\u05d9\u05dd \u05dc\u05d7\u05e9\u05d5\u05d1 \u05e9\u05d4\u05d3\u05e8\u05d2\u05d4 \u05d4\u05db\u05d9 \u05d2\u05d1\u05d5\u05d4\u05d4 \u05e9\u05d0\u05d3\u05dd \u05d9\u05db\u05d5\u05dc \u05dc\u05d4\u05e9\u05d9\u05d2 \u05d4\u05d9\u05d0 \u05e0\u05d1\u05d5\u05d0\u05d4. \u05d6\u05d4 \u05d9\u05db\u05d5\u05dc \u05dc\u05d4\u05d9\u05d5\u05ea \u05e0\u05d7\u05de\u05d3 \u05dc\u05d3\u05e2\u05ea \u05de\u05d4 \u05d4\u05d9\u05d4 \u05d5\u05de\u05d4 \u05d9\u05d4\u05d9\u05d4. \u05d0\u05da \u05d9\u05e9 \u05de\u05e9\u05d4\u05d5 \u05d0\u05e4\u05d9\u05dc\u05d5 \u05d9\u05d5\u05ea\u05e8 \u05d7\u05e9\u05d5\u05d1: \u05dc\u05d3\u05e2\u05ea \u05de\u05d4 \u05e7\u05d5\u05e8\u05d4 \u05e2\u05db\u05e9\u05d9\u05d5. \u05dc\u05d3\u05e2\u05ea \u05d0\u05ea \u05d4\u05de\u05d4\u05d5\u05ea \u05e9\u05dc \u05db\u05dc \u05e8\u05d2\u05e2. \u05d4\u05d0\u05d9\u05e9\u05d1\u05d9\u05e6\u05e8 \u05d0\u05d5\u05de\u05e8 \u05e9\u05d6\u05d4 \u05dc\u05d0 \u05e0\u05db\u05d5\u05df \u05dc\u05d7\u05e9\u05d5\u05d1 \u05e9\u05e0\u05d1\u05d5\u05d0\u05d4 \u05d4\u05d9\u05d0 \u05d4\u05e9\u05d0\u05d9\u05e4\u05d4 \u05d4\u05d2\u05d1\u05d5\u05d4\u05d4 \u05d1\u05d9\u05d5\u05ea\u05e8. \u05d4\u05d5\u05d0 \u05d8\u05d5\u05e2\u05df \u05e9\u05d9\u05d9\u05ea\u05db\u05df \u05e9\u05ea\u05d4\u05d9\u05d4 \u05e0\u05d1\u05d9\u05d0 \u05e9\u05d9\u05d5\u05d3\u05e2 \u05de\u05d4 \u05d4\u05d9\u05d4 \u05d5\u05de\u05d4 \u05d9\u05d4\u05d9\u05d4, \u05d0\u05d1\u05dc \u05d0\u05d9\u05df \u05dc\u05da \u05e9\u05de\u05e5 \u05e9\u05dc \u05de\u05d5\u05e9\u05d2 \u05de\u05d4 \u05d4\u05ea\u05e4\u05e7\u05d9\u05d3 \u05e9\u05dc\u05da \u05d1\u05e2\u05d5\u05dc\u05dd. \u05dc\u05de\u05d4 \u05d0\u05ea\u05d4 \u05db\u05d0\u05df? \u05d6\u05d4 \u05d4\u05e8\u05d1\u05d4 \u05d9\u05d5\u05ea\u05e8 \u05e2\u05de\u05d5\u05e7 \u05de\u05e0\u05d1\u05d5\u05d0\u05d4.\n\u05d4\u05de\u05d0\u05d1\u05e7 \u05d4\u05d0\u05de\u05d9\u05ea\u05d9 \u05d4\u05d5\u05d0 \u05dc\u05d0 \u05dc\u05d3\u05e2\u05ea \u05d0\u05ea \u05d4\u05e2\u05ea\u05d9\u05d3 \u05d0\u05d5 \u05d0\u05ea \u05d4\u05e2\u05d1\u05e8, \u05d0\u05dc\u05d0 \u05dc\u05d3\u05e2\u05ea \u05de\u05d4 \u05d4\u05ea\u05e4\u05e7\u05d9\u05d3 \u05e9\u05dc\u05d9 \u05db\u05d0\u05df \u05d5\u05e2\u05db\u05e9\u05d9\u05d5, \u05d1\u05db\u05dc \u05e8\u05d2\u05e2. \u05dc\u05de\u05d4 \u05e0\u05d5\u05dc\u05d3\u05ea\u05d9 \u05d1\u05d6\u05de\u05df \u05d4\u05d6\u05d4, \u05d1-1983 \u05d5\u05dc\u05d0 \u05d1-1883, \u05d1\u05d6\u05de\u05df \u05e9\u05dc \u05e1\u05d1\u05d0 \u05e8\u05d1\u05d0 \u05e9\u05dc\u05d9? \u05d7\u05e9\u05d5\u05d1 \u05d4\u05e8\u05d1\u05d4 \u05d9\u05d5\u05ea\u05e8 \u05dc\u05d3\u05e2\u05ea \u05d0\u05ea \u05de\u05d4\u05d5\u05ea \u05e7\u05d9\u05d5\u05de\u05e0\u05d5, \u05d0\u05ea \u05d4\u05ea\u05e4\u05e7\u05d9\u05d3 \u05e9\u05dc\u05e0\u05d5 \u05d1\u05e8\u05d2\u05e2 \u05d4\u05d6\u05d4.\n\u05de\u05d4\u05d5\u05ea \u05d4\u05e2\u05d5\u05dc\u05dd \u05d4\u05d9\u05d0 \u05dc\u05d7\u05d9\u05d5\u05ea \u05d0\u05ea \u05d4\u05e8\u05d2\u05e2, \u05dc\u05d3\u05e2\u05ea \u05d0\u05ea \u05d4\u05ea\u05e4\u05e7\u05d9\u05d3 \u05e9\u05dc\u05d9 \u05d1\u05db\u05dc \u05e8\u05d2\u05e2 \u05d5\u05e8\u05d2\u05e2. \u05dc\u05d3\u05e2\u05ea \u05d0\u05ea \u05d6\u05d4 \u05d3\u05d5\u05e8\u05e9 \u05d7\u05d9\u05d1\u05d5\u05e8 \u05dc\u05de\u05e7\u05d5\u05dd \u05d4\u05db\u05d9 \u05e2\u05dc\u05d9\u05d5\u05df \u2014 \u05d6\u05d5 \u05d4\u05d4\u05ea\u05d2\u05dc\u05d5\u05ea \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9\u05ea \u05d4\u05d2\u05d1\u05d5\u05d4\u05d4 \u05d1\u05d9\u05d5\u05ea\u05e8. \u05d0\u05d3\u05dd \u05d9\u05db\u05d5\u05dc \u05dc\u05d4\u05d9\u05d5\u05ea \u05de\u05e7\u05d5\u05d1\u05dc \u05d0\u05d5 \u05dc\u05e2\u05e9\u05d5\u05ea \u05e0\u05d9\u05e1\u05d9\u05dd \u05d2\u05d3\u05d5\u05dc\u05d9\u05dd \u05d5\u05e2\u05d3\u05d9\u05d9\u05df \u05dc\u05d0 \u05dc\u05d3\u05e2\u05ea \u05d0\u05ea \u05ea\u05e4\u05e7\u05d9\u05d3\u05d5 \u05d1\u05e2\u05d5\u05dc\u05dd. \u05d4\u05d1\u05e2\u05e9"\u05d8 \u05d4\u05e7\u05d3\u05d5\u05e9 \u05e9\u05d9\u05e0\u05d4 \u05d0\u05ea \u05d4\u05e4\u05d5\u05e7\u05d5\u05e1. \u05d4\u05de\u05d8\u05e8\u05d4 \u05d4\u05d9\u05d0 \u05dc\u05d0 \u05dc\u05d3\u05e2\u05ea \u05db\u05d9\u05e6\u05d3 \u05dc\u05e2\u05d1\u05d5\u05e8 \u05de\u05de\u05e7\u05d5\u05dd \u05dc\u05de\u05e7\u05d5\u05dd \u05d0\u05d5 \u05dc\u05e9\u05dc\u05d5\u05d8 \u05d1\u05d6\u05de\u05e0\u05d9\u05dd \u05d5\u05de\u05e8\u05d7\u05d1\u05d9\u05dd.\n\u05d4\u05d4\u05d1\u05e0\u05d4 \u05d4\u05d0\u05de\u05d9\u05ea\u05d9\u05ea \u05d4\u05d9\u05d0 \u05dc\u05e2\u05d1\u05d5\u05d3 \u05d0\u05ea \u05d4\u05e9\u05dd \u05d1\u05e8\u05de\u05d4 \u05d4\u05db\u05d9 \u05e2\u05de\u05d5\u05e7\u05d4 \u05d1\u05db\u05dc \u05e8\u05d2\u05e2. \u05dc\u05d4\u05d9\u05d5\u05ea \u05de\u05d7\u05d5\u05d1\u05e8 \u05dc\u05e2\u05d5\u05de\u05e7 \u05d4\u05e7\u05d9\u05d5\u05dd \u05e9\u05dc \u05db\u05dc \u05e8\u05d2\u05e2.\n\u05d4\u05d4\u05db\u05e0\u05d4 \u05dc\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4\n\u05d1\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9\u05ea \u05d0\u05e0\u05d5 \u05e9\u05de\u05d9\u05dd \u05dc\u05d1 \u05dc\u05e6\u05d5\u05e8\u05d4 \u05e9\u05d1\u05d4 \u05d0\u05e0\u05d5 \u05d9\u05d5\u05e9\u05d1\u05d9\u05dd, \u05dc\u05d0\u05df \u05e4\u05e0\u05d9\u05e0\u05d5 \u05de\u05d5\u05e4\u05e0\u05d5\u05ea, \u05d5\u05db\u05d9\u05e6\u05d3 \u05d0\u05e0\u05d5 \u05e0\u05d5\u05e9\u05de\u05d9\u05dd. \u05d1\u05e0\u05d9\u05d2\u05d5\u05d3 \u05dc\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d4\u05e2\u05d5\u05dc\u05de\u05d9\u05ea, \u05e9\u05d1\u05d4 \u05d4\u05de\u05d8\u05e8\u05d4 \u05d4\u05d9\u05d0 \u05dc\u05e4\u05e0\u05d5\u05ea \u05d0\u05ea \u05d4\u05de\u05d7\u05e9\u05d1\u05d5\u05ea, \u05d1\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9\u05ea \u05d4\u05de\u05d8\u05e8\u05d4 \u05d4\u05d9\u05d0 \u05dc\u05db\u05d5\u05d5\u05df \u05d0\u05ea \u05d4\u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05dc\u05de\u05d7\u05e9\u05d1\u05d5\u05ea \u05d4\u05e8\u05e6\u05d5\u05d9\u05d5\u05ea. \u05db\u05d9\u05e6\u05d3 \u05e0\u05e2\u05e9\u05d4 \u05d6\u05d0\u05ea?\n\u05d4\u05db\u05d9\u05d5\u05d5\u05df \u05d4\u05d5\u05d0 \u05dc\u05d0 \u05d1\u05d4\u05db\u05e8\u05d7 \u05dc\u05d4\u05e4\u05e1\u05d9\u05e7 \u05d0\u05ea \u05d4\u05de\u05d7\u05e9\u05d1\u05d5\u05ea, \u05d0\u05dc\u05d0 \u05dc\u05e2\u05e6\u05d1 \u05d0\u05d5\u05ea\u05df \u05db\u05da \u05e9\u05d9\u05ea\u05de\u05e7\u05d3\u05d5 \u05d1\u05e0\u05d5\u05e9\u05d0\u05d9\u05dd \u05d5\u05d1\u05db\u05d9\u05d5\u05d5\u05e0\u05d9\u05dd \u05e9\u05de\u05d5\u05d1\u05d9\u05dc\u05d9\u05dd \u05d0\u05d5\u05ea\u05e0\u05d5 \u05dc\u05d4\u05ea\u05d7\u05d1\u05e8\u05d5\u05ea \u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05e2\u05de\u05d5\u05e7\u05d4 \u05d9\u05d5\u05ea\u05e8 \u05e2\u05dd \u05e2\u05e6\u05de\u05e0\u05d5 \u05d5\u05e2\u05dd \u05d4\u05d1\u05e8\u05d9\u05d0\u05d4.\n\u05db\u05d9\u05e6\u05d3 \u05d9\u05d5\u05e9\u05d1\u05d9\u05dd \u05d1\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9\u05ea\n\u05d1\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9\u05ea, \u05d1\u05e0\u05d9\u05d2\u05d5\u05d3 \u05dc\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d4\u05e2\u05d5\u05dc\u05de\u05d9\u05ea, \u05d9\u05d5\u05e9\u05d1\u05d9\u05dd \u05e2\u05dd \u05d4\u05e8\u05d2\u05dc\u05d9\u05d9\u05dd \u05e2\u05dc \u05d4\u05e7\u05e8\u05e7\u05e2 \u05d5\u05d9\u05d3\u05d9\u05d9\u05dd \u05e4\u05ea\u05d5\u05d7\u05d5\u05ea \u05db\u05dc\u05e4\u05d9 \u05d4\u05e9\u05de\u05d9\u05d9\u05dd. \u05d9\u05e9 \u05dc\u05db\u05da \u05db\u05de\u05d4 \u05de\u05e9\u05de\u05e2\u05d5\u05d9\u05d5\u05ea.\n\u05e8\u05d0\u05e9\u05d9\u05ea, \u05d0\u05e0\u05d5 \u05e8\u05d5\u05e6\u05d9\u05dd \u05dc\u05d4\u05d7\u05d9\u05dc \u05e2\u05dc \u05d4\u05de\u05d5\u05d3\u05e2\u05d5\u05ea \u05e9\u05dc\u05e0\u05d5 \u05d0\u05ea \u05d4\u05d7\u05d9\u05d1\u05d5\u05e8 \u05d1\u05d9\u05df \u05e9\u05de\u05d9\u05d9\u05dd \u05d5\u05d0\u05e8\u05e5. \u05d4\u05e8\u05d2\u05dc\u05d9\u05d9\u05dd \u05e4\u05e8\u05d5\u05e1\u05d5\u05ea \u05e2\u05dc \u05d4\u05e7\u05e8\u05e7\u05e2, \u05de\u05d9\u05d9\u05e6\u05d2\u05d5\u05ea \u05d0\u05ea \u05d4\u05d7\u05d9\u05d1\u05d5\u05e8 \u05e9\u05dc\u05e0\u05d5 \u05dc\u05d0\u05d3\u05de\u05d4, \u05d5\u05d9\u05d3\u05d9\u05e0\u05d5 \u05de\u05d5\u05e4\u05e0\u05d5\u05ea \u05db\u05dc\u05e4\u05d9 \u05d4\u05e9\u05de\u05d9\u05d9\u05dd, \u05de\u05d9\u05d9\u05e6\u05d2\u05d5\u05ea \u05d0\u05ea \u05d4\u05e7\u05e9\u05e8 \u05e2\u05dd \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9\u05d5\u05ea \u05d5\u05d4\u05d1\u05e8\u05db\u05d4 \u05d4\u05e2\u05dc\u05d9\u05d5\u05e0\u05d4.\n\u05e9\u05e0\u05d9\u05ea, \u05d0\u05e0\u05d5 \u05e9\u05d5\u05d0\u05d1\u05d9\u05dd \u05d0\u05e0\u05e8\u05d2\u05d9\u05d4 \u05de\u05d4\u05e9\u05de\u05d9\u05d9\u05dd \u05d5\u05de\u05e2\u05d1\u05d9\u05e8\u05d9\u05dd \u05d0\u05d5\u05ea\u05d4 \u05dc\u05d9\u05d3\u05d9 \u05d1\u05d9\u05e6\u05d5\u05e2 \u05d1\u05e2\u05d5\u05dc\u05dd \u05d4\u05d6\u05d4. \u05d1\u05db\u05da \u05d0\u05e0\u05d5 \u05de\u05d6\u05db\u05d9\u05e8\u05d9\u05dd \u05dc\u05e2\u05e6\u05de\u05e0\u05d5 \u05e9\u05d4\u05d7\u05d9\u05d9\u05dd \u05de\u05e7\u05d5\u05e8\u05dd \u05d1\u05d1\u05e8\u05db\u05d4 (\u05de\u05d6\u05dc) \u05de\u05d4\u05e9\u05de\u05d9\u05d9\u05dd, \u05d0\u05da \u05d4\u05d4\u05e9\u05ea\u05d3\u05dc\u05d5\u05ea \u05d1\u05e2\u05d5\u05dc\u05dd \u05d4\u05d6\u05d4 \u05d4\u05d9\u05d0 \u05e2\u05dc\u05d9\u05e0\u05d5. \u05db\u05e9\u05e0\u05e6\u05dc\u05d9\u05d7, \u05e0\u05d6\u05db\u05d5\u05e8 \u05e9\u05dc\u05d0 \u05d1\u05d6\u05db\u05d5\u05ea \u05e2\u05e6\u05de\u05e0\u05d5 \u05d4\u05e6\u05dc\u05d7\u05ea\u05d9, \u05d0\u05dc\u05d0 \u05d1\u05d6\u05db\u05d5\u05ea \u05d4\u05db\u05d5\u05d7\u05d5\u05ea, \u05d4\u05d1\u05e8\u05db\u05d4 \u05d5\u05d4\u05de\u05d6\u05dc \u05e9\u05e7\u05d9\u05d1\u05dc\u05e0\u05d5 \u05de\u05d4\u05e9\u05de\u05d9\u05d9\u05dd, \u05db\u05de\u05d5 \u05e9\u05e0\u05d0\u05de\u05e8: "\u05dc\u05d0 \u05db\u05d5\u05d7\u05d9 \u05d5\u05e2\u05d5\u05e6\u05dd \u05d9\u05d3\u05d9 \u05e2\u05e9\u05d4 \u05dc\u05d9 \u05d0\u05ea \u05d4\u05d7\u05d9\u05dc \u05d4\u05d6\u05d4".\n\u05d1\u05e0\u05d5\u05e1\u05e3, \u05d1\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d4\u05e2\u05d5\u05dc\u05de\u05d9\u05ea \u05e0\u05d4\u05d5\u05d2 \u05dc\u05e1\u05d2\u05d5\u05e8 \u05d0\u05ea \u05d4\u05d9\u05d3\u05d9\u05d9\u05dd, \u05d0\u05da \u05d0\u05e6\u05dc\u05e0\u05d5 \u05d0\u05e0\u05d5 \u05e4\u05d5\u05ea\u05d7\u05d9\u05dd \u05d0\u05ea \u05d4\u05d9\u05d3\u05d9\u05d9\u05dd. \u05d0\u05e0\u05d5 \u05de\u05ea\u05d7\u05d1\u05e8\u05d9\u05dd \u05dc\u05e8\u05d5\u05d7\u05d1 \u05d4\u05d9\u05d3, \u05dc\u05e9\u05e4\u05e2 \u05e9\u05d9\u05d5\u05e8\u05d3 \u05d0\u05dc\u05d9\u05e0\u05d5 \u05de\u05d4\u05e9\u05de\u05d9\u05d9\u05dd, \u05d5\u05dc\u05d0 \u05e1\u05d5\u05d2\u05e8\u05d9\u05dd \u05d0\u05ea \u05e2\u05e6\u05de\u05e0\u05d5 \u05d1\u05e4\u05e0\u05d9 \u05d4\u05d0\u05e0\u05e8\u05d2\u05d9\u05d4 \u05d4\u05d6\u05d5.\n\u05e4\u05e0\u05d9\u05e0\u05d5 \u05dc\u05de\u05d6\u05e8\u05d7\n\u05d4\u05de\u05d6\u05e8\u05d7 \u05de\u05e1\u05de\u05dc \u05d0\u05ea \u05d4\u05d0\u05d5\u05e8 \u05d4\u05d7\u05d3\u05e9. \u05db\u05dc \u05d9\u05d5\u05dd \u05de\u05d0\u05d9\u05e8 \u05d9\u05d5\u05dd \u05d7\u05d3\u05e9 \u05e2\u05dd \u05d1\u05e8\u05db\u05d4 \u05d7\u05d3\u05e9\u05d4 \u05dc\u05e2\u05d5\u05dc\u05dd. \u05db\u05da \u05d2\u05dd \u05d0\u05e0\u05d5 \u05d6\u05d5\u05db\u05e8\u05d9\u05dd \u05dc\u05e4\u05e0\u05d5\u05ea \u05de\u05e7\u05d5\u05dd \u05dc\u05d0\u05d5\u05e4\u05d8\u05d9\u05de\u05d9\u05d5\u05ea \u05d7\u05d3\u05e9\u05d4 \u05d1\u05db\u05dc \u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4. \u05db\u05dc \u05de\u05d4 \u05e9\u05e8\u05e6\u05d9\u05e0\u05d5 \u05e9\u05d9\u05e7\u05e8\u05d4 \u05e2\u05d3 \u05e2\u05db\u05e9\u05d9\u05d5 \u05d5\u05e2\u05d3\u05d9\u05d9\u05df \u05dc\u05d0 \u05e7\u05e8\u05d4, \u05e0\u05d6\u05db\u05d5\u05e8 \u05db\u05d9 \u05d2\u05dd \u05d0\u05dd \u05dc\u05d0 \u05e7\u05e8\u05d4 \u05e2\u05d3 \u05db\u05d4, \u05d6\u05d4 \u05dc\u05d0 \u05d1\u05d2\u05dc\u05dc \u05e9\u05dc\u05d0 \u05d9\u05e7\u05e8\u05d4, \u05d0\u05dc\u05d0 \u05db\u05d9 \u05d6\u05d4 \u05e2\u05d3\u05d9\u05d9\u05df \u05dc\u05d0 \u05d4\u05d2\u05d9\u05e2. \u05db\u05de\u05d5 \u05e9\u05d4\u05e9\u05de\u05e9 \u05d6\u05d5\u05e8\u05d7\u05ea \u05db\u05dc \u05d9\u05d5\u05dd \u05de\u05d7\u05d3\u05e9, \u05db\u05da \u05d2\u05dd \u05d9\u05d2\u05d9\u05e2 \u05d0\u05dc\u05d9\u05e0\u05d5 \u05d0\u05d5\u05e8 \u05d5\u05e9\u05e4\u05e2 \u05d7\u05d3\u05e9\u05d9\u05dd \u05d4\u05d9\u05d5\u05dd.\n\u05e0\u05d9\u05e4\u05ea\u05d7 \u05d2\u05dd \u05dc\u05d4\u05e4\u05e0\u05de\u05d4 \u05e9\u05d3\u05d1\u05e8\u05d9\u05dd \u05d8\u05d5\u05d1\u05d9\u05dd \u05e9\u05e2\u05d5\u05d3 \u05dc\u05d0 \u05e7\u05e8\u05d5 \u05dc\u05e0\u05d5, \u05e2\u05d3\u05d9\u05d9\u05df \u05dc\u05d0 \u05e7\u05e8\u05d5 \u05db\u05d9 \u05dc\u05d0 \u05d4\u05d2\u05e2\u05e0\u05d5 \u05dc\u05ea\u05d5\u05d1\u05e0\u05d4 \u05de\u05e1\u05d5\u05d9\u05de\u05ea \u05e9\u05de\u05d7\u05db\u05d4 \u05dc\u05d4\u05ea\u05d2\u05dc\u05d5\u05ea \u05dc\u05e0\u05d5. \u05d5\u05d0\u05d5\u05dc\u05d9 \u05d4\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d4\u05d6\u05d5 \u05ea\u05d4\u05d9\u05d4 \u05d6\u05d5 \u05e9\u05ea\u05e4\u05ea\u05d7 \u05dc\u05e0\u05d5 \u05d0\u05ea \u05d4\u05ea\u05d5\u05d1\u05e0\u05d4 \u05e9\u05ea\u05d0\u05e4\u05e9\u05e8 \u05d2\u05dd \u05d0\u05ea \u05d4\u05e9\u05e4\u05e2 \u05d4\u05d2\u05e9\u05de\u05d9.\n\u05d1\u05de\u05d9\u05dc\u05d9\u05dd \u05d0\u05d7\u05e8\u05d5\u05ea, \u05d1\u05db\u05dc \u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d0\u05e0\u05d5 \u05e4\u05d5\u05ea\u05d7\u05d9\u05dd \u05d0\u05ea \u05e2\u05e6\u05de\u05e0\u05d5 \u05dc\u05d0 \u05e8\u05e7 \u05dc\u05d1\u05e7\u05e9 \u05d0\u05ea \u05d4\u05e9\u05e4\u05e2 \u05d4\u05d2\u05e9\u05de\u05d9 \u05d4\u05d7\u05e1\u05e8 \u05dc\u05e0\u05d5, \u05d0\u05dc\u05d0 \u05d1\u05e2\u05d9\u05e7\u05e8 \u05d0\u05e0\u05d5 \u05de\u05d7\u05e4\u05e9\u05d9\u05dd \u05d0\u05ea \u05d4\u05ea\u05d5\u05d1\u05e0\u05d5\u05ea \u05e9\u05de\u05e4\u05e8\u05d9\u05e2\u05d5\u05ea \u05dc\u05e0\u05d5 \u05dc\u05d4\u05ea\u05e7\u05d3\u05dd \u05d1\u05d7\u05d9\u05d9\u05dd.\n\u05d0\u05dd \u05ea\u05d7\u05e9\u05d1\u05d5 \u05e2\u05dc \u05db\u05da, \u05d9\u05d9\u05ea\u05db\u05df \u05e9\u05de\u05d4 \u05e9\u05de\u05e4\u05e8\u05d9\u05e2 \u05dc\u05db\u05dd \u05dc\u05d4\u05ea\u05e7\u05d3\u05dd \u05d1\u05d7\u05d9\u05d9\u05dd \u05d4\u05d5\u05d0 \u05db\u05d0\u05d1 \u05d1\u05d2\u05d1 \u05d0\u05d5 \u05d7\u05d5\u05e1\u05e8 \u05d1\u05db\u05e1\u05e3 \u05dc\u05de\u05d9\u05de\u05d5\u05e9 \u05d4\u05d7\u05dc\u05d5\u05de\u05d5\u05ea. \u05d5\u05d0\u05db\u05df, \u05d6\u05d4 \u05e0\u05db\u05d5\u05df \u05d7\u05dc\u05e7\u05d9\u05ea. \u05d0\u05da \u05d3\u05e8\u05da \u05d4\u05d4\u05e1\u05ea\u05db\u05dc\u05d5\u05ea \u05d4\u05d4\u05e4\u05d5\u05db\u05d4 \u05ea\u05e4\u05ea\u05d7 \u05dc\u05db\u05dd \u05d0\u05ea \u05d4\u05e9\u05e4\u05e2 \u05d4\u05d2\u05e9\u05de\u05d9. \u05d0\u05dd \u05e0\u05d1\u05d9\u05df \u05e9\u05d4\u05ea\u05e7\u05d9\u05e2\u05d5\u05ea \u05e9\u05dc\u05e0\u05d5 \u05d1\u05d7\u05d9\u05d9\u05dd \u05e7\u05d9\u05d9\u05de\u05ea \u05db\u05d3\u05d9 \u05dc\u05e9\u05e8\u05ea \u05d0\u05ea \u05d4\u05e6\u05de\u05d9\u05d7\u05d4 \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9\u05ea \u05e9\u05dc\u05e0\u05d5, \u05e0\u05ea\u05de\u05e7\u05d3 \u05d1\u05e6\u05de\u05d9\u05d7\u05d4 \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9\u05ea. \u05d0\u05d6, \u05db\u05d0\u05e9\u05e8 \u05e0\u05e4\u05ea\u05d7 \u05d0\u05ea \u05d4\u05e4\u05ea\u05d7 \u05dc\u05ea\u05d5\u05d1\u05e0\u05d5\u05ea \u05e9\u05de\u05d7\u05db\u05d5\u05ea \u05dc\u05e0\u05d5, \u05d4\u05e9\u05e4\u05e2 \u05d4\u05d2\u05e9\u05de\u05d9 \u05d9\u05d1\u05d5\u05d0 \u05d1\u05e2\u05e7\u05d1\u05d5\u05ea\u05d9\u05d4\u05df.\n\u05e4\u05e0\u05d9\u05e0\u05d5 \u05dc\u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd\n\u05db\u05de\u05d5 \u05db\u05df, \u05d0\u05e0\u05d5 \u05de\u05de\u05e7\u05de\u05d9\u05dd \u05d0\u05ea \u05e2\u05e6\u05de\u05e0\u05d5 \u05e2\u05dd \u05d4\u05e4\u05e0\u05d9\u05dd \u05dc\u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd. \u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd \u05d4\u05d9\u05d0 \u05e6\u05e8\u05d5\u05e3 \u05d4\u05de\u05d9\u05dc\u05d9\u05dd "\u05d9\u05e8\u05d0\u05d4 \u05e9\u05dc\u05de\u05d4". \u05d9\u05e8\u05d5\u05e9\u05dc\u05d9\u05dd \u05de\u05e1\u05de\u05dc\u05ea \u05d0\u05ea \u05de\u05e7\u05d5\u05e8 \u05d4\u05e7\u05d3\u05d5\u05e9\u05d4 \u05e9\u05dc \u05d4\u05e2\u05d5\u05dc\u05dd. \u05e9\u05dd \u05e0\u05de\u05e6\u05d0 \u05d1\u05d9\u05ea \u05d4\u05de\u05e7\u05d3\u05e9, \u05d5\u05e9\u05dd \u05de\u05e1\u05e8\u05d5 \u05d0\u05d1\u05e8\u05d4\u05dd \u05d5\u05d9\u05e6\u05d7\u05e7 \u05d0\u05d1\u05d9\u05e0\u05d5 \u05d0\u05ea \u05e0\u05e4\u05e9\u05dd \u05dc\u05d1\u05d5\u05e8\u05d0 \u05d1\u05e2\u05e7\u05d9\u05d3\u05ea \u05d9\u05e6\u05d7\u05e7. \u05de\u05e1\u05d9\u05e8\u05d5\u05ea \u05d4\u05e0\u05e4\u05e9 \u05e9\u05dc\u05d4\u05dd \u05d4\u05d1\u05d9\u05d0\u05d4 \u05e9\u05e0\u05d9 \u05d3\u05d1\u05e8\u05d9\u05dd \u05d7\u05e9\u05d5\u05d1\u05d9\u05dd \u05dc\u05e2\u05d5\u05dc\u05dd.\n\u05e7\u05d5\u05d3\u05dd \u05db\u05dc, \u05d4\u05d9\u05d0 \u05e4\u05ea\u05d7\u05d4 \u05dc\u05d4\u05dd \u05e4\u05ea\u05d7 \u05dc\u05e8\u05d0\u05d5\u05ea \u05d0\u05ea \u05d0\u05dc\u05d5\u05e7\u05d9\u05dd, \u05db\u05de\u05d5 \u05e9\u05db\u05ea\u05d5\u05d1:\n"\u05d5\u05b7\u05d9\u05b4\u05bc\u05e7\u05b0\u05e8\u05b8\u05d0 \u05d0\u05b7\u05d1\u05b0\u05e8\u05b8\u05d4\u05b8\u05dd \u05e9\u05b5\u05c1\u05dd \u05d4\u05b7\u05de\u05b8\u05bc\u05e7\u05d5\u05b9\u05dd \u05d4\u05b7\u05d4\u05d5\u05bc\u05d0 \u05d9\u05b0\u05d4\u05d5\u05b8\u05d4 \u05d9\u05b4\u05e8\u05b0\u05d0\u05b6\u05d4, \u05d0\u05b2\u05e9\u05b6\u05c1\u05e8 \u05d9\u05b5\u05d0\u05b8\u05de\u05b5\u05e8 \u05d4\u05b7\u05d9\u05bc\u05d5\u05b9\u05dd \u05d1\u05b0\u05bc\u05d4\u05b7\u05e8 \u05d9\u05b0\u05d4\u05d5\u05b8\u05d4 \u05d9\u05b5\u05e8\u05b8\u05d0\u05b6\u05d4."\n\u05db\u05dc\u05d5\u05de\u05e8, \u05d0\u05d1\u05e8\u05d4\u05dd \u05d0\u05d1\u05d9\u05e0\u05d5 \u05e8\u05d0\u05d4 \u05e9\u05dd \u05de\u05e9\u05d4\u05d5 \u05d1\u05d3\u05e8\u05d2\u05d5\u05ea \u05e8\u05d5\u05d7\u05e0\u05d9\u05d5\u05ea \u05d0\u05d7\u05e8\u05d5\u05ea \u05de\u05de\u05d4 \u05e9\u05d4\u05d5\u05d0 \u05e8\u05d0\u05d4 \u05e7\u05d5\u05d3\u05dd.\n\u05d1\u05e0\u05d5\u05e1\u05e3, \u05d4\u05de\u05d9\u05dc\u05d4 "\u05d9\u05b4\u05e8\u05b0\u05d0\u05b6\u05d4" \u05d4\u05d9\u05d0 \u05de\u05d0\u05d5\u05ea\u05d5 \u05e9\u05d5\u05e8\u05e9 \u05e9\u05dc "\u05d9\u05b4\u05e8\u05b0\u05d0\u05b8\u05d4", \u05d5\u05d4\u05de\u05e9\u05de\u05e2\u05d5\u05ea \u05d4\u05db\u05e4\u05d5\u05dc\u05d4 \u05e9\u05dc \u05d4\u05de\u05d9\u05dc\u05d4 \u05d1\u05e0\u05d9\u05e7\u05d5\u05d3 \u05d4\u05e9\u05d5\u05e0\u05d4 \u05de\u05d1\u05d9\u05d0\u05d4 \u05d0\u05d5\u05ea\u05e0\u05d5 \u05dc\u05d4\u05d1\u05e0\u05d4 \u05e9\u05db\u05d0\u05e9\u05e8 \u05d0\u05e0\u05d5 \u05d7\u05d9\u05d9\u05dd \u05d1\u05de\u05e1\u05d9\u05e8\u05d5\u05ea \u05e0\u05e4\u05e9 \u05e2\u05dc \u05e2\u05e7\u05e8\u05d5\u05e0\u05d5\u05ea \u05d4\u05d7\u05d9\u05d9\u05dd \u05d4\u05d7\u05e9\u05d5\u05d1\u05d9\u05dd, \u05d0\u05e0\u05d5 \u05d6\u05d5\u05db\u05d9\u05dd \u05dc\u05e8\u05d0\u05d5\u05ea \u05d0\u05d5\u05e8 \u05e8\u05d5\u05d7\u05e0\u05d9 \u05d2\u05d3\u05d5\u05dc.\n\u05e9\u05de\u05e2 \u05d9\u05e9\u05e8\u05d0\u05dc\n\u05de\u05e9\u05de\u05e2\u05d5\u05ea "\u05e9\u05de\u05e2 \u05d9\u05e9\u05e8\u05d0\u05dc"\n"\u05e9\u05de\u05e2 \u05d9\u05e9\u05e8\u05d0\u05dc" \u05d4\u05d9\u05d0 \u05d4\u05d6\u05d3\u05de\u05e0\u05d5\u05ea \u05dc\u05d4\u05ea\u05d1\u05d5\u05e0\u05df \u05d1\u05e9\u05d9\u05ea\u05d5\u05e3 \u05d4\u05e4\u05e2\u05d5\u05dc\u05d4 \u05d1\u05d9\u05df \u05d4\u05d0\u05d3\u05dd \u05dc\u05d1\u05d5\u05e8\u05d0. \u05d6\u05d5 \u05e7\u05e8\u05d9\u05d0\u05d4 \u05dc\u05e2\u05e6\u05d5\u05e8, \u05dc\u05d4\u05e7\u05e9\u05d9\u05d1, \u05d5\u05dc\u05d2\u05dc\u05d5\u05ea \u05d0\u05ea \u05d4\u05e7\u05e9\u05e8 \u05d4\u05d0\u05d9\u05e9\u05d9 \u05e9\u05dc\u05d9 \u05e2\u05dd \u05d4\u05d0\u05dc\u05d5\u05d4\u05d5\u05ea.\n\u05d4\u05de\u05d9\u05dc\u05d4 "\u05e9\u05de\u05e2" \u05d0\u05d9\u05e0\u05d4 \u05e8\u05e7 \u05e4\u05e7\u05d5\u05d3\u05d4 \u05dc\u05e9\u05de\u05d5\u05e2, \u05d0\u05dc\u05d0 \u05e7\u05e8\u05d9\u05d0\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05dc\u05db\u05dc \u05d0\u05d7\u05d3 \u05de\u05d0\u05d9\u05ea\u05e0\u05d5 \u2013 \u05dc\u05d4\u05d0\u05d6\u05d9\u05df \u05dc\u05e7\u05d5\u05dc \u05d4\u05d0\u05dc, \u05dc\u05d4\u05ea\u05d7\u05d1\u05e8 \u05dc\u05e8\u05e6\u05d5\u05df \u05d4\u05e4\u05e0\u05d9\u05de\u05d9 \u05d5\u05dc\u05d2\u05dc\u05d5\u05ea \u05d0\u05ea \u05d4\u05de\u05e1\u05e8 \u05d4\u05d9\u05d9\u05d7\u05d5\u05d3\u05d9 \u05e9\u05de\u05d9\u05d5\u05e2\u05d3 \u05dc\u05d9 \u05d1\u05db\u05dc \u05e8\u05d2\u05e2.\n\u05d4\u05d7\u05d9\u05d1\u05d5\u05e8 \u05dc\u05de\u05d9\u05dc\u05d4 "\u05d9\u05e9\u05e8\u05d0\u05dc" \u05e4\u05d5\u05ea\u05d7 \u05e4\u05ea\u05d7 \u05dc\u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea \u05e0\u05d5\u05e1\u05e4\u05ea: \u05de\u05d4\u05d5 \u05d4\u05e7\u05e9\u05e8 \u05e9\u05dc\u05d9 \u05e2\u05dd \u05d4\u05e2\u05dd \u05e9\u05dc\u05d9? \u05d4\u05d0\u05dd \u05d0\u05e0\u05d9 \u05e8\u05d5\u05d0\u05d4 \u05d0\u05ea \u05e2\u05dd \u05d9\u05e9\u05e8\u05d0\u05dc \u05db\u05e2\u05dd \u05d4\u05e0\u05d5\u05e9\u05d0 \u05d6\u05db\u05d5\u05d9\u05d5\u05ea \u05d9\u05ea\u05e8, \u05d0\u05d5 \u05db\u05d7\u05d1\u05e8\u05d4 \u05d4\u05de\u05d7\u05d5\u05d9\u05d1\u05ea \u05dc\u05d0\u05d7\u05e8\u05d9\u05d5\u05ea \u05db\u05dc\u05e4\u05d9 \u05d4\u05e2\u05d5\u05dc\u05dd? \u05e9\u05d0\u05dc\u05d5\u05ea \u05d0\u05dc\u05d5 \u05de\u05d5\u05d1\u05d9\u05dc\u05d5\u05ea \u05d0\u05d5\u05ea\u05d9 \u05dc\u05d4\u05e8\u05d4\u05e8 \u05d1\u05de\u05e9\u05de\u05e2\u05d5\u05ea \u05d4\u05d9\u05d5\u05ea\u05d9 \u05d7\u05dc\u05e7 \u05de\u05e2\u05dd \u05d9\u05e9\u05e8\u05d0\u05dc \u2013 \u05d4\u05d0\u05dd \u05d4\u05d3\u05d1\u05e8 \u05de\u05e2\u05d5\u05e8\u05e8 \u05d1\u05d9 \u05d2\u05d0\u05d5\u05d5\u05d4, \u05d0\u05d5 \u05e9\u05de\u05d0 \u05de\u05d8\u05d9\u05dc \u05e2\u05dc\u05d9\u05d9 \u05d0\u05d7\u05e8\u05d9\u05d5\u05ea \u05dc\u05d9\u05e6\u05d5\u05e8 \u05e9\u05d9\u05e0\u05d5\u05d9?\n\u05d4\u05de\u05d9\u05dc\u05d9\u05dd "\u05d4\' \u05d0\u05dc\u05d5\u05e7\u05d9\u05e0\u05d5, \u05d4\' \u05d0\u05d7\u05d3" \u05de\u05d7\u05d1\u05e8\u05d5\u05ea \u05d1\u05d9\u05df \u05d4\u05de\u05de\u05d3 \u05d4\u05de\u05d9\u05e1\u05d8\u05d9 \u05e9\u05dc \u05d4\u05d0\u05dc\u05d5\u05d4\u05d5\u05ea \u05dc\u05d1\u05d9\u05df \u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea \u05d4\u05de\u05e2\u05e9\u05d9\u05ea \u05e9\u05dc \u05d7\u05d9\u05d9\u05e0\u05d5. \u05d7\u05d6"\u05dc \u05dc\u05d9\u05de\u05d3\u05d5 \u05d0\u05d5\u05ea\u05e0\u05d5 \u05e9\u05db\u05e4\u05d9 \u05e9\u05d0\u05e0\u05d5 \u05de\u05d4\u05dc\u05dc\u05d9\u05dd \u05d0\u05ea \u05d4\u05d1\u05d5\u05e8\u05d0 \u05e2\u05dc \u05d4\u05d9\u05d5\u05ea\u05d5 \u05d0\u05d7\u05d3 \u05d5\u05d9\u05d7\u05d9\u05d3 \u05d1\u05d1\u05e8\u05d9\u05d0\u05d4, \u05db\u05da \u05d4\u05d5\u05d0 \u05de\u05d4\u05dc\u05dc \u05d0\u05d5\u05ea\u05e0\u05d5 \u05d1\u05d0\u05d5\u05de\u05e8\u05d5: "\u05de\u05d9 \u05db\u05e2\u05de\u05da \u05d9\u05e9\u05e8\u05d0\u05dc \u05d2\u05d5\u05d9 (\u05e2\u05dd) \u05d0\u05d7\u05d3 \u05d1\u05d0\u05e8\u05e5(\u05d1\u05e2\u05d5\u05dc\u05dd)". \u05db\u05dc\u05d5\u05de\u05e8, \u05d4\u05d1\u05d5\u05e8\u05d0 \u05de\u05d1\u05d9\u05e2 \u05d0\u05de\u05d5\u05df \u05d1\u05e0\u05d5 \u2013 \u05dc\u05d0 \u05dc\u05e1\u05de\u05d5\u05da \u05e2\u05dc\u05d9\u05d5 \u05d1\u05dc\u05d1\u05d3, \u05d0\u05dc\u05d0 \u05d2\u05dd \u05dc\u05e7\u05d7\u05ea \u05d0\u05d7\u05e8\u05d9\u05d5\u05ea \u05e2\u05dc \u05e2\u05e6\u05de\u05e0\u05d5.\n\u05de\u05db\u05d0\u05df \u05e2\u05d5\u05dc\u05d4 \u05d4\u05e9\u05d0\u05dc\u05d4: \u05e2\u05d3 \u05db\u05de\u05d4 \u05d0\u05e0\u05d5 \u05dc\u05d5\u05e7\u05d7\u05d9\u05dd \u05d0\u05d7\u05e8\u05d9\u05d5\u05ea \u05e2\u05dc \u05d7\u05d9\u05d9\u05e0\u05d5 \u05d5\u05e2\u05dc \u05d4\u05e2\u05d5\u05dc\u05dd, \u05d5\u05e2\u05d3 \u05db\u05de\u05d4 \u05d0\u05e0\u05d5 \u05de\u05e6\u05e4\u05d9\u05dd \u05e9\u05d4\u05d3\u05d1\u05e8\u05d9\u05dd \u05d9\u05e1\u05ea\u05d3\u05e8\u05d5 \u05de\u05e2\u05e6\u05de\u05dd?\n"\u05e9\u05de\u05e2 \u05d9\u05e9\u05e8\u05d0\u05dc" \u05db\u05de\u05d5 \u05d2\u05dd \u05e9\u05d0\u05e8 \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d0\u05d9\u05e0\u05d4 \u05e8\u05e7 \u05d0\u05de\u05d9\u05e8\u05d4 \u05d8\u05e7\u05e1\u05d9\u05ea \u2013 \u05d6\u05d4 \u05de\u05d5\u05e7\u05d3 \u05de\u05e8\u05db\u05d6\u05d9 \u05e9\u05dc \u05d4\u05d4\u05d6\u05de\u05e0\u05d4 \u05dc\u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea \u05e4\u05e0\u05d9\u05de\u05d9\u05ea, \u05dc\u05d7\u05d9\u05d1\u05d5\u05e8 \u05e2\u05de\u05d5\u05e7 \u05e2\u05dd \u05e2\u05e6\u05de\u05d9, \u05e2\u05dd \u05e2\u05de\u05d9, \u05d5\u05e2\u05dd \u05d4\u05d1\u05e8\u05d9\u05d0\u05d4 \u05db\u05d5\u05dc\u05d4.\n\u05db\u05de\u05d5\u05d1\u05df! \u05d4\u05e0\u05d4 \u05ea\u05e8\u05d2\u05d5\u05dd \u05dc\u05e2\u05d1\u05e8\u05d9\u05ea \u05e7\u05d5\u05dc\u05d7\u05ea \u05d5\u05d1\u05e8\u05d5\u05e8\u05d4 \u05e9\u05dc \u05d4\u05e7\u05d8\u05e2:\n"\u05d5\u05d9\u05d3\u05d1\u05e8 \u05d4\' \u05d0\u05dc \u05de\u05e9\u05d4 \u05dc\u05d0\u05de\u05e8: \u05d5\u05e2\u05e9\u05d9\u05ea \u05db\u05d9\u05d5\u05e8 \u05e0\u05d7\u05d5\u05e9\u05ea... \u05d5\u05e8\u05d7\u05e6\u05d5 \u05d0\u05d4\u05e8\u05df \u05d5\u05d1\u05e0\u05d9\u05d5 \u05de\u05de\u05e0\u05d5..."\n\u05de\u05d5\u05e9\u05d2 \u05e0\u05d8\u05d9\u05dc\u05ea \u05d9\u05d3\u05d9\u05d9\u05dd \u05d4\u05d5\u05e1\u05d1\u05e8 \u05e2\u05dc \u05d9\u05d3\u05d9 \u05d0\u05d1\u05d9 \u05d6\u05e6"\u05dc \u05d1\u05e1\u05e4\u05e8\u05d5 \u05d4\u05e7\u05d3\u05d5\u05e9 \u05de\u05d9 \u05d4\u05e9\u05dc\u05d5\u05d7 (\u05d7\u05dc\u05e7 \u05d0, \u05e4\u05e8\u05e9\u05ea \u05db\u05d9 \u05ea\u05e9\u05d0, \u05d3"\u05d4 "\u05d5\u05e8\u05d7\u05e6\u05d5"). \u05d4\u05d5\u05d0 \u05dc\u05d9\u05de\u05d3 \u05e9\u05e0\u05d8\u05d9\u05dc\u05ea \u05d9\u05d3\u05d9\u05d9\u05dd \u05de\u05e8\u05de\u05d6\u05ea \u05e2\u05dc \u05e1\u05d9\u05dc\u05d5\u05e7 \u05e0\u05d2\u05d9\u05e2\u05d4 \u05e2\u05e6\u05de\u05d9\u05ea \u05d5\u05d0\u05d9\u05e0\u05d8\u05e8\u05e1\u05d9\u05dd \u05d0\u05d9\u05e9\u05d9\u05d9\u05dd. \u05d6\u05d5 \u05d2\u05dd \u05d4\u05e1\u05d9\u05d1\u05d4 \u05e9\u05d0\u05e0\u05d5 \u05d0\u05d5\u05de\u05e8\u05d9\u05dd "\u05e9\u05d0\u05d5 \u05d9\u05d3\u05d9\u05db\u05dd \u05e7\u05d5\u05d3\u05e9"\u2014\u05db\u05dc\u05d5\u05de\u05e8, \u05d4\u05d9\u05d3\u05d9\u05d9\u05dd, \u05e9\u05de\u05e1\u05de\u05dc\u05d5\u05ea \u05d0\u05ea \u05db\u05dc\u05d9 \u05d4\u05de\u05e2\u05e9\u05d4, \u05e6\u05e8\u05d9\u05db\u05d5\u05ea \u05dc\u05d4\u05ea\u05e8\u05d5\u05de\u05dd \u05d5\u05dc\u05d4\u05d9\u05d5\u05ea \u05de\u05d7\u05d5\u05d1\u05e8\u05d5\u05ea \u05dc\u05de\u05d7\u05e9\u05d1\u05d4 \u05e9\u05d1\u05e8\u05d0\u05e9, \u05dc\u05ea\u05d5\u05d3\u05e2\u05d4 \u05d4\u05e2\u05dc\u05d9\u05d5\u05e0\u05d4. \u05d4\u05d0\u05d3\u05dd \u05e6\u05e8\u05d9\u05da \u05dc\u05d7\u05e0\u05da \u05d0\u05ea \u05e2\u05e6\u05de\u05d5 \u05dc\u05d0 \u05dc\u05e4\u05e2\u05d5\u05dc \u05d0\u05dc\u05d0 \u05d0\u05dd \u05d1\u05e8\u05d5\u05e8 \u05dc\u05d5 \u05e9\u05de\u05e2\u05e9\u05d9\u05d5 \u05ea\u05d5\u05d0\u05de\u05d9\u05dd \u05dc\u05e8\u05e6\u05d5\u05df \u05d4\u05e9\u05dd.\n\u05d4\u05d2\u05de\u05e8\u05d0 (\u05d1\u05e8\u05db\u05d5\u05ea \u05d8"\u05d5 \u05e2"\u05d0) \u05de\u05dc\u05de\u05d3\u05ea: \u05d4\u05e8\u05d5\u05e6\u05d4 \u05dc\u05e7\u05d1\u05dc \u05e2\u05dc\u05d9\u05d5 \u05e2\u05d5\u05dc \u05de\u05dc\u05db\u05d5\u05ea \u05e9\u05de\u05d9\u05d9\u05dd \u05e9\u05dc\u05de\u05d4\u2014\u05d9\u05e4\u05e0\u05d4, \u05d9\u05d9\u05d8\u05d5\u05dc \u05d9\u05d3\u05d9\u05d5, \u05d9\u05e0\u05d9\u05d7 \u05ea\u05e4\u05d9\u05dc\u05d9\u05df, \u05d9\u05e7\u05e8\u05d0 \u05e7\u05e8\u05d9\u05d0\u05ea \u05e9\u05de\u05e2 \u05d5\u05d9\u05ea\u05e4\u05dc\u05dc.\n\u05e9\u05dc\u05d1\u05d9 \u05ea\u05d4\u05dc\u05d9\u05da \u05d6\u05d4 \u05de\u05d1\u05d8\u05d0\u05d9\u05dd \u05d6\u05d9\u05db\u05d5\u05da \u05e8\u05d5\u05d7\u05e0\u05d9:\n\u05d9\u05e4\u05e0\u05d4\u2014\u05e0\u05e4\u05e0\u05d4 \u05e2\u05d5\u05d3\u05e4\u05d9\u05dd \u05d5\u05d4\u05e1\u05d7\u05d5\u05ea \u05d3\u05e2\u05ea \u05d2\u05d5\u05e4\u05e0\u05d9\u05d5\u05ea \u05d1\u05d1\u05d9\u05ea \u05d4\u05db\u05e1\u05d0 \u05d5\u05e0\u05e4\u05e9\u05d9\u05d5\u05ea \u05de\u05d4\u05ea\u05d5\u05d3\u05e2\u05d4.\n\u05d9\u05d9\u05d8\u05d5\u05dc \u05d9\u05d3\u05d9\u05d5\u2014\u05e0\u05e1\u05dc\u05e7 \u05d0\u05d9\u05e0\u05d8\u05e8\u05e1 \u05d0\u05d9\u05e9\u05d9 \u05d5\u05e0\u05d2\u05d9\u05e2\u05d4 \u05e2\u05e6\u05de\u05d9\u05ea.\n\u05d9\u05e7\u05e8\u05d0 \u05e7\u05e8\u05d9\u05d0\u05ea \u05e9\u05de\u05e2\u2014\u05d9\u05e7\u05d1\u05dc \u05e2\u05d5\u05dc \u05e9\u05de\u05d9\u05d9\u05dd \u05de\u05ea\u05d5\u05da \u05e8\u05e6\u05d5\u05df \u05e4\u05e0\u05d9\u05de\u05d9 \u05dc\u05d5\u05d5\u05ea\u05e8 \u05e2\u05dc \u05db\u05dc \u05de\u05d4 \u05e9\u05e0\u05d5\u05d2\u05d3 \u05d0\u05ea \u05e8\u05e6\u05d5\u05df \u05d4\u05e9\u05dd.\n\u05d5\u05e8\u05e7 \u05d0\u05d6 \u05d9\u05ea\u05e4\u05dc\u05dc \u05ea\u05e4\u05d9\u05dc\u05ea \u05e2\u05de\u05d9\u05d3\u05d4 \u05e9\u05e0\u05d5\u05e2\u05d3\u05d4 \u05dc\u05d4\u05ea\u05e4\u05dc\u05dc\u2014\u05d2\u05dd \u05e2\u05dc \u05e6\u05e8\u05db\u05d9 \u05d4\u05d2\u05d5\u05e3\u2014\u05de\u05e4\u05e0\u05d9 \u05e9\u05dc\u05d0\u05d7\u05e8 \u05e9\u05e1\u05d9\u05dc\u05e7 \u05d0\u05ea \u05d4\u05e0\u05d2\u05d9\u05e2\u05d5\u05ea, \u05db\u05dc \u05de\u05d1\u05d5\u05e7\u05e9\u05d5 \u05d4\u05d5\u05d0 \u05e8\u05e7 \u05db\u05d3\u05d9 \u05e9\u05d9\u05d5\u05db\u05dc \u05dc\u05e2\u05d1\u05d5\u05d3 \u05d0\u05ea \u05d4\u05e9\u05dd \u05d1\u05e9\u05dc\u05de\u05d5\u05ea.\n\u05d3\u05d1\u05e8 \u05d6\u05d4 \u05de\u05ea\u05d2\u05dc\u05dd \u05d2\u05dd \u05d1\u05d7\u05d9\u05d9 \u05d0\u05d1\u05e8\u05d4\u05dd \u05d0\u05d1\u05d9\u05e0\u05d5. \u05de\u05d0\u05d7\u05e8 \u05e9\u05d8\u05d9\u05d4\u05e8 \u05d0\u05ea \u05e2\u05e6\u05de\u05d5 \u05d5\u05d4\u05e9\u05ea\u05d7\u05e8\u05e8 \u05de\u05db\u05dc \u05ea\u05d0\u05d5\u05d5\u05ea \u05d4\u05e2\u05d5\u05dc\u05dd \u05d4\u05d6\u05d4, \u05d4\u05d5\u05d0 \u05d4\u05d2\u05d9\u05e2 \u05dc\u05d4\u05db\u05e8\u05d4 \u05e9\u05d4\u05e2\u05d5\u05dc\u05dd \u05db\u05d5\u05dc\u05d5 \u05dc\u05d0 \u05e0\u05d1\u05e8\u05d0 \u05d0\u05dc\u05d0 \u05db\u05d3\u05d9 \u05dc\u05e2\u05d6\u05d5\u05e8 \u05dc\u05d5 \u05dc\u05e2\u05d1\u05d5\u05d3 \u05d0\u05ea \u05d4\u05e9\u05dd. \u05d5\u05db\u05e4\u05d9 \u05e9\u05de\u05d5\u05d1\u05d0 \u05d1\u05de\u05d3\u05e8\u05e9 (\u05d1\u05e8\u05d0\u05e9\u05d9\u05ea \u05e8\u05d1\u05d4 \u05dc"\u05d8): \u05d0\u05e4\u05d9\u05dc\u05d5 \u05d4\u05e1\u05e4\u05d9\u05e0\u05d5\u05ea \u05e9\u05d4\u05e4\u05dc\u05d9\u05d2\u05d5 \u05d1\u05d9\u05dd \u05d4\u05d9\u05d5 \u05de\u05ea\u05d1\u05e8\u05db\u05d5\u05ea \u05d1\u05d6\u05db\u05d5\u05ea\u05d5 \u05e9\u05dc \u05d0\u05d1\u05e8\u05d4\u05dd. \u05d5\u05d0\u05e3 \u05e2\u05dc \u05e4\u05d9 \u05e9\u05d4\u05d9\u05d9\u05df \u05e9\u05e0\u05e9\u05d0\u05d5 \u05d4\u05d9\u05d4 \u05de\u05d9\u05d5\u05e2\u05d3 \u05dc\u05e2\u05d1\u05d5\u05d3\u05d4 \u05d6\u05e8\u05d4, \u05d4\u05d1\u05e8\u05db\u05d4 \u05e2\u05d1\u05e8\u05d4 \u05d3\u05e8\u05db\u05d5. \u05d5\u05d4\u05de\u05d3\u05e8\u05e9 \u05de\u05ea\u05e8\u05e5: "\u05d7\u05dc\u05d0 \u05de\u05d5\u05d6\u05d9\u05dc, \u05d7\u05de\u05e8\u05d0 \u05d9\u05e7\u05e8"\u2014\u05db\u05dc\u05d5\u05de\u05e8, \u05d4\u05d9\u05d9\u05df \u05d6\u05d5\u05dc, \u05d0\u05d1\u05dc \u05d4\u05e0\u05d5\u05e9\u05d0 \u05d9\u05e7\u05e8. \u05de\u05e9\u05d5\u05dd \u05e9\u05dc\u05d0\u05d1\u05e8\u05d4\u05dd \u05dc\u05d0 \u05d4\u05d9\u05d9\u05ea\u05d4 \u05db\u05dc \u05e0\u05d2\u05d9\u05e2\u05d4 \u05dc\u05ea\u05e2\u05e0\u05d5\u05d2\u05d5\u05ea \u05d4\u05e2\u05d5\u05dc\u05dd \u05d4\u05d6\u05d4, \u05db\u05dc \u05de\u05d4 \u05e9\u05d6\u05e8\u05dd \u05d3\u05e8\u05db\u05d5 \u05d4\u05d9\u05d4 \u05db\u05d5\u05dc\u05d5 \u05dc\u05e9\u05dd \u05e9\u05de\u05d9\u05d9\u05dd.\n\u05d6\u05d5 \u05d2\u05dd \u05d4\u05e1\u05d9\u05d1\u05d4 \u05e9\u05de\u05e9\u05d4 \u05e8\u05d1\u05e0\u05d5 \u05e2\u05e9\u05d4 \u05d0\u05ea \u05d4\u05db\u05d9\u05d5\u05e8 \u05de\u05d4\u05de\u05e8\u05d0\u05d5\u05ea \u05e9\u05ea\u05e8\u05de\u05d5 \u05d4\u05e0\u05e9\u05d9\u05dd \u05e9\u05d4\u05ea\u05d0\u05e1\u05e4\u05d5 \u05d1\u05e4\u05ea\u05d7 \u05d0\u05d5\u05d4\u05dc \u05de\u05d5\u05e2\u05d3. \u05d4\u05d5\u05d0 \u05e8\u05e6\u05d4 \u05dc\u05d4\u05e8\u05d0\u05d5\u05ea \u05e9\u05d1\u05e7\u05e8\u05d1 \u05d9\u05e9\u05e8\u05d0\u05dc \u05d0\u05d9\u05df \u05de\u05e7\u05d5\u05dd \u05dc\u05e2\u05e9\u05d5\u05ea \u05d3\u05d1\u05e8 \u05dc\u05e9\u05dd \u05d4\u05e0\u05d0\u05d4 \u05e2\u05e6\u05de\u05d9\u05ea. \u05db\u05dc \u05e4\u05e2\u05d5\u05dc\u05d4\u2014even \u05de\u05d4 \u05e9\u05e0\u05e8\u05d0\u05d4 \u05d2\u05e9\u05de\u05d9 \u05d1\u05d9\u05d5\u05ea\u05e8\u2014\u05e0\u05d5\u05e2\u05d3\u05d4 \u05d0\u05da \u05d5\u05e8\u05e7 \u05dc\u05e9\u05dd \u05e7\u05d9\u05d5\u05dd \u05e8\u05e6\u05d5\u05df \u05d4\u05e9\u05dd.\n\u05d4\u05e9\u05d9\u05d1\u05d4 \u05e9\u05d5\u05e4\u05d8\u05d9\u05e0\u05d5 \u05db\u05d1\u05e8\u05d0\u05e9\u05d5\u05e0\u05d4 \u05d5\u05d9\u05d5\u05e2\u05e6\u05d9\u05e0\u05d5 \u05db\u05d1\u05ea\u05d7\u05d9\u05dc\u05d4\n\u05d1\u05d3\u05d5\u05e8\u05e0\u05d5 \u05e2\u05dd \u05d4\u05ea\u05de\u05d5\u05d8\u05d8\u05d5\u05ea \u05d4\u05e6\u05d3\u05e7 \u05d4\u05d7\u05d1\u05e8\u05ea\u05d9 \u05d5\u05d0\u05d1\u05d3\u05df \u05d4\u05d0\u05de\u05d5\u05df \u05d1\u05de\u05e2\u05e8\u05db\u05ea \u05d4\u05de\u05e9\u05e4\u05d8 \u05e7\u05dc \u05dc\u05d4\u05ea\u05d7\u05d1\u05e8 \u05d0\u05dc \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d4\u05d6\u05d5. \u05d6\u05d5\u05d4\u05d9 \u05d4\u05d6\u05d3\u05de\u05e0\u05d5\u05ea \u05dc\u05db\u05d0\u05d5\u05d1 \u05d5\u05dc\u05d1\u05db\u05d5\u05ea \u05e2\u05dc \u05d4\u05e9\u05d7\u05d9\u05ea\u05d5\u05ea \u05d1\u05e2\u05d5\u05dc\u05dd \u05d4\u05de\u05de\u05e9\u05dc\u05ea\u05d9,\u05d5\u05d4\u05de\u05e9\u05e4\u05d8\u05d9, \u05d4\u05d7\u05d5\u05e7\u05ea\u05d9 \u05d5\u05d4\u05de\u05d3\u05e2\u05d9, \u05d4\u05db\u05dc\u05db\u05dc\u05d9 \u05d5\u05d4\u05d7\u05d1\u05e8\u05ea\u05d9. \u05d6\u05d4\u05d5 \u05d2\u05dd \u05e8\u05d2\u05e2 \u05dc\u05d7\u05e9\u05d5\u05d1 \u05e2\u05dc \u05db\u05dc \u05d4\u05d7\u05d5\u05e1\u05e8 \u05e6\u05d3\u05e7 \u05e9\u05e0\u05e2\u05e9\u05d4 \u05dc\u05d9. \u05dc\u05d4\u05ea\u05d1\u05d5\u05e0\u05df \u05d4\u05d9\u05db\u05df \u05d0\u05e0\u05d9 \u05d1\u05d0\u05de\u05ea \u05e6\u05d5\u05d3\u05e7/\u05ea \u05d5\u05d4\u05d9\u05db\u05df \u05dc\u05d0, \u05d0\u05dd \u05d0\u05e0\u05d9 \u05e2\u05d5\u05de\u05d3\u05ea \u05e4\u05d4 \u05d1\u05e4\u05e0\u05d9 \u05de\u05e9\u05e4\u05d8. \u05db\u05d9 \u05d0\u05dd \u05d0\u05e0\u05d9 \u05e2\u05d5\u05de\u05d3\u05ea \u05d1\u05e4\u05e0\u05d9 \u05de\u05e9\u05e4\u05d8 \u05d1\u05e2\u05d5\u05dc\u05dd \u05d4\u05d6\u05d4 \u05db\u05e0\u05e8\u05d0\u05d4\u05e9\u05d4\u05de\u05e9\u05e4\u05d8 \u05d4\u05d5\u05d0 \u05d1\u05d0\u05de\u05ea \u05d1\u05e2\u05d5\u05dc\u05de\u05d5\u05ea \u05e2\u05dc\u05d9\u05d5\u05e0\u05d9\u05dd \u05d5\u05dc\u05d0 \u05e8\u05e7 \u05e4\u05d4. \u05d0\u05d5\u05dc\u05d9 \u05d4\u05e0\u05e9\u05de\u05d4 \u05e9\u05dc\u05d9 \u05e6\u05e8\u05d9\u05db\u05d4 \u05dc\u05db\u05e4\u05e8 \u05e2\u05dc \u05de\u05e9\u05d4\u05d5. \u05db\u05da \u05e0\u05e2\u05e9\u05d4 \u05e7\u05dc \u05d9\u05d5\u05ea\u05e8 \u05dc\u05e2\u05de\u05d5\u05d3 \u05d1\u05e4\u05e0\u05d9 \u05d4\u05de\u05e9\u05e4\u05d8 \u05d1\u05e2\u05d5\u05dc\u05dd \u05d4\u05d6\u05d4. \u05d5\u05d6\u05d4 \u05d2\u05dd \u05e0\u05d5\u05ea\u05df \u05dc\u05d9 \u05e8\u05d2\u05e2 \u05dc\u05d4\u05ea\u05d1\u05d5\u05e0\u05df \u05d5\u05dc\u05e2\u05e9\u05d5\u05ea \u05de\u05e9\u05e4\u05d8 \u05dc\u05e2\u05e6\u05de\u05d9. \u05d1\u05d0\u05d9\u05d6\u05d5 \u05e6\u05d5\u05e8\u05d4 \u05d5\u05d1\u05d0\u05d9\u05dc\u05d5 \u05de\u05e6\u05d1\u05d9\u05dd \u05d0\u05e0\u05d9 \u05de\u05e9\u05d7\u05d3\u05ea \u05d0\u05ea \u05e2\u05e6\u05de\u05d9. \u05d5\u05dc\u05d0 \u05d1\u05d0\u05de\u05ea \u05de\u05e1\u05ea\u05db\u05dc\u05ea \u05e2\u05dc \u05e2\u05e6\u05de\u05d9 \u05d1\u05de\u05d1\u05d8 \u05d0\u05d5\u05d1\u05d9\u05e7\u05d8\u05d9\u05d1\u05d9. \u05d5\u05db\u05de\u05d5\u05d1\u05df \u05d6\u05d4 \u05e0\u05d5\u05ea\u05df \u05d4\u05d6\u05d3\u05de\u05e0\u05d5\u05ea \u05dc\u05d4\u05ea\u05e4\u05dc\u05dc \u05e2\u05dc \u05db\u05dc \u05d4\u05e9\u05d9\u05e0\u05d0\u05d4 \u05d1\u05e2\u05d5\u05dc\u05dd \u05d5\u05db\u05dc \u05d7\u05d5\u05e1\u05e8 \u05d4\u05e6\u05d3\u05e7.\n\u05e0\u05e4\u05e9\u05d9 \u05db\u05e2\u05e4\u05e8 \u05dc\u05db\u05dc \u05ea\u05d4\u05d9\u05d4 \u2013 \u05dc\u05dc\u05de\u05d5\u05d3 \u05dc\u05d0 \u05dc\u05d4\u05d9\u05e2\u05dc\u05d1 \u05d5\u05dc\u05d4\u05d9\u05e9\u05d0\u05e8 \u05e8\u05d2\u05d5\u05e2\u05d9\u05dd\n\u05de\u05d1\u05d5\u05d0: \u05db\u05d5\u05d7\u05d5 \u05e9\u05dc \u05d4\u05d0\u05d9\u05d6\u05d5\u05df \u05d4\u05e8\u05d2\u05e9\u05d9\n\u05d1\u05d7\u05d9\u05d9 \u05d4\u05d9\u05d5\u05de\u05d9\u05d5\u05dd \u05d0\u05e0\u05d5 \u05e0\u05ea\u05e7\u05dc\u05d9\u05dd \u05d1\u05d0\u05e0\u05e9\u05d9\u05dd \u05e9\u05d0\u05d5\u05de\u05e8\u05d9\u05dd \u05d3\u05d1\u05e8\u05d9\u05dd \u05e9\u05de\u05db\u05e2\u05d9\u05e1\u05d9\u05dd \u05d0\u05d5\u05ea\u05e0\u05d5, \u05de\u05d1\u05e7\u05e8\u05d9\u05dd \u05d0\u05d5\u05ea\u05e0\u05d5, \u05d0\u05d5 \u05d2\u05d5\u05e8\u05de\u05d9\u05dd \u05dc\u05e0\u05d5 \u05dc\u05d4\u05e8\u05d2\u05d9\u05e9 \u05d0\u05d9 \u05e0\u05d5\u05d7\u05d5\u05ea \u05e8\u05d2\u05e9\u05d9\u05ea. \u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05d6\u05d4 \u05d0\u05d3\u05dd \u05e7\u05e8\u05d5\u05d1 \u05d0\u05dc\u05d9\u05e0\u05d5 \u2013 \u05d7\u05d1\u05e8, \u05d1\u05df \u05de\u05e9\u05e4\u05d7\u05d4 \u05d0\u05d5 \u05e2\u05de\u05d9\u05ea \u05dc\u05e2\u05d1\u05d5\u05d3\u05d4 \u2013 \u05d5\u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05d6\u05d4 \u05d6\u05e8 \u05de\u05d5\u05d7\u05dc\u05d8. \u05d1\u05de\u05e7\u05e8\u05d9\u05dd \u05e8\u05d1\u05d9\u05dd, \u05d4\u05ea\u05d2\u05d5\u05d1\u05d4 \u05d4\u05d8\u05d1\u05e2\u05d9\u05ea \u05e9\u05dc\u05e0\u05d5 \u05d4\u05d9\u05d0 \u05dc\u05d4\u05d9\u05e4\u05d2\u05e2, \u05dc\u05db\u05e2\u05d5\u05e1, \u05d0\u05d5 \u05dc\u05d4\u05e8\u05d2\u05d9\u05e9 \u05de\u05d5\u05ea\u05e7\u05e4\u05d9\u05dd. \u05d0\u05d1\u05dc \u05d4\u05d0\u05dd \u05d9\u05e9 \u05d3\u05e8\u05da \u05d8\u05d5\u05d1\u05d4 \u05d9\u05d5\u05ea\u05e8 \u05dc\u05d4\u05ea\u05de\u05d5\u05d3\u05d3 \u05e2\u05dd \u05de\u05e6\u05d1\u05d9\u05dd \u05db\u05d0\u05dc\u05d4?\n\u05d0\u05d7\u05d3 \u05d4\u05de\u05e9\u05e4\u05d8\u05d9\u05dd \u05de\u05e2\u05d5\u05e8\u05e8\u05d9 \u05d4\u05d4\u05e9\u05e8\u05d0\u05d4 \u05d1\u05ea\u05e4\u05d9\u05dc\u05d4, "\u05e0\u05e4\u05e9\u05d9 \u05db\u05e2\u05e4\u05e8 \u05dc\u05db\u05dc \u05ea\u05d4\u05d9\u05d4", \u05de\u05e6\u05d9\u05e2 \u05d2\u05d9\u05e9\u05d4 \u05d0\u05d7\u05e8\u05ea \u2013 \u05d3\u05e8\u05da \u05e9\u05dc \u05e2\u05e0\u05d5\u05d5\u05d4, \u05d7\u05d5\u05e1\u05df \u05e0\u05e4\u05e9\u05d9 \u05d5\u05e9\u05dc\u05d5\u05d5\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea. \u05d1\u05de\u05d0\u05de\u05e8 \u05d6\u05d4, \u05e0\u05e2\u05de\u05d9\u05e7 \u05d1\u05de\u05e9\u05de\u05e2\u05d5\u05ea \u05d4\u05de\u05e9\u05e4\u05d8 \u05d5\u05e0\u05dc\u05de\u05d3 \u05db\u05d9\u05e6\u05d3 \u05e0\u05d9\u05ea\u05df \u05dc\u05e4\u05ea\u05d7 \u05e2\u05de\u05d9\u05d3\u05d5\u05ea \u05e8\u05d2\u05e9\u05d9\u05ea \u05d5\u05dc\u05de\u05e0\u05d5\u05e2 \u05de\u05d0\u05d7\u05e8\u05d9\u05dd \u05dc\u05e2\u05e8\u05e2\u05e8 \u05d0\u05ea \u05d4\u05e9\u05dc\u05d5\u05d5\u05d4 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05e9\u05dc\u05e0\u05d5.\n1. \u05de\u05d4 \u05e4\u05d9\u05e8\u05d5\u05e9 "\u05e0\u05e4\u05e9\u05d9 \u05db\u05e2\u05e4\u05e8 \u05dc\u05db\u05dc \u05ea\u05d4\u05d9\u05d4"?\n\u05d4\u05d1\u05d9\u05d8\u05d5\u05d9 \u05de\u05d5\u05e4\u05d9\u05e2 \u05d1\u05ea\u05e4\u05d9\u05dc\u05ea \u05e9\u05de\u05d5\u05e0\u05d4 \u05e2\u05e9\u05e8\u05d4 \u05db\u05d7\u05dc\u05e7 \u05de\u05d1\u05e7\u05e9\u05ea\u05e0\u05d5 \u05dc\u05e4\u05e0\u05d9 \u05d4\':\n"\u05d5\u05b0\u05e0\u05b7\u05e4\u05b0\u05e9\u05b4\u05c1\u05d9 \u05db\u05b6\u05bc\u05e2\u05b8\u05e4\u05b8\u05e8 \u05dc\u05b7\u05db\u05b9\u05bc\u05dc \u05ea\u05b4\u05bc\u05d4\u05b0\u05d9\u05b6\u05d4, \u05e4\u05b0\u05bc\u05ea\u05b7\u05d7 \u05dc\u05b4\u05d1\u05b4\u05bc\u05d9 \u05d1\u05b0\u05bc\u05ea\u05d5\u05b9\u05e8\u05b8\u05ea\u05b6\u05da\u05b8 \u05d5\u05bc\u05d1\u05b0\u05de\u05b4\u05e6\u05b0\u05d5\u05b9\u05ea\u05b6\u05d9\u05da\u05b8 \u05ea\u05b4\u05bc\u05e8\u05b0\u05d3\u05bc\u05d5\u05b9\u05e3 \u05e0\u05b7\u05e4\u05b0\u05e9\u05b4\u05c1\u05d9."\n\u05d4\u05de\u05e9\u05de\u05e2\u05d5\u05ea \u05d4\u05e4\u05e9\u05d5\u05d8\u05d4 \u05d4\u05d9\u05d0 \u05e2\u05e0\u05d5\u05d5\u05d4 \u05d5\u05d4\u05e9\u05dc\u05de\u05d4 \u05e2\u05dd \u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea, \u05d0\u05da \u05d9\u05e9 \u05db\u05d0\u05df \u05e2\u05d5\u05de\u05e7 \u05e8\u05d1 \u05d9\u05d5\u05ea\u05e8: \u05db\u05de\u05d5 \u05e9\u05d4\u05e2\u05e4\u05e8 \u05e0\u05de\u05e6\u05d0 \u05d1\u05db\u05dc \u05de\u05e7\u05d5\u05dd, \u05e0\u05e8\u05de\u05e1 \u05dc\u05e2\u05d9\u05ea\u05d9\u05dd, \u05d0\u05da \u05d0\u05d9\u05e0\u05d5 \u05de\u05d0\u05d1\u05d3 \u05de\u05e2\u05e8\u05db\u05d5 \u05d5\u05d0\u05d9\u05e0\u05d5 \u05de\u05e9\u05ea\u05e0\u05d4 \u05d1\u05de\u05d4\u05d5\u05ea\u05d5, \u05db\u05da \u05d2\u05dd \u05d0\u05e0\u05d5 \u05e6\u05e8\u05d9\u05db\u05d9\u05dd \u05dc\u05e9\u05d0\u05d5\u05e3 \u05dc\u05d0 \u05dc\u05d4\u05ea\u05e8\u05d2\u05e9 \u05de\u05db\u05dc \u05de\u05d9\u05dc\u05d4 \u05e9\u05e0\u05d0\u05de\u05e8\u05ea \u05e0\u05d2\u05d3\u05e0\u05d5 \u05d5\u05dc\u05d0 \u05dc\u05ea\u05ea \u05dc\u05d0\u05d7\u05e8\u05d9\u05dd \u05dc\u05e2\u05e8\u05e2\u05e8 \u05d0\u05d5\u05ea\u05e0\u05d5.\n\u05d2\u05d9\u05e9\u05d4 \u05d6\u05d5 \u05d0\u05d9\u05e0\u05e0\u05d4 \u05d7\u05d5\u05dc\u05e9\u05d4 \u05d0\u05d5 \u05d5\u05d9\u05ea\u05d5\u05e8 \u05e2\u05e6\u05de\u05d9, \u05d0\u05dc\u05d0 \u05d3\u05d5\u05d5\u05e7\u05d0 \u05d1\u05d9\u05d8\u05d5\u05d9 \u05dc\u05d7\u05d5\u05e1\u05df \u05e4\u05e0\u05d9\u05de\u05d9 \u05d0\u05d3\u05d9\u05e8 \u2013 \u05dc\u05d3\u05e2\u05ea \u05de\u05ea\u05d9 \u05dc\u05d0 \u05dc\u05ea\u05ea \u05dc\u05e8\u05d2\u05e9\u05d5\u05ea \u05e9\u05dc\u05d9\u05dc\u05d9\u05d9\u05dd \u05dc\u05e9\u05dc\u05d5\u05d8 \u05d1\u05e0\u05d5.\n2. \u05dc\u05de\u05d4 \u05d0\u05e0\u05d5 \u05e0\u05e2\u05dc\u05d1\u05d9\u05dd \u05d1\u05e7\u05dc\u05d5\u05ea \u05d5\u05de\u05d4 \u05d6\u05d4 \u05d2\u05d5\u05e8\u05dd \u05dc\u05e0\u05d5?\n\u05d4\u05e0\u05d8\u05d9\u05d9\u05d4 \u05dc\u05d4\u05d9\u05e4\u05d2\u05e2 \u05d5\u05dc\u05d4\u05ea\u05e8\u05d2\u05e9 \u05de\u05db\u05dc \u05de\u05d9\u05dc\u05d4 \u05e0\u05d5\u05d1\u05e2\u05ea \u05de\u05de\u05e1\u05e4\u05e8 \u05d2\u05d5\u05e8\u05de\u05d9\u05dd \u05e4\u05e1\u05d9\u05db\u05d5\u05dc\u05d5\u05d2\u05d9\u05d9\u05dd:\n\u05e6\u05d5\u05e8\u05da \u05d1\u05d0\u05d9\u05e9\u05d5\u05e8 \u05d7\u05d9\u05e6\u05d5\u05e0\u05d9 \u2013 \u05d0\u05e0\u05d5 \u05e8\u05d5\u05e6\u05d9\u05dd \u05e9\u05d9\u05e2\u05e8\u05d9\u05db\u05d5 \u05d0\u05d5\u05ea\u05e0\u05d5, \u05d5\u05dc\u05db\u05df \u05d1\u05d9\u05e7\u05d5\u05e8\u05ea \u05d0\u05d5 \u05d3\u05d7\u05d9\u05d9\u05d4 \u05e0\u05ea\u05e4\u05e1\u05d5\u05ea \u05db\u05d0\u05d9\u05d5\u05dd.\n\u05e4\u05e8\u05e9\u05e0\u05d5\u05ea \u05d0\u05d9\u05e9\u05d9\u05ea \u05e9\u05dc\u05d9\u05dc\u05d9\u05ea \u2013 \u05dc\u05e2\u05d9\u05ea\u05d9\u05dd \u05d0\u05e0\u05d5 \u05de\u05e4\u05e8\u05e9\u05d9\u05dd \u05d4\u05e2\u05e8\u05d5\u05ea \u05ea\u05de\u05d9\u05de\u05d5\u05ea \u05db\u05d4\u05ea\u05e7\u05e4\u05d4 \u05d0\u05d9\u05e9\u05d9\u05ea.\n\u05e4\u05d2\u05d9\u05e2\u05d5\u05ea \u05d0\u05d9\u05e9\u05d9\u05ea \u05d2\u05d1\u05d5\u05d4\u05d4 \u2013 \u05db\u05d0\u05e9\u05e8 \u05d0\u05e0\u05d5 \u05d7\u05d5\u05d5\u05d9\u05dd \u05d7\u05d5\u05e1\u05e8 \u05d1\u05d9\u05d8\u05d7\u05d5\u05df, \u05db\u05dc \u05d0\u05de\u05d9\u05e8\u05d4 \u05e9\u05d5\u05dc\u05d9\u05ea \u05d9\u05db\u05d5\u05dc\u05d4 \u05dc\u05d2\u05e2\u05ea \u05d1\u05e0\u05e7\u05d5\u05d3\u05d4 \u05e8\u05d2\u05d9\u05e9\u05d4.\n\u05e8\u05e6\u05d5\u05df \u05dc\u05e9\u05dc\u05d9\u05d8\u05d4 \u2013 \u05d0\u05e0\u05d5 \u05de\u05e6\u05e4\u05d9\u05dd \u05e9\u05d0\u05d7\u05e8\u05d9\u05dd \u05d9\u05ea\u05e0\u05d4\u05d2\u05d5 \u05db\u05e4\u05d9 \u05e9\u05d4\u05d9\u05d9\u05e0\u05d5 \u05e8\u05d5\u05e6\u05d9\u05dd, \u05d5\u05db\u05e9\u05d4\u05dd \u05dc\u05d0 \u05e2\u05d5\u05de\u05d3\u05d9\u05dd \u05d1\u05e6\u05d9\u05e4\u05d9\u05d5\u05ea, \u05d6\u05d4 \u05de\u05ea\u05e1\u05db\u05dc \u05d0\u05d5\u05ea\u05e0\u05d5.\n\u05d0\u05d1\u05dc \u05de\u05d4 \u05d4\u05de\u05d7\u05d9\u05e8 \u05e9\u05dc \u05e8\u05d2\u05d9\u05e9\u05d5\u05ea \u05d9\u05ea\u05e8 \u05db\u05d6\u05d5?\n\u05db\u05e9\u05d0\u05e0\u05d5 \u05e0\u05e2\u05dc\u05d1\u05d9\u05dd \u05d1\u05e7\u05dc\u05d5\u05ea, \u05d0\u05e0\u05d5 \u05d7\u05d9\u05d9\u05dd \u05d1\u05ea\u05dc\u05d5\u05ea \u05e8\u05d2\u05e9\u05d9\u05ea \u05d1\u05d0\u05d7\u05e8\u05d9\u05dd. \u05de\u05e6\u05d1 \u05e8\u05d5\u05d7\u05e0\u05d5 \u05e0\u05e7\u05d1\u05e2 \u05dc\u05e4\u05d9 \u05d4\u05ea\u05e0\u05d4\u05d2\u05d5\u05ea\u05dd \u05d5\u05d3\u05d1\u05e8\u05d9\u05d4\u05dd \u05e9\u05dc \u05d0\u05e0\u05e9\u05d9\u05dd \u05d0\u05d7\u05e8\u05d9\u05dd, \u05d5\u05d0\u05e0\u05d5 \u05de\u05d0\u05d1\u05d3\u05d9\u05dd \u05e9\u05dc\u05d9\u05d8\u05d4 \u05e2\u05dc \u05d4\u05e8\u05d2\u05e9\u05d5\u05ea \u05e9\u05dc\u05e0\u05d5.\n3. \u05db\u05d9\u05e6\u05d3 \u05dc\u05e4\u05ea\u05d7 \u05d7\u05e1\u05d9\u05e0\u05d5\u05ea \u05e8\u05d2\u05e9\u05d9\u05ea \u05d5\u05dc\u05d4\u05d9\u05de\u05e0\u05e2 \u05de\u05d4\u05d9\u05e2\u05dc\u05d1\u05d5\u05ea \u05d9\u05ea\u05e8?\n\u05d0. \u05d0\u05d9\u05de\u05d5\u05e5 \u05d2\u05d9\u05e9\u05d4 \u05e9\u05dc "\u05e0\u05e4\u05e9\u05d9 \u05db\u05e2\u05e4\u05e8 \u05dc\u05db\u05dc \u05ea\u05d4\u05d9\u05d4"\n\u05dc\u05d4\u05d1\u05d9\u05df \u05e9\u05dc\u05d0 \u05db\u05dc \u05de\u05d9\u05dc\u05d4 \u05e9\u05e0\u05d0\u05de\u05e8\u05ea \u05e2\u05dc\u05d9\u05e0\u05d5 \u05de\u05e9\u05e7\u05e4\u05ea \u05d0\u05ea \u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea. \u05d0\u05e0\u05e9\u05d9\u05dd \u05de\u05d3\u05d1\u05e8\u05d9\u05dd \u05de\u05ea\u05d5\u05da \u05d7\u05d5\u05d5\u05d9\u05d5\u05ea\u05d9\u05d4\u05dd, \u05e4\u05d7\u05d3\u05d9\u05d4\u05dd \u05d5\u05dc\u05e2\u05d9\u05ea\u05d9\u05dd \u05de\u05ea\u05d5\u05da \u05d7\u05d5\u05e1\u05e8 \u05de\u05d7\u05e9\u05d1\u05d4.\n\u05dc\u05d0 \u05dc\u05ea\u05ea \u05dc\u05de\u05d9\u05dc\u05d9\u05dd \u05e9\u05dc \u05d0\u05d7\u05e8\u05d9\u05dd \u05db\u05d5\u05d7 \u05dc\u05e9\u05dc\u05d5\u05d8 \u05d1\u05e8\u05d2\u05e9\u05d5\u05ea \u05e9\u05dc\u05e0\u05d5.\n\u05dc\u05d6\u05db\u05d5\u05e8 \u05e9\u05d4\u05e2\u05e8\u05da \u05d4\u05e2\u05e6\u05de\u05d9 \u05e9\u05dc\u05e0\u05d5 \u05dc\u05d0 \u05e0\u05e7\u05d1\u05e2 \u05dc\u05e4\u05d9 \u05d3\u05e2\u05ea\u05dd \u05e9\u05dc \u05d0\u05d7\u05e8\u05d9\u05dd.\n\u05d1. \u05dc\u05d4\u05e4\u05e8\u05d9\u05d3 \u05d1\u05d9\u05df \u05d3\u05e2\u05d4 \u05d7\u05d9\u05e6\u05d5\u05e0\u05d9\u05ea \u05dc\u05d1\u05d9\u05df \u05d4\u05d6\u05d4\u05d5\u05ea \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05e9\u05dc\u05e0\u05d5\n\u05d1\u05d9\u05e7\u05d5\u05e8\u05ea \u05d0\u05d9\u05e0\u05d4 \u05d1\u05d4\u05db\u05e8\u05d7 \u05d4\u05ea\u05e7\u05e4\u05d4 \u05d0\u05d9\u05e9\u05d9\u05ea \u2013 \u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05d4\u05d9\u05d0 \u05d9\u05db\u05d5\u05dc\u05d4 \u05dc\u05e2\u05d6\u05d5\u05e8 \u05dc\u05e0\u05d5 \u05dc\u05d4\u05e9\u05ea\u05e4\u05e8.\n\u05d2\u05dd \u05d0\u05dd \u05de\u05d9\u05e9\u05d4\u05d5 \u05ea\u05d5\u05e7\u05e3 \u05d0\u05d5\u05ea\u05e0\u05d5 \u05de\u05d9\u05dc\u05d5\u05dc\u05d9\u05ea, \u05d6\u05d4 \u05d9\u05d5\u05ea\u05e8 \u05de\u05e2\u05d9\u05d3 \u05e2\u05dc\u05d9\u05d5 \u05de\u05d0\u05e9\u05e8 \u05e2\u05dc\u05d9\u05e0\u05d5.\n\u05d2. \u05d7\u05d9\u05d6\u05d5\u05e7 \u05d4\u05d1\u05d9\u05d8\u05d7\u05d5\u05df \u05d4\u05e2\u05e6\u05de\u05d9\n\u05d0\u05d3\u05dd \u05d1\u05d8\u05d5\u05d7 \u05d1\u05e2\u05e6\u05de\u05d5 \u05e4\u05d7\u05d5\u05ea \u05e0\u05e2\u05dc\u05d1, \u05db\u05d9 \u05d4\u05d5\u05d0 \u05d0\u05d9\u05e0\u05d5 \u05ea\u05dc\u05d5\u05d9 \u05d1\u05de\u05d4 \u05e9\u05d0\u05d7\u05e8\u05d9\u05dd \u05d0\u05d5\u05de\u05e8\u05d9\u05dd \u05e2\u05dc\u05d9\u05d5.\n\u05e2\u05d1\u05d5\u05d3\u05d4 \u05e2\u05dc \u05d4\u05d4\u05e2\u05e8\u05db\u05d4 \u05d4\u05e2\u05e6\u05de\u05d9\u05ea \u05d9\u05db\u05d5\u05dc\u05d4 \u05dc\u05db\u05dc\u05d5\u05dc \u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4, \u05ea\u05e4\u05d9\u05dc\u05d4, \u05dc\u05d9\u05de\u05d5\u05d3 \u05d5\u05d4\u05ea\u05e4\u05ea\u05d7\u05d5\u05ea \u05d0\u05d9\u05e9\u05d9\u05ea.\n\u05d3. \u05dc\u05ea\u05e8\u05d2\u05dc \u05e0\u05e9\u05d9\u05de\u05d4 \u05d5\u05e9\u05dc\u05d9\u05d8\u05d4 \u05e2\u05e6\u05de\u05d9\u05ea\n\u05db\u05e9\u05de\u05e8\u05d2\u05d9\u05e9\u05d9\u05dd \u05e9\u05e2\u05d5\u05de\u05d3\u05d9\u05dd \u05dc\u05d4\u05ea\u05e8\u05d2\u05d6 \u05d0\u05d5 \u05dc\u05d4\u05d9\u05e2\u05dc\u05d1, \u05dc\u05e2\u05e6\u05d5\u05e8, \u05dc\u05e7\u05d7\u05ea \u05e0\u05e9\u05d9\u05de\u05d4 \u05e2\u05de\u05d5\u05e7\u05d4 \u05d5\u05dc\u05e9\u05d0\u05d5\u05dc: "\u05d4\u05d0\u05dd \u05d6\u05d4 \u05d1\u05d0\u05de\u05ea \u05d7\u05e9\u05d5\u05d1? \u05d4\u05d0\u05dd \u05d6\u05d4 \u05e6\u05e8\u05d9\u05da \u05dc\u05d4\u05e9\u05e4\u05d9\u05e2 \u05e2\u05dc\u05d9\u05d9?"\n\u05e4\u05e2\u05de\u05d9\u05dd \u05e8\u05d1\u05d5\u05ea \u05e0\u05d2\u05dc\u05d4 \u05e9\u05d4\u05ea\u05e9\u05d5\u05d1\u05d4 \u05d4\u05d9\u05d0 \u05dc\u05d0.\n4. \u05de\u05ea\u05d9 \u05db\u05df \u05dc\u05d4\u05d2\u05d9\u05d1 \u05d5\u05db\u05d9\u05e6\u05d3?\n\u05dc\u05de\u05e8\u05d5\u05ea \u05d4\u05d2\u05d9\u05e9\u05d4 \u05e9\u05dc "\u05e0\u05e4\u05e9\u05d9 \u05db\u05e2\u05e4\u05e8 \u05dc\u05db\u05dc \u05ea\u05d4\u05d9\u05d4", \u05d9\u05e9 \u05de\u05e6\u05d1\u05d9\u05dd \u05d1\u05d4\u05dd \u05d7\u05e9\u05d5\u05d1 \u05dc\u05d4\u05d2\u05d9\u05d1 \u05d5\u05dc\u05d4\u05e6\u05d9\u05d1 \u05d2\u05d1\u05d5\u05dc\u05d5\u05ea:\n\u05d0\u05dd \u05de\u05d9\u05e9\u05d4\u05d5 \u05e4\u05d5\u05d2\u05e2 \u05d1\u05e0\u05d5 \u05d1\u05d0\u05d5\u05e4\u05df \u05de\u05ea\u05de\u05e9\u05da, \u05d0\u05d9\u05df \u05e6\u05d5\u05e8\u05da \u05dc\u05e9\u05ea\u05d5\u05e7 \u2013 \u05d0\u05dc\u05d0 \u05dc\u05d4\u05e6\u05d9\u05d1 \u05d2\u05d1\u05d5\u05dc\u05d5\u05ea \u05d1\u05e8\u05d5\u05e8\u05d9\u05dd.\n\u05d0\u05dd \u05de\u05d3\u05d5\u05d1\u05e8 \u05d1\u05d9\u05d7\u05e1\u05d9\u05dd \u05d7\u05e9\u05d5\u05d1\u05d9\u05dd \u05dc\u05e0\u05d5, \u05d0\u05e4\u05e9\u05e8 \u05dc\u05d4\u05e1\u05d1\u05d9\u05e8 \u05d1\u05e0\u05d7\u05ea \u05de\u05d4 \u05de\u05e4\u05e8\u05d9\u05e2 \u05dc\u05e0\u05d5 \u05d5\u05dc\u05d1\u05e7\u05e9 \u05e9\u05d9\u05e0\u05d5\u05d9.\n\u05e2\u05dd \u05d6\u05d0\u05ea, \u05d0\u05dd \u05de\u05d3\u05d5\u05d1\u05e8 \u05d1\u05d0\u05de\u05d9\u05e8\u05d4 \u05d7\u05e1\u05e8\u05ea \u05de\u05e9\u05de\u05e2\u05d5\u05ea \u05de\u05de\u05d9\u05e9\u05d4\u05d5 \u05e9\u05d0\u05d9\u05e0\u05d5 \u05d7\u05e9\u05d5\u05d1 \u05dc\u05e0\u05d5, \u05d4\u05ea\u05d2\u05d5\u05d1\u05d4 \u05d4\u05d8\u05d5\u05d1\u05d4 \u05d1\u05d9\u05d5\u05ea\u05e8 \u05d4\u05d9\u05d0 \u05d0\u05d3\u05d9\u05e9\u05d5\u05ea.\n\u05e1\u05d9\u05db\u05d5\u05dd: \u05db\u05d5\u05d7\u05d5 \u05e9\u05dc \u05d4\u05e9\u05e7\u05d8 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\n\u05dc\u05dc\u05de\u05d5\u05d3 \u05dc\u05d0 \u05dc\u05d4\u05d9\u05e4\u05d2\u05e2 \u05de\u05db\u05dc \u05d3\u05d1\u05e8 \u05d6\u05d5 \u05de\u05d9\u05d5\u05de\u05e0\u05d5\u05ea \u05d7\u05e9\u05d5\u05d1\u05d4 \u05e9\u05d9\u05db\u05d5\u05dc\u05d4 \u05dc\u05e9\u05e4\u05e8 \u05de\u05e9\u05de\u05e2\u05d5\u05ea\u05d9\u05ea \u05d0\u05ea \u05d0\u05d9\u05db\u05d5\u05ea \u05d7\u05d9\u05d9\u05e0\u05d5. \u05db\u05d0\u05e9\u05e8 \u05d0\u05e0\u05d5 \u05de\u05d0\u05de\u05e6\u05d9\u05dd \u05d0\u05ea \u05d2\u05d9\u05e9\u05ea "\u05e0\u05e4\u05e9\u05d9 \u05db\u05e2\u05e4\u05e8 \u05dc\u05db\u05dc \u05ea\u05d4\u05d9\u05d4", \u05d0\u05e0\u05d5 \u05dc\u05d0 \u05d4\u05d5\u05e4\u05db\u05d9\u05dd \u05dc\u05d0\u05d3\u05d9\u05e9\u05d9\u05dd, \u05d0\u05dc\u05d0 \u05de\u05e4\u05ea\u05d7\u05d9\u05dd \u05d7\u05d5\u05e1\u05df \u05e0\u05e4\u05e9\u05d9 \u05d0\u05de\u05d9\u05ea\u05d9 \u05e9\u05de\u05d0\u05e4\u05e9\u05e8 \u05dc\u05e0\u05d5 \u05dc\u05d7\u05d9\u05d5\u05ea \u05d1\u05e9\u05dc\u05d5\u05d5\u05d4 \u05d5\u05dc\u05d0 \u05dc\u05d4\u05d9\u05d5\u05ea \u05ea\u05dc\u05d5\u05d9\u05d9\u05dd \u05d1\u05e8\u05d2\u05e9\u05d5\u05ea \u05e9\u05dc \u05d0\u05d7\u05e8\u05d9\u05dd.\n\u05d1\u05e1\u05d5\u05e4\u05d5 \u05e9\u05dc \u05d3\u05d1\u05e8, \u05d4\u05d1\u05d7\u05d9\u05e8\u05d4 \u05d4\u05d9\u05d0 \u05e9\u05dc\u05e0\u05d5: \u05d4\u05d0\u05dd \u05dc\u05ea\u05ea \u05dc\u05d0\u05d7\u05e8\u05d9\u05dd \u05d0\u05ea \u05d4\u05db\u05d5\u05d7 \u05dc\u05e7\u05d1\u05d5\u05e2 \u05d0\u05d9\u05da \u05e0\u05e8\u05d2\u05d9\u05e9, \u05d0\u05d5 \u05dc\u05e7\u05d7\u05ea \u05d0\u05d7\u05e8\u05d9\u05d5\u05ea \u05e2\u05dc \u05d4\u05e8\u05d2\u05e9\u05d5\u05ea \u05e9\u05dc\u05e0\u05d5 \u05d5\u05dc\u05d1\u05d7\u05d5\u05e8 \u05d1\u05d7\u05d9\u05d9\u05dd \u05e9\u05dc \u05e8\u05d5\u05d2\u05e2 \u05d5\u05e9\u05dc\u05d5\u05d5\u05d4?\n\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05dc\u05e9\u05d7\u05e8\u05d5\u05e8 \u05d4\u05d9\u05e2\u05dc\u05d1\u05d5\u05ea \u05d5\u05dc\u05d7\u05d9\u05d6\u05d5\u05e7 \u05d4\u05e9\u05dc\u05d5\u05d5\u05d4 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05ea\n\ud83e\uddd8\u200d\u2642\ufe0f \u05d4\u05db\u05e0\u05d4 \u05dc\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4\n\u05de\u05e6\u05d0 \u05de\u05e7\u05d5\u05dd \u05e9\u05e7\u05d8 \u05d5\u05e0\u05d5\u05d7. \u05e9\u05d1 \u05d1\u05ea\u05e0\u05d5\u05d7\u05d4 \u05e8\u05d2\u05d5\u05e2\u05d4, \u05e2\u05e6\u05de\u05da \u05d0\u05ea \u05d4\u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05d5\u05e7\u05d7 \u05e0\u05e9\u05d9\u05de\u05d4 \u05e2\u05de\u05d5\u05e7\u05d4 \u05e4\u05e0\u05d9\u05de\u05d4... \u05d5\u05e9\u05d7\u05e8\u05e8 \u05dc\u05d0\u05d8.\n\u2728 \u05e9\u05dc\u05d1 1: \u05d7\u05d9\u05d1\u05d5\u05e8 \u05dc\u05e8\u05d5\u05d2\u05e2 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\n\u05e0\u05e9\u05d5\u05dd \u05e2\u05de\u05d5\u05e7 \u05d3\u05e8\u05da \u05d4\u05d0\u05e3... \u05d5\u05e9\u05d7\u05e8\u05e8 \u05dc\u05d0\u05d8 \u05d3\u05e8\u05da \u05d4\u05e4\u05d4.\n\u05d3\u05de\u05d9\u05d9\u05df \u05d0\u05ea \u05e2\u05e6\u05de\u05da \u05db\u05de\u05d5 \u05e2\u05e4\u05e8 \u05e8\u05da... \u05db\u05de\u05d5 \u05d4\u05d0\u05d3\u05de\u05d4 \u05e9\u05de\u05ea\u05d7\u05ea \u05dc\u05e8\u05d2\u05dc\u05d9\u05d9\u05dd \u2013 \u05d9\u05e6\u05d9\u05d1\u05d4, \u05d7\u05d6\u05e7\u05d4, \u05d0\u05da \u05d0\u05d9\u05e0\u05d4 \u05e0\u05e1\u05e2\u05e8\u05ea \u05de\u05d4\u05e8\u05d5\u05d7\u05d5\u05ea \u05d4\u05e0\u05d5\u05e9\u05d1\u05d5\u05ea \u05de\u05e2\u05dc\u05d9\u05d4.\n\ud83c\udf00 \u05e9\u05dc\u05d1 2: \u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea \u05e2\u05dc \u05d4\u05e4\u05d2\u05d9\u05e2\u05d5\u05ea \u05e9\u05dc\u05da\n\u05d4\u05d9\u05d6\u05db\u05e8 \u05d1\u05de\u05e6\u05d1 \u05e9\u05d1\u05d5 \u05de\u05d9\u05e9\u05d4\u05d5 \u05d0\u05de\u05e8 \u05dc\u05da \u05de\u05e9\u05d4\u05d5 \u05e9\u05e4\u05d2\u05e2 \u05d1\u05da.\n\u05d4\u05ea\u05d1\u05d5\u05e0\u05df \u05d1\u05e8\u05d2\u05e9 \u05e9\u05e2\u05d5\u05dc\u05d4... \u05d0\u05d5\u05dc\u05d9 \u05d6\u05d4 \u05db\u05e2\u05e1, \u05d0\u05d5\u05dc\u05d9 \u05db\u05d0\u05d1, \u05d0\u05d5\u05dc\u05d9 \u05ea\u05e1\u05db\u05d5\u05dc.\n\u05db\u05e2\u05ea, \u05e0\u05e1\u05d4 \u05dc\u05e8\u05d0\u05d5\u05ea \u05d0\u05ea \u05d4\u05e8\u05d2\u05e9 \u05d4\u05d6\u05d4 \u05db\u05de\u05d5 \u05e2\u05e0\u05df \u05d7\u05d5\u05dc\u05e3 \u05d1\u05e9\u05de\u05d9\u05d9\u05dd \u2013 \u05d4\u05d5\u05d0 \u05d1\u05d0, \u05d0\u05da \u05d4\u05d5\u05d0 \u05d2\u05dd \u05d9\u05db\u05d5\u05dc \u05dc\u05d4\u05d9\u05e2\u05dc\u05dd.\n\ud83c\udf3f \u05e9\u05dc\u05d1 3: \u05e9\u05d7\u05e8\u05d5\u05e8 \u05d4\u05d9\u05e2\u05dc\u05d1\u05d5\u05ea \u05d5\u05e7\u05d1\u05dc\u05ea \u05e9\u05dc\u05d5\u05d5\u05d4\n\u05d0\u05de\u05d5\u05e8 \u05dc\u05e2\u05e6\u05de\u05da \u05d1\u05dc\u05d1 \u05d0\u05d5 \u05d1\u05e7\u05d5\u05dc:\n"\u05d0\u05e0\u05d9 \u05de\u05e9\u05d7\u05e8\u05e8/\u05ea \u05db\u05dc \u05e2\u05dc\u05d1\u05d5\u05df"\n"\u05d0\u05e0\u05d9 \u05d7\u05d6\u05e7/\u05d4 \u05de\u05d1\u05e4\u05e0\u05d9\u05dd"\n"\u05d4\u05de\u05d9\u05dc\u05d9\u05dd \u05e9\u05dc \u05d0\u05d7\u05e8\u05d9\u05dd \u05d0\u05d9\u05e0\u05df \u05de\u05d2\u05d3\u05d9\u05e8\u05d5\u05ea \u05d0\u05d5\u05ea\u05d9"\n"\u05e0\u05e4\u05e9\u05d9 \u05db\u05e2\u05e4\u05e8 \u05dc\u05db\u05dc \u05ea\u05d4\u05d9\u05d4 \u2013 \u05d0\u05e0\u05d9 \u05d9\u05e6\u05d9\u05d1/\u05d4, \u05e8\u05d2\u05d5\u05e2/\u05d4 \u05d5\u05e9\u05dc\u05d9\u05d5/\u05d4"\n\u05d3\u05de\u05d9\u05d9\u05df \u05d0\u05d9\u05da \u05d4\u05de\u05d9\u05dc\u05d9\u05dd \u05d4\u05e4\u05d5\u05d2\u05e2\u05d5\u05ea \u05d4\u05d5\u05e4\u05db\u05d5\u05ea \u05dc\u05d0\u05d1\u05e7 \u05e9\u05de\u05ea\u05e4\u05d6\u05e8 \u05d1\u05e8\u05d5\u05d7, \u05e8\u05d7\u05d5\u05e7 \u05de\u05de\u05da.\n\u05d0\u05ea\u05d4 \u05e0\u05e9\u05d0\u05e8 \u05d9\u05e6\u05d9\u05d1, \u05e9\u05e7\u05d8, \u05de\u05d7\u05d5\u05d1\u05e8 \u05dc\u05e2\u05e6\u05de\u05da.\n\ud83c\udf05 \u05e9\u05dc\u05d1 4: \u05d4\u05ea\u05de\u05dc\u05d0\u05d5\u05ea \u05d1\u05d0\u05e0\u05e8\u05d2\u05d9\u05d4 \u05d7\u05d9\u05d5\u05d1\u05d9\u05ea\n\u05db\u05e2\u05ea, \u05d3\u05de\u05d9\u05d9\u05df \u05d0\u05d5\u05e8 \u05e8\u05da \u05d5\u05d7\u05dd \u05de\u05de\u05dc\u05d0 \u05d0\u05d5\u05ea\u05da \u05de\u05d1\u05e4\u05e0\u05d9\u05dd \u2013 \u05d0\u05d5\u05e8 \u05e9\u05dc \u05d1\u05d9\u05d8\u05d7\u05d5\u05df, \u05e9\u05dc \u05d0\u05d4\u05d1\u05d4 \u05e2\u05e6\u05de\u05d9\u05ea, \u05e9\u05dc \u05d7\u05d5\u05e4\u05e9 \u05e8\u05d2\u05e9\u05d9.\n\u05e0\u05e9\u05d5\u05dd \u05e2\u05de\u05d5\u05e7...\n\u05ea\u05df \u05dc\u05e8\u05d5\u05d2\u05e2 \u05dc\u05d4\u05ea\u05e4\u05e9\u05d8 \u05d1\u05db\u05dc \u05d2\u05d5\u05e4\u05da\u2026\n\ud83c\udf3f \u05e1\u05d9\u05d5\u05dd \u05d4\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4\n\u05d1\u05e2\u05d3\u05d9\u05e0\u05d5\u05ea, \u05e4\u05ea\u05d7 \u05d0\u05ea \u05d4\u05e2\u05d9\u05e0\u05d9\u05d9\u05dd.\n\u05e9\u05d9\u05dd \u05dc\u05d1 \u05d0\u05d9\u05da \u05d0\u05ea\u05d4 \u05de\u05e8\u05d2\u05d9\u05e9 \u2013 \u05d9\u05d5\u05ea\u05e8 \u05e7\u05dc\u05d9\u05dc, \u05d9\u05d5\u05ea\u05e8 \u05e9\u05e7\u05d8, \u05d9\u05d5\u05ea\u05e8 \u05d7\u05d6\u05e7 \u05de\u05d1\u05e4\u05e0\u05d9\u05dd.\n\u05e7\u05d7 \u05d0\u05d9\u05ea\u05da \u05d0\u05ea \u05d4\u05ea\u05d7\u05d5\u05e9\u05d4 \u05d4\u05d6\u05d5 \u05dc\u05d4\u05de\u05e9\u05da \u05d4\u05d9\u05d5\u05dd.\n\u05db\u05d9 \u05d0\u05e3 \u05de\u05d9\u05dc\u05d4 \u05e9\u05dc \u05d0\u05e3 \u05d0\u05d3\u05dd \u05dc\u05d0 \u05d9\u05db\u05d5\u05dc\u05d4 \u05dc\u05e7\u05d7\u05ea \u05de\u05de\u05da \u05d0\u05ea \u05d4\u05e9\u05dc\u05d5\u05d5\u05d4 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05e9\u05dc\u05da.\n\u05de\u05e2\u05d5\u05dc\u05d4, \u05d4\u05e0\u05d4 \u05e0\u05d5\u05e1\u05d7 \u05de\u05dc\u05d0 \u05e9\u05de\u05d7\u05d1\u05e8 \u05d0\u05ea \u05d1\u05e8\u05db\u05ea \u201c\u05ea\u05df \u05d1\u05dc\u05d9\u05d1\u05d9\u201d \u05e2\u05dd \u05d4\u05d4\u05db\u05e0\u05d4 \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9\u05ea \u05e9\u05dc \u05e1\u05d5\u05db\u05d5\u05ea, \u05e4\u05e8\u05e9\u05ea \u05d0\u05ea\u05d7\u05e0\u05df \u05d5\u05d4\u05d7\u05e1\u05d9\u05d3\u05d5\u05ea, \u05d1\u05d3\u05d2\u05e9 \u05e2\u05dc \u05db\u05e0\u05d9\u05e2\u05d4, \u05e2\u05e0\u05d5\u05d5\u05d4 \u05d5\u05d4\u05ea\u05de\u05e1\u05e8\u05d5\u05ea:\n\u05ea\u05df \u05d1\u05dc\u05d9\u05d1\u05d9 \u2013 \u05d4\u05d4\u05db\u05e0\u05d4 \u05dc\u05d4\u05db\u05e0\u05e2\u05d4 \u05d5\u05e2\u05e0\u05d5\u05d5\u05d4 \u05d1\u05d7\u05e1\u05d9\u05d3\u05d5\u05ea \u05d5\u05d1\u05e1\u05d5\u05db\u05d5\u05ea\n\u05d4\u05d1\u05e8\u05db\u05d4 \u201c\u05ea\u05df \u05d1\u05dc\u05d9\u05d1\u05d9\u201d \u05d4\u05d9\u05d0 \u05d0\u05d7\u05ea \u05d4\u05d1\u05e8\u05db\u05d5\u05ea \u05d4\u05d7\u05e9\u05d5\u05d1\u05d5\u05ea \u05d1\u05d9\u05d5\u05ea\u05e8 \u05d1\u05e2\u05d1\u05d5\u05d3\u05ea \u05d4\u05e8\u05d5\u05d7. \u05d4\u05d9\u05d0 \u05de\u05d1\u05e7\u05e9\u05ea \u05e9\u05d4\u05dc\u05d1 \u05e9\u05dc\u05e0\u05d5 \u05d9\u05e4\u05ea\u05d7, \u05d9\u05ea\u05de\u05e1\u05e8 \u05d5\u05d9\u05ea\u05d9\u05d9\u05e9\u05e8 \u05dc\u05e8\u05e6\u05d5\u05df \u05d4\u05e2\u05dc\u05d9\u05d5\u05df \u2013 \u05d1\u05dc\u05d9 \u05de\u05d0\u05d1\u05e7, \u05d1\u05dc\u05d9 \u05e6\u05d5\u05e8\u05da \u05d1\u05e9\u05dc\u05d9\u05d8\u05d4. \u05db\u05d0\u05df \u05d8\u05de\u05d5\u05df \u05db\u05d5\u05d7 \u05d4\u05e2\u05e0\u05d5\u05d5\u05d4: \u05db\u05e9\u05d0\u05e0\u05d7\u05e0\u05d5 \u05de\u05db\u05d9\u05e8\u05d9\u05dd \u05d1\u05de\u05d2\u05d1\u05dc\u05d5\u05ea\u05d9\u05e0\u05d5 \u05d5\u05de\u05e1\u05db\u05d9\u05de\u05d9\u05dd \u05dc\u05d4\u05e9\u05d0\u05d9\u05e8 \u05d0\u05ea \u05d4\u05d4\u05e0\u05d4\u05d2\u05d4 \u05d1\u05d9\u05d3 \u05d4\u2019, \u05d0\u05e0\u05d7\u05e0\u05d5 \u05e4\u05d5\u05ea\u05d7\u05d9\u05dd \u05de\u05e7\u05d5\u05dd \u05dc\u05d1\u05e8\u05db\u05d4 \u05d5\u05dc\u05e1\u05d3\u05e8 \u05e9\u05de\u05d2\u05d9\u05e2 \u05de\u05d1\u05d7\u05d5\u05e5, \u05d5\u05d0\u05e4\u05d9\u05dc\u05d5 \u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea \u05e1\u05d1\u05d9\u05d1\u05e0\u05d5 \u05de\u05ea\u05d7\u05d9\u05dc\u05d4 \u05dc\u05d6\u05e8\u05d5\u05dd \u05d1\u05e6\u05d5\u05e8\u05d4 \u05d8\u05d1\u05e2\u05d9\u05ea \u05d5\u05d4\u05e8\u05de\u05d5\u05e0\u05d9\u05ea.\n\u05d4\u05d7\u05e1\u05d9\u05d3\u05d5\u05ea \u05de\u05d3\u05d2\u05d9\u05e9\u05d4 \u05e9\u05d1\u05db\u05dc \u05de\u05e2\u05e9\u05d4, \u05d2\u05dd \u05d1\u05ea\u05e4\u05d9\u05dc\u05d5\u05ea \u05d5\u05d2\u05dd \u05d1\u05d4\u05dc\u05d9\u05db\u05d5\u05ea \u05d4\u05d9\u05d5\u05dd-\u05d9\u05d5\u05dd, \u05d4\u05db\u05e0\u05d9\u05e2\u05d4 \u05d4\u05d9\u05d0 \u05d4\u05de\u05e7\u05d5\u05e8 \u05d4\u05d0\u05de\u05d9\u05ea\u05d9 \u05dc\u05db\u05d5\u05d7 \u05d5\u05dc\u05e1\u05d3\u05e8. \u05db\u05e9\u05d0\u05e0\u05d5 \u05e0\u05d6\u05db\u05e8\u05d9\u05dd \u05dc\u05d4\u05d9\u05db\u05e0\u05e2 \u2013 \u05dc\u05d0 \u05dc\u05d5\u05d5\u05ea\u05e8 \u05e2\u05dc \u05e2\u05e6\u05de\u05e0\u05d5, \u05d0\u05dc\u05d0 \u05dc\u05d4\u05db\u05d9\u05e8 \u05e9\u05d4\u05db\u05d5\u05d7 \u05d4\u05e2\u05dc\u05d9\u05d5\u05df \u05e4\u05d5\u05e2\u05dc \u05d3\u05e8\u05db\u05e0\u05d5 \u2013 \u05d4\u05db\u05dc \u05de\u05e1\u05ea\u05d3\u05e8. \u05d4\u05d4\u05ea\u05de\u05e1\u05e8\u05d5\u05ea \u05d4\u05d6\u05d5 \u05d4\u05d9\u05d0 \u05dc\u05d0 \u05d7\u05d5\u05dc\u05e9\u05d4, \u05d0\u05dc\u05d0 \u05d7\u05d5\u05e1\u05df \u05e4\u05e0\u05d9\u05de\u05d9 \u05e9\u05de\u05d7\u05d1\u05e8 \u05d1\u05d9\u05df \u05d4\u05e8\u05e6\u05d5\u05df \u05d4\u05d0\u05d9\u05e9\u05d9 \u05dc\u05d1\u05d9\u05df \u05e8\u05e6\u05d5\u05df \u05d4\u05d1\u05d5\u05e8\u05d0, \u05d5\u05d9\u05d5\u05e6\u05e8 \u05d0\u05ea \u05d4\u05e9\u05e4\u05e2 \u05d5\u05d4\u05e9\u05dc\u05d5\u05d5\u05d4 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05ea.\n\u05d1\u05d7\u05d2 \u05d4\u05e1\u05d5\u05db\u05d5\u05ea, \u05d4\u05e0\u05d5\u05e9\u05d0 \u05de\u05e7\u05d1\u05dc \u05e2\u05d5\u05de\u05e7 \u05e0\u05d5\u05e1\u05e3: \u05d4\u05e1\u05d5\u05db\u05d4 \u05e2\u05e6\u05de\u05d4 \u05d4\u05d9\u05d0 \u05e1\u05de\u05dc \u05dc\u05d4\u05ea\u05de\u05e1\u05e8\u05d5\u05ea \u05d5\u05dc\u05db\u05e0\u05d9\u05e2\u05d4 \u2013 \u05de\u05d1\u05e0\u05d4 \u05d6\u05de\u05e0\u05d9, \u05e4\u05ea\u05d5\u05d7 \u05dc\u05e9\u05de\u05d9\u05d9\u05dd, \u05e9\u05d1\u05d5 \u05d4\u05d0\u05d3\u05dd \u05d6\u05d5\u05db\u05d4 \u05dc\u05d4\u05e8\u05d2\u05d9\u05e9 \u05d0\u05ea \u05d4\u05e7\u05e9\u05e8 \u05d4\u05d9\u05e9\u05d9\u05e8 \u05e2\u05dd \u05d4\u05db\u05d5\u05d7 \u05d4\u05e2\u05dc\u05d9\u05d5\u05df. \u05d4\u05d7\u05e1\u05d9\u05d3\u05d5\u05ea \u05de\u05dc\u05de\u05d3\u05ea \u05d0\u05d5\u05ea\u05e0\u05d5 \u05e2\u05dc \u05d4\u05e9\u05d9\u05dc\u05d5\u05d1 \u05d1\u05d9\u05df \u05d4\u05e1\u05d9\u05de\u05d8\u05e8\u05d9\u05d4 \u05e9\u05dc \u05e9\u05dd \u05d9\u05d4\u05d5\u05d4 \u05dc\u05e9\u05dd \u05d0\u05d3\u05e0\u05d9, \u05d5\u05db\u05d9\u05e6\u05d3 \u05d4\u05d9\u05d0 \u05de\u05e9\u05ea\u05e7\u05e4\u05ea \u05d1\u05d2\u05d9\u05de\u05d8\u05e8\u05d9\u05d4 \u05e9\u05dc \u05d4\u05de\u05d9\u05dc\u05d4 \u201c\u05e1\u05d5\u05db\u05d4\u201d \u2013 \u05de\u05d1\u05e0\u05d4 \u05e9\u05de\u05d0\u05e4\u05e9\u05e8 \u05dc\u05e0\u05d5 \u05dc\u05d4\u05d9\u05db\u05e0\u05e1 \u05dc\u05de\u05e8\u05d7\u05d1 \u05e9\u05d1\u05d5 \u05d4\u05e0\u05e9\u05de\u05d4 \u05d5\u05d4\u05e2\u05d5\u05dc\u05dd \u05d4\u05d7\u05d5\u05de\u05e8\u05d9 \u05e0\u05e4\u05d2\u05e9\u05d9\u05dd \u05d1\u05d4\u05e8\u05de\u05d5\u05e0\u05d9\u05d4, \u05d1\u05d3\u05d9\u05d5\u05e7 \u05db\u05e9\u05d0\u05e0\u05d7\u05e0\u05d5 \u05d1\u05db\u05e0\u05d9\u05e2\u05d4 \u05d5\u05e2\u05e0\u05d5\u05d5\u05d4.\n\u05d2\u05dd \u05e4\u05e8\u05e9\u05ea \u05d0\u05ea\u05d7\u05e0\u05df \u05de\u05d6\u05db\u05d9\u05e8\u05d4 \u05dc\u05e0\u05d5 \u05e9\u05d4\u05db\u05d5\u05d7 \u05d4\u05d0\u05de\u05d9\u05ea\u05d9 \u05d0\u05d9\u05e0\u05d5 \u05d1\u05e9\u05dc\u05d9\u05d8\u05ea \u05d4\u05d0\u05d3\u05dd \u05d1\u05dc\u05d1\u05d3. \u05de\u05e9\u05d4 \u05de\u05e4\u05e0\u05d4 \u05d0\u05d5\u05ea\u05e0\u05d5 \u05dc\u05de\u05d5\u05d3\u05e2\u05d5\u05ea \u05e9\u05d4\u05d7\u05d9\u05d9\u05dd \u05d5\u05d4\u05d1\u05e8\u05db\u05d4 \u05ea\u05dc\u05d5\u05d9\u05d9\u05dd \u05d1\u05d4\u05e7\u05e9\u05d1\u05d4, \u05e7\u05d1\u05dc\u05d4 \u05d5\u05d4\u05db\u05e0\u05e2\u05d4 \u2013 \u05dc\u05d0 \u05d1\u05d4\u05ea\u05e2\u05e7\u05e9\u05d5\u05ea \u05e2\u05dc \u05e9\u05dc\u05d9\u05d8\u05d4 \u05e2\u05e6\u05de\u05d9\u05ea, \u05d0\u05dc\u05d0 \u05d1\u05e9\u05d7\u05e8\u05d5\u05e8 \u05d0\u05de\u05d9\u05ea\u05d9 \u05e9\u05dc \u05d4\u05dc\u05d1.\n\u05dc\u05db\u05df, \u05d1\u05e8\u05db\u05ea \u201c\u05ea\u05df \u05d1\u05dc\u05d9\u05d1\u05d9 \u05d4\u05db\u05e0\u05e2\u05d4 \u05d5\u05e2\u05e0\u05d5\u05d5\u05d4\u201d \u05d4\u05d9\u05d0 \u05ea\u05e4\u05d9\u05dc\u05d4 \u05e2\u05dc \u05d4\u05d4\u05d1\u05e0\u05d4 \u05e9\u05d4\u05dc\u05d1 \u05e6\u05e8\u05d9\u05da \u05dc\u05d4\u05d9\u05d5\u05ea \u05e4\u05ea\u05d5\u05d7 \u05dc\u05d4\u05ea\u05de\u05e1\u05e8\u05d5\u05ea, \u05e9\u05d4\u05e2\u05e0\u05d5\u05d5\u05d4 \u05d4\u05d9\u05d0 \u05d4\u05de\u05e7\u05d5\u05e8 \u05dc\u05e9\u05e4\u05e2, \u05d5\u05db\u05e9\u05d4\u05ea\u05d5\u05d3\u05e2\u05d4 \u05e9\u05dc\u05e0\u05d5 \u05de\u05db\u05d9\u05e8\u05d4 \u05d1\u05db\u05d5\u05d7 \u05d4\u05e2\u05dc\u05d9\u05d5\u05df, \u05d4\u05e2\u05d5\u05dc\u05dd \u05db\u05d5\u05dc\u05d5 \u05de\u05ea\u05d7\u05d9\u05dc \u05dc\u05d4\u05ea\u05d7\u05d1\u05e8 \u05d5\u05dc\u05d6\u05e8\u05d5\u05dd \u05d1\u05e6\u05d5\u05e8\u05d4 \u05d8\u05d1\u05e2\u05d9\u05ea.')
B.L2=new A.cv(18,"\u05ea\u05e4\u05d9\u05dc\u05ea \u05e9\u05de\u05d5\u05e0\u05d4 \u05e2\u05e9\u05e8\u05d4 \u05d5\u05d4\u05d8\u05d5\u05d1 \u05d5\u05d4\u05de\u05d8\u05d9\u05d1",'\u05d1\u05e8\u05db\u05ea \u05d4\u05d8\u05d5\u05d1 \u05d5\u05d4\u05de\u05d8\u05d9\u05d1 \u2013 \u05d4\u05d9\u05e1\u05d8\u05d5\u05e8\u05d9\u05d4 \u05e9\u05dc \u05db\u05d0\u05d1 \u05d5\u05e8\u05d0\u05d9\u05d9\u05ea \u05d4\u05d8\u05d5\u05d1 \u05de\u05ea\u05d5\u05da \u05d4\u05d7\u05d5\u05e9\u05da\n\u05de\u05e2\u05d8\u05d5\u05ea \u05d4\u05d1\u05e8\u05db\u05d5\u05ea \u05e9\u05de\u05db\u05d9\u05dc\u05d5\u05ea \u05d1\u05ea\u05d5\u05db\u05df \u05de\u05ea\u05d7 \u05db\u05dc \u05db\u05da \u05e2\u05d6 \u05d1\u05d9\u05df \u05d4\u05d9\u05e1\u05d8\u05d5\u05e8\u05d9\u05d4 \u05e9\u05dc \u05e9\u05d1\u05e8 \u05dc\u05e8\u05d0\u05d9\u05d9\u05d4 \u05e9\u05dc \u05d7\u05e1\u05d3, \u05db\u05de\u05d5 \u05d1\u05e8\u05db\u05ea "\u05d1\u05e8\u05d5\u05da \u05d0\u05ea\u05d4 \u05d4\' \u05d0\u05dc\u05d5\u05d4\u05d9\u05e0\u05d5 \u05de\u05dc\u05da \u05d4\u05e2\u05d5\u05dc\u05dd, \u05d4\u05d8\u05d5\u05d1 \u05d5\u05d4\u05de\u05d8\u05d9\u05d1."\n\u05dc\u05db\u05d0\u05d5\u05e8\u05d4, \u05de\u05d3\u05d5\u05d1\u05e8 \u05d1\u05d1\u05e8\u05db\u05d4 \u05d7\u05d9\u05d5\u05d1\u05d9\u05ea, \u05e4\u05e9\u05d5\u05d8\u05d4, \u05d0\u05d5\u05dc\u05d9 \u05d0\u05e4\u05d9\u05dc\u05d5 \u05de\u05d5\u05d1\u05e0\u05ea \u05de\u05d0\u05dc\u05d9\u05d4 \u05dc\u05d4\u05d5\u05d3\u05d5\u05ea \u05e2\u05dc \u05d3\u05d1\u05e8 \u05d8\u05d5\u05d1 \u05e9\u05e7\u05e8\u05d4.\n\u05d0\u05da \u05de\u05d0\u05d7\u05d5\u05e8\u05d9 \u05d4\u05d1\u05e8\u05db\u05d4 \u05d4\u05d6\u05d5 \u05de\u05e1\u05ea\u05ea\u05e8\u05ea \u05de\u05e6\u05d9\u05d0\u05d5\u05ea \u05d4\u05d9\u05e1\u05d8\u05d5\u05e8\u05d9\u05ea \u05e9\u05dc \u05d3\u05de\u05e2\u05d5\u05ea, \u05d5\u05d4\u05db\u05e8\u05e2\u05d4 \u05ea\u05d5\u05d3\u05e2\u05ea\u05d9\u05ea \u05e2\u05de\u05d5\u05e7\u05d4.\n\u05de\u05ea\u05d9 \u05e0\u05ea\u05e7\u05e0\u05d4 \u05d4\u05d1\u05e8\u05db\u05d4?\n\u05d7\u05d6"\u05dc \u05de\u05e1\u05e4\u05e8\u05d9\u05dd \u05dc\u05e0\u05d5 \u05d1\u05de\u05e1\u05db\u05ea \u05d1\u05e8\u05db\u05d5\u05ea (\u05d3\u05e3 \u05e0:) \u05e9\u05d1\u05e8\u05db\u05d4 \u05d6\u05d5 \u05e0\u05ea\u05e7\u05e0\u05d4 \u05dc\u05d0\u05d7\u05e8 \u05d4\u05e8\u05d5\u05d2\u05d9 \u05d1\u05d9\u05ea\u05e8 \u05d0\u05dc\u05e4\u05d9 \u05d9\u05d4\u05d5\u05d3\u05d9\u05dd \u05e9\u05e0\u05e8\u05e6\u05d7\u05d5 \u05d1\u05d0\u05db\u05d6\u05e8\u05d9\u05d5\u05ea \u05dc\u05d0\u05d7\u05e8 \u05d3\u05d9\u05db\u05d5\u05d9 \u05de\u05e8\u05d3 \u05d1\u05e8 \u05db\u05d5\u05db\u05d1\u05d0 \u05d1\u05d9\u05d3\u05d9 \u05d4\u05e8\u05d5\u05de\u05d0\u05d9\u05dd. \u05d1\u05de\u05e9\u05da \u05ea\u05e7\u05d5\u05e4\u05d4 \u05d0\u05e8\u05d5\u05db\u05d4 \u05e0\u05d0\u05e1\u05e8 \u05dc\u05e7\u05d1\u05d5\u05e8 \u05d0\u05ea \u05d2\u05d5\u05e4\u05d5\u05ea\u05d9\u05d4\u05dd, \u05e2\u05d3 \u05d0\u05e9\u05e8 \u05dc\u05d1\u05e1\u05d5\u05e3 \u05d1\u05e4\u05dc\u05d0 \u05db\u05de\u05e2\u05d8 \u05d1\u05dc\u05ea\u05d9 \u05de\u05d5\u05e1\u05d1\u05e8  \u05d4\u05e8\u05d5\u05de\u05d0\u05d9\u05dd \u05d0\u05d9\u05e4\u05e9\u05e8\u05d5 \u05dc\u05e7\u05d5\u05d1\u05e8\u05dd, \u05d5\u05d4\u05d2\u05d5\u05e4\u05d5\u05ea \u05e0\u05de\u05e6\u05d0\u05d5 \u05e9\u05dc\u05de\u05d5\u05ea \u05d5\u05dc\u05d0 \u05e0\u05e8\u05e7\u05d1\u05d5.\n\u05d0\u05d6 \u05ea\u05e7\u05e0\u05d5 \u05d7\u05db\u05de\u05d9\u05dd \u05d0\u05ea \u05d1\u05e8\u05db\u05ea "\u05d4\u05d8\u05d5\u05d1 \u05d5\u05d4\u05de\u05d8\u05d9\u05d1" \u05d4\u05d8\u05d5\u05d1 \u05e2\u05dc \u05e9\u05d4\u05d2\u05d5\u05e4\u05d5\u05ea \u05dc\u05d0 \u05e0\u05e8\u05e7\u05d1\u05d5, \u05d5\u05d4\u05de\u05d8\u05d9\u05d1 \u05e2\u05dc \u05e9\u05d4\u05d5\u05ea\u05e8 \u05dc\u05e7\u05d1\u05d5\u05e8 \u05d0\u05d5\u05ea\u05df.\n\u05d4\u05de\u05e1\u05e8 \u05de\u05d8\u05dc\u05d8\u05dc: \u05dc\u05d0 \u05ea\u05d9\u05e7\u05e0\u05d5 \u05d0\u05ea \u05d4\u05d1\u05e8\u05db\u05d4 \u05e2\u05dc \u05d4\u05e0\u05e1 \u05d4\u05d2\u05d3\u05d5\u05dc \u05e9\u05dc \u05e0\u05d9\u05e6\u05d7\u05d5\u05df, \u05e9\u05d7\u05e8\u05d5\u05e8 \u05d0\u05d5 \u05ea\u05d7\u05d9\u05d9\u05d4 \u05d0\u05dc\u05d0 \u05d3\u05d5\u05d5\u05e7\u05d0 \u05e2\u05dc \u05e0\u05d9\u05e6\u05d5\u05e5 \u05e9\u05dc \u05d7\u05e1\u05d3 \u05d1\u05ea\u05d5\u05da \u05e9\u05d5\u05d0\u05d4 \u05e0\u05d5\u05e8\u05d0\u05d9\u05ea.\n\u05dc\u05d0 \u05e2\u05dc \u05d4\u05d0\u05d5\u05e8 \u05d4\u05d2\u05d3\u05d5\u05dc, \u05d0\u05dc\u05d0 \u05e2\u05dc \u05e9\u05d1\u05d9\u05d1 \u05d0\u05d5\u05e8 \u05d1\u05ea\u05d5\u05da \u05d7\u05d5\u05e9\u05da \u05db\u05d1\u05d3.\n\u05de\u05d4 \u05d6\u05d4 \u05de\u05d2\u05dc\u05d4 \u05e2\u05dc \u05db\u05d5\u05d7\u05d4 \u05e9\u05dc \u05d4\u05d1\u05e8\u05db\u05d4?\n\u05d1\u05de\u05e7\u05d5\u05dd \u05dc\u05d1\u05d7\u05d5\u05e8 \u05dc\u05e9\u05e7\u05d5\u05e2 \u05d1\u05d0\u05d1\u05dc, \u05d1\u05d9\u05d9\u05d0\u05d5\u05e9 \u05d0\u05d5 \u05d1\u05db\u05e2\u05e1 \u05d7\u05db\u05de\u05d9\u05dd \u05de\u05dc\u05de\u05d3\u05d9\u05dd \u05d0\u05d5\u05ea\u05e0\u05d5 \u05dc\u05d4\u05d9\u05d0\u05d7\u05d6 \u05d1\u05d8\u05d5\u05d1 \u05d4\u05e7\u05d8\u05df \u05e9\u05de\u05d0\u05d9\u05e8 \u05d0\u05ea \u05d4\u05ea\u05d4\u05d5\u05dd.\n\u05d6\u05d5 \u05dc\u05d0 \u05e8\u05e7 \u05ea\u05d2\u05d5\u05d1\u05d4 \u05e0\u05e1\u05d9\u05d1\u05ea\u05d9\u05ea. \u05d6\u05d5 \u05d4\u05db\u05e8\u05e2\u05d4 \u05d0\u05de\u05d5\u05e0\u05d9\u05ea: \u05dc\u05e8\u05d0\u05d5\u05ea \u05d0\u05ea \u05d4\u05d8\u05d5\u05d1, \u05d2\u05dd \u05db\u05e9\u05d4\u05d5\u05d0 \u05de\u05db\u05d5\u05e1\u05d4, \u05d2\u05dd \u05db\u05e9\u05d4\u05d5\u05d0 \u05de\u05d5\u05e4\u05d9\u05e2 \u05db\u05d8\u05d9\u05e4\u05d4 \u05d0\u05d7\u05ea \u05e9\u05dc \u05d7\u05e1\u05d3 \u05d1\u05ea\u05d5\u05da \u05d9\u05dd \u05e9\u05dc \u05db\u05d0\u05d1.\n\u05de\u05d1\u05d8 \u05d7\u05e1\u05d9\u05d3\u05d9: \u05dc\u05d2\u05dc\u05d5\u05ea \u05d0\u05ea \u05d4\u05d7\u05e1\u05d3 \u05e9\u05d1\u05d3\u05d9\u05df\n\u05d4\u05d7\u05e1\u05d9\u05d3\u05d5\u05ea \u05dc\u05e7\u05d7\u05d4 \u05d0\u05ea \u05d4\u05d1\u05e8\u05db\u05d4 \u05d4\u05d6\u05d5 \u05db\u05d1\u05e1\u05d9\u05e1 \u05dc\u05e2\u05d1\u05d5\u05d3\u05d4 \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea \u05e2\u05de\u05d5\u05e7\u05d4:\n\u05d1\u05e2\u05d5\u05dc\u05dd \u05d4\u05d7\u05e1\u05d9\u05d3\u05d5\u05ea, \u05e0\u05d0\u05de\u05e8 \u05e4\u05e2\u05de\u05d9\u05dd \u05e8\u05d1\u05d5\u05ea \u05e9\u05d4\u05db\u05d5\u05dc "\u05e8\u05d7\u05de\u05d9\u05dd \u05d2\u05d3\u05d5\u05dc\u05d9\u05dd \u05d0\u05e4\u05d9\u05dc\u05d5 \u05db\u05e9\u05d4\u05dd \u05de\u05ea\u05d2\u05dc\u05d9\u05dd \u05d1\u05dc\u05d1\u05d5\u05e9 \u05e9\u05dc \u05d3\u05d9\u05df."\n\u05d4\u05d1\u05e8\u05db\u05d4 \u05d4\u05d6\u05d5 \u05de\u05d6\u05de\u05d9\u05e0\u05d4 \u05d0\u05d5\u05ea\u05e0\u05d5 \u05dc\u05ea\u05e8\u05d2\u05d5\u05dc \u05e9\u05dc \u05e2\u05d9\u05df \u05d8\u05d5\u05d1\u05d4 \u05e2\u05dc \u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea \u05db\u05d5\u05dc\u05d4, \u05d2\u05dd \u05d5\u05d1\u05e2\u05d9\u05e7\u05e8 \u05db\u05e9\u05d4\u05d9\u05d0 \u05e1\u05d5\u05ea\u05e8\u05ea \u05d0\u05ea \u05d4\u05e9\u05db\u05dc \u05d0\u05d5 \u05d0\u05ea \u05d4\u05e8\u05e6\u05d5\u05df.\n\u05d4\'\u05e9\u05e4\u05ea \u05d0\u05de\u05ea\' \u05db\u05d5\u05ea\u05d1 \u05e9\u05e2\u05d1\u05d5\u05d3\u05ea \u05d4\u05d0\u05d3\u05dd \u05d4\u05d9\u05d0 "\u05dc\u05d2\u05dc\u05d5\u05ea \u05d0\u05ea \u05d4\u05d8\u05d5\u05d1 \u05d1\u05db\u05dc \u05d3\u05d1\u05e8", \u05d0\u05e4\u05d9\u05dc\u05d5 \u05d5\u05d1\u05de\u05d9\u05d5\u05d7\u05d3 \u05d1\u05ea\u05d5\u05da \u05d4\u05d9\u05d2\u05d5\u05df.\n\u05d5\u05d4\u05e8\u05d9, \u05db\u05e4\u05d9 \u05e9\u05db\u05d5\u05ea\u05d1 \u05e8\u05d1\u05d9 \u05e0\u05d7\u05de\u05df, "\u05d2\u05dd \u05d1\u05ea\u05d5\u05da \u05d4\u05d4\u05e1\u05ea\u05e8\u05d4 \u05e9\u05d1\u05ea\u05d5\u05da \u05d4\u05d4\u05e1\u05ea\u05e8\u05d4 \u05d2\u05dd \u05e9\u05dd \u05e0\u05de\u05e6\u05d0 \u05d4\u05e9\u05dd \u05d9\u05ea\u05d1\u05e8\u05da."\n\u05db\u05dc\u05d5\u05de\u05e8, \u05d1\u05e8\u05db\u05ea \u05d4\u05d8\u05d5\u05d1 \u05d5\u05d4\u05de\u05d8\u05d9\u05d1 \u05d0\u05d9\u05e0\u05e0\u05d4 \u05e8\u05e7 \u05d0\u05de\u05d9\u05e8\u05d4 \u05d8\u05db\u05e0\u05d9\u05ea \u05e2\u05dc \u05de\u05d9\u05e9\u05d4\u05d5 \u05e9\u05d6\u05db\u05d4 \u05d1\u05d9\u05d9\u05df \u05d7\u05d3\u05e9 \u05d0\u05d5 \u05e9\u05de\u05d7\u05d4 \u05d2\u05e9\u05de\u05d9\u05ea.\n\u05d6\u05d5 \u05d4\u05db\u05e8\u05d6\u05d4 \u05ea\u05d5\u05d3\u05e2\u05ea\u05d9\u05ea \u05e2\u05de\u05d5\u05e7\u05d4:\n\u05d0\u05e0\u05d9 \u05d1\u05d5\u05d7\u05e8 \u05dc\u05e8\u05d0\u05d5\u05ea \u05d0\u05ea \u05d4\u05d8\u05d5\u05d1. \u05d0\u05e0\u05d9 \u05d1\u05d5\u05d7\u05e8 \u05dc\u05d4\u05d0\u05de\u05d9\u05df \u05e9\u05d4\u05d5\u05d0 \u05db\u05d0\u05df, \u05d2\u05dd \u05db\u05e9\u05d0\u05d9\u05e0\u05d9 \u05de\u05d1\u05d9\u05df.\n\u05d5\u05d6\u05d5 \u05d1\u05d7\u05d9\u05e8\u05d4 \u05e9\u05d9\u05db\u05d5\u05dc\u05d4 \u05dc\u05e8\u05e4\u05d0 \u05d0\u05ea \u05d4\u05dc\u05d1.','\u05ea\u05e8\u05d2\u05d9\u05dc \u05d4\u05d8\u05de\u05e2\u05d4 \u05e2\u05de\u05d5\u05e7 \u05dc\u05e2\u05d1\u05d5\u05d3\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05d5\u05ea\u05e4\u05d9\u05dc\u05d4 \u05de\u05ea\u05d5\u05da \u05e9\u05dc\u05d5\u05e9 \u05de\u05d3\u05e8\u05d2\u05d5\u05ea \u05d4"\u05e7\u05d3\u05d5\u05e9" \u05d1\u05d4\u05e9\u05e8\u05d0\u05ea \u05e4\u05e8\u05e9\u05d5\u05ea \u05e7\u05d5\u05e8\u05d7, \u05d7\u05d5\u05e7\u05ea \u05d5\u05d1\u05dc\u05e7','\u05e8\u05d1\u05d9 \u05dc\u05d5\u05d9 \u05d9\u05e6\u05d7\u05e7 \u05de\u05d1\u05e8\u05d3\u05d9\u05d8\u05e9\u05d5\u05d1 \u05d4\u05d9\u05d4 \u05e9\u05d5\u05d0\u05dc \u05d0\u05d3\u05dd \u05d1\u05e6\u05e8\u05d4:\n"\u05d5\u05de\u05d4 \u05d0\u05ea\u05d4 \u05de\u05d1\u05e8\u05da \u05d4\u05d9\u05d5\u05dd?"\n\u05dc\u05d0 \u05db\u05d3\u05d9 \u05dc\u05d6\u05dc\u05d6\u05dc \u05d1\u05db\u05d0\u05d1 \u05d0\u05dc\u05d0 \u05db\u05d3\u05d9 \u05dc\u05e2\u05d6\u05d5\u05e8 \u05dc\u05d5 \u05dc\u05de\u05e6\u05d5\u05d0 \u05e0\u05e7\u05d5\u05d3\u05ea \u05d0\u05d5\u05e8 \u05e9\u05ea\u05e9\u05d9\u05d1 \u05dc\u05d5 \u05d0\u05ea \u05e0\u05e9\u05de\u05ea\u05d5.\n\u05d6\u05d4\u05d5 \u05db\u05d5\u05d7 \u05d4\u05d1\u05e8\u05db\u05d4 \u05dc\u05e4\u05ea\u05d5\u05d7 \u05d7\u05e8\u05da \u05e9\u05dc \u05ea\u05e7\u05d5\u05d5\u05d4 \u05d2\u05dd \u05db\u05e9\u05d3\u05dc\u05ea\u05d5\u05ea \u05e0\u05d3\u05de\u05d5\u05ea \u05e0\u05e2\u05d5\u05dc\u05d5\u05ea.\n\u05d5\u05d4\u05d7\u05e1\u05d9\u05d3\u05d5\u05ea \u05de\u05d6\u05db\u05d9\u05e8\u05d4: \u05db\u05dc \u05de\u05d4 \u05e9\u05d0\u05ea\u05d4 \u05de\u05d5\u05d3\u05d4 \u05e2\u05dc\u05d9\u05d5 \u05de\u05ea\u05e8\u05d7\u05d1. \u05db\u05dc \u05de\u05d4 \u05e9\u05d0\u05ea\u05d4 \u05de\u05d1\u05e8\u05da \u05e2\u05dc\u05d9\u05d5 \u05d4\u05d5\u05e4\u05da \u05e6\u05d9\u05e0\u05d5\u05e8 \u05dc\u05e9\u05e4\u05e2 \u05e0\u05d5\u05e1\u05e3.\n\u05e1\u05d9\u05d5\u05dd: \u05dc\u05e8\u05d0\u05d5\u05ea \u05d0\u05ea \u05d4\u05d8\u05d5\u05d1 \u05d5\u05d4\u05de\u05d8\u05d9\u05d1 \u05db\u05d7\u05d9\u05d9\u05dd \u05e9\u05dc\u05de\u05d9\u05dd\n\u05d1\u05e8\u05db\u05ea \u05d4\u05d8\u05d5\u05d1 \u05d5\u05d4\u05de\u05d8\u05d9\u05d1 \u05d4\u05d9\u05d0 \u05dc\u05d0 \u05e8\u05e7 \u05de\u05e9\u05e4\u05d8. \u05d4\u05d9\u05d0 \u05d2\u05d9\u05e9\u05d4.\n\u05d4\u05d9\u05d0 \u05d0\u05de\u05d5\u05e0\u05d4 \u05e9\u05dc\u05de\u05e8\u05d5\u05ea \u05d4\u05db\u05d5\u05dc \u05d9\u05e9 \u05d8\u05d5\u05d1. \u05d5\u05d9\u05e9 \u05de\u05d9\u05d8\u05d9\u05d1.\n\u05d5\u05dc\u05e4\u05e2\u05de\u05d9\u05dd, \u05d3\u05d5\u05d5\u05e7\u05d0 \u05d0\u05d7\u05e8\u05d9 \u05d4\u05db\u05d0\u05d1 \u05de\u05d2\u05dc\u05d9\u05dd \u05d0\u05ea \u05d4\u05de\u05d9\u05d8\u05d9\u05d1 \u05d4\u05d0\u05de\u05d9\u05ea\u05d9, \u05e9\u05dc\u05e2\u05d5\u05dc\u05dd \u05dc\u05d0 \u05e2\u05d6\u05d1.\n\u05d1\u05e9\u05de\u05d7\u05d4. \u05d4\u05e0\u05d4 \u05ea\u05e8\u05d2\u05d5\u05dc \u05d7\u05e1\u05d9\u05d3\u05d9 \u05d9\u05d5\u05de\u05d9 \u05dc\u05d4\u05d8\u05de\u05e2\u05ea \u05d4\u05ea\u05d5\u05d3\u05e2\u05d4 \u05e9\u05dc \u05d4\u05d8\u05d5\u05d1 \u05d5\u05d4\u05de\u05d8\u05d9\u05d1 \u05d1\u05d7\u05d9\u05d9\u05dd \u05d4\u05d0\u05d9\u05e9\u05d9\u05d9\u05dd:\n\ud83c\udf3f \u05ea\u05e8\u05d2\u05d5\u05dc \u05d9\u05d5\u05de\u05d9 \u05d7\u05e1\u05d9\u05d3\u05d9 \u05dc\u05d4\u05d8\u05de\u05e2\u05ea "\u05d4\u05d8\u05d5\u05d1 \u05d5\u05d4\u05de\u05d8\u05d9\u05d1" \u2014 \u05dc\u05e8\u05d0\u05d5\u05ea \u05d8\u05d5\u05d1 \u05d2\u05dd \u05db\u05e9\u05d4\u05dc\u05d1 \u05db\u05d5\u05d0\u05d1\n\u05de\u05d1\u05d5\u05e1\u05e1 \u05e2\u05dc \u05ea\u05d5\u05d1\u05e0\u05d5\u05ea \u05de\u05d4\u05d7\u05e1\u05d9\u05d3\u05d5\u05ea \u05d5\u05de\u05e2\u05d1\u05d5\u05d3\u05ea \u05d4\u05ea\u05d5\u05d3\u05e2\u05d4 \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9\u05ea.\n\ud83d\udd6f \u05d1\u05d5\u05e7\u05e8: \u05dc\u05d4\u05ea\u05d7\u05d9\u05dc \u05d0\u05ea \u05d4\u05d9\u05d5\u05dd \u05d1\u05e2\u05d9\u05df \u05d8\u05d5\u05d1\u05d4\n\u05d3\u05d1\u05e8 \u05d0\u05d7\u05d3 \u05e9\u05d8\u05d5\u05d1 \u05d1\u05d9.\n\u05d3\u05d1\u05e8 \u05d0\u05d7\u05d3 \u05e9\u05d8\u05d5\u05d1 \u05d1\u05e2\u05d5\u05dc\u05dd.\n\u05d3\u05d1\u05e8 \u05d0\u05d7\u05d3 \u05d8\u05d5\u05d1 \u05e9\u05d4\u05e9\u05dd \u05e2\u05e9\u05d4 \u05e2\u05d9\u05de\u05d9 \u05d0\u05ea\u05de\u05d5\u05dc \u2014 \u05d0\u05e4\u05d9\u05dc\u05d5 \u05e7\u05d8\u05df \u05de\u05d0\u05d5\u05d3.\n(\u05dc\u05de\u05e9\u05dc: "\u05d4\u05d9\u05d9\u05ea\u05d4 \u05dc\u05d9 \u05e0\u05e9\u05d9\u05de\u05d4 \u05e8\u05d2\u05d5\u05e2\u05d4", "\u05e4\u05d2\u05e9\u05ea\u05d9 \u05d7\u05d9\u05d5\u05da \u05d1\u05e8\u05d7\u05d5\u05d1", "\u05d4\u05e6\u05dc\u05d7\u05ea\u05d9 \u05dc\u05e2\u05e0\u05d5\u05ea \u05d1\u05e1\u05d1\u05dc\u05e0\u05d5\u05ea \u05dc\u05d9\u05dc\u05d3 \u05e9\u05dc\u05d9")\n\ud83e\ude9e\u05db\u05d5\u05d5\u05e0\u05d4: \u05d1\u05db\u05dc \u05e4\u05e2\u05dd \u05e9\u05de\u05d6\u05d4\u05d9\u05dd \u05d8\u05d5\u05d1 \u2014 \u05d4\u05d5\u05d0 \u05de\u05ea\u05e8\u05d7\u05d1. \u05d6\u05d5 \u05dc\u05d0 \u05d0\u05de\u05d9\u05e8\u05d4 \u05e4\u05e1\u05d9\u05db\u05d5\u05dc\u05d5\u05d2\u05d9\u05ea \u05d1\u05dc\u05d1\u05d3, \u05d0\u05dc\u05d0 \u05e2\u05d9\u05e7\u05e8\u05d5\u05df \u05e8\u05d5\u05d7\u05e0\u05d9: "\u05d4\u05d5\u05d3\u05d5 \u05dc\u05d4\' \u05db\u05d9 \u05d8\u05d5\u05d1 \u2014 \u05db\u05d9 \u05dc\u05e2\u05d5\u05dc\u05dd \u05d7\u05e1\u05d3\u05d5".\n\ud83d\udc94 \u05d0\u05de\u05e6\u05e2 \u05d4\u05d9\u05d5\u05dd \u2013 \u05d1\u05ea\u05d5\u05da \u05e1\u05e2\u05e8\u05ea \u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea\n"\u05d0\u05d9\u05e4\u05d4 \u05db\u05d0\u05df \u05e0\u05e7\u05d5\u05d3\u05ea \u05d4\u05d8\u05d5\u05d1 \u05e9\u05d0\u05e0\u05d9 \u05dc\u05d0 \u05e8\u05d5\u05d0\u05d4 \u05e2\u05d3\u05d9\u05d9\u05df?"\n"\u05de\u05d4 \u05d4\u05e9\u05dd \u05de\u05d9\u05d8\u05d9\u05d1 \u05dc\u05d9 \u05d0\u05e4\u05d9\u05dc\u05d5 \u05db\u05e9\u05d0\u05e0\u05d9 \u05dc\u05d0 \u05de\u05e8\u05d2\u05d9\u05e9\u05d4 \u05d6\u05d0\u05ea?"\n\u2728\u05db\u05d5\u05d5\u05e0\u05d4: \u05d4\u05ea\u05e8\u05d2\u05d5\u05dc \u05d0\u05d9\u05e0\u05d5 \u05de\u05d3\u05d7\u05d9\u05e7 \u05db\u05d0\u05d1. \u05d4\u05d5\u05d0 \u05de\u05d7\u05e4\u05e9 \u05d0\u05ea \u05d4\u05d7\u05e1\u05d3 \u05e9\u05d1\u05dc\u05d1\u05d5\u05e9 \u05d3\u05d9\u05df, \u05d0\u05ea \u05d4\u05d0\u05d5\u05e8 \u05d4\u05d3\u05e7 \u05e9\u05e0\u05de\u05e6\u05d0 \u05d1\u05ea\u05d5\u05da \u05d4\u05d7\u05d5\u05e9\u05da.\n\u05d1\u05de\u05d5\u05e0\u05d7\u05d9\u05dd \u05e9\u05dc \u05d4\u05d1\u05e2\u05dc \u05e9\u05dd \u05d8\u05d5\u05d1: \u05db\u05dc \u05d3\u05d1\u05e8 \u05e9\u05de\u05ea\u05d2\u05dc\u05d4 \u2014 \u05d9\u05e9 \u05d1\u05d5 \u05e9\u05dc\u05d9\u05d7\u05d5\u05ea \u05d0\u05dc\u05d5\u05e7\u05d9\u05ea.\n\ud83c\udf19 \u05e2\u05e8\u05d1: \u05e1\u05d9\u05db\u05d5\u05dd \u05d7\u05e1\u05d3\u05d9\u05dd\n\u05dc\u05e4\u05e0\u05d9 \u05d4\u05e9\u05d9\u05e0\u05d4: \u05e2\u05e6\u05e8\u05d9 \u05dc\u05e8\u05d2\u05e2. \u05e7\u05d7\u05d9 \u05e0\u05e9\u05d9\u05de\u05d4 \u05e2\u05de\u05d5\u05e7\u05d4.\n\u05db\u05ea\u05d1\u05d9 \u05d0\u05d5 \u05d0\u05de\u05e8\u05d9 \u05d1\u05dc\u05d1 \u05e9\u05dc\u05d5\u05e9 \u05d1\u05e8\u05db\u05d5\u05ea \u05e9\u05dc "\u05d4\u05d8\u05d5\u05d1 \u05d5\u05d4\u05de\u05d9\u05d8\u05d9\u05d1" \u05de\u05d4\u05d9\u05d5\u05dd \u05e9\u05d7\u05dc\u05e3 \u2014 \u05d0\u05e4\u05d9\u05dc\u05d5 \u05d0\u05dd \u05d4\u05d9\u05d5\u05dd \u05d4\u05d9\u05d4 \u05e7\u05e9\u05d4:\n\u05d4\u05d8\u05d5\u05d1: \u05e9\u05d4\u05e6\u05dc\u05d7\u05ea\u05d9 \u05dc\u05e9\u05e8\u05d5\u05d3 \u05d0\u05d5\u05ea\u05d5.\n\u05d4\u05de\u05d8\u05d9\u05d1: \u05e9\u05d4\u05d2\u05d9\u05e2\u05d4 \u05e2\u05d6\u05e8\u05d4 \u05d1\u05e8\u05d2\u05e2 \u05dc\u05d0 \u05e6\u05e4\u05d5\u05d9.\n\u05d4\u05de\u05d8\u05d9\u05d1: \u05e9\u05d6\u05db\u05d9\u05ea\u05d9 \u05dc\u05d4\u05d1\u05d9\u05df \u05de\u05e9\u05d4\u05d5 \u05e7\u05d8\u05df \u05e2\u05dc \u05e2\u05e6\u05de\u05d9 \u05d3\u05e8\u05db\u05d5.\n\ud83d\udcff \u05db\u05d5\u05d5\u05e0\u05d4: \u05db\u05db\u05dc \u05e9\u05de\u05d1\u05e8\u05db\u05d9\u05dd \u05e2\u05dc \u05d4\u05d8\u05d5\u05d1 \u05d2\u05dd \u05d0\u05dd \u05d4\u05db\u05d9 \u05d6\u05e2\u05d9\u05e8 \u05db\u05da \u05d4\u05dc\u05d1 \u05e0\u05e4\u05ea\u05d7 \u05dc\u05e9\u05e4\u05e2 \u05e0\u05d5\u05e1\u05e3.\n\u05db\u05da \u05e4\u05d5\u05e2\u05dc \u05d7\u05d5\u05e7 \u05d4\u05d4\u05e9\u05ea\u05e7\u05e4\u05d5\u05ea \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9\u05ea: \u05de\u05d4 \u05e9\u05d0\u05ea \u05e8\u05d5\u05d0\u05d4 \u05de\u05ea\u05e8\u05d7\u05d1. \u05de\u05d4 \u05e9\u05de\u05d1\u05e8\u05db\u05d9\u05dd \u05d4\u05d5\u05e4\u05da \u05dc\u05de\u05e7\u05d5\u05e8 \u05d7\u05d9\u05d9\u05dd.\n\ud83d\udca1 \u05de\u05e9\u05e4\u05d8 \u05de\u05e4\u05ea\u05d7 \u05dc\u05ea\u05d5\u05d3\u05e2\u05d4 \u05d1\u05de\u05d4\u05dc\u05da \u05d4\u05d9\u05d5\u05dd:\n"\u05d2\u05dd \u05d1\u05ea\u05d5\u05da \u05d4\u05d4\u05e1\u05ea\u05e8\u05d4 \u05d0\u05ea\u05d4 \u05d8\u05d5\u05d1 \u05d5\u05de\u05d8\u05d9\u05d1 \u05dc\u05d9\n\u05e7\u05d3\u05d5\u05e9 \u05e7\u05d3\u05d5\u05e9 \u05e7\u05d3\u05d5\u05e9\n\u05e9\u05dc\u05d5\u05e9 \u05e8\u05de\u05d5\u05ea \u05e9\u05dc \u05e7\u05d3\u05d5\u05e9\u05d4 \u05d1\u05d4\u05e9\u05e8\u05d0\u05ea \u05e4\u05e8\u05e9\u05d5\u05ea \u05d4\u05ea\u05d5\u05e8\u05d4 \u05e7\u05e8\u05d7 \u05d7\u05d1\u05e8\u05ea \u05d5\u05d1\u05dc\u05e7.\n\u05d4\u05e7\u05d3\u05d5\u05e9 \u05d4\u05e8\u05d0\u05e9\u05d5\u05df (\u05e7\u05e8\u05d7): \u05de\u05d3\u05e8\u05d9\u05da \u05d0\u05d5\u05ea\u05e0\u05d5 \u05dc\u05e1\u05d5\u05d3 \u05d4\u05d4\u05ea\u05d1\u05d8\u05dc\u05d5\u05ea (\u05e2\u05d5\u05dc\u05dd \u05d4\u05d1\u05e8\u05d9\u05d0\u05d4)\n\u05e7\u05d5\u05e8\u05d7 \u05d8\u05e2\u05df: "\u05db\u05d9 \u05db\u05dc \u05d4\u05e2\u05d3\u05d4 \u05db\u05d5\u05dc\u05dd \u05e7\u05d3\u05d5\u05e9\u05d9\u05dd". \u05d0\u05d1\u05dc \u05dc\u05e4\u05d9 \u05d4\u05e7\u05d1\u05dc\u05d4, \u05e7\u05d3\u05d5\u05e9\u05d4 \u05d0\u05de\u05ea\u05d9\u05ea \u05de\u05ea\u05d7\u05d9\u05dc\u05d4 \u05d1\u05d1\u05d9\u05d8\u05d5\u05dc \u05d4"\u05d0\u05e0\u05d9" \u05db\u05dc\u05e4\u05d9 \u05d4\u05d0\u05d5\u05e8 \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9.\n\u05d1\u05d7\u05e1\u05d9\u05d3\u05d5\u05ea \u05de\u05d5\u05e1\u05d1\u05e8 \u05e9\u05e7\u05d5\u05e8\u05d7 \u05e8\u05e6\u05d4 \u05e7\u05d3\u05d5\u05e9\u05d4 \u05d1\u05dc\u05d9 \u05e1\u05d3\u05e8, \u05d1\u05dc\u05d9 \u05d4\u05d9\u05e8\u05e8\u05db\u05d9\u05d4 \u05e9\u05dc \u05e0\u05e9\u05de\u05d5\u05ea, \u05d1\u05dc\u05d9 \u05de\u05e9\u05d4 \u05d5\u05d0\u05d4\u05e8\u05d5\u05df \u2013 \u05d0\u05d1\u05dc \u05d6\u05d4 \u05db\u05de\u05d5 \u05dc\u05d1\u05e7\u05e9 \u05d0\u05d5\u05e8 \u05d1\u05dc\u05d9 \u05db\u05dc\u05d9.\n\ud83d\udd39 \u05d4"\u05e7\u05d3\u05d5\u05e9" \u05d4\u05e8\u05d0\u05e9\u05d5\u05df \u05d1\u05ea\u05e4\u05d9\u05dc\u05ea "\u05e7\u05d3\u05d5\u05e9, \u05e7\u05d3\u05d5\u05e9, \u05e7\u05d3\u05d5\u05e9"  \u05de\u05e9\u05d5\u05d9\u05da \u05dc\u05e4\u05d9 \u05d4\u05d6\u05d5\u05d4\u05e8 \u05dc\u05e2\u05d5\u05dc\u05dd \u05d4\u05d1\u05e8\u05d9\u05d0\u05d4 - \u05e2\u05d5\u05dc\u05dd \u05d4\u05e0\u05e9\u05de\u05d5\u05ea, \u05e2\u05d5\u05dc\u05dd \u05e9\u05d1\u05d5 \u05d9\u05e9 \u05ea\u05e4\u05d9\u05e1\u05d4 \u05de\u05e1\u05d5\u05d9\u05de\u05ea \u05d1\u05d0\u05d5\u05e8, \u05d0\u05da \u05e2\u05d3\u05d9\u05d9\u05df \u05d1\u05d9\u05d8\u05d5\u05dc \u05de\u05d5\u05d7\u05dc\u05d8 \u05e9\u05dc \u05d4\u05e0\u05d1\u05e8\u05d0 \u05db\u05dc\u05e4\u05d9 \u05d4\u05d1\u05d5\u05e8\u05d0.\n\u05e7\u05d5\u05e8\u05d7 \u05dc\u05d0 \u05d4\u05e9\u05d9\u05d2 \u05d0\u05ea \u05d4"\u05d1\u05d9\u05d8\u05d5\u05dc" \u05d5\u05dc\u05db\u05df \u05d9\u05e8\u05d3 \u05de\u05d8\u05d4 \u05de\u05d8\u05d4, \u05e2\u05d3 \u05e9\u05e0\u05d1\u05dc\u05e2 \u05d1\u05d0\u05d3\u05de\u05d4.\n\ud83d\udd38 \u05d1\u05d7\u05e1\u05d9\u05d3\u05d5\u05ea (\u05dc\u05d9\u05e7\u05d5\u05d8\u05d9 \u05ea\u05d5\u05e8\u05d4) \u05de\u05d5\u05e1\u05d1\u05e8 \u05e9\u05e7\u05d5\u05e8\u05d7 \u05e8\u05e6\u05d4 "\u05ea\u05db\u05dc\u05d9\u05ea \u05d4\u05e7\u05d3\u05d5\u05e9\u05d4" \u05d0\u05d1\u05dc \u05d1\u05dc\u05d9 \u05dc\u05e2\u05d1\u05d5\u05e8 \u05d0\u05ea \u05d4\u05d3\u05e8\u05da. \u05d1\u05dc\u05d9 \u05e2\u05d1\u05d5\u05d3\u05d4. \u05d5\u05d6\u05d4\u05d5 \u05e9\u05d5\u05e8\u05e9 \u05d4\u05d7\u05d8\u05d0 \u2013 \u05e8\u05e6\u05d5\u05df \u05dc\u05d0\u05d5\u05e8 \u05d1\u05dc\u05d9 \u05d6\u05d9\u05db\u05d5\u05da \u05d4\u05db\u05dc\u05d9\u05dd.\n"\u05e7\u05d3\u05d5\u05e9" \u05e9\u05e0\u05d9 (\u05d7\u05d5\u05e7\u05ea): \u05e1\u05d5\u05d3 \u05d4\u05d0\u05de\u05d5\u05e0\u05d4 \u05d4\u05e4\u05e9\u05d5\u05d8\u05d4 - \u05e2\u05d5\u05dc\u05dd \u05d4\u05d0\u05e6\u05d9\u05dc\u05d5\u05ea\n\u05d1\u05e4\u05e8\u05e9\u05ea \u05d7\u05d5\u05e7\u05ea \u05e2\u05d5\u05e1\u05e7\u05d9\u05dd \u05d1\u05d7\u05d5\u05e7\u05d9 \u05d9\u05e1\u05d5\u05d3. \u05de\u05e6\u05d5\u05d5\u05ea \u05e4\u05e8\u05d4 \u05d0\u05d3\u05d5\u05de\u05d4, \u05e9\u05d0\u05d9\u05df \u05dc\u05d4 \u05d8\u05e2\u05dd \u05d1\u05e9\u05db\u05dc \u05d0\u05e0\u05d5\u05e9\u05d9.\n\u05d1\u05d6\u05d5\u05d4\u05e8 \u05e0\u05d0\u05de\u05e8 \u05e9\u05d6\u05d5 \u05de\u05e6\u05d5\u05d5\u05d4 \u05e9\u05d1\u05d0\u05d4 "\u05de\u05e1\u05d8\u05e8\u05d0 \u05d3\u05d0\u05ea\u05db\u05e1\u05d9\u05d0" \u05de\u05e6\u05d3 \u05d4\u05e8\u05e6\u05d5\u05df \u05d4\u05e2\u05dc\u05d9\u05d5\u05df \u05e9\u05d0\u05d9\u05df \u05dc\u05d5 \u05e9\u05d5\u05dd \u05dc\u05d1\u05d5\u05e9.\n\ud83d\udd39 \u05d4"\u05e7\u05d3\u05d5\u05e9" \u05d4\u05e9\u05e0\u05d9 \u05e9\u05d9\u05d9\u05da \u05dc\u05e4\u05d9 \u05d4\u05e7\u05d1\u05dc\u05d4 \u05dc\u05e2\u05d5\u05dc\u05dd \u05d4\u05d0\u05e6\u05d9\u05dc\u05d5\u05ea, \u05e9\u05dd \u05d0\u05d9\u05df \u05db\u05dc\u05dc \u05ea\u05e4\u05d9\u05e1\u05d4 \u05e8\u05e7 \u05d0\u05d7\u05d3\u05d5\u05ea \u05e4\u05e9\u05d5\u05d8\u05d4.\n\u05e7\u05d3\u05d5\u05e9\u05d4 \u05d6\u05d5 \u05d1\u05d0\u05d4 \u05d3\u05d5\u05d5\u05e7\u05d0 \u05de\u05ea\u05d5\u05da \u05d0\u05de\u05d5\u05e0\u05d4 \u05ea\u05de\u05d9\u05de\u05d4, \u05e7\u05d1\u05dc\u05ea \u05e2\u05d5\u05dc \u05e9\u05dc "\u05e0\u05e2\u05e9\u05d4 \u05d5\u05e0\u05e9\u05de\u05e2", \u05d1\u05dc\u05d9 \u05e9\u05db\u05dc, \u05d1\u05dc\u05d9 \u05e9\u05d0\u05dc\u05d5\u05ea - \u05e8\u05e7 \u05d3\u05d1\u05e7\u05d5\u05ea.\n\ud83d\udd38 \u05e8\u05d1\u05d9 \u05e0\u05d7\u05de\u05df \u05de\u05d1\u05e8\u05e1\u05dc\u05d1 \u05de\u05e1\u05d1\u05d9\u05e8 \u05e9\u05d3\u05d5\u05d5\u05e7\u05d0 \u05db\u05e9\u05d4\u05d0\u05d3\u05dd \u05e0\u05db\u05e0\u05e2 \u05dc\u05de\u05d4 \u05e9\u05d4\u05d5\u05d0 \u05dc\u05d0 \u05de\u05d1\u05d9\u05df \u05e9\u05dd \u05de\u05ea\u05d2\u05dc\u05d4 \u05d4\u05e7\u05d3\u05d5\u05e9\u05d4 \u05d4\u05d2\u05d1\u05d5\u05d4\u05d4 \u05d1\u05d9\u05d5\u05ea\u05e8.\n\u05d6\u05d4 \u05d4"\u05e7\u05d3\u05d5\u05e9" \u05e9\u05dc \u05d4\u05e0\u05e4\u05e9 \u05d4\u05d1\u05d4\u05de\u05d9\u05ea \u05e9\u05de\u05ea\u05d1\u05d8\u05dc\u05ea \u05d5\u05dc\u05d0 \u05de\u05ea\u05d5\u05d5\u05db\u05d7\u05ea  \u05d5\u05dc\u05db\u05df \u05e0\u05e4\u05ea\u05d7\u05ea \u05dc\u05d0\u05d5\u05e8 \u05e9\u05dc\u05de\u05e2\u05dc\u05d4 \u05de\u05d4\u05d8\u05d1\u05e2.\n"\u05e7\u05d3\u05d5\u05e9" \u05e9\u05dc\u05d9\u05e9\u05d9 (\u05d1\u05dc\u05e7): \u05e1\u05d5\u05d3 \u05d4\u05d4\u05ea\u05d4\u05e4\u05db\u05d5\u05ea - \u05e2\u05d5\u05dc\u05dd \u05d4\u05e2\u05e9\u05d9\u05d9\u05d4\n\u05d1\u05e4\u05e8\u05e9\u05ea \u05d1\u05dc\u05e7, \u05d1\u05dc\u05e2\u05dd \u05de\u05e0\u05e1\u05d4 \u05dc\u05e7\u05dc\u05dc \u05d5\u05d4\u05e7\u05d3\u05d5\u05e9 \u05d1\u05e8\u05d5\u05da \u05d4\u05d5\u05d0 \u05d4\u05d5\u05e4\u05da \u05d0\u05ea \u05d4\u05e7\u05dc\u05dc\u05d4 \u05dc\u05d1\u05e8\u05db\u05d4.\n\u05d4\u05d7\u05e1\u05d9\u05d3\u05d5\u05ea \u05de\u05e1\u05d1\u05d9\u05e8\u05d4 \u05e9\u05d6\u05d5 \u05de\u05d3\u05e8\u05d2\u05d4 \u05e9\u05d1\u05d4 \u05d4\u05d0\u05d5\u05e8 \u05d4\u05e2\u05dc\u05d9\u05d5\u05df \u05d9\u05d5\u05e8\u05d3 \u05e2\u05d3 \u05dc\u05de\u05e6\u05d9\u05d0\u05d5\u05ea \u05d4\u05d7\u05d5\u05de\u05e8\u05d9\u05ea \u05d1\u05d9\u05d5\u05ea\u05e8 \u05d5\u05de\u05d0\u05d9\u05e8 \u05d1\u05ea\u05d5\u05db\u05d4.\n\ud83d\udd39 \u05d4"\u05e7\u05d3\u05d5\u05e9" \u05d4\u05e9\u05dc\u05d9\u05e9\u05d9 \u05e9\u05d9\u05d9\u05da \u05dc\u05e2\u05d5\u05dc\u05dd \u05d4\u05e2\u05e9\u05d9\u05d9\u05d4 \u05d4\u05e2\u05d5\u05dc\u05dd \u05e9\u05dc\u05e0\u05d5, \u05e9\u05d1\u05d5 \u05d4\u05e7\u05dc\u05d9\u05e4\u05d4 \u05d7\u05d6\u05e7\u05d4, \u05d5\u05d4\u05d4\u05ea\u05d2\u05dc\u05d5\u05ea \u05de\u05d5\u05e1\u05ea\u05e8\u05ea.\n\u05d0\u05d1\u05dc \u05d3\u05d5\u05d5\u05e7\u05d0 \u05db\u05d0\u05df \u05de\u05ea\u05d2\u05dc\u05d4 \u05d4\u05db\u05d7 \u05e9\u05dc \u05d4\u05e7\u05d3\u05d5\u05e9\u05d4 \u05dc\u05d4\u05e4\u05d5\u05da \u05d7\u05d5\u05e9\u05da \u05dc\u05d0\u05d5\u05e8.\n\ud83d\udd38 \u05e2\u05dc \u05e4\u05d9 \u05e8\u05d1\u05d9 \u05d9\u05e6\u05d7\u05e7 \u05dc\u05d5\u05e8\u05d9\u05d0 (\u05d4\u05d0\u05e8"\u05d9), \u05e0\u05e9\u05de\u05ea\u05d5 \u05e9\u05dc \u05d1\u05dc\u05e2\u05dd \u05de\u05e9\u05d5\u05e8\u05e9 \u05d2\u05d1\u05d5\u05d4 \u05de\u05d0\u05d5\u05d3 \u05d0\u05da \u05d4\u05d5\u05d0 \u05e0\u05e4\u05dc \u05d0\u05dc \u05d4\u05e7\u05dc\u05d9\u05e4\u05d5\u05ea \u05db\u05d9 \u05dc\u05d0 \u05e9\u05de\u05e8 \u05e2\u05dc \u05e2\u05e6\u05de\u05d5.\n\u05d5\u05d4\u05d1\u05e8\u05db\u05d5\u05ea \u05e9\u05d9\u05e6\u05d0\u05d5 \u05de\u05e4\u05d9\u05d5 \u05d4\u05df \u05ea\u05d5\u05e6\u05d0\u05d4 \u05e9\u05dc \u05db\u05d7 \u05e2\u05dc\u05d9\u05d5\u05df \u05e9\u05e9\u05d5\u05d1\u05e8 \u05d0\u05ea \u05d4\u05d8\u05d1\u05e2 \u05d5\u05de\u05d2\u05dc\u05d4 \u05d0\u05d5\u05e8 \u05e9\u05dc \u05d2\u05d0\u05d5\u05dc\u05d4 \u05d2\u05dd \u05de\u05ea\u05d5\u05da \u05d8\u05d5\u05de\u05d0\u05d4.\n\u05d5\u05d6\u05d4 \u05e1\u05d5\u05d3 \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4: \u05d2\u05dd \u05db\u05e9\u05e0\u05e8\u05d0\u05d4 \u05e9\u05d0\u05d9\u05df \u05ea\u05e7\u05d5\u05d5\u05d4 \u05d4\u05e7\u05d3\u05d5\u05e9\u05d4 \u05e4\u05d5\u05e8\u05e6\u05ea \u05d0\u05ea \u05d4\u05de\u05d7\u05e1\u05d5\u05dd \u05d5\u05de\u05d5\u05e6\u05d9\u05d0\u05d4 \u05d1\u05e8\u05db\u05d4.\n\u2728 \u05e1\u05d9\u05db\u05d5\u05dd \u05d7\u05e1\u05d9\u05d3\u05d9-\u05e7\u05d1\u05dc\u05d9:\n\u05e4\u05e8\u05e9\u05d4\n\u05e7\u05d3\u05d5\u05e9\n\u05e2\u05d5\u05dc\u05dd \u05e7\u05d1\u05dc\u05d9\n\u05de\u05d9\u05d3\u05d4 \u05e0\u05e4\u05e9\u05d9\u05ea\n\u05e2\u05d9\u05e7\u05e8 \u05d4\u05e2\u05d1\u05d5\u05d3\u05d4\n\u05e7\u05d5\u05e8\u05d7\n\u05e7\u05d3\u05d5\u05e9 \u05e8\u05d0\u05e9\u05d5\u05df\n\u05e2\u05d5\u05dc\u05dd \u05d4\u05d1\u05e8\u05d9\u05d0\u05d4\n\u05d1\u05d9\u05d8\u05d5\u05dc \u05d4\u05d0\u05d2\u05d5\n\u05e7\u05d1\u05dc\u05ea \u05d4\u05e0\u05d4\u05d2\u05d4 \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea\n\u05d7\u05d5\u05e7\u05ea\n\u05e7\u05d3\u05d5\u05e9 \u05e9\u05e0\u05d9\n\u05e2\u05d5\u05dc\u05dd \u05d4\u05d0\u05e6\u05d9\u05dc\u05d5\u05ea\n\u05d0\u05de\u05d5\u05e0\u05d4 \u05ea\u05de\u05d9\u05de\u05d4\n\u05e7\u05d1\u05dc\u05ea \u05e2\u05d5\u05dc \u05de\u05e6\u05d5\u05d5\u05ea\n\u05d1\u05dc\u05e7\n\u05e7\u05d3\u05d5\u05e9 \u05e9\u05dc\u05d9\u05e9\u05d9\n\u05e2\u05d5\u05dc\u05dd \u05d4\u05e2\u05e9\u05d9\u05d9\u05d4\n\u05ea\u05d9\u05e7\u05d5\u05df \u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea\n\u05d4\u05e4\u05d9\u05db\u05ea \u05d7\u05d5\u05e9\u05da \u05dc\u05d0\u05d5\u05e8\n\ud83d\udcab \u05de\u05d4 \u05d6\u05d4 \u05d0\u05d5\u05de\u05e8 \u05dc\u05e0\u05d5 \u05d1\u05ea\u05e4\u05d9\u05dc\u05d4?\n\u05d1\u05db\u05dc \u05e4\u05e2\u05dd \u05e9\u05d0\u05e0\u05d7\u05e0\u05d5 \u05d0\u05d5\u05de\u05e8\u05d9\u05dd "\u05e7\u05d3\u05d5\u05e9 \u05e7\u05d3\u05d5\u05e9 \u05e7\u05d3\u05d5\u05e9" \u05d0\u05e0\u05d7\u05e0\u05d5 \u05dc\u05d0 \u05e8\u05e7 \u05de\u05e9\u05d1\u05d7\u05d9\u05dd.\n\u05d0\u05e0\u05d7\u05e0\u05d5 \u05e2\u05d5\u05d1\u05e8\u05d9\u05dd \u05ea\u05d4\u05dc\u05d9\u05da \u05e4\u05e0\u05d9\u05de\u05d9:\n\u05de\u05ea\u05d1\u05d8\u05dc\u05d9\u05dd (\u05e7\u05d5\u05e8\u05d7)\n\u05de\u05e7\u05d1\u05dc\u05d9\u05dd \u05d1\u05d0\u05de\u05d5\u05e0\u05d4 (\u05d7\u05d5\u05e7\u05ea)\n\u05de\u05d0\u05d9\u05e8\u05d9\u05dd \u05d0\u05ea \u05d4\u05e2\u05d5\u05dc\u05dd \u05e1\u05d1\u05d9\u05d1\u05e0\u05d5 (\u05d1\u05dc\u05e7)')
B.KV=new A.cv(19,'\u05e9\u05dc\u05d5\u05e9\u05ea \u05d4"\u05e7\u05d3\u05d5\u05e9": \u05e9\u05dc\u05d5\u05e9\u05d4 \u05e9\u05e2\u05e8\u05d9\u05dd \u05dc\u05e0\u05e9\u05de\u05d4','\u2728 \u05ea\u05e8\u05d2\u05d9\u05dc \u05d4\u05d8\u05de\u05e2\u05d4: \u05e9\u05dc\u05d5\u05e9\u05ea \u05d4"\u05e7\u05d3\u05d5\u05e9" \u05e9\u05dc\u05d5\u05e9\u05d4 \u05e9\u05e2\u05e8\u05d9\u05dd \u05dc\u05e0\u05e9\u05de\u05d4 \u2728\n\u05e9\u05d1\u05d5 \u05d1\u05e9\u05e7\u05d8, \u05d1\u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05e2\u05e6\u05d5\u05de\u05d5\u05ea, \u05d9\u05d3\u05d9\u05d9\u05dd \u05e2\u05dc \u05d4\u05dc\u05d1 \u05d0\u05d5 \u05e4\u05ea\u05d5\u05d7\u05d5\u05ea \u05db\u05dc\u05e4\u05d9 \u05de\u05e2\u05dc\u05d4\n\ud83d\udd25 \u05e9\u05dc\u05d1 \u05e8\u05d0\u05e9\u05d5\u05df: "\u05e7\u05d3\u05d5\u05e9"  \u05e9\u05e2\u05e8 \u05d4\u05d4\u05ea\u05d1\u05d8\u05dc\u05d5\u05ea\n\u05d1\u05d4\u05e9\u05e8\u05d0\u05ea \u05e4\u05e8\u05e9\u05ea \u05e7\u05d5\u05e8\u05d7 | \u05e2\u05d5\u05dc\u05dd \u05d4\u05d1\u05e8\u05d9\u05d0\u05d4 | \u05d1\u05d9\u05d8\u05d5\u05dc \u05d4\u05d0\u05d2\u05d5\n\ud83d\udd38 \u05e2\u05e6\u05d5\u05dd/\u05d9 \u05e2\u05d9\u05e0\u05d9\u05d9\u05dd.\n\ud83d\udd38 \u05e0\u05e9\u05d5\u05dd \u05e2\u05de\u05d5\u05e7. \u05d5\u05d3\u05de\u05d9\u05d9\u05df \u05d0\u05d5\u05e8 \u05dc\u05d1\u05df \u05d7\u05d6\u05e7 \u05d9\u05d5\u05e8\u05d3 \u05de\u05d4\u05e9\u05de\u05d9\u05d9\u05dd \u05d5\u05de\u05e7\u05d9\u05e3 \u05d0\u05d5\u05ea\u05da.\n\ud83d\udd38 \u05e9\u05d0\u05dc \u05d0\u05ea \u05e2\u05e6\u05de\u05da \u05d1\u05e9\u05e7\u05d8:\n\u05de\u05d4 \u05d1\u05d9 \u05e2\u05d3\u05d9\u05d9\u05df \u05e8\u05d5\u05e6\u05d4 \u05e9\u05dc\u05d9\u05d8\u05d4?\n\u05d4\u05d9\u05db\u05df \u05d0\u05e0\u05d9 \u05de\u05ea\u05e7\u05e9\u05d4 \u05dc\u05e7\u05d1\u05dc \u05e1\u05de\u05db\u05d5\u05ea, \u05de\u05d3\u05e8\u05d9\u05da, \u05d0\u05d5 \u05e1\u05d3\u05e8 \u05e0\u05e9\u05de\u05ea\u05d9?\n\ud83d\udd38 \u05d0\u05de\u05d5\u05e8 \u05d1\u05dc\u05d1:\n"\u05d0\u05e0\u05d9 \u05d1\u05d5\u05d7\u05e8 \u05dc\u05e9\u05d7\u05e8\u05e8 \u05d0\u05ea \u05d4\u05e9\u05dc\u05d9\u05d8\u05d4. \u05d0\u05e0\u05d9 \u05dc\u05d0 \u05d7\u05d9\u05d9\u05d1 \u05dc\u05d3\u05e2\u05ea \u05d4\u05db\u05d5\u05dc. \u05d0\u05e0\u05d9 \u05de\u05ea\u05d1\u05d8\u05dc \u05dc\u05d0\u05d5\u05e8 \u05d4\u05e2\u05dc\u05d9\u05d5\u05df."\n\ud83d\udd38 \u05d0\u05de\u05d5\u05e8 \u05dc\u05d0\u05d8:\n"\u05e7\u05d3\u05d5\u05e9..." \u2013 \u05db\u05de\u05d5 \u05de\u05dc\u05d0\u05da.\n\ud83d\udc2e \u05e9\u05dc\u05d1 \u05e9\u05e0\u05d9: "\u05e7\u05d3\u05d5\u05e9" - \u05e9\u05e2\u05e8 \u05d4\u05d0\u05de\u05d5\u05e0\u05d4 \u05d4\u05e4\u05e9\u05d5\u05d8\u05d4\n\u05d1\u05d4\u05e9\u05e8\u05d0\u05ea \u05e4\u05e8\u05e9\u05ea \u05d7\u05d5\u05e7\u05ea | \u05e2\u05d5\u05dc\u05dd \u05d4\u05d0\u05e6\u05d9\u05dc\u05d5\u05ea | \u05e7\u05d1\u05dc\u05ea \u05d4\u05e0\u05e1\u05ea\u05e8\n\ud83d\udd38 \u05d3\u05de\u05d9\u05d9\u05df \u05d0\u05ea \u05e2\u05e6\u05de\u05da \u05e2\u05d5\u05de\u05d3 \u05de\u05d5\u05dc \u05d3\u05dc\u05ea \u05d2\u05d3\u05d5\u05dc\u05d4, \u05e2\u05e9\u05d5\u05d9\u05d4 \u05d0\u05d5\u05e8. \u05d0\u05d9\u05e0\u05da \u05d9\u05d5\u05d3\u05e2 \u05de\u05d4 \u05d9\u05e9 \u05de\u05d0\u05d7\u05d5\u05e8\u05d9\u05d4, \u05d0\u05d1\u05dc \u05d0\u05ea\u05d4 \u05e1\u05d5\u05de\u05da.\n\ud83d\udd38 \u05e9\u05d0\u05dc \u05d0\u05ea \u05e2\u05e6\u05de\u05da:\n\u05de\u05d4 \u05d1\u05d7\u05d9\u05d9 \u05de\u05d1\u05e7\u05e9 \u05d4\u05e1\u05d1\u05e8, \u05d0\u05d1\u05dc \u05d0\u05e0\u05d9 \u05dc\u05d0 \u05de\u05e7\u05d1\u05dc?\n\u05d0\u05d9\u05e4\u05d4 \u05d0\u05e0\u05d9 \u05d9\u05db\u05d5\u05dc \u05dc\u05d1\u05d7\u05d5\u05e8 \u05d1\u05d0\u05de\u05d5\u05e0\u05d4 \u05d1\u05de\u05e7\u05d5\u05dd \u05dc\u05d4\u05d1\u05d9\u05df?\n\ud83d\udd38 \u05d0\u05de\u05d5\u05e8 \u05d1\u05dc\u05d1:\n"\u05d0\u05e0\u05d9 \u05e0\u05d5\u05ea\u05df \u05d0\u05de\u05d5\u05df. \u05d0\u05e0\u05d9 \u05d1\u05d5\u05d8\u05d7 \u05e9\u05d4\' \u05de\u05d5\u05d1\u05d9\u05dc \u05d0\u05d5\u05ea\u05d9, \u05d2\u05dd \u05d0\u05dd \u05d0\u05d9\u05e0\u05d9 \u05de\u05d1\u05d9\u05df."\n\ud83d\udd38 \u05d0\u05de\u05d5\u05e8 \u05d1\u05dc\u05d7\u05d9\u05e9\u05d4:\n"\u05e7\u05d3\u05d5\u05e9..."  \u05db\u05de\u05d5 \u05ea\u05e4\u05d9\u05dc\u05d4 \u05e9\u05dc \u05d9\u05dc\u05d3.\n\ud83e\uddd9 \u05e9\u05dc\u05d1 \u05e9\u05dc\u05d9\u05e9\u05d9: "\u05e7\u05d3\u05d5\u05e9" \u05e9\u05e2\u05e8 \u05d4\u05d4\u05ea\u05d4\u05e4\u05db\u05d5\u05ea\n\u05d1\u05d4\u05e9\u05e8\u05d0\u05ea \u05e4\u05e8\u05e9\u05ea \u05d1\u05dc\u05e7 | \u05e2\u05d5\u05dc\u05dd \u05d4\u05e2\u05e9\u05d9\u05d9\u05d4 | \u05d4\u05e4\u05d9\u05db\u05ea \u05d4\u05d7\u05d5\u05e9\u05da \u05dc\u05d0\u05d5\u05e8\n\ud83d\udd38 \u05d6\u05db\u05d5\u05e8 \u05e7\u05d5\u05e9\u05d9 \u05e9\u05d7\u05d5\u05d5\u05d9\u05ea \u05dc\u05d0\u05d7\u05e8\u05d5\u05e0\u05d4 - \u05e8\u05d2\u05e2 \u05d7\u05e9\u05d5\u05da, \u05de\u05d1\u05dc\u05d1\u05dc, \u05db\u05d0\u05d5\u05d1.\n\ud83d\udd38 \u05e9\u05d0\u05dc \u05d0\u05ea \u05e2\u05e6\u05de\u05da:\n\u05d4\u05d0\u05dd \u05d0\u05e4\u05e9\u05e8 \u05e9\u05de\u05e1\u05ea\u05ea\u05e8\u05ea \u05db\u05d0\u05df \u05d1\u05e8\u05db\u05d4?\n\u05d4\u05d0\u05dd \u05d9\u05d9\u05ea\u05db\u05df \u05e9\u05d4\u05e7\u05d5\u05e9\u05d9 \u05d4\u05d6\u05d4 \u05d4\u05d5\u05d0 \u05d3\u05d7\u05d9\u05e4\u05d4 \u05dc\u05e2\u05d5\u05e6\u05de\u05d4 \u05d7\u05d3\u05e9\u05d4?\n\ud83d\udd38 \u05d0\u05de\u05d5\u05e8 \u05d1\u05dc\u05d1:\n"\u05d0\u05e4\u05d9\u05dc\u05d5 \u05de\u05d4 \u05e9\u05e0\u05e8\u05d0\u05d4 \u05e8\u05e2 \u05d9\u05d4\u05e4\u05d5\u05da \u05dc\u05d8\u05d5\u05d1. \u05d9\u05e9 \u05d1\u05d9 \u05d0\u05d5\u05e8 \u05e9\u05de\u05e1\u05d5\u05d2\u05dc \u05dc\u05d4\u05d0\u05d9\u05e8 \u05d2\u05dd \u05d0\u05ea \u05d6\u05d4."\n\ud83d\udd38 \u05d0\u05de\u05d5\u05e8 \u05d1\u05e7\u05d5\u05dc \u05e9\u05e7\u05d8 \u05d0\u05da \u05de\u05dc\u05d0 \u05e2\u05d5\u05e6\u05de\u05d4:\n"\u05e7\u05d3\u05d5\u05e9!" \u2013 \u05db\u05de\u05d5 \u05d1\u05e8\u05db\u05ea \u05db\u05d4\u05df \u05e2\u05dc \u05d0\u05d3\u05dd.\n\ud83d\udcab \u05e1\u05d9\u05d5\u05dd \u05d4\u05ea\u05e8\u05d2\u05d5\u05dc:\n\u05d4\u05e0\u05d7 \u05d9\u05d3 \u05e2\u05dc \u05d4\u05dc\u05d1. \u05d0\u05de\u05d5\u05e8 \u05dc\u05e2\u05e6\u05de\u05da:\n"\u05d0\u05e0\u05d9 \u05db\u05dc\u05d9 \u05dc\u05d0\u05d5\u05e8 \u05d0\u05dc\u05d5\u05e7\u05d9. \u05d0\u05e0\u05d9 \u05de\u05ea\u05d1\u05d8\u05dc, \u05d0\u05e0\u05d9 \u05de\u05d0\u05de\u05d9\u05df, \u05d0\u05e0\u05d9 \u05de\u05d4\u05e4\u05da \u05d0\u05ea \u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea.\n\u05e9\u05dc\u05d5\u05e9 \u05de\u05d3\u05e8\u05d2\u05d5\u05ea \u05e9\u05dc \u05e7\u05d3\u05d5\u05e9\u05d4 \u05e4\u05d5\u05e2\u05de\u05d5\u05ea \u05d1\u05d9."\n\u05e0\u05e9\u05d5\u05dd \u05e2\u05de\u05d5\u05e7. \u05e4\u05e7\u05d7 \u05e2\u05d9\u05e0\u05d9\u05d9\u05dd. \u05d7\u05d6\u05d5\u05e8 \u05dc\u05e2\u05d5\u05dc\u05dd \u2013 \u05e2\u05dd \u05de\u05e2\u05d8 \u05d9\u05d5\u05ea\u05e8 \u05d0\u05d5\u05e8.\n\u05db\u05d9 \u05e9\u05dd \u05d4\u05e9\u05dd \u05d0\u05e7\u05e8\u05d0 \u2013 \u05d4\u05d7\u05db\u05de\u05d4 \u05d5\u05d4\u05d7\u05d9\u05d1\u05d5\u05e8 \u05d0\u05dc \u05d4\u05d0\u05d9\u05e0\u05e1\u05d5\u05e3\n"\u05d4\u05d1\u05d5 \u05d2\u05d5\u05d3\u05dc \u05dc\u05d0\u05dc\u05d5\u05e7\u05d9\u05e0\u05d5" \u2013 \u05e7\u05e8\u05d9\u05d0\u05d4 \u05d6\u05d5 \u05de\u05d6\u05de\u05e0\u05ea \u05d0\u05d5\u05ea\u05e0\u05d5 \u05dc\u05d4\u05e6\u05d9\u05d1 \u05d0\u05ea \u05d4\u05de\u05d5\u05e9\u05d2 \u05e9\u05dc \u05d0\u05dc\u05d5\u05e7\u05d5\u05ea \u05d5\u05de\u05d7\u05d5\u05d9\u05d1\u05d5\u05ea\u05e0\u05d5 \u05d0\u05dc\u05d9\u05d4 \u05d1\u05de\u05e8\u05db\u05d6 \u05d7\u05d9\u05d9\u05e0\u05d5. \u05d0\u05dc\u05d5\u05e7\u05d5\u05ea \u05d0\u05d9\u05e0\u05e0\u05d4 \u05e8\u05e7 \u05db\u05d5\u05d7 \u05d7\u05d9\u05e6\u05d5\u05e0\u05d9 \u05d0\u05d5 \u05d3\u05de\u05d5\u05ea \u05de\u05d5\u05e1\u05e8\u05d9\u05ea; \u05d4\u05d9\u05d0 \u05de\u05d9\u05d9\u05e6\u05d2\u05ea \u05d0\u05ea \u05d4\u05d7\u05db\u05de\u05d4 \u05d4\u05d0\u05d9\u05e0\u05e1\u05d5\u05e4\u05d9\u05ea, \u05d0\u05ea \u05d4\u05d9\u05d3\u05e2 \u05e9\u05de\u05d0\u05d7\u05d5\u05e8\u05d9 \u05db\u05dc \u05d3\u05d1\u05e8 \u05d1\u05e2\u05d5\u05dc\u05dd \u05d5\u05d0\u05ea \u05d4\u05e1\u05d3\u05e8 \u05d4\u05d9\u05e1\u05d5\u05d3\u05d9 \u05e9\u05dc \u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea.\n\u05d4\u05d7\u05db\u05de\u05d4, \u05e2\u05dc \u05e4\u05d9 \u05d4\u05d4\u05d1\u05e0\u05d4 \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9\u05ea, \u05d4\u05d9\u05d0 \u05de\u05e4\u05ea\u05d7 \u05dc\u05d0\u05d5\u05e9\u05e8 \u05d4\u05d0\u05de\u05d9\u05ea\u05d9. \u05d4\u05d9\u05d0 \u05de\u05d0\u05e4\u05e9\u05e8\u05ea \u05dc\u05e0\u05d5 \u05dc\u05e8\u05d0\u05d5\u05ea \u05de\u05e2\u05d1\u05e8 \u05dc\u05de\u05e8\u05d0\u05d9\u05ea \u05d4\u05e2\u05d9\u05df, \u05dc\u05d4\u05d1\u05d7\u05d9\u05df \u05d1\u05e7\u05e9\u05e8\u05d9\u05dd \u05d4\u05e2\u05de\u05d5\u05e7\u05d9\u05dd \u05d1\u05d9\u05df \u05d0\u05d9\u05e8\u05d5\u05e2\u05d9\u05dd, \u05d5\u05dc\u05d4\u05d1\u05d9\u05df \u05d0\u05ea \u05e2\u05e6\u05de\u05e0\u05d5 \u05d5\u05d0\u05ea \u05ea\u05db\u05dc\u05d9\u05ea\u05e0\u05d5 \u05d1\u05e6\u05d5\u05e8\u05d4 \u05de\u05e2\u05de\u05d9\u05e7\u05d4. \u05db\u05d0\u05e9\u05e8 \u05d0\u05e0\u05d5 \u05de\u05ea\u05d7\u05d1\u05e8\u05d9\u05dd \u05d0\u05dc \u05d4\u05d7\u05db\u05de\u05d4 \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9\u05ea, \u05d0\u05e0\u05d5 \u05dc\u05de\u05e2\u05e9\u05d4 \u05de\u05ea\u05e7\u05e8\u05d1\u05d9\u05dd \u05dc\u05de\u05e7\u05d5\u05e8 \u05d4\u05d0\u05d9\u05e0\u05e1\u05d5\u05e4\u05d9, \u05dc\u05d0\u05d5\u05ea\u05d4 \u05e0\u05d5\u05db\u05d7\u05d5\u05ea \u05e9\u05de\u05de\u05dc\u05d0\u05ea \u05d0\u05ea \u05db\u05dc \u05e7\u05d9\u05d5\u05dd.\n"\u05db\u05d9 \u05e9\u05dd \u05d4\u05e9\u05dd \u05d0\u05e7\u05e8\u05d0" \u2013 \u05d1\u05db\u05da \u05d0\u05e0\u05d5 \u05de\u05d1\u05e7\u05e9\u05d9\u05dd \u05dc\u05d4\u05e2\u05dc\u05d5\u05ea \u05d0\u05ea \u05de\u05d5\u05d3\u05e2\u05d5\u05ea\u05e0\u05d5 \u05d0\u05dc \u05d4\u05e9\u05dd, \u05d0\u05dc \u05d4\u05d7\u05db\u05de\u05d4, \u05d0\u05dc \u05d0\u05d5\u05ea\u05d5 \u05de\u05e8\u05d7\u05d1 \u05d1\u05d5 \u05d0\u05d9\u05df \u05d2\u05d1\u05d5\u05dc\u05d5\u05ea. \u05d4\u05e8\u05e6\u05d5\u05df \u05e9\u05dc\u05e0\u05d5 \u05dc\u05d4\u05ea\u05d7\u05d1\u05e8 \u05d0\u05dc \u05d4\u05d0\u05dc\u05d5\u05e7\u05d5\u05ea \u05d4\u05d5\u05d0 \u05dc\u05de\u05e2\u05e9\u05d4 \u05e8\u05e6\u05d5\u05df \u05dc\u05d4\u05ea\u05d7\u05d1\u05e8 \u05dc\u05d0\u05de\u05ea, \u05dc\u05d9\u05d3\u05e2 \u05d5\u05dc\u05e1\u05d3\u05e8 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9 \u05e9\u05dc \u05d4\u05e2\u05d5\u05dc\u05dd. \u05db\u05db\u05dc \u05e9\u05e0\u05d7\u05d5\u05d5\u05d4 \u05d0\u05ea \u05d4\u05d7\u05db\u05de\u05d4 \u05d4\u05d6\u05d0\u05ea, \u05db\u05da \u05e0\u05d2\u05dc\u05d4 \u05d0\u05ea \u05d4\u05d0\u05d5\u05e9\u05e8 \u05d4\u05d0\u05de\u05d9\u05ea\u05d9 \u2013 \u05d0\u05d5\u05e9\u05e8 \u05e9\u05de\u05d1\u05d5\u05e1\u05e1 \u05e2\u05dc \u05d4\u05d1\u05e0\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea, \u05e2\u05dc \u05e8\u05d0\u05d9\u05d9\u05d4 \u05e2\u05de\u05d5\u05e7\u05d4, \u05d5\u05e2\u05dc \u05ea\u05d7\u05d5\u05e9\u05ea \u05d0\u05d7\u05d3\u05d5\u05ea \u05e2\u05dd \u05d4\u05de\u05d4\u05d5\u05ea \u05e9\u05de\u05d0\u05d7\u05d5\u05e8\u05d9 \u05db\u05dc \u05d4\u05d3\u05d1\u05e8\u05d9\u05dd.\n\u05d4\u05d7\u05d9\u05d1\u05d5\u05e8 \u05d0\u05dc \u05d4\u05d7\u05db\u05de\u05d4 \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9\u05ea \u05d4\u05d5\u05d0 \u05dc\u05d0 \u05e8\u05e7 \u05d7\u05d5\u05d5\u05d9\u05d4 \u05e8\u05d5\u05d7\u05e0\u05d9\u05ea, \u05d0\u05dc\u05d0 \u05d2\u05dd \u05de\u05d5\u05e8\u05d4 \u05d3\u05e8\u05da \u05dc\u05d7\u05d9\u05d9\u05dd: \u05dc\u05d4\u05ea\u05d1\u05d5\u05e0\u05df, \u05dc\u05d4\u05d1\u05d9\u05df, \u05dc\u05e4\u05e2\u05d5\u05dc \u05de\u05ea\u05d5\u05da\n\u05ea\u05d5\u05d1\u05e0\u05d4. \u05d1\u05db\u05da, \u05db\u05dc \u05e8\u05d2\u05e2 \u05e9\u05dc \u05d7\u05d9\u05d9 \u05d4\u05d9\u05d5\u05dd-\u05d9\u05d5\u05dd \u05d4\u05d5\u05e4\u05da \u05dc\u05de\u05e2\u05d9\u05df \u05e9\u05e2\u05e8 \u05d0\u05dc \u05d4\u05d0\u05d9\u05e0\u05e1\u05d5\u05e3, \u05d5\u05db\u05dc \u05e2\u05e9\u05d9\u05d9\u05d4 \u05e9\u05dc\u05e0\u05d5 \u05de\u05ea\u05de\u05dc\u05d0\u05ea \u05de\u05e9\u05de\u05e2\u05d5\u05ea \u05d5\u05d9\u05d5\u05e4\u05d9.\n\u05d1\u05d5\u05d5\u05d3\u05d0\u05d9! \u05d4\u05e0\u05d4 \u05d2\u05e8\u05e1\u05d4 \u05e9\u05de\u05d7\u05d1\u05e8\u05ea \u05d0\u05ea \u05d4\u05d8\u05e7\u05e1\u05d8 \u05e9\u05dc\u05da \u05e2\u05dd \u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05de\u05e2\u05e9\u05d9\u05ea \u05dc\u05d7\u05d9\u05d1\u05d5\u05e8 \u05dc\u05d7\u05db\u05de\u05d4 \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9\u05ea:',"\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05dc\u05d7\u05d9\u05d1\u05d5\u05e8 \u05dc\u05d7\u05db\u05de\u05d4 \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9\u05ea:",'\u05e9\u05d1\u05d9 \u05d1\u05e0\u05d5\u05d7\u05d5\u05ea, \u05e1\u05d2\u05e8\u05d9 \u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05d5\u05e7\u05d7\u05d9 \u05db\u05de\u05d4 \u05e0\u05e9\u05d9\u05de\u05d5\u05ea \u05e2\u05de\u05d5\u05e7\u05d5\u05ea.\n\u05d7\u05d5\u05e9\u05d9 \u05d0\u05ea \u05de\u05e9\u05e7\u05dc \u05d2\u05d5\u05e4\u05da \u05e2\u05dc \u05d4\u05db\u05d9\u05e1\u05d0 \u05d0\u05d5 \u05e2\u05dc \u05d4\u05e8\u05e6\u05e4\u05d4, \u05d5\u05d4\u05e8\u05d2\u05d9\u05e9\u05d9 \u05d0\u05ea \u05d4\u05d7\u05d9\u05d1\u05d5\u05e8 \u05e9\u05dc\u05da \u05d0\u05dc \u05d4\u05d0\u05d3\u05de\u05d4.\n\u05e0\u05e9\u05e4\u05d9 \u05dc\u05d0\u05d8, \u05d5\u05e9\u05d7\u05e8\u05e8\u05d9 \u05db\u05dc \u05de\u05ea\u05d7. \u05d3\u05de\u05d9\u05d9\u05e0\u05d9 \u05d0\u05d5\u05e8 \u05e8\u05da \u05e2\u05d5\u05dc\u05d4 \u05de\u05d4\u05de\u05e8\u05db\u05d6 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9 \u05e9\u05dc\u05da \u05db\u05dc\u05e4\u05d9 \u05de\u05e2\u05dc\u05d4.\n\u05d7\u05d6\u05e8\u05d9 \u05d1\u05dc\u05d1\u05da \u05e2\u05dc \u05d4\u05de\u05d9\u05dc\u05d9\u05dd: "\u05db\u05d9 \u05e9\u05dd \u05d4\u05e9\u05dd \u05d0\u05e7\u05e8\u05d0". \u05d4\u05e8\u05d2\u05d9\u05e9\u05d9 \u05d0\u05d9\u05da \u05d4\u05e9\u05dd \u05de\u05d7\u05d1\u05e8 \u05d0\u05d5\u05ea\u05da \u05d0\u05dc \u05d4\u05d7\u05db\u05de\u05d4 \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9\u05ea.\n\u05d3\u05de\u05d9\u05d9\u05e0\u05d9 \u05d0\u05d5\u05e8 \u05d0\u05d9\u05e0\u05e1\u05d5\u05e4\u05d9 \u05e9\u05de\u05de\u05dc\u05d0 \u05d0\u05d5\u05ea\u05da \u05d5\u05de\u05d2\u05d9\u05e2 \u05dc\u05db\u05dc \u05e4\u05d9\u05e0\u05d4 \u05d1\u05d7\u05d9\u05d9\u05da. \u05db\u05dc \u05e0\u05e9\u05d9\u05de\u05d4 \u05de\u05e7\u05e8\u05d1\u05ea \u05d0\u05d5\u05ea\u05da \u05dc\u05d4\u05d1\u05e0\u05d4 \u05e2\u05de\u05d5\u05e7\u05d4 \u05d9\u05d5\u05ea\u05e8 \u05e9\u05dc \u05e2\u05e6\u05de\u05da \u05d5\u05d4\u05e2\u05d5\u05dc\u05dd.\n\u05ea\u05d5\u05da \u05db\u05d3\u05d9 \u05e0\u05e9\u05d9\u05de\u05d5\u05ea, \u05d0\u05de\u05e8\u05d9 \u05d1\u05dc\u05d1\u05da: "\u05d0\u05e0\u05d9 \u05e4\u05d5\u05ea\u05d7\u05ea \u05d0\u05ea \u05dc\u05d9\u05d1\u05d9 \u05dc\u05d7\u05db\u05de\u05d4, \u05d0\u05dc \u05d4\u05d0\u05d9\u05e0\u05e1\u05d5\u05e3, \u05d0\u05dc \u05d4\u05d0\u05d5\u05e9\u05e8 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9".\n\u05e9\u05d1\u05d5 \u05db\u05da \u05db\u05de\u05d4 \u05d3\u05e7\u05d5\u05ea, \u05d5\u05d4\u05e8\u05d2\u05d9\u05e9\u05d5 \u05d0\u05d9\u05da \u05db\u05dc \u05de\u05d7\u05e9\u05d1\u05d4 \u05de\u05ea\u05d1\u05d4\u05e8\u05ea, \u05d5\u05db\u05dc \u05e8\u05d2\u05e2 \u05d4\u05d5\u05e4\u05da \u05dc\u05de\u05dc\u05d0 \u05de\u05e9\u05de\u05e2\u05d5\u05ea.\n\u05d1\u05e1\u05d9\u05d5\u05dd, \u05e7\u05d7\u05d9 \u05e0\u05e9\u05d9\u05de\u05d4 \u05e2\u05de\u05d5\u05e7\u05d4 \u05d0\u05d7\u05ea \u05d2\u05d3\u05d5\u05dc\u05d4 \u05d5\u05e4\u05ea\u05d9\u05d7\u05d4 \u05e9\u05dc \u05d4\u05e2\u05d9\u05e0\u05d9\u05d9\u05dd, \u05d5\u05d4\u05e8\u05d2\u05d9\u05e9\u05d9 \u05d0\u05ea \u05d4\u05d7\u05d9\u05d1\u05d5\u05e8 \u05e9\u05dc\u05da \u05d0\u05dc \u05d4\u05d7\u05db\u05de\u05d4 \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9\u05ea \u05dc\u05d0\u05d5\u05e8\u05da \u05db\u05dc \u05d4\u05d9\u05d5\u05dd.\n"\u05e0\u05e4\u05e9\u05d9 \u05db\u05e2\u05e4\u05e8 \u05dc\u05db\u05dc \u05ea\u05d4\u05d9\u05d4" \u2013 \u05de\u05e1\u05e2 \u05d4\u05d4\u05e1\u05db\u05de\u05d4 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05dc\u05d4\u05d9\u05d5\u05ea \u05e7\u05e8\u05e7\u05e2 \u05e4\u05d5\u05e8\u05d9\u05d4 \u05dc\u05db\u05dc"\n\u05d4\u05d1\u05d9\u05d8\u05d5\u05d9 \u05d4\u05d6\u05d4 \u05de\u05ea\u05e4\u05d9\u05dc\u05ea \u05e2\u05de\u05d9\u05d3\u05d4 \u2013 "\u05d5\u05e0\u05e4\u05e9\u05d9 \u05db\u05e2\u05e4\u05e8 \u05dc\u05db\u05dc \u05ea\u05d4\u05d9\u05d4" \u2013 \u05d4\u05d5\u05d0 \u05de\u05d4\u05d1\u05d9\u05d8\u05d5\u05d9\u05d9\u05dd \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9\u05d9\u05dd \u05d4\u05e2\u05de\u05d5\u05e7\u05d9\u05dd \u05d5\u05d4\u05e2\u05d3\u05d9\u05e0\u05d9\u05dd \u05d1\u05d9\u05d5\u05ea\u05e8 \u05d1\u05de\u05e1\u05d5\u05e8\u05ea \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9\u05ea. \u05e7\u05dc \u05dc\u05d8\u05e2\u05d5\u05ea \u05d5\u05dc\u05e4\u05e8\u05e9 \u05d0\u05d5\u05ea\u05d5 \u05db\u05e7\u05e8\u05d9\u05d0\u05d4 \u05dc\u05d1\u05d9\u05d8\u05d5\u05dc \u05e2\u05e6\u05de\u05d9 \u05d0\u05d5 \u05dc\u05d5\u05d5\u05d9\u05ea\u05d5\u05e8 \u05e2\u05dc \u05e2\u05e8\u05da \u05d0\u05d9\u05e9\u05d9, \u05d0\u05da \u05d1\u05e2\u05d5\u05de\u05e7\u05d5 \u2013 \u05d4\u05d5\u05d0 \u05e7\u05e8\u05d9\u05d0\u05d4 \u05e2\u05d6\u05d4 \u05dc\u05d4\u05ea\u05de\u05e1\u05e8\u05d5\u05ea, \u05e4\u05ea\u05d9\u05d7\u05d5\u05ea, \u05d5\u05e8\u05d9\u05e4\u05d5\u05d9 \u05d4\u05d0\u05d2\u05d5.\n\u05de\u05d4 \u05de\u05e9\u05de\u05e2\u05d5\u05ea \u05d4\u05ea\u05d7\u05d5\u05e9\u05d4?\n\u05d4\u05e2\u05e4\u05e8 \u05d0\u05d9\u05e0\u05d5 \u05d7\u05e1\u05e8 \u05e2\u05e8\u05da \u2013 \u05d4\u05d5\u05d0 \u05d4\u05d1\u05e1\u05d9\u05e1 \u05dc\u05db\u05dc \u05d7\u05d9\u05d9\u05dd. \u05d4\u05d5\u05d0 \u05d6\u05d4 \u05e9\u05de\u05e6\u05de\u05d9\u05d7, \u05e9\u05de\u05db\u05d9\u05dc, \u05e9\u05de\u05e7\u05d1\u05dc \u05dc\u05ea\u05d5\u05db\u05d5 \u05d4\u05db\u05dc \u05de\u05d1\u05dc\u05d9 \u05dc\u05e9\u05e4\u05d5\u05d8: \u05de\u05d9 \u05e9\u05d3\u05d5\u05e8\u05da, \u05de\u05d9 \u05e9\u05d6\u05d5\u05e8\u05e2, \u05de\u05d9 \u05e9\u05e0\u05d7 \u05e2\u05dc\u05d9\u05d5. \u05db\u05da \u05d2\u05dd \u05d4\u05d0\u05d3\u05dd \u05d4\u05de\u05d1\u05e7\u05e9 \u05e9\u05d4\u05e0\u05e4\u05e9 \u05e9\u05dc\u05d5 \u05ea\u05d4\u05d9\u05d4 \u05db\u05e2\u05e4\u05e8 \u2013 \u05d0\u05d9\u05e0\u05e0\u05d4 \u05d1\u05e7\u05e9\u05d4 \u05dc\u05d4\u05d9\u05d5\u05ea \u05e8\u05de\u05d5\u05e1, \u05d0\u05dc\u05d0 \u05dc\u05d4\u05d9\u05d5\u05ea \u05e4\u05ea\u05d5\u05d7, \u05de\u05e7\u05d1\u05dc, \u05d7\u05d5\u05e4\u05e9\u05d9 \u05de\u05d0\u05d2\u05d5, \u05d5\u05de\u05ea\u05de\u05e1\u05e8 \u05dc\u05e9\u05dc\u05d9\u05d7\u05d5\u05ea \u05d4\u05d2\u05d1\u05d5\u05d4\u05d4.\n\u05de\u05ea\u05d9 \u05e0\u05db\u05d5\u05df \u05dc\u05d0\u05de\u05e5 \u05d0\u05ea \u05d4\u05ea\u05d7\u05d5\u05e9\u05d4?\n\u05db\u05d0\u05e9\u05e8 \u05d4\u05e4\u05d2\u05d9\u05e2\u05d5\u05ea \u05d2\u05d5\u05d1\u05e8\u05ea \u2013 \u05d4\u05e2\u05e4\u05e8 \u05de\u05d6\u05de\u05d9\u05df \u05d0\u05d5\u05ea\u05e0\u05d5 \u05dc\u05e0\u05e9\u05d5\u05dd \u05dc\u05ea\u05d5\u05da \u05d4\u05e2\u05e0\u05d5\u05d5\u05d4 \u05d1\u05de\u05e7\u05d5\u05dd \u05dc\u05ea\u05d5\u05da \u05d4\u05e2\u05dc\u05d1\u05d5\u05df.\n\u05db\u05d0\u05e9\u05e8 \u05d0\u05e0\u05d7\u05e0\u05d5 \u05de\u05ea\u05e2\u05e7\u05e9\u05d9\u05dd \u05dc\u05e8\u05d0\u05d5\u05ea \u05e6\u05d3\u05e7, \u05e9\u05dc\u05d9\u05d8\u05d4, \u05d4\u05db\u05e8\u05d4 \u2013 \u05d4\u05e2\u05e4\u05e8 \u05de\u05d6\u05db\u05d9\u05e8 \u05dc\u05e0\u05d5 \u05e9\u05e6\u05de\u05d9\u05d7\u05d4 \u05d0\u05de\u05d9\u05ea\u05d9\u05ea \u05d1\u05d0\u05d4 \u05de\u05d4\u05e8\u05e4\u05d9\u05d4, \u05dc\u05d0 \u05de\u05d4\u05d0\u05d7\u05d6\u05d5\u05ea.')
B.KX=new A.cv(20,"\u05dc\u05d4\u05d9\u05d5\u05ea \u05e2\u05e4\u05e8: \u05e4\u05ea\u05d9\u05d7\u05d4 \u05d5\u05d4\u05db\u05dc\u05d4",'\u05db\u05d0\u05e9\u05e8 \u05d0\u05e0\u05d5 \u05e8\u05d5\u05e6\u05d9\u05dd \u05dc\u05d4\u05e7\u05e9\u05d9\u05d1 \u05d1\u05d0\u05de\u05ea \u05dc\u05d0\u05d7\u05e8, \u05d0\u05d5 \u05dc\u05e7\u05d5\u05dc\u05d5 \u05e9\u05dc \u05d0\u05dc\u05d5\u05d4\u05d9\u05dd \u05d1\u05ea\u05d5\u05db\u05e0\u05d5 \u2013 \u05d0\u05e0\u05d5 \u05de\u05d1\u05e7\u05e9\u05d9\u05dd \u05dc\u05d4\u05d9\u05d5\u05ea \u05e2\u05e4\u05e8: \u05dc\u05d0 \u05de\u05dc\u05d0\u05d9\u05dd \u05d1\u05e2\u05e6\u05de\u05e0\u05d5 \u05d0\u05dc\u05d0 \u05e4\u05ea\u05d5\u05d7\u05d9\u05dd \u05dc\u05de\u05d4 \u05e9\u05d1\u05d0.\n\u05e2\u05d3 \u05db\u05de\u05d4 \u05d4\u05d9\u05d0 \u05e6\u05e8\u05d9\u05db\u05d4 \u05dc\u05e9\u05dc\u05d5\u05d8 \u05d1\u05d7\u05d9\u05d9?\n\u05d4\u05ea\u05d7\u05d5\u05e9\u05d4 \u05d4\u05d6\u05d5 \u05d0\u05d9\u05e0\u05d4 \u05de\u05d9\u05d5\u05e2\u05d3\u05ea \u05dc\u05e9\u05dc\u05d5\u05d8 \u2013 \u05d0\u05dc\u05d0 \u05dc\u05dc\u05d5\u05d5\u05ea.\n\u05d4\u05d9\u05d0 \u05dc\u05d0 \u05e7\u05e8\u05d9\u05d0\u05d4 \u05dc\u05d4\u05d7\u05e0\u05e7\u05d4 \u05e9\u05dc \u05d4\u05e2\u05e6\u05de\u05d9, \u05d0\u05dc\u05d0 \u05dc\u05e9\u05d7\u05e8\u05d5\u05e8 \u05de\u05df \u05d4\u05d0\u05d2\u05d5.\n\u05d6\u05d4\u05d5 \u05de\u05e6\u05d1 \u05ea\u05d5\u05d3\u05e2\u05ea\u05d9 \u05e9\u05e0\u05db\u05d5\u05df \u05dc\u05e9\u05d5\u05d1 \u05d0\u05dc\u05d9\u05d5 \u05e8\u05d2\u05e2 \u05dc\u05e4\u05e0\u05d9 \u05e7\u05d1\u05dc\u05ea \u05ea\u05d5\u05e8\u05d4, \u05e8\u05d2\u05e2 \u05dc\u05e4\u05e0\u05d9 \u05d3\u05d9\u05d1\u05d5\u05e8 \u05d0\u05d5 \u05ea\u05d2\u05d5\u05d1\u05d4, \u05e8\u05d2\u05e2 \u05dc\u05e4\u05e0\u05d9 \u05e9\u05d9\u05e4\u05d5\u05d8 \u05d0\u05d5 \u05e8\u05d9\u05d1.\n\u05d0\u05da \u05d0\u05d9\u05df \u05d4\u05d9\u05d0 \u05dc\u05d1\u05d3\u05d4 \u2013 \u05d4\u05d9\u05d0 \u05d7\u05dc\u05e7 \u05de\u05de\u05db\u05dc\u05d5\u05dc:\n\u05d0\u05d7\u05e8\u05d9 \u05e9\u05e0\u05e4\u05e9\u05d9 \u05db\u05e2\u05e4\u05e8, \u05d0\u05e0\u05d9 \u05d0\u05d5\u05de\u05e8 \u05d1\u05ea\u05e4\u05d9\u05dc\u05d4: "\u05e4\u05ea\u05d7 \u05dc\u05d9\u05d1\u05d9 \u05d1\u05ea\u05d5\u05e8\u05ea\u05da" \u2013 \u05db\u05dc\u05d5\u05de\u05e8: \u05d3\u05d5\u05d5\u05e7\u05d0 \u05de\u05de\u05e7\u05d5\u05dd \u05d4\u05e2\u05e0\u05d5\u05d5\u05d4, \u05d4\u05dc\u05d1 \u05d9\u05db\u05d5\u05dc \u05dc\u05d4\u05d9\u05e4\u05ea\u05d7.\n\u05d5\u05db\u05e9\u05e0\u05e4\u05ea\u05d7 \u05d4\u05dc\u05d1 \u2013 \u05d2\u05dd \u05d4\u05d6\u05d4\u05d5\u05ea, \u05d4\u05e2\u05e9\u05d9\u05d9\u05d4 \u05d5\u05d4\u05d2\u05d1\u05d5\u05dc\u05d5\u05ea \u05d4\u05d0\u05d9\u05e9\u05d9\u05d9\u05dd \u05de\u05ea\u05d1\u05e8\u05e8\u05d9\u05dd \u05dc\u05d0 \u05db\u05d0\u05d2\u05d5 \u05d0\u05dc\u05d0 \u05db\u05e9\u05dc\u05d9\u05d7\u05d5\u05ea.\n\u05d7\u05d5\u05ea\u05de\u05ea:\n"\u05e0\u05e4\u05e9\u05d9 \u05db\u05e2\u05e4\u05e8 \u05dc\u05db\u05dc \u05ea\u05d4\u05d9\u05d4" \u2013 \u05dc\u05d0 \u05db\u05d3\u05d9 \u05dc\u05d4\u05d9\u05e2\u05dc\u05dd, \u05d0\u05dc\u05d0 \u05db\u05d3\u05d9 \u05dc\u05d4\u05d9\u05d5\u05ea \u05e7\u05e8\u05e7\u05e2 \u05e4\u05ea\u05d5\u05d7\u05d4 \u05dc\u05d0\u05d5\u05e8.\n\u05dc\u05d0 \u05db\u05d3\u05d9 \u05dc\u05d5\u05d5\u05ea\u05e8 \u05e2\u05dc \u05e2\u05e6\u05de\u05d9 \u2013 \u05d0\u05dc\u05d0 \u05db\u05d3\u05d9 \u05dc\u05d2\u05dc\u05d5\u05ea \u05d0\u05ea \u05d4\u05e2\u05e6\u05de\u05d9 \u05d4\u05e2\u05de\u05d5\u05e7, \u05d4\u05e2\u05e0\u05d9\u05d5, \u05d4\u05e9\u05d5\u05e8\u05e9\u05d9, \u05d4\u05e0\u05e6\u05d7\u05d9.\n\u05d1\u05d4\u05d7\u05dc\u05d8. \u05d4\u05e0\u05d4 \u05e1\u05d9\u05e4\u05d5\u05e8 \u05d7\u05e1\u05d9\u05d3\u05d9 \u05e9\u05e0\u05d5\u05d2\u05e2 \u05d1\u05e2\u05d5\u05de\u05e7 \u05d4\u05e8\u05e2\u05d9\u05d5\u05df \u05e9\u05dc "\u05e0\u05e4\u05e9\u05d9 \u05db\u05e2\u05e4\u05e8 \u05dc\u05db\u05dc \u05ea\u05d4\u05d9\u05d4" \u2013 \u05e2\u05e0\u05d5\u05d5\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05e9\u05dc\u05d0 \u05de\u05d1\u05d8\u05dc\u05ea \u05d0\u05ea \u05d4\u05d0\u05d3\u05dd, \u05d0\u05dc\u05d0 \u05d4\u05d5\u05e4\u05db\u05ea \u05d0\u05d5\u05ea\u05d5 \u05dc\u05db\u05dc\u05d9 \u05e9\u05dc \u05d4\u05e7\u05e9\u05d1\u05d4 \u05d5\u05e7\u05d9\u05e8\u05d1\u05d4 \u05d0\u05de\u05d9\u05ea\u05d9\u05ea:\n\ud83c\udf3e \u05e1\u05d9\u05e4\u05d5\u05e8 \u05d7\u05e1\u05d9\u05d3\u05d9: \u05d4\u05e8\u05d1\u05d9 \u05e9\u05d4\u05e9\u05e4\u05d9\u05dc \u05d0\u05ea \u05e2\u05e6\u05de\u05d5 \u2013 \u05d5\u05d3\u05d5\u05d5\u05e7\u05d0 \u05d0\u05d6 \u05d2\u05d9\u05dc\u05d4 \u05d0\u05ea \u05d4\u05e9\u05dd \u05d4\u05e7\u05d3\u05d5\u05e9\n\u05e1\u05d9\u05e4\u05e8\u05d5 \u05e2\u05dc \u05e8\u05d1\u05d9 \u05d6\u05d5\u05e9\u05d0 \u05de\u05d0\u05e0\u05d9\u05e4\u05d5\u05dc\u05d9, \u05d0\u05d7\u05d3 \u05de\u05ea\u05dc\u05de\u05d9\u05d3\u05d9\u05d5 \u05d4\u05d2\u05d3\u05d5\u05dc\u05d9\u05dd \u05e9\u05dc \u05d4\u05de\u05d2\u05d9\u05d3 \u05de\u05de\u05e2\u05d6\u05e8\u05d9\u05d8\u05e9, \u05e9\u05e4\u05e2\u05dd \u05d9\u05e6\u05d0 \u05e2\u05dd \u05d0\u05d7\u05d9\u05d5, \u05e8\u05d1\u05d9 \u05d0\u05dc\u05d9\u05de\u05dc\u05da, \u05dc\u05d2\u05dc\u05d5\u05ea \u2013 \u05dc\u05ea\u05e7\u05df \u05d0\u05ea \u05de\u05d9\u05d3\u05d5\u05ea\u05d9\u05d4\u05dd \u05d5\u05dc\u05d8\u05d4\u05e8 \u05d0\u05ea \u05dc\u05d9\u05d1\u05dd.\n\u05d4\u05dd \u05e0\u05d4\u05d2\u05d5 \u05dc\u05e0\u05d3\u05d5\u05d3 \u05de\u05e2\u05d9\u05e8 \u05dc\u05e2\u05d9\u05e8 \u05d1\u05dc\u05d9 \u05dc\u05d5\u05de\u05e8 \u05de\u05d9 \u05d4\u05dd, \u05dc\u05e2\u05d9\u05ea\u05d9\u05dd \u05d1\u05dc\u05d9 \u05db\u05e1\u05e3, \u05d1\u05dc\u05d9 \u05d0\u05d5\u05db\u05dc, \u05d5\u05d1\u05dc\u05d9 \u05e9\u05dd.\n\u05d1\u05d0\u05d7\u05ea \u05d4\u05e2\u05d9\u05d9\u05e8\u05d5\u05ea \u05e0\u05ea\u05e4\u05e1\u05d5 \u05db\u05e7\u05d1\u05e6\u05e0\u05d9\u05dd, \u05d5\u05d4\u05d5\u05e9\u05de\u05d5 \u05d1\u05d1\u05d9\u05ea \u05db\u05dc\u05d0 \u05e2\u05dd \u05e4\u05d5\u05e9\u05e2\u05d9\u05dd. \u05e8\u05d1\u05d9 \u05d6\u05d5\u05e9\u05d0, \u05e9\u05d4\u05d9\u05d4 \u05db\u05d5\u05dc\u05d5 \u05dc\u05d1 \u05e4\u05ea\u05d5\u05d7 \u05d5\u05ea\u05de\u05d9\u05de\u05d5\u05ea \u05e7\u05d3\u05d5\u05e9\u05d4, \u05d9\u05e9\u05d1 \u05d1\u05e4\u05d9\u05e0\u05d4 \u05d5\u05d1\u05db\u05d4 \u2013 \u05d0\u05d1\u05dc \u05dc\u05d0 \u05e2\u05dc \u05e2\u05d5\u05d5\u05dc \u05d4\u05d3\u05d9\u05df, \u05d0\u05dc\u05d0 \u05e2\u05dc \u05db\u05da \u05e9\u05dc\u05d0 \u05d9\u05d5\u05db\u05dc \u05dc\u05d4\u05ea\u05e4\u05dc\u05dc \u05dc\u05d9\u05d3 \u05d4\u05e1\u05d9\u05e8 \u05d4\u05de\u05d8\u05d5\u05e0\u05e3 \u05e9\u05d1\u05e4\u05d9\u05e0\u05d4, \u05db\u05d9\u05d5\u05d5\u05df \u05e9\u05d6\u05d4 \u05d0\u05e1\u05d5\u05e8 \u05dc\u05e4\u05d9 \u05d4\u05d4\u05dc\u05db\u05d4.\n\u05e8\u05d1\u05d9 \u05d0\u05dc\u05d9\u05de\u05dc\u05da \u05e0\u05d9\u05e1\u05d4 \u05dc\u05e0\u05d7\u05dd \u05d0\u05d5\u05ea\u05d5, \u05d0\u05da \u05e8\u05d1\u05d9 \u05d6\u05d5\u05e9\u05d0 \u05e8\u05e7 \u05d4\u05d6\u05db\u05d9\u05e8 \u05d0\u05ea \u05d0\u05d4\u05d1\u05ea\u05d5 \u05d4\u05d2\u05d3\u05d5\u05dc\u05d4 \u05dc\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d5\u05dc\u05e9\u05d9\u05d7 \u05e2\u05dd \u05d4\'.\n\u05d0\u05de\u05e8 \u05dc\u05d5 \u05e8\u05d1\u05d9 \u05d0\u05dc\u05d9\u05de\u05dc\u05da:\n"\u05d0\u05dd \u05e8\u05e6\u05d5\u05df \u05d4\' \u05d4\u05d5\u05d0 \u05e9\u05e2\u05db\u05e9\u05d9\u05d5 \u05ea\u05e2\u05d1\u05d5\u05d3 \u05d0\u05d5\u05ea\u05d5 \u05dc\u05d0 \u05d3\u05e8\u05da \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u2013 \u05d0\u05dc\u05d0 \u05d3\u05e8\u05da \u05e7\u05d1\u05dc\u05ea \u05d4\u05d3\u05d9\u05df \u05d1\u05d0\u05d4\u05d1\u05d4, \u05d3\u05e8\u05da \u05e2\u05e4\u05e8 \u05e9\u05de\u05e7\u05d1\u05dc \u05d0\u05ea \u05d4\u05db\u05dc \u2013 \u05d4\u05d0\u05dd \u05d0\u05d9\u05df \u05d6\u05d5 \u05d2\u05dd \u05e2\u05d1\u05d5\u05d3\u05ea \u05d4\'?"\n\u05e8\u05d1\u05d9 \u05d6\u05d5\u05e9\u05d0 \u05e9\u05de\u05e2, \u05d5\u05d7\u05d9\u05d5\u05da \u05d4\u05d7\u05dc \u05dc\u05e2\u05dc\u05d5\u05ea \u05e2\u05dc \u05e4\u05e0\u05d9\u05d5.\n\u05d4\u05d5\u05d0 \u05e7\u05dd \u05d5\u05e8\u05e7\u05d3 \u05d1\u05e9\u05de\u05d7\u05d4 \u2013 "\u05d0\u05e9\u05e8\u05d9 \u05dc\u05d9 \u05e9\u05d6\u05db\u05d9\u05ea\u05d9 \u05dc\u05e2\u05e9\u05d5\u05ea \u05e8\u05e6\u05d5\u05df \u05e7\u05d5\u05e0\u05d9 \u05d2\u05dd \u05db\u05e9\u05d0\u05e0\u05d9 \u05e2\u05e4\u05e8, \u05d2\u05dd \u05db\u05e9\u05d0\u05e0\u05d9 \u05dc\u05d0 \u05de\u05ea\u05e4\u05dc\u05dc \u2013 \u05d0\u05dc\u05d0 \u05e4\u05e9\u05d5\u05d8 \u05de\u05e7\u05d1\u05dc."\n\u05d5\u05d1\u05e8\u05d2\u05e2 \u05d6\u05d4 \u2013 \u05d4\u05ea\u05e4\u05e9\u05d8\u05d4 \u05e9\u05de\u05d7\u05d4 \u05de\u05d5\u05d6\u05e8\u05d4 \u05d1\u05db\u05dc \u05d4\u05ea\u05d0. \u05d2\u05dd \u05d4\u05e4\u05d5\u05e9\u05e2\u05d9\u05dd \u05d4\u05e6\u05d8\u05e8\u05e4\u05d5 \u05dc\u05e8\u05d9\u05e7\u05d5\u05d3.\n\u05d4\u05e9\u05d5\u05de\u05e8, \u05e9\u05e8\u05d0\u05d4 \u05d0\u05d5\u05ea\u05dd \u05e9\u05de\u05d7\u05d9\u05dd, \u05e0\u05d1\u05d4\u05dc \u05de\u05d4\u05e9\u05e4\u05e2\u05ea\u05dd \u2013 \u05d5\u05d4\u05d5\u05e6\u05d9\u05d0 \u05d0\u05ea \u05d4\u05e1\u05d9\u05e8 \u05de\u05d4\u05ea\u05d0.\n\u05d5\u05db\u05da \u2013 \u05d3\u05d5\u05d5\u05e7\u05d0 \u05de\u05ea\u05d5\u05da \u05d4\u05d4\u05e1\u05db\u05de\u05d4 \u05dc\u05d4\u05d9\u05d5\u05ea \u05e2\u05e4\u05e8, \u05de\u05ea\u05d5\u05da \u05d4\u05e2\u05e0\u05d5\u05d5\u05d4 \u05dc\u05e7\u05d1\u05dc \u05d0\u05ea \u05e8\u05e6\u05d5\u05df \u05d4\' \u05d2\u05dd \u05db\u05e9\u05d0\u05d9\u05e0\u05d5 \u05de\u05d5\u05d1\u05df \u2013\n\u05e0\u05e4\u05ea\u05d7\u05d4 \u05d4\u05d3\u05dc\u05ea \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05d5\u05d4\u05d7\u05d9\u05e6\u05d5\u05e0\u05d9\u05ea \u05db\u05d0\u05d7\u05ea.\n\u05d4\u05e2\u05e0\u05d5\u05d5\u05d4 \u05e9\u05dc "\u05e0\u05e4\u05e9\u05d9 \u05db\u05e2\u05e4\u05e8" \u05d0\u05d9\u05e0\u05e0\u05d4 \u05d5\u05d9\u05ea\u05d5\u05e8 \u05e2\u05dc \u05d4\u05db\u05d5\u05d7, \u05d0\u05dc\u05d0 \u05de\u05e7\u05d5\u05e8 \u05dc\u05db\u05d5\u05d7 \u05d0\u05d7\u05e8 \u2013 \u05e2\u05de\u05d5\u05e7, \u05e9\u05e7\u05d8, \u05de\u05d4\u05e4\u05da.\n\u05d4\u05d9\u05d0 \u05de\u05d0\u05e4\u05e9\u05e8\u05ea \u05e0\u05d5\u05db\u05d7\u05d5\u05ea \u05de\u05dc\u05d0\u05d4 \u05d2\u05dd \u05db\u05e9\u05d4\u05db\u05dc \u05e0\u05dc\u05e7\u05d7 \u05d5\u05d1\u05d3\u05d9\u05d5\u05e7 \u05db\u05da \u05d4\u05e4\u05dc\u05d0 \u05e0\u05d5\u05dc\u05d3.\n\ud83c\udf31 \u05ea\u05e8\u05d2\u05d9\u05dc \u05d4\u05d8\u05de\u05e2\u05d4: \u05dc\u05d4\u05d9\u05d5\u05ea \u05e2\u05e4\u05e8 \u2013 \u05de\u05e8\u05d7\u05d1 \u05e9\u05dc \u05d4\u05e7\u05e9\u05d1\u05d4, \u05e4\u05ea\u05d9\u05d7\u05d4 \u05d5\u05d4\u05db\u05dc\u05d4',"\u05de\u05d8\u05e8\u05ea \u05d4\u05ea\u05e8\u05d2\u05d9\u05dc:",'\u05dc\u05ea\u05e8\u05d2\u05dc \u05ea\u05d5\u05d3\u05e2\u05ea \u05e2\u05e0\u05d5\u05d5\u05d4, \u05d4\u05e7\u05e9\u05d1\u05d4, \u05d5\u05e0\u05db\u05d5\u05e0\u05d5\u05ea \u05dc\u05d4\u05e8\u05e4\u05d5\u05ea \u05de\u05d0\u05d2\u05d5 \u2013 \u05de\u05d1\u05dc\u05d9 \u05dc\u05d5\u05d5\u05ea\u05e8 \u05e2\u05dc \u05e2\u05e8\u05da \u05e2\u05e6\u05de\u05d9. \u05dc\u05d7\u05d5\u05d5\u05ea \u05d0\u05ea \u05d4\u05ea\u05d7\u05d5\u05e9\u05d4 \u05e9\u05dc \u05d4\u05d9\u05d5\u05ea "\u05e2\u05e4\u05e8" \u05db\u05e7\u05e8\u05e7\u05e2 \u05d1\u05d8\u05d5\u05d7\u05d4 \u05d5\u05dc\u05d0 \u05db\u05e7\u05e8\u05d1\u05df.\n\u05e9\u05dc\u05d1 1: \u05d4\u05db\u05e0\u05d4\n\u05de\u05e6\u05d0\u05d9 \u05de\u05e7\u05d5\u05dd \u05e9\u05e7\u05d8.\n\u05e9\u05d1\u05d9 \u05d0\u05d5 \u05e9\u05db\u05d1\u05d9 \u05d1\u05e0\u05d9\u05e0\u05d5\u05d7\u05d5\u05ea, \u05e2\u05e6\u05de/\u05d9 \u05e2\u05d9\u05e0\u05d9\u05d9\u05dd, \u05d5\u05d4\u05ea\u05de\u05e7\u05d3/\u05d9 \u05d1\u05e0\u05e9\u05d9\u05de\u05d4.\n\u05d4\u05e8\u05d2\u05d9\u05e9\u05d9 \u05db\u05d9\u05e6\u05d3 \u05db\u05dc \u05e0\u05e9\u05d9\u05e4\u05d4 \u05de\u05e7\u05e8\u05e7\u05e2\u05ea \u05d0\u05d5\u05ea\u05da \u2013 \u05db\u05d0\u05d9\u05dc\u05d5 \u05d0\u05ea \u05e0\u05de\u05e1\u05d4 \u05d0\u05dc \u05ea\u05d5\u05da \u05d4\u05d0\u05d3\u05de\u05d4, \u05db\u05de\u05d5 \u05d7\u05d5\u05dc \u05e0\u05d9\u05e0\u05d5\u05d7.\n\u05e9\u05dc\u05d1 2: \u05d3\u05de\u05d9\u05d5\u05df \u05de\u05d5\u05d3\u05e8\u05da\n\u05d3\u05de\u05d9\u05d9\u05e0\u05d9 \u05e9\u05d0\u05ea \u05e2\u05e4\u05e8 \u05e9\u05e7\u05d8 \u05d5\u05e0\u05e2\u05d9\u05dd.\n\u05d0\u05d9\u05df \u05dc\u05da \u05e6\u05d5\u05e8\u05da \u05dc\u05d4\u05d5\u05db\u05d9\u05d7, \u05dc\u05d4\u05d9\u05dc\u05d7\u05dd, \u05d0\u05d5 \u05dc\u05d4\u05ea\u05d2\u05d5\u05e0\u05df.\n\u05d0\u05ea \u05e4\u05e9\u05d5\u05d8 \u05e0\u05de\u05e6\u05d0\u05ea. \u05db\u05dc \u05de\u05d4 \u05e9\u05d1\u05d0 \u2013 \u05de\u05d5\u05ea\u05e8 \u05dc\u05d5 \u05dc\u05d4\u05d9\u05d5\u05ea.\n\u05de\u05d9\u05e9\u05d4\u05d5 \u05d3\u05d5\u05e8\u05da? \u05de\u05d9\u05e9\u05d4\u05d5 \u05e0\u05d5\u05e4\u05dc? \u05de\u05d9\u05e9\u05d4\u05d5 \u05d6\u05d5\u05e8\u05e2?\n\u05d0\u05ea \u05dc\u05d0 \u05e0\u05e2\u05dc\u05d1\u05ea \u2013 \u05d0\u05ea \u05de\u05d0\u05e4\u05e9\u05e8\u05ea.\n\u05d7\u05d6\u05e8\u05d9 \u05d1\u05dc\u05d1\u05da, \u05d1\u05e9\u05e7\u05d8:\n"\u05e0\u05e4\u05e9\u05d9 \u05db\u05e2\u05e4\u05e8 \u05dc\u05db\u05dc \u05ea\u05d4\u05d9\u05d4 \u2013 \u05db\u05d3\u05d9 \u05e9\u05ea\u05e4\u05ea\u05d7 \u05dc\u05d9\u05d1\u05d9 \u05d1\u05ea\u05d5\u05e8\u05ea\u05da" - \u05ea\u05df \u05dc\u05d9 \u05ea\u05d5\u05e8\u05d4 \u05d7\u05d3\u05e9\u05d4 , \u05ea\u05d5\u05d1\u05e0\u05d4 \u05d7\u05d3\u05e9\u05d4.\n\u05d4\u05e8\u05d2\u05d9\u05e9\u05d9 \u05d0\u05d9\u05da \u05d3\u05d5\u05d5\u05e7\u05d0 \u05de\u05d4\u05e9\u05e7\u05d8 \u05d5\u05d4\u05d4\u05db\u05dc\u05d4 \u2013 \u05e2\u05d5\u05dc\u05d4 \u05db\u05d5\u05d7 \u05e4\u05e0\u05d9\u05de\u05d9 \u05e2\u05d3\u05d9\u05df, \u05d0\u05da \u05d0\u05d9\u05ea\u05df.\n\u05d4\u05e7\u05e9\u05d9\u05d1\u05d9 \u05de\u05d4 \u05e8\u05d5\u05e6\u05d4 \u05dc\u05d4\u05d9\u05d5\u05d5\u05dc\u05d3 \u05d1\u05da \u05db\u05e9\u05d0\u05ea \u05e9\u05d5\u05db\u05d7\u05ea \u05d0\u05ea \u05d4\u05e6\u05d5\u05e8\u05da \u05dc\u05e9\u05dc\u05d5\u05d8 \u05d0\u05d5 \u05dc\u05d4\u05e6\u05d8\u05d3\u05e7.\n\u05e9\u05dc\u05d1 3: \u05db\u05ea\u05d9\u05d1\u05d4 \u05d0\u05d5 \u05e9\u05d9\u05ea\u05d5\u05e3 (\u05d0\u05d5\u05e4\u05e6\u05d9\u05d5\u05e0\u05dc\u05d9)\n\u05db\u05ea\u05d1\u05d9 \u05ea\u05e9\u05d5\u05d1\u05d4 \u05dc\u05e9\u05d0\u05dc\u05d4:\n\ud83c\udf3e \u05de\u05d4 \u05d0\u05e0\u05d9 \u05de\u05e1\u05d5\u05d2\u05dc\u05ea \u05dc\u05e9\u05de\u05d5\u05e2 \u05d0\u05d5 \u05dc\u05d4\u05db\u05d9\u05dc \u05db\u05e9\u05d0\u05e0\u05d9 "\u05db\u05e2\u05e4\u05e8" \u05e9\u05dc\u05d0 \u05d9\u05db\u05d5\u05dc\u05ea\u05d9 \u05dc\u05e9\u05de\u05d5\u05e2 \u05e7\u05d5\u05d3\u05dd?\n\u05d0\u05d5:\n\ud83c\udf3e \u05d0\u05d9\u05d6\u05d4 \u05db\u05d0\u05d1 \u05d0\u05d5 \u05d1\u05d9\u05e7\u05d5\u05e8\u05ea \u05e0\u05e8\u05d0\u05d9\u05dd \u05dc\u05d9 \u05d0\u05d7\u05e8\u05ea \u05db\u05e9\u05d0\u05e0\u05d9 \u05d1\u05d0\u05d4 \u05de\u05e2\u05de\u05d3\u05d4 \u05e9\u05dc \u05e2\u05e4\u05e8 \u05d5\u05dc\u05d0 \u05e9\u05dc \u05d0\u05d2\u05d5?\n\u05d0\u05e4\u05e9\u05e8 \u05d2\u05dd \u05dc\u05e9\u05ea\u05e3 \u05d0\u05d3\u05dd \u05e7\u05e8\u05d5\u05d1 \u05de\u05de\u05e7\u05d5\u05dd \u05d7\u05d3\u05e9 \u05d6\u05d4, \u05d0\u05d5 \u05dc\u05ea\u05e8\u05d2\u05dc \u05d4\u05e7\u05e9\u05d1\u05d4 \u05de\u05dc\u05d0\u05d4 \u05de\u05d1\u05dc\u05d9 \u05dc\u05d4\u05d2\u05d9\u05d1.\n\u05e9\u05dc\u05d1 4: \u05d7\u05d6\u05e8\u05d4 \u05dc\u05d7\u05d9\u05d9\u05dd\n\u05e7\u05d7\u05d9 \u05d0\u05d9\u05ea\u05da \u05d0\u05ea \u05d4\u05ea\u05d7\u05d5\u05e9\u05d4 \u05d4\u05d6\u05d5 \u05dc\u05d9\u05d5\u05dd \u05d9\u05d5\u05dd.\n\u05d0\u05d9\u05e0\u05da \u05e6\u05e8\u05d9\u05db\u05d4 \u05dc\u05d4\u05d9\u05d5\u05ea \u05e2\u05e4\u05e8 \u05de\u05d5\u05dc \u05db\u05dc \u05d0\u05d3\u05dd \u05d0\u05d5 \u05d1\u05db\u05dc \u05de\u05e6\u05d1.\n\u05d0\u05d1\u05dc \u05db\u05e9\u05d0\u05ea \u05d1\u05d5\u05d7\u05e8\u05ea \u05d1\u05d6\u05d4 \u05d0\u05ea \u05d4\u05d5\u05e4\u05db\u05ea \u05dc\u05e7\u05e8\u05e7\u05e2 \u05e9\u05de\u05e6\u05de\u05d9\u05d7\u05d4 \u05d7\u05d9\u05d9\u05dd.\n\u05de\u05d3\u05d9 \u05e4\u05e2\u05dd \u05d7\u05d6\u05e8\u05d9 \u05dc\u05de\u05e9\u05e4\u05d8 \u05d1\u05dc\u05d1 \u05dc\u05d0 \u05db\u05d3\u05d9 \u05dc\u05de\u05d7\u05d5\u05e7 \u05d0\u05ea \u05e2\u05e6\u05de\u05da, \u05d0\u05dc\u05d0 \u05db\u05d3\u05d9 \u05dc\u05d6\u05db\u05d5\u05e8 \u05d0\u05ea \u05d4\u05de\u05e7\u05d5\u05e8 \u05e9\u05dc\u05da.\n\u05e2\u05e4\u05e8 \u05e9\u05de\u05db\u05d9\u05dc \u05e0\u05e9\u05de\u05d4.\n-------------------------------------------------\n\u05d0\u05d9\u05df \u05db\u05d0\u05dc\u05d5\u05e7\u05d9\u05e0\u05d5 \u2013 \u05e2\u05dc \u05d4\u05d2\u05d9\u05e9\u05d4 \u05e9\u05dc\u05e0\u05d5 \u05dc\u05d0\u05dc\u05d5\u05e7\u05d9\u05dd \u05d5\u05e2\u05dc \u05d4\u05d3\u05d9\u05e1\u05d0\u05d5\u05e0\u05e0\u05e1 \u05e9\u05d1\u05d0\u05de\u05d5\u05e0\u05d4 \u05d5\u05ea\u05e4\u05d9\u05dc\u05d4\n\u05f4\u05d0\u05d9\u05df \u05db\u05d0\u05dc\u05d5\u05e7\u05d9\u05e0\u05d5, \u05d0\u05d9\u05df \u05db\u05d0\u05d3\u05d5\u05e0\u05e0\u05d5, \u05d0\u05d9\u05df \u05db\u05de\u05dc\u05db\u05e0\u05d5, \u05d0\u05d9\u05df \u05db\u05de\u05d5\u05e9\u05d9\u05e2\u05e0\u05d5\u05f4 \u2013\n\u05e4\u05d9\u05d5\u05d8 \u05e9\u05d8\u05d5\u05de\u05df \u05d1\u05ea\u05d5\u05db\u05d5 \u05de\u05d4\u05e4\u05db\u05d4 \u05e9\u05e7\u05d8\u05d4 \u05d1\u05d9\u05d7\u05e1 \u05e9\u05dc\u05e0\u05d5 \u05dc\u05d0\u05dc\u05d5\u05e7\u05d9\u05dd.\n\u05e8\u05d1\u05d9\u05dd \u05d7\u05d9\u05d9\u05dd \u05d1\u05d3\u05d9\u05e1\u05d0\u05d5\u05e0\u05e0\u05e1 \u05e4\u05e0\u05d9\u05de\u05d9:\n\u05de\u05e6\u05d3 \u05d0\u05d7\u05d3 \u2013 \u05e8\u05e6\u05d5\u05df \u05dc\u05d4\u05ea\u05e4\u05dc\u05dc, \u05dc\u05d1\u05e7\u05e9, \u05dc\u05d4\u05d9\u05d0\u05d7\u05d6 \u05d1\u05de\u05e9\u05d4\u05d5 \u05d2\u05d3\u05d5\u05dc \u05de\u05d0\u05d9\u05ea\u05e0\u05d5.\n\u05d5\u05de\u05e6\u05d3 \u05e9\u05e0\u05d9 \u2013 \u05e1\u05e4\u05e7:\n\u05d4\u05d0\u05dd \u05d0\u05e0\u05d9 \u05d1\u05d0\u05de\u05ea \u05de\u05d0\u05de\u05d9\u05df? \u05d5\u05d0\u05dd \u05db\u05df \u2013 \u05d1\u05de\u05d4 \u05d0\u05e0\u05d9 \u05de\u05d0\u05de\u05d9\u05df?\n\u05d1\u05db\u05d5\u05d7 \u05e2\u05dc\u05d9\u05d5\u05df \u05e9\u05de\u05e0\u05d4\u05dc \u05de\u05e6\u05d9\u05d0\u05d5\u05ea?\n\u05d1\u05d0\u05dc \u05e8\u05d7\u05d5\u05e7?\n\u05d1\u05d0\u05dc \u05e7\u05e8\u05d5\u05d1?\n\u05d0\u05d5 \u05d0\u05d5\u05dc\u05d9 \u05d1\u05e8\u05e2\u05d9\u05d5\u05df \u05de\u05d5\u05e4\u05e9\u05d8 \u05e9\u05d0\u05d9\u05df \u05dc\u05d5 \u05e0\u05d5\u05db\u05d7\u05d5\u05ea \u05de\u05de\u05e9\u05d9\u05ea \u05d1\u05d7\u05d9\u05d9 \u05d4\u05d9\u05d5\u05dd\u05be\u05d9\u05d5\u05dd?\n\u05d4\u05d3\u05d9\u05e1\u05d0\u05d5\u05e0\u05e0\u05e1 \u05d4\u05d6\u05d4 \u05d9\u05d5\u05e6\u05e8 \u05e9\u05d0\u05dc\u05d4 \u05e2\u05de\u05d5\u05e7\u05d4 \u05e2\u05d5\u05d3 \u05d9\u05d5\u05ea\u05e8:\n\u05d4\u05d0\u05dd \u05ea\u05e4\u05d9\u05dc\u05d4 \u05d1\u05d0\u05de\u05ea \u05de\u05e9\u05e0\u05d4 \u05de\u05e9\u05d4\u05d5?\n\u05d4\u05d0\u05dd \u05d4\u05d9\u05d0 \u05de\u05e9\u05e0\u05d4 \u05d0\u05ea \u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea \u2013 \u05d0\u05d5 \u05e8\u05e7 \u05de\u05e8\u05d2\u05d9\u05e2\u05d4 \u05d0\u05d5\u05ea\u05d9?\n\u05e9\u05de\u05d5\u05ea \u2013 \u05d5\u05d2\u05d9\u05e9\u05d5\u05ea\n\u05d4\u05d9\u05d4\u05d3\u05d5\u05ea \u05d0\u05d9\u05e0\u05d4 \u05de\u05e1\u05ea\u05e4\u05e7\u05ea \u05d1\u05e9\u05dd \u05d0\u05d7\u05d3 \u05dc\u05d0\u05dc\u05d5\u05e7\u05d9\u05dd.\n\u05db\u05dc \u05e9\u05dd \u05e4\u05d5\u05ea\u05d7 \u05e9\u05e2\u05e8 \u05d0\u05d7\u05e8 \u05e9\u05dc \u05d9\u05d7\u05e1:\n\u05d0\u05dc\u05d5\u05e7\u05d9\u05dd \u2013 \u05e9\u05dd \u05e9\u05dc \u05d7\u05d5\u05e7, \u05e1\u05d3\u05e8, \u05d8\u05d1\u05e2, \u05d2\u05d1\u05d5\u05dc\u05d5\u05ea.\n\u05db\u05d5\u05d7 \u05e9\u05e4\u05d5\u05e2\u05dc \u05d1\u05ea\u05d5\u05da \u05d7\u05d5\u05e7\u05d9\u05d5\u05ea \u05d1\u05e8\u05d5\u05e8\u05d4, \u05e1\u05d9\u05d1\u05d4 \u05d5\u05ea\u05d5\u05e6\u05d0\u05d4.\n\u05d9\u05d4\u05d5\u05d4 \u2013 \u05e9\u05dd \u05d4\u05d4\u05d5\u05d5\u05d9\u05d4, \u05d4\u05d0\u05d9\u05e0\u05e1\u05d5\u05e4\u05d9\u05d5\u05ea.\n\u05de\u05d4 \u05e9\u05de\u05e2\u05d1\u05e8 \u05dc\u05d8\u05d1\u05e2, \u05dc\u05d6\u05de\u05df, \u05dc\u05d4\u05d2\u05d3\u05e8\u05d4.\n\u05dc\u05d0 \u201c\u05de\u05e9\u05d4\u05d5\u201d \u05d0\u05dc\u05d0 \u05d4\u05d5\u05d5\u05d9\u05d4 \u05de\u05ea\u05de\u05d3\u05ea.\n\u05d0\u05d3\u05d5\u05e0\u05d9 \u2013 \u05d0\u05d3\u05d5\u05df \u05db\u05dc \u05d4\u05d0\u05e8\u05e5.\n\u05dc\u05d0 \u05db\u05d5\u05d7 \u05de\u05d5\u05e4\u05e9\u05d8 \u05d0\u05dc\u05d0 \u05d4\u05e0\u05d4\u05d2\u05d4, \u05e7\u05e9\u05e8, \u05d9\u05d7\u05e1 \u05e9\u05dc \u05de\u05e9\u05de\u05e2\u05d5\u05ea \u05d5\u05d0\u05d7\u05e8\u05d9\u05d5\u05ea.\n\u05db\u05e9\u05d4\u05d0\u05d3\u05dd \u05e9\u05d5\u05d0\u05dc \u201c\u05d4\u05d0\u05dd \u05d0\u05e0\u05d9 \u05de\u05d0\u05de\u05d9\u05df?\u201d \u2013\n\u05dc\u05e2\u05d9\u05ea\u05d9\u05dd \u05d4\u05e9\u05d0\u05dc\u05d4 \u05d4\u05d0\u05de\u05d9\u05ea\u05d9\u05ea \u05d4\u05d9\u05d0: \u05dc\u05d0\u05d9\u05d6\u05d4 \u05e9\u05dd \u05d0\u05e0\u05d9 \u05de\u05d5\u05db\u05df \u05dc\u05e4\u05e0\u05d5\u05ea?\n\u05dc\u05d0\u05d9\u05d6\u05d4 \u05e1\u05d5\u05d2 \u05e9\u05dc \u05e7\u05e9\u05e8?\n\u05d4\u05d1\u05e2\u05d9\u05d4 \u05d4\u05e8\u05d0\u05e9\u05d5\u05e0\u05d4: \u05d0\u05de\u05d5\u05e0\u05d4 \u05db\u05ea\u05e0\u05d0\u05d9\n\u05e8\u05d1\u05d9\u05dd \u05de\u05e8\u05d2\u05d9\u05e9\u05d9\u05dd \u05e9\u05d4\u05dd \u201c\u05dc\u05d0 \u05de\u05e1\u05e4\u05d9\u05e7 \u05de\u05d0\u05de\u05d9\u05e0\u05d9\u05dd\u201d \u05d5\u05dc\u05db\u05df \u05d0\u05d9\u05e0\u05dd \u05e8\u05d0\u05d5\u05d9\u05d9\u05dd \u05dc\u05d4\u05ea\u05e4\u05dc\u05dc.\n\u05d0\u05da \u05d4\u05d9\u05d4\u05d3\u05d5\u05ea \u05de\u05e6\u05d9\u05e2\u05d4 \u05d4\u05d9\u05e4\u05d5\u05da:\n\u05dc\u05d0 \u05de\u05ea\u05e4\u05dc\u05dc\u05d9\u05dd \u05db\u05d9 \u05de\u05d0\u05de\u05d9\u05e0\u05d9\u05dd \u2013\n\u05d0\u05dc\u05d0 \u05de\u05d0\u05de\u05d9\u05e0\u05d9\u05dd \u05d3\u05e8\u05da \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4.\n\u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d0\u05d9\u05e0\u05e0\u05d4 \u05de\u05d1\u05d7\u05df \u05d0\u05de\u05d5\u05e0\u05d4 \u05d0\u05dc\u05d0 \u05de\u05e8\u05d7\u05d1 \u05e9\u05dc \u05d7\u05e7\u05d9\u05e8\u05d4.\n\u05d2\u05dd \u05e1\u05e4\u05e7, \u05d1\u05dc\u05d1\u05d5\u05dc, \u05db\u05e2\u05e1 \u05d5\u05e8\u05d9\u05d7\u05d5\u05e7 \u2013 \u05d4\u05dd \u05d7\u05d5\u05de\u05e8\u05d9 \u05d2\u05dc\u05dd \u05dc\u05ea\u05e4\u05d9\u05dc\u05d4.\n\u05d4\u05d1\u05e2\u05d9\u05d4 \u05d4\u05e9\u05e0\u05d9\u05d9\u05d4: \u05ea\u05e4\u05d9\u05dc\u05d4 \u05db\u05e2\u05d9\u05e1\u05e7\u05d4\n\u05d4\u05e9\u05d0\u05dc\u05d4:\n\u201c\u05d0\u05dd \u05d0\u05ea\u05e4\u05dc\u05dc \u2013 \u05d4\u05d0\u05dd \u05d7\u05d9\u05d9 \u05d1\u05d4\u05db\u05e8\u05d7 \u05d9\u05e9\u05ea\u05e0\u05d5 \u05dc\u05d8\u05d5\u05d1\u05d4?\u201d\n\u05de\u05e1\u05ea\u05d9\u05e8\u05d4 \u05d4\u05e0\u05d7\u05d4 \u05e1\u05de\u05d5\u05d9\u05d4:\n\u05e9\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d4\u05d9\u05d0 \u05db\u05dc\u05d9 \u05dc\u05e9\u05dc\u05d9\u05d8\u05d4 \u05d1\u05de\u05e6\u05d9\u05d0\u05d5\u05ea.\n\u05d0\u05da \u05e2\u05dc \u05e4\u05d9 \u05d4\u05d7\u05e1\u05d9\u05d3\u05d5\u05ea, \u05e2\u05d5\u05de\u05e7 \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d0\u05d9\u05e0\u05d5 \u05e9\u05d9\u05e0\u05d5\u05d9 \u05d4\u05e2\u05d5\u05dc\u05dd \u2013\n\u05d0\u05dc\u05d0 \u05e9\u05d9\u05e0\u05d5\u05d9 \u05e0\u05e7\u05d5\u05d3\u05ea \u05d4\u05de\u05d1\u05d8 \u05e9\u05de\u05de\u05e0\u05d4 \u05d0\u05e0\u05d9 \u05e4\u05d5\u05d2\u05e9 \u05d0\u05ea \u05d4\u05e2\u05d5\u05dc\u05dd.\n\u05db\u05d0\u05e9\u05e8 \u05d4\u05d0\u05d3\u05dd \u05de\u05ea\u05e4\u05dc\u05dc, \u05d4\u05d5\u05d0 \u05d0\u05d9\u05e0\u05d5 \u201c\u05de\u05e9\u05db\u05e0\u05e2\u201d \u05d0\u05ea \u05d0\u05dc\u05d5\u05e7\u05d9\u05dd \u05dc\u05d4\u05e9\u05ea\u05e0\u05d5\u05ea,\n\u05d0\u05dc\u05d0 \u05de\u05d0\u05e4\u05e9\u05e8 \u05dc\u05e2\u05e6\u05de\u05d5 \u05dc\u05d6\u05d5\u05d6 \u05de\u05de\u05e7\u05d5\u05dd \u05e1\u05d2\u05d5\u05e8 \u05dc\u05de\u05e7\u05d5\u05dd \u05e4\u05ea\u05d5\u05d7,\n\u05de\u05e2\u05de\u05d3\u05ea \u05e7\u05d5\u05e8\u05d1\u05df \u05dc\u05e2\u05de\u05d3\u05ea \u05e9\u05d5\u05ea\u05e4\u05d5\u05ea.\n\u05d0\u05d9\u05df \u05db\u05d0\u05dc\u05d5\u05e7\u05d9\u05e0\u05d5 \u2013 \u05d0\u05d9\u05df \u05d3\u05d5\u05de\u05d4 \u05dc\u05d5\n\u05d4\u05e4\u05d9\u05d5\u05d8 \u05d0\u05d9\u05e0\u05d5 \u05d1\u05d0 \u05dc\u05d4\u05d5\u05db\u05d9\u05d7 \u05e9\u05d9\u05e9 \u05d0\u05dc\u05d5\u05e7\u05d9\u05dd,\n\u05d0\u05dc\u05d0 \u05dc\u05e9\u05d7\u05e8\u05e8 \u05d0\u05d5\u05ea\u05e0\u05d5 \u05de\u05d4\u05d3\u05d9\u05de\u05d5\u05d9\u05d9\u05dd \u05d4\u05de\u05e6\u05de\u05e6\u05de\u05d9\u05dd \u05e9\u05dc\u05e0\u05d5 \u05e2\u05dc\u05d9\u05d5 \u05d0\u05d5 \u05dc\u05e4\u05ea\u05d5\u05d7 \u05dc\u05e0\u05d5 \u05e2\u05e8\u05d5\u05e6\u05d9\u05dd \u05e0\u05d5\u05e1\u05e4\u05d9\u05dd \u05dc\u05d4\u05ea\u05d1\u05d5\u05e0\u05df \u05d1\u05e7\u05e9\u05e8 \u05d0\u05d9\u05ea\u05d5.')
B.L0=new A.cv(21,"\u05d0\u05d9\u05df \u05db\u05d0\u05dc\u05d5\u05e7\u05d9\u05e0\u05d5: \u05db\u05de\u05d9\u05d4\u05d4 \u05e7\u05d9\u05d5\u05de\u05d9\u05ea \u05d5\u05d0\u05de\u05d5\u05df",'\u05d0\u05d9\u05df \u05db\u05d0\u05dc\u05d5\u05e7\u05d9\u05e0\u05d5 \u2013 \u05db\u05dc\u05d5\u05de\u05e8:\n\u05d4\u05d5\u05d0 \u05d0\u05d9\u05e0\u05d5 \u05d4\u05d3\u05de\u05d5\u05ea \u05e9\u05e6\u05d9\u05d9\u05e8\u05ea\u05d9.\n\u05d0\u05d9\u05e0\u05d5 \u05d4\u05de\u05e0\u05d2\u05e0\u05d5\u05df \u05e9\u05d0\u05de\u05d5\u05e8 \u201c\u05dc\u05e1\u05d3\u05e8 \u05dc\u05d9\u201d \u05d0\u05ea \u05d4\u05d7\u05d9\u05d9\u05dd.\n\u05d5\u05d0\u05d9\u05e0\u05d5 \u05d2\u05dd \u05d4\u05e8\u05e2\u05d9\u05d5\u05df \u05d4\u05e4\u05d9\u05dc\u05d5\u05e1\u05d5\u05e4\u05d9 \u05d4\u05e7\u05e8 \u05d5\u05d4\u05de\u05e0\u05d5\u05db\u05e8.\n\u05d4\u05ea\u05e4\u05d9\u05dc\u05d4, \u05d0\u05dd \u05db\u05df, \u05d0\u05d9\u05e0\u05e0\u05d4 \u05e4\u05e2\u05d5\u05dc\u05d4 \u05d8\u05db\u05e0\u05d9\u05ea,\n\u05d0\u05dc\u05d0 \u05ea\u05e0\u05d5\u05e2\u05d4 \u05e0\u05e4\u05e9\u05d9\u05ea \u05e9\u05dc \u05d4\u05e1\u05db\u05de\u05d4 \u05dc\u05e4\u05d2\u05d5\u05e9 \u05d0\u05ea \u05d4\u05d7\u05d9\u05d9\u05dd \u05dc\u05d0 \u05dc\u05d1\u05d3.\n\u05dc\u05d0 \u05ea\u05de\u05d9\u05d3 \u05de\u05ea\u05d5\u05da \u05d0\u05de\u05d5\u05e0\u05d4 \u05d1\u05e8\u05d5\u05e8\u05d4.\n\u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05d3\u05d5\u05d5\u05e7\u05d0 \u05de\u05ea\u05d5\u05da \u05e9\u05d0\u05dc\u05d4 \u05e4\u05ea\u05d5\u05d7\u05d4.\n\u05d5\u05d0\u05d5\u05dc\u05d9 \u05e9\u05dd \u2013\n\u05d1\u05d9\u05df \u05d4\u05e1\u05e4\u05e7 \u05dc\u05d1\u05e7\u05e9\u05d4,\n\u05d1\u05d9\u05df \u05d0\u05dc\u05d5\u05e7\u05d9\u05dd \u05dc\u05d0\u05d3\u05d5\u05e0\u05d9,\n\u05de\u05ea\u05d7\u05d9\u05dc\u05d4 \u05ea\u05e0\u05d5\u05e2\u05d4 \u05e7\u05d8\u05e0\u05d4 \u05e9\u05dc \u05e9\u05d9\u05e0\u05d5\u05d9.\n\u05d4\u05d0\u05dd \u05d4\u05e1\u05d9\u05d1\u05d4 \u05d4\u05d9\u05d7\u05d9\u05d3\u05d4 \u05dc\u05d4\u05ea\u05e4\u05dc\u05dc \u05d4\u05d9\u05d0 \u05db\u05d3\u05d9 \u05dc\u05e9\u05e0\u05d5\u05ea \u05d0\u05ea \u05de\u05e6\u05d9\u05d0\u05d5\u05ea \u05d7\u05d9\u05d9?\n\u05d0\u05d5 \u05e9\u05d0\u05d5\u05dc\u05d9 \u05dc\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d9\u05e9 \u05e2\u05e8\u05da \u05e2\u05de\u05d5\u05e7 \u05d5\u05e9\u05e7\u05d8 \u05d9\u05d5\u05ea\u05e8?\n\u05d9\u05d9\u05ea\u05db\u05df \u05e9\u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d0\u05d9\u05e0\u05e0\u05d4 \u05e0\u05d5\u05e2\u05d3\u05d4 \u05d1\u05e8\u05d0\u05e9 \u05d5\u05d1\u05e8\u05d0\u05e9\u05d5\u05e0\u05d4 \u05dc\u05e9\u05e0\u05d5\u05ea \u05d0\u05ea \u05de\u05d4 \u05e9\u05e7\u05d5\u05e8\u05d4 \u05d0\u05dc\u05d0 \u05dc\u05e9\u05e0\u05d5\u05ea \u05d0\u05ea \u05d4\u05d0\u05d5\u05e4\u05df \u05e9\u05d1\u05d5 \u05d0\u05e0\u05d9 \u05e4\u05d5\u05d2\u05e9\u05ea \u05d0\u05ea \u05de\u05d4 \u05e9\u05e7\u05d5\u05e8\u05d4.\n\u05dc\u05d0 \u05db\u05d1\u05e8\u05d9\u05d7\u05d4 \u05de\u05df \u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea, \u05d0\u05dc\u05d0 \u05db\u05d4\u05e1\u05db\u05de\u05d4 \u05dc\u05d4\u05ea\u05d1\u05d5\u05e0\u05df \u05d1\u05d4 \u05d1\u05dc\u05d9 \u05de\u05e1\u05db\u05d9\u05dd \u05d5\u05d1\u05dc\u05d9 \u05e6\u05d9\u05e0\u05d9\u05d5\u05ea \u05de\u05d2\u05d5\u05e0\u05e0\u05ea.\n\u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d9\u05db\u05d5\u05dc\u05d4 \u05dc\u05d4\u05d9\u05d5\u05ea \u05d7\u05d9\u05d1\u05d5\u05e8 \u05dc\u05de\u05e7\u05d5\u05e8 \u05d4\u05d7\u05d9\u05d9\u05dd \u2013 \u05dc\u05d0 \u05db\u05db\u05d5\u05d7 \u05d7\u05d9\u05e6\u05d5\u05e0\u05d9 \u05e9\u05de\u05ea\u05e7\u05df \u05e2\u05d1\u05d5\u05e8\u05d9, \u05d0\u05dc\u05d0 \u05db\u05d6\u05e8\u05dd \u05e4\u05e0\u05d9\u05de\u05d9 \u05e9\u05de\u05d6\u05db\u05d9\u05e8 \u05dc\u05d9 \u05e9\u05d0\u05e0\u05d9 \u05d7\u05dc\u05e7 \u05de\u05de\u05e9\u05d4\u05d5 \u05e8\u05d7\u05d1, \u05d7\u05d9, \u05e0\u05d5\u05e9\u05dd, \u05de\u05ea\u05d4\u05d5\u05d5\u05d4.\n\u05d4\u05d9\u05d0 \u05d9\u05db\u05d5\u05dc\u05d4 \u05dc\u05d4\u05d9\u05d5\u05ea \u05d7\u05d9\u05d1\u05d5\u05e8 \u05dc\u05e0\u05e9\u05de\u05d4 \u05e9\u05dc\u05d9 \u2013 \u05dc\u05d0 \u05d6\u05d5 \u05d4\u05d0\u05d9\u05d3\u05d9\u05d0\u05dc\u05d9\u05ea, \u05d0\u05dc\u05d0 \u05d6\u05d5 \u05d4\u05db\u05d5\u05d0\u05d1\u05ea, \u05d4\u05de\u05d1\u05d5\u05dc\u05d1\u05dc\u05ea, \u05d4\u05de\u05ea\u05d2\u05e2\u05d2\u05e2\u05ea.\n\u05d5\u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05d4\u05d9\u05d0 \u05e4\u05e9\u05d5\u05d8 \u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea: \u05d1\u05de\u05e6\u05d9\u05d0\u05d5\u05ea \u05d7\u05d9\u05d9 \u05db\u05e4\u05d9 \u05e9\u05d4\u05d9\u05d0, \u05d1\u05e2\u05d5\u05dc\u05dd \u05db\u05d5\u05dc\u05d5 \u05db\u05e4\u05d9 \u05e9\u05d4\u05d5\u05d0, \u05d1\u05db\u05d0\u05d1 \u05d4\u05d0\u05e0\u05d5\u05e9\u05d9 \u05e9\u05d0\u05d9\u05e0\u05e0\u05d5 \u05e4\u05e8\u05d8\u05d9 \u05d0\u05dc\u05d0 \u05de\u05e9\u05d5\u05ea\u05e3.\n\u05d9\u05e9 \u05d1\u05ea\u05e4\u05d9\u05dc\u05d4 \u05de\u05e7\u05d5\u05dd \u05d2\u05dd \u05dc\u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea \u05d1\u05db\u05d0\u05d1 \u05d4\u05e2\u05d5\u05dc\u05dd,\n\u05d1\u05d7\u05d5\u05e1\u05e8 \u05d4\u05e6\u05d3\u05e7,\n\u05d1\u05e4\u05e2\u05e8 \u05d4\u05d1\u05dc\u05ea\u05d9 \u05e0\u05e1\u05d1\u05dc \u05d1\u05d9\u05df \u201c\u05d0\u05de\u05d5\u05e8 \u05dc\u05d4\u05d9\u05d5\u05ea\u201d \u05dc\u201c\u05d9\u05e9\u201d.\n\u05dc\u05d0 \u05db\u05d3\u05d9 \u05dc\u05d9\u05d9\u05e4\u05d5\u05ea, \u05dc\u05d0 \u05db\u05d3\u05d9 \u05dc\u05d4\u05e6\u05d3\u05d9\u05e7 \u2013 \u05d0\u05dc\u05d0 \u05db\u05d3\u05d9 \u05dc\u05d0\u05d8\u05be\u05dc\u05d0\u05d8 \u05dc\u05d0\u05d8\u05d5\u05dd \u05e4\u05d7\u05d5\u05ea \u05d0\u05ea \u05d4\u05dc\u05d1.\n\u05d9\u05e9 \u05d4\u05e1\u05d1\u05e8 \u05d9\u05e4\u05d4 \u05d4\u05d0\u05d5\u05de\u05e8:\n\u05ea\u05d7\u05d9\u05dc\u05d4 \u05d0\u05e0\u05d5 \u05d0\u05d5\u05de\u05e8\u05d9\u05dd \u201c\u05d0\u05d9\u05df \u05db\u05d0\u05dc\u05d5\u05e7\u05d9\u05e0\u05d5\u201d \u2013\n\u05db\u05dc\u05d5\u05de\u05e8, \u05d0\u05e0\u05d5 \u05de\u05d1\u05e7\u05e9\u05d9\u05dd \u05dc\u05d4\u05d8\u05de\u05d9\u05e2 \u05d1\u05ea\u05d5\u05d3\u05e2\u05ea\u05e0\u05d5 \u05d0\u05de\u05d5\u05df \u05e8\u05d0\u05e9\u05d5\u05e0\u05d9:\n\u05d9\u05e9 \u05de\u05dc\u05da \u05dc\u05e2\u05d5\u05dc\u05dd.\n\u05d9\u05e9 \u05d4\u05e0\u05d4\u05d2\u05d4.\n\u05d9\u05e9 \u05e8\u05e6\u05d5\u05df \u05d1\u05d8\u05d5\u05d1, \u05d2\u05dd \u05d0\u05dd \u05d4\u05d5\u05d0 \u05e0\u05e1\u05ea\u05e8, \u05d2\u05dd \u05d0\u05dd \u05d0\u05d9\u05e0\u05e0\u05d5 \u05de\u05d5\u05d1\u05df.\n\u05e8\u05e7 \u05dc\u05d0\u05d7\u05e8 \u05e9\u05d4\u05e7\u05e8\u05e7\u05e2 \u05d4\u05d6\u05d5 \u05de\u05d5\u05e0\u05d7\u05ea, \u05d0\u05e0\u05d5 \u05d9\u05db\u05d5\u05dc\u05d9\u05dd \u05dc\u05d4\u05e8\u05e9\u05d5\u05ea \u05dc\u05e2\u05e6\u05de\u05e0\u05d5 \u05dc\u05e9\u05d0\u05d5\u05dc:\n\u201c\u05de\u05d9 \u05db\u05d0\u05dc\u05d5\u05e7\u05d9\u05e0\u05d5?\u201d\n\u05d0\u05d9\u05da \u05d9\u05d9\u05ea\u05db\u05df \u05e9\u05d0\u05d5\u05ea\u05d5 \u05de\u05e7\u05d5\u05e8 \u05d8\u05d5\u05d1, \u05d0\u05d5\u05ea\u05d5 \u201c\u05d0\u05d1\u05d0\u201d, \u05e0\u05e8\u05d0\u05d4 \u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05db\u05dc \u05db\u05da \u05e8\u05d7\u05d5\u05e7?\n\u05d0\u05d9\u05da \u05de\u05ea\u05e7\u05d9\u05d9\u05de\u05d9\u05dd \u05db\u05dc \u05db\u05da \u05d4\u05e8\u05d1\u05d4 \u05e2\u05d5\u05d5\u05dc\u05d5\u05ea, \u05d0\u05dc\u05d9\u05de\u05d5\u05ea, \u05d0\u05db\u05d6\u05e8\u05d9\u05d5\u05ea, \u05e9\u05ea\u05d9\u05e7\u05d4?\n\u05d5\u05d6\u05d5 \u05d0\u05d9\u05e0\u05d4 \u05e9\u05d0\u05dc\u05d4 \u05ea\u05d9\u05d0\u05d5\u05dc\u05d5\u05d2\u05d9\u05ea \u05d1\u05dc\u05d1\u05d3 \u2013 \u05d6\u05d5 \u05e9\u05d0\u05dc\u05d4 \u05e0\u05e4\u05e9\u05d9\u05ea \u05e2\u05de\u05d5\u05e7\u05d4.\n\u05db\u05d9 \u05dc\u05e6\u05e2\u05e8\u05e0\u05d5, \u05d2\u05dd \u05d4\u05de\u05d8\u05d0\u05e4\u05d5\u05e8\u05d4 \u05e9\u05dc \u201c\u05d4\u05d5\u05e8\u05d4 \u05d8\u05d5\u05d1\u201d \u05d0\u05d9\u05e0\u05d4 \u05e4\u05e9\u05d5\u05d8\u05d4.\n\u05e2\u05d1\u05d5\u05e8 \u05e8\u05d1\u05d9\u05dd \u05d4\u05d9\u05d0 \u05d8\u05e2\u05d5\u05e0\u05d4, \u05e4\u05e6\u05d5\u05e2\u05d4, \u05d0\u05e4\u05d9\u05dc\u05d5 \u05de\u05e1\u05d5\u05db\u05e0\u05ea.\n\u05db\u05dc \u05db\u05da \u05d4\u05e8\u05d1\u05d4 \u05d4\u05d5\u05e8\u05d9\u05dd \u05d4\u05e9\u05ea\u05de\u05e9\u05d5 \u05dc\u05e8\u05e2\u05d4 \u05d1\u05db\u05d5\u05d7\u05dd \u2013\n\u05dc\u05e9\u05dc\u05d9\u05d8\u05d4, \u05dc\u05de\u05e0\u05d9\u05e4\u05d5\u05dc\u05e6\u05d9\u05d4, \u05dc\u05d4\u05d6\u05e0\u05d7\u05d4, \u05d5\u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05dc\u05e8\u05e9\u05e2\u05d5\u05ea \u05d8\u05d4\u05d5\u05e8\u05d4 \u05db\u05dc\u05e4\u05d9 \u05d9\u05dc\u05d3\u05d9\u05d4\u05dd.\n\u05d5\u05d1\u05db\u05dc \u05d6\u05d0\u05ea \u2013\n\u05d0\u05d9\u05e4\u05e9\u05d4\u05d5 \u05e2\u05de\u05d5\u05e7, \u05d0\u05e0\u05d7\u05e0\u05d5 \u05e2\u05d3\u05d9\u05d9\u05df \u05e8\u05d5\u05e6\u05d9\u05dd \u05dc\u05d4\u05d0\u05de\u05d9\u05df\n\u05e9\u05d9\u05e9 \u05d3\u05d1\u05e8 \u05db\u05d6\u05d4 \u05d0\u05d4\u05d1\u05d4 \u05d4\u05d5\u05e8\u05d9\u05ea \u05d8\u05d4\u05d5\u05e8\u05d4.\n\u05dc\u05d0 \u05db\u05de\u05e6\u05d9\u05d0\u05d5\u05ea \u05d7\u05d5\u05d5\u05d9\u05d9\u05ea\u05d9\u05ea \u05e9\u05db\u05d5\u05dc\u05e0\u05d5 \u05d6\u05db\u05d9\u05e0\u05d5 \u05dc\u05d4,\n\u05d0\u05dc\u05d0 \u05db\u05db\u05de\u05d9\u05d4\u05d4 \u05e7\u05d9\u05d5\u05de\u05d9\u05ea:\n\u05e9\u05d0\u05e4\u05e9\u05e8 \u05dc\u05d4\u05d9\u05d5\u05ea \u05de\u05d5\u05d7\u05d6\u05e7 \u05d1\u05dc\u05d9 \u05ea\u05e0\u05d0\u05d9\u05dd,\n\u05e0\u05e8\u05d0\u05d4 \u05d1\u05dc\u05d9 \u05dc\u05d4\u05d9\u05d1\u05dc\u05e2,\n\u05e0\u05d0\u05d4\u05d1 \u05d1\u05dc\u05d9 \u05dc\u05d4\u05d9\u05e9\u05dc\u05d8.\n\u05d0\u05d5\u05dc\u05d9 \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d0\u05d9\u05e0\u05e0\u05d4 \u05d4\u05e6\u05d4\u05e8\u05d4 \u05e9\u05dc \u05d5\u05d3\u05d0\u05d5\u05ea,\n\u05d0\u05dc\u05d0 \u05e4\u05e2\u05d5\u05dc\u05d4 \u05e9\u05dc \u05d0\u05d5\u05de\u05e5.\n\u05d4\u05d0\u05d5\u05de\u05e5 \u05dc\u05d4\u05d0\u05de\u05d9\u05df \u05d1\u05d8\u05d5\u05d1 \u05d2\u05dd \u05db\u05e9\u05d0\u05d9\u05df \u05dc\u05d5 \u05d4\u05d5\u05db\u05d7\u05d4.\n\u05d4\u05d0\u05d5\u05de\u05e5 \u05dc\u05d0 \u05dc\u05e0\u05ea\u05e7 \u05d0\u05ea \u05d4\u05e7\u05e9\u05e8 \u05dc\u05de\u05e8\u05d5\u05ea \u05d4\u05d0\u05db\u05d6\u05d1\u05d4.\n\u05d4\u05d0\u05d5\u05de\u05e5 \u05dc\u05d4\u05d9\u05e9\u05d0\u05e8 \u05d1\u05e9\u05d9\u05d7 \u2013 \u05d2\u05dd \u05db\u05e9\u05d4\u05d5\u05d0 \u05db\u05d5\u05d0\u05d1, \u05d2\u05dd \u05db\u05e9\u05d4\u05d5\u05d0 \u05e9\u05d5\u05ea\u05e7.\n\u05d5\u05d1\u05de\u05d5\u05d1\u05df \u05d4\u05d6\u05d4,\n\u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d0\u05d9\u05e0\u05d4 \u05ea\u05e9\u05d5\u05d1\u05d4 \u05dc\u05d7\u05d5\u05e1\u05e8 \u05d4\u05e6\u05d3\u05e7,\n\u05d0\u05dc\u05d0 \u05e1\u05d9\u05e8\u05d5\u05d1 \u05dc\u05d4\u05e4\u05d5\u05da \u05d0\u05d3\u05d9\u05e9\u05d9\u05dd \u05d0\u05dc\u05d9\u05d5.\n\u05d4\u05d9\u05d0 \u05e9\u05de\u05d9\u05e8\u05d4 \u05e2\u05dc \u05dc\u05d1 \u05e4\u05ea\u05d5\u05d7 \u05d1\u05e2\u05d5\u05dc\u05dd \u05e9\u05de\u05e6\u05d9\u05e2 \u05dc\u05e0\u05d5 \u05dc\u05d4\u05d9\u05e1\u05d2\u05e8.\n\u05d4\u05e8\u05d0\u05e9\u05d5\u05e0\u05d9\u05dd \u05de\u05e1\u05d1\u05d9\u05e8\u05d9\u05dd \u05db\u05d9 \u05d4\u05de\u05d6\u05de\u05d5\u05e8 \u201c\u05d0\u05d9\u05df \u05db\u05d0\u05dc\u05d5\u05e7\u05d9\u05e0\u05d5\u201d \u05de\u05e1\u05d5\u05d3\u05e8 \u05dc\u05e4\u05d9 \u05e8\u05d0\u05e9\u05d9 \u05d4\u05ea\u05d9\u05d1\u05d5\u05ea \u05e9\u05dc \u05d4\u05de\u05d9\u05dc\u05d4 \u05d0\u05de\u05df:\n\u05d0 \u2013 \u05d0\u05d9\u05df \u05db\u05d0\u05dc\u05d5\u05e7\u05d9\u05e0\u05d5\n\u05de \u2013 \u05de\u05d9 \u05db\u05d0\u05dc\u05d5\u05e7\u05d9\u05e0\u05d5\n\u05df \u2013 \u05d5\u05d0\u05d6 \u05e0\u05d5\u05d3\u05d4 \u05dc\u05d0\u05dc\u05d5\u05e7\u05d9\u05e0\u05d5\n\u05d4\u05e1\u05d3\u05e8 \u05d4\u05d6\u05d4 \u05de\u05de\u05e9\u05d9\u05da \u05d1\u05d0\u05d5\u05e4\u05df \u05d8\u05d1\u05e2\u05d9 \u05dc\u05d1\u05e8\u05db\u05d4: \u201c\u05d1\u05e8\u05d5\u05da \u05d0\u05dc\u05d5\u05e7\u05d9\u05e0\u05d5 \u05d5\u05d0\u05ea\u05d4 \u05d4\u05d5\u05d0 \u05d0\u05dc\u05d5\u05e7\u05d9\u05e0\u05d5\u201d.\n\u05de\u05db\u05da \u05d0\u05e0\u05d5 \u05dc\u05de\u05d3\u05d9\u05dd \u05e9\u05d4\u05de\u05d9\u05dc\u05d4 \u05d0\u05de\u05df \u05d0\u05d9\u05e0\u05e0\u05d4 \u05e1\u05ea\u05dd \u05e1\u05d9\u05d5\u05dd \u05e9\u05dc \u05d1\u05e8\u05db\u05d4, \u05d0\u05dc\u05d0 \u05e4\u05e2\u05d5\u05dc\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05e9\u05dc \u05d4\u05e1\u05db\u05de\u05d4 \u05d5\u05d4\u05db\u05e0\u05d4 \u05e0\u05e4\u05e9\u05d9\u05ea.\n\u05d0\u05de\u05df = \u05d4\u05e2\u05e0\u05e7\u05ea \u05d0\u05de\u05d5\u05e0\u05d4 \u05d1\u05e4\u05d5\u05e2\u05dc, \u05d5\u05d0\u05de\u05d5\u05e0\u05d4 \u05d6\u05d5 \u05d2\u05d3\u05d5\u05dc\u05d4 \u05d9\u05d5\u05ea\u05e8 \u05de\u05d4\u05d1\u05e8\u05db\u05d4 \u05e2\u05e6\u05de\u05d4. \u05db\u05d9 \u05d4\u05d3\u05d1\u05e8 \u05d4\u05d9\u05e7\u05e8 \u05d1\u05d9\u05d5\u05ea\u05e8 \u05dc\u05d0\u05d3\u05dd \u05d4\u05d5\u05d0 \u05dc\u05d9\u05d9\u05e6\u05e8 \u05d1\u05e0\u05e4\u05e9\u05d5 \u05d0\u05de\u05d5\u05e0\u05d4 \u2013 \u05d7\u05d9\u05d1\u05d5\u05e8 \u05e4\u05e0\u05d9\u05de\u05d9, \u05d7\u05d9, \u05d5\u05d0\u05de\u05d9\u05ea\u05d9 \u05dc\u05d0\u05dc\u05d5\u05e7\u05d9\u05d5, \u05de\u05e2\u05d1\u05e8 \u05dc\u05de\u05d9\u05dc\u05d9\u05dd \u05d5\u05dc\u05e0\u05d5\u05e1\u05d7.\n\u05d4\u05d1\u05e2\u05e9"\u05d8 \u05d4\u05d6\u05d4\u05d9\u05e8, \u05db\u05d9 \u05db\u05d0\u05e9\u05e8 \u05d4\u05d0\u05d3\u05dd \u05e1\u05d1\u05d5\u05e8 \u05e9\u05d4\u05d5\u05d0 \u05de\u05db\u05d9\u05e8 \u05d0\u05ea \u05d4\u05e9\u05dd \u05d5\u05e4\u05d5\u05e0\u05d4 \u05d0\u05dc\u05d9\u05d5 \u05d1\u05dc\u05e9\u05d5\u05df \u201c\u05d0\u05ea\u05d4\u201d, \u05db\u05d0\u05d9\u05dc\u05d5 \u05d4\u05d5\u05d0 \u05d9\u05d5\u05d3\u05e2 \u05de\u05d9 \u05d4\u05d5\u05d0 \u05d4\u05d0\u05ea\u05d4, \u05d4\u05d5\u05d0 \u05e2\u05dc\u05d5\u05dc \u05dc\u05d4\u05ea\u05e8\u05d7\u05e7 \u05de\u05d4\u05d4\u05d5\u05d5\u05d9\u05d4 \u05d4\u05e2\u05de\u05d5\u05e7\u05d4 \u05e9\u05dc \u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea \u05d4\u05e8\u05d5\u05d7\u05e0\u05d9\u05ea \u05d1\u05d7\u05d9\u05d9\u05d5.\n\u05e8\u05d1\u05d9 \u05e0\u05d7\u05de\u05df \u05de\u05d5\u05e1\u05d9\u05e3 \u05e2\u05dc \u05db\u05da: \u05d4\u05de\u05d9\u05dc\u05d9\u05dd \u201c\u05d0\u05d9\u05d4 \u05de\u05e7\u05d5\u05dd \u05db\u05d1\u05d5\u05d3\u05d5\u201d \u2013 \u05d1\u05e2\u05dc\u05d5\u05ea \u05e2\u05d5\u05e6\u05de\u05d4 \u05d2\u05d1\u05d5\u05d4\u05d4 \u05d0\u05e3 \u05d9\u05d5\u05ea\u05e8 \u05de\u201d\u05e7\u05d3\u05d5\u05e9 \u05e7\u05d3\u05d5\u05e9 \u05e7\u05d3\u05d5\u05e9\u201d, \u05de\u05e9\u05d5\u05dd \u05e9\u05d4\u05df \u05de\u05d5\u05e0\u05d7\u05d5\u05ea \u05e2\u05dc \u05d4\u05d4\u05db\u05e8\u05d4 \u05e9\u05d4\u05db\u05d1\u05d5\u05d3 \u05d5\u05d4\u05e7\u05d3\u05d5\u05e9\u05d4 \u05e9\u05dc \u05d4\u05d1\u05d5\u05e8\u05d0 \u05d0\u05d9\u05e0\u05e1\u05d5\u05e4\u05d9\u05d9\u05dd, \u05d5\u05e9\u05d0\u05d9\u05e0\u05e0\u05d5 \u05d9\u05db\u05d5\u05dc\u05d9\u05dd \u05d1\u05d0\u05de\u05ea \u05dc\u05d4\u05d1\u05d9\u05df \u05d0\u05ea \u05e2\u05d5\u05de\u05e7 \u05e7\u05d3\u05d5\u05e9\u05ea\u05d5.\n\u05d7\u05d5\u05d5\u05d9\u05d9\u05ea \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u2013 \u05d5\u05db\u05dc \u05d7\u05d5\u05d5\u05d9\u05d5\u05ea \u05d4\u05d7\u05d9\u05d9\u05dd \u05d1\u05db\u05dc\u05dc \u2013 \u05d4\u05d9\u05d0 \u05e8\u05d0\u05d9\u05d9\u05d4 \u05e9\u05dc \u05e7\u05d3\u05d5\u05e9\u05ea\u05d5 \u05d5\u05d4\u05d9\u05e2\u05dc\u05de\u05d5\u05ea\u05d4 \u05d1\u05d5\u05be\u05d6\u05de\u05e0\u05d9\u05ea.\n\u05d0\u05e0\u05d5 \u05d7\u05d9\u05d9\u05dd \u05d1\u05ea\u05d5\u05da \u05d8\u05d5\u05d5\u05d7 \u05de\u05ea\u05de\u05d9\u05d3, \u05d1\u05ea\u05d5\u05d5\u05da \u05e9\u05d1\u05d5 \u05d4\u05e7\u05d3\u05d5\u05e9\u05d4 \u05e0\u05e8\u05d0\u05d9\u05ea \u05dc\u05e4\u05e2\u05de\u05d9\u05dd \u05d5\u05de\u05d5\u05e1\u05ea\u05e8\u05ea \u05dc\u05e4\u05e2\u05de\u05d9\u05dd, \u05d5\u05e8\u05e6\u05d5\u05e0\u05e0\u05d5 \u05dc\u05d4\u05d1\u05d9\u05df \u05d5\u05dc\u05d4\u05ea\u05d7\u05d1\u05e8 \u05d4\u05d5\u05d0 \u05d1\u05dc\u05ea\u05d9 \u05e0\u05dc\u05d0\u05d4.\n\u05d4\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d4\u05d9\u05d4\u05d5\u05d3\u05d9\u05ea, \u05db\u05e9\u05d9\u05d8\u05d4 \u05e9\u05dc \u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea \u05e4\u05e0\u05d9\u05de\u05d9\u05ea, \u05de\u05d0\u05e4\u05e9\u05e8\u05ea \u05dc\u05e0\u05d5 \u05dc\u05d4\u05e8\u05d2\u05d9\u05e9 \u05d0\u05ea \u05d4\u05de\u05e7\u05d5\u05dd \u05d4\u05d6\u05d4:\n\u05d0\u05ea \u05d4\u05d7\u05dc\u05dc \u05e9\u05d1\u05d5 \u05d0\u05e0\u05d5 \u05e2\u05d5\u05de\u05d3\u05d9\u05dd \u05de\u05d5\u05dc \u05d4\u05d0\u05dc\u05d5\u05e7\u05d5\u05ea, \u05de\u05d5\u05dc \u05d7\u05d9\u05d9\u05e0\u05d5 \u05d5\u05de\u05d5\u05dc \u05d4\u05e2\u05d5\u05dc\u05dd \u05db\u05d5\u05dc\u05d5, \u05d1\u05dc\u05d9 \u05dc\u05e9\u05dc\u05d5\u05d8 \u05d0\u05d5 \u05dc\u05d4\u05d1\u05d9\u05df \u05d4\u05db\u05dc, \u05d0\u05da \u05d1\u05d4\u05d9\u05e9\u05d0\u05e8\u05d5\u05ea \u05e7\u05e9\u05d5\u05d1\u05d9\u05dd, \u05e4\u05ea\u05d5\u05d7\u05d9\u05dd \u05d5\u05e0\u05d5\u05db\u05d7\u05d9\u05dd.\n\u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d0\u05d9\u05e0\u05d4 \u05e8\u05e7 \u05d1\u05e7\u05e9\u05d4 \u05dc\u05e9\u05d9\u05e0\u05d5\u05d9 \u05de\u05e6\u05d9\u05d0\u05d5\u05ea \u05d7\u05d9\u05d9, \u05d0\u05dc\u05d0 \u05d7\u05d9\u05d1\u05d5\u05e8 \u05e4\u05e0\u05d9\u05de\u05d9 \u05e2\u05de\u05d5\u05e7:\n\u05d7\u05d9\u05d1\u05d5\u05e8 \u05dc\u05e0\u05e9\u05de\u05d4 \u05e9\u05dc\u05d9, \u05d4\u05e7\u05d5\u05dc \u05d4\u05e4\u05e0\u05d9\u05de\u05d9 \u05e9\u05de\u05e8\u05d2\u05d9\u05e9, \u05db\u05d5\u05d0\u05d1, \u05de\u05ea\u05d2\u05e2\u05d2\u05e2 \u05d5\u05e0\u05d5\u05e9\u05dd.\n\u05d7\u05d9\u05d1\u05d5\u05e8 \u05dc\u05de\u05e7\u05d5\u05e8 \u05d4\u05d7\u05d9\u05d9\u05dd, \u05d4\u05d6\u05e8\u05dd \u05d4\u05d0\u05dc\u05d5\u05e7\u05d9 \u05e9\u05de\u05d7\u05d1\u05e8 \u05db\u05dc \u05d3\u05d1\u05e8 \u05d1\u05e7\u05d9\u05d5\u05dd.\n\u05d4\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5\u05ea \u05d1\u05db\u05d0\u05d1 \u05d4\u05e2\u05d5\u05dc\u05dd \u05d5\u05d1\u05d7\u05d5\u05e1\u05e8 \u05d4\u05e6\u05d3\u05e7, \u05de\u05d1\u05dc\u05d9 \u05dc\u05d4\u05d9\u05e1\u05d2\u05e8 \u05d0\u05d5 \u05dc\u05d1\u05e8\u05d5\u05d7 \u05de\u05d4\u05de\u05e6\u05d9\u05d0\u05d5\u05ea.\n\u05d1\u05ea\u05d5\u05da \u05d7\u05d5\u05e1\u05e8 \u05d4\u05d5\u05d5\u05d3\u05d0\u05d5\u05ea \u05d4\u05d6\u05d4, \u05d1\u05ea\u05d5\u05d5\u05da \u05e9\u05d1\u05d9\u05df \u05e8\u05d0\u05d9\u05d9\u05d4 \u05dc\u05d4\u05d9\u05e2\u05dc\u05de\u05d5\u05ea, \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05d5\u05d4\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05de\u05e2\u05e0\u05d9\u05e7\u05d5\u05ea \u05dc\u05e0\u05d5 \u05d0\u05d5\u05de\u05e5 \u05d5\u05e0\u05d5\u05db\u05d7\u05d5\u05ea, \u05de\u05e7\u05d5\u05dd \u05dc\u05d4\u05d9\u05e9\u05d0\u05e8 \u05e4\u05ea\u05d5\u05d7\u05d9\u05dd, \u05dc\u05d4\u05db\u05d9\u05e8 \u05d0\u05ea \u05d4\u05d2\u05d1\u05d5\u05dc\u05d5\u05ea \u05e9\u05dc\u05e0\u05d5 \u05de\u05d5\u05dc \u05d4\u05d0\u05d9\u05e0\u05e1\u05d5\u05e4\u05d9, \u05d5\u05dc\u05d4\u05ea\u05d7\u05d1\u05e8 \u05dc\u05d7\u05d9\u05d9\u05dd \u05e2\u05e6\u05de\u05dd.\n\u05dc\u05d5\u05de\u05e8 \u201c\u05d0\u05d9\u05df \u05db\u05d0\u05dc\u05d5\u05e7\u05d9\u05e0\u05d5\u201d \u05d0\u05d9\u05e0\u05d5 \u05e8\u05e7 \u05d7\u05d6\u05e8\u05d4 \u05e2\u05dc \u05de\u05d9\u05dc\u05d9\u05dd \u05e2\u05ea\u05d9\u05e7\u05d5\u05ea; \u05d6\u05d5 \u05ea\u05e0\u05d5\u05e2\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea \u05e9\u05dc \u05d0\u05de\u05d5\u05e0\u05d4, \u05d0\u05d5\u05de\u05e5 \u05dc\u05d4\u05d0\u05de\u05d9\u05df \u05d1\u05d8\u05d5\u05d1 \u05d2\u05dd \u05db\u05e9\u05d0\u05d9\u05df \u05d4\u05d5\u05db\u05d7\u05d4, \u05d0\u05d5\u05de\u05e5 \u05dc\u05d4\u05d9\u05e9\u05d0\u05e8 \u05e4\u05ea\u05d5\u05d7\u05d9\u05dd \u05d1\u05e2\u05d5\u05dc\u05dd \u05d4\u05db\u05d5\u05d0\u05d1 \u05d0\u05da \u05de\u05dc\u05d0 \u05d4\u05d0\u05e4\u05e9\u05e8\u05d5\u05d9\u05d5\u05ea, \u05d5\u05d0\u05d5\u05de\u05e5 \u05dc\u05d4\u05ea\u05d1\u05d5\u05e0\u05df \u05d1\u05e7\u05d3\u05d5\u05e9\u05ea \u05d4\u05d7\u05d9\u05d9\u05dd \u05d5\u05d4\u05d9\u05e7\u05d5\u05dd, \u05d2\u05dd \u05db\u05e9\u05d0\u05d9\u05e0\u05d4 \u05d1\u05e8\u05d5\u05e8\u05d4 \u05dc\u05e2\u05d9\u05df.',"\u05ea\u05e8\u05d2\u05d5\u05dc \u05d6\u05d4 \u05de\u05d0\u05e4\u05e9\u05e8 \u05dc\u05db\u05dd \u05dc\u05d7\u05d5\u05d5\u05ea \u05d0\u05ea \u05d4\u05ea\u05e4\u05d9\u05dc\u05d4 \u05db\u05de\u05d3\u05d9\u05d8\u05e6\u05d9\u05d4 \u05d7\u05d9\u05d4 \u2013 \u05dc\u05d0 \u05e8\u05e7 \u05de\u05d9\u05dc\u05d9\u05dd, \u05d0\u05dc\u05d0 \u05d7\u05d5\u05d5\u05d9\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea, \u05e0\u05d5\u05db\u05d7\u05d5\u05ea \u05d5\u05d0\u05de\u05d5\u05e0\u05d4 \u05de\u05ea\u05e4\u05ea\u05d7\u05ea.",'\u05e9\u05d1\u05d5 \u05d1\u05de\u05e6\u05d1 \u05e0\u05d9\u05e0\u05d5\u05d7, \u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05e2\u05e6\u05d5\u05de\u05d5\u05ea, \u05e0\u05e9\u05d9\u05de\u05d5\u05ea \u05e2\u05de\u05d5\u05e7\u05d5\u05ea \u05d5\u05d0\u05d9\u05d8\u05d9\u05d5\u05ea.\n\u05d7\u05d6\u05e8\u05d5 \u05d1\u05dc\u05d1 \u05d0\u05ea \u05d4\u05de\u05d9\u05dc\u05d9\u05dd: \u201c\u05d0\u05d9\u05df \u05db\u05d0\u05dc\u05d5\u05e7\u05d9\u05e0\u05d5\u201d, \u05d5\u05d4\u05e8\u05d2\u05d9\u05e9\u05d5 \u05d0\u05ea \u05de\u05e9\u05de\u05e2\u05d5\u05ea\u05df \u2013 \u05d0\u05d9\u05df \u05d3\u05d5\u05de\u05d4 \u05dc\u05d5, \u05d0\u05d9\u05df \u05db\u05de\u05d5\u05d4\u05d5.\n\u05dc\u05d0\u05d7\u05e8 \u05de\u05db\u05df \u05d7\u05d6\u05e8\u05d5 \u201c\u05de\u05d9 \u05db\u05d0\u05dc\u05d5\u05e7\u05d9\u05e0\u05d5\u201d, \u05d5\u05ea\u05e0\u05d5 \u05dc\u05e2\u05e6\u05de\u05db\u05dd \u05dc\u05d4\u05e8\u05d2\u05d9\u05e9 \u05d0\u05ea \u05d4\u05e8\u05e6\u05d5\u05df \u05dc\u05d4\u05ea\u05d7\u05d1\u05e8, \u05d0\u05ea \u05d4\u05db\u05de\u05d9\u05d4\u05d4 \u05dc\u05e0\u05d5\u05db\u05d7\u05d5\u05ea \u05e2\u05dc\u05d9\u05d5\u05e0\u05d4.\n\u05d4\u05de\u05e9\u05d9\u05db\u05d5 \u05d1**\u201c\u05d0\u05de\u05df\u201d**, \u05d5\u05d4\u05e8\u05d2\u05d9\u05e9\u05d5 \u05d0\u05ea \u05d4\u05d4\u05e1\u05db\u05de\u05d4 \u05d4\u05e4\u05e0\u05d9\u05de\u05d9\u05ea, \u05d0\u05ea \u05d4\u05d0\u05de\u05d5\u05e0\u05d4 \u05e9\u05e0\u05d5\u05e6\u05e8\u05ea \u05d1\u05db\u05dd.\n\u05ea\u05d1\u05d5\u05e0\u05e0\u05d5 \u05d1\u05e8\u05d2\u05e9\u05d5\u05ea \u05e9\u05e2\u05d5\u05dc\u05d9\u05dd \u2013 \u05d0\u05ea \u05d4\u05e8\u05e6\u05d5\u05df, \u05d4\u05db\u05d0\u05d1, \u05d4\u05e9\u05de\u05d7\u05d4 \u05d0\u05d5 \u05d4\u05e4\u05e2\u05e8 \u2013 \u05d5\u05d4\u05e0\u05d9\u05d7\u05d5 \u05dc\u05d4\u05dd \u05dc\u05d4\u05d9\u05d5\u05ea \u05de\u05d1\u05dc\u05d9 \u05dc\u05e9\u05e4\u05d5\u05d8.\n\u05e1\u05d9\u05d9\u05de\u05d5 \u05d1\u05e0\u05e9\u05d9\u05de\u05d4 \u05e2\u05de\u05d5\u05e7\u05d4, \u05d5\u05d4\u05e8\u05d2\u05d9\u05e9\u05d5 \u05d0\u05ea \u05d4\u05d7\u05d9\u05d1\u05d5\u05e8 \u05dc\u05e0\u05e9\u05de\u05d4 \u05e9\u05dc\u05db\u05dd \u05d5\u05dc\u05de\u05e7\u05d5\u05e8 \u05d4\u05d7\u05d9\u05d9\u05dd, \u05d2\u05dd \u05d0\u05dd \u05d4\u05d5\u05d0 \u05e0\u05e1\u05ea\u05e8 \u05d0\u05d5 \u05d7\u05de\u05e7\u05de\u05e7.\n\u05d1\u05e8\u05db\u05ea \u05d4\u05de\u05d6\u05d5\u05df\n\u05d1\u05e8\u05db\u05ea \u05d4\u05de\u05d6\u05d5\u05df\n"\u05d4\u05d6\u05d5\u05e8\u05e2\u05d9\u05dd \u05d1\u05d3\u05de\u05e2\u05d4 \u2013 \u05d1\u05e8\u05d9\u05e0\u05d4 \u05d9\u05e7\u05e6\u05d5\u05e8\u05d5"\n\u2013 \u05de\u05e9\u05e4\u05d8 \u05e7\u05e6\u05e8 \u05d5\u05e4\u05e9\u05d5\u05d8, \u05d0\u05da \u05d8\u05de\u05d5\u05df \u05d1\u05d5 \u05e2\u05d5\u05dc\u05dd \u05e9\u05dc\u05dd \u05e9\u05dc \u05d7\u05db\u05de\u05d4 \u05e8\u05d2\u05e9\u05d9\u05ea \u05d5\u05e8\u05d5\u05d7\u05e0\u05d9\u05ea.\n\u05d1\u05e7\u05e8\u05d9\u05d0\u05d4 \u05ea\u05d5\u05d3\u05e2\u05ea\u05d9\u05ea, \u05de\u05d3\u05d5\u05d1\u05e8 \u05db\u05d0\u05df \u05d1\u05ea\u05d4\u05dc\u05d9\u05da \u05e0\u05e4\u05e9\u05d9 \u05e2\u05de\u05d5\u05e7:\n\ud83c\udf31 \u05d4\u05d6\u05d5\u05e8\u05e2\u05d9\u05dd \u05d1\u05d3\u05de\u05e2\u05d4\n\u05d4\u05dd \u05d4\u05d0\u05e0\u05e9\u05d9\u05dd \u05e9\u05de\u05e2\u05d6\u05d9\u05dd \u05dc\u05d6\u05e8\u05d5\u05e2, \u05d2\u05dd \u05db\u05e9\u05db\u05d5\u05d0\u05d1.\n\u05d4\u05dd \u05dc\u05d0 \u05de\u05d7\u05db\u05d9\u05dd \u05dc\u05d9\u05d5\u05dd \u05e9\u05de\u05e9 \u05e0\u05e2\u05d9\u05dd \u05d0\u05d5 \u05dc\u05e8\u05d5\u05d7 \u05d8\u05d5\u05d1\u05d4 \u05d1\u05d2\u05d1, \u05d0\u05dc\u05d0 \u05d1\u05d5\u05d7\u05e8\u05d9\u05dd \u05dc\u05e9\u05ea\u05d5\u05dc \u05d6\u05e8\u05e2\u05d9\u05dd \u05e9\u05dc \u05ea\u05e7\u05d5\u05d5\u05d4, \u05e9\u05d9\u05e0\u05d5\u05d9, \u05e1\u05dc\u05d9\u05d7\u05d4, \u05d0\u05d4\u05d1\u05d4 \u2013 \u05d2\u05dd \u05db\u05e9\u05d4\u05dc\u05d1 \u05e0\u05e9\u05d1\u05e8, \u05d2\u05dd \u05db\u05e9\u05d9\u05e9 \u05d3\u05de\u05e2\u05d5\u05ea.\n\u05d0\u05dc\u05d5 \u05e9\u05de\u05d1\u05d9\u05e0\u05d9\u05dd \u05e9\u05d3\u05d5\u05d5\u05e7\u05d0 \u05d4\u05db\u05d0\u05d1 \u05d9\u05db\u05d5\u05dc \u05dc\u05d4\u05e4\u05d5\u05da \u05dc\u05d3\u05e9\u05df.\n\u05e9\u05db\u05dc \u05d3\u05de\u05e2\u05d4 \u05d4\u05d9\u05d0 \u05ea\u05e4\u05d9\u05dc\u05d4 \u05d0\u05d9\u05dc\u05de\u05ea.\n\u05e9\u05d1\u05db\u05dc \u05d3\u05de\u05e2\u05d4 \u05d9\u05e9 \u05e4\u05d5\u05d8\u05e0\u05e6\u05d9\u05d0\u05dc \u05e9\u05dc \u05d7\u05d9\u05d9\u05dd \u05d7\u05d3\u05e9\u05d9\u05dd.\n\u05d4\u05dd \u05d6\u05d5\u05e8\u05e2\u05d9\u05dd \u2013 \u05db\u05dc\u05d5\u05de\u05e8 \u05e4\u05d5\u05e2\u05dc\u05d9\u05dd. \u05d4\u05dd \u05dc\u05d0 \u05e7\u05d5\u05e4\u05d0\u05d9\u05dd \u05de\u05d4\u05db\u05d0\u05d1, \u05dc\u05d0 \u05d1\u05d5\u05e8\u05d7\u05d9\u05dd, \u05dc\u05d0 \u05de\u05d0\u05e9\u05d9\u05de\u05d9\u05dd.\n\u05d4\u05dd \u05e0\u05d5\u05db\u05d7\u05d9\u05dd. \u05d4\u05dd \u05e2\u05d5\u05e9\u05d9\u05dd \u05e2\u05d1\u05d5\u05d3\u05d4 \u05e4\u05e0\u05d9\u05de\u05d9\u05ea.\n\u05d6\u05d5\u05e8\u05e2\u05d9\u05dd \u05d1\u05ea\u05d5\u05d3\u05e2\u05d4 \u05d0\u05de\u05d5\u05e0\u05d4, \u05dc\u05de\u05e8\u05d5\u05ea \u05d4\u05e4\u05d7\u05d3.\n\u05d6\u05d5\u05e8\u05e2\u05d9\u05dd \u05ea\u05e0\u05d5\u05e2\u05d4, \u05dc\u05de\u05e8\u05d5\u05ea \u05d4\u05d3\u05db\u05d3\u05d5\u05da.\n\ud83c\udf38 \u05d1\u05e8\u05d9\u05e0\u05d4 \u05d9\u05e7\u05e6\u05d5\u05e8\u05d5\n\u05dc\u05d0 \u05e8\u05e7 \u05e9\u05d9\u05e7\u05e6\u05d5\u05e8\u05d5 \u2013 \u05d0\u05dc\u05d0 \u05d1\u05e8\u05d9\u05e0\u05d4.\n\u05d4\u05dd \u05d9\u05e7\u05d1\u05dc\u05d5 \u05d1\u05d7\u05d6\u05e8\u05d4 \u05e4\u05d9 \u05db\u05de\u05d4, \u05d5\u05d1\u05e9\u05de\u05d7\u05d4 \u05e2\u05de\u05d5\u05e7\u05d4, \u05d0\u05ea \u05e4\u05d9\u05e8\u05d5\u05ea \u05d0\u05d5\u05ea\u05d4 \u05d1\u05d7\u05d9\u05e8\u05d4 \u05de\u05d5\u05d3\u05e2\u05ea \u05dc\u05d2\u05d3\u05d5\u05dc \u05de\u05ea\u05d5\u05da \u05d4\u05db\u05d0\u05d1.\n\u05d4\u05dd \u05d9\u05e7\u05e6\u05d5\u05e8\u05d5 \u05e9\u05d9\u05e0\u05d5\u05d9, \u05e6\u05de\u05d9\u05d7\u05d4, \u05e8\u05d9\u05e4\u05d5\u05d9.\n\u05dc\u05d0 \u05ea\u05de\u05d9\u05d3 \u05d1\u05d0\u05d5\u05ea\u05d4 \u05e2\u05d5\u05e0\u05d4, \u05dc\u05d0 \u05ea\u05de\u05d9\u05d3 \u05de\u05d4\u05db\u05d9\u05d5\u05d5\u05df \u05e9\u05e6\u05d9\u05e4\u05d5 \u2013\n\u05d0\u05d1\u05dc \u05d4\u05dd \u05d9\u05e7\u05e6\u05d5\u05e8\u05d5.\n\u05db\u05d9 \u05db\u05dc \u05d3\u05de\u05e2\u05d4 \u05e9\u05e0\u05e9\u05e4\u05db\u05d4 \u05de\u05ea\u05d5\u05da \u05db\u05d5\u05d5\u05e0\u05d4 \u05dc\u05d4\u05ea\u05e8\u05e4\u05d0 \u05d5\u05dc\u05e6\u05de\u05d5\u05d7 \u2013\n\u05d4\u05d5\u05e4\u05db\u05ea \u05dc\u05d1\u05e1\u05d5\u05e3 \u05dc\u05de\u05d9\u05dd \u05d7\u05d9\u05d9\u05dd, \u05dc\u05d4\u05e9\u05e7\u05d9\u05d4 \u05e9\u05dc \u05e4\u05e8\u05d9 \u05d7\u05d3\u05e9.\n\u2728 \u05ea\u05e8\u05d2\u05d9\u05dc \u05ea\u05d5\u05d3\u05e2\u05ea\u05d9 \u05dc\u05d4\u05d8\u05de\u05e2\u05d4:\n\u05e2\u05e6\u05de\u05d9 \u05e2\u05d9\u05e0\u05d9\u05d9\u05dd \u05d5\u05e9\u05d0\u05dc\u05d9 \u05d0\u05ea \u05e2\u05e6\u05de\u05da:\n\u05de\u05d4\u05d5 \u05d4\u05d6\u05e8\u05e2 \u05e9\u05d0\u05e0\u05d9 \u05e8\u05d5\u05e6\u05d4 \u05dc\u05d6\u05e8\u05d5\u05e2 \u05e2\u05db\u05e9\u05d9\u05d5, \u05dc\u05de\u05e8\u05d5\u05ea \u05d4\u05d3\u05de\u05e2\u05d4?\n\u05d0\u05d9\u05d6\u05d5 \u05e4\u05e2\u05d5\u05dc\u05d4 \u05e7\u05d8\u05e0\u05d4 \u05d0\u05d1\u05dc \u05e0\u05d0\u05de\u05e0\u05d4 \u05dc\u05e2\u05e6\u05de\u05d9, \u05d9\u05db\u05d5\u05dc\u05d4 \u05dc\u05d4\u05d9\u05d5\u05ea \u05d6\u05e8\u05d9\u05e2\u05ea \u05ea\u05e7\u05d5\u05d5\u05d4 \u05e2\u05d1\u05d5\u05e8\u05d9?\n\u05d0\u05d9\u05da \u05ea\u05d9\u05e8\u05d0\u05d4 \u05d4\u05e8\u05d9\u05e0\u05d4 \u05e9\u05dc\u05d9? \u05d0\u05d9\u05d6\u05d4 \u05e4\u05e8\u05d9 \u05d0\u05e0\u05d9 \u05de\u05d0\u05d7\u05dc\u05ea \u05dc\u05e2\u05e6\u05de\u05d9 \u05dc\u05e7\u05e6\u05d5\u05e8?\n\u05db\u05ea\u05d1\u05d9 \u05de\u05e9\u05e4\u05d8 \u05d0\u05d7\u05d3:\n\u05d0\u05e0\u05d9 \u05d1\u05d5\u05d7\u05e8\u05ea \u05dc\u05d6\u05e8\u05d5\u05e2 ________, \u05d2\u05dd \u05d0\u05dd \u05d6\u05d4 \u05db\u05d5\u05d0\u05d1.\n\u05d0\u05e0\u05d9 \u05de\u05d0\u05de\u05d9\u05e0\u05d4 \u05e9\u05d9\u05d5\u05dd \u05d0\u05d7\u05d3 \u05d0\u05e7\u05e6\u05d5\u05e8 ________, \u05d1\u05e8\u05d9\u05e0\u05d4.\n"\u05e8\u05b5\u05d0\u05e9\u05b4\u05c1\u05d9\u05ea \u05d7\u05b8\u05db\u05b0\u05de\u05b8\u05d4 \u05d9\u05b4\u05e8\u05b0\u05d0\u05b7\u05ea \u05d4\', \u05e9\u05b5\u05c2\u05db\u05b6\u05dc \u05d8\u05d5\u05b9\u05d1 \u05dc\u05b0\u05db\u05b8\u05dc \u05e2\u05b9\u05e9\u05b5\u05c2\u05d9\u05d4\u05b6\u05dd, \u05ea\u05b0\u05bc\u05d4\u05b4\u05dc\u05b8\u05bc\u05ea\u05d5\u05b9 \u05e2\u05d5\u05b9\u05de\u05b6\u05d3\u05b6\u05ea \u05dc\u05b8\u05e2\u05b7\u05d3" (\u05ea\u05d4\u05d9\u05dc\u05d9\u05dd \u05e7\u05d9"\u05d0)\n\u05d0\u05e0\u05e9\u05d9\u05dd \u05e8\u05d1\u05d9\u05dd \u05de\u05d7\u05e4\u05e9\u05d9\u05dd \u05d0\u05ea \u05d4\u05e1\u05d5\u05d3 \u05dc\u05d7\u05d9\u05d9\u05dd \u05d8\u05d5\u05d1\u05d9\u05dd \u05d9\u05d5\u05ea\u05e8.\n\u05d9\u05d5\u05ea\u05e8 \u05e9\u05de\u05d7\u05d4, \u05d9\u05d5\u05ea\u05e8 \u05d4\u05e6\u05dc\u05d7\u05d4, \u05d9\u05d5\u05ea\u05e8 \u05d6\u05d5\u05d2\u05d9\u05d5\u05ea, \u05d9\u05d5\u05ea\u05e8 \u05d1\u05e8\u05d9\u05d0\u05d5\u05ea, \u05d9\u05d5\u05ea\u05e8 \u05de\u05e9\u05de\u05e2\u05d5\u05ea.\n\u05d0\u05d1\u05dc \u05d3\u05d5\u05d3 \u05d4\u05de\u05dc\u05da \u05de\u05dc\u05de\u05d3 \u05d0\u05d5\u05ea\u05e0\u05d5 \u05e2\u05d9\u05e7\u05e8\u05d5\u05df \u05e4\u05e9\u05d5\u05d8 \u05d5\u05e2\u05de\u05d5\u05e7:\n\u05e8\u05d0\u05e9\u05d9\u05ea \u05d7\u05db\u05de\u05d4 \u05d9\u05e8\u05d0\u05ea \u05d4\'.\n\u05d9\u05e8\u05d0\u05ea \u05d4\' \u05d0\u05d9\u05e0\u05e0\u05d4 \u05e4\u05d7\u05d3.\n\u05d4\u05d9\u05d0 \u05d4\u05d4\u05db\u05e8\u05d4 \u05e9\u05d9\u05e9 \u05e1\u05d3\u05e8 \u05d1\u05e2\u05d5\u05dc\u05dd.\n\u05e9\u05d0\u05e0\u05d9 \u05dc\u05d0 \u05de\u05e8\u05db\u05d6 \u05d4\u05d9\u05e7\u05d5\u05dd.\n\u05e9\u05d9\u05e9 \u05d0\u05de\u05ea \u05d2\u05d1\u05d5\u05d4\u05d4 \u05d9\u05d5\u05ea\u05e8 \u05de\u05d4\u05d7\u05e9\u05e7 \u05d4\u05e8\u05d2\u05e2\u05d9 \u05e9\u05dc\u05d9, \u05de\u05d4\u05e8\u05d2\u05e9 \u05d4\u05de\u05e9\u05ea\u05e0\u05d4 \u05e9\u05dc\u05d9 \u05d5\u05de\u05d4\u05e0\u05d5\u05d7\u05d5\u05ea \u05d4\u05de\u05d9\u05d9\u05d3\u05d9\u05ea \u05e9\u05dc\u05d9.\n\u05db\u05d0\u05e9\u05e8 \u05d0\u05d3\u05dd \u05d7\u05d9 \u05de\u05ea\u05d5\u05da \u05d9\u05e8\u05d0\u05ea \u05e9\u05de\u05d9\u05dd, \u05d4\u05d5\u05d0 \u05de\u05e4\u05e1\u05d9\u05e7 \u05dc\u05e9\u05d0\u05d5\u05dc \u05e8\u05e7:\n"\u05de\u05d4 \u05d1\u05d0 \u05dc\u05d9 \u05e2\u05db\u05e9\u05d9\u05d5?"\n\u05d5\u05de\u05ea\u05d7\u05d9\u05dc \u05dc\u05e9\u05d0\u05d5\u05dc:\n"\u05de\u05d4 \u05e0\u05db\u05d5\u05df \u05dc\u05e2\u05e9\u05d5\u05ea \u05e2\u05db\u05e9\u05d9\u05d5?"\n\u05d5\u05de\u05d9\u05d3 \u05d0\u05d7\u05e8 \u05db\u05da \u05de\u05d2\u05d9\u05e2 \u05d4\u05e4\u05e1\u05d5\u05e7:\n"\u05e9\u05db\u05dc \u05d8\u05d5\u05d1 \u05dc\u05db\u05dc \u05e2\u05d5\u05e9\u05d9\u05d4\u05dd."\n\u05dc\u05d0 \u05dc\u05db\u05dc \u05d7\u05d5\u05e9\u05d1\u05d9\u05d4\u05dd.\n\u05dc\u05d0 \u05dc\u05db\u05dc \u05de\u05d3\u05d1\u05e8\u05d9\u05d4\u05dd.\n\u05dc\u05d0 \u05dc\u05db\u05dc \u05d7\u05d5\u05dc\u05de\u05d9\u05d4\u05dd.\n\u05dc\u05db\u05dc \u05e2\u05d5\u05e9\u05d9\u05d4\u05dd.\n\u05d4\u05d7\u05db\u05de\u05d4 \u05d4\u05d0\u05de\u05d9\u05ea\u05d9\u05ea \u05d0\u05d9\u05e0\u05d4 \u05e0\u05de\u05d3\u05d3\u05ea \u05d1\u05db\u05de\u05d5\u05ea \u05d4\u05d9\u05d3\u05e2 \u05e9\u05d0\u05d3\u05dd \u05e6\u05d1\u05e8, \u05d0\u05dc\u05d0 \u05d1\u05db\u05de\u05d4 \u05d4\u05d5\u05d0 \u05de\u05d5\u05db\u05df \u05dc\u05d9\u05d9\u05e9\u05dd \u05d0\u05d5\u05ea\u05d5.\n\u05dc\u05db\u05df \u05d0\u05d7\u05ea \u05d4\u05d8\u05e2\u05d5\u05d9\u05d5\u05ea \u05d4\u05d2\u05d3\u05d5\u05dc\u05d5\u05ea \u05e9\u05dc \u05d3\u05d5\u05e8\u05e0\u05d5 \u05d4\u05d9\u05d0 \u05dc\u05d4\u05de\u05ea\u05d9\u05df \u05dc\u05de\u05d5\u05d8\u05d9\u05d1\u05e6\u05d9\u05d4.\n\u05d0\u05e0\u05e9\u05d9\u05dd \u05d0\u05d5\u05de\u05e8\u05d9\u05dd:\n\u05db\u05e9\u05d9\u05d4\u05d9\u05d4 \u05dc\u05d9 \u05d7\u05e9\u05e7 \u05d0\u05ea\u05d7\u05d9\u05dc \u05dc\u05d4\u05ea\u05d0\u05de\u05df.\n\u05db\u05e9\u05d0\u05e8\u05d2\u05d9\u05e9 \u05d4\u05e9\u05e8\u05d0\u05d4 \u05d0\u05ea\u05e4\u05dc\u05dc.\n\u05db\u05e9\u05d9\u05d4\u05d9\u05d4 \u05dc\u05d9 \u05db\u05d5\u05d7 \u05d0\u05e9\u05e0\u05d4 \u05d0\u05ea \u05d4\u05ea\u05d6\u05d5\u05e0\u05d4.\n\u05db\u05e9\u05d0\u05e8\u05d2\u05d9\u05e9 \u05d0\u05d4\u05d1\u05d4 \u05d0\u05e9\u05e7\u05d9\u05e2 \u05d1\u05d6\u05d5\u05d2\u05d9\u05d5\u05ea.\n\u05d0\u05d1\u05dc \u05d4\u05d7\u05d9\u05d9\u05dd \u05e2\u05d5\u05d1\u05d3\u05d9\u05dd \u05d4\u05e4\u05d5\u05da.\n\u05d4\u05de\u05e9\u05de\u05e2\u05ea \u05d1\u05d0\u05d4 \u05dc\u05e4\u05e0\u05d9 \u05d4\u05de\u05d5\u05d8\u05d9\u05d1\u05e6\u05d9\u05d4.\n\u05d7\u05d6"\u05dc \u05dc\u05d9\u05de\u05d3\u05d5\u05e0\u05d5 \u05db\u05d9 \u05d0\u05d7\u05e8\u05d9 \u05d4\u05de\u05e2\u05e9\u05d9\u05dd \u05e0\u05de\u05e9\u05db\u05d9\u05dd \u05d4\u05dc\u05d1\u05d1\u05d5\u05ea.\n\u05d4\u05e2\u05e9\u05d9\u05d9\u05d4 \u05d9\u05d5\u05e6\u05e8\u05ea \u05d0\u05ea \u05d4\u05d4\u05e8\u05d2\u05e9\u05d4.\n\u05d4\u05e4\u05e2\u05d5\u05dc\u05d4 \u05d9\u05d5\u05e6\u05e8\u05ea \u05d0\u05ea \u05d4\u05d7\u05e9\u05e7.\n\u05d4\u05d4\u05ea\u05de\u05d3\u05d4 \u05d9\u05d5\u05e6\u05e8\u05ea \u05d0\u05ea \u05d4\u05d0\u05de\u05d5\u05e0\u05d4.\n\u05de\u05d9 \u05e9\u05de\u05d7\u05db\u05d4 \u05dc\u05de\u05d5\u05d8\u05d9\u05d1\u05e6\u05d9\u05d4 \u05d7\u05d9 \u05db\u05e7\u05d5\u05e8\u05d1\u05df \u05dc\u05de\u05e6\u05d1 \u05d4\u05e8\u05d5\u05d7 \u05d4\u05de\u05e9\u05ea\u05e0\u05d4.\n\u05de\u05d9 \u05e9\u05d7\u05d9 \u05dc\u05e4\u05d9 \u05e2\u05e8\u05db\u05d9\u05dd \u05d5\u05de\u05e9\u05de\u05e2\u05ea \u05d1\u05d5\u05e0\u05d4 \u05d7\u05d9\u05d9\u05dd \u05d9\u05e6\u05d9\u05d1\u05d9\u05dd.\n\u05d4\u05d1\u05e8\u05db\u05d4 \u05d1\u05d7\u05d9\u05d9\u05dd \u05d0\u05d9\u05e0\u05d4 \u05de\u05d2\u05d9\u05e2\u05d4 \u05e8\u05e7 \u05de\u05d4\u05e8\u05d2\u05e2\u05d9\u05dd \u05d4\u05de\u05e8\u05d2\u05e9\u05d9\u05dd.\n\u05d4\u05d9\u05d0 \u05e0\u05d5\u05e6\u05e8\u05ea \u05de\u05d0\u05dc\u05e4\u05d9 \u05d4\u05d7\u05dc\u05d8\u05d5\u05ea \u05e7\u05d8\u05e0\u05d5\u05ea:\n\u05dc\u05e7\u05d5\u05dd \u05db\u05e9\u05e7\u05e9\u05d4.\n\u05dc\u05d4\u05ea\u05e4\u05dc\u05dc \u05d1\u05e8\u05d9\u05db\u05d5\u05d6 \u05db\u05e9\u05e2\u05d9\u05d9\u05e4\u05d9\u05dd \u05d0\u05d5 \u05d0\u05d9\u05df \u05d7\u05e9\u05e7 \u05d5\u05d4\u05e9\u05e8\u05d0\u05d4.\n\u05dc\u05e9\u05de\u05d5\u05e8 \u05e2\u05dc \u05d4\u05e4\u05d4 \u05db\u05e9\u05db\u05d5\u05e2\u05e1\u05d9\u05dd.\n\u05dc\u05d4\u05e7\u05e9\u05d9\u05d1 \u05db\u05e9\u05dc\u05d0 \u05de\u05ea\u05d7\u05e9\u05e7.\n\u05dc\u05e2\u05e9\u05d5\u05ea \u05d0\u05ea \u05de\u05d4 \u05e9\u05e0\u05db\u05d5\u05df \u05d2\u05dd \u05db\u05e9\u05dc\u05d0 \u05de\u05e8\u05d2\u05d9\u05e9\u05d9\u05dd.\n\u05d6\u05d4\u05d5 "\u05e9\u05db\u05dc \u05d8\u05d5\u05d1 \u05dc\u05db\u05dc \u05e2\u05d5\u05e9\u05d9\u05d4\u05dd".\n\u05d5\u05db\u05e9\u05d0\u05d3\u05dd \u05d7\u05d9 \u05db\u05da, \u05de\u05ea\u05d5\u05da \u05d9\u05e8\u05d0\u05ea \u05e9\u05de\u05d9\u05dd, \u05d0\u05d7\u05e8\u05d9\u05d5\u05ea \u05d5\u05e2\u05e9\u05d9\u05d9\u05d4 \u05e2\u05e7\u05d1\u05d9\u05ea, \u05d4\u05d5\u05d0 \u05de\u05d2\u05dc\u05d4 \u05d3\u05d1\u05e8 \u05de\u05d5\u05e4\u05dc\u05d0:\n\u05d4\u05de\u05d5\u05d8\u05d9\u05d1\u05e6\u05d9\u05d4 \u05e9\u05d1\u05d0\u05d4 \u05d5\u05d4\u05d5\u05dc\u05db\u05ea \u05db\u05d1\u05e8 \u05dc\u05d0 \u05de\u05e0\u05d4\u05dc\u05ea \u05d0\u05d5\u05ea\u05d5.\n\u05d4\u05d5\u05d0 \u05de\u05d7\u05d5\u05d1\u05e8 \u05dc\u05de\u05e7\u05d5\u05e8 \u05e2\u05de\u05d5\u05e7 \u05d9\u05d5\u05ea\u05e8.\n\u05d5\u05d0\u05d6 \u05de\u05ea\u05e7\u05d9\u05d9\u05dd \u05d1\u05d5 \u05e1\u05d5\u05e3 \u05d4\u05e4\u05e1\u05d5\u05e7:\n"\u05ea\u05d4\u05d9\u05dc\u05ea\u05d5 \u05e2\u05d5\u05de\u05d3\u05ea \u05dc\u05e2\u05d3."\n\u05dc\u05d0 \u05d4\u05ea\u05dc\u05d4\u05d1\u05d5\u05ea \u05e8\u05d2\u05e2\u05d9\u05ea.\n\u05dc\u05d0 \u05d4\u05e6\u05dc\u05d7\u05d4 \u05d7\u05d5\u05dc\u05e4\u05ea.\n\u05d0\u05dc\u05d0 \u05d7\u05d9\u05d9\u05dd \u05d4\u05d1\u05e0\u05d5\u05d9\u05d9\u05dd \u05e2\u05dc \u05d9\u05e1\u05d5\u05d3\u05d5\u05ea \u05d7\u05d6\u05e7\u05d9\u05dd, \u05e9\u05de\u05de\u05e9\u05d9\u05db\u05d9\u05dd \u05dc\u05d4\u05d0\u05d9\u05e8 \u05d2\u05dd \u05db\u05e9\u05d4\u05e8\u05d2\u05e9 \u05de\u05e9\u05ea\u05e0\u05d4 \u05d5\u05d4\u05d3\u05e8\u05da \u05de\u05d0\u05ea\u05d2\u05e8\u05ea.\n\u05db\u05d9 \u05d4\u05ea\u05e9\u05ea\u05d9\u05ea \u05e9\u05dc \u05d7\u05d9\u05d9\u05dd \u05e0\u05db\u05d5\u05e0\u05d9\u05dd \u05d4\u05d9\u05d0 \u05dc\u05d0 \u05dc\u05e2\u05e9\u05d5\u05ea \u05de\u05d4 \u05e9\u05de\u05ea\u05d7\u05e9\u05e7.\n\u05d4\u05ea\u05e9\u05ea\u05d9\u05ea \u05e9\u05dc \u05d7\u05d9\u05d9\u05dd \u05e0\u05db\u05d5\u05e0\u05d9\u05dd \u05d4\u05d9\u05d0 \u05dc\u05e2\u05e9\u05d5\u05ea \u05d0\u05ea \u05de\u05d4 \u05e9\u05e0\u05db\u05d5\u05df \u2013 \u05e2\u05d3 \u05e9\u05d2\u05dd \u05d4\u05dc\u05d1 \u05de\u05e6\u05d8\u05e8\u05e3')
